# Countdown popup shown on the TV itself. VLC is launched with a `marq`
# sub-source that re-reads this file ~5×/s and renders its contents bottom-right.
# main.py writes the "Skipping … in N" text here; emptying the file clears it.
# run.py and watchdog.py launch VLC with --marq-file pointed at this same path —
# keep _vlc_marquee_args() (below) in sync with their arg lists.
MARQUEE_FILE = Path(__file__).parent / ".vlc_marquee.txt"


def _vlc_marquee_args() -> list:
    """VLC CLI args enabling the bottom-right countdown marquee.

    Mirrored verbatim in run.py (start_vlc) and watchdog.py (vlc_spec) — the
    three launch paths must agree. Text-only (no background box) so regular
    subtitles render unchanged; readability comes from VLC's default outline.
    """
    return [
        "--sub-source=marq",
        f"--marq-file={MARQUEE_FILE}",
        "--marq-refresh=200",      # re-read the file ~5×/s → smooth countdown
        "--marq-position=10",      # 10 = Bottom-Right
        "--marq-x=50", "--marq-y=50",   # padding in from the corner
        "--marq-size=48",
        "--marq-color=16777215",   # white
        "--marq-opacity=255",      # fully opaque text
        "--marq-timeout=0",        # persist until the file is emptied
    ]


# ── Night mode (dynamic-range compression) ──────────────────────────────────
# "Night mode" narrows the gap between the quietest and loudest sounds so quiet
# dialogue stays audible without explosions being jarring at low room volume.
# It's VLC's `compressor` audio filter — there is no runtime HTTP command to add
# an audio filter, so the filter is set at launch and toggling it restarts VLC
# (see _apply_night_mode + _restart_vlc_process).
#
# Three intensity presets (user-selectable, settings menu only). The chosen
# preset persists independently of the on/off toggle, so turning night mode off
# and back on reuses the same intensity. The presets dict below is mirrored
# verbatim in run.py (start_vlc) and watchdog.py (vlc_spec); change one, change
# all three (same contract as _vlc_marquee_args).
#
# Tuning (all dB / ms): a lower threshold + higher ratio pull loud peaks down
# harder, a higher makeup gain lifts the now-quieter dialogue back up, and an RMS
# (not peak) detector with a slow-ish release keeps it from "pumping" on speech.
# light  = gentle leveling; medium = balanced default; max = strongest.
NIGHT_MODE_PRESETS = {
    "light": [
        "--audio-filter=compressor",
        "--compressor-rms-peak=0.00",
        "--compressor-attack=25.0",
        "--compressor-release=250.0",
        "--compressor-threshold=-20.0",
        "--compressor-ratio=3.0",
        "--compressor-knee=5.0",
        "--compressor-makeup-gain=6.0",
    ],
    "medium": [
        "--audio-filter=compressor",
        "--compressor-rms-peak=0.00",
        "--compressor-attack=25.0",
        "--compressor-release=250.0",
        "--compressor-threshold=-24.0",
        "--compressor-ratio=6.0",
        "--compressor-knee=3.0",
        "--compressor-makeup-gain=10.0",
    ],
    "max": [
        "--audio-filter=compressor",
        "--compressor-rms-peak=0.00",
        "--compressor-attack=15.0",
        "--compressor-release=180.0",
        "--compressor-threshold=-28.0",
        "--compressor-ratio=12.0",
        "--compressor-knee=2.0",
        "--compressor-makeup-gain=13.0",
    ],
}
NIGHT_MODE_DEFAULT_PRESET = "medium"

# UI metadata for the settings-menu intensity picker (order + labels). Lives in
# main.py only — run.py / watchdog.py just need the args dict above.
NIGHT_MODE_PRESET_META = [
    {"id": "light",  "label": "Light",  "desc": "Gentle leveling"},
    {"id": "medium", "label": "Medium", "desc": "Balanced (default)"},
    {"id": "max",    "label": "Max",    "desc": "Strongest — flattens loud peaks hard"},
]


def _night_mode_preset(name: Optional[str]) -> str:
    """Normalise a preset name to a known key, falling back to the default."""
    return name if name in NIGHT_MODE_PRESETS else NIGHT_MODE_DEFAULT_PRESET


def _vlc_audio_filter_args(night_mode: bool, preset: Optional[str] = None) -> list:
    """VLC CLI args for the night-mode compressor at `preset`, or [] when off.

    Mirrored in run.py / watchdog.py via the shared NIGHT_MODE_PRESETS contract.
    """
    if not night_mode:
        return []
    return list(NIGHT_MODE_PRESETS[_night_mode_preset(preset)])


def _marquee_write(text: str) -> None:
    """Atomically replace the marquee file's contents (sync; tiny write).

    Clearing writes a single space, never an empty string. VLC's marq filter
    reads the file with getline(); on an *empty* file getline hits EOF, so the
    filter keeps the previously-shown text (and logs a read error every refresh
    tick). A lone space is a valid non-empty line that forces the update yet
    renders nothing — we draw no background box, so a space has no glyph.
    """
    try:
        tmp = MARQUEE_FILE.with_suffix(".tmp")
        tmp.write_text(text or " ", encoding="utf-8")
        os.replace(tmp, MARQUEE_FILE)
    except Exception:
        pass

# Keep in sync with the version badge at the bottom of static/index.html.
# Clients fetch this via /api/version and force a hard reload when the cached
# page's badge value is older than the server's value.
UI_VERSION = "8.7.0"
_lib_lock: asyncio.Lock  # initialised in lifespan

# Retains references to fire-and-forget background tasks so the event loop's weak
# reference doesn't let them be garbage-collected mid-flight. Each task discards
# itself on completion.
_bg_tasks: set = set()


def _spawn_bg(coro) -> "asyncio.Task":
    """Schedule a fire-and-forget coroutine, keeping a strong reference until it
    finishes (otherwise asyncio may GC the task while it's still running)."""
    t = asyncio.create_task(coro)
    _bg_tasks.add(t)
    t.add_done_callback(_bg_tasks.discard)
    return t

# Cap how many series fingerprint at once. Each series pipeline parks blocking
# ffmpeg/fpcalc decodes (now on the analyzer's own thread pool) AND spins up a
# low-priority match process; left unbounded, hitting "Analyze" on many shows
# fans both out across every series at once and oversubscribes the host. The
# gate serialises the heavy work so a bulk analyze drains as a queue instead of
# a thundering herd. See docs/ANALYZER.md § Concurrency.
ANALYSIS_CONCURRENCY = 2
_analysis_gate: asyncio.Semaphore  # initialised in lifespan


# ── Library Storage ───────────────────────────────────────────────────────────

def _migrate_item(item: dict) -> dict:
    """Upgrade items written by older versions of the server in-place."""
    # v2.0 → v2.1: flat file_path → files list
    if not item.get("files") and item.get("file_path"):
        item["files"] = [{
            "name": Path(item["file_path"]).name,
            "path": item["file_path"],
            "size_bytes": item.get("size_bytes", 0),
            "season": item.get("season", 0),
            "episode": item.get("episode", 0),
        }]
    # v2.0 → v2.1: flat per-profile progress → per-file progress
    for prof_id, prog in list(item.get("progress", {}).items()):
        if isinstance(prog, dict) and "file_progress" not in prog and "position_sec" in prog:
            file_path = item.get("file_path", "")
            if file_path:
                item["progress"][prof_id] = {
                    "last_file": file_path,
                    "file_progress": {
                        file_path: {
                            "position_sec": prog.get("position_sec", 0),
                            "duration_sec": prog.get("duration_sec", 0),
                            "completed": prog.get("completed", False),
                            "updated_at": prog.get("updated_at", ""),
                        }
                    },
                }
    return item


def _load_lib_raw() -> dict:
    if LIBRARY_FILE.exists():
        try:
            raw = json.loads(LIBRARY_FILE.read_text(encoding="utf-8"))
            raw["items"] = [_migrate_item(it) for it in raw.get("items", [])]
            return raw
        except Exception:
            pass
    return {"profiles": [], "items": []}


def _save_lib_raw(data: dict) -> None:
    # Atomic write (temp file + os.replace, same directory ⇒ same volume, so
    # the replace is atomic on Windows/NTFS and POSIX alike). library.json is
    # rewritten every ~15 s during playback; a plain write_text truncated it
    # first, so a crash / service restart / power cut mid-write left corrupt
    # JSON — and _load_lib_raw's fallback then started an EMPTY library,
    # losing every profile, watch position, and subtitle pick.
    tmp = LIBRARY_FILE.with_name(LIBRARY_FILE.name + ".tmp")
    tmp.write_text(json.dumps(data, indent=2, ensure_ascii=False), encoding="utf-8")
    os.replace(tmp, LIBRARY_FILE)


async def get_library() -> dict:
    # The read + json.loads + _migrate_item-over-every-item is O(library size)
    # and was previously run inline on the event loop. Hot loops call this every
    # 2-5 s (progress tracker, download monitor) and it grows after every
    # download (skip_data fingerprints), so a large library.json stalled the
    # whole loop — the dashboard went laggy and the HTTPS proxy threw ReadErrors
    # mid-request while the loop was blocked. Run the blocking work in a thread;
    # the lock still serialises access, but the loop stays free.
    async with _lib_lock:
        return await asyncio.to_thread(_load_lib_raw)


async def put_library(data: dict) -> None:
    async with _lib_lock:
        await asyncio.to_thread(_save_lib_raw, data)


def _now_iso() -> str:
    return datetime.now(timezone.utc).isoformat(timespec="seconds")


def _parse_iso_dt(s: Optional[str]) -> Optional[datetime]:
    """Tolerant ISO-8601 → aware datetime (UTC). Accepts a trailing 'Z' and
    naive strings (assumed UTC). Returns None if unparseable. Used by the iOS
    progress-sync conflict logic to compare server `updated_at` against the
    device's `base_synced_at` / `client_updated_at` watermarks."""
    if not s:
        return None
    try:
        t = s.strip()
        if t.endswith("Z"):
            t = t[:-1] + "+00:00"
        dt = datetime.fromisoformat(t)
        if dt.tzinfo is None:
            dt = dt.replace(tzinfo=timezone.utc)
        return dt
    except Exception:
        return None


# ── Global State ──────────────────────────────────────────────────────────────

@dataclass
class AppState:
    vpn_secure: bool = True
    vpn_status_text: str = "Checking…"
    # VPN kill-switch reach: True ⇒ block the whole UI behind the overlay when the
    # VPN drops; False ⇒ only kill qBit (qBit is killed either way). Mirror of
    # settings.vpn_killswitch.block_ui; seeded at lifespan, updated by the admin POST.
    vpn_block_ui: bool = True
    # Admin-selected primary network adapter (interface *name*, "" = auto). The
    # network_adapter_redirect middleware bounces a client that connected on any
    # other adapter's IP to this adapter's current IP. Mirror of
    # settings.network.preferred_adapter; seeded at lifespan, updated by the POST.
    preferred_adapter: str = ""
    jackett_ok: bool = True               # last known Jackett HTTP reachability
    # Indexer degradation. Set from /api/search when Jackett reports that some
    # configured indexers errored while others still returned results — search
    # stays usable, but we flag it. Drives a non-specific user banner (never
    # names which indexers); the admin Indexers tab shows the per-indexer detail.
    indexers_degraded: bool = False
    indexers_total: int = 0
    indexers_failing: int = 0
    indexer_health: list = field(default_factory=list)  # [{id, name, ok, error, results}] — last observed per-indexer health (search-derived or test-derived)
    indexer_health_checked_at: float = 0.0
    active_hash: Optional[str] = None
    active_title: Optional[str] = None
    active_file: Optional[Path] = None
    stream_status: str = "idle"   # idle | buffering | playing | error
    progress: float = 0.0
    downloaded_mb: float = 0.0
    total_mb: float = 0.0
    dl_speed_bps: int = 0
    ul_speed_bps: int = 0
    stream_task: Optional[asyncio.Task] = None
    library_play_task: Optional[asyncio.Task] = None  # in-flight VLC handoff for a library play / prev / next
    library_item_id: Optional[str] = None
    library_profile_id: Optional[str] = None
    # Identity of the profile that *started* the current playback, snapshotted so
    # SSE clients can show "who's watching" without a library lookup. Progress is
    # always attributed to library_profile_id regardless of who drives the shared
    # VLC controls afterward — these just make the owner visible. Cleared on stop.
    library_profile_name: str = ""
    library_profile_color: str = ""
    library_item_file_count: int = 0                     # total files in the playing item
    library_playlist: list = field(default_factory=list)  # ordered file paths
    # Shuffle Play: the full temp random order of file paths for the active item.
    # Empty when not shuffling. When set, next/prev (and the credit "skip to next"
    # auto-advance) navigate this order instead of the item's natural file order —
    # and unlike library_playlist (which is the remaining VLC tail and shrinks on
    # advance), this keeps the *whole* order so prev can walk back through history.
    library_shuffle_order: list = field(default_factory=list)
    # Pool the live shuffle order was drawn from ("all" | "unwatched"). Travels
    # alongside library_shuffle_order so a VLC→device handoff can carry it (and
    # keep the persisted Resume-on-shuffle scope intact). Empty when not shuffling.
    library_shuffle_scope: str = ""
    # Merged-series playback: a single show whose episodes live in *separate*
    # library items (each a single-episode torrent) is played as one playlist that
    # spans those items. `library_series_map` maps each playlist path → its owning
    # item id; the progress tracker re-points `library_item_id` at the owner of the
    # file VLC is actually playing so progress/skip/track-prefs key off the right
    # item as playback crosses item boundaries. `library_series_order` is the full,
    # stable ordered path list (like library_shuffle_order — doesn't shrink) so
    # prev/next and the credit auto-advance can span items. Both empty for a normal
    # single-item play. See docs/GOTCHAS.md § cross-item series playback.
    library_series_map: dict = field(default_factory=dict)
    library_series_order: list = field(default_factory=list)
    library_current_file: Optional[str] = None            # path VLC is playing now
    downloading_count: int = 0                            # active library downloads (ALL, incl. admin-only — drives host-busy/idle gating)
    downloading_count_visible: int = 0                    # active downloads a non-elevated viewer may know about (excludes admin_only) — drives the user-facing badge
    play_when_ready_item_id: Optional[str] = None        # auto-play this item on download complete
    play_when_ready_profile_id: Optional[str] = None
    play_when_ready_file_path: Optional[str] = None      # if set, wait for this specific file
    current_audio_track: int = -1                         # last track ID sent to VLC
    current_subtitle_track: int = -1                      # last track ID sent to VLC
    # ES ID → {"lang","ai","path"} for the current file's subtitle tracks, as
    # annotated by _load_all_local_subs / _download_and_attach_subtitle. Lets a
    # manual VLC pick be persisted as a resolvable descriptor (subtitle_sel)
    # instead of just a bare ES ID — the descriptor is what the on-device
    # player restores from. Rebuilt on every sidecar-load pass.
    vlc_sub_meta: dict = field(default_factory=dict)
    track_pref_applied_file: Optional[str] = None         # path for which track prefs were last applied
    vlc_time: int = 0                                     # VLC current position (seconds)
    vlc_duration: int = 0                                 # VLC total duration (seconds)
    vlc_volume: int = 100                                 # VLC volume 0-200 (100 = normal)
    prepare_hash: Optional[str] = None                    # hash added by /stream/prepare, pending user selection
    skip_offer: Optional[dict] = None                     # {"type": "intro"|"credits", "end_at": s, "next_item_id": id?, "next_file_path": p?}
    skip_offer_file: Optional[str] = None                 # path the current skip offer corresponds to
    skip_countdown: Optional[dict] = None                 # {"type", "file_path", "n"} active auto-skip countdown (TV marquee)
    skip_countdown_task: Optional[asyncio.Task] = None    # in-flight countdown coroutine
    resume_offer: Optional[dict] = None                   # {"position_sec": N, "file_path": "..."} when resume_mode="prompt"
    pending_watch: Optional[dict] = None                  # {"item_id","profile_id","file_path","duration_sec"} deferred "mark watched" armed when the viewer skips to the next episode from any position. Cleared if they return to that file.
    pending_watch_task: Optional[asyncio.Task] = None     # in-flight grace-period coroutine for pending_watch (one at a time)
    analysis_jobs: dict = field(default_factory=dict)     # series_key → {status, stage, current, total, message, item_ids, started_at, finished_at}
    # Ring buffer of Smart Skip events (most recent first). Each entry:
    # {ts, level: "info"|"warn"|"error", series_key, item_id, file_path,
    #  error_code, message}. Surfaces in the admin "Smart Skip" tab so the
    # operator can see *why* fingerprinting failed for individual files without
    # tailing logs/streamlink_app.log.
    analyzer_log: deque = field(default_factory=lambda: deque(maxlen=200))
    background_playing: bool = False                      # True when the idle background video is the active VLC playlist
    user_volume_before_bg: int = 100                      # snapshot of state.vlc_volume taken when bg first took over
    # Non-admin "let me use the computer" override. While set, the idle background
    # video loop AND every focus/minimize/fullscreen assertion stand down so VLC
    # stops grabbing the screen and other windows stop being minimized. Values:
    # 0.0 = active (normal behaviour); a future time.time() = paused until then;
    # float('inf') = paused until the user resumes. See window_mgmt_paused() and
    # POST /api/window-control.
    window_mgmt_paused_until: float = 0.0
    vlc_night_mode: bool = False                          # VLC compressor (dynamic-range) filter; persisted in library.json → settings.vlc_night_mode, seeded at lifespan startup. VLC must relaunch to apply (no runtime HTTP command for audio filters)
    vlc_night_mode_preset: str = "medium"                 # intensity preset (light|medium|max); persisted in library.json → settings.vlc_night_mode_preset, remembered independently of the on/off toggle
    subtitle_default_language: str = "eng"                # preferred subtitle language (settings.subtitles.default_language; "" = Any), mirrored here for state_snapshot/UI defaults; seeded at lifespan, updated by the admin subtitles POST
    subtitle_upgrade_late: bool = True                    # settings.subtitles.upgrade_late_subs, mirrored for the on-device upgrade poller
    subtitle_single_option: bool = True                   # settings.subtitles.single_option, mirrored for client/UI
    sub_auto_ai_path: str = ""                            # abs path of the AI sidecar currently auto-applied in VLC ("" = none); the upgrade loop watches this and swaps in a real sub when one arrives
    last_activity: float = 0.0                            # time.time() of last user-initiated interaction (drives scheduled-reboot idle check)
    prep_paused: bool = False                             # True ⇒ bulk stream-prep jobs hold (set by the non-admin Pause control / auto-prep falling edge)
    admin_prep_stop: bool = False                         # True ⇒ admin force-prep ("admin" queue) jobs cancel at the gate (set by the admin Stop control). Cleared when a new force-prep batch starts. Independent of prep_paused — force-prep ignores the bulk gate + activity-kill by design
    auto_prep_engaged: bool = False                       # True while the unified auto_prep_loop has prep running (always mode OR idle trigger) — edge flag for resume/pause
    play_prep_task: Optional[asyncio.Task] = None         # the chain task prepping the currently-playing series' tail for on-device (settings.play_prep); cancelled + replaced on each new VLC play
    download_idle_open: bool = False                      # last computed idle/night DOWNLOAD window state (set by download_scheduler_loop) — drives the "waiting for idle" UI
    download_idle_configured: bool = False                # True if Automatic Stream Prep is enabled (auto_prep mode != off) — so idle-only downloads have a window to run in
    idle_prep_on: bool = False                            # cached: auto_prep mode == "idle" (set each auto_prep_loop tick) — lets the activity hook decide cheaply
    idle_prep_hard: bool = False                          # cached: auto_prep idle mode with on_activity == "hard" (set each tick) — only then does the activity hook kill the in-flight encode immediately
    sys_status: dict = field(default_factory=dict)        # latest CPU/GPU/RAM/network sample + ok/degraded/overloaded classification (set by system_monitor_loop)
    cache_autopurge_last: dict = field(default_factory=dict)  # last auto-purge result (set by cache_autopurge_loop): {at, deleted, bytes_freed, total_bytes_before} — drives the admin card's "last run" line
    # ── Source-file validator (admin System tab) ─────────────────────────────
    # Decodes library video files with ffmpeg to find CORRUPT/unreadable SOURCES,
    # independent of qBit's piece recheck (a torrent only proves the bytes match
    # its hashes — it happily seeds a perfect copy of an already-damaged file).
    # Snapshot of the current/last run for the admin card to poll; the runner
    # coroutine task + the in-flight proc handle so Stop can terminate a long
    # deep decode mid-file.
    file_validation: dict = field(default_factory=dict)   # {running, deep, scope, total, scanned, current_name, damaged:[…], missing:[…], started_at, finished_at, stopped, error}
    file_validation_task: Optional[asyncio.Task] = None
    file_validation_stop: bool = False
    file_validation_proc: Optional["asyncio.subprocess.Process"] = None
    # Best-effort in-place repair of the files the validator flagged (remux, then
    # optional lossy re-encode); replaces the original only when the candidate
    # decodes clean, and purges the stale HLS bundle. Same job-state shape.
    file_repair: dict = field(default_factory=dict)       # {running, reencode, total, scanned, current_name, repaired:[…], failed:[…], started_at, finished_at, stopped, error}
    file_repair_task: Optional[asyncio.Task] = None
    file_repair_stop: bool = False
    file_repair_proc: Optional["asyncio.subprocess.Process"] = None
    # In-place lossy re-encode of source files to reclaim disk space (admin
    # Storage & Compression card). Replaces each source only when the re-encode
    # decodes clean AND came out smaller, then purges the stale HLS bundle. Same
    # job-state shape as the validator/repair.
    file_compression: dict = field(default_factory=dict)  # {running, scope, level, codec, total, scanned, current_name, results:[…], bytes_before, bytes_after, started_at, finished_at, stopped, error}
    file_compression_task: Optional[asyncio.Task] = None
    file_compression_stop: bool = False
    file_compression_proc: Optional["asyncio.subprocess.Process"] = None
    # Normalised paths of source files currently mid-compress. A robust playback
    # LOCK: while a file is here, every playback/read entry point (VLC play,
    # on-device prep, on-demand JIT, clip) refuses it, and the compressor stops
    # any in-flight playback of it first — because the in-place replace (os.replace)
    # fails on Windows while anything holds the file open (WinError 5).
    compressing_paths: set = field(default_factory=set)
    # Item ids flagged "on-demand stream only": on-device browser playback uses the
    # just-in-time pipeline and NO permanent HLS bundle is ever built (saves disk).
    # Seeded at lifespan from library.json (item["ondemand_only"]) and rebuilt on
    # toggle. Does NOT affect VLC (TV) playback — that reads the source directly.
    ondemand_only_items: set = field(default_factory=set)
    # Idle-gated automatic background validation (separate from the admin scan so
    # they never collide). Walks files whose persisted `validation` verdict is
    # missing/stale, one at a time, ONLY while the box is idle — and persists each
    # verdict into library.json, so it RESUMES after a restart/auto-update instead
    # of starting over (the resumable counterpart to the in-memory admin scan).
    auto_validate: dict = field(default_factory=dict)     # {running, total, scanned, current_name, started_at}
    auto_validate_task: Optional[asyncio.Task] = None
    auto_validate_stop: bool = False
    auto_validate_proc: Optional["asyncio.subprocess.Process"] = None
    # ── YouTube-on-TV (browser playback on the host display, remote-controlled) ──
    youtube_active: bool = False                          # True while a YouTube video is the active TV playback (browser, not VLC)
    youtube_video_id: Optional[str] = None               # 11-char YouTube id currently loaded on the TV page
    youtube_playback: str = ""                            # last player state from /tv: unstarted|buffering|playing|paused|ended
    youtube_tv_seen_at: float = 0.0                       # time.time() of last /tv heartbeat (drives relaunch-vs-load decision)
    system_volume_before_yt: Optional[int] = None        # OS volume (0-100) snapshot at YouTube start; falls back when no default configured
    # ── TV UI (Firestick-style dashboard kiosk on the host display) ──
    tv_ui_active: bool = False                            # True while the dashboard kiosk should hold the screen; gates every VLC focus assertion (see docs/REMOTE.md)
    tv_input_last: float = 0.0                            # time.time() of the last HID input (key/click/move) — drives the TV UI idle hand-back
    host_volume_expected: Optional[int] = None            # last OS volume WE set/accepted (0-100). Only consumed by the OPT-IN remote_volume_guard (REMOTE_VOLUME_GUARD=1, Windows) which reverts any other change
    # ── Auto-updater (transient view of the current update operation) ──
    # All persisted updater state lives in library.json → settings.autoupdate.
    # These fields just expose the live state of an in-flight check/apply so
    # the admin UI can render progress without polling git directly.
    updater_phase: str = "idle"            # idle | checking | applying | setup | restarting | error
    updater_message: str = ""              # human-readable detail for the current phase
    updater_busy: bool = False             # True while a check/apply is running (admin UI disables buttons)
    updater_last_output: str = ""          # last 8 KiB of setup.py stdout/stderr — for diagnostics
    sse_queues: list = field(default_factory=list)


state = AppState()
# The main asyncio loop, captured at lifespan startup. Needed by code running
# on foreign threads (the HID input listener) to schedule coroutines back onto
# the loop via run_coroutine_threadsafe.
_MAIN_LOOP: Optional[asyncio.AbstractEventLoop] = None
qbit: Optional[httpx.AsyncClient] = None
vlc_client: Optional[httpx.AsyncClient] = None   # persistent keep-alive client for VLC (see _vlc_http)
_admin_sessions: dict[str, float] = {}   # token → expiry Unix timestamp

# ── iOS app device-pairing tokens (M5, plan A4) ────────────────────────────────
# Long-lived bearer tokens issued to paired client apps (POST /api/pair). Unlike
# _admin_sessions these are persisted to disk so a paired device survives a host
# restart. Map: token → {"created_at": iso, "label": str, "last_seen": iso}.
DEVICE_TOKENS_FILE = Path(__file__).parent / "device_tokens.json"
_device_tokens: dict[str, dict] = {}


def _load_device_tokens() -> None:
    global _device_tokens
    try:
        if DEVICE_TOKENS_FILE.exists():
            data = json.loads(DEVICE_TOKENS_FILE.read_text(encoding="utf-8"))
            if isinstance(data, dict):
                _device_tokens = {k: v for k, v in data.items() if isinstance(v, dict)}
    except Exception as e:  # corrupt file shouldn't break startup
        log.warning("Could not load device tokens: %s", e)
        _device_tokens = {}


def _save_device_tokens() -> None:
    try:
        DEVICE_TOKENS_FILE.write_text(json.dumps(_device_tokens, indent=2), encoding="utf-8")
    except Exception as e:
        log.warning("Could not persist device tokens: %s", e)

# ── Jackett Session ───────────────────────────────────────────────────────────
_jackett_cookie: str = ""
_jackett_cookie_expiry: float = 0.0
_jackett_cookie_lock: asyncio.Lock  # initialised in lifespan


async def _jackett_login() -> str:
    """Login to Jackett and return the session cookie value."""
    async with httpx.AsyncClient(follow_redirects=True, timeout=10.0) as tmp:
        await tmp.get(f"{settings.indexer_url}/UI/Login")
        r = await tmp.post(
            f"{settings.indexer_url}/UI/Dashboard",
            data={"password": settings.jackett_password},
            follow_redirects=False,
        )
    cookie = r.cookies.get("Jackett")
    if not cookie:
        raise HTTPException(502, "Could not authenticate with Jackett — check JACKETT_PASSWORD in .env")
    return cookie


@asynccontextmanager
async def _jackett_admin():
    """Yield an httpx client authenticated to Jackett's admin API."""
    global _jackett_cookie, _jackett_cookie_expiry
    cookies: dict[str, str] = {}
    if settings.jackett_password:
        async with _jackett_cookie_lock:
            if not _jackett_cookie or time.time() >= _jackett_cookie_expiry:
                _jackett_cookie = await _jackett_login()
                _jackett_cookie_expiry = time.time() + 3600
        cookies = {"Jackett": _jackett_cookie}
    async with httpx.AsyncClient(cookies=cookies, timeout=15.0) as c:
        yield c


# ── SSE Helpers ───────────────────────────────────────────────────────────────

async def broadcast(event: str, data: dict) -> None:
    msg = f"event: {event}\ndata: {json.dumps(data)}\n\n"
    dead = []
    for q in state.sse_queues:
        try:
            q.put_nowait(msg)
        except asyncio.QueueFull:
            dead.append(q)
    for q in dead:
        state.sse_queues.remove(q)


def state_snapshot() -> dict:
    playlist = state.library_playlist
    current  = state.library_current_file
    try:
        cur_idx = playlist.index(current) if (current and current in playlist) else -1
    except (ValueError, AttributeError):
        cur_idx = -1
    # Window control pause: compute the live remaining seconds for the UI.
    # window_mgmt_paused() auto-expires a finished timed pause as a side effect.
    wm_until = state.window_mgmt_paused_until
    wm_paused = window_mgmt_paused()
    if not wm_paused:
        wm_remaining = 0                       # 0 ⇒ active (normal behaviour)
    elif wm_until == WINDOW_MGMT_PAUSE_INDEFINITE:
        wm_remaining = -1                      # -1 ⇒ paused until the user resumes
    else:
        wm_remaining = max(0, int(round(wm_until - time.time())))
    return {
        "vpn_secure": state.vpn_secure,
        "vpn_status": state.vpn_status_text,
        # Whether a VPN drop locks the whole UI (overlay) or only kills qBit.
        "vpn_block_ui": state.vpn_block_ui,
        "jackett_ok": state.jackett_ok,
        # Some configured indexers are failing while others work (set on search).
        # The user-facing banner only needs the boolean + counts — never the names.
        "indexers_degraded": state.indexers_degraded,
        "indexers_total": state.indexers_total,
        "indexers_failing": state.indexers_failing,
        "stream_status": state.stream_status,
        "active_title": state.active_title,
        "progress": round(state.progress, 2),
        "downloaded_mb": round(state.downloaded_mb, 2),
        "total_mb": round(state.total_mb, 2),
        "dl_speed_bps": state.dl_speed_bps,
        "ul_speed_bps": state.ul_speed_bps,
        # Only the count of downloads a non-elevated viewer is allowed to know
        # about — admin-locked items must leave NO trace (no badge, no count) for
        # profiles that can't see them. Internal busy/idle gating still reads the
        # true `state.downloading_count`. See docs/ADMIN.md § Content Lock.
        "downloading_count": state.downloading_count_visible,
        "vlc_time": state.vlc_time,
        "vlc_duration": state.vlc_duration,
        "vlc_volume": state.vlc_volume,
        # VLC night mode (compressor / dynamic-range reduction). Persisted global
        # setting, mirrored here so the fullscreen-control toggle reflects it.
        # The intensity preset is settings-menu only but rides along so the
        # picker stays in sync across clients.
        "vlc_night_mode": state.vlc_night_mode,
        "vlc_night_mode_preset": state.vlc_night_mode_preset,
        # Admin's preferred subtitle language ("" = Any); the dashboard uses it to
        # default the subtitle-search modal's language filter. See docs/API.md.
        "subtitle_default_language": state.subtitle_default_language,
        # Auto-upgrade AI subs → real subs when they arrive, and single-option
        # language assumption. The on-device player reads these to drive its
        # subtitle-upgrade poller. See docs/STT.md / docs/STREAMING.md.
        "subtitle_upgrade_late": state.subtitle_upgrade_late,
        "subtitle_single_option": state.subtitle_single_option,
        "library_playlist_count": len(playlist),
        "library_current_index": cur_idx,
        "library_current_file": current,
        "library_playlist": list(playlist),
        # Merged-series playback: path→owning-item map (empty for a normal play).
        # Lets a TV→device handoff carry the per-file item so the device re-targets
        # the active item across episode-torrents exactly as the TV does.
        "library_series_map": dict(state.library_series_map),
        # True while Shuffle Play is active (random episode order). Lets the UI
        # surface a "shuffle" badge; next/prev already follow the random order.
        "library_shuffle": bool(state.library_shuffle_order),
        # Scope of the live shuffle ("all" | "unwatched"), masked to "" when not
        # shuffling so a stale value can never leak. Lets a VLC→device handoff carry
        # the scope so the device's persisted Resume-on-shuffle pref stays accurate.
        "library_shuffle_scope": state.library_shuffle_scope if state.library_shuffle_order else "",
        "library_item_file_count": state.library_item_file_count,
        "is_library_playback": state.library_item_id is not None,
        "library_item_id": state.library_item_id,
        # Who started the active playback. Progress is always attributed to this
        # profile no matter who drives the shared VLC controls — the UI shows it
        # so other viewers know whose session/progress they're affecting.
        "library_profile_id": state.library_profile_id,
        "library_profile_name": state.library_profile_name,
        "library_profile_color": state.library_profile_color,
        "play_when_ready_item_id": state.play_when_ready_item_id,
        "play_when_ready_file_path": state.play_when_ready_file_path,
        "skip_offer": state.skip_offer,
        "skip_countdown": state.skip_countdown,
        "resume_offer": state.resume_offer,
        "analysis_jobs": state.analysis_jobs,
        # False on macOS hosts — the UI hides stream-to-device / Prep affordances.
        "hls_available": HLS_AVAILABLE,
        # True ⇒ whisper.cpp + a model are installed; drives the "Generate subtitles
        # (AI)" affordance in the subtitle menus. See docs/STT.md.
        "stt_available": _stt_available(),
        # True ⇒ bulk stream-prep is paused (drives the global prep bar's Resume control).
        "prep_paused": state.prep_paused,
        # Window control pause (non-admin "use the computer normally" override).
        # paused: idle background video + focus/minimize/fullscreen loops are
        # standing down. remaining: seconds left for a timed pause, -1 if until
        # the user resumes, 0 if active. See POST /api/window-control.
        "window_mgmt_paused": wm_paused,
        "window_mgmt_pause_remaining": wm_remaining,
        # Idle/night DOWNLOAD window: whether it's open right now, and whether any
        # admin prep window is even configured (so the UI can warn that an idle-only
        # download has no window to run in). See docs/STREAMING.md + the scheduler.
        "download_idle_open": state.download_idle_open,
        "download_idle_configured": state.download_idle_configured,
        # Host resource health (cpu/ram/gpu/net + overall ok|degraded|overloaded).
        # Drives the user "host busy" banner + the admin System health card.
        "sys_status": state.sys_status,
        # YouTube-on-TV: when active, the dashboard routes its player controls to
        # /api/youtube/control instead of VLC, and hides save/handoff/episode-nav.
        # active_title / vlc_time / vlc_duration / vlc_volume are reused for display,
        # populated from the /tv page's heartbeat (see /api/youtube/tv-state).
        "youtube_active": state.youtube_active,
        "youtube_video_id": state.youtube_video_id,
        # Env keys whose absence disables features. The non-admin UI shows a
        # passive banner ("server needs admin attention") when this is non-empty
        # AND any entry has `required=True`; the admin Updates tab renders the
        # full list as a fill-in form. Keep this cheap to compute — it runs on
        # every state broadcast.
        "missing_env_keys": _missing_env_keys(),
        # Auto-updater phase for the in-flight operation (idle when nothing
        # is happening). Persisted history lives in library.json — fetch
        # `/api/admin/updater` for the full record.
        "updater_phase":   state.updater_phase,
        "updater_busy":    state.updater_busy,
        "updater_message": state.updater_message,
    }


# ── Admin Auth ────────────────────────────────────────────────────────────────

def _check_admin(request: Request) -> bool:
    """Return True if the request carries a valid admin session token."""
    if not settings.admin_password:
        return False
    token: Optional[str] = None
    auth = request.headers.get("authorization", "")
    if auth.lower().startswith("bearer "):
        token = auth[7:].strip()
    if not token:
        token = request.headers.get("x-admin-token", "").strip() or None
    if not token:
        token = request.query_params.get("admin_token", "").strip() or None
    if not token or token not in _admin_sessions:
        return False
    if time.time() > _admin_sessions[token]:
        _admin_sessions.pop(token, None)
        return False
    return True


def _require_admin(request: Request) -> None:
    if not _check_admin(request):
        raise HTTPException(401, "Admin authentication required.")


def _request_bearer(request: Request) -> Optional[str]:
    """Pull a bearer token from Authorization / X-Device-Token / ?device_token."""
    auth = request.headers.get("authorization", "")
    if auth.lower().startswith("bearer "):
        tok = auth[7:].strip()
        if tok:
            return tok
    tok = request.headers.get("x-device-token", "").strip()
    if tok:
        return tok
    tok = request.query_params.get("device_token", "").strip()
    return tok or None


def _check_device_token(request: Request) -> bool:
    """True if the request carries a recognised paired-device token (M5)."""
    tok = _request_bearer(request)
    if not tok or tok not in _device_tokens:
        return False
    # Best-effort last-seen bookkeeping (not persisted on every hit to avoid I/O).
    _device_tokens[tok]["last_seen"] = _now_iso()
    return True


def _require_device_auth(request: Request) -> None:
    """Gate the device-facing endpoints (sync, bundle-manifest) when pairing is
    enforced. A valid admin session also passes (admin is a superset). When
    `require_device_auth` is off this is a no-op, so LAN / browser use is
    completely unaffected (the no-regression invariant)."""
    if not settings.require_device_auth:
        return
    if _check_device_token(request) or _check_admin(request):
        return
    raise HTTPException(401, "Device pairing required — pair this app with the host first.")


def _pin_hash(pin: str) -> str:
    return hashlib.sha256(pin.encode()).hexdigest()


# ── qBittorrent Client ────────────────────────────────────────────────────────

async def qbit_login() -> bool:
    try:
        r = await qbit.post(
            f"{settings.qbit_url}/api/v2/auth/login",
            data={"username": settings.qbit_username, "password": settings.qbit_password},
        )
        return r.text.strip() == "Ok."
    except Exception:
        return False


async def qreq(method: str, path: str, **kw) -> Optional[httpx.Response]:
    """Make an authenticated qBit API request, re-logging in on 403."""
    try:
        r = await qbit.request(method, f"{settings.qbit_url}{path}", **kw)
        if r.status_code == 403:
            await qbit_login()
            r = await qbit.request(method, f"{settings.qbit_url}{path}", **kw)
        return r
    except Exception:
        return None


async def qbit_add_magnet(
    magnet: str,
    save_path: Optional[str] = None,
    sequential: bool = False,
) -> Optional[str]:
    h = extract_hash(magnet)
    data: dict = {"urls": magnet, "savepath": save_path or settings.qbit_download_path}
    if sequential:
        # Set sequential download at add-time so it applies before any pieces download.
        # This is the qBittorrent /add API field, separate from the toggle endpoint.
        data["sequentialDownload"] = "true"
    r = await qreq("POST", "/api/v2/torrents/add", data=data)
    if r and r.text.strip() == "Ok.":
        return h
    # qBit replies "Fails." (HTTP 200) when it *rejects* the add — most commonly
    # because the torrent is ALREADY in the session (a duplicate add, a prior
    # errored attempt still present, or a torrent qBit already has on disk). That
    # is not a failure for us: we extracted the info-hash from the magnet, so if
    # qBit is already tracking that torrent we adopt it instead of orphaning the
    # caller's item as an un-hashed "error" while the file quietly downloads.
    # Only give up when the hash truly isn't present (genuine bad-magnet reject).
    if h:
        for _ in range(3):
            if await qbit_info(h):
                return h
            await asyncio.sleep(1)
    return None


async def qbit_set_file_priority(h: str, indices: list[int], priority: int) -> None:
    """Set qBit file priority for a list of file indices. priority 0=skip, 1=normal, 6=high."""
    if not indices:
        return
    await qreq(
        "POST", "/api/v2/torrents/filePrio",
        data={"hash": h, "id": "|".join(str(i) for i in indices), "priority": str(priority)},
    )


async def qbit_streaming_mode(h: str) -> None:
    """Ensure sequential download is on.

    The correct API endpoint is toggleSequentialDownload (not setSequentialDownload,
    which does not exist).  Because it is a toggle, we read seq_dl from torrent info
    first and only call it when sequential is currently off.  This is a belt-and-
    suspenders check — sequential=true is already passed at add-time via qbit_add_magnet.
    """
    info = await qbit_info(h)
    if info is not None and not info.get("seq_dl", False):
        await qreq("POST", "/api/v2/torrents/toggleSequentialDownload",
                   data={"hashes": h})


async def qbit_info(h: str) -> Optional[dict]:
    r = await qreq("GET", f"/api/v2/torrents/info?hashes={h}")
    if r and r.status_code == 200:
        data = r.json()
        return data[0] if data else None
    return None


async def qbit_info_all() -> Optional[list]:
    """Every torrent qBit currently tracks (no `hashes` filter ⇒ the full list).
    Returns None when qBit is unreachable (so callers can show an offline state),
    and [] for a reachable-but-empty client."""
    r = await qreq("GET", "/api/v2/torrents/info")
    if r and r.status_code == 200:
        return r.json()
    return None


async def qbit_files(h: str) -> list:
    r = await qreq("GET", f"/api/v2/torrents/files?hash={h}")
    return r.json() if (r and r.status_code == 200) else []


async def qbit_delete(h: str, delete_files: bool = True) -> None:
    await qreq("POST", "/api/v2/torrents/delete",
                data={"hashes": h, "deleteFiles": "true" if delete_files else "false"})


async def qbit_recheck(h: str) -> None:
    """Force a piece-level recheck of a torrent (re-verifies every downloaded piece
    against the .torrent hashes). qBit re-fetches any piece that fails. Operates on
    whole torrents — there is no per-file recheck in the qBit API."""
    await qreq("POST", "/api/v2/torrents/recheck", data={"hashes": h})


async def qbit_set_location(h: str, location: str) -> bool:
    """Relocate a torrent's content to `location` and keep seeding from there.
    qBit physically moves the existing data and re-points its save path. Returns
    True on a 2xx. (qBit returns 409 if the path can't be created/written.)"""
    r = await qreq("POST", "/api/v2/torrents/setLocation",
                   data={"hashes": h, "location": location})
    return bool(r is not None and 200 <= r.status_code < 300)


async def qbit_pause(h: str) -> None:
    """Pause a torrent. qBittorrent 5.x renamed pause→stop; /pause still works there
    as a deprecated alias, but fall back to /stop on a 404 to stay correct on the
    Windows builds the box ships with (Windows is the primary target)."""
    r = await qreq("POST", "/api/v2/torrents/pause", data={"hashes": h})
    if r is None or r.status_code == 404:
        await qreq("POST", "/api/v2/torrents/stop", data={"hashes": h})


async def qbit_resume(h: str) -> None:
    """Resume a torrent. See qbit_pause for the 5.x /start fallback."""
    r = await qreq("POST", "/api/v2/torrents/resume", data={"hashes": h})
    if r is None or r.status_code == 404:
        await qreq("POST", "/api/v2/torrents/start", data={"hashes": h})


async def qbit_get_preferences() -> Optional[dict]:
    """Read qBittorrent's global application preferences (JSON dict), or None."""
    r = await qreq("GET", "/api/v2/app/preferences")
    if r and r.status_code == 200:
        try:
            return r.json()
        except Exception:
            return None
    return None


async def qbit_set_preferences(prefs: dict) -> bool:
    """Merge a partial set of global preferences into qBittorrent. qBit persists
    these in its own config, so they survive a qBit (or host) restart."""
    r = await qreq("POST", "/api/v2/app/setPreferences",
                   data={"json": json.dumps(prefs)})
    return bool(r and 200 <= r.status_code < 300)


async def qbit_get_speed_limit(kind: str) -> int:
    """Current global speed limit in bytes/sec (0 = unlimited). kind ∈ download|upload.
    Uses the transfer/*Limit endpoints, which are unambiguously bytes/sec — the
    app/preferences dl_limit/up_limit fields have a KiB-vs-bytes ambiguity across
    qBit versions, so we avoid them for speeds."""
    r = await qreq("GET", f"/api/v2/transfer/{kind}Limit")
    if r and r.status_code == 200:
        try:
            return max(0, int(r.text.strip()))
        except Exception:
            return 0
    return 0


async def qbit_set_speed_limit(kind: str, limit_bytes: int) -> bool:
    """Set the global speed limit in bytes/sec (0 = unlimited). kind ∈ download|upload."""
    verb = "setDownloadLimit" if kind == "download" else "setUploadLimit"
    r = await qreq("POST", f"/api/v2/transfer/{verb}",
                   data={"limit": str(max(0, int(limit_bytes)))})
    return bool(r and 200 <= r.status_code < 300)


async def qbit_global_limits() -> dict:
    """Snapshot qBittorrent's global seeding-ratio + speed limits for the admin UI.
    Returns {ok: False} when qBit is unreachable (the card shows an offline note)."""
    prefs = await qbit_get_preferences()
    if prefs is None:
        return {"ok": False}
    try:
        ratio = float(prefs.get("max_ratio", 1.0))
    except (TypeError, ValueError):
        ratio = 1.0
    if ratio < 0:
        ratio = 1.0   # qBit stores -1 when never set; show a sane default in the box
    return {
        "ok": True,
        "ratio_enabled":  bool(prefs.get("max_ratio_enabled", False)),
        "ratio":          round(ratio, 2),
        "dl_limit_bytes": await qbit_get_speed_limit("download"),
        "up_limit_bytes": await qbit_get_speed_limit("upload"),
    }


# ── VLC Client ────────────────────────────────────────────────────────────────

def _vlc_http() -> httpx.AsyncClient:
    """Return the shared, persistent VLC HTTP client (keep-alive connection pool).

    VLC's built-in HTTP interface is a tiny, effectively single-threaded server.
    Opening a *fresh* TCP connection on every call — which the old per-call
    `httpx.AsyncClient()` did — swamps its accept path: three background loops
    (`stat_broadcaster`, `vlc_progress_tracker`, `background_video_loop`) each
    poll every 2–3 s, and a play fires several commands in a burst, so VLC is
    constantly tearing down and re-establishing sockets and every call ends up
    taking seconds. One keep-alive client amortizes the connect across all calls
    (a warm connection from the polling loops is almost always already in the
    pool when a play starts), so commands and status reads stay sub-second.

    Created in `lifespan`; lazily built here too so any call that runs before
    startup finishes (or in a stray task) still works. `base_url` + client-level
    `auth` mean callers pass only the relative path.
    """
    global vlc_client
    if vlc_client is None or vlc_client.is_closed:
        vlc_client = httpx.AsyncClient(
            base_url=settings.vlc_url,
            auth=httpx.BasicAuth("", settings.vlc_password),
            timeout=httpx.Timeout(5.0, connect=2.0),
            limits=httpx.Limits(max_connections=4, max_keepalive_connections=4, keepalive_expiry=30.0),
        )
    return vlc_client


async def vlc(command: str, **params) -> None:
    try:
        c = _vlc_http()
        if command == "in_play":
            # Real content is taking the screen — the TV UI kiosk (if up) loses
            # it, and every focus assertion may again bring VLC forward. Must
            # happen before the play paths' vlc_focus_and_fullscreen() tasks
            # run their first tv_ui_active check. (The bg video bypasses vlc()
            # and posts in_play directly, so it never trips this.)
            state.tv_ui_active = False
            # User content is taking over from the idle background video —
            # restore the volume the user had before bg took the floor.
            if state.background_playing:
                state.vlc_volume = state.user_volume_before_bg
                state.background_playing = False
            # Clamp by the current max-volume cap. state.vlc_volume can drift
            # above the cap: it's polled directly from VLC's reported volume
            # (which is 100 at fresh start) and the user_volume_before_bg
            # snapshot may have been taken before the cap was lowered. Without
            # this clamp, in_play would blast at >cap until the user nudged
            # the slider and tripped the server-side clamp.
            cap = await _global_max_volume()
            state.vlc_volume = max(0, min(cap, state.vlc_volume))
            raw = max(0, min(512, round(state.vlc_volume / 100 * 256)))
            await c.get(
                "/requests/status.xml",
                params={"command": "volume", "val": str(raw)},
            )
        await c.get(
            "/requests/status.xml",
            params={"command": command, **params},
        )
    except Exception:
        pass


async def vlc_clear_playlist() -> None:
    """Empty VLC's playlist (`pl_empty`).

    VLC's HTTP `in_play` *appends* the input to the playlist and plays it — it
    never clears what's already there. So across a session VLC's playlist
    silently grows: `[bg, epA, epB, epC, …]`. Two failure modes follow from the
    leftover items, both of which look like "the wrong thing plays":

    1. `in_play` of a URI already in the playlist plays that *existing* entry
       (often mid-list). When it ends VLC auto-advances to the item after it —
       e.g. replaying the bg video (already at index 0 from an earlier idle
       period) ends and VLC advances into a stale episode → after **Stop** an
       episode plays instead of the background video.
    2. A stale bg/episode entry left in the list can win an end-of-file
       auto-advance during a prev/next transition → the background video plays
       instead of the next episode.

    Calling this immediately *before* every fresh `in_play` keeps VLC's playlist
    a faithful mirror of `state.library_playlist` (or just the bg video), so the
    only auto-advance target is the intended tail. See docs/GOTCHAS.md.
    """
    await vlc("pl_empty")


async def vlc_status() -> Optional[dict]:
    """Return VLC's current status JSON (includes 'time' and 'length' in seconds)."""
    try:
        r = await _vlc_http().get("/requests/status.json", timeout=3.0)
        if r.status_code == 200:
            return r.json()
    except Exception:
        pass
    return None



async def vlc_playlist_uri() -> Optional[str]:
    """Return the file:// URI of the currently active VLC playlist item."""
    try:
        r = await _vlc_http().get("/requests/playlist.json", timeout=3.0)
        if r.status_code == 200:
            def _find_current(node: dict) -> Optional[str]:
                if node.get("current") == "current":
                    return node.get("uri")
                for child in node.get("children", []):
                    found = _find_current(child)
                    if found:
                        return found
                return None
            return _find_current(r.json())
    except Exception:
        pass
    return None


def uri_to_path(uri: str) -> str:
    """Convert a file:// URI back to an absolute file path."""
    path = unquote(urlparse(uri).path)
    if platform.system() == "Windows":
        path = path.lstrip("/")
    return path


def vlc_file_uri(p: Path) -> str:
    """Build the file:// URI handed to VLC as an input MRL. Use this — never
    `.resolve().as_uri()` directly — for anything VLC must open.

    Equivalent to `Path.resolve().as_uri()` everywhere except Windows paths at
    or over MAX_PATH: VLC opens file inputs with the plain Win32 API (no `\\\\?\\`
    extended-length prefix), so a 260+-character path fails with "unable to open
    the MRL" even though the file exists (qBittorrent can WRITE such files — it
    uses extended-length paths internally; long multi-episode filenames are the
    usual culprit). For those, substitute the 8.3 short form (GetShortPathNameW),
    which stays under the limit. Round-tripping is safe: everything that maps
    VLC's reported URI back to a library path goes through `Path.resolve()`,
    which expands short names to the canonical long path. Falls back to the
    long URI (and logs) if 8.3 names are disabled on the volume.
    """
    try:
        rp = p.resolve()
    except Exception:
        rp = p
    sp = str(rp)
    if platform.system() == "Windows" and len(sp) > 259:
        try:
            import ctypes
            # \\?\ prefix so the lookup itself accepts the over-long input.
            src = sp if sp.startswith("\\\\?\\") else "\\\\?\\" + sp
            need = ctypes.windll.kernel32.GetShortPathNameW(src, None, 0)
            if need:
                buf = ctypes.create_unicode_buffer(need)
                if ctypes.windll.kernel32.GetShortPathNameW(src, buf, need):
                    short = buf.value
                    if short.startswith("\\\\?\\"):
                        short = short[4:]
                    if short and len(short) <= 259:
                        return Path(short).as_uri()
            print(f"[vlc] WARNING: path exceeds MAX_PATH and has no 8.3 short name — "
                  f"VLC will likely fail to open it: {sp}")
        except Exception as exc:
            print(f"[vlc] short-path conversion failed for over-long path ({exc}): {sp}")
    return rp.as_uri()


# ── Subtitle Download (OpenSubtitles) ─────────────────────────────────────────

def _opensubtitles_hash(path: Path) -> Optional[str]:
    """Compute the OpenSubtitles movie hash: 64-bit sum of filesize + first 64 KB
    + last 64 KB, read as little-endian 8-byte ints. Returns 16-char hex."""
    try:
        fmt = "<q"
        chunk = 65536
        bsize = struct.calcsize(fmt)
        filesize = path.stat().st_size
        if filesize < chunk * 2:
            return None
        h = filesize
        with path.open("rb") as f:
            for _ in range(chunk // bsize):
                (val,) = struct.unpack(fmt, f.read(bsize))
                h = (h + val) & 0xFFFFFFFFFFFFFFFF
            f.seek(filesize - chunk, 0)
            for _ in range(chunk // bsize):
                (val,) = struct.unpack(fmt, f.read(bsize))
                h = (h + val) & 0xFFFFFFFFFFFFFFFF
        return f"{h:016x}"
    except Exception:
        return None


async def _current_playback_path() -> Optional[Path]:
    """Resolve the file VLC is actually playing, regardless of how it started."""
    uri = await vlc_playlist_uri()
    if uri and uri.startswith("file:"):
        try:
            p = Path(uri_to_path(uri))
            if p.exists():
                return p
        except Exception:
            pass
    for cand in (state.library_current_file, state.active_file):
        if cand:
            try:
                p = Path(cand)
                if p.exists():
                    return p
            except Exception:
                pass
    return None


def _trim_subtitle_result(s: dict) -> dict:
    return {
        "name": s.get("SubFileName") or s.get("MovieReleaseName") or "subtitle",
        "lang": s.get("ISO639") or "",
        "lang_name": s.get("LanguageName") or s.get("SubLanguageID") or "Unknown",
        "downloads": int(s.get("SubDownloadsCount") or 0),
        "matched_by": s.get("MatchedBy") or "",
        "release": s.get("MovieReleaseName") or "",
        "download_link": s.get("SubDownloadLink") or "",
    }


async def _opensubtitles_search(
    file_hash: Optional[str], file_size: Optional[int],
    query: str, lang: str,
) -> list[dict]:
    """Query the keyless rest.opensubtitles.org API by hash and/or text. Hash
    matches are exact; text matches are a fallback. Results are merged."""
    headers = {
        "User-Agent": settings.opensubtitles_user_agent,
        "X-User-Agent": settings.opensubtitles_user_agent,
    }
    lang_seg = f"/sublanguageid-{quote(lang)}" if lang else ""
    urls: list[str] = []
    if file_hash and file_size:
        urls.append(
            f"https://rest.opensubtitles.org/search"
            f"/moviebytesize-{file_size}/moviehash-{file_hash}{lang_seg}"
        )
    if query:
        urls.append(
            f"https://rest.opensubtitles.org/search/query-{quote(query)}{lang_seg}"
        )
    raw: list[dict] = []
    async with httpx.AsyncClient(timeout=20.0, follow_redirects=True) as c:
        for url in urls:
            try:
                r = await c.get(url, headers=headers)
                if r.status_code == 200 and isinstance(r.json(), list):
                    raw.extend(r.json())
            except Exception:
                pass
    # Dedup by download link, prefer hash matches, then by download count
    seen: set[str] = set()
    trimmed: list[dict] = []
    for s in raw:
        t = _trim_subtitle_result(s)
        link = t["download_link"]
        if not link or link in seen:
            continue
        seen.add(link)
        trimmed.append(t)
    trimmed.sort(
        key=lambda t: (0 if t["matched_by"] == "moviehash" else 1, -t["downloads"])
    )
    return trimmed[:40]


# ── TMDb (show / episode metadata) ────────────────────────────────────────────
#
# Optional integration. Provides episode titles, overviews, posters, and stills
# for the Netflix-style episode picker. Requires a free TMDb v3 API key.
#
# Configure via `TMDB_API_KEY` in .env or via the admin panel (overrides .env).
# All metadata is cached on the library item under `item["metadata"]` so the
# UI loads instantly after the first fetch.

TMDB_IMG_BASE = "https://image.tmdb.org/t/p"

# Host-relative image base handed to clients instead of TMDB_IMG_BASE. Routes
# through /api/metadata/img/{size}/{filename}, which serves from the on-disk
# cache first — so artwork keeps working on the LAN when the internet is down.
LOCAL_IMG_BASE = "/api/metadata/img"

# On-disk cache for TMDb artwork (posters/backdrops/stills). TMDb image paths
# are content-addressed, so entries never go stale and are kept forever.
TMDB_IMG_CACHE = Path(__file__).parent / ".tmdb_img_cache"
_TMDB_IMG_SIZES = {"w92", "w154", "w185", "w300", "w342", "w500", "w780",
                   "w1280", "original"}
_TMDB_IMG_FILE_RE = re.compile(r"^[A-Za-z0-9_-]+\.(?:jpg|jpeg|png|svg)$")
_TMDB_IMG_CT = {".jpg": "image/jpeg", ".jpeg": "image/jpeg",
                ".png": "image/png", ".svg": "image/svg+xml"}

_tmdb_fetch_locks: dict[str, asyncio.Lock] = {}
# item_id → in-flight background fetch task (see _spawn_metadata_fetch).
_tmdb_fetch_tasks: dict[str, "asyncio.Task[Optional[dict]]"] = {}

# Fire-and-forget tasks need a strong reference until they finish — a bare
# asyncio.create_task() result can be garbage-collected mid-flight.
_tmdb_bg_tasks: set = set()


def _tmdb_bg(coro) -> None:
    t = asyncio.create_task(coro)
    _tmdb_bg_tasks.add(t)
    t.add_done_callback(_tmdb_bg_tasks.discard)


async def _tmdb_img_bytes(size: str, filename: str,
                          fetch: bool = True) -> Optional[tuple[bytes, str]]:
    """Return (bytes, content_type) for a TMDb image, serving the on-disk cache
    first and (optionally) fetching + caching from TMDb on a miss. Returns None
    when the image isn't cached and can't be fetched (e.g. internet down).
    `size`/`filename` must already be validated against the whitelists above."""
    ext = Path(filename).suffix.lower()
    ct = _TMDB_IMG_CT.get(ext, "image/jpeg")
    cache_file = TMDB_IMG_CACHE / size / filename
    try:
        if cache_file.exists():
            return cache_file.read_bytes(), ct
    except Exception:
        pass
    if not fetch:
        return None
    try:
        url = f"{TMDB_IMG_BASE}/{size}/{filename}"
        async with httpx.AsyncClient(timeout=httpx.Timeout(12.0, connect=5.0),
                                     follow_redirects=True) as c:
            r = await c.get(url)
        if r.status_code == 200 and r.content:
            try:
                cache_file.parent.mkdir(parents=True, exist_ok=True)
                # Atomic write so a concurrent reader never sees a torn file.
                tmp = cache_file.with_suffix(cache_file.suffix + f".{os.getpid()}.tmp")
                tmp.write_bytes(r.content)
                os.replace(tmp, cache_file)
            except Exception:
                pass
            return r.content, ct
    except Exception:
        pass
    return None


async def _prefetch_metadata_images(data: dict) -> None:
    """Best-effort warm of the artwork cache right after a metadata fetch, so
    posters/backdrops/stills survive a later internet outage. Sizes mirror what
    the frontend requests (w342 poster, w1280 backdrop, w300 stills)."""
    wanted: list[tuple[str, str]] = []
    if data.get("poster_path"):
        wanted.append(("w342", data["poster_path"]))
    if data.get("backdrop_path"):
        wanted.append(("w1280", data["backdrop_path"]))
    for s in (data.get("seasons") or {}).values():
        if s.get("poster_path"):
            wanted.append(("w342", s["poster_path"]))
        for ep in s.get("episodes", []) or []:
            if ep.get("still_path"):
                wanted.append(("w300", ep["still_path"]))
    for size, path in wanted:
        fn = path.lstrip("/")
        if not _TMDB_IMG_FILE_RE.match(fn):
            continue
        try:
            await _tmdb_img_bytes(size, fn)
        except Exception:
            pass


async def _tmdb_effective_key() -> str:
    """Resolve the active TMDb API key. Admin override beats .env."""
    lib = await get_library()
    override = (
        lib.get("settings", {})
           .get("admin_overrides", {})
           .get("tmdb_api_key", "")
    )
    return (override or settings.tmdb_api_key or "").strip()


async def _tmdb_get(path: str, params: Optional[dict] = None) -> Optional[dict]:
    key = await _tmdb_effective_key()
    if not key:
        return None
    q = dict(params or {})
    q["api_key"] = key
    url = f"https://api.themoviedb.org/3{path}"
    try:
        # Short connect timeout so a dead/unreachable internet link fails fast
        # (the read timeout stays generous for slow-but-working networks).
        async with httpx.AsyncClient(timeout=httpx.Timeout(15.0, connect=5.0)) as c:
            r = await c.get(url, params=q)
            if r.status_code == 200:
                return r.json()
    except Exception:
        pass
    return None


_YEAR_RE = re.compile(r"\b(19|20)\d{2}\b")


def _strip_release_tags(name: str) -> str:
    """Strip common release/quality tags from a torrent title so a TMDb search
    has a shot at matching the canonical show name."""
    if not name:
        return ""
    s = name
    s = re.sub(r"\[[^\]]*\]", " ", s)
    s = re.sub(r"\([^)]*\)", " ", s)
    s = re.sub(
        r"\b(2160p|1080p|720p|480p|4K|UHD|BluRay|BDRip|BRRip|DVDRip|WEB-?DL|WEBRip|"
        r"HDTV|HDR|HDR10|HEVC|x264|x265|H\.?264|H\.?265|AAC|AC3|DTS|FLAC|EAC3|"
        r"REMUX|REPACK|PROPER|EXTENDED|UNRATED|MULTi|DUAL|SUBBED|DUBBED|BATCH|"
        r"VOSTFR|SUBFRENCH|\d{1,2}[ -]?bit|"
        r"COMPLETE|S\d{1,2}|Season\s*\d{1,2}|E\d{1,3})\b.*",
        " ", s, flags=re.IGNORECASE,
    )
    s = re.sub(r"[._\-]+", " ", s)
    s = re.sub(r"\s+", " ", s).strip(" -_.")
    return s


def _search_terms_for_item(item: dict) -> tuple[str, Optional[int]]:
    """Build (query, year_hint?) for TMDb search from a library item."""
    series = (item.get("series") or "").strip()
    title  = (item.get("title")  or "").strip()
    raw    = series or title
    # Strip a trailing "S01" off the series field (it's how we group entries)
    raw = re.sub(r"\s*S\d{1,2}\s*$", "", raw, flags=re.IGNORECASE)
    cleaned = _strip_release_tags(raw)
    year_m = _YEAR_RE.search(title)
    year = int(year_m.group(0)) if year_m else None
    return cleaned, year


# Country/region suffixes torrent titles append but TMDb usually omits from the
# canonical show name (e.g. "Big Brother US" → TMDb "Big Brother"). Used only for
# match scoring, never to alter the search query we send.
_TMDB_COUNTRY_SUFFIXES = {"us", "usa", "uk", "gb", "au", "aus", "ca", "nz"}


def _tmdb_norm_title(s: str) -> str:
    """Lowercase, strip punctuation, collapse whitespace, and drop a trailing
    country code so 'Big Brother US' and 'Big Brother' normalise equal."""
    s = re.sub(r"[^\w\s]", " ", (s or "").lower())
    s = re.sub(r"\s+", " ", s).strip()
    toks = s.split()
    if len(toks) > 1 and toks[-1] in _TMDB_COUNTRY_SUFFIXES:
        toks = toks[:-1]
    return " ".join(toks)


def _tmdb_pick_tv(query: str, results: list[dict]) -> Optional[dict]:
    """Choose the best TV match from a TMDb /search/tv result set.

    TMDb's text ranking sometimes floats a low-signal partial match above the
    obvious show — e.g. `query="Big Brother US"` returns "Celebrity Big Brother"
    (popularity 3.7) ahead of the canonical "Big Brother" (popularity 68, 28
    seasons). Blindly taking results[0] then binds the wrong show and only its
    handful of seasons ever surface. We score by title-match tier first, then
    break ties by popularity, so the canonical show wins."""
    if not results:
        return None
    q = _tmdb_norm_title(query)

    def score(r: dict) -> tuple[int, float]:
        name = _tmdb_norm_title(r.get("name") or r.get("original_name") or "")
        if name == q:                       tier = 3   # exact (after country-strip)
        elif q and name.startswith(q):      tier = 2   # candidate extends the query
        elif q and q in name:               tier = 1   # query appears inside candidate
        elif name and q.startswith(name):   tier = 1   # candidate is a prefix of query
        else:                               tier = 0
        return (tier, float(r.get("popularity") or 0))

    return max(results, key=score)


async def _tmdb_match_show(item: dict) -> Optional[dict]:
    """Find the most plausible TMDb TV show for this library item. Movies are
    treated as one-shot items and matched via /search/movie when there's only
    one file and no season info."""
    query, year = _search_terms_for_item(item)
    if not query:
        return None

    files = item.get("files", [])
    is_movieish = len(files) <= 1 and not item.get("season")

    # TV first — most of our library is series.
    tv = await _tmdb_get("/search/tv", {"query": query, "include_adult": "false"})
    tv_results = (tv or {}).get("results", []) or []
    # Score by title-match tier + popularity rather than trusting TMDb's raw
    # ranking (which can float a low-signal partial above the obvious show).
    if tv_results and not is_movieish:
        r = _tmdb_pick_tv(query, tv_results)
        return {"kind": "tv", "id": r["id"], "raw": r}

    if is_movieish:
        movie = await _tmdb_get(
            "/search/movie",
            {"query": query, "include_adult": "false",
             **({"year": year} if year else {})},
        )
        mv_results = (movie or {}).get("results", []) or []
        if mv_results:
            r = mv_results[0]
            return {"kind": "movie", "id": r["id"], "raw": r}

    # Fall back to the TV result for series-shaped items even if movieish failed
    if tv_results:
        r = _tmdb_pick_tv(query, tv_results)
        return {"kind": "tv", "id": r["id"], "raw": r}
    return None


_TMDB_LATIN_RE = re.compile(r"[A-Za-z]")


def _tmdb_akas(alt_results: list, primary: str, original: str) -> list[str]:
    """Latin-script alternative titles for a show/movie, for cross-language
    search + relevance (e.g. an anime indexed under its romaji name as well as
    its English title). Romaji / JP-region titles are ordered first (they're what
    the torrent scene tends to use), the English `primary` and non-Latin (CJK)
    names are dropped — our tokenizer can't score CJK anyway. Capped so the show
    page fires only a couple of extra queries."""
    seen = {(primary or "").strip().lower()}
    prefer: list[str] = []
    rest: list[str] = []
    def _add(t: str, bucket: list) -> None:
        t = (t or "").strip()
        if not t or not _TMDB_LATIN_RE.search(t):
            return
        k = t.lower()
        if k in seen:
            return
        seen.add(k)
        bucket.append(t)
    for a in alt_results or []:
        t = a.get("title") or ""
        romaji = (a.get("iso_3166_1") == "JP"
                  or "roman" in (a.get("type") or "").lower())
        _add(t, prefer if romaji else rest)
    _add(original, rest)   # original_name, only if it's already Latin script
    return (prefer + rest)[:6]


async def _tmdb_fetch_tv(show_id: int, seasons: list[int]) -> dict:
    """Fetch show details + each requested season's episodes. Returns the
    cache-shaped dict (see _build_metadata_cache)."""
    details = await _tmdb_get(
        f"/tv/{show_id}", {"append_to_response": "alternative_titles"}) or {}
    akas = _tmdb_akas((details.get("alternative_titles") or {}).get("results", []),
                      details.get("name") or "", details.get("original_name") or "")
    cache_seasons: dict[str, dict] = {}
    # Default to season 1 if no seasons were detected on disk (so a one-off
    # picker that opens before season parsing still gets *something*).
    if not seasons:
        seasons = [1]
    for sn in seasons:
        s = await _tmdb_get(f"/tv/{show_id}/season/{sn}", {}) or {}
        eps = []
        for ep in s.get("episodes", []) or []:
            eps.append({
                "season":      ep.get("season_number", sn),
                "episode":     ep.get("episode_number", 0),
                "name":        ep.get("name", "") or "",
                "overview":    ep.get("overview", "") or "",
                "still_path":  ep.get("still_path") or "",
                "air_date":    ep.get("air_date", "") or "",
                "runtime":     ep.get("runtime") or 0,
            })
        if eps or s.get("name"):
            cache_seasons[str(sn)] = {
                "name":     s.get("name", f"Season {sn}"),
                "overview": s.get("overview", "") or "",
                "poster_path": s.get("poster_path") or "",
                "episodes": eps,
            }
    return {
        "tmdb_id":       show_id,
        "tmdb_kind":     "tv",
        "title":         details.get("name") or "",
        "original_language": details.get("original_language") or "",
        "original_title": details.get("original_name") or "",
        "aka":           akas,
        "overview":      details.get("overview") or "",
        "poster_path":   details.get("poster_path") or "",
        "backdrop_path": details.get("backdrop_path") or "",
        "first_air_date": details.get("first_air_date") or "",
        "vote_average":  details.get("vote_average") or 0,
        "genres":        [g.get("name", "") for g in details.get("genres", []) or []],
        "seasons":       cache_seasons,
        "fetched_at":    _now_iso(),
    }


async def _tmdb_fetch_movie(movie_id: int) -> dict:
    details = await _tmdb_get(
        f"/movie/{movie_id}", {"append_to_response": "alternative_titles"}) or {}
    akas = _tmdb_akas((details.get("alternative_titles") or {}).get("titles", []),
                      details.get("title") or "", details.get("original_title") or "")
    return {
        "tmdb_id":       movie_id,
        "tmdb_kind":     "movie",
        "title":         details.get("title") or "",
        "original_language": details.get("original_language") or "",
        "original_title": details.get("original_title") or "",
        "aka":           akas,
        "overview":      details.get("overview") or "",
        "poster_path":   details.get("poster_path") or "",
        "backdrop_path": details.get("backdrop_path") or "",
        "release_date":  details.get("release_date") or "",
        "vote_average":  details.get("vote_average") or 0,
        "runtime":       details.get("runtime") or 0,
        "genres":        [g.get("name", "") for g in details.get("genres", []) or []],
        "seasons":       {},
        "fetched_at":    _now_iso(),
    }


async def _fetch_item_metadata(item_id: str, force: bool = False,
                                override_tmdb_id: Optional[int] = None,
                                override_kind: Optional[str] = None) -> Optional[dict]:
    """Match an item against TMDb and cache the result on the item. Coalesces
    concurrent fetches for the same item via a per-id lock."""
    if not await _tmdb_effective_key():
        return None

    lock = _tmdb_fetch_locks.setdefault(item_id, asyncio.Lock())
    async with lock:
        lib = await get_library()
        item = next((it for it in lib["items"] if it["id"] == item_id), None)
        if not item:
            return None
        cached = item.get("metadata") or {}
        # Manual picks / hand-entered custom metadata are pinned — never let a
        # plain (non-forced) access silently re-run the auto-match over them.
        # Custom entries have no tmdb_id, so this is the guard that protects them.
        if cached.get("source") in ("manual", "custom") and not force:
            return cached
        if cached.get("tmdb_id") and not force and not override_tmdb_id:
            return cached

        if override_tmdb_id and override_kind:
            match = {"kind": override_kind, "id": int(override_tmdb_id)}
        else:
            match = await _tmdb_match_show(item)
        if not match:
            return None

        seasons = sorted({
            int(f.get("season", 0)) for f in item.get("files", [])
            if int(f.get("season", 0)) > 0
        })

        if match["kind"] == "tv":
            data = await _tmdb_fetch_tv(match["id"], seasons)
        else:
            data = await _tmdb_fetch_movie(match["id"])

        # Record how this binding was chosen. A user-forced override is a
        # deliberate "manual" pick and is pinned (see the early-return guard
        # above and the rename handler); an auto-match is plain "tmdb".
        data["source"] = "manual" if override_tmdb_id else "tmdb"

        # Re-read the library before writing — analyzer / progress writers may
        # have updated other fields while we were fetching from TMDb.
        lib2 = await get_library()
        it2 = next((x for x in lib2["items"] if x["id"] == item_id), None)
        if it2:
            it2["metadata"] = data
            await put_library(lib2)
        # Warm the artwork cache in the background so posters/backdrops/stills
        # keep rendering for every client even if the internet later drops.
        _tmdb_bg(_prefetch_metadata_images(data))
        return data


def _spawn_metadata_fetch(item_id: str) -> "asyncio.Task[Optional[dict]]":
    """Start (or join) a background `_fetch_item_metadata` for an item. The GET
    /metadata endpoint waits on this only briefly — on a slow/dead internet link
    it returns `pending` and the task keeps running; when the fetch eventually
    lands, a `metadata_update` SSE event tells open clients to re-pull."""
    task = _tmdb_fetch_tasks.get(item_id)
    if task and not task.done():
        return task

    async def _run() -> Optional[dict]:
        try:
            return await _fetch_item_metadata(item_id)
        finally:
            _tmdb_fetch_tasks.pop(item_id, None)

    task = asyncio.create_task(_run())

    def _notify(t: "asyncio.Task[Optional[dict]]") -> None:
        try:
            if not t.cancelled() and not t.exception() and t.result():
                _tmdb_bg(broadcast("metadata_update", {"item_id": item_id}))
        except Exception:
            pass

    task.add_done_callback(_notify)
    _tmdb_fetch_tasks[item_id] = task
    return task


def _find_vlc_bin() -> Optional[str]:
    """Locate the VLC binary, checking .env first then well-known paths."""
    env_file = Path(__file__).parent / ".env"
    if env_file.exists():
        for line in env_file.read_text(encoding="utf-8", errors="replace").splitlines():
            line = line.strip()
            if line.startswith("_VLC_BIN="):
                val = line[9:].strip()
                if val and Path(val).exists():
                    return val
    candidates: list[str] = {
        "Darwin":  ["/Applications/VLC.app/Contents/MacOS/VLC"],
        "Windows": [
            r"C:\Program Files\VideoLAN\VLC\vlc.exe",
            r"C:\Program Files (x86)\VideoLAN\VLC\vlc.exe",
        ],
    }.get(platform.system(), ["/usr/bin/vlc"])
    for c in candidates:
        if Path(c).exists():
            return c
    return shutil.which("vlc")


def _find_vlc_hwnds_windows() -> list:
    """Return all visible top-level window handles belonging to any VLC process.

    Uses psutil for PID lookup + GetWindowThreadProcessId for matching.
    The cb variable keeps the EnumWindowsProc wrapper alive to prevent ctypes GC.
    """
    try:
        import ctypes
        from ctypes import wintypes

        vlc_pids: set = set()
        for p in psutil.process_iter(["name", "pid"]):
            if (p.info["name"] or "").lower().startswith("vlc"):
                vlc_pids.add(p.info["pid"])
        if not vlc_pids:
            return []

        user32 = ctypes.windll.user32
        found: list = []
        EnumWindowsProc = ctypes.WINFUNCTYPE(ctypes.c_bool, wintypes.HWND, wintypes.LPARAM)

        def _cb(hwnd, _):
            if user32.IsWindowVisible(hwnd):
                pid = wintypes.DWORD()
                user32.GetWindowThreadProcessId(hwnd, ctypes.byref(pid))
                if pid.value in vlc_pids:
                    found.append(hwnd)
            return True

        cb = EnumWindowsProc(_cb)   # keep ref alive — ctypes GC pitfall
        user32.EnumWindows(cb, 0)
        return found
    except Exception:
        return []


def _stop_vlc_flash_windows() -> None:
    """Clear any taskbar attention flash on all VLC windows.

    When Windows blocks SetForegroundWindow (focus-stealing prevention), it
    falls back to flashing the target's taskbar icon — and a flashing icon
    forces the taskbar to stay visible even over a fullscreen window. Calling
    FlashWindowEx with FLASHW_STOP cancels that attention state.
    """
    hwnds = _find_vlc_hwnds_windows()
    if not hwnds:
        return
    try:
        import ctypes
        from ctypes import wintypes

        class FLASHWINFO(ctypes.Structure):
            _fields_ = [
                ("cbSize", ctypes.c_uint),
                ("hwnd", wintypes.HWND),
                ("dwFlags", wintypes.DWORD),
                ("uCount", wintypes.UINT),
                ("dwTimeout", wintypes.DWORD),
            ]

        FLASHW_STOP = 0x00000000
        user32 = ctypes.windll.user32
        for hwnd in hwnds:
            info = FLASHWINFO(ctypes.sizeof(FLASHWINFO), hwnd, FLASHW_STOP, 0, 0)
            user32.FlashWindowEx(ctypes.byref(info))
    except Exception:
        pass


WINDOW_MGMT_PAUSE_INDEFINITE = float("inf")


def window_mgmt_paused() -> bool:
    """True while the user has paused window control via POST /api/window-control.

    When paused, the idle background video loop and every focus / minimize-others
    / fullscreen assertion stand down so the user can use the desktop normally
    without VLC grabbing the screen or their windows being minimized. A timed
    pause auto-expires on read, so callers don't need their own clock.
    """
    until = state.window_mgmt_paused_until
    if until <= 0:
        return False
    if until != WINDOW_MGMT_PAUSE_INDEFINITE and time.time() >= until:
        state.window_mgmt_paused_until = 0.0   # auto-expire a finished timed pause
        return False
    return True


def _minimize_other_windows_windows() -> None:
    """Minimize every visible top-level window that isn't owned by a VLC process.

    Called before focusing VLC so the player owns the screen on TV playback.
    Skips system / chromeless windows (no title) and already-minimized windows.
    """
    try:
        import ctypes
        from ctypes import wintypes

        vlc_pids: set = set()
        for p in psutil.process_iter(["name", "pid"]):
            if (p.info["name"] or "").lower().startswith("vlc"):
                vlc_pids.add(p.info["pid"])

        user32 = ctypes.windll.user32
        kernel32 = ctypes.windll.kernel32
        my_pid = kernel32.GetCurrentProcessId()
        shell_hwnd = user32.GetShellWindow()

        EnumWindowsProc = ctypes.WINFUNCTYPE(ctypes.c_bool, wintypes.HWND, wintypes.LPARAM)

        def _cb(hwnd, _):
            if not user32.IsWindowVisible(hwnd):
                return True
            if hwnd == shell_hwnd:
                return True
            if user32.IsIconic(hwnd):
                return True
            if user32.GetWindowTextLengthW(hwnd) == 0:
                return True
            pid = wintypes.DWORD()
            user32.GetWindowThreadProcessId(hwnd, ctypes.byref(pid))
            if pid.value == 0 or pid.value == my_pid or pid.value in vlc_pids:
                return True
            # SW_FORCEMINIMIZE (11) is cross-thread / cross-process safe.
            user32.ShowWindow(hwnd, 11)
            return True

        cb = EnumWindowsProc(_cb)   # keep ref alive — ctypes GC pitfall
        user32.EnumWindows(cb, 0)
    except Exception:
        pass


def _vlc_focus_windows() -> None:
    """Bring the main VLC window to the foreground on Windows using ctypes.

    Bypasses focus-stealing prevention with the standard cocktail:
      1. Zero the foreground-lock timeout (SPI_SETFOREGROUNDLOCKTIMEOUT).
      2. Send a synthetic ALT keypress — Windows resets the foreground lock
         on any keystroke, which lets SetForegroundWindow succeed.
      3. Attach our input queue to the current foreground thread.
      4. SetForegroundWindow + BringWindowToTop.
      5. FlashWindowEx(FLASHW_STOP) on every VLC hwnd to clear any taskbar
         attention flash left over from a previous blocked focus attempt.
    Without #2 and #5 the taskbar stays visible after retry/relaunch even
    though VLC is fullscreen, because the flashing icon defeats auto-hide.
    """
    hwnds = _find_vlc_hwnds_windows()
    if not hwnds:
        return
    hwnd = hwnds[0]
    try:
        import ctypes
        user32 = ctypes.windll.user32
        kernel32 = ctypes.windll.kernel32

        SPI_SETFOREGROUNDLOCKTIMEOUT = 0x2001
        SPIF_SENDCHANGE = 0x02
        user32.SystemParametersInfoW(SPI_SETFOREGROUNDLOCKTIMEOUT, 0, 0, SPIF_SENDCHANGE)

        VK_MENU = 0x12
        KEYEVENTF_KEYUP = 0x0002
        user32.keybd_event(VK_MENU, 0, 0, 0)
        user32.keybd_event(VK_MENU, 0, KEYEVENTF_KEYUP, 0)

        fg_thread = user32.GetWindowThreadProcessId(user32.GetForegroundWindow(), None)
        my_thread = kernel32.GetCurrentThreadId()
        if fg_thread != my_thread:
            user32.AttachThreadInput(my_thread, fg_thread, True)
        user32.ShowWindow(hwnd, 9)   # SW_RESTORE
        user32.BringWindowToTop(hwnd)
        user32.SetForegroundWindow(hwnd)
        if fg_thread != my_thread:
            user32.AttachThreadInput(my_thread, fg_thread, False)
    except Exception:
        pass
    _stop_vlc_flash_windows()


def _vlc_minimize_windows() -> None:
    """Minimize all VLC windows on Windows using ctypes."""
    hwnds = _find_vlc_hwnds_windows()
    if not hwnds:
        return
    try:
        import ctypes
        user32 = ctypes.windll.user32
        WM_SYSCOMMAND = 0x0112
        SC_MINIMIZE    = 0xF020
        for hwnd in hwnds:
            # PostMessage puts SC_MINIMIZE into VLC's own message queue (UI-thread safe).
            user32.PostMessageW(hwnd, WM_SYSCOMMAND, SC_MINIMIZE, 0)
            # SW_FORCEMINIMIZE (11) is designed for cross-process/thread minimization.
            user32.ShowWindow(hwnd, 11)
    except Exception:
        pass


async def vlc_minimize() -> None:
    """Minimize VLC on all platforms. Best-effort; never raises."""
    system = platform.system()
    try:
        if system == "Windows":
            await asyncio.get_running_loop().run_in_executor(None, _vlc_minimize_windows)
        elif system == "Darwin":
            proc = await asyncio.create_subprocess_exec(
                "osascript", "-e",
                'tell application "VLC" to set miniaturized of every window to true',
                stdout=asyncio.subprocess.DEVNULL,
                stderr=asyncio.subprocess.DEVNULL,
            )
            await proc.wait()
        elif system == "Linux":
            if shutil.which("xdotool"):
                proc = await asyncio.create_subprocess_exec(
                    "xdotool", "search", "--name", "VLC", "windowminimize", "--sync",
                    stdout=asyncio.subprocess.DEVNULL,
                    stderr=asyncio.subprocess.DEVNULL,
                )
                await proc.wait()
            elif shutil.which("wmctrl"):
                proc = await asyncio.create_subprocess_exec(
                    "wmctrl", "-r", "VLC", "-b", "add,hidden",
                    stdout=asyncio.subprocess.DEVNULL,
                    stderr=asyncio.subprocess.DEVNULL,
                )
                await proc.wait()
    except Exception:
        pass


_MACOS_HIDE_OTHERS_SCRIPT = (
    'tell application "System Events" to '
    'set visible of (every process whose visible is true and '
    'name is not "VLC" and frontmost is false) to false'
)


async def _vlc_assert_focus(system: str) -> None:
    """Single pass of platform-specific focus + minimize-others. Never raises."""
    try:
        if system == "Windows":
            loop = asyncio.get_running_loop()
            await loop.run_in_executor(None, _minimize_other_windows_windows)
            await loop.run_in_executor(None, _vlc_focus_windows)
        elif system == "Darwin":
            proc = await asyncio.create_subprocess_exec(
                "osascript", "-e", 'tell application "VLC" to activate',
                stdout=asyncio.subprocess.DEVNULL,
                stderr=asyncio.subprocess.DEVNULL,
            )
            await proc.wait()
            proc = await asyncio.create_subprocess_exec(
                "osascript", "-e", _MACOS_HIDE_OTHERS_SCRIPT,
                stdout=asyncio.subprocess.DEVNULL,
                stderr=asyncio.subprocess.DEVNULL,
            )
            await proc.wait()
        elif system == "Linux":
            if shutil.which("wmctrl"):
                proc = await asyncio.create_subprocess_exec(
                    "wmctrl", "-a", "VLC",
                    stdout=asyncio.subprocess.DEVNULL,
                    stderr=asyncio.subprocess.DEVNULL,
                )
                await proc.wait()
    except Exception:
        pass


async def vlc_focus_and_fullscreen() -> None:
    """Bring VLC to the foreground, minimize everything else, and enable fullscreen.
    Best-effort; never raises.

    Why this loops instead of running once:
    Hitting Stop in the UI reliably comes up correctly because the desktop is
    fully settled — Explorer/Dock/menu bar/startup apps are stable, so a single
    minimize-others + focus pass catches every window. At boot via the system
    service the dashboard starts ~5–15 s into the login sequence, so by the
    time the idle background video kicks in there are still startup apps and
    Explorer shell pieces actively launching, and they appear *on top of* VLC
    after we focused it. A single pass leaves the user looking at a windowed
    VLC behind the user's normal apps with the taskbar visible.

    Fix: keep re-asserting focus + minimize-others + fullscreen for ~20 s after
    the call, on a slowing cadence (0.5 s → 1 s → 2 s). This catches late-
    launching apps without hammering the desktop forever once things settle.
    """
    # User asked to use the computer normally — don't grab focus or minimize
    # anything. The background_video_loop will re-engage once the pause lifts.
    if window_mgmt_paused():
        return
    await asyncio.sleep(1.5)
    system = platform.system()

    # Cadence: tight at the start to grab the screen ASAP, then back off.
    # Total wall-time ≈ 24 s, plenty for Windows logon-time app churn.
    delays = [0.5] * 6 + [1.0] * 8 + [2.0] * 6

    for delay in delays:
        # YouTube took over the TV (browser kiosk) — stop fighting it. Without
        # this, a still-running background focus loop would keep minimizing the
        # kiosk window (via _minimize_other_windows) and re-focusing VLC.
        if state.youtube_active:
            return
        # Same for the TV UI dashboard kiosk: while it should hold the screen,
        # don't minimize it / pull VLC back over it. Real plays clear the flag
        # (vlc() in_play branch) before this loop's first iteration runs.
        if state.tv_ui_active:
            return
        # User paused window control mid-loop — stop fighting for the screen.
        if window_mgmt_paused():
            return
        # Always re-assert focus + minimize-others, even if VLC reports
        # fullscreen=True. The reported flag tracks VLC's internal state and
        # can be True while a later-launching app is rendering on top.
        await _vlc_assert_focus(system)

        try:
            vs = await vlc_status()
        except Exception:
            vs = None
        if vs:
            vlc_state = vs.get("state", "")
            is_fs = bool(vs.get("fullscreen"))
            if vlc_state in ("playing", "paused") and not is_fs:
                try:
                    await vlc("fullscreen")
                except Exception:
                    pass

        # Belt-and-suspenders for Windows: clear taskbar attention flash
        # so the taskbar can auto-hide over fullscreen VLC.
        if system == "Windows":
            try:
                await asyncio.get_running_loop().run_in_executor(
                    None, _stop_vlc_flash_windows,
                )
            except Exception:
                pass

        # If the user explicitly stopped the bg / started a new pipeline, bail.
        if state.stream_status == "buffering":
            return

        await asyncio.sleep(delay)


async def _restart_vlc_process() -> bool:
    """Kill any running VLC processes, relaunch with HTTP interface. Returns True when port opens."""
    for p in psutil.process_iter(["name"]):
        if (p.info["name"] or "").lower().startswith("vlc"):
            try:
                p.kill()
            except Exception:
                pass

    await asyncio.sleep(1.5)

    vlc_bin = _find_vlc_bin()
    if not vlc_bin:
        return False

    vlc_port = int(urlparse(settings.vlc_url).port or 8080)

    kw: dict = {"stdout": subprocess.DEVNULL, "stderr": subprocess.DEVNULL}
    if platform.system() == "Windows":
        kw["creationflags"] = subprocess.DETACHED_PROCESS | subprocess.CREATE_NEW_PROCESS_GROUP
    else:
        kw["start_new_session"] = True
    _marquee_write("")  # start clean; marq needs the file to exist at launch
    subprocess.Popen(
        [vlc_bin, "--extraintf=http", "--http-host=localhost",
         f"--http-port={vlc_port}", f"--http-password={settings.vlc_password}", "--no-random",
         # StreamLink owns sidecar loading via _load_all_local_subs (which tags AI
         # subs). VLC's own autodetect would load AI `.srt`s first as *untagged*
         # tracks, so the policy mistakes them for real subs — disable it. See
         # docs/GOTCHAS.md.
         "--no-sub-autodetect-file",
         "--fullscreen", *_vlc_marquee_args(),
         # Night mode (dynamic-range compressor) when enabled — see _apply_night_mode.
         *_vlc_audio_filter_args(state.vlc_night_mode, state.vlc_night_mode_preset)],
        **kw,
    )

    deadline = asyncio.get_event_loop().time() + 15
    while asyncio.get_event_loop().time() < deadline:
        await asyncio.sleep(0.5)
        try:
            with socket.create_connection(("127.0.0.1", vlc_port), timeout=0.5):
                await asyncio.sleep(0.8)
                return True
        except OSError:
            pass
    return False


async def _retry_task(file_path: Path) -> None:
    """Background task: restart VLC and replay the current file + remainder of playlist."""
    try:
        await broadcast("stream_status", {"status": state.stream_status, "message": "Relaunching VLC…"})
        ok = await _restart_vlc_process()
        if not ok:
            state.stream_status = "error"
            await broadcast("stream_status", {"status": "error", "message": "VLC could not be relaunched."})
            return

        await vlc("in_play", input=vlc_file_uri(file_path))

        if state.library_playlist and state.library_current_file:
            try:
                cur = str(state.library_current_file)
                idx = state.library_playlist.index(cur)
                for p in state.library_playlist[idx + 1:]:
                    await vlc("in_enqueue", input=vlc_file_uri(Path(p)))
            except (ValueError, Exception):
                pass

        state.stream_status = "playing"
        state.current_audio_track = -1
        state.current_subtitle_track = -1
        asyncio.create_task(vlc_focus_and_fullscreen())
        await broadcast("stream_status", {"status": "playing", "message": f"Retrying: {file_path.name}"})
    except Exception as exc:
        state.stream_status = "error"
        await broadcast("stream_status", {"status": "error", "message": f"Retry failed: {exc}"})


async def _apply_night_mode(enabled: bool) -> None:
    """Toggle the VLC night-mode compressor by relaunching VLC, then resume.

    VLC's HTTP interface has no command to add/remove an audio filter at runtime,
    so the compressor can only be switched by relaunching VLC — it's a launch arg
    (`NIGHT_MODE_ARGS`, read off `state.vlc_night_mode` in `_restart_vlc_process`).
    To make the toggle seamless mid-playback we snapshot the current file +
    position, relaunch, replay the file (and any remaining playlist tail), and
    seek back. When only the idle background video (or nothing) is on screen we
    just relaunch and let `background_video_loop` bring the bg video back with the
    new filter applied.
    """
    state.vlc_night_mode = enabled

    # Snapshot what's playing *before* killing VLC. Skip the bg video — the loop
    # restarts it on its own.
    resume_path: Optional[Path] = None
    if not state.background_playing:
        if state.library_current_file:
            resume_path = Path(state.library_current_file)
        elif state.active_file:
            resume_path = state.active_file
    vs = await vlc_status()
    live_state = (vs or {}).get("state", "")
    try:
        resume_pos = int(float((vs or {}).get("time", 0) or 0))
    except (TypeError, ValueError):
        resume_pos = 0
    has_content = resume_path is not None and live_state in ("playing", "paused")

    # Remaining playlist tail (multi-episode plays) captured before the restart.
    tail: list[str] = []
    if has_content and state.library_playlist and state.library_current_file:
        try:
            idx = state.library_playlist.index(str(state.library_current_file))
            tail = list(state.library_playlist[idx + 1:])
        except ValueError:
            tail = []

    try:
        if has_content:
            # Buffering both shows the user something and tells
            # background_video_loop to stand down during the restart gap.
            state.stream_status = "buffering"
            await broadcast("stream_status", {"status": "buffering", "message": "Applying night mode…"})
            await broadcast("state", state_snapshot())

        ok = await _restart_vlc_process()

        if not has_content:
            # Idle / background only: nothing to resume. The toggle still took
            # effect (VLC relaunched with/without the filter); just republish.
            await broadcast("state", state_snapshot())
            return

        if not ok:
            state.stream_status = "error"
            await broadcast("stream_status", {"status": "error", "message": "VLC could not be relaunched."})
            return

        first_resolved = resume_path.resolve()
        play_task = asyncio.create_task(vlc("in_play", input=vlc_file_uri(first_resolved)))
        ready = await _vlc_wait_until_ready(first_resolved, timeout=10.0)

        state.stream_status = "playing"
        state.current_audio_track = -1
        state.current_subtitle_track = -1
        await broadcast("stream_status", {"status": "playing", "message": f"Playing: {resume_path.name}"})
        await broadcast("state", state_snapshot())
        asyncio.create_task(vlc_focus_and_fullscreen())

        # Seek back to where we were once the demuxer is up. Re-issue once if VLC
        # ignored the first seek the instant it opened the file (same guard as
        # the resume-seek in _library_play_launch).
        if resume_pos > 5 and (ready or await _vlc_wait_until_ready(first_resolved, timeout=10.0)):
            await vlc("seek", val=str(resume_pos))
            await asyncio.sleep(0.6)
            cur = await vlc_status()
            if cur and float(cur.get("time", 0) or 0) < resume_pos - 15:
                await vlc("seek", val=str(resume_pos))

        # Re-apply the saved audio/subtitle track for a library item (the restart
        # reset VLC's track selection to defaults).
        if state.library_item_id and state.library_profile_id:
            asyncio.create_task(_apply_track_prefs(
                state.library_item_id, state.library_profile_id,
                str(state.library_current_file), delay=3.5,
            ))

        # Append the tail after the current file is accepted so order is right.
        if tail:
            try:
                await play_task
            except Exception:
                pass
            for p in tail:
                try:
                    await vlc("in_enqueue", input=vlc_file_uri(Path(p)))
                except Exception:
                    pass
    except Exception as exc:
        state.stream_status = "error"
        await broadcast("stream_status", {"status": "error", "message": f"Night mode toggle failed: {exc}"})


# ── Utilities ─────────────────────────────────────────────────────────────────

def extract_hash(magnet: str) -> Optional[str]:
    """Pull the info-hash from a magnet URI, normalising base32 → hex."""
    m = re.search(r"xt=urn:btih:([a-fA-F0-9]{40}|[A-Za-z2-7]{32})", magnet, re.I)
    if not m:
        return None
    h = m.group(1)
    if len(h) == 32:
        try:
            h = base64.b32decode(h.upper()).hex()
        except Exception:
            return None
    return h.lower()


def parse_season_episode(name: str) -> tuple[int, int]:
    """Extract (season, episode) from filenames like S01E03, s2e5, 1x03, etc."""
    m = re.search(r"[Ss](\d{1,2})[Ee](\d{1,2})", name)
    if m:
        return int(m.group(1)), int(m.group(2))
    m = re.search(r"\b(\d{1,2})x(\d{2})\b", name)
    if m:
        return int(m.group(1)), int(m.group(2))
    return 0, 0


# ── Search-result title parsing (show grouping) ──────────────────────────────
# Structural markers that separate a show's name from its season/episode/release
# info. Used by parse_torrent_title() to group flat search results into shows.
_TT_EP_RE          = re.compile(r"[Ss](\d{1,2})[Ee](\d{1,2})")
_TT_EP_X_RE        = re.compile(r"\b(\d{1,2})x(\d{2})\b")
# Multi-season packs. The trailing (?!\d) stops the second number from matching a
# resolution/year *prefix* — "S01 - 720p" must NOT read as S1-72, "S08 - 2019"
# not as S8-20. Legit forms: S01-S05, S01-05, S01-5, S1+S2+S3, S01-S02-S03.
_TT_MULTI_PLUS_RE  = re.compile(r"[Ss]\d{1,2}(?:\s*[+&]\s*[Ss]?\d{1,2})+")         # S1+S2+S3 / S01&02
_TT_MULTI_WORD_PLUS_RE = re.compile(
    r"[Ss]easons?\s*\d{1,2}(?:\s*[+&]\s*(?:[Ss]easons?\s*)?\d{1,2})+")             # Season 1 + 2
_TT_MULTI_LIST_RE  = re.compile(r"[Ss]\d{1,2}(?:\s*-\s*[Ss]?\d{1,2}(?!\d)){2,}")   # S01-S02-S03…
_TT_MULTI_RANGE_RE = re.compile(r"[Ss](\d{1,2})\s*-\s*[Ss]?(\d{1,2})(?!\d)")       # S01-S05 / S01-5
# Fansub per-episode form for sequel seasons: "[SubsPlease] Show S2 - 05" /
# "Show Season 2 - 05". A *spaced* dash + a 2+-digit second number with no S
# prefix is an episode, not a season range — real packs write "S01-S05"/"S01-05"
# tight, or "Seasons 1-5" (plural, which this pattern's singular "Season" never
# matches). Must be tested before the multiseason ranges, which would otherwise
# swallow "S2 - 05" as a bogus seasons-2-to-5 pack.
_TT_SEASON_EP_DASH_RE = re.compile(r"\b[Ss](?:eason\s*)?(\d{1,2})\s+-\s+(\d{2,4})(?!\d)")
_TT_SEASONS_WORD_RE = re.compile(r"[Ss]easons?\s*(\d{1,2})\s*-\s*(\d{1,2})(?!\d)") # Seasons 1-5
_TT_SEASON_RE      = re.compile(r"\b[Ss](\d{1,2})\b")
_TT_SEASON_WORD_RE = re.compile(r"\b[Ss]eason\s*(\d{1,2})\b")
# Ordinal season ("Sousou no Frieren 2nd Season") — the dominant fansub form for
# anime sequels. Without it, "…2nd Season - 10" reads as absolute S1E10 and the
# ordinal stays in the show name, fragmenting the group away from season 1.
_TT_ORDINAL_SEASON_RE = re.compile(r"\b(\d{1,2})(?:st|nd|rd|th)\s+[Ss]eason\b", re.IGNORECASE)
_TT_COMPLETE_SERIES_RE = re.compile(r"\bComplete\s+(?:Series|Pack|Collection)\b", re.IGNORECASE)
# Absolute-numbered anime episode ("[Grp] One Piece - 1168 [1080p]", "One Piece
# EP1168", "Naruto 121 (..."). Only consulted when NO S/E or season marker exists.
# Dash / EP are strong fansub signals (1-4 digits); a bare trailing number needs
# 3-4 digits so "Ocean's 11" (a movie) isn't read as an episode.
# Absolute-episode-range batch ("One Piece 001-574", "One Piece 1094-1099") —
# the long-running-anime bulk form. Requires a 3+-digit upper bound so year
# spans and small number pairs never match; validated further at the use site.
_TT_EP_RANGE_RE    = re.compile(r"\b(\d{1,4})\s*[-~]\s*(\d{3,4})(?!\d)")
_TT_ABS_EP_RE      = re.compile(r"\b[Ee][Pp]\s?(\d{1,4})\b")                       # EP1168
_TT_ABS_DASH_RE    = re.compile(r"\s-\s+(\d{1,4})(?!\d)")                          # Show - 121
# Size tags ("1.85GB", "700 MB", "2 GB") — stripped before structural parsing so a
# YIFY-style "- 1.85GB" can't be misread as absolute episode 1 (dots → spaces in
# norm turn "1.85GB" into "1 85GB", so match the split form too).
_TT_SIZE_RE        = re.compile(r"\b\d+(?:[ .]\d+)?\s*(?:[GMKT]i?B|MB|GB|KB|TB)\b", re.I)
_TT_ABS_TAIL_RE    = re.compile(r"\s(\d{3,4})\s*(?=[\[(]|$)")                      # Show 1168 [.. / (..
_TT_TRAIL_YEAR_RE  = re.compile(r"\s+(?:19|20)\d{2}$")
_TT_EXT_RE         = re.compile(r"\.(?:mkv|mp4|avi|mov|m4v|ts|webm)$", re.IGNORECASE)
_TT_RES_NUMS       = {480, 540, 576, 720, 1080, 1440, 2160, 4320}


def _tt_bounded_span(a: int, b: int):
    """Accept a season range only if it's plausible. Rejects the resolution/year
    bleed and absolute-ep dashes ("S4 - 37") that would otherwise read as a
    30+-season pack — real multi-season packs span a handful of seasons."""
    lo, hi = min(a, b), max(a, b)
    if hi > 50 or (hi - lo) > 30:
        return None
    return lo, hi


def parse_torrent_title(title: str) -> dict:
    """Classify a raw torrent title into a show + kind so flat search results can
    be grouped. Returns:
        show        display-cased show name ("Breaking Bad")
        show_key    normalised grouping key ("breaking bad")
        kind        "episode" | "season" | "multiseason" | "movie"
        season      episode/season kinds: the season number (0 otherwise)
        episode     episode kind: episode number (absolute-numbered anime → season 1)
        season_from/season_to  multiseason kind: inclusive season range (0 = "complete")
        ep_from/ep_to  multiseason kind only: absolute-episode-range batch
                       ("One Piece 001-574"; 0 when the pack is season-based)
        year        detected release year (or None)
    The show name is the text *before* the first structural marker, run through
    _strip_release_tags — this is what separates e.g. a "Better Call Saul S06E11
    Breaking Bad" or "Moonshiners S15E12 Braking Badly" hit out of a search for
    "breaking bad" into their own groups instead of polluting the show."""
    raw = _html.unescape(title or "")   # Jackett titles can carry &amp; etc.
    norm = re.sub(r"[._]+", " ", raw)
    norm = re.sub(r"\s+", " ", norm).strip()
    # Drop size tags so "- 1.85GB" / "- 700 MB" aren't misread as absolute episodes.
    norm = re.sub(r"\s+", " ", _TT_SIZE_RE.sub(" ", norm)).strip()

    ym = _YEAR_RE.search(norm)
    year = int(ym.group(0)) if ym else None

    season = episode = season_from = season_to = ep_from = ep_to = 0
    abs_marker_pos = None   # where to cut the show name for an absolute-numbered ep

    ep_m    = _TT_EP_RE.search(norm) or _TT_EP_X_RE.search(norm)
    plus_m  = _TT_MULTI_PLUS_RE.search(norm) or _TT_MULTI_WORD_PLUS_RE.search(norm)
    list_m  = _TT_MULTI_LIST_RE.search(norm)
    range_m = _TT_SEASONS_WORD_RE.search(norm) or _TT_MULTI_RANGE_RE.search(norm)
    complete_series = bool(_TT_COMPLETE_SERIES_RE.search(norm))

    # "S2 - 05" / "Season 2 - 05" (spaced dash, padded episode) is a sequel-
    # season *episode*, not a range — claim it before the multiseason block.
    epdash_m = None
    if ep_m is None:
        m = _TT_SEASON_EP_DASH_RE.search(norm)
        if m:
            n = int(m.group(2))
            if not (1900 <= n <= 2099) and n not in _TT_RES_NUMS:
                epdash_m = m

    kind = None
    if epdash_m is not None:
        kind = "episode"
        season, episode = int(epdash_m.group(1)), int(epdash_m.group(2))
    if kind is None and (plus_m or list_m or range_m or complete_series):
        span = None
        if plus_m:
            nums = [int(x) for x in re.findall(r"\d{1,2}", plus_m.group(0))]
            span = _tt_bounded_span(min(nums), max(nums)) if nums else None
        elif list_m:
            nums = [int(x) for x in re.findall(r"\d{1,2}", list_m.group(0))]
            span = _tt_bounded_span(min(nums), max(nums)) if nums else None
        elif range_m:
            span = _tt_bounded_span(int(range_m.group(1)), int(range_m.group(2)))
        if span:
            kind, (season_from, season_to) = "multiseason", span
        elif complete_series:
            kind = "multiseason"          # "Complete Series" with no explicit numbers
        elif range_m:
            # Implausible span ("S01 - 720p" already blocked by (?!\d); "S4 - 37")
            # → treat as the single leading season, not a bogus pack.
            kind, season = "season", int(range_m.group(1))

    if kind is None:
        if ep_m:
            kind = "episode"
            season, episode = int(ep_m.group(1)), int(ep_m.group(2))
        else:
            sm = (_TT_SEASON_WORD_RE.search(norm) or _TT_ORDINAL_SEASON_RE.search(norm)
                  or _TT_SEASON_RE.search(norm))
            if sm:
                kind, season = "season", int(sm.group(1))
                # "<show> 2nd Season - 10" / "<show> Season 2 - 10": an absolute
                # episode number AFTER a word/ordinal season marker is that
                # season's episode (the fansub form for sequel seasons), not a
                # batch. Bare "S2 - 10" is left alone — _TT_MULTI_RANGE_RE owns
                # that ambiguity.
                if sm.re is not _TT_SEASON_RE:
                    am = (_TT_ABS_EP_RE.search(norm, sm.end())
                          or _TT_ABS_DASH_RE.search(norm, sm.end()))
                    if am:
                        n = int(am.group(1))
                        if not (1900 <= n <= 2099) and n not in _TT_RES_NUMS:
                            kind, episode = "episode", n
            else:
                # Absolute-episode-range batch ("One Piece 001-574") — must be
                # tested before the single abs-episode forms, whose " - NNN"
                # would otherwise read the range's upper bound as one episode.
                rm = _TT_EP_RANGE_RE.search(norm)
                if rm:
                    a_, b_ = int(rm.group(1)), int(rm.group(2))
                    if (b_ <= a_ or b_ < 100
                            or (1900 <= a_ <= 2099 and 1900 <= b_ <= 2099)
                            or (a_ in _TT_RES_NUMS and b_ in _TT_RES_NUMS)):
                        rm = None
                if rm is not None:
                    kind = "multiseason"     # an episodes batch is a pack
                    ep_from, ep_to = int(rm.group(1)), int(rm.group(2))
                    abs_marker_pos = rm.start()
                else:
                    am = (_TT_ABS_EP_RE.search(norm) or _TT_ABS_DASH_RE.search(norm)
                          or _TT_ABS_TAIL_RE.search(norm))
                    if am:
                        n = int(am.group(1))
                        if not (1900 <= n <= 2099) and n not in _TT_RES_NUMS:
                            kind, season, episode = "episode", 1, n
                            abs_marker_pos = am.start()   # cut before " - " / "EP" / the number
                if kind is None:
                    kind = "movie"

    # Show name = text before the earliest structural marker.
    positions = []
    for rx in (_TT_EP_RE, _TT_EP_X_RE, _TT_SEASONS_WORD_RE, _TT_MULTI_PLUS_RE,
               _TT_MULTI_WORD_PLUS_RE, _TT_MULTI_LIST_RE, _TT_MULTI_RANGE_RE,
               _TT_SEASON_WORD_RE, _TT_ORDINAL_SEASON_RE, _TT_SEASON_RE,
               _TT_COMPLETE_SERIES_RE):
        m = rx.search(norm)
        if m:
            positions.append(m.start())
    if abs_marker_pos is not None:
        positions.append(abs_marker_pos)
    cut = min(positions) if positions else len(norm)
    show = _strip_release_tags(norm[:cut]) or _strip_release_tags(norm) or norm.strip()
    # A cut inside parens ("Show (Season 1) …") leaves a dangling "(" the tag
    # stripper can't remove (it only strips balanced pairs) — trim trailing
    # opener/separator punctuation so the group key merges with the clean name.
    show = re.sub(r"[\s(\[{|:,&+\-–—]+$", "", show).strip() or show
    # Key ignores punctuation so apostrophe/colon variants of the same title
    # ("Frieren: Beyond Journey's End" / "Frieren Beyond Journeys End") land in
    # one group instead of fragmenting by scene-name styling.
    show_key = re.sub(r"\s+", " ", re.sub(r"[^\w\s]+", "", show.lower())).strip()
    # …and ignores CJK decoration when a Latin name remains ("DanDaDan ダンダダン"
    # groups with "Dandadan"; a purely-CJK title keeps its CJK key).
    ascii_key = re.sub(r"\s+", " ", re.sub(r"[^\x00-\x7f]+", " ", show_key)).strip()
    if len(re.sub(r"[^a-z0-9]", "", ascii_key)) >= 3:
        show_key = ascii_key
    show_key = _TT_EXT_RE.sub("", show_key)                       # drop a trailing .mkv etc
    show_key = _TT_TRAIL_YEAR_RE.sub("", show_key).strip()        # "inception 2010" ⇒ "inception"

    return {
        "show": show, "show_key": show_key, "kind": kind,
        "season": season, "episode": episode,
        "season_from": season_from, "season_to": season_to,
        "ep_from": ep_from, "ep_to": ep_to, "year": year,
    }


# ── Release audio-language classification ───────────────────────────────────
# Anime (and foreign-content) releases mix audio variants under one show:
# original audio + subs (SubsPlease/Erai-raws), English DUBBED, Dual/Multi-
# Audio, and foreign-language dubs (ArabicDub, Korean Dub, VOSTFR, LATINO…). A
# seeder sort is blind to this — an English-dub household bulk-grabbing a season
# gets a language lottery. Classify each release title so the UI can badge
# sources and the auto-picker can honour an audio preference.
# "MULTi" (no sub suffix) is a multi-*language* scene tag, but it does NOT
# imply English — the French scene uses it for FR+original (Tsundere-Raws) —
# so it's resolved contextually in _parse_release_audio, not treated as dual
# outright. Explicit Dual/Multi-Audio and bare DUAL do imply English.
_AUD_DUAL_RE  = re.compile(r"\b(?:dual|multi)[ ._-]?audio\b|\bdual\b", re.IGNORECASE)
_AUD_MULTI_RE = re.compile(r"\bmulti\b(?![ ._-]?subs?)", re.IGNORECASE)
_AUD_DUB_RE   = re.compile(r"\bdub(?:bed|s)?\b", re.IGNORECASE)
# "Multiple Subtitle" is the Erai-raws batch form whose bracketed language list
# ([ENG][POR-BR]…) describes SUBS, not audio — it must win over those tokens.
_AUD_SUB_RE   = re.compile(
    r"\bmulti(?:ple)?[ ._-]?sub(?:title)?s?\b|\bsubbed\b|\beng(?:lish)?[ ._-]?subs?\b",
    re.IGNORECASE)
# English *audio* evidence ("ENG-ITA", "[Eng-Hindi-Tam-Tel]", "AUDIO #1 ENGLISH")
# — checked only after eng-subs phrases are stripped, so "ENG SUBS" never counts.
_AUD_ENG_RE      = re.compile(r"\beng(?:lish)?\b", re.IGNORECASE)
_AUD_ENG_SUB_RE  = re.compile(r"\beng(?:lish)?[ ._-]?sub(?:title)?s?\b", re.IGNORECASE)
# Release groups whose language is known but untagged in the title.
_AUD_FRENCH_GROUP_RE = re.compile(r"tsundere[ ._-]?raws", re.IGNORECASE)
# Token → display language for non-English tags. Deliberately conservative —
# only unambiguous full words / well-known scene tags (no "GER"/"SPA"/"POR"
# abbreviations that collide with title words).
_AUD_LANGS = {
    "french": "French", "truefrench": "French", "vf": "French", "vff": "French",
    "vfq": "French", "vostfr": "French subs", "subfrench": "French subs",
    "ita": "Italian", "italian": "Italian",
    "spanish": "Spanish", "castellano": "Spanish", "latino": "Latino",
    "german": "German", "hindi": "Hindi", "tamil": "Tamil", "telugu": "Telugu",
    "russian": "Russian", "rus": "Russian",
    "arabic": "Arabic", "korean": "Korean",
    "portuguese": "Portuguese", "dublado": "Portuguese",
    "polish": "Polish", "lektor": "Polish",
}


def _parse_release_audio(title: str) -> tuple:
    """Classify a release title's audio → ``(audio, lang)``:
        "dual"  – carries original *and* English audio (Dual/Multi-Audio, DUAL,
                  or an explicit English token alongside foreign ones: ENG-ITA)
        "other" – non-English language tag(s), no English audio; ``lang`` names it
        "dub"   – English dub
        "sub"   – explicitly subtitled (original audio)
        ""      – no language markers (plain English content, or an untagged
                  fansub release — original audio + English subs for anime)
    Precedence: dual > other > dub > sub, with two context rules: a foreign tag
    next to "dub" ("ArabicDub", "Korean Dub") must not read as an English dub,
    and a multi-SUB marker means the language tokens describe subtitles
    (Erai-raws "[Multiple Subtitle] [ENG][POR-BR]…" is original audio + subs,
    not an English/Portuguese release)."""
    t = re.sub(r"[._]+", " ", title or "").lower()
    t = re.sub(r"\b([a-z]{3,})dub\b", r"\1 dub", t)   # split fused "arabicdub"
    toks = set(re.sub(r"[^a-z0-9]+", " ", t).split())
    langs = sorted({v for k, v in _AUD_LANGS.items() if k in toks})
    sub_marked = bool(_AUD_SUB_RE.search(t))
    # English *audio* token — strip eng-subs phrases first so they don't count.
    eng_audio = bool(_AUD_ENG_RE.search(_AUD_ENG_SUB_RE.sub(" ", t)))
    if _AUD_DUAL_RE.search(t):
        return "dual", ""
    if _AUD_FRENCH_GROUP_RE.search(t):
        # Known French release group: its MULTi/Multi-Subs releases are
        # FR+original audio, no English — the sub-marker rule must not fire.
        return "other", "French"
    if langs:
        if sub_marked and not _AUD_DUB_RE.search(t):
            return "sub", ""          # the language tokens are the subs list
        if eng_audio:
            return "dual", "/".join(langs)   # multi-language incl. English
        return "other", "/".join(langs)
    if _AUD_MULTI_RE.search(t):
        # Bare "MULTi" with no language context: multi-audio from an English-
        # facing scene (ToonsHub) — treat as dual. (Foreign MULTi carries its
        # own language tokens/group names and is caught above.)
        return "dual", ""
    if _AUD_DUB_RE.search(t):
        return "dub", ""
    if sub_marked:
        return "sub", ""
    return "", ""


VIDEO_EXTS = {".mkv", ".mp4", ".avi", ".mov", ".wmv", ".m4v", ".ts", ".m2ts", ".webm"}


def build_file_list(qbit_file_list: list, save_path: str) -> list[dict]:
    """Build a sorted video-file list from qBittorrent's files API response."""
    result = []
    for f in qbit_file_list:
        rel = f.get("name", "")
        if Path(rel).suffix.lower() not in VIDEO_EXTS:
            continue
        season, episode = parse_season_episode(rel)
        result.append({
            "name": Path(rel).name,
            "path": str(Path(save_path) / rel),
            "size_bytes": f.get("size", 0),
            "season": season,
            "episode": episode,
        })
    result.sort(key=lambda x: (x["season"] or 9999, x["episode"] or 9999, x["name"]))
    return result


def _file_by_index(files: list, idx: int) -> Optional[dict]:
    """Return the file dict whose 'index' field equals idx (falls back to enumerate position)."""
    for i, f in enumerate(files):
        if f.get("index", i) == idx:
            return f
    return None


def largest_video(files: list) -> Optional[dict]:
    videos = [f for f in files if Path(f["name"]).suffix.lower() in VIDEO_EXTS]
    pool = videos or files
    return max(pool, key=lambda f: f.get("size", 0), default=None)


def human_size(n: int) -> str:
    for unit in ("B", "KB", "MB", "GB", "TB"):
        if n < 1024:
            return f"{n:.1f} {unit}"
        n /= 1024
    return f"{n:.1f} PB"


# ── Per-item download scheduling ────────────────────────────────────────────────
# A library item may carry a `download` config controlling WHEN its torrent's files
# are fetched. The download_scheduler_loop is the *single source of truth* for qBit
# file priorities + torrent pause/resume on scheduled items — never write filePrio /
# pause/resume for these items elsewhere without going through this model, or the
# next reconcile reverts it (see docs/GOTCHAS.md).
#
#   item["download"] = {
#       "mode":  "now" | "idle",          # item-wide default for files w/o an override
#       "files": { "<abs path>": "now" | "high" | "idle" | "skip" },
#   }
#
# Effective per-file schedule = files[path] if present else mode. Mapping to a live
# qBit priority depends on whether the idle/night download window is open right now:
#   skip → 0 (never)          high → 7 (download now, MAXIMAL priority)
#   idle → 1 when open, else 0
# The three exposed download-priority levels (mid = default) map to qBit's own
# file-priority tiers so episodes within one torrent fetch in the chosen order:
#   low  → 1 (Normal)         mid → 6 (High)          high → 7 (Maximal, first)
# Legacy "now" is treated as "mid" (the default tier) so old items keep working.
_FILE_MODES = ("now", "low", "mid", "high", "idle", "skip")
# The subset that is a pure download-PRIORITY choice (not a schedule like idle/skip).
_DL_PRIORITIES = ("low", "mid", "high")


def _download_cfg(item: dict) -> dict:
    """Return item['download'] with defaults filled in (never mutates the item)."""
    dl = item.get("download") or {}
    mode = dl.get("mode", "now")
    if mode not in ("now", "idle"):
        mode = "now"
    files = dl.get("files") or {}
    return {"mode": mode, "files": {k: v for k, v in files.items() if v in _FILE_MODES}}


def _effective_file_mode(cfg: dict, path: str) -> str:
    """Resolve a single file's effective schedule from the item download cfg."""
    fm = cfg["files"].get(path)
    return fm if fm in _FILE_MODES else cfg["mode"]


def _file_is_compressed(f: dict) -> bool:
    """True if this file entry was re-encoded in place by the compression tool.

    A compressed file's bytes no longer match the torrent's pieces: it can't seed and
    a qBit recheck would mark it damaged. So it is effectively NO LONGER torrent-backed
    even though the item still carries a torrent_hash (one torrent can hold several
    files, only some compressed — the marker is per-file, never per-item). Disk is the
    authority for these files; qBit progress must be ignored and re-download blocked."""
    return bool(f.get("compressed"))


def _item_has_compressed(item: dict) -> bool:
    """True if any file in the item was compressed in place. Gates torrent-wide
    destructive ops (recheck/recover) that would damage/overwrite the compressed bytes."""
    return any(_file_is_compressed(f) for f in item.get("files", []))


# Per-file STREAM-PREP schedule — the sibling of the download schedule above, but
# governing HLS stream-prep (the .offline_cache bundles) instead of the qBit
# download. Stored as:
#
#   item["prep"] = { "files": { "<abs path>": "now" | "idle" | "never" } }
#
# Effective per-file prep mode = files[path] if present else "idle" (the implicit
# default — eligible for Automatic Stream Prep when the box is idle/always). The
# modes parallel the download bar:
#   now   → prep this file immediately (the /prep-schedule endpoint enqueues a job)
#   idle  → let auto_prep_loop prep it during the idle/always window (default)
#   never → exclude from auto-prep entirely (_enqueue_library_prep skips it). The
#           existing cached bundle, if any, is left intact (non-destructive).
#
# Independently, prep PRIORITY orders the (single-slot) bulk prep queue so a
# whole series or a single episode can jump ahead of other auto-prep work. Three
# tiers (mid = default), stored alongside the schedule:
#
#   item["prep"] = {
#       "files":            { "<abs path>": "now" | "idle" | "never" },
#       "priority_default": "low" | "mid" | "high",   # item/series-level default
#       "priority":         { "<abs path>": "low" | "mid" | "high" },  # per-episode
#   }
#
# Effective per-file priority = priority[path] if set, else priority_default, else
# "mid". A higher tier runs ahead of a lower one at the bulk-queue gate in
# _run_offline_job (interactive / admin prep still outrank ALL bulk work).
_PREP_MODES = ("now", "idle", "never")
_PREP_PRIORITIES = ("low", "mid", "high")
_PREP_PRIO_NUM = {"low": 0, "mid": 1, "high": 2}


def _prep_cfg(item: dict) -> dict:
    """Return item['prep'] with defaults filled in (never mutates the item)."""
    pr = item.get("prep") or {}
    files = pr.get("files") or {}
    pdef = pr.get("priority_default")
    prio = pr.get("priority") or {}
    return {
        "files": {k: v for k, v in files.items() if v in _PREP_MODES},
        "priority_default": pdef if pdef in _PREP_PRIORITIES else "mid",
        "priority": {k: v for k, v in prio.items() if v in _PREP_PRIORITIES},
    }


def _effective_prep_mode(cfg: dict, path: str) -> str:
    """Resolve a single file's effective prep schedule. Default 'idle' = auto-prep
    eligible (so a brand-new library item is prepped by Automatic Stream Prep
    exactly as before this per-file control existed)."""
    pm = cfg["files"].get(path)
    return pm if pm in _PREP_MODES else "idle"


def _effective_prep_priority(cfg: dict, path: str) -> str:
    """Resolve a file's effective prep-queue priority: per-file override → the
    item/series-level default → "mid"."""
    pp = cfg["priority"].get(path)
    return pp if pp in _PREP_PRIORITIES else cfg["priority_default"]


def _prep_priority_num_for(item: dict, path: str) -> int:
    """Numeric prep priority (0=low, 1=mid, 2=high) for one file of an item."""
    return _PREP_PRIO_NUM.get(_effective_prep_priority(_prep_cfg(item), path), 1)


def _file_mode_to_priority(mode: str, idle_open: bool) -> int:
    """Map an effective file mode + current idle-window state to a qBit priority.

    The three priority tiers (low/mid/high) map onto qBit's Normal/High/Maximal so
    episodes in one torrent download in the chosen order; legacy "now" is "mid"."""
    if mode == "skip":
        return 0
    if mode == "high":
        return 7          # Maximal — download first
    if mode == "mid":
        return 6          # High — the default tier
    if mode == "low":
        return 1          # Normal — download after mid/high files
    if mode == "idle":
        return 1 if idle_open else 0
    return 6   # legacy "now" → mid (default tier)


def _dl_priority_of(mode: str) -> str:
    """Collapse an effective file mode to one of the three UI priority levels.
    Schedule-only modes (idle/skip) still report their would-be download tier so the
    priority control shows a sensible position; the schedule is surfaced separately."""
    if mode == "high":
        return "high"
    if mode == "low":
        return "low"
    return "mid"   # now / mid / idle / skip


def _analyzable_files(item: dict) -> list[dict]:
    """Item video files that should be treated as part of the download: excludes
    files the user marked "skip" (deselected from the download). Those never land on
    disk, so they must not be audio-fingerprinted, counted as "pending" Smart Skip,
    or gate the ready flip."""
    cfg = _download_cfg(item)
    return [f for f in item.get("files", [])
            if _effective_file_mode(cfg, f.get("path", "")) != "skip"]


def _all_nonskip_complete(item: dict, qfiles: list, save_path: str) -> bool:
    """True iff every non-skip file in the torrent is fully downloaded (and there is
    at least one). The ready/fingerprint gate: a partial selection flips ready once
    its kept files are done, and an idle-deferred file still has to finish first — so
    audio fingerprinting only ever runs on the complete set the user asked for."""
    cfg = _download_cfg(item)
    compressed_paths = {f.get("path", "") for f in item.get("files", []) if _file_is_compressed(f)}
    saw = False
    for i, qf in enumerate(qfiles):
        full = str(Path(save_path) / qf.get("name", ""))
        if _effective_file_mode(cfg, full) == "skip":
            continue
        saw = True
        # Compressed files: disk is authoritative (qBit sees them as damaged). They're
        # complete by definition, so don't let a stale qBit progress block "ready".
        if full in compressed_paths:
            continue
        if qf.get("progress", 0.0) < 0.999:
            return False
    return saw


def _file_progress(item: dict, profile_id: str, file_path: str) -> Optional[dict]:
    """Return per-file progress dict for a given profile and path, or None."""
    prof = item.get("progress", {}).get(profile_id, {})
    return prof.get("file_progress", {}).get(file_path)


def _canonical_item_path(vlc_path: str, item: dict) -> str:
    """Return the item["files"] path that resolves to the same file as vlc_path.

    VLC receives vlc_file_uri(p) — a resolved path (symlinks followed; on
    Windows possibly an 8.3 short form for over-MAX_PATH files).  The stored
    path may not be resolved, so we compare resolved forms (resolve() also
    expands 8.3 short names back to the long path) and return the stored path
    so progress keys always match what get_item_files and find_resume_hint
    expect.  Falls back to vlc_path if no match is found.
    """
    try:
        target = Path(vlc_path).resolve()
    except Exception:
        return vlc_path
    for f in item.get("files", []):
        stored = f.get("path", "")
        try:
            if Path(stored).resolve() == target:
                return stored
        except Exception:
            continue
    return vlc_path


async def _set_playback_owner(profile_id: Optional[str], lib: Optional[dict] = None) -> None:
    """Pin the active playback to a profile and snapshot its name/color onto state.

    Single source of truth for *who started* the current VLC playback. Whoever
    presses Play owns the session; everyone else can drive the shared controls
    (pause/seek/next) but progress always lands on this profile. Pass profile_id
    ``None`` to clear (stop / background). ``lib`` is reused if the caller already
    holds a library snapshot, else fetched."""
    state.library_profile_id = profile_id or None
    if not profile_id:
        state.library_profile_name = ""
        state.library_profile_color = ""
        return
    if lib is None:
        lib = await get_library()
    prof = next((p for p in lib.get("profiles", []) if p.get("id") == profile_id), None)
    state.library_profile_name = (prof or {}).get("name", "") or ""
    state.library_profile_color = (prof or {}).get("color", "") or ""


def find_resume_hint(item: dict, profile_id: str) -> Optional[dict]:
    """Return the best file+position to resume for a profile, or None."""
    if not profile_id:
        return None
    files = item.get("files", [])
    if not files:
        return None
    prof = item.get("progress", {}).get(profile_id, {})
    file_progs = prof.get("file_progress", {})
    last_file = prof.get("last_file")

    def _hint_for(f: dict) -> dict:
        path = f.get("path", "")
        fp = file_progs.get(path, {})
        pos = fp.get("position_sec", 0)
        dur = fp.get("duration_sec", 0)
        return {
            "file_path": path,
            "episode_name": f.get("name", Path(path).name),
            "position_sec": pos,
            "duration_sec": dur,
            "pct": round(pos / dur * 100, 1) if dur else 0,
            # Whether this item's last play (for this profile) was Shuffle Play, so
            # Resume can offer to keep shuffling. Ephemeral playback state is gone by
            # now; this preference is what survives the stop. See set_shuffle_pref.
            "shuffle": bool(prof.get("shuffle")),
            "shuffle_scope": prof.get("shuffle_scope", "") or "",
        }

    paths = [f.get("path", "") for f in files]

    # Continue forward from whatever the viewer last played, never backwards to an
    # earlier episode they skipped. If they watched ep6 (skipping ep5) and stopped
    # partway, resume ep6; once ep6 is finished, advance to ep7 — not back to ep5.
    if last_file and last_file in paths:
        idx = paths.index(last_file)
        lf = file_progs.get(last_file, {})
        # Still mid-episode → resume the last-watched file itself.
        if not lf.get("completed") and lf.get("position_sec", 0) > 5:
            return _hint_for(files[idx])
        # Finished it (or barely started) → first un-completed episode at/after it.
        # Skip the last file only when it's actually completed.
        start = idx + 1 if lf.get("completed") else idx
        for f in files[start:]:
            if not file_progs.get(f.get("path", ""), {}).get("completed"):
                return _hint_for(f)
        # Nothing left ahead — fall through to the global scan so a genuinely
        # skipped earlier episode (or the all-completed rewatch) is surfaced.

    # Walk files in order — return first that isn't completed
    for f in files:
        if not file_progs.get(f.get("path", ""), {}).get("completed"):
            return _hint_for(f)

    # All completed — point back to first so user can rewatch
    f = files[0]
    return {
        "file_path": f.get("path", ""),
        "episode_name": f.get("name", ""),
        "position_sec": 0,
        "duration_sec": 0,
        "pct": 100,
        "all_completed": True,
        "shuffle": bool(prof.get("shuffle")),
        "shuffle_scope": prof.get("shuffle_scope", "") or "",
    }


def _merged_series_files(items: list[dict]) -> list[dict]:
    """Flatten every member item's files into one (season, episode)-ordered list,
    tagging each file with its owning ``item_id`` — the join key that lets the
    merged-series UI drive play/prep/progress against the right item."""
    out: list[dict] = []
    for it in items:
        iid = it.get("id", "")
        for f in it.get("files", []):
            g = dict(f)
            g["item_id"] = iid
            out.append(g)
    out.sort(key=lambda f: (f.get("season", 0) or 9999,
                            f.get("episode", 0) or 9999, f.get("name", "")))
    return out


def find_series_resume_hint(items: list[dict], profile_id: str) -> Optional[dict]:
    """Series-level resume across a show whose episodes live in separate items.
    Picks the most-recently-updated non-completed episode (so "continue watching"
    lands on whatever the viewer last had open), else the first unwatched episode
    in order, else the first episode (all-completed rewatch). Returns a hint that
    also carries the owning ``item_id`` so the caller knows which item to seek."""
    if not profile_id:
        return None
    files = _merged_series_files(items)
    if not files:
        return None
    prog_by_item = {
        it.get("id", ""): it.get("progress", {}).get(profile_id, {}).get("file_progress", {})
        for it in items
    }

    def _fp(f):
        return prog_by_item.get(f.get("item_id", ""), {}).get(f.get("path", ""), {})

    def _hint(f, *, all_completed=False):
        fp = _fp(f)
        pos = 0 if all_completed else fp.get("position_sec", 0)
        dur = 0 if all_completed else fp.get("duration_sec", 0)
        return {
            "item_id": f.get("item_id", ""),
            "file_path": f.get("path", ""),
            "episode_name": f.get("name", Path(f.get("path", "")).name),
            "position_sec": pos,
            "duration_sec": dur,
            "pct": round(pos / dur * 100, 1) if dur else (100 if all_completed else 0),
            **({"all_completed": True} if all_completed else {}),
        }

    # Most-recently-touched un-finished episode.
    best = None
    best_at = ""
    for f in files:
        fp = _fp(f)
        if fp and not fp.get("completed") and fp.get("position_sec", 0) > 5:
            at = fp.get("updated_at", "")
            if best is None or at > best_at:
                best, best_at = f, at
    if best is not None:
        return _hint(best)

    # First unwatched in order.
    for f in files:
        if not _fp(f).get("completed"):
            return _hint(f)

    # Everything watched → rewatch from the top.
    return _hint(files[0], all_completed=True)


# ── Track Preference Helpers ──────────────────────────────────────────────────

async def _save_track_pref(
    item_id: str, profile_id: str, file_path: str,
    audio: Optional[int] = None, subtitle: Optional[int] = None,
    sub_sel: Optional[dict] = None, audio_sel: Optional[dict] = None,
) -> None:
    """Persist audio/subtitle track preference for a file into library.json.

    `sub_sel`/`audio_sel` are the resolvable descriptors written alongside the
    raw VLC ES IDs — they're what the on-device player (and a VLC replay whose
    ES IDs drifted, or the next episode of the series) restore from."""
    try:
        async with _lib_lock:
            lib = await asyncio.to_thread(_load_lib_raw)
            item = next((it for it in lib["items"] if it["id"] == item_id), None)
            if not item:
                return
            fp = (item.setdefault("progress", {})
                      .setdefault(profile_id, {})
                      .setdefault("file_progress", {})
                      .setdefault(file_path, {}))
            if audio is not None:
                fp["audio_track"] = audio
            if subtitle is not None:
                fp["subtitle_track"] = subtitle
            if sub_sel is not None:
                norm = _norm_sub_sel(sub_sel)
                if norm:
                    norm.setdefault("at", _now_iso())   # newest-wins vs series pick
                    fp["subtitle_sel"] = norm
            if audio_sel is not None:
                norm = _norm_audio_sel(audio_sel)
                if norm:
                    norm.setdefault("at", _now_iso())   # newest-wins vs series pick
                    fp["audio_sel"] = norm
            await asyncio.to_thread(_save_lib_raw, lib)
    except Exception:
        pass


async def _set_shuffle_pref(item_id: str, profile_id: str, shuffle: bool, scope: str = "") -> None:
    """Remember whether this item's playback (for a profile) is Shuffle Play.

    Shuffle's live order (state.library_shuffle_order / the device's lp.playlist)
    is ephemeral — gone on stop. This per-(item,profile) flag is what survives, so
    Resume / Play All can offer to keep shuffling. `scope` is the last-used pool
    ("all" | "unwatched"), reused verbatim when the user opts to continue. Surfaced
    on the resume hint by find_resume_hint."""
    if not item_id or not profile_id:
        return
    try:
        async with _lib_lock:
            lib = await asyncio.to_thread(_load_lib_raw)
            item = next((it for it in lib["items"] if it["id"] == item_id), None)
            if not item:
                return
            prof = item.setdefault("progress", {}).setdefault(profile_id, {})
            prof["shuffle"] = bool(shuffle)
            prof["shuffle_scope"] = scope or "" if shuffle else ""
            await asyncio.to_thread(_save_lib_raw, lib)
    except Exception:
        pass


# ── Subtitle-selection descriptor + per-series memory ─────────────────────────
# A subtitle pick is remembered as a *resolvable descriptor* — not a VLC ES ID
# or HLS sidecar index, which both drift between replays (and especially once a
# late-downloaded sidecar shifts the list). The descriptor captures the user's
# intent so it survives across episodes of a series, even weeks later:
#   {off: bool, lang: "<canon>", ai: bool, name: "<sidecar filename>",
#    title: "<norm track title>", idx: <embedded-text index>, sig: "<track sig>",
#    at: "<iso pick time>"}
# `name` enables an exact re-match when the same file is present; `lang`+`ai`
# drive the cross-episode / fallback match. `sig` is the episode's embedded
# TEXT-subtitle signature (see _sub_sig_of) and `idx` the pick's position in
# that list — together they re-apply the exact slot on any episode with the
# same track layout, even when tracks carry no language/title tags at all.
# `at` (pick time) drives newest-wins between a per-file and a per-series pick.
# Stored per-file (file_progress) and per-series
# (profile["series_subtitle_prefs"][<series>]); the per-series entry also keeps
# a `groups` map — one remembered pick per track-layout signature — so a series
# stitched from several releases (different sub options per episode group)
# remembers the right pick for EACH group.

def _norm_sub_title(t: object) -> str:
    """Normalized (lowercased, whitespace-collapsed) container track title."""
    return re.sub(r"\s+", " ", str(t or "").strip().lower())


def _sub_fuzzy_name(name: str) -> str:
    """Episode-invariant core of a sidecar subtitle filename: lowercase stem
    with SxxEyy / digits / separators stripped. Lets 'Show.S01E02.en.srt' match
    the 'Show.S01E05.en.srt' pick from another episode when the language can't
    be parsed. Keep in sync with the client's _lpSubFuzzyName."""
    stem = Path(str(name or "")).stem.lower()
    stem = re.sub(r"s\d{1,2}[ ._-]?e\d{1,3}", "", stem)
    stem = re.sub(r"\d+", "", stem)
    return re.sub(r"[^a-z]+", "", stem)


# VLC codec strings that mean an image-based subtitle (PGS/VobSub/…) — excluded
# from the track signature because HLS bundles carry text subs only, and the
# signature must be identical between the VLC and on-device players.
_VLC_IMAGE_SUB_HINTS = ("pgs", "vobsub", "dvd", "dvb", "xsub", "bitmap")


def _vlc_track_is_image_sub(t: dict) -> bool:
    c = (t.get("codec") or "").lower()
    return any(h in c for h in _VLC_IMAGE_SUB_HINTS)


def _vlc_embedded_text_subs(tracks: list[dict]) -> list[dict]:
    """The embedded (non-sidecar) text subtitle tracks, in container order —
    the index space the descriptor's sig/idx pair addresses. Takes annotated
    tracks (with `path` set for loaded sidecars)."""
    return [t for t in tracks if not t.get("path") and not _vlc_track_is_image_sub(t)]


def _sub_sig_of(tracks: list[dict]) -> str:
    """Layout signature of an episode's embedded text subtitle list: one
    'lang:title' token per track, in order. Two episodes with the same
    signature have interchangeable track indices. Keep in sync with the
    client's _lpSubSig (bundle meta subtitles are the same list)."""
    return "|".join(
        f"{t.get('lang') or 'und'}:{_norm_sub_title(t.get('title'))}" for t in tracks
    )


def _norm_sub_sel(sel: Optional[dict]) -> Optional[dict]:
    """Normalize/validate a subtitle-selection descriptor; None if unusable."""
    if not isinstance(sel, dict):
        return None
    at = str(sel.get("at") or "")
    if sel.get("off"):
        out: dict = {"off": True, "lang": "", "ai": False, "name": ""}
        if at:
            out["at"] = at
        return out
    lang = _canon_lang(str(sel.get("lang") or "")) if sel.get("lang") else ""
    if lang == "und":
        lang = ""
    name = str(sel.get("name") or "")
    title = _norm_sub_title(sel.get("title"))
    sig = str(sel.get("sig") or "")
    try:
        idx = int(sel.get("idx", -1) if sel.get("idx") is not None else -1)
    except (TypeError, ValueError):
        idx = -1
    if not (lang or name or title or (sig and idx >= 0)):
        return None                       # nothing matchable
    out = {"off": False, "lang": lang, "ai": bool(sel.get("ai")), "name": name,
           "title": title, "idx": idx, "sig": sig}
    if at:
        out["at"] = at
    return out


def _get_series_sub_sel(lib: dict, profile_id: str, series: str) -> Optional[dict]:
    """The remembered subtitle descriptor for this profile + series, if any."""
    series = (series or "").strip()
    if not (series and profile_id):
        return None
    prof = next((p for p in lib.get("profiles", []) if p.get("id") == profile_id), None)
    if not prof:
        return None
    return (prof.get("series_subtitle_prefs", {}) or {}).get(series)


async def _save_series_sub_sel(profile_id: str, series: str, sel: Optional[dict]) -> None:
    """Persist a subtitle descriptor for this profile + series so the same kind
    of subtitle is auto-applied on the next episode (and on return weeks later).

    Besides the latest pick, the entry accumulates a `groups` map — signature →
    descriptor — one per distinct episode track-layout the viewer has picked on.
    A series mixing releases (episodes 1–8 with one set of sub options, 9–12
    with another) then resolves each episode against ITS group's remembered
    pick instead of hoping the latest pick's language happens to match. An
    explicit 'off' pick becomes the latest descriptor but keeps the groups, so
    re-enabling subs later still restores each group's exact track."""
    series = (series or "").strip()
    sel = _norm_sub_sel(sel)
    if not (series and profile_id and sel):
        return
    sel.setdefault("at", _now_iso())
    try:
        async with _lib_lock:
            lib = await asyncio.to_thread(_load_lib_raw)
            prof = next((p for p in lib.get("profiles", []) if p.get("id") == profile_id), None)
            if not prof:
                return
            prefs = prof.setdefault("series_subtitle_prefs", {})
            prev = prefs.get(series) or {}
            groups = dict(prev.get("groups") or {})
            if not sel.get("off") and sel.get("sig"):
                groups[sel["sig"]] = {k: v for k, v in sel.items() if k != "groups"}
            if len(groups) > 16:          # cap: drop the oldest picks
                oldest = sorted(groups, key=lambda k: str(groups[k].get("at") or ""))
                for k in oldest[:len(groups) - 16]:
                    groups.pop(k, None)
            entry = {**sel, "updated_at": _now_iso()}
            if groups:
                entry["groups"] = groups
            prefs[series] = entry
            await asyncio.to_thread(_save_lib_raw, lib)
    except Exception:
        pass


def _series_of_item(item: dict) -> str:
    """The subtitle-memory grouping key for an item: the series name when it
    belongs to one, else a stable per-item key ("item:<id>"). The fallback is
    what carries a subtitle pick from one episode to the next inside a
    multi-file item that was never tagged with a series (season packs, and the
    default ""-series from the download/upload flows) — with a bare ""
    key the per-series save silently no-oped and picks never crossed
    episodes for those items."""
    s = (item.get("series") or "").strip()
    if s:
        return s
    return f"item:{item.get('id')}" if item.get("id") else ""


# ── Audio-selection descriptor + per-series memory ───────────────────────────
# Mirrors the subtitle machinery above, simplified: audio tracks are always
# embedded (no sidecars, no AI, never "off"), so an audio pick is remembered as
# {lang, title, idx, sig, at} — no name/ai/off fields. `sig` is the episode's
# audio-track layout signature (one `lang:title` token per track, in container
# order — identical between the VLC status list and the HLS bundle meta, so a
# pick made on the TV resolves on the phone and vice versa). `idx` is the pick's
# slot in that list, so episodes with the same layout restore the exact track
# even when tracks carry no language/title tags. Stored per-file
# (file_progress[path].audio_sel) and per-series
# (profile["series_audio_prefs"][<key>]); the per-series entry also keeps a
# `groups` map — one pick per distinct layout signature — for series stitched
# from several releases. Keep _resolve_audio_descriptor in sync with the client
# _lpResolveAudioSel.

def _audio_sig_of(tracks: list[dict]) -> str:
    """Layout signature of an audio-track list: one 'lang:title' token per
    track, in order. `tracks` are VLC audio tracks ({language, title, …}); the
    client computes the same over the bundle's audios[]. Keep in sync."""
    return "|".join(
        f"{_canon_lang(t.get('language', '')) or 'und'}:{_norm_sub_title(t.get('title'))}"
        for t in tracks
    )


def _norm_audio_sel(sel: Optional[dict]) -> Optional[dict]:
    """Normalize/validate an audio-selection descriptor; None if unusable."""
    if not isinstance(sel, dict):
        return None
    lang = _canon_lang(str(sel.get("lang") or "")) if sel.get("lang") else ""
    if lang == "und":
        lang = ""
    title = _norm_sub_title(sel.get("title"))
    sig = str(sel.get("sig") or "")
    try:
        idx = int(sel.get("idx", -1) if sel.get("idx") is not None else -1)
    except (TypeError, ValueError):
        idx = -1
    if not (lang or title or (sig and idx >= 0)):
        return None                       # nothing matchable
    out = {"lang": lang, "title": title, "idx": idx, "sig": sig}
    at = str(sel.get("at") or "")
    if at:
        out["at"] = at
    return out


def _get_series_audio_sel(lib: dict, profile_id: str, series: str) -> Optional[dict]:
    """The remembered audio descriptor for this profile + series, if any."""
    series = (series or "").strip()
    if not (series and profile_id):
        return None
    prof = next((p for p in lib.get("profiles", []) if p.get("id") == profile_id), None)
    if not prof:
        return None
    return (prof.get("series_audio_prefs", {}) or {}).get(series)


async def _save_series_audio_sel(profile_id: str, series: str, sel: Optional[dict]) -> None:
    """Persist an audio descriptor for this profile + series so the same audio
    track (language/kind) is auto-applied on the next episode. Accumulates a
    `groups` map (signature → descriptor) so a series mixing releases resolves
    each episode against ITS layout's remembered pick."""
    series = (series or "").strip()
    sel = _norm_audio_sel(sel)
    if not (series and profile_id and sel):
        return
    sel.setdefault("at", _now_iso())
    try:
        async with _lib_lock:
            lib = await asyncio.to_thread(_load_lib_raw)
            prof = next((p for p in lib.get("profiles", []) if p.get("id") == profile_id), None)
            if not prof:
                return
            prefs = prof.setdefault("series_audio_prefs", {})
            prev = prefs.get(series) or {}
            groups = dict(prev.get("groups") or {})
            if sel.get("sig"):
                groups[sel["sig"]] = {k: v for k, v in sel.items() if k != "groups"}
            if len(groups) > 16:          # cap: drop the oldest picks
                oldest = sorted(groups, key=lambda k: str(groups[k].get("at") or ""))
                for k in oldest[:len(groups) - 16]:
                    groups.pop(k, None)
            entry = {**sel, "updated_at": _now_iso()}
            if groups:
                entry["groups"] = groups
            prefs[series] = entry
            await asyncio.to_thread(_save_lib_raw, lib)
    except Exception:
        pass


# ── Profile-level preferred-audio-language memory ────────────────────────────
# The per-series descriptor above only crosses episodes that share a series key
# (`_series_of_item`). But episodes downloaded individually are each a SEPARATE
# library item with an empty `series` → a unique `item:<id>` key, so per-series
# audio memory never carries between them. Subtitles don't suffer this because
# the admin subtitle policy re-selects the preferred *language* on every episode
# regardless of item grouping; audio had no equivalent. This is that equivalent:
# a self-learning per-profile audio-language preference, updated on every
# deliberate pick and applied as a fallback whenever no descriptor resolves — so
# choosing e.g. Japanese once makes every later episode prefer Japanese audio,
# even across unrelated items. Stored as {lang, idx, count, at}; `idx`/`count`
# let untagged multi-audio releases (no language tags) still restore the same
# slot, but only when the track count matches (avoids picking the wrong slot on
# a differently-laid-out episode).

def _get_profile_audio_pref(lib: dict, profile_id: str) -> Optional[dict]:
    if not profile_id:
        return None
    prof = next((p for p in lib.get("profiles", []) if p.get("id") == profile_id), None)
    if not prof:
        return None
    pref = prof.get("audio_language_pref")
    return pref if isinstance(pref, dict) else None


async def _learn_profile_audio_pref(profile_id: str, sel: Optional[dict]) -> None:
    """Record the profile's preferred audio language/slot from a deliberate pick.
    Derived from the same descriptor VLC/device picks build, so both players feed
    it. A pick with neither a language nor a resolvable slot isn't learnable."""
    sel = _norm_audio_sel(sel)
    if not (profile_id and sel):
        return
    lang = sel.get("lang") or ""
    try:
        idx = int(sel.get("idx", -1))
    except (TypeError, ValueError):
        idx = -1
    sig = sel.get("sig") or ""
    count = (sig.count("|") + 1) if sig else 0
    if not (lang or (count and idx >= 0)):
        return
    try:
        async with _lib_lock:
            lib = await asyncio.to_thread(_load_lib_raw)
            prof = next((p for p in lib.get("profiles", []) if p.get("id") == profile_id), None)
            if not prof:
                return
            prof["audio_language_pref"] = {
                "lang": lang, "idx": idx, "count": count, "at": _now_iso()}
            await asyncio.to_thread(_save_lib_raw, lib)
    except Exception:
        pass


def _resolve_profile_audio_pref(pref: Optional[dict], tracks: list[dict]) -> Optional[dict]:
    """Match the profile audio-language preference against the live track list:
    language first (stable across releases), then the remembered slot only when
    this episode's audio layout has the same number of tracks."""
    if not pref or not tracks:
        return None
    lang = pref.get("lang") or ""
    if lang:
        cand = next((t for t in tracks
                     if _canon_lang(t.get("language", "")) == lang), None)
        if cand:
            return cand
    try:
        idx = int(pref.get("idx", -1))
        count = int(pref.get("count", 0))
    except (TypeError, ValueError):
        return None
    if count and count == len(tracks) and 0 <= idx < len(tracks):
        return tracks[idx]
    return None


def _resolve_audio_descriptor(sel: dict, tracks: list[dict]) -> Optional[dict]:
    """Match a remembered audio descriptor against the live VLC audio-track list
    (each {id, language, title, …}). Returns the matched track or None. Mirrors
    the on-device _lpResolveAudioSel. Order:
      1. same track layout (sig) → same slot (idx);
      2. group memory: the pick remembered for THIS episode's layout;
      3. language;
      4. container title.
    """
    if not sel:
        return None
    cur_sig = _audio_sig_of(tracks)

    def _try_exact(d: dict) -> Optional[dict]:
        sig = d.get("sig") or ""
        try:
            idx = int(d.get("idx", -1) if d.get("idx") is not None else -1)
        except (TypeError, ValueError):
            idx = -1
        if sig and 0 <= idx < len(tracks) and sig == cur_sig:
            return tracks[idx]
        return None

    cand = _try_exact(sel)
    if cand:
        return cand
    grp = (sel.get("groups") or {}).get(cur_sig)
    if isinstance(grp, dict):
        cand = _try_exact(grp)
        if cand:
            return cand
        try:
            gidx = int(grp.get("idx", -1) or -1)
        except (TypeError, ValueError):
            gidx = -1
        if 0 <= gidx < len(tracks):
            return tracks[gidx]
    slang = sel.get("lang") or ""
    if slang:
        cand = next((t for t in tracks
                     if _canon_lang(t.get("language", "")) == slang), None)
        if cand:
            return cand
    stitle = _norm_sub_title(sel.get("title"))
    if stitle:
        cand = next((t for t in tracks
                     if _norm_sub_title(t.get("title")) == stitle), None)
        if cand:
            return cand
    return None


async def _load_all_local_subs(video: Path) -> list[dict]:
    """Load *every* sidecar subtitle found for `video` into VLC so they all show
    up as selectable tracks, then return the resulting subtitle-track list — each
    entry annotated with a best-guess `lang` (VLC's own tag when present, else
    parsed from the source filename, since VLC rarely tags loose sidecars).

    Subs are added one at a time so we can map each freshly-created ES ID back to
    the language we parsed from its filename — and, crucially, whether it's an AI
    sidecar (`_is_ai_sub_file`). VLC's own sidecar autodetect is disabled at launch
    (`--no-sub-autodetect-file`) precisely so this is the *only* path that loads
    sidecars: an AI `.srt` VLC auto-loaded would arrive untagged and read as a real
    track, which the policy would then prefer over a genuine sub. Any track already
    present here is therefore an embedded (in-container) track. The skip-on-no-new
    branch below is a harmless safety net (e.g. a sub already loaded by a download).
    """
    tracks = await _vlc_subtitle_tracks()
    known_ids = {t["id"] for t in tracks}
    lang_by_id = {t["id"]: _canon_lang(t.get("language", "")) for t in tracks}
    # Embedded tracks (present before we add anything) are real, not AI; sidecars
    # we load get their `ai`/path tagged as they're added. Lets the policy prefer
    # a real preferred-language sub over an AI one for the same language.
    meta_by_id: dict[int, dict] = {}

    for sub in await asyncio.to_thread(_discover_local_subs, video):
        guess = _parse_sub_lang(sub.name)
        is_ai = _is_ai_sub_file(sub)
        await vlc("addsubtitle", val=str(sub))
        await asyncio.sleep(0.3)
        after = await _vlc_subtitle_tracks()
        new = [t for t in after if t["id"] not in known_ids]
        if not new:
            continue                      # VLC already had this sidecar loaded
        for t in new:
            known_ids.add(t["id"])
            lang_by_id[t["id"]] = _canon_lang(t.get("language", "")) or guess
            meta_by_id[t["id"]] = {"ai": is_ai, "path": str(sub)}
        tracks = after

    annotated = [{**t,
                  "lang": lang_by_id.get(t["id"], _canon_lang(t.get("language", ""))),
                  "ai":   meta_by_id.get(t["id"], {}).get("ai", False),
                  "path": meta_by_id.get(t["id"], {}).get("path", "")}
                 for t in tracks]
    # Remember each track's lang/ai/sidecar-path so a later manual pick can be
    # persisted as a resolvable descriptor (see set_subtitle_track).
    state.vlc_sub_meta = {t["id"]: {"lang": t["lang"], "ai": t["ai"], "path": t["path"]}
                          for t in annotated}
    return annotated


def _resolve_sub_descriptor(sel: dict, tracks: list[dict], *,
                            single_option: bool) -> Optional[dict]:
    """Match a remembered subtitle descriptor against the live annotated VLC
    track list (each entry {id, lang, ai, path, title, codec, …}). Returns the
    matched track or None. Mirrors the on-device _lpResolveSubSel — keep the
    two chains in sync. Order:
      1. exact sidecar filename;
      2. same track layout (sig) → same embedded slot (idx);
      3. group memory: the pick remembered for THIS episode's layout;
      4. fuzzy sidecar filename (episode-number-invariant), kind-aware;
      5. language — same kind (real/AI) first, then any;
      6. embedded track with the same container title;
      7. lone real option (admin single_option).
    """
    if not sel or sel.get("off"):
        return None
    real = [t for t in tracks if not t.get("ai")]
    emb_text = _vlc_embedded_text_subs(tracks)
    cur_sig = _sub_sig_of(emb_text)

    def _try_exact(d: dict) -> Optional[dict]:
        name = d.get("name") or ""
        if name:
            c = next((t for t in tracks if t.get("path")
                      and Path(t["path"]).name == name), None)
            if c:
                return c
        sig = d.get("sig") or ""
        try:
            idx = int(d.get("idx", -1) if d.get("idx") is not None else -1)
        except (TypeError, ValueError):
            idx = -1
        if sig and 0 <= idx < len(emb_text) and sig == cur_sig:
            return emb_text[idx]
        return None

    cand = _try_exact(sel)
    if cand:
        return cand
    grp = (sel.get("groups") or {}).get(cur_sig)
    if isinstance(grp, dict) and not grp.get("off"):
        cand = _try_exact(grp)
        if cand:
            return cand
        try:
            gidx = int(grp.get("idx", -1) or -1)
        except (TypeError, ValueError):
            gidx = -1
        if 0 <= gidx < len(emb_text):
            return emb_text[gidx]
    fuzzy = _sub_fuzzy_name(sel.get("name") or "")
    if fuzzy:
        side = [t for t in tracks if t.get("path")]
        kind = [t for t in side if bool(t.get("ai")) == bool(sel.get("ai"))]
        for pool in (kind, side):
            cand = next((t for t in pool
                         if _sub_fuzzy_name(Path(t["path"]).name) == fuzzy), None)
            if cand:
                return cand
    slang = sel.get("lang") or ""
    if slang:
        ai = [t for t in tracks if t.get("ai")]
        pool = ai if sel.get("ai") else real
        cand = (next((t for t in pool if t["lang"] == slang), None)
                or next((t for t in tracks if t["lang"] == slang), None))
        if cand:
            return cand
    stitle = _norm_sub_title(sel.get("title"))
    if stitle:
        cand = next((t for t in emb_text
                     if _norm_sub_title(t.get("title")) == stitle), None)
        if cand:
            return cand
    if single_option and len(real) == 1:
        return real[0]
    return None


async def _apply_subtitle_policy(lib: dict, profile_id: str, file_path: str,
                                 series_sel: Optional[dict] = None) -> None:
    """Decide and *explicitly* set the subtitle track for a freshly-started file
    when the viewer has no saved per-file pick. `series_sel` is the remembered
    per-series subtitle descriptor (if any), honoured ahead of the generic policy.

    Resolves subs on/off (profile `subtitles_on` override → admin `on_by_default`).
    Off ⇒ send `subtitle_track -1` so VLC can't sneak its auto/forced sub on (it
    otherwise does, even when the UI says off — see docs/GOTCHAS.md). On ⇒ first
    aggressively load *all* sidecar subs for the file into VLC (covering `Subs/`
    folders and the like — see `_discover_local_subs`), so every option is
    selectable, then select, in priority order:
      (a) an embedded/loaded track in the preferred language (any track if the
          admin chose "Any") — embedded tracks rank ahead of sidecars;
      (b) an online auto-search download in the preferred language (if enabled);
      (c) when a remembered ON descriptor is pending (the viewer chose subs for
          this series), a last-resort real track — never silently revert to off;
      (d) otherwise leave subtitles off.
    """
    subs = _subs_cfg(lib)
    prof = next((p for p in lib.get("profiles", []) if p["id"] == profile_id), {})
    override = prof.get("subtitles_on")
    subs_on = subs["on_by_default"] if override is None else bool(override)

    # Any prior auto-applied-AI marker is stale on a fresh selection; re-set
    # below only if we deliberately land on an AI track.
    state.sub_auto_ai_path = ""

    pref = _canon_lang(subs["default_language"]) if subs["default_language"] else ""
    video = Path(file_path)

    if not subs_on and not series_sel:
        # Subtitles default off — but still load every sidecar so they show up as
        # selectable tracks in the menu (the on-device player lists all discovered
        # subs regardless of the on/off default; VLC was hiding sidecars entirely
        # when off, so the menus disagreed — see docs/GOTCHAS.md). Force the
        # selection off afterwards (addsubtitle auto-enables the last one added).
        # An explicit remembered descriptor (`series_sel` — per-file or per-series
        # user pick) skips this gate: a deliberate pick beats the off default,
        # exactly like a saved per-file ES-ID pick does.
        if video.exists():
            await _load_all_local_subs(video)
        state.current_subtitle_track = -1
        await vlc("subtitle_track", val="-1")
        return

    # (a) Load every local sidecar (Subs/ folders included) + embedded tracks,
    #     then pick the preferred language. Tracks come embedded-first, so a
    #     `next()` match prefers an embedded track over a loaded sidecar.
    if video.exists():
        tracks = await _load_all_local_subs(video)
    else:
        tracks = [{**t, "lang": _canon_lang(t.get("language", "")), "ai": False, "path": ""}
                  for t in await _vlc_subtitle_tracks()]

    async def _select(track: dict) -> None:
        state.current_subtitle_track = track["id"]
        # Remember when the chosen track is an AI sub so the upgrade loop can
        # swap in a real preferred-language sub once it finishes downloading.
        state.sub_auto_ai_path = track.get("path", "") if track.get("ai") else ""
        await vlc("subtitle_track", val=str(track["id"]))

    real = [t for t in tracks if not t.get("ai")]
    ai   = [t for t in tracks if t.get("ai")]

    # Per-series memory: honour the kind of subtitle the viewer last chose for
    # this series (real vs AI vs off), falling back across kinds when the exact
    # one isn't present on this episode. Takes priority over the generic policy.
    want_on = bool(series_sel) and not series_sel.get("off")
    if series_sel:
        if series_sel.get("off"):
            state.current_subtitle_track = -1
            await vlc("subtitle_track", val="-1")
            return
        cand = _resolve_sub_descriptor(series_sel, tracks,
                                       single_option=subs["single_option"])
        if cand:
            await _select(cand)
            return
        # The remembered ON pick didn't resolve on this episode. Do NOT revert
        # to off (that pick IS the on switch for this series, regardless of the
        # admin/profile default) — fall through to the generic policy, and a
        # last-resort track below if that also comes up empty.

    if pref:
        # Prefer a REAL preferred-language track over an AI one for that language.
        match = next((t for t in real if t["lang"] == pref), None)
        # Only one real option and no exact match → assume it's the right one.
        if match is None and subs["single_option"] and len(real) == 1:
            match = real[0]
        # Fall back to an AI track in the preferred language; the upgrade loop
        # will replace it with a real sub when one arrives (if enabled).
        if match is None:
            match = next((t for t in ai if t["lang"] == pref), None)
        if match:
            await _select(match)
            return
    elif tracks:
        # "Any" preferred language — prefer a real track, else anything available.
        await _select(real[0] if real else tracks[0])
        return

    # (b) auto-search OpenSubtitles for the preferred language.
    if subs["auto_search"] and pref and video.exists():
        new_id = await _auto_fetch_subtitle(video, pref)
        if new_id is not None:
            return

    # (c) the viewer chose subs for this series but nothing matched — pick the
    #     least-surprising available track rather than silently reverting to
    #     off (avoid signs/commentary-titled tracks when possible).
    if want_on and tracks:
        avoid = ("sign", "song", "commentary", "forced")
        cand = (next((t for t in real
                      if not any(a in _norm_sub_title(t.get("title")) for a in avoid)),
                     None)
                or (real[0] if real else None)
                or tracks[0])
        await _select(cand)
        return

    # (d) nothing usable — leave subtitles off.
    state.current_subtitle_track = -1
    await vlc("subtitle_track", val="-1")


async def _reassert_audio(a_sel: Optional[dict], prof_pref: Optional[dict],
                          raw_id: Optional[int]) -> None:
    """Re-send the chosen audio track a few times after the initial pick.

    VLC re-runs its own default audio selection as the input finishes buffering
    (common with sequential torrent streaming, where the head trickles in),
    silently overriding the `audio_track` command `_apply_track_prefs` just sent.
    The symptom: the dropdown shows the remembered track (it mirrors
    `state.current_audio_track`, which we set) while VLC actually plays its
    default — e.g. Japanese under an English dub. VLC 3.x's HTTP API can't report
    the current audio track, so we can't read-verify; instead re-assert the pick
    a few times over the next few seconds so a late default-select loses.

    Re-resolves each pass in case ES IDs drifted, and stops the instant a manual
    pick (`set_audio_track`) or a newer `_apply_track_prefs` changes the state we
    set — otherwise this would fight the viewer's own choice. A new video resets
    `state.current_audio_track` to -1, which also trips that guard and ends the
    loop harmlessly.
    """
    last = state.current_audio_track
    for _ in range(4):
        await asyncio.sleep(1.0)
        if state.current_audio_track != last:
            return                         # superseded by a manual/newer pick
        audio_tracks, _ = _parse_track_streams(await vlc_status())
        if not audio_tracks:
            continue
        recand = None
        if a_sel is not None:
            recand = _resolve_audio_descriptor(a_sel, audio_tracks)
        if recand is None and prof_pref is not None:
            recand = _resolve_profile_audio_pref(prof_pref, audio_tracks)
        if recand is not None:
            rid: Optional[int] = recand["id"]
        elif raw_id is not None and any(t["id"] == raw_id for t in audio_tracks):
            rid = raw_id                   # raw ES ID still present on this input
        else:
            rid = None
        if rid is None:
            continue
        state.current_audio_track = rid
        await vlc("audio_track", val=str(rid))
        last = rid


async def _apply_track_prefs(
    item_id: str, profile_id: str, file_path: str, delay: float = 2.0,
) -> None:
    """Apply audio/subtitle tracks for a file after a short delay.

    Audio + subtitle honour any saved per-file preference. With no saved subtitle
    pick, the subtitle track falls through to the admin/profile default policy
    (`_apply_subtitle_policy`), which tells VLC *explicitly* whether subs are on
    or off — VLC otherwise auto-enables its first/forced sub even when subs should
    be off. See docs/GOTCHAS.md.
    """
    try:
        await asyncio.sleep(delay)
        lib = await get_library()
        item = next((it for it in lib["items"] if it["id"] == item_id), None)
        if not item:
            return
        fp = (item.get("progress", {})
                  .get(profile_id, {})
                  .get("file_progress", {})
                  .get(file_path, {}))
        audio = fp.get("audio_track")
        subtitle = fp.get("subtitle_track")
        # Audio: newest intent wins between the per-file descriptor (`at`) and
        # the per-series pick (`updated_at`) — a track chosen later on another
        # episode/device beats a stale per-file pick. The raw ES-ID fast path
        # only applies when it isn't outranked by a newer series pick (embedded
        # audio ES IDs are container-derived and stable across replays of the
        # SAME file, but meaningless on a different episode — there the
        # descriptor drives selection against the live track list).
        a_file_sel = _norm_audio_sel(fp.get("audio_sel"))
        a_series_sel = _get_series_audio_sel(lib, profile_id, _series_of_item(item))
        a_chose_file = a_file_sel is not None
        a_sel = a_file_sel if a_chose_file else a_series_sel
        if a_file_sel and a_series_sel:
            f_at = _parse_iso_dt(a_file_sel.get("at"))
            s_at = _parse_iso_dt(a_series_sel.get("updated_at"))
            if s_at and (f_at is None or s_at > f_at):
                a_sel, a_chose_file = a_series_sel, False
        if a_chose_file and a_series_sel and isinstance(a_series_sel.get("groups"), dict):
            a_sel = {**a_sel, "groups": a_series_sel["groups"]}
        # Profile-level preferred-audio-language fallback — the audio analog of
        # the subtitle language default. Carries a pick across episodes even when
        # they're separate library items (no shared series key), which is the
        # common case for individually-downloaded episodes.
        prof_pref = _get_profile_audio_pref(lib, profile_id)
        if audio is not None and (a_sel is None or a_chose_file):
            state.current_audio_track = audio
            await vlc("audio_track", val=str(audio))
            # Same file replay: ES IDs are stable, so re-assert the raw pick too
            # (VLC can still override it with its default as buffering finishes).
            asyncio.create_task(_reassert_audio(None, None, audio))
        elif a_sel is not None or prof_pref is not None:
            # Resolve against the LIVE audio-track list. VLC populates that list
            # asynchronously after opening a stream, so a single snapshot at the
            # fixed `delay` can arrive before the tracks exist — the resolve then
            # finds nothing and audio silently stays on VLC's default. That race
            # is exactly what made cross-episode audio memory "sometimes" work.
            # Poll briefly (up to ~4 s) until tracks appear, then resolve the
            # per-file/series descriptor first, else the profile language pref; a
            # genuinely unmatchable pick just falls through harmlessly.
            cand = None
            for _attempt in range(8):
                audio_tracks, _ = _parse_track_streams(await vlc_status())
                if audio_tracks:
                    if a_sel is not None:
                        cand = _resolve_audio_descriptor(a_sel, audio_tracks)
                    if cand is None and prof_pref is not None:
                        cand = _resolve_profile_audio_pref(prof_pref, audio_tracks)
                    if cand or len(audio_tracks) > 1:
                        break
                await asyncio.sleep(0.5)
            if cand:
                state.current_audio_track = cand["id"]
                await vlc("audio_track", val=str(cand["id"]))
                # Re-assert in the background so a late default-select loses; the
                # subtitle work below must not wait on it.
                asyncio.create_task(_reassert_audio(a_sel, prof_pref, None))
        # Newest intent wins between the per-file and the per-series subtitle
        # descriptor: a pick made later on another episode (or on the device)
        # beats a stale per-file pick. This is also what heals per-file `off`
        # descriptors older builds wrote as a side effect of audio changes.
        # Legacy picks without timestamps are treated as oldest.
        file_sel = _norm_sub_sel(fp.get("subtitle_sel"))
        series_sel = _get_series_sub_sel(lib, profile_id, _series_of_item(item))
        chose_file = file_sel is not None
        sel = file_sel if chose_file else series_sel
        if file_sel and series_sel:
            f_at = _parse_iso_dt(file_sel.get("at"))
            s_at = _parse_iso_dt(series_sel.get("updated_at"))
            if s_at and (f_at is None or s_at > f_at):
                sel, chose_file = series_sel, False
        if chose_file and series_sel and isinstance(series_sel.get("groups"), dict):
            # Group memory lives on the series entry — carry it so an exact
            # per-layout match still works when the file's own pick wins.
            sel = {**sel, "groups": series_sel["groups"]}

        if subtitle is not None and (sel is None
                                     or (chose_file and not sel.get("off")
                                         and not sel.get("name"))):
            # Raw VLC ES-ID pick for THIS file, not outranked by a newer series
            # pick. Embedded ES IDs are container-derived and stable across
            # replays; sidecar IDs drift with load order, so a sidecar pick
            # (descriptor carries `name`) resolves via the descriptor branch
            # instead. VLC's own sidecar autodetect is disabled, so load every
            # sidecar ourselves first — otherwise the subtitle menu would show
            # only embedded tracks. (The descriptor branch loads them via
            # _apply_subtitle_policy.)
            video = Path(file_path)
            if video.exists():
                await _load_all_local_subs(video)
            state.current_subtitle_track = subtitle
            state.sub_auto_ai_path = ""           # an explicit pick isn't auto-AI
            await vlc("subtitle_track", val=str(subtitle))
        else:
            # No usable raw pick — resolve the winning descriptor (per-file or
            # per-series). This is what makes a subtitle chosen on the phone
            # survive a switch back to VLC playback.
            await _apply_subtitle_policy(lib, profile_id, file_path, series_sel=sel)
        state.track_pref_applied_file = file_path
    except Exception:
        pass


# ── Background Task: Mullvad Guard ───────────────────────────────────────────

async def vpn_guard() -> None:
    """Poll `mullvad status` every 3 s; kill qBittorrent if not connected."""
    while True:
        try:
            proc = await asyncio.create_subprocess_exec(
                "mullvad", "status",
                stdout=asyncio.subprocess.PIPE,
                stderr=asyncio.subprocess.PIPE,
            )
            out, _ = await proc.communicate()
            text = out.decode(errors="replace")
            connected = "Connected" in text
            first_line = text.strip().splitlines()[0] if text.strip() else "Unknown"
            state.vpn_status_text = first_line

            if not connected and state.vpn_secure:
                state.vpn_secure = False
                pname = "qbittorrent.exe" if platform.system() == "Windows" else "qbittorrent"
                for p in psutil.process_iter(["name"]):
                    if (p.info["name"] or "").lower() == pname.lower():
                        try:
                            p.kill()
                        except psutil.NoSuchProcess:
                            pass
                await broadcast("vpn_status", {"secure": False, "status": first_line, "block_ui": state.vpn_block_ui})

            elif connected and not state.vpn_secure:
                state.vpn_secure = True
                await broadcast("vpn_status", {"secure": True, "status": first_line, "block_ui": state.vpn_block_ui})

        except FileNotFoundError:
            state.vpn_status_text = "mullvad CLI not installed"
        except Exception:
            pass

        await asyncio.sleep(3)


# ── Background Task: Jackett Health Monitor ──────────────────────────────────

async def jackett_health_monitor() -> None:
    """Poll Jackett over HTTP regularly so the dashboard knows when the indexer
    is unreachable, and — as a backstop to the process watchdog — kick a local
    restart if Jackett stays wedged for an extended period.

    The watchdog (run.py / the installed service) is the primary supervisor and
    recovers a hung Jackett within seconds. This in-app monitor only force-
    restarts after a *long* sustained outage, so it never duels a healthy
    watchdog: if the watchdog can recover Jackett it already has, and this path
    stays dormant. It also covers running the dashboard without the watchdog.

    Reachability here means "answers HTTP", not "port is open" — a hung Jackett
    keeps the port bound while it stops serving, which is the failure mode that
    used to require a reboot.
    """
    CHECK_EVERY         = 20    # seconds between probes
    FAIL_BEFORE_RESTART = 6     # ~2 min of sustained failure before a backstop restart

    base = settings.indexer_url.rstrip("/")
    m = re.search(r"https?://([^:/]+)", settings.indexer_url)
    host = m.group(1) if m else "127.0.0.1"
    is_local = host in ("localhost", "127.0.0.1", "::1")

    consecutive_fail = 0
    while True:
        await asyncio.sleep(CHECK_EVERY)

        serving = False
        try:
            async with httpx.AsyncClient(timeout=5.0) as c:
                await c.get(f"{base}/UI/Login")
            serving = True   # any HTTP status means the web stack is answering
        except Exception:
            serving = False

        if serving != state.jackett_ok:
            state.jackett_ok = serving
            await broadcast("jackett_status", {"ok": serving, "url": settings.indexer_url})
            print(f"[jackett] {'reachable again' if serving else 'UNREACHABLE'} at {settings.indexer_url}")

        if serving:
            consecutive_fail = 0
            continue

        consecutive_fail += 1
        if is_local and consecutive_fail >= FAIL_BEFORE_RESTART:
            print(f"[jackett] unreachable for ~{consecutive_fail * CHECK_EVERY}s — "
                  "attempting in-app backstop restart")
            try:
                from watchdog import restart_jackett
                ok = await asyncio.to_thread(restart_jackett)
                print(f"[jackett] backstop restart {'succeeded' if ok else 'failed'}")
            except Exception as exc:
                print(f"[jackett] backstop restart errored: {exc}")
            consecutive_fail = 0   # cooldown — re-evaluate fresh on the next probes


# ── Machine Reboot / Scheduled Restart ───────────────────────────────────────

def _reboot_commands() -> list[list[str]]:
    """Platform-appropriate reboot command(s), tried in order until one works.

    On macOS the launchd *user agent* can restart via System Events without
    sudo; we fall back to `sudo -n shutdown` (passwordless) then a bare
    `shutdown` for setups that allow it. Linux prefers `systemctl reboot`.
    """
    sysname = platform.system()
    if sysname == "Windows":
        return [["shutdown", "/r", "/t", "0"]]
    if sysname == "Darwin":
        return [
            ["osascript", "-e", 'tell application "System Events" to restart'],
            ["sudo", "-n", "shutdown", "-r", "now"],
            ["shutdown", "-r", "now"],
        ]
    # Linux / other Unix
    return [
        ["systemctl", "reboot"],
        ["sudo", "-n", "shutdown", "-r", "now"],
        ["shutdown", "-r", "now"],
    ]


def _do_reboot_blocking() -> bool:
    """Fire the reboot. Returns True if a command was accepted. Blocking — run
    via asyncio.to_thread. The machine usually goes down before this returns."""
    for cmd in _reboot_commands():
        try:
            proc = subprocess.run(cmd, capture_output=True, text=True, timeout=20)
            if proc.returncode == 0:
                print(f"[reboot] issued: {' '.join(cmd)}")
                return True
            print(f"[reboot] '{' '.join(cmd)}' rc={proc.returncode} "
                  f"stderr={proc.stderr.strip()[:200]}")
        except FileNotFoundError:
            continue   # command not on this platform — try the next
        except Exception as exc:
            print(f"[reboot] '{' '.join(cmd)}' errored: {exc}")
    return False


async def _reboot_machine(delay: float = 0.5) -> None:
    """Reboot the host after a short delay (lets the HTTP response flush)."""
    await asyncio.sleep(delay)
    print("[reboot] rebooting host machine now")
    ok = await asyncio.to_thread(_do_reboot_blocking)
    if not ok:
        print("[reboot] all reboot commands failed — host may lack permission. "
              "On macOS/Linux configure passwordless sudo for `shutdown`, "
              "or run the service with reboot rights.")


def _now_in_tz(tzname: str) -> datetime:
    """Current time in the named IANA tz (e.g. 'America/Los_Angeles').
    Empty / unknown tz → system local time."""
    if tzname:
        try:
            from zoneinfo import ZoneInfo
            return datetime.now(ZoneInfo(tzname))
        except Exception:
            pass
    return datetime.now()


async def _machine_in_use(window_secs: int, ignore_downloads: bool = False,
                          for_prep: bool = False) -> bool:
    """True if the box looks busy: VLC actively playing/paused real content, an
    active stream/download, or a user interaction within `window_secs`.

    `ignore_downloads=True` drops library downloads from the "busy" signal — used by
    the download scheduler's idle check so an idle-only download that's running can't
    flip the box "in use" and self-close its own idle window (see _download_idle_open).

    `for_prep=True` ALSO treats an open dashboard (a live SSE client) as "in use", so
    idle stream-prep won't hammer the box while someone has the site open — even if
    they're just looking and haven't clicked anything (a page load is a GET, which
    deliberately doesn't stamp last_activity). The scheduled reboot does NOT pass this
    (a forgotten-open tab shouldn't block the nightly reboot).
    """
    if for_prep and state.sse_queues:
        return True
    # 1. Live VLC playback of non-background content
    if not state.background_playing:
        vs = await vlc_status()
        if vs and vs.get("state") in ("playing", "paused"):
            return True
    # 2. Active stream pipeline or library downloads in flight
    if state.stream_status in ("buffering", "playing"):
        return True
    if not ignore_downloads and state.downloading_count > 0:
        return True
    # 3. Recent user-initiated HTTP interaction (set by the activity middleware)
    if state.last_activity and (time.time() - state.last_activity) < window_secs:
        return True
    return False


def _scheduled_reboot_cfg(lib: dict) -> dict:
    """Read settings.scheduled_reboot with defaults filled in."""
    cfg = (lib.get("settings", {}) or {}).get("scheduled_reboot") or {}
    return {
        "enabled":      bool(cfg.get("enabled", False)),
        "time":         str(cfg.get("time", "00:00")),
        "timezone":     str(cfg.get("timezone", "America/Los_Angeles")),
        "idle_minutes": int(cfg.get("idle_minutes", 15)),
        "last_fired":   str(cfg.get("last_fired", "")),
    }


def _autoupdate_cfg(lib: dict) -> dict:
    """Read settings.autoupdate with defaults filled in.

    The auto-updater is opt-in (default off) and pinned to the `main` branch
    unless the admin changes it. Allowed branches are enforced by updater.py;
    a stale config that names something else is sanitised to `main` on read —
    UNLESS dev mode is on, in which case any structurally-valid branch name
    (e.g. a feature branch) is honoured so a developer can ride it.
    """
    cfg = (lib.get("settings", {}) or {}).get("autoupdate") or {}
    dev_mode = bool(cfg.get("dev_mode", False))
    branch = str(cfg.get("branch", "main"))
    if branch not in updater.ALLOWED_BRANCHES \
            and not (dev_mode and updater.branch_allowed(branch, allow_any=True)[0]):
        branch = "main"
    try:
        interval = int(cfg.get("interval_hours", 6))
    except (TypeError, ValueError):
        interval = 6
    interval = max(1, min(168, interval))   # 1 h .. 1 week
    return {
        "enabled":           bool(cfg.get("enabled", False)),
        "branch":            branch,
        "dev_mode":          dev_mode,
        "interval_hours":    interval,
        "auto_apply":        bool(cfg.get("auto_apply", True)),
        "last_check_at":     int(cfg.get("last_check_at", 0)),
        "last_check_status": str(cfg.get("last_check_status", "")),
        "last_applied_at":   int(cfg.get("last_applied_at", 0)),
        "last_applied_commit": str(cfg.get("last_applied_commit", "")),
        "last_error":        str(cfg.get("last_error", "")),
    }


def _auto_prep_cfg(lib: dict) -> dict:
    """Read settings.auto_prep (the unified automatic stream-prep control) with
    defaults. One mode replaces the old overnight-window + idle pair:

      • "always" — prep every un-prepped file whenever there's anything to do,
        regardless of host activity (background work runs at below-normal priority).
      • "idle"   — prep only while the box has been idle for `idle_minutes`, and
        stop the instant activity returns. `on_activity` picks the stop kind:
        "hard" kills the in-flight encode immediately (restarts later — HLS prep
        can't checkpoint); "soft" lets the in-flight file finish, then holds.
      • "off"    — never auto-prep; only user/admin-triggered prep runs.

    **Lazy migration:** if `settings.auto_prep` is absent, derive a sensible
    default from the legacy `idle_prep` / `overnight_prep` keys so existing
    installs keep behaving — either enabled ⇒ mode "idle" (carrying the old
    idle_minutes), else "off". The new key is written on the first save."""
    settings = lib.get("settings", {}) or {}
    cfg = settings.get("auto_prep")

    if not isinstance(cfg, dict):
        # Migrate from the legacy split config.
        legacy_idle = settings.get("idle_prep") or {}
        legacy_overnight = settings.get("overnight_prep") or {}
        enabled = bool(legacy_idle.get("enabled")) or bool(legacy_overnight.get("enabled"))
        cfg = {
            "mode": "idle" if enabled else "off",
            "idle_minutes": legacy_idle.get("idle_minutes", 30),
            "on_activity": "hard",
        }

    mode = str(cfg.get("mode", "off"))
    if mode not in ("always", "idle", "off"):
        mode = "off"
    on_activity = str(cfg.get("on_activity", "hard"))
    if on_activity not in ("soft", "hard"):
        on_activity = "hard"
    try:
        idle_minutes = int(cfg.get("idle_minutes", 30))
    except (TypeError, ValueError):
        idle_minutes = 30
    idle_minutes = max(1, min(720, idle_minutes))
    return {
        "mode":         mode,
        "idle_minutes": idle_minutes,
        "on_activity":  on_activity,
    }


def _play_prep_cfg(lib: dict) -> dict:
    """Read settings.play_prep (auto on-device prep when a video is played on VLC).

    Enabled by default. When on, every VLC library play immediately HLS-preps the
    playing episode for on-device, then the rest of the playlist one at a time —
    regardless of the Automatic Stream Prep mode or live user activity (the jobs run
    as 'interactive', so the bulk pause gate and the activity-kill don't touch
    them). See `_maybe_start_play_prep` / `_play_prep_chain`."""
    cfg = (lib.get("settings", {}) or {}).get("play_prep") or {}
    return {"enabled": bool(cfg.get("enabled", True))}


_PREP_VALIDATE_MODES = ("off", "before", "after")


def _prep_validate_cfg(lib: dict) -> dict:
    """Read settings.prep_validate — auto deep-validate (and remux-repair) of a
    source file as it rides through bulk/idle stream prep.

    `mode` is one of:
      • "off"    — never validate during prep (default; manual admin scan only).
      • "before" — deep-decode the source BEFORE building its HLS bundle; if
                   damaged, remux-repair in place, then prep the healed file.
      • "after"  — build the HLS bundle first, THEN deep-decode the source; a
                   repair purges the just-built bundle so it re-preps next cycle.

    Only bulk jobs (idle auto-prep + the per-row/per-item Prep buttons) honour
    this; interactive play-on-device preps never validate so playback isn't
    delayed. The scan/repair ffmpeg runs on the GPU when NVENC is present (see
    `_decode_hwaccel_args`). Consumed in `_run_offline_job`."""
    cfg = (lib.get("settings", {}) or {}).get("prep_validate") or {}
    mode = str(cfg.get("mode", "off")).lower()
    if mode not in _PREP_VALIDATE_MODES:
        mode = "off"
    return {"mode": mode}


def _auto_maint_cfg(lib: dict) -> dict:
    """Read settings.auto_maintenance — the idle-gated background workers that
    drain the library's *outstanding* (never-run) work so it doesn't sit forever
    waiting on a manual trigger:

      • fingerprint — auto-run Smart Skip analysis for any eligible series that
        has never been fingerprinted (the periodic counterpart to the on-ready /
        post-prep hook, which only fires for newly-added content).
      • validate    — auto deep-validate source files whose persisted verdict is
        missing or stale, one at a time.

    Both run ONLY while the host is idle (no playback / recent activity) and at
    below-normal OS priority, so they never compete with viewing. Defaults ON —
    the whole point is that the backlog clears itself. Consumed by
    `background_maintenance_loop`."""
    cfg = (lib.get("settings", {}) or {}).get("auto_maintenance") or {}
    return {
        "fingerprint": bool(cfg.get("fingerprint", True)),
        "validate":    bool(cfg.get("validate", True)),
    }


def _cache_autopurge_cfg(lib: dict) -> dict:
    """Read settings.cache_autopurge (auto-evict orphan offline-cache bundles when
    the cache outgrows a size cap) with defaults.

    `max_gb` is the total `.offline_cache/` size at which a purge fires. When the
    walk reports the cache at/above this, every *orphan* bundle (cache/partial dirs
    + legacy MP4s that no longer map to a live library file) is deleted. Bundles
    backing current library files are never touched, so this can't evict something
    a viewer might still want — see `cache_autopurge_loop`."""
    cfg = (lib.get("settings", {}) or {}).get("cache_autopurge") or {}
    try:
        max_gb = float(cfg.get("max_gb", 50))
    except (TypeError, ValueError):
        max_gb = 50.0
    max_gb = max(1.0, min(10000.0, max_gb))
    return {
        "enabled": bool(cfg.get("enabled", False)),
        "max_gb":  max_gb,
    }


def _subs_cfg(lib: dict) -> dict:
    """Read settings.subtitles (the unified subtitle policy) with defaults.

    `default_language` is the preferred subtitle language (3-letter canon code,
    or "" = Any). One language drives all three subtitle features: the online-
    search default, automatic track selection on playback, AND the AI-generation
    trigger (`_stt_cfg` re-sources its language from here).

    Unconfigured ⇒ "eng": when the `subtitles` block has never been written we
    seed from the legacy `settings.stt.default_language` if it's set, else fall
    back to English. Once the block exists its stored value is used verbatim, so
    an admin who explicitly picks "Any" (saved as "") keeps it.

    `on_by_default` is the admin default for subtitles on/off (a profile may
    override via `profile["subtitles_on"]`). `auto_search` lets playback fetch a
    preferred-language subtitle from OpenSubtitles when none is embedded.
    """
    settings = lib.get("settings", {}) or {}
    cfg = settings.get("subtitles")
    if not isinstance(cfg, dict) or "default_language" not in cfg:
        # Never configured — migrate from the old STT language, else English.
        legacy = str((settings.get("stt") or {}).get("default_language", "")).strip().lower()
        default_language = _canon_lang(legacy) if legacy else "eng"
        cfg = cfg if isinstance(cfg, dict) else {}
    else:
        raw = str(cfg.get("default_language", "")).strip().lower()
        default_language = _canon_lang(raw) if raw else ""
    return {
        "default_language": default_language,
        "on_by_default":    bool(cfg.get("on_by_default", False)),
        "auto_search":      bool(cfg.get("auto_search", True)),
        # When a real (downloaded/embedded) preferred-language subtitle arrives
        # AFTER an AI sub was auto-applied (sidecars often finish downloading
        # after the video), swap to it automatically. Default on.
        "upgrade_late_subs": bool(cfg.get("upgrade_late_subs", True)),
        # When exactly one real subtitle is found, treat it as the preferred
        # language even if its filename doesn't declare one. Default on.
        "single_option":     bool(cfg.get("single_option", True)),
    }


def _stt_cfg(lib: dict) -> dict:
    """Read settings.stt (auto subtitle generation) with defaults.

    `default_language` is unified with the subtitle policy — it's sourced from
    `_subs_cfg` (settings.subtitles), not a separate STT key — so the same
    preferred language drives search, track selection, and generation. When set,
    a source with text subtitles but none in that language still triggers
    generation; when blank ("Any"), only a source with NO usable text subtitle
    does. `translate` adds an English track for non-English audio (whisper can
    only translate TO English).
    """
    cfg = (lib.get("settings", {}) or {}).get("stt") or {}
    return {
        "enabled":          bool(cfg.get("enabled", True)),
        "default_language": _subs_cfg(lib)["default_language"],
        "translate":        bool(cfg.get("translate", True)),
    }


def _vpn_killswitch_cfg(lib: dict) -> dict:
    """Read settings.vpn_killswitch (the VPN kill-switch policy) with defaults.

    `block_ui` decides how far the kill switch reaches when Mullvad drops:

    - `True`  (default) — the whole dashboard is blocked behind a full-screen
      "VPN DISCONNECTED" overlay until the VPN comes back.
    - `False` — only qBittorrent is killed (and the P2P stream/download endpoints
      stay 403'd); the rest of the UI keeps working so a viewer can still watch
      already-prepped on-device content.

    Regardless of this setting, **qBittorrent is always killed when the VPN is
    down** — that invariant is enforced unconditionally by `vpn_guard` here and by
    `watchdog.py` at the process level; `block_ui` only governs the UI lockout.
    Default `True` preserves the historical behaviour (overlay on every drop).
    """
    cfg = (lib.get("settings", {}) or {}).get("vpn_killswitch") or {}
    return {"block_ui": bool(cfg.get("block_ui", True))}


def _network_cfg(lib: dict) -> dict:
    """Read settings.network (the preferred primary adapter) with defaults.

    `preferred_adapter` is a physical interface *name* (not an IP, which moves
    with DHCP); "" means auto-pick. The redirect middleware + run.py's mDNS
    advertise resolve it to that adapter's current IP at runtime, falling back
    to the route-table heuristic when it's offline. See netadapters.py.
    """
    cfg = (lib.get("settings", {}) or {}).get("network") or {}
    return {"preferred_adapter": str(cfg.get("preferred_adapter", "") or "")}


# Canonicalize a language tag so 2- and 3-letter spellings of the same language
# compare equal (en/eng, ja/jpn, …). Anything unknown maps to itself.
_LANG_CANON = {
    "en": "eng", "ja": "jpn", "es": "spa", "esp": "spa", "fr": "fre", "fra": "fre",
    "de": "ger", "deu": "ger", "it": "ita", "pt": "por", "ru": "rus",
    "zh": "chi", "zho": "chi", "ko": "kor", "ar": "ara", "hi": "hin",
    "nl": "nld", "sv": "swe", "fi": "fin", "no": "nor", "da": "dan",
    "pl": "pol", "tr": "tur", "uk": "ukr", "th": "tha", "vi": "vie",
}


def _canon_lang(code: str) -> str:
    code = (code or "").strip().lower()
    if code in _LANG_CANON:
        return _LANG_CANON[code]
    # VLC's status.json reports full language NAMES ("English"), not ISO codes —
    # without this a device-saved descriptor ("eng") never language-matches a
    # VLC embedded track, so series subtitle memory silently failed on the TV.
    return _LANG_NAME_TO_CODE.get(code, code)


def _hhmm_to_min(s: str) -> Optional[int]:
    """'HH:MM' → minutes-since-midnight, or None if malformed."""
    try:
        h, m = s.split(":")
        h, m = int(h), int(m)
    except (ValueError, AttributeError):
        return None
    if 0 <= h <= 23 and 0 <= m <= 59:
        return h * 60 + m
    return None


# ── Download scheduling: idle/night window + reconcile + loop ───────────────────

async def _download_idle_open(lib: dict) -> bool:
    """True if the moment is inside the idle/night DOWNLOAD window — derived from the
    unified Automatic Stream Prep mode (`settings.auto_prep`):

      • "always" — the window is always open (the owner wants background work to run).
      • "idle"   — open while the box has been idle for `idle_minutes`.
      • "off"    — never open (idle-only downloads have no window; the modal warns).

    Unlike auto_prep's idle check, a running download does NOT count as activity here
    (`ignore_downloads=True`), so an idle-only download that's actively fetching can't
    flip the box "in use" and immediately close its own window."""
    cfg = _auto_prep_cfg(lib)
    if cfg["mode"] == "always":
        return True
    if cfg["mode"] == "idle":
        return not await _machine_in_use(cfg["idle_minutes"] * 60, ignore_downloads=True)
    return False


def _download_idle_configured(lib: dict) -> bool:
    """True if Automatic Stream Prep is enabled (mode != off), i.e. an idle-only
    download actually has a window to run in."""
    return _auto_prep_cfg(lib)["mode"] != "off"


async def _reconcile_item_downloads(item: dict, idle_open: bool) -> bool:
    """Apply an item's download schedule to qBittorrent: set each managed file's
    priority from its effective mode + the idle window, then pause/resume the torrent
    so it only fetches when something is allowed to download right now.

    The single writer of scheduled items' qBit file priorities + pause state. Returns
    True if anything is actively downloading for this item now."""
    h = item.get("torrent_hash")
    if not h:
        return False
    cfg = _download_cfg(item)
    # Plain "download now, no per-file overrides" items are left entirely alone.
    if cfg["mode"] == "now" and not cfg["files"]:
        return True
    info = await qbit_info(h)
    qfiles = await qbit_files(h)
    if not info or not qfiles:
        return False
    sp = info.get("save_path", settings.qbit_download_path)
    # Compressed-in-place files are no longer torrent-backed — force them to priority 0
    # so qBit can never re-fetch and overwrite the smaller re-encoded bytes.
    compressed_paths = {f.get("path", "") for f in item.get("files", []) if _file_is_compressed(f)}
    by_priority: dict[int, list[int]] = {}
    any_active = False
    for i, qf in enumerate(qfiles):
        idx = qf.get("index", i)
        full = str(Path(sp) / qf.get("name", ""))
        if full in compressed_paths:
            want = 0
        else:
            want = _file_mode_to_priority(_effective_file_mode(cfg, full), idle_open)
        if want > 0:
            any_active = True
        if qf.get("priority", 1) != want:
            by_priority.setdefault(want, []).append(idx)
    for prio, ids in by_priority.items():
        await qbit_set_file_priority(h, ids, prio)
    # Torrent-level pause is the coarse gate (only touch download-phase states so we
    # never pause a torrent that's already finished + seeding): don't leave a torrent
    # "downloading" with every file at priority 0 (some qBit builds error/auto-pause
    # that), and an explicit pause is what actually halts tracker churn while idle.
    qstate = info.get("state", "")
    DL_PAUSED = ("pausedDL", "stoppedDL")
    DL_ACTIVE = ("downloading", "metaDL", "forcedMetaDL", "stalledDL", "forcedDL",
                 "queuedDL", "checkingDL", "allocating", "checkingResumeData")
    if any_active and qstate in DL_PAUSED:
        await qbit_resume(h)
    elif not any_active and qstate in DL_ACTIVE:
        await qbit_pause(h)
    return any_active


async def _apply_item_schedule(item: dict, lib: dict) -> bool:
    """Reconcile qBit after a user schedule change, and reactivate a *finished* item
    when the change re-introduced a non-skip file that isn't on disk yet — e.g.
    un-skipping a file (or moving an idle file to now) on a download that had already
    flipped to 'ready'. Flipping the item back to 'downloading' is what lets the
    monitor + scheduler resume managing it (downloading→ready stays the monitor's job).
    Returns the current idle-window state. Mutates `item` in place; caller persists."""
    idle_open = await _download_idle_open(lib)
    await _reconcile_item_downloads(item, idle_open)
    h = item.get("torrent_hash")
    if h and item.get("status") == "ready":
        info = await qbit_info(h)
        qfiles = await qbit_files(h) if info else []
        if info and qfiles:
            sp = info.get("save_path", settings.qbit_download_path)
            cfg = _download_cfg(item)
            compressed_paths = {f.get("path", "") for f in item.get("files", []) if _file_is_compressed(f)}
            pending = any(
                str(Path(sp) / qf.get("name", "")) not in compressed_paths
                and _effective_file_mode(cfg, str(Path(sp) / qf.get("name", ""))) != "skip"
                and qf.get("progress", 0.0) < 0.999
                for qf in qfiles
            )
            if pending:
                item["status"] = "downloading"
                state.downloading_count += 1
                if not item.get("admin_only"):
                    state.downloading_count_visible += 1
    return idle_open


async def download_scheduler_loop() -> None:
    """Honour per-item download schedules: only fetch 'idle'-scheduled files/torrents
    during the idle/night window (reusing the admin prep windows), and keep 'now'
    files downloading. Runs every 15 s and is the single writer of scheduled items'
    qBit file priorities + pause state. See _reconcile_item_downloads."""
    while True:
        await asyncio.sleep(15)
        try:
            lib = await get_library()
            idle_open = await _download_idle_open(lib)
            prev_open = state.download_idle_open
            state.download_idle_open = idle_open
            state.download_idle_configured = _download_idle_configured(lib)
            scheduled = [
                it for it in lib["items"]
                if it.get("status") == "downloading" and it.get("torrent_hash")
                and (_download_cfg(it)["mode"] == "idle" or _download_cfg(it)["files"])
            ]
            for item in scheduled:
                await _reconcile_item_downloads(item, idle_open)
                await asyncio.sleep(0)
            if prev_open != idle_open:
                await broadcast("state", state_snapshot())
        except asyncio.CancelledError:
            raise
        except Exception as exc:
            print(f"[dlsched] download_scheduler_loop error: {exc}")


# ── System resource monitor ───────────────────────────────────────────────────
# Samples CPU / RAM / GPU / network every few seconds and classifies each as
# ok | degraded | overloaded, into state.sys_status. Drives the user-facing
# "host busy — performance may be reduced" banner (so a user arriving mid-prep
# knows it's catching up) and the admin System-tab health card. Best-effort:
# psutil for CPU/RAM/net, nvidia-smi (if present) for GPU.

_net_prev: dict = {}                 # last net counters + timestamp, for rate deltas
_net_bad_streak: int = 0             # consecutive bad net samples (debounce ramp-up spikes)
_gpu_smi_ok: Optional[bool] = None   # None=untested, True=usable, False=give up probing

# Network health is classified by *packet-loss rate*, not an absolute drop count.
# A handful of drops while a fast transfer ramps up (TCP probing for bandwidth)
# or while the NIC settles after boot is normal — flagging that as "overloaded"
# spammed the user-facing banner. So: ignore loss until enough packets have
# actually flowed this window (_NET_MIN_*), measure it as a fraction of traffic,
# and only escalate once it persists for _NET_CONFIRM consecutive samples.
_NET_MIN_PKTS = 2000     # need real traffic before a loss rate is meaningful (~5 s window)
_NET_MIN_ERRS = 20       # ignore a trickle of drops regardless of rate
_NET_LOSS_DEG = 0.02     # ≥2% sustained packet loss → degraded
_NET_LOSS_OVER = 0.08    # ≥8% sustained packet loss → overloaded
_NET_CONFIRM = 2         # consecutive bad samples (~10 s) required before flagging


def _classify(value: float, deg: float, over: float) -> str:
    """Map a 0–100 utilisation to ok / degraded / overloaded."""
    if value >= over:
        return "overloaded"
    if value >= deg:
        return "degraded"
    return "ok"


async def _sample_gpu() -> Optional[dict]:
    """Best-effort NVIDIA GPU sample via nvidia-smi → {util_pct, mem_pct}, or None
    when there's no usable GPU/tool (cached so a GPU-less box stops probing)."""
    global _gpu_smi_ok
    if _gpu_smi_ok is False:
        return None
    try:
        proc = await asyncio.create_subprocess_exec(
            "nvidia-smi",
            "--query-gpu=utilization.gpu,memory.used,memory.total",
            "--format=csv,noheader,nounits",
            stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.DEVNULL,
        )
        out, _ = await asyncio.wait_for(proc.communicate(), timeout=4.0)
    except Exception:
        _gpu_smi_ok = False
        return None
    parts = [p.strip() for p in (out.decode(errors="ignore").strip().splitlines() or [""])[0].split(",")]
    if len(parts) < 3:
        _gpu_smi_ok = False
        return None
    try:
        util, used, total = float(parts[0]), float(parts[1]), float(parts[2])
    except ValueError:
        _gpu_smi_ok = False
        return None
    _gpu_smi_ok = True
    return {"util_pct": round(util, 1), "mem_pct": round((used / total * 100.0) if total else 0.0, 1)}


async def system_monitor_loop() -> None:
    """Sample host resources every 5 s and classify into state.sys_status."""
    _ORDER = {"ok": 0, "degraded": 1, "overloaded": 2}
    try:
        psutil.cpu_percent(interval=None)   # prime the delta (first call is meaningless)
    except Exception:
        pass
    while True:
        await asyncio.sleep(5)
        try:
            cpu = float(psutil.cpu_percent(interval=None))   # % since last call (~5 s window)
            vm = psutil.virtual_memory()
            ram = float(vm.percent)

            # Network: throughput + packet-loss rate from the counters. Loss is
            # measured as a fraction of traffic (not an absolute count) and only
            # flagged once it persists, so ramp-up/boot transients don't trip it.
            global _net_bad_streak
            net = await asyncio.to_thread(psutil.net_io_counters)
            now = time.time()
            up_mbps = down_mbps = 0.0
            net_status = "ok"
            errs = net.errin + net.errout + net.dropin + net.dropout
            pkts = net.packets_sent + net.packets_recv
            if _net_prev:
                dt = max(0.001, now - _net_prev["ts"])
                down_mbps = max(0.0, (net.bytes_recv - _net_prev["recv"]) * 8 / 1e6 / dt)
                up_mbps   = max(0.0, (net.bytes_sent - _net_prev["sent"]) * 8 / 1e6 / dt)
                d_err  = max(0, errs - _net_prev["errs"])
                d_pkts = max(0, pkts - _net_prev["pkts"])
                # Only meaningful once enough packets flowed and the drops aren't a trickle.
                loss = (d_err / d_pkts) if (d_pkts >= _NET_MIN_PKTS and d_err >= _NET_MIN_ERRS) else 0.0
                raw = "overloaded" if loss >= _NET_LOSS_OVER else "degraded" if loss >= _NET_LOSS_DEG else "ok"
                # Debounce: a bad sample must repeat before we surface it; recovery is instant.
                _net_bad_streak = _net_bad_streak + 1 if raw != "ok" else 0
                net_status = raw if _net_bad_streak >= _NET_CONFIRM else "ok"
            _net_prev.update(ts=now, recv=net.bytes_recv, sent=net.bytes_sent, errs=errs, pkts=pkts)

            gpu = await _sample_gpu()

            cpu_status = _classify(cpu, 75, 92)
            ram_status = _classify(ram, 82, 93)
            comps = [cpu_status, ram_status, net_status]
            gpu_block = None
            if gpu is not None:
                gpu_status = _classify(max(gpu["util_pct"], gpu["mem_pct"]), 80, 94)
                gpu_block = {**gpu, "status": gpu_status}
                comps.append(gpu_status)
            overall = max(comps, key=lambda s: _ORDER.get(s, 0))

            state.sys_status = {
                "cpu": {"pct": round(cpu, 1), "status": cpu_status},
                "ram": {"pct": round(ram, 1), "used_gb": round(vm.used / 1e9, 1),
                        "total_gb": round(vm.total / 1e9, 1), "status": ram_status},
                "gpu": gpu_block,   # None ⇒ no usable NVIDIA GPU on this host
                "net": {"up_mbps": round(up_mbps, 1), "down_mbps": round(down_mbps, 1),
                        "status": net_status},
                "overall": overall,
                "updated_at": now,
            }
        except asyncio.CancelledError:
            raise
        except Exception as exc:
            print(f"[sysmon] system_monitor_loop error: {exc}")


async def cache_autopurge_loop() -> None:
    """Auto-evict orphan offline-cache bundles once the cache outgrows a size cap.

    When `settings.cache_autopurge.enabled` and the total `.offline_cache/` size
    reaches `max_gb`, purge every orphan bundle (cache/partial dirs + legacy MP4s
    that no longer map to any live library file). Only orphans are removed —
    bundles backing current library files are never touched, so this can never
    delete something a viewer might still want. Active prep jobs are skipped
    (the same `_offline_cache_path_active` guard the manual purge uses).

    The size check rides on `_build_offline_cache_inventory`, which offloads the
    heavy recursive walk to a worker thread, so the event loop never stalls. We
    only run that walk when the feature is enabled, and only every few minutes —
    eviction is housekeeping, not something that needs to be instant.
    """
    await asyncio.sleep(45)   # let the app settle before the first (heavy) walk
    while True:
        try:
            cfg = _cache_autopurge_cfg(await get_library())
            if cfg["enabled"]:
                # force=True: eviction must act on the real current size, and
                # this refreshes the admin snapshot for free every 5 min.
                inv = await _build_offline_cache_inventory(force=True)
                cap_bytes = int(cfg["max_gb"] * (1024 ** 3))
                if inv["total_bytes"] >= cap_bytes and inv["orphans"]:
                    deleted = 0
                    freed = 0
                    for o in inv["orphans"]:
                        if _offline_cache_path_active(o["cache_key"]):
                            continue
                        b = await asyncio.to_thread(_delete_cache_artifacts, o["cache_key"], o.get("root"))
                        if b > 0:
                            deleted += 1
                            freed += b
                    if deleted:
                        _invalidate_offline_cache_inventory()
                        _invalidate_bundle_index()
                        state.cache_autopurge_last = {
                            "at":                 time.time(),
                            "deleted":            deleted,
                            "bytes_freed":        freed,
                            "total_bytes_before": inv["total_bytes"],
                        }
                        print(f"[cachepurge] auto-purged {deleted} orphan bundle(s), "
                              f"freed {freed / (1024 ** 3):.2f} GiB (cache was "
                              f"{inv['total_bytes'] / (1024 ** 3):.2f} GiB, cap {cfg['max_gb']:g} GiB)")
        except asyncio.CancelledError:
            raise
        except Exception as exc:
            print(f"[cachepurge] cache_autopurge_loop error: {exc}")
        await asyncio.sleep(300)   # re-check every 5 min


async def scheduled_reboot_loop() -> None:
    """Daily scheduled host reboot with an idle guard.

    At the configured local time, if the machine has been idle for
    `idle_minutes`, reboot it. If it's in use, wait `idle_minutes` and re-check —
    repeating until the box is idle. A persisted `last_fired` date stops the
    just-rebooted machine from immediately re-arming and looping.
    """
    next_check = 0.0   # monotonic time of next idle re-check while armed for today
    while True:
        await asyncio.sleep(20)
        try:
            lib = await get_library()
            cfg = _scheduled_reboot_cfg(lib)
            if not cfg["enabled"]:
                continue

            parts = cfg["time"].split(":")
            try:
                target_h, target_m = int(parts[0]), int(parts[1])
            except (ValueError, IndexError):
                continue
            if not (0 <= target_h <= 23 and 0 <= target_m <= 59):
                continue

            now = _now_in_tz(cfg["timezone"])
            today = now.date().isoformat()
            if cfg["last_fired"] == today:
                continue   # already handled (or rebooted) for today

            scheduled_today = now.replace(hour=target_h, minute=target_m,
                                          second=0, microsecond=0)
            if now < scheduled_today:
                next_check = 0.0   # re-arm fresh for the upcoming window
                continue

            # We're at/past today's scheduled time and haven't fired yet.
            idle_secs = max(60, cfg["idle_minutes"] * 60)
            if asyncio.get_event_loop().time() < next_check:
                continue

            # Prep counts as "in use" for the reboot even when no one's watching:
            # idle stream-prep / STT runs precisely when the box is otherwise
            # idle, and HLS prep can't checkpoint — a reboot mid-encode throws
            # the work away. Downloads are already covered by _machine_in_use
            # (downloading_count). Both must be quiet before the nightly reboot.
            if await _machine_in_use(idle_secs) or _prep_in_progress():
                next_check = asyncio.get_event_loop().time() + idle_secs
                print(f"[reboot] scheduled restart deferred — machine in use / prep "
                      f"in progress; re-checking in {cfg['idle_minutes']} min")
                continue

            # Idle → record that we've fired for today (loop guard), then reboot.
            lib2 = await get_library()
            sr = lib2.setdefault("settings", {}).setdefault("scheduled_reboot", {})
            sr["last_fired"] = today
            await put_library(lib2)
            print(f"[reboot] scheduled restart firing — machine idle for "
                  f"{cfg['idle_minutes']} min")
            await _reboot_machine()
            # On success the process is torn down by the reboot before we reach
            # here. If it returns (no reboot permission), don't kill the loop —
            # last_fired == today now stops it re-hammering reboot commands every
            # tick, and it stands down until tomorrow's window.
        except asyncio.CancelledError:
            raise
        except Exception as exc:
            print(f"[reboot] scheduled_reboot_loop error: {exc}")


async def auto_prep_loop() -> None:
    """Drive automatic stream-prep from the single unified control
    (`settings.auto_prep`, read via `_auto_prep_cfg`). One mode owns the decision,
    so there's nothing to reconcile between competing triggers:

      • **always** — `want` is always True: prep every un-prepped file regardless
        of host activity (background work runs at below-normal priority). Because
        the loop stays engaged, it re-enqueues periodically so newly-downloaded
        content gets picked up.
      • **idle** — `want = not in_use`: prep only while the box has been idle for
        `idle_minutes`. On the falling edge (activity returned) the pause kind is
        the user's `on_activity` choice — "hard" kills the in-flight encode
        immediately (restarts later — HLS prep can't checkpoint), "soft" lets the
        in-flight file finish then holds the rest.
      • **off** — `want` is always False; nothing auto-preps.

    A rising edge (`want` and not engaged) resumes + enqueues the whole un-prepped
    library; a falling edge pauses. `auto_prep_engaged` is the in-memory edge flag
    (re-derived after any config save). `_machine_in_use` doubles as the activity
    detector — a fresh interaction stamps last_activity, flipping it True within a
    tick (the cheap `_activity_kick` hook shortcuts the hard-stop case)."""
    # While engaged in "always" mode the loop stays up, so re-enqueue every
    # ALWAYS_REQUEUE_TICKS ticks (~5 min at 15 s/tick) to catch new content.
    ALWAYS_REQUEUE_TICKS = 20
    ticks_since_enqueue = 0
    while True:
        await asyncio.sleep(15)
        try:
            cfg = _auto_prep_cfg(await get_library())
            mode = cfg["mode"]

            # Idle membership: busy within the idle window ⇒ not eligible. for_prep
            # makes an open dashboard count as "in use" so idle prep won't hammer
            # the box while a viewer is on the site (even if just looking).
            in_use = False
            if mode == "idle":
                in_use = await _machine_in_use(cfg["idle_minutes"] * 60, for_prep=True)

            # Cache for the cheap activity hook (`_activity_kick`): only the idle +
            # hard-stop case kills the in-flight encode the moment activity returns.
            state.idle_prep_on   = (mode == "idle")
            state.idle_prep_hard = (mode == "idle" and cfg["on_activity"] == "hard")

            if mode == "always":
                want = True
            elif mode == "idle":
                want = not in_use
            else:
                want = False

            if want and not state.auto_prep_engaged:
                state.auto_prep_engaged = True
                _resume_prep()   # clear any prior pause + re-spawn paused jobs
                n = await _enqueue_library_prep()
                ticks_since_enqueue = 0
                reason = "always-on" if mode == "always" else f"idle {cfg['idle_minutes']} min"
                print(f"[autoprep] {reason} — queued {n} file(s) for stream-prep")
            elif want and state.auto_prep_engaged and mode == "always":
                # Stays engaged in always mode — periodically re-enqueue so freshly
                # downloaded files get prepped without waiting for an edge.
                ticks_since_enqueue += 1
                if ticks_since_enqueue >= ALWAYS_REQUEUE_TICKS:
                    ticks_since_enqueue = 0
                    await _enqueue_library_prep()
            elif state.auto_prep_engaged and not want:
                state.auto_prep_engaged = False
                if mode == "idle":
                    kill = (cfg["on_activity"] == "hard")
                    killed = _pause_prep(kill=kill)
                    how = f"killed {killed} in-flight" if kill else "finishing current file"
                    print(f"[autoprep] activity detected — pausing prep ({how})")
                else:
                    _pause_prep(kill=False)           # mode turned off — graceful hold
                    print("[autoprep] auto-prep disabled — pausing remaining prep")
        except asyncio.CancelledError:
            raise
        except Exception as exc:
            print(f"[autoprep] auto_prep_loop error: {exc}")


# ── Background Task: Auto-Updater ────────────────────────────────────────────

_updater_lock = asyncio.Lock()   # serialise check + apply against each other


async def _set_updater_phase(phase: str, message: str = "", busy: bool = False) -> None:
    """Update the in-memory updater status + broadcast a state event so the
    admin UI animates progress live."""
    state.updater_phase = phase
    state.updater_message = message
    state.updater_busy = busy
    try:
        await broadcast("state", state_snapshot())
    except Exception:
        pass


async def _persist_updater_state(**fields) -> None:
    """Merge `fields` into library.json → settings.autoupdate, preserving everything else."""
    lib = await get_library()
    au = lib.setdefault("settings", {}).setdefault("autoupdate", {})
    au.update(fields)
    await put_library(lib)


async def _run_check(branch: str, allow_any: bool = False) -> dict:
    """Wrapper around updater.check_update that records the result in library.json."""
    res = await updater.check_update(branch, allow_any=allow_any)
    status = "ok" if res.get("ok") else (res.get("error") or "error")
    await _persist_updater_state(
        last_check_at=int(time.time()),
        last_check_status=status,
    )
    return res


async def _run_apply(branch: str, reboot: bool = True, allow_any: bool = False) -> dict:
    """The full update sequence: git apply → setup.py → service reinstall →
    machine reboot.

    Steps (each gated so a failure surfaces with a stage label):
      1. **git apply** — `git switch -C <branch>` (if current branch differs)
         then `git reset --hard origin/<branch>`. Goes forwards AND backwards
         (alpha → main is the same operation as main → alpha as far as git is
         concerned; library.json / .env / .offline_cache survive because they
         are gitignored).
      2. **setup.py** — re-run non-interactively so any new deps land and the
         qBit ini / certs / .env are refreshed against the new code's
         expectations.
      3. **Service reinstall** — `daemon.uninstall()` then `daemon.install()`
         so `streamlink_service.py` (the supervisor wrapper) is regenerated
         from the new `daemon.py`'s `_WRAPPER_CONTENT`. Without this the OS
         supervisor would keep running the old wrapper code even after the
         pull. Best-effort: a failure here is logged but doesn't abort the
         reboot, since the existing service may still work on the new code.
      4. **Reboot** — the whole host. Cleanest possible state on the way back
         up; the OS service supervisor brings StreamLink back on its own.

    With `reboot=False`, steps 3 and 4 are skipped (used by the dev-mode
    "files only" toggle, and by the auto-apply loop's polling path when it
    just wants to validate that the pull + setup would succeed).
    """
    async with _updater_lock:
        if state.updater_busy:
            return {"ok": False, "stage": "busy", "message": "An update is already running."}

        await _set_updater_phase("applying", f"Applying {branch} branch…", busy=True)
        prev_commit = await updater.current_commit()
        apply_res = await updater.apply_update(branch, allow_any=allow_any)
        if not apply_res.get("ok"):
            err = apply_res.get("error") or "git update failed"
            await _set_updater_phase("error", f"git apply: {err}", busy=False)
            await _persist_updater_state(last_error=err)
            return {"ok": False, "stage": "git", "message": err}

        new_commit = apply_res.get("commit", "")
        same_commit = new_commit and new_commit == prev_commit

        await _set_updater_phase("setup", "Running setup.py (non-interactive)…", busy=True)
        setup_res = await updater.run_setup()
        state.updater_last_output = setup_res.get("output_tail", "")
        if not setup_res.get("ok"):
            base_err = setup_res.get("error") or f"setup.py exited rc={setup_res.get('returncode')}"
            # Hoist the last non-empty line of setup.py's output into the
            # phase message so the admin sees the actual cause (e.g. a
            # `UnicodeEncodeError` traceback's exception line) without having
            # to expand the collapsed diagnostic panel.
            last_line = ""
            for line in reversed(state.updater_last_output.splitlines()):
                stripped = line.strip()
                if stripped and not stripped.startswith("─"):
                    last_line = stripped
                    break
            err = f"{base_err} — {last_line}" if last_line else base_err
            await _set_updater_phase("error", err, busy=False)
            await _persist_updater_state(
                last_error=err,
                last_applied_at=int(time.time()),
                last_applied_commit=new_commit,
            )
            return {"ok": False, "stage": "setup", "message": err,
                    "output_tail": state.updater_last_output}

        await _persist_updater_state(
            last_error="",
            last_applied_at=int(time.time()),
            last_applied_commit=new_commit,
        )

        # Flag the logs to roll over on the next process start. We can't safely
        # archive + clear streamlink_app.log / hls.log here — this live process
        # still holds them open (fatal on Windows) — so we drop a marker that
        # _init_logging() consumes on the post-restart clean slate, zipping the
        # old version's logs to logs_old_<timestamp>.zip and starting fresh.
        try:
            _ROTATE_MARKER.write_text(new_commit or "update", encoding="utf-8")
        except OSError as exc:
            log.warning("Could not write log-rotate marker: %s", exc)

        if not reboot:
            await _set_updater_phase("idle",
                                    f"Updated to {new_commit}. Reboot pending.",
                                    busy=False)
            return {"ok": True, "stage": "complete",
                    "message": f"Updated to {new_commit}.",
                    "commit": new_commit, "reboot_pending": True}

        # Step 3: refresh the supervisor wrapper script (streamlink_service.py)
        # from the freshly-pulled daemon._WRAPPER_CONTENT. This is a plain file
        # write — NO elevation required, no UAC prompt on Windows. The OS-level
        # service registration (task / plist / unit) keeps pointing to the same
        # wrapper path, so the reboot brings up the new wrapper code on its own.
        # Re-registration would require admin on Windows (UAC) and is therefore
        # incompatible with a fully-automatic update; the wrapper refresh is
        # enough for the common case.
        await _set_updater_phase("refreshing-service",
                                f"Refreshing supervisor wrapper for {new_commit}…",
                                busy=True)
        svc = await updater.refresh_service_wrapper()
        # Append the wrapper output to the diagnostic buffer alongside setup's.
        if svc.get("output"):
            tail = (state.updater_last_output + "\n── service ──\n" + svc["output"])[-8192:]
            state.updater_last_output = tail
        if not svc.get("ok"):
            # Log + persist but don't bail — proceed to reboot anyway. If the
            # wrapper write genuinely fails (read-only filesystem, missing
            # daemon.py), the existing wrapper file still runs the new code
            # because main.py / watchdog.py path references are dynamic.
            log.warning("Wrapper refresh failed; rebooting anyway. Error: %s",
                       svc.get("error", ""))
            await _persist_updater_state(
                last_error=f"wrapper refresh: {svc.get('error', 'unknown')}",
            )

        # Step 4: machine reboot. Fire after a short grace so this RPC's HTTP
        # response gets flushed to the admin UI first.
        await _set_updater_phase("rebooting",
                                f"Updated to {new_commit}. Rebooting host machine…",
                                busy=True)
        asyncio.create_task(_reboot_machine(delay=1.5))

        msg_prefix = "Updated" if not same_commit else "Branch reset"
        return {"ok": True, "stage": "reboot",
                "message": f"{msg_prefix} to {new_commit}. Host is rebooting…",
                "commit": new_commit,
                # Kept the legacy `service_reinstalled` key name so the admin
                # UI's success-toast branch doesn't have to change shape.
                "service_reinstalled": svc.get("ok", False),
                "service_install_output": svc.get("output", "")}


async def updater_loop() -> None:
    """Periodic auto-update poll.

    Reads settings.autoupdate every minute; when enabled, runs a check at
    `interval_hours` cadence and (when `auto_apply` is on) auto-applies new
    commits if the machine is currently idle. Active streams, downloads, and
    recent admin actions all defer the apply — we never tear the server down
    while the user is watching something.
    """
    last_check_mono = 0.0
    while True:
        await asyncio.sleep(60)
        try:
            lib = await get_library()
            cfg = _autoupdate_cfg(lib)
            if not cfg["enabled"]:
                continue

            # A pinned commit (detached HEAD, set via switch_commit in dev mode)
            # has no branch to track — auto-update would be meaningless and would
            # silently yank the admin off their pinned build. Stand down until
            # they switch back to a branch from the admin panel.
            if await updater.is_detached_head():
                continue

            interval_secs = cfg["interval_hours"] * 3600
            now_mono = asyncio.get_event_loop().time()
            last_check_wall = cfg["last_check_at"]
            wall_due = (time.time() - last_check_wall) >= interval_secs if last_check_wall else True
            mono_due = (now_mono - last_check_mono) >= interval_secs
            if not (wall_due and mono_due):
                continue

            if state.updater_busy:
                continue

            branch = cfg["branch"]
            allow_any = cfg["dev_mode"]
            async with _updater_lock:
                if state.updater_busy:
                    continue
                await _set_updater_phase("checking", f"Checking origin/{branch}…", busy=True)
                res = await _run_check(branch, allow_any=allow_any)
                last_check_mono = now_mono

            if not res.get("ok"):
                await _set_updater_phase("error", res.get("error", "check failed"), busy=False)
                continue

            if not res.get("has_update"):
                await _set_updater_phase("idle",
                                        f"Up to date with origin/{branch}.",
                                        busy=False)
                continue

            if not cfg["auto_apply"]:
                # New commits available but admin opted out of auto-apply —
                # leave the banner for them and idle.
                await _set_updater_phase("idle",
                                        f"Update available: origin/{branch} ({res['behind_by']} ahead). Apply from the admin panel.",
                                        busy=False)
                continue

            # Idle gate: never tear down a running playback for a routine update.
            if await _machine_in_use(window_secs=300):
                await _set_updater_phase("idle",
                                        f"Update queued: machine in use, will retry next cycle.",
                                        busy=False)
                continue

            print(f"[updater] auto-applying origin/{branch} "
                  f"(local={res['local']} → remote={res['remote']})")
            apply_res = await _run_apply(branch, reboot=True, allow_any=allow_any)
            if not apply_res.get("ok"):
                print(f"[updater] auto-apply failed at stage={apply_res.get('stage')}: "
                      f"{apply_res.get('message')}")
        except asyncio.CancelledError:
            raise
        except Exception as exc:
            print(f"[updater] updater_loop error: {exc}")


# ── Background Task: State Broadcaster ───────────────────────────────────────

async def stat_broadcaster() -> None:
    """Push a full state snapshot to all SSE clients every 2 s."""
    while True:
        if state.active_hash and state.stream_status in ("buffering", "playing"):
            info = await qbit_info(state.active_hash)
            if info:
                total = info.get("size", 1) or 1
                done = info.get("completed", 0)
                state.progress = done / total * 100
                state.downloaded_mb = done / 1_048_576
                state.total_mb = total / 1_048_576
                state.dl_speed_bps = info.get("dlspeed", 0)
                state.ul_speed_bps = info.get("upspeed", 0)
        if state.stream_status == "playing" and not state.youtube_active:
            vs = await vlc_status()
            if vs:
                state.vlc_time = int(vs.get("time", 0))
                state.vlc_duration = int(vs.get("length", 0))
                reported = round(int(vs.get("volume", 256)) / 256 * 100)
                # Self-heal: VLC occasionally snaps volume back to 100 on
                # playlist advance / track start. If it sits above the user's
                # cap, push it back down immediately rather than waiting for
                # the user to nudge the slider.
                cap = await _global_max_volume()
                if reported > cap:
                    raw = max(0, min(512, round(cap / 100 * 256)))
                    await vlc("volume", val=str(raw))
                    state.vlc_volume = cap
                else:
                    state.vlc_volume = reported
        await broadcast("state", state_snapshot())
        await asyncio.sleep(2)


async def _auto_play_item(item: dict, profile_id: str, file_path: str = "") -> None:
    """Trigger playback for a library item (or specific file) that just finished downloading."""
    try:
        all_paths = [f["path"] for f in item.get("files", [])]
        if file_path and file_path in all_paths:
            start_idx = all_paths.index(file_path)
            playlist = all_paths[start_idx:]
        else:
            hint = find_resume_hint(item, profile_id)
            if hint and hint.get("file_path") and not hint.get("all_completed"):
                try:
                    start_idx = all_paths.index(hint["file_path"])
                    playlist = all_paths[start_idx:]
                except ValueError:
                    playlist = all_paths
            else:
                playlist = all_paths

        if not playlist:
            return

        # Wait up to 10 s for files to appear on disk after qBit marks complete
        for _ in range(10):
            if all(Path(p).exists() for p in playlist):
                break
            await asyncio.sleep(1)

        first = Path(playlist[0])
        await vlc("in_play", input=vlc_file_uri(first))
        for p in playlist[1:]:
            await vlc("in_enqueue", input=vlc_file_uri(Path(p)))
        asyncio.create_task(vlc_focus_and_fullscreen())

        state.stream_status = "playing"
        state.active_title = item["title"]
        state.active_file = first
        state.current_audio_track = -1
        state.current_subtitle_track = -1
        state.active_hash = item.get("torrent_hash") or None
        state.library_item_id = item["id"]
        await _set_playback_owner(profile_id)
        state.library_item_file_count = len(item.get("files", []))
        state.library_playlist = playlist
        state.library_shuffle_order = []   # auto-play is always natural order
        state.library_series_map = {}
        state.library_series_order = []
        state.library_current_file = playlist[0]

        await broadcast("stream_status", {"status": "playing", "message": f"Auto-playing: {first.name}"})
    except Exception:
        pass


# ── Idle Background Video ─────────────────────────────────────────────────────

async def _play_background_video() -> bool:
    """Start the configured background video on VLC. Returns True on success.

    Caller is responsible for deciding *when* to play; this just issues the
    commands and resets the AppState fields so the rest of the system treats
    the dashboard as idle (no library item, no skip offers, no resume tile).
    """
    lib = await get_library()
    bg = lib.get("settings", {}).get("background_video") or {}
    path_str = bg.get("path", "")
    if not path_str:
        return False
    p = Path(path_str)
    if not p.exists():
        return False
    cap = await _global_max_volume()
    bg_vol = max(0, min(cap, max(0, min(200, int(bg.get("volume", 50))))))
    raw = max(0, min(512, round(bg_vol / 100 * 256)))

    # Snapshot the user's normal volume on the first transition into bg, so the
    # next user-initiated `in_play` can restore it.
    if not state.background_playing:
        state.user_volume_before_bg = state.vlc_volume
    state.vlc_volume = bg_vol
    state.background_playing = True
    # Reset playback state so SSE clients show "nothing is playing"
    state.stream_status = "idle"
    state.library_item_id = None
    state.library_profile_id = None
    state.library_profile_name = ""
    state.library_profile_color = ""
    state.library_item_file_count = 0
    state.library_playlist = []
    state.library_shuffle_order = []
    state.library_series_map = {}
    state.library_series_order = []
    state.library_current_file = None
    state.active_title = None
    state.active_file = None
    state.skip_offer = None
    state.skip_offer_file = None
    state.resume_offer = None

    try:
        c = _vlc_http()
        # Clear stale items (old episodes from the just-stopped playlist) before
        # playing the bg video — otherwise replaying a bg entry that's already in
        # the list ends and VLC auto-advances into a leftover episode. See
        # vlc_clear_playlist() / docs/GOTCHAS.md.
        await c.get("/requests/status.xml", params={"command": "pl_empty"})
        await c.get("/requests/status.xml", params={"command": "volume", "val": str(raw)})
        await c.get("/requests/status.xml", params={"command": "in_play", "input": vlc_file_uri(p)})
    except Exception:
        return False
    # Belt-and-braces: never let the idle video pull VLC over the TV UI kiosk
    # (the loop already skips while tv_ui_active, but direct callers exist).
    if not state.tv_ui_active:
        asyncio.create_task(vlc_focus_and_fullscreen())
    await broadcast("state", state_snapshot())
    return True


async def background_video_loop() -> None:
    """Poll every 3 s; (re)start the configured background video when VLC is idle.

    Bg is naturally replaced by `vlc("in_play", ...)` from any user-initiated
    playback, so we don't need to explicitly stop it. When VLC stops (a movie
    ends, /api/stop is called, etc.) this loop picks up the slack within ~3 s.
    """
    while True:
        await asyncio.sleep(3)
        try:
            # YouTube is playing in the browser on the TV — VLC is intentionally
            # stopped. Don't let the idle-background loop start a video over it.
            if state.youtube_active:
                continue
            # Window control paused by the user — leave the desktop alone and
            # don't (re)start the idle background video over their work.
            if window_mgmt_paused():
                continue
            # TV UI kiosk holds the screen — don't (re)start the bg video under
            # it (its audio would play over the dashboard). A bg video we
            # paused on wake reads `paused` below and is skipped anyway; this
            # guard covers the stopped/ended case. tv_ui_loop hands back.
            if state.tv_ui_active:
                continue
            lib = await get_library()
            bg = lib.get("settings", {}).get("background_video") or {}
            if not bg.get("path") or not bg.get("enabled", True):
                state.background_playing = False
                continue
            # Don't fight an in-flight stream pipeline about to hand off to VLC
            if state.stream_status == "buffering":
                continue
            vs = await vlc_status()
            if vs is None:
                continue
            vlc_state = vs.get("state", "")
            if vlc_state in ("playing", "paused"):
                continue
            await _play_background_video()
        except Exception:
            pass


async def _sync_state_from_vlc() -> None:
    """On lifespan startup, restore `state` from VLC's actual playback so SSE
    clients see the correct "now playing" title after a server restart (admin
    shutdown, watchdog kick, manual relaunch) while VLC kept running.

    Without this, every `AppState` field is at its dataclass default —
    `stream_status="idle"`, `active_title=None` — and `background_video_loop`
    sees VLC already `state=playing` so it stays out of the way, leaving the
    dashboard stuck on "No active stream" until someone calls /api/stop and
    starts a new playback.

    `library_profile_id` is intentionally left unset — the profile that
    originally started the playback isn't recoverable, so `vlc_progress_tracker`
    will skip progress saves and skip-offer logic for the restored session.
    Playback control (next/prev/stop, title display) still works.
    """
    try:
        vs = await vlc_status()
        if not vs or vs.get("state") not in ("playing", "paused"):
            return
        uri = await vlc_playlist_uri()
        if not uri or not uri.startswith("file://"):
            return
        cur_path = uri_to_path(uri)
        try:
            cur_resolved = Path(cur_path).resolve()
        except Exception:
            cur_resolved = Path(cur_path)

        lib = await get_library()
        bg_path = (lib.get("settings", {}).get("background_video") or {}).get("path", "")
        if bg_path:
            try:
                if Path(bg_path).resolve() == cur_resolved:
                    state.background_playing = True
                    return
            except Exception:
                pass

        matched_item: Optional[dict] = None
        matched_path: Optional[str] = None
        for item in lib.get("items", []):
            for f in item.get("files", []):
                stored = f.get("path", "")
                if not stored:
                    continue
                try:
                    if Path(stored).resolve() == cur_resolved:
                        matched_item = item
                        matched_path = stored
                        break
                except Exception:
                    continue
            if matched_item:
                break

        state.stream_status = "playing"
        if matched_item and matched_path:
            state.active_title = matched_item.get("title") or Path(cur_path).stem
            state.library_item_id = matched_item["id"]
            state.library_item_file_count = len(matched_item.get("files", []))
            state.active_hash = matched_item.get("torrent_hash") or None
            state.library_playlist = [
                f.get("path", "") for f in matched_item.get("files", []) if f.get("path")
            ]
            state.library_current_file = matched_path
        else:
            state.active_title = Path(cur_path).stem
            state.library_current_file = cur_path
    except Exception:
        pass


# ── Background Task: Library Download Monitor ─────────────────────────────────

async def library_download_monitor() -> None:
    """Poll qBit every 5 s for pending library downloads and mark them complete."""
    while True:
        await asyncio.sleep(5)
        try:
            lib = await get_library()
            pending = [it for it in lib["items"] if it.get("status") == "downloading"]
            state.downloading_count = len(pending)
            # The visible count excludes admin-locked items so a non-elevated
            # viewer's download badge never reveals hidden content is fetching.
            state.downloading_count_visible = sum(1 for it in pending if not it.get("admin_only"))
            if not pending:
                continue
            changed = False
            for item in pending:
                h = item.get("torrent_hash")
                if not h:
                    continue
                info = await qbit_info(h)
                if not info:
                    continue

                # Refresh file list now that sizes are final
                qfiles = await qbit_files(h)
                save_path = info.get("save_path", settings.qbit_download_path)
                new_files = build_file_list(qfiles, save_path)
                if new_files:
                    # Carry forward the per-file "compressed" marker — build_file_list
                    # rebuilds from qBit, which has no knowledge of an in-place re-encode.
                    prev_compressed = {f.get("path", "") for f in item.get("files", []) if _file_is_compressed(f)}
                    for nf in new_files:
                        if nf.get("path") in prev_compressed:
                            nf["compressed"] = True
                    item["files"] = new_files
                    item["size_bytes"] = sum(f["size_bytes"] for f in new_files)

                qstate = info.get("state", "")
                # Ready is gated on every NON-SKIP file being fully downloaded — not on
                # qBit's torrent state. With skip/idle files at priority 0, qBit reports
                # the torrent "complete" (uploading) while skipped files are absent and
                # idle-deferred files haven't fetched yet; flipping ready on that would
                # both mislabel a partial download as whole and fingerprint a missing set.
                nonskip_done = _all_nonskip_complete(item, qfiles, save_path)
                if qstate in ("error", "missingFiles"):
                    item["status"] = "error"
                    state.downloading_count = max(0, state.downloading_count - 1)
                    if not item.get("admin_only"):
                        state.downloading_count_visible = max(0, state.downloading_count_visible - 1)
                    changed = True
                    await broadcast("library_update", {"item_id": item["id"], "status": "error"})
                elif nonskip_done:
                    item["status"] = "ready"
                    state.downloading_count = max(0, state.downloading_count - 1)
                    if not item.get("admin_only"):
                        state.downloading_count_visible = max(0, state.downloading_count_visible - 1)
                    changed = True
                    await broadcast("library_update", {"item_id": item["id"], "status": "ready"})
                    # Smart Skip fingerprinting is NOT triggered here anymore — it
                    # rides along with stream prep instead (`_ensure_analysis_for`
                    # in `_run_offline_job`). See docs/ANALYZER.md § Trigger flow.
                    if state.play_when_ready_item_id == item["id"]:
                        pwr_profile = state.play_when_ready_profile_id
                        pwr_fp = state.play_when_ready_file_path
                        state.play_when_ready_item_id = None
                        state.play_when_ready_profile_id = None
                        state.play_when_ready_file_path = None
                        asyncio.create_task(_auto_play_item(item, pwr_profile or "", pwr_fp or ""))
                else:
                    # Still downloading — push live stats to the UI
                    eta = info.get("eta", 8640000)
                    cfg = _download_cfg(item)
                    # "Waiting for idle window": either qBit paused us, or all the
                    # kept-but-incomplete files are idle-deferred and the window is shut
                    # (qBit may be seeding the now-files meanwhile, so check per-file).
                    waiting_idle = qstate in ("pausedDL", "stoppedDL")
                    if not waiting_idle and not state.download_idle_open:
                        for i, qf in enumerate(qfiles):
                            full = str(Path(save_path) / qf.get("name", ""))
                            if _effective_file_mode(cfg, full) == "idle" and qf.get("progress", 0.0) < 0.999:
                                waiting_idle = True
                                break
                    await broadcast("library_progress", {
                        "item_id": item["id"],
                        "speed_bps": info.get("dlspeed", 0),
                        "downloaded_bytes": info.get("completed", 0),
                        "total_bytes": info.get("size", 0),
                        "progress_pct": round(info.get("completed", 0) / max(info.get("size", 1), 1) * 100, 1),
                        "eta_secs": eta if eta < 8640000 else -1,
                        "download_mode": cfg["mode"],   # now | idle
                        # Intentionally halted (idle window closed) — the UI shows
                        # "Waiting for idle window" instead of "Downloading".
                        "paused": waiting_idle,
                    })
                    changed = True  # file list updated
                    # Check if a specific queued file finished (even while torrent is still going)
                    if (state.play_when_ready_item_id == item["id"]
                            and state.play_when_ready_file_path and qfiles):
                        pwr_path = state.play_when_ready_file_path
                        for qf in qfiles:
                            full = str(Path(save_path) / qf.get("name", ""))
                            if full == pwr_path and qf.get("progress", 0) >= 1.0:
                                pwr_profile = state.play_when_ready_profile_id
                                state.play_when_ready_item_id = None
                                state.play_when_ready_profile_id = None
                                state.play_when_ready_file_path = None
                                asyncio.create_task(_auto_play_item(item, pwr_profile or "", pwr_path))
                                break

            if changed:
                await put_library(lib)
        except Exception:
            pass


# ── Smart Skip helpers ────────────────────────────────────────────────────────

def _series_key(item: dict) -> str:
    """Group items by series for cross-episode fingerprinting.

    Items with a non-empty series field group together; everything else is
    grouped by item ID (a single-item bucket) so movies and one-offs still
    get the credits fallback.
    """
    s = (item.get("series") or "").strip()
    return f"series:{s.lower()}" if s else f"item:{item.get('id', '')}"


def _items_for_series_key(lib: dict, key: str) -> list[dict]:
    return [it for it in lib["items"] if _series_key(it) == key]


def _skip_settings_for_profile(lib: dict, profile_id: str) -> dict:
    """Return {auto_skip_intro, auto_skip_credits} for a profile (defaults False)."""
    if not profile_id:
        return {"auto_skip_intro": False, "auto_skip_credits": False}
    prof = next((p for p in lib.get("profiles", []) if p["id"] == profile_id), None)
    if not prof:
        return {"auto_skip_intro": False, "auto_skip_credits": False}
    return {
        "auto_skip_intro":   bool(prof.get("auto_skip_intro", False)),
        "auto_skip_credits": bool(prof.get("auto_skip_credits", False)),
    }


def _series_owner_for_path(path: str) -> Optional[str]:
    """For merged-series playback, the library item id that owns `path` (the file
    VLC is playing), or None when no series playlist is active. Tolerates minor
    path differences via a basename fallback."""
    m = state.library_series_map
    if not m or not path:
        return None
    if path in m:
        return m[path]
    base = Path(path).name
    for p, iid in m.items():
        if Path(p).name == base:
            return iid
    return None


def _nav_order(item: dict) -> list[str]:
    """The path order that defines next/prev for the active playback.

    Shuffle Play overrides natural file order: while `library_shuffle_order` is
    set, "next" / "prev" (and the credit auto-advance) follow the random order.
    A merged-series play (`library_series_order`) spans multiple items. Otherwise
    it's the item's natural season/episode-sorted file list.
    """
    if state.library_shuffle_order:
        return list(state.library_shuffle_order)
    if state.library_series_order:
        return list(state.library_series_order)
    return [f.get("path", "") for f in item.get("files", [])]


def _next_file_in_item(item: dict, current_path: str) -> Optional[str]:
    """Return the next file path after current_path (shuffle-aware), or None."""
    paths = _nav_order(item)
    try:
        idx = paths.index(current_path)
    except ValueError:
        return None
    return paths[idx + 1] if idx + 1 < len(paths) else None


def _find_file_meta(item: dict, file_path: str) -> Optional[dict]:
    """Return the per-file analysis dict (intro/credits_start) if present."""
    skip_data = item.get("skip_data", {})
    return skip_data.get(file_path)


def _item_skip_summary(item: dict) -> dict:
    """Summarize the Smart Skip availability of every file in this item.

    Drives the user-facing skip-availability chip in the library list and the
    admin Smart Skip tab's quick filter. Returns a dict with:
      `status` — one of:
        `none`        — no files (status surface not applicable)
        `pending`     — at least one file has no skip_data entry yet (analysis
                        hasn't run, or item still downloading)
        `failed`      — every analyzed file is marked failed (no intro AND no
                        credits AND analysis.source == "failed")
        `partial`     — some files succeeded, others failed/not yet analyzed
        `ok`          — every file produced usable intro/credits (or has been
                        manually edited)
      `affected` — count of files without usable skip points (failed + pending)
      `total`    — count of analyzable files

    Note `affected` is informational, not an error count: many episodes simply
    have no intro or no credits, which is normal — the chip wording reflects
    that.
    """
    files = _analyzable_files(item)   # skipped (not-downloaded) files aren't analyzed
    if not files:
        return {"status": "none", "affected": 0, "total": 0}
    skip_data = item.get("skip_data", {}) or {}
    ok = 0
    fail = 0
    pending = 0
    for f in files:
        path = f.get("path", "")
        entry = skip_data.get(path)
        if not entry:
            pending += 1
            continue
        src = (entry.get("analysis") or {}).get("source", "")
        if src == "failed":
            fail += 1
        else:
            ok += 1
    total = len(files)
    affected = fail + pending
    if pending and not fail and not ok:
        status = "pending"
    elif fail and not ok:
        status = "failed"
    elif fail and ok:
        status = "partial"
    elif pending:
        # Some succeeded, some not yet analyzed — surface as partial so the UI
        # still hints that not everything is covered.
        status = "partial"
    else:
        status = "ok"
    return {"status": status, "affected": affected, "total": total}


def _item_skip_status(item: dict) -> str:
    """Back-compat string accessor over `_item_skip_summary` — returns just the
    status. See that function for the value catalog."""
    return _item_skip_summary(item)["status"]


async def _set_analysis_status(series_key: str, **patch) -> None:
    """Update state.analysis_jobs[series_key] and broadcast the change."""
    job = state.analysis_jobs.setdefault(series_key, {})
    job.update(patch)
    await broadcast("analysis_status", {"series_key": series_key, "job": job})


def _log_analyzer_event(*, level: str, message: str, series_key: str = "",
                        item_id: str = "", file_path: str = "",
                        error_code: str = "") -> None:
    """Append a Smart Skip event to the analyzer ring buffer + app log.

    The ring buffer is the source of truth for the admin "Smart Skip" tab's
    log panel (state lives in-memory and resets on restart — failures are
    re-discovered on the next analysis run, so persistence isn't worth the
    library.json bloat). `streamlink_app.log` mirrors the message for
    longer-term forensics.
    """
    entry = {
        "ts":         _now_iso(),
        "level":      level,
        "series_key": series_key,
        "item_id":    item_id,
        "file_path":  file_path,
        "error_code": error_code,
        "message":    message,
    }
    state.analyzer_log.appendleft(entry)
    fname = Path(file_path).name if file_path else ""
    code = f" [{error_code}]" if error_code else ""
    log_fn = log.error if level == "error" else (log.warning if level == "warn" else log.info)
    log_fn(f"[analyzer]{code} {fname}: {message}")


async def _run_series_analysis(series_key: str) -> None:
    """Background task: analyze a series, save results, broadcast progress.

    `analyzer.analyze_series` now always returns an entry per file (success or
    failure), so the orchestrator persists everything it gets and uses
    `analysis.source == "failed"` to drive the admin log + user-facing chip.
    Missing-binary and exception cases are still surfaced as a series-level
    `analysis_jobs.status = "failed"` for the admin UI.
    """
    lock = analyzer.lock_for_series(series_key)
    # Per-series lock dedups re-entry for the SAME series; the global gate bounds
    # how many DIFFERENT series fingerprint at once so a bulk "Analyze" doesn't
    # oversubscribe the host (see ANALYSIS_CONCURRENCY). Acquire the lock first so
    # duplicate triggers for one series collapse before they ever queue on the
    # gate.
    async with lock, _analysis_gate:
        lib = await get_library()
        items = _items_for_series_key(lib, series_key)
        ready_items = [it for it in items if it.get("status") == "ready"]
        item_ids = [it["id"] for it in ready_items]
        if not ready_items:
            return

        # Start
        await _set_analysis_status(
            series_key, status="running",
            stage="starting", current=0, total=0,
            message="Preparing analysis…",
            item_ids=item_ids,
            started_at=_now_iso(),
            finished_at=None,
        )

        async def _on_progress(**kw):
            await _set_analysis_status(series_key, status="running", **kw)

        # Fingerprint only the files the user actually downloaded — exclude "skip"
        # files (deselected from the download) so a partial selection isn't dragged
        # to "failed" by absent files. The persistence loop's `p in results` guard
        # then naturally leaves skip files' skip_data untouched.
        analyze_items = [dict(it, files=_analyzable_files(it)) for it in ready_items]
        try:
            results = await analyzer.analyze_series(analyze_items, progress_cb=_on_progress)
        except Exception as exc:
            err_msg = f"Analysis crashed: {exc}"
            # Record an exception entry for every file in the series so the
            # user-facing chip + admin editor still surface the failure even
            # when nothing else gets persisted.
            results = {}
            for it in ready_items:
                for f in _analyzable_files(it):
                    p = f.get("path", "")
                    if p:
                        results[p] = {
                            "intro": None, "credits_start": None,
                            "analysis": {
                                "version":    analyzer.ANALYZER_VERSION,
                                "source":     "failed",
                                "error_code": analyzer.ERR_EXCEPTION,
                                "error":      err_msg,
                            },
                        }
            _log_analyzer_event(
                level="error", series_key=series_key,
                error_code=analyzer.ERR_EXCEPTION, message=err_msg,
            )
            await _set_analysis_status(
                series_key, status="failed",
                stage="error", message=err_msg,
                finished_at=_now_iso(),
            )
            # fall through to persistence so per-file failures still get recorded

        # Persist results back into library.json under each item.
        files_updated = 0
        files_failed = 0
        lib = await get_library()
        for it in lib["items"]:
            if _series_key(it) != series_key:
                continue
            skip_data = it.setdefault("skip_data", {})
            changed = False
            for f in it.get("files", []):
                p = f.get("path", "")
                if p in results:
                    # Manual admin edits are never overwritten — not even by a
                    # forced re-run (docs/ANALYZER.md). The file still gets
                    # fingerprinted (its print helps cluster the peers), but
                    # its stored entry stays as the admin set it.
                    prev_ana = (skip_data.get(p) or {}).get("analysis") or {}
                    if prev_ana.get("source") == "manual":
                        continue
                    skip_data[p] = results[p]
                    files_updated += 1
                    changed = True
                    ana = results[p].get("analysis") or {}
                    if ana.get("source") == "failed":
                        files_failed += 1
                        _log_analyzer_event(
                            level="error", series_key=series_key,
                            item_id=it["id"], file_path=p,
                            error_code=ana.get("error_code", ""),
                            message=ana.get("error", "Fingerprinting failed."),
                        )
            if changed:
                await broadcast("library_update", {"item_id": it["id"], "status": it.get("status", "ready")})
        await put_library(lib)

        # If the analyze_series call already set the job to "failed" (exception
        # path), don't overwrite it back to complete.
        job_now = state.analysis_jobs.get(series_key) or {}
        if job_now.get("status") != "failed":
            successes = files_updated - files_failed
            if files_updated == 0:
                await _set_analysis_status(
                    series_key, status="failed",
                    stage="error", message="No analyzable episodes found",
                    finished_at=_now_iso(),
                )
            elif files_failed and not successes:
                await _set_analysis_status(
                    series_key, status="failed",
                    stage="error",
                    message=f"All {files_failed} file(s) failed fingerprinting",
                    current=files_updated, total=files_updated,
                    finished_at=_now_iso(),
                )
            else:
                msg = f"Updated {successes} file(s)"
                if files_failed:
                    msg += f", {files_failed} failed"
                await _set_analysis_status(
                    series_key, status="complete",
                    stage="done", message=msg,
                    current=files_updated, total=files_updated,
                    finished_at=_now_iso(),
                )


def _schedule_series_analysis_if_eligible(item: dict, lib: dict) -> None:
    """When an item flips to 'ready', kick off series analysis if 2+ ready episodes
    exist in the same series and no analysis has been run yet for this series.
    Single-item buckets still run (to populate the credits fallback)."""
    if not analyzer.is_available():
        return
    key = _series_key(item)
    # Don't stack runs: a /prep-all of a 77-file series fires the post-prep hook
    # 77 times. The in-flight pass already fingerprints every ready file in the
    # series, so later prep completions are covered without re-queuing.
    job = state.analysis_jobs.get(key) or {}
    if job.get("status") == "running":
        return
    peers = [it for it in _items_for_series_key(lib, key) if it.get("status") == "ready"]

    def _needs_reanalysis(file_data: Optional[dict]) -> bool:
        if not file_data:
            return True
        analysis = file_data.get("analysis") or {}
        if analysis.get("source") == "manual":
            return False
        # Failures are sticky: a previously-failed file is NOT auto-retried (it
        # would otherwise re-run on every prep in the series). It only re-runs
        # when ANALYZER_VERSION bumps (the version check below — failed entries
        # store the current version, so they qualify after a bump) or when an
        # admin forces it via the Smart Skip "Analyze" button (which calls
        # _run_series_analysis directly and skips this guard). See docs/ANALYZER.md.
        return analysis.get("version", 0) < analyzer.ANALYZER_VERSION

    needs_run = False
    for peer in peers:
        sk = peer.get("skip_data", {})
        for f in _analyzable_files(peer):   # skip-moded files are never fingerprinted
            if _needs_reanalysis(sk.get(f.get("path", ""))):
                needs_run = True
                break
        if needs_run:
            break
    if not needs_run:
        return
    # Coalesce: while more prep for this series is queued/encoding, defer. Each
    # pass re-fingerprints the WHOLE series, so triggering per prepped file made
    # the analyzer restart from episode 1 after every bundle (quadratic work +
    # the admin "progress keeps restarting" report). The next completion re-fires
    # this hook, and the watcher backstops prep exit paths that don't (crash,
    # sibling-race done) — so the series gets one pass after the last file lands.
    if _series_prep_active(key, lib):
        if key not in _deferred_analysis_watch:
            _deferred_analysis_watch.add(key)
            asyncio.create_task(_watch_prep_then_analyze(key))
        return
    asyncio.create_task(_run_series_analysis(key))


# Series keys with an active deferred-analysis watcher (so repeated post-prep
# hook firings while a season preps don't stack watcher tasks).
_deferred_analysis_watch: set[str] = set()


def _series_prep_active(key: str, lib: dict) -> bool:
    """True while any HLS prep job for an item in this series is queued or
    encoding. "paused" deliberately doesn't count — a parked queue can sit for
    hours and the below-normal-priority analysis is safe to run during it."""
    ids = {it.get("id") for it in _items_for_series_key(lib, key)}
    return any(j.get("item_id") in ids and j.get("status") in ("pending", "processing")
               for j in _offline_jobs.values())


async def _watch_prep_then_analyze(key: str) -> None:
    """Self-healing tail for a deferred series analysis: poll until the series
    has no active prep jobs, then re-run the eligibility check. Needed because
    not every prep exit path fires the post-prep hook (errors, the sibling-race
    early "done") — without this a deferred pass could be stranded forever."""
    lib = None
    try:
        while True:
            await asyncio.sleep(15)
            lib = await get_library()
            if not _series_prep_active(key, lib):
                break
    finally:
        _deferred_analysis_watch.discard(key)
    items = _items_for_series_key(lib, key) if lib else []
    if items:
        _schedule_series_analysis_if_eligible(items[0], lib)


async def _ensure_analysis_for(src: Path, item_id: str = "") -> None:
    """Schedule a Smart Skip fingerprint pass for the item a freshly-prepped
    source belongs to. The post-prep counterpart of `_ensure_stt_for` — called
    from `_run_offline_job` once the HLS bundle lands. Best-effort and
    non-blocking: it only does one library read + (at most) a `create_task`, so
    it never holds up the prep job. `_schedule_series_analysis_if_eligible`
    handles the running-guard, eligibility, and the per-series lock."""
    if not analyzer.is_available() or not item_id:
        return
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if item:
        _schedule_series_analysis_if_eligible(item, lib)


# Pre-roll: show the skip button this many seconds before the range starts so
# the user has visual time to react when entering the window.
SKIP_PREROLL_SEC = 2.0

# Auto-skip countdown lengths (seconds). When a profile has auto-skip enabled we
# warn the viewer on the TV before acting instead of cutting immediately.
SKIP_COUNTDOWN_INTRO_SEC = 5
SKIP_COUNTDOWN_CREDITS_SEC = 10

# Deferred "mark watched" on skip-to-next-episode. When the viewer advances to
# the next episode, treat the current one as finished — regardless of how far in
# they were when they skipped. We arm a grace timer instead of marking
# immediately: if they were actually skipping real content (or skipped by
# mistake), the viewer comes back to that file within the window and we leave
# their real progress alone. If they don't return, we mark it watched.
CREDIT_SKIP_WATCH_DELAY_SEC = 60   # grace period before marking watched
# A stop / supersede / periodic save counts a file finished only once playback
# has reached the OUTRO: within this many seconds of the detected credits start,
# or — when no credits were detected — within this many seconds of the file's
# real end. Deliberately tighter than a blanket %-of-duration: stopping mid-
# episode (even well past the old 0.92 mark) leaves the file resumable; only
# reaching the outro credits it.
STOP_OUTRO_WINDOW_SEC = 10

# Track-preference sibling keys carried across every file_progress rewrite, so a
# periodic/stop/supersede save never clobbers a subtitle/audio pick. See GOTCHAS.md.
_TRACK_PREF_KEYS = ("audio_track", "subtitle_track",
                    "local_audio_idx", "local_subtitle_idx",
                    "subtitle_sel", "audio_sel")


def _cancel_pending_watch() -> None:
    """Drop any armed deferred-watch timer (viewer returned, or it's superseded)."""
    t = state.pending_watch_task
    state.pending_watch_task = None
    state.pending_watch = None
    if t and not t.done():
        t.cancel()


def _arm_credit_skip_watch(
    item_id: Optional[str], profile_id: Optional[str], file_path: Optional[str],
    pos_sec: float, dur_sec: float,
) -> None:
    """Schedule `file_path` to be marked watched after a grace period when the
    viewer skips away from it to the next episode, from any position. Only one
    timer is armed at a time — a newer skip supersedes an older pending one.

    Supersession semantics: if a watch is already pending for a *different* file
    when a new skip arrives, the viewer has skipped forward again without ever
    returning to that earlier episode. Their intent is unambiguous — they're
    done with it — so we mark it watched immediately rather than letting its
    grace timer get silently cancelled (which would lose the watch entirely if
    they keep skipping faster than the grace period). The new file then begins
    its own grace period as usual."""
    if not (item_id and profile_id and file_path) or dur_sec <= 0:
        return
    prior = state.pending_watch
    if prior and prior.get("file_path") != file_path:
        # Skipped past the prior episode without returning — finish it now.
        asyncio.create_task(_mark_file_watched_internal(
            prior["item_id"], prior["profile_id"],
            prior["file_path"], prior.get("duration_sec", 0) or 0,
        ))
    _cancel_pending_watch()
    state.pending_watch = {
        "item_id": item_id, "profile_id": profile_id,
        "file_path": file_path, "duration_sec": round(dur_sec, 1),
    }
    state.pending_watch_task = asyncio.create_task(
        _credit_skip_watch_grace(item_id, profile_id, file_path, dur_sec)
    )


async def _credit_skip_watch_grace(
    item_id: str, profile_id: str, file_path: str, dur_sec: float,
) -> None:
    """Wait out the grace period, then mark `file_path` watched unless the viewer
    has returned to it (vlc_progress_tracker cancels us on return; this is the
    backstop check for the case where playback simply stopped on a different
    file)."""
    try:
        await asyncio.sleep(CREDIT_SKIP_WATCH_DELAY_SEC)
    except asyncio.CancelledError:
        return
    cur = state.library_current_file
    if cur and file_path:
        try:
            if Path(cur).resolve() == Path(file_path).resolve():
                return  # viewer came back to it — leave their real progress alone
        except OSError:
            if cur == file_path:
                return
    await _mark_file_watched_internal(item_id, profile_id, file_path, dur_sec)
    if state.pending_watch and state.pending_watch.get("file_path") == file_path:
        state.pending_watch = None
        state.pending_watch_task = None


async def _mark_file_watched_internal(
    item_id: str, profile_id: str, file_path: str, dur_sec: float,
) -> None:
    """Set completed=True for one file/profile (used by the deferred credit-skip
    watch). Preserves any saved track prefs; never clobbers an already-completed
    entry."""
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        return
    canon = _canonical_item_path(file_path, item)
    prof_prog = item.setdefault("progress", {}).setdefault(profile_id, {})
    file_prog = prof_prog.setdefault("file_progress", {})
    existing = file_prog.get(canon) or file_prog.get(file_path) or {}
    if existing.get("completed"):
        return
    dur = existing.get("duration_sec") or dur_sec or 0
    file_prog[canon] = {
        "position_sec": round(dur, 1),
        "duration_sec": round(dur, 1),
        "completed": True,
        "updated_at": _now_iso(),
        **{k: v for k, v in existing.items()
           if k in ("audio_track", "subtitle_track",
                    "local_audio_idx", "local_subtitle_idx", "subtitle_sel",
                    "audio_sel")},
    }
    await put_library(lib)
    await broadcast("library_update", {"item_id": item_id, "status": item.get("status", "ready")})


def _position_is_finished(item: dict, file_path: str, pos: float, dur: float) -> bool:
    """Whether a stop/supersede/periodic-save at `pos` should count the file as
    finished — i.e. playback reached the outro.

    Finished only when `pos` is within `STOP_OUTRO_WINDOW_SEC` of the outro: the
    detected `skip_data[...].credits_start`, or the file's real end when no
    credits were detected. Completion is tied to the outro, not an arbitrary
    fraction — an episode the viewer stopped in the middle of (even past the old
    0.92 mark) stays resumable, which is the behaviour requested for a plain
    Stop. The next-episode / credit-skip path finalises via its own grace timer,
    so this stricter rule doesn't affect skip-to-next completion."""
    if dur <= 0:
        return False
    meta = _find_file_meta(item, file_path) or {}
    cs = meta.get("credits_start")
    outro = float(cs) if cs else dur
    return pos >= outro - STOP_OUTRO_WINDOW_SEC


async def _finalize_stopped_file(
    item_id: Optional[str], profile_id: Optional[str], file_path: Optional[str],
    pos: float, dur: float,
) -> None:
    """Persist a final position when VLC library playback of `file_path` stops or
    is superseded by another episode, marking it completed if it's effectively
    finished (near the end, or past the credits).

    Neither Stop nor starting a different episode ever flushed the outgoing
    episode's position — the only completion writers were the 15 s periodic saver
    (which needs a live `playing`/`paused` state and lags up to 15 s) and the
    credit-skip grace timer. So stopping — or jumping to another episode from the
    library list — while at the outro left the episode `completed:false` and
    therefore resumable: the next Play jumped back into an episode the viewer
    considered finished. This closes that gap. Completion is gated on reaching
    the outro (see `_position_is_finished`), so a stop partway through — even past
    the old 0.92 mark — is preserved as a resume point rather than credited.

    A non-finished stop still refreshes the position (closing the ≤15 s periodic
    gap) but never regresses a newer saved position — which also makes an
    end-of-file race that briefly reports the *next* file at t≈0 a no-op."""
    if not (item_id and profile_id and file_path) or dur <= 0 or pos <= 0:
        return
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        return
    canon = _canonical_item_path(file_path, item)
    prof_prog = item.setdefault("progress", {}).setdefault(profile_id, {})
    file_prog = prof_prog.setdefault("file_progress", {})
    existing = file_prog.get(canon) or file_prog.get(file_path) or {}
    if existing.get("completed"):
        return
    finished = _position_is_finished(item, canon, pos, dur)
    if not finished and pos <= existing.get("position_sec", 0):
        return  # older/stale snapshot (or an EOF-race t≈0) — keep what we have
    file_prog[canon] = {
        "position_sec": round(dur if finished else pos, 1),
        "duration_sec": round(dur, 1),
        "completed": finished,
        "updated_at": _now_iso(),
        **{k: v for k, v in existing.items() if k in _TRACK_PREF_KEYS},
    }
    await put_library(lib)


async def _series_finalize_and_switch(new_item_id: str,
                                       outgoing_file: Optional[str],
                                       pos: float = 0.0, dur: float = 0.0) -> None:
    """Merged-series playback crossed from one item's episode into another's.
    Finalize the outgoing episode under its OWN (old) item, then re-point
    `state.library_item_id` at the new owner so progress/skip/track-prefs key off
    the right item from here on. Idempotent — a no-op if the item didn't change.

    `pos`/`dur` are the outgoing file's live position at the crossing. When given
    they're preferred over the last saved progress record, which on a natural
    end-of-file advance can sit up to a 15 s save-tick short of the real end —
    enough to fall outside the outro window and leave a finished episode
    un-completed (see `_position_is_finished`)."""
    old_id = state.library_item_id
    old_prof = state.library_profile_id
    lib = await get_library()
    new_item = next((it for it in lib["items"] if it["id"] == new_item_id), None)
    if not new_item:
        return
    if old_id and old_prof and outgoing_file and old_id != new_item_id:
        old_item = next((it for it in lib["items"] if it["id"] == old_id), None)
        if old_item:
            canon = _canonical_item_path(outgoing_file, old_item)
            rec = (old_item.get("progress", {}).get(old_prof, {})
                           .get("file_progress", {}).get(canon, {}))
            fpos = pos if pos > 0 else float(rec.get("position_sec", 0) or 0)
            fdur = dur if dur > 0 else float(rec.get("duration_sec", 0) or 0)
            if fdur > 0:
                await _finalize_stopped_file(old_id, old_prof, canon, fpos, fdur)
    state.library_item_id = new_item_id
    state.library_item_file_count = len(new_item.get("files", []))
    # Force the tracker to (re)apply saved audio/subtitle prefs for the new item's
    # episode — the applied-file guard would otherwise treat it as already done.
    state.track_pref_applied_file = None


async def _vlc_marquee(text: str) -> None:
    """Show `text` on the TV (or clear it when empty). Offloads the file I/O."""
    await asyncio.to_thread(_marquee_write, text)


async def _cancel_skip_countdown() -> None:
    """Stop any in-flight auto-skip countdown and wipe the on-screen popup."""
    t = state.skip_countdown_task
    state.skip_countdown_task = None
    state.skip_countdown = None
    if t and not t.done():
        t.cancel()
    await _vlc_marquee("")


def _start_skip_countdown(
    kind: str, item: dict, file_path: str,
    end_at: float, target: float, lead: int,
) -> None:
    """Kick off the auto-skip countdown task (no-op if one is already running).

    `target` is the playback position to skip AT; `lead` is how many seconds of
    countdown precede it. The skip fires when playback reaches `target`.
    """
    if state.skip_countdown_task and not state.skip_countdown_task.done():
        return
    state.skip_countdown = {"type": kind, "file_path": file_path, "n": lead}
    state.skip_countdown_task = asyncio.create_task(
        _run_skip_countdown(kind, item, file_path, end_at, target, lead)
    )


async def _run_skip_countdown(
    kind: str, item: dict, file_path: str,
    end_at: float, target: float, lead: int,
) -> None:
    """Count down to `target` on the TV, then perform the skip.

    Position-driven: the displayed number is `ceil(target - pos)`, so it tracks
    real playback — it freezes while paused and grows/shrinks as the viewer
    seeks. The skip fires once `pos >= target` (intro start → seek past the
    whole intro; credits start → advance to the next episode, else stop), so the
    intro/credits is skipped in full after the warning. Aborts (clearing the
    popup) if the file changes, the viewer seeks well before the countdown
    window, or — for an intro — seeks past the intro end.
    """
    label = "intro" if kind == "intro" else "credits"
    intro_end = end_at if kind == "intro" else None
    last_n: Optional[int] = None
    try:
        while True:
            vs = await vlc_status()
            vstate = (vs or {}).get("state")
            # Playback ended or file changed under us → drop the countdown.
            if vstate in (None, "stopped") or state.library_current_file != file_path:
                return
            pos = float((vs or {}).get("time", 0) or 0)
            # Seeked clean past the intro → nothing left to skip.
            if intro_end is not None and pos >= intro_end:
                return
            remaining = target - pos
            # Seeked back well before the countdown window → drop it.
            if remaining > lead + SKIP_PREROLL_SEC:
                return
            if vstate == "paused":
                # Hold (and don't fire) while paused; pos is frozen anyway.
                await asyncio.sleep(0.5)
                continue
            if remaining <= 0:
                break  # reached the skip point
            n = max(1, min(lead, math.ceil(remaining)))
            if n != last_n:
                last_n = n
                state.skip_countdown = {"type": kind, "file_path": file_path, "n": n}
                await _vlc_marquee(f"Skipping {label} in {n}")
                await broadcast("state", state_snapshot())
            await asyncio.sleep(0.5)

        # Final guard against VLC having already advanced past this file.
        cur_uri = await vlc_playlist_uri()
        if cur_uri and cur_uri.startswith("file://"):
            if Path(uri_to_path(cur_uri)).resolve() != Path(file_path).resolve():
                return

        if kind == "intro":
            state.skip_offer_file = f"{file_path}#intro-done"
            await vlc("seek", val=str(int(end_at) + 1))
        else:
            state.skip_offer_file = f"{file_path}#credits-done"
            next_path = _next_file_in_item(item, file_path)
            if next_path and Path(next_path).exists():
                _arm_credit_skip_watch(
                    state.library_item_id, state.library_profile_id, file_path,
                    float((vs or {}).get("time", 0) or 0),
                    float((vs or {}).get("length", 0) or 0),
                )
                await vlc_next_file(file_path, item)
            else:
                await vlc("pl_stop")
        await broadcast("state", state_snapshot())
    finally:
        state.skip_countdown = None
        await _vlc_marquee("")


async def _maybe_emit_skip_offer(
    item: dict, file_path: str, meta: Optional[dict],
    prefs: dict, pos_sec: float, dur_sec: float,
) -> None:
    """Set or clear state.skip_offer based on current playback position.

    Auto-skip behavior: if the profile has auto_skip_* enabled, this helper
    starts an on-TV countdown (`_start_skip_countdown`) that fires the skip when
    playback reaches the intro/credits start — it does NOT show the dashboard
    offer. Manual (auto-skip off) still shows the Skip button as before.
    """
    if not meta:
        await _clear_skip_offer(file_path)
        return

    # A countdown owns the screen while it runs — don't fight it with offers.
    if state.skip_countdown_task and not state.skip_countdown_task.done():
        return

    # Intro window
    intro = meta.get("intro")
    if intro and intro.get("end", 0) > intro.get("start", 0):
        start = float(intro.get("start", 0))
        end   = float(intro.get("end",   0))
        if prefs.get("auto_skip_intro"):
            # Auto path: run the countdown over the `lead` seconds *before* the
            # intro and skip the whole intro the moment it starts. Trigger once
            # per file; the countdown task owns the screen from there.
            if ((start - SKIP_COUNTDOWN_INTRO_SEC) <= pos_sec < end
                    and state.skip_offer_file != f"{file_path}#intro-done"):
                state.skip_offer = None
                _start_skip_countdown(
                    "intro", item, file_path, end, start, SKIP_COUNTDOWN_INTRO_SEC,
                )
                await broadcast("state", state_snapshot())
                return
        elif ((start - SKIP_PREROLL_SEC) <= pos_sec < end
                and state.skip_offer_file != f"{file_path}#intro-done"):
            # Manual path: show the Skip button across [start - PREROLL, end].
            # The done-marker guard mirrors the auto path so a dismissed offer
            # (DELETE /api/skip-now sets `#intro-done`) doesn't pop back on the
            # next tick while still inside the intro window.
            offer = {"type": "intro", "end_at": round(end, 1), "file_path": file_path}
            if state.skip_offer != offer:
                state.skip_offer = offer
                state.skip_offer_file = file_path
                await broadcast("state", state_snapshot())
            return
        elif pos_sec >= end and state.skip_offer and state.skip_offer.get("type") == "intro":
            await _clear_skip_offer(file_path)

    # Credits window
    credits_start = meta.get("credits_start")
    if credits_start and pos_sec < dur_sec - 1:
        cs = float(credits_start)
        if prefs.get("auto_skip_credits"):
            # Auto path: run the countdown over the `lead` seconds *before* the
            # credits, then advance at credits_start (credits skipped in full).
            # Trigger once per file; the countdown task owns the screen from there.
            if (pos_sec >= cs - SKIP_COUNTDOWN_CREDITS_SEC
                    and state.skip_offer_file != f"{file_path}#credits-done"):
                state.skip_offer = None
                _start_skip_countdown(
                    "credits", item, file_path, 0.0, cs, SKIP_COUNTDOWN_CREDITS_SEC,
                )
                await broadcast("state", state_snapshot())
                return
        elif (pos_sec >= cs - SKIP_PREROLL_SEC
                and state.skip_offer_file != f"{file_path}#credits-done"):
            # Manual path: show the Skip button from [credits_start - PREROLL, end).
            # Done-marker guard mirrors the auto path so a dismissed offer stays
            # dismissed for the rest of the credits window.
            next_path = _next_file_in_item(item, file_path)
            next_exists = bool(next_path) and Path(next_path).exists()
            offer = {
                "type": "credits",
                "credits_start": round(cs, 1),
                "file_path": file_path,
                "has_next": next_exists,
                "next_file_path": next_path if next_exists else None,
            }
            if state.skip_offer != offer:
                state.skip_offer = offer
                state.skip_offer_file = file_path
                await broadcast("state", state_snapshot())
            return

    # Outside any window — clear if one was set for this file
    await _clear_skip_offer(file_path)


async def _clear_skip_offer(file_path: str) -> None:
    if state.skip_offer is not None and state.skip_offer.get("file_path") == file_path:
        state.skip_offer = None
        # don't reset skip_offer_file — it carries the done marker
        await broadcast("state", state_snapshot())
    elif state.skip_offer is not None:
        # Different file (e.g. user advanced manually) — drop the offer
        state.skip_offer = None
        await broadcast("state", state_snapshot())


async def vlc_next_file(current_file: str, item: dict) -> None:
    """Internal helper: advance VLC to the next file in this item's playlist."""
    next_path = _next_file_in_item(item, current_file)
    if not next_path or not Path(next_path).exists():
        return
    all_paths = _nav_order(item)
    try:
        idx = all_paths.index(next_path)
        new_tail = all_paths[idx:]
    except ValueError:
        new_tail = [next_path]
    state.library_playlist = new_tail
    state.library_current_file = next_path
    state.current_audio_track = -1
    state.current_subtitle_track = -1
    state.track_pref_applied_file = next_path
    await vlc_clear_playlist()
    await vlc("in_play", input=vlc_file_uri(Path(next_path)))
    for p in new_tail[1:]:
        await vlc("in_enqueue", input=vlc_file_uri(Path(p)))
    if state.library_item_id and state.library_profile_id:
        asyncio.create_task(_apply_track_prefs(
            state.library_item_id, state.library_profile_id, next_path, delay=2.0,
        ))


# ── Background Task: VLC Progress Tracker ────────────────────────────────────

async def vlc_progress_tracker() -> None:
    """Save watch progress + manage Smart Skip offers. Two cadences:

    - skip-offer detection runs every 2 s while a library item is playing
    - progress save runs every 15 s
    """
    last_progress_save = 0.0
    series_prev_file: Optional[str] = None   # outgoing file, for cross-item finalize
    prev_item_id: Optional[str] = None       # item that owned series_prev_file
    prev_pos = prev_dur = 0.0                 # its last-observed position/duration
    while True:
        await asyncio.sleep(2)
        if not state.library_item_id or not state.library_profile_id:
            # Clear any stale skip/resume offers when playback ends
            if state.skip_countdown_task and not state.skip_countdown_task.done():
                await _cancel_skip_countdown()
            changed = False
            if state.skip_offer is not None:
                state.skip_offer = None
                state.skip_offer_file = None
                changed = True
            if state.resume_offer is not None:
                state.resume_offer = None
                changed = True
            if changed:
                await broadcast("state", state_snapshot())
            continue
        try:
            vs = await vlc_status()
            if not vs:
                continue
            pos_sec = float(vs.get("time", 0))
            dur_sec = float(vs.get("length", 0))
            if dur_sec < 10:
                continue

            # Resolve which file is playing and look up its skip metadata
            current_uri = await vlc_playlist_uri()
            if current_uri and current_uri.startswith("file://"):
                state.library_current_file = uri_to_path(current_uri)
            cur_file = state.library_current_file

            # VLC advanced from series_prev_file to a different file on its own
            # (reached EOF and stepped to the next playlist entry). Provisionally a
            # within-item advance; the series branch below downgrades it if the new
            # file belongs to another item (that path finalizes separately).
            advanced = (series_prev_file is not None and cur_file
                        and cur_file != series_prev_file
                        and state.library_item_id == prev_item_id)

            # Merged-series playback spans multiple items (one per episode torrent).
            # Keep state.library_item_id pointed at the item that owns the file VLC
            # is actually playing so everything below (skip offers, track prefs,
            # progress save) keys off the right item as playback auto-advances
            # across item boundaries.
            if cur_file and state.library_series_map:
                owner = _series_owner_for_path(cur_file)
                if owner and owner != state.library_item_id:
                    await _series_finalize_and_switch(
                        owner, series_prev_file, prev_pos, prev_dur)
                    advanced = False  # cross-item crossing already finalized it

            # Within-item natural auto-advance: nothing else flushes the outgoing
            # episode (Stop/supersede go through their own handlers, cross-item via
            # the branch above), so finalize it from its last-observed position.
            # _finalize_stopped_file only credits it when that position reached the
            # outro — a natural EOF advance (pos ≈ dur) completes it; a manual jump
            # from mid-episode just refreshes the position without completing.
            if advanced and prev_dur > 0 and state.library_profile_id:
                await _finalize_stopped_file(
                    state.library_item_id, state.library_profile_id,
                    series_prev_file, prev_pos, prev_dur)

            series_prev_file = cur_file
            prev_item_id = state.library_item_id
            prev_pos, prev_dur = pos_sec, dur_sec

            if cur_file:
                lib_q = await get_library()
                item_q = next((it for it in lib_q["items"] if it["id"] == state.library_item_id), None)
                if item_q:
                    cur_file = _canonical_item_path(cur_file, item_q)
                    state.library_current_file = cur_file
                    # Viewer returned to a file we'd armed for deferred-watch
                    # (the credits were skipped wrong) — cancel the timer.
                    if state.pending_watch and state.pending_watch.get("file_path") == cur_file:
                        _cancel_pending_watch()
                    meta = _find_file_meta(item_q, cur_file)
                    prefs = _skip_settings_for_profile(lib_q, state.library_profile_id)
                    await _maybe_emit_skip_offer(item_q, cur_file, meta, prefs, pos_sec, dur_sec)

            # Apply saved track prefs when VLC advances to a new episode. This
            # runs on the 2 s cadence — it used to sit under the 15 s progress
            # throttle below, which left an auto-advanced episode subtitle-less
            # for up to ~17 s (and permanently, if the viewer stopped first).
            # The applied-file guard keeps it from re-sending mid-file so the
            # user can still override tracks during playback (see GOTCHAS.md).
            cur_now = state.library_current_file
            if (cur_now and cur_now != state.track_pref_applied_file and
                    state.library_item_id and state.library_profile_id):
                state.track_pref_applied_file = cur_now
                asyncio.create_task(_apply_track_prefs(
                    state.library_item_id, state.library_profile_id, cur_now, delay=2.0,
                ))

            now = asyncio.get_event_loop().time()
            if now - last_progress_save < 15:
                continue

            current_file = state.library_current_file
            if not current_file:
                continue

            lib = await get_library()
            item = next((it for it in lib["items"] if it["id"] == state.library_item_id), None)
            if not item:
                continue

            # Take a FRESH, self-consistent snapshot right before writing. The
            # pos/dur read at the top of this loop iteration come from status.json,
            # but the current file is resolved from a SEPARATE playlist.json call —
            # and during an auto-advance those two reads straddle the transition,
            # so one episode's position gets written under the NEXT episode's key.
            # That single inconsistency produces both reported symptoms: a finished
            # episode "restarts" (its key inherits the next file's t≈0) and playback
            # "jumps to the wrong episode" (the next file is stamped complete at the
            # old file's position). Re-read status + the active URI back-to-back and
            # bail this tick unless they agree with the file we're about to key on
            # and VLC is genuinely mid-playback (an end-of-file transition briefly
            # reports state≠playing / time≈0). A skipped tick does NOT advance
            # last_progress_save, so the next 2 s tick retries until consistent.
            vs2 = await vlc_status()
            if not vs2 or vs2.get("state") not in ("playing", "paused"):
                continue
            uri_now = await vlc_playlist_uri()
            if not (uri_now and uri_now.startswith("file://")):
                continue
            save_file = _canonical_item_path(uri_to_path(uri_now), item)
            if save_file != current_file:
                continue  # mid-transition — next tick will be consistent
            save_pos = float(vs2.get("time", 0) or 0)
            save_dur = float(vs2.get("length", 0) or 0)
            if save_dur < 10:
                continue

            last_progress_save = now
            pct = save_pos / save_dur
            prof_prog = item.setdefault("progress", {}).setdefault(state.library_profile_id, {})
            prof_prog["last_file"] = save_file
            file_prog = prof_prog.setdefault("file_progress", {})
            existing_fp = file_prog.get(save_file, {})
            file_prog[save_file] = {
                "position_sec": round(save_pos, 1),
                "duration_sec": round(save_dur, 1),
                # Complete only once playback reaches the outro (never regress an
                # already-completed file). Same rule as the stop/supersede
                # finalize, so a mid-episode position is never blanket-credited
                # at 0.92 and then left un-resumable.
                "completed": bool(existing_fp.get("completed"))
                             or _position_is_finished(item, save_file, save_pos, save_dur),
                "updated_at": _now_iso(),
                # Preserve saved track picks — they're sibling keys in the same
                # file_progress dict, and this write fires every 15 s (a full
                # replacement here silently wiped a subtitle pick made seconds
                # earlier, so replays defaulted back to subs-off).
                **{k: v for k, v in existing_fp.items()
                   if k in ("audio_track", "subtitle_track",
                            "local_audio_idx", "local_subtitle_idx", "subtitle_sel",
                    "audio_sel")},
            }
            await put_library(lib)

            await broadcast("progress_saved", {
                "item_id": state.library_item_id,
                "profile_id": state.library_profile_id,
                "file_path": save_file,
                "episode_name": Path(save_file).name,
                "position_sec": save_pos,
                "duration_sec": save_dur,
                "pct": round(pct * 100, 1),
            })
        except Exception:
            pass


# ── Stream Pipeline (stream-now, torrent auto-deleted on stop) ────────────────

async def stream_pipeline(
    magnet: str,
    title: str,
    file_index: Optional[int] = None,
    torrent_hash: Optional[str] = None,
) -> None:
    try:
        state.active_title = title
        state.stream_status = "buffering"
        state.current_audio_track = -1
        state.current_subtitle_track = -1
        await broadcast("stream_status", {"status": "buffering", "message": "Adding torrent to qBittorrent…"})

        if torrent_hash:
            # Torrent already added by /stream/prepare — use existing hash directly
            h = torrent_hash
            state.active_hash = h
        else:
            h = await qbit_add_magnet(magnet, sequential=True)
            if not h:
                raise RuntimeError("qBittorrent rejected the magnet (is it running on port 8081?)")
            state.active_hash = h
            for _ in range(30):
                await asyncio.sleep(1)
                if await qbit_info(h):
                    break
            else:
                raise RuntimeError("Torrent did not appear in qBittorrent after 30 s.")

        await qbit_streaming_mode(h)

        if file_index is not None:
            # Skip all files except the selected one
            all_files = await qbit_files(h)
            skip_ids = [f.get("index", i) for i, f in enumerate(all_files)
                        if f.get("index", i) != file_index]
            if skip_ids:
                await qbit_set_file_priority(h, skip_ids, 0)
            await broadcast("stream_status", {
                "status": "buffering", "message": "File selected. Buffering first pieces…",
            })
        else:
            await broadcast("stream_status", {
                "status": "buffering", "message": "Sequential mode set. Buffering first pieces…",
            })

        # Buffer loop — track per-file progress when a specific file is selected
        while True:
            if file_index is not None:
                file_list = await qbit_files(h)
                target = _file_by_index(file_list, file_index)
                info = await qbit_info(h)
                if target and info:
                    f_size = target.get("size", 1) or 1
                    f_prog = target.get("progress", 0)
                    mb = f_size * f_prog / 1_048_576
                    pct = f_prog * 100
                    total_mb = f_size / 1_048_576
                    state.progress = pct
                    state.downloaded_mb = mb
                    state.total_mb = total_mb
                    state.dl_speed_bps = info.get("dlspeed", 0)
                    state.ul_speed_bps = info.get("upspeed", 0)
                    await broadcast("stream_status", {
                        "status": "buffering",
                        "message": f"Buffering {mb:.1f} MB / {total_mb:.1f} MB ({pct:.1f}%)",
                        "progress": pct, "downloaded_mb": mb, "total_mb": total_mb,
                        "dl_speed_bps": state.dl_speed_bps, "ul_speed_bps": state.ul_speed_bps,
                    })
                    if mb >= settings.buffer_min_mb or pct >= settings.buffer_min_pct:
                        break
            else:
                info = await qbit_info(h)
                if info:
                    total = info.get("size", 1) or 1
                    done = info.get("completed", 0)
                    pct = done / total * 100
                    mb = done / 1_048_576
                    state.progress = pct
                    state.downloaded_mb = mb
                    state.total_mb = total / 1_048_576
                    state.dl_speed_bps = info.get("dlspeed", 0)
                    state.ul_speed_bps = info.get("upspeed", 0)
                    await broadcast("stream_status", {
                        "status": "buffering",
                        "message": f"Buffering {mb:.1f} MB / {state.total_mb:.1f} MB ({pct:.1f}%)",
                        "progress": pct, "downloaded_mb": mb, "total_mb": state.total_mb,
                        "dl_speed_bps": state.dl_speed_bps, "ul_speed_bps": state.ul_speed_bps,
                    })
                    if mb >= settings.buffer_min_mb or pct >= settings.buffer_min_pct:
                        break
            await asyncio.sleep(1)

        # Resolve the file to play
        files = await qbit_files(h)
        vid = _file_by_index(files, file_index) if file_index is not None else largest_video(files)
        if not vid:
            raise RuntimeError("No recognisable video file found in torrent.")

        info = await qbit_info(h)
        save_path = (info or {}).get("save_path", settings.qbit_download_path)
        file_path = Path(save_path) / vid["name"]
        state.active_file = file_path

        await vlc_clear_playlist()
        await vlc("in_play", input=vlc_file_uri(file_path))
        asyncio.create_task(vlc_focus_and_fullscreen())
        state.stream_status = "playing"
        await broadcast("stream_status", {"status": "playing", "message": f"Playing: {file_path.name}"})

    except asyncio.CancelledError:
        pass
    except Exception as e:
        state.stream_status = "error"
        await broadcast("stream_status", {"status": "error", "message": str(e)})


# ── Library Download Pipeline (keep file, no auto-delete) ─────────────────────

async def _recover_interrupted_downloads() -> None:
    """Re-drive download pipelines orphaned by an app restart.

    `library_download` persists the magnet + add params in item['pending_download']
    and spawns library_download_pipeline as a detached task. If the process
    restarts before that task records the torrent_hash, the item is left
    status='downloading' with no hash: library_download_monitor skips hash-less
    items and nothing re-adds the magnet, so it sits in the ongoing list forever
    (the "queued downloads stuck after restart" bug). On startup, find those
    orphans — anything still carrying a pending_download — and respawn the
    pipeline. Idempotent: re-adding a magnet qBit already has is a no-op, and
    pending_download is cleared the moment a hash is recorded."""
    try:
        lib = await get_library()
    except Exception:
        return
    recovered = 0
    for it in lib.get("items", []):
        if it.get("status") != "downloading":
            continue
        pend = it.get("pending_download") or {}
        magnet = pend.get("magnet", "")
        if not magnet:
            continue   # no params to replay (legacy item or already started) — leave to the monitor
        asyncio.create_task(library_download_pipeline(
            it["id"], magnet,
            pend.get("save_path", "") or settings.qbit_download_path,
            torrent_hash=it.get("torrent_hash") or pend.get("torrent_hash", ""),
            selected_file_indices=pend.get("selected_file_indices") or None,
            download_mode=_download_cfg(it)["mode"],
        ))
        recovered += 1
    if recovered:
        print(f"[download] re-driving {recovered} interrupted download(s) after restart")


async def library_download_pipeline(
    item_id: str,
    magnet: str,
    save_path: str = "",
    torrent_hash: str = "",
    selected_file_indices: Optional[list[int]] = None,
    download_mode: str = "now",
) -> None:
    """Add magnet to qBit for a full download; no streaming mode, never auto-deleted."""
    try:
        if torrent_hash:
            h = torrent_hash
        else:
            h = await qbit_add_magnet(magnet, save_path=save_path or None)
            if not h:
                lib = await get_library()
                for it in lib["items"]:
                    if it["id"] == item_id:
                        it["status"] = "error"
                        it.pop("pending_download", None)   # add failed — don't retry on restart
                        break
                await put_library(lib)
                await broadcast("library_update", {"item_id": item_id, "status": "error"})
                return

        lib = await get_library()
        for it in lib["items"]:
            if it["id"] == item_id:
                it["torrent_hash"] = h
                # Hash recorded → the monitor can manage this item from qBit even if
                # metadata is still pending, so it's no longer an orphan to recover.
                it.pop("pending_download", None)
                break
        await put_library(lib)

        # Wait for torrent metadata to appear, then build the file list
        for _ in range(30):
            await asyncio.sleep(2)
            info = await qbit_info(h)
            if info:
                break

        if info := await qbit_info(h):
            save_path = info.get("save_path", settings.qbit_download_path)
            qfiles = await qbit_files(h)
            files = build_file_list(qfiles, save_path)

            # Record the download schedule in the item model (the single source of
            # truth) and let _reconcile_item_downloads apply qBit priorities + pause.
            # Non-selected files become "skip" so they never download; the rest
            # inherit the item mode (now/idle). The scheduler reconciles every 15 s
            # too, but we apply once here so gating takes effect immediately.
            file_modes: dict[str, str] = {}
            if selected_file_indices:
                selected_set = set(selected_file_indices)
                for i, qf in enumerate(qfiles):
                    full = str(Path(save_path) / qf.get("name", ""))
                    if qf.get("index", i) not in selected_set:
                        file_modes[full] = "skip"

            lib = await get_library()
            target = None
            for it in lib["items"]:
                if it["id"] == item_id:
                    it["files"] = files
                    it["size_bytes"] = info.get("size", 0)
                    it["download"] = {
                        "mode": download_mode if download_mode in ("now", "idle") else "now",
                        "files": file_modes,
                    }
                    target = it
                    break
            await put_library(lib)
            if target is not None:
                idle_open = await _download_idle_open(lib)
                await _reconcile_item_downloads(target, idle_open)

        await broadcast("library_update", {"item_id": item_id, "status": "downloading"})

    except Exception as exc:
        await broadcast("library_update", {"item_id": item_id, "status": "error", "message": str(exc)})


# ── Background Task: late-subtitle upgrade (TV/VLC) ──────────────────────────

async def subtitle_upgrade_loop() -> None:
    """Swap an auto-applied AI subtitle for a real one once it finishes downloading.

    Real `.srt` sidecars routinely arrive *after* the video (streaming/sequential
    download) and discovery happens in waves, so the playback policy often lands
    on an AI sub first. While VLC is playing a library file whose subtitle is a
    *system-auto-applied* AI track (`state.sub_auto_ai_path` set) and the admin
    has `upgrade_late_subs` on, re-scan for a real preferred-language sidecar and
    switch to it, then notify the dashboard. A manual pick clears the marker, so
    we never override a deliberate choice. Runs only on the VLC path; the
    on-device player polls for the same upgrade itself (it isn't server-driven)."""
    while True:
        try:
            await asyncio.sleep(20)
            if not (state.subtitle_upgrade_late and state.sub_auto_ai_path
                    and state.library_item_id):
                continue
            video = await _current_playback_path()
            if not video or not video.exists():
                continue
            lib = await get_library()
            subs = _subs_cfg(lib)
            pref = subs["default_language"]
            # Cheap disk pre-check: is there a real (non-AI) preferred-language
            # sidecar present yet? Skip the heavier VLC re-scan until there is.
            files = await asyncio.to_thread(_discover_local_subs, video)
            real_files = [f for f in files if not _is_ai_sub_file(f)]
            has_pref = (any(_parse_sub_lang(f.name) == pref for f in real_files) if pref
                        else bool(real_files))
            if not has_pref and not (subs["single_option"] and len(real_files) == 1):
                continue
            tracks = await _load_all_local_subs(video)
            real = [t for t in tracks if not t.get("ai")]
            match = next((t for t in real if t["lang"] == pref), None) if pref else (real[0] if real else None)
            if match is None and subs["single_option"] and len(real) == 1:
                match = real[0]
            if match is None:
                continue                       # no real sub yet — keep watching
            state.current_subtitle_track = match["id"]
            state.sub_auto_ai_path = ""        # upgraded — stop watching this file
            await vlc("subtitle_track", val=str(match["id"]))
            lang = (match.get("lang") or pref or "").upper()
            await broadcast("subtitle_upgraded", {
                "lang": match.get("lang") or pref,
                "label": f"Switched to downloaded {lang + ' ' if lang else ''}subtitles".strip(),
            })
        except asyncio.CancelledError:
            raise
        except Exception:
            pass


# ── FastAPI App ───────────────────────────────────────────────────────────────

@asynccontextmanager
async def lifespan(app: FastAPI) -> AsyncGenerator:
    global qbit, vlc_client, _lib_lock, _jackett_cookie_lock, _analysis_gate, _MAIN_LOOP
    _MAIN_LOOP = asyncio.get_running_loop()
    # Make StreamLink's request handling the box's top priority before anything
    # else — so controls / UI / VLC-control stay responsive under heavy prep load.
    _raise_own_priority()
    await _log_version_banner()
    _lib_lock = asyncio.Lock()
    _jackett_cookie_lock = asyncio.Lock()
    _analysis_gate = asyncio.Semaphore(ANALYSIS_CONCURRENCY)
    _load_device_tokens()   # M5: restore paired-device bearer tokens
    qbit = httpx.AsyncClient(timeout=10.0)
    _vlc_http()   # build the persistent keep-alive VLC client up front
    await qbit_login()
    Path(settings.qbit_download_path).mkdir(parents=True, exist_ok=True)
    _marquee_write("")  # wipe any stale countdown text from a prior run

    # Seed the night-mode flag + intensity preset from the persisted settings so
    # the snapshot + any mid-session VLC relaunch (retry / restart) reflect them.
    # run.py / watchdog.py read the same settings independently at launch.
    try:
        _lib0 = await get_library()
        _nm = _lib0.get("settings", {})
        state.vlc_night_mode = bool(_nm.get("vlc_night_mode", False))
        state.vlc_night_mode_preset = _night_mode_preset(_nm.get("vlc_night_mode_preset"))
        _subs0 = _subs_cfg(_lib0)
        state.subtitle_default_language = _subs0["default_language"]
        state.subtitle_upgrade_late = _subs0["upgrade_late_subs"]
        state.subtitle_single_option = _subs0["single_option"]
        state.vpn_block_ui = _vpn_killswitch_cfg(_lib0)["block_ui"]
        _rebuild_ondemand_only_items(_lib0)
        state.preferred_adapter = _network_cfg(_lib0)["preferred_adapter"]
    except Exception:
        state.vlc_night_mode = False
        state.vlc_night_mode_preset = NIGHT_MODE_DEFAULT_PRESET

    # Apply the configured startup volume — a % of the admin cap (default 50%,
    # i.e. half-max). Without this, state.vlc_volume starts at 100 (the dataclass
    # default) which can blast if the cap is low.
    _startup_vol = round((await _global_max_volume()) * (await _global_vlc_start_volume_pct()) / 100)
    state.vlc_volume = _startup_vol
    state.user_volume_before_bg = _startup_vol
    _startup_raw = max(0, min(512, round(_startup_vol / 100 * 256)))
    await vlc("volume", val=str(_startup_raw))

    # If uvicorn was just restarted (admin shutdown, watchdog, manual relaunch)
    # while VLC kept playing, seed state from VLC so the dashboard doesn't sit
    # at "No active stream" until someone presses Stop.
    await _sync_state_from_vlc()

    # Health-check + repair the offline-cache layout: pre-v8 installs kept every
    # HLS bundle in a central .offline_cache/; v8 stores each beside its media so
    # it travels with the series. Relocate any old bundles (no re-encode) BEFORE
    # the prep loops spawn, so a bundle that's merely being moved is never seen as
    # "missing" and re-queued. Also builds the bundle serving index.
    await _migrate_offline_cache_layout()

    # Re-drive any download whose pipeline was interrupted by the restart (added
    # via library_download but no torrent_hash recorded yet) so it doesn't sit
    # orphaned in the ongoing list. Must run before the monitor so the hash lands
    # quickly; the monitor then takes over from qBit.
    await _recover_interrupted_downloads()

    guard       = asyncio.create_task(vpn_guard())
    broadcaster = asyncio.create_task(stat_broadcaster())
    dl_monitor  = asyncio.create_task(library_download_monitor())
    vlc_tracker = asyncio.create_task(vlc_progress_tracker())
    bg_loop     = asyncio.create_task(background_video_loop())
    jackett_mon = asyncio.create_task(jackett_health_monitor())
    reboot_loop = asyncio.create_task(scheduled_reboot_loop())
    autoprep_loop = asyncio.create_task(auto_prep_loop())
    update_loop = asyncio.create_task(updater_loop())
    dlsched_loop = asyncio.create_task(download_scheduler_loop())
    sysmon_loop = asyncio.create_task(system_monitor_loop())
    cachepurge_loop = asyncio.create_task(cache_autopurge_loop())
    subupgrade_loop = asyncio.create_task(subtitle_upgrade_loop())
    od_reaper_loop  = asyncio.create_task(_od_reaper())
    maint_loop      = asyncio.create_task(background_maintenance_loop())
    tvui_task       = asyncio.create_task(tv_ui_loop())
    rvol_guard      = asyncio.create_task(remote_volume_guard())   # opt-in: no-op unless REMOTE_VOLUME_GUARD=1 (Windows)

    # HID wireless remote (air-mouse) input — optional; needs pynput and an
    # interactive desktop session. None when disabled (REMOTE_CONTROL=0),
    # pynput is missing, or the hook couldn't install (headless service) —
    # start_listener logs the reason and the dashboard runs without it. The
    # `_tv_input_event` activity feed is what wakes the TV UI kiosk.
    state.tv_input_last = time.time()
    remote_listener = None
    power_listener = None
    if settings.remote_control:
        try:
            import remote_input
            remote_listener = remote_input.start_listener(
                asyncio.get_running_loop(), _remote_key_action,
                _remote_should_handle, on_input=_tv_input_event)
        except Exception:
            log.warning("HID remote input listener failed to start", exc_info=True)
        # ⏻ power button (Windows): usually a HID System Control usage the
        # keyboard hook can't see — Windows locks + sleeps the box. Disable
        # the OS sleep-button action and observe the press via Raw Input
        # instead. See docs/REMOTE.md + docs/GOTCHAS.md.
        if platform.system() == "Windows":
            asyncio.create_task(_neuter_sleep_button())
            try:
                import remote_input
                power_listener = remote_input.start_power_listener(
                    asyncio.get_running_loop(), _remote_key_action,
                    _remote_should_handle)
            except Exception:
                log.warning("power-button raw-input listener failed to start",
                            exc_info=True)

    yield

    for t in (guard, broadcaster, dl_monitor, vlc_tracker, bg_loop, jackett_mon,
              reboot_loop, autoprep_loop, update_loop, dlsched_loop, sysmon_loop,
              cachepurge_loop, subupgrade_loop, od_reaper_loop, maint_loop,
              tvui_task, rvol_guard):
        t.cancel()
    if remote_listener is not None:
        remote_listener.stop()
    if power_listener is not None:
        power_listener.stop()
    if state.stream_task and not state.stream_task.done():
        state.stream_task.cancel()
    await qbit.aclose()
    if vlc_client is not None:
        await vlc_client.aclose()


app = FastAPI(title="P2P StreamLink", version="2.0", lifespan=lifespan)


@app.middleware("http")
async def admin_https_redirect(request: Request, call_next):
    """Redirect /admin and /api/admin/* to HTTPS when accessed over plain HTTP.

    Honours `X-Forwarded-Proto` / `X-Forwarded-Host` so requests arriving via
    the port-443 reverse proxy (see https_proxy.py) are recognised as already
    HTTPS — without this, every admin hit through the proxy would redirect to
    the upstream's `127.0.0.1` host on https, breaking access for the real
    client and looping.
    """
    path = request.url.path
    if (path == "/admin" or path.startswith("/admin/") or path.startswith("/api/admin")):
        proto = (request.headers.get("x-forwarded-proto") or request.url.scheme).lower()
        if proto == "http":
            host = request.headers.get("x-forwarded-host") or request.url.hostname
            qs   = ("?" + request.url.query) if request.url.query else ""
            return RedirectResponse(f"https://{host}{path}{qs}", status_code=301)
    return await call_next(request)


# Endpoints that fire on a timer regardless of whether a human is present — they
# must NOT count as "usage" for the scheduled-reboot idle check.
_ACTIVITY_IGNORE_PATHS = (
    "/api/admin/scheduled-reboot",
    "/api/admin/reboot",
    "/api/admin/shutdown",
    # Updater config + status pollers — the admin Updates tab refreshes its
    # banner every few seconds; that's not "the user is watching", so it
    # mustn't keep the scheduled-reboot loop on the bench.
    "/api/admin/updater",
)


@app.middleware("http")
async def track_activity(request: Request, call_next):
    """Stamp state.last_activity on user-initiated interactions so the scheduled
    reboot can tell whether the box is idle. Mutating verbs (POST/PUT/PATCH/
    DELETE) and search GETs are treated as real usage; routine GET polling
    (state/events/version/prep-status) is not, so it never blocks a reboot."""
    method = request.method
    path = request.url.path
    if (method in ("POST", "PUT", "PATCH", "DELETE") or path == "/api/search") \
            and path not in _ACTIVITY_IGNORE_PATHS:
        state.last_activity = time.time()
        # Shed heavy background work the instant a user shows up (don't wait for the
        # 15 s auto-prep tick) — see _activity_kick. Cheap + idempotent once paused.
        try:
            _activity_kick()
        except Exception:
            pass
    return await call_next(request)


# Bare IPv4 literal (with an optional :port), e.g. "192.168.0.104" or
# "192.168.0.104:80". Group 1 is the address. Used by the adapter redirect to
# tell an IP-based connection apart from `remote.local` / `localhost`.
_IPV4_HOST_RE = re.compile(r"^(\d{1,3}(?:\.\d{1,3}){3})(?::\d+)?$")


@app.middleware("http")
async def network_adapter_redirect(request: Request, call_next):
    """Bounce a client that connected on a non-preferred adapter to the chosen one.

    uvicorn stays bound to 0.0.0.0, so every adapter answers — but when the admin
    has picked a primary adapter, a request that arrived on a *different* LAN
    adapter's IP is 307-redirected to the preferred adapter's current IP (e.g.
    http://192.168.0.104/ → http://192.168.0.106/). This keeps a single canonical
    address while still serving "something" on every adapter.

    Only bare-IPv4 hosts are touched: `remote.local` (mDNS) and `localhost` /
    `127.0.0.1` (the loopback the 443 reverse proxy uses) pass through untouched.
    `X-Forwarded-Host` / `-Proto` are honoured so requests arriving via the
    port-443 proxy redirect on the real client host + scheme, not 127.0.0.1.
    """
    raw_host = (request.headers.get("x-forwarded-host") or request.url.hostname or "")
    m = _IPV4_HOST_RE.match(raw_host)
    if m:
        host_ip = m.group(1)
        if host_ip != "127.0.0.1":
            try:
                import netadapters
                target = netadapters.redirect_target(state.preferred_adapter, host_ip)
            except Exception:
                target = None
            if target:
                proto = (request.headers.get("x-forwarded-proto") or request.url.scheme).lower()
                qs = ("?" + request.url.query) if request.url.query else ""
                return RedirectResponse(
                    f"{proto}://{target}{request.url.path}{qs}", status_code=307)
    return await call_next(request)


