# ── Routes: Profiles ─────────────────────────────────────────────────────────

@app.get("/api/profiles")
async def list_profiles() -> JSONResponse:
    lib = await get_library()
    profiles = [
        {
            "id": p["id"],
            "name": p["name"],
            "color": p.get("color", "indigo"),
            "has_pin": bool(p.get("pin_hash", "")),
            "elevated": bool(p.get("elevated", False)),
            "auto_skip_intro":   bool(p.get("auto_skip_intro", False)),
            "auto_skip_credits": bool(p.get("auto_skip_credits", False)),
            "resume_mode":       p.get("resume_mode", "auto"),
            "subtitles_on":      p.get("subtitles_on"),
            "allowed_indexers":  list(p.get("allowed_indexers", [])),
        }
        for p in lib["profiles"]
    ]
    return JSONResponse({"profiles": profiles})


@app.post("/api/profiles")
async def create_profile(req: ProfileReq) -> JSONResponse:
    lib = await get_library()
    if len(lib["profiles"]) >= 6:
        raise HTTPException(400, "Maximum 6 profiles reached.")
    profile = {"id": str(uuid.uuid4()), "name": req.name.strip()[:30], "color": req.color}
    lib["profiles"].append(profile)
    await put_library(lib)
    return JSONResponse({"profile": profile})


@app.delete("/api/profiles/{profile_id}")
async def delete_profile(profile_id: str) -> JSONResponse:
    lib = await get_library()
    lib["profiles"] = [p for p in lib["profiles"] if p["id"] != profile_id]
    for item in lib["items"]:
        item.get("progress", {}).pop(profile_id, None)
        hvp = item.get("hidden_by_profiles", [])
        if profile_id in hvp:
            hvp.remove(profile_id)
        dvp = item.get("default_visible_profiles", [])
        if profile_id in dvp:
            dvp.remove(profile_id)
    await put_library(lib)
    return JSONResponse({"ok": True})


# ── Routes: Library ───────────────────────────────────────────────────────────

def _item_hidden_for_profile(item: dict, profile_id: str) -> bool:
    """Return True if this item should appear in the user's hidden tab."""
    if not profile_id:
        return False
    if profile_id in item.get("hidden_by_profiles", []):
        return True
    dvp = item.get("default_visible_profiles", [])
    return bool(dvp) and profile_id not in dvp


@app.get("/api/library")
async def list_library(request: Request, profile_id: str = "") -> JSONResponse:
    is_admin = _check_admin(request)
    lib = await get_library()
    elevated_ids = {p["id"] for p in lib["profiles"] if p.get("elevated")}
    is_elevated  = bool(profile_id) and profile_id in elevated_ids
    items = []
    for it in lib["items"]:
        if it.get("admin_only") and not is_admin and not is_elevated:
            continue
        files = it.get("files", [])
        resume = find_resume_hint(it, profile_id) if profile_id else None
        # Slim "first_file" so single-file UI affordances (e.g. the On Device
        # button) know the path without fetching /files. Cheap: 1 file × 2 keys.
        first_file = None
        if files:
            f0 = files[0]
            first_file = {"path": f0.get("path", ""), "name": f0.get("name", "")}
        items.append({
            "id": it["id"],
            "title": it["title"],
            "series": it.get("series", ""),
            "season": it.get("season", 0),
            "episode": it.get("episode", 0),
            "file_count": len(files),
            "size_bytes": it.get("size_bytes", 0),
            "size_human": human_size(it.get("size_bytes", 0)),
            "added_at": it.get("added_at", ""),
            "status": it.get("status", "ready"),
            "torrent_hash": it.get("torrent_hash", ""),
            "series_key": _series_key(it),   # groups same-series items into one show tile
            "resume": resume,
            "first_file": first_file,
            "hidden": _item_hidden_for_profile(it, profile_id),
            **{f"skip_{k}": v for k, v in _item_skip_summary(it).items()},  # skip_status, skip_affected, skip_total
            "download_mode": _download_cfg(it)["mode"],   # now | idle — drives the card's Pause/Resume control
            "download_partial": any(m == "skip" for m in _download_cfg(it)["files"].values()),  # some files deselected → "Partial" badge
            "compressed": _item_has_compressed(it),       # any file re-encoded in place → "Compressed" badge (local-only)
        })
    items.sort(key=lambda x: (
        x["series"] or "\xff" + x["title"],
        x["season"],
        x["episode"],
        x["added_at"],
    ))
    return JSONResponse({"items": items})


async def _build_item_files(item: dict, profile_id: str) -> list[dict]:
    """Build the per-file payload (progress + live download/prep state) for one
    library item. Shared by the single-item `/files` endpoint and the merged
    `/series/{key}` endpoint so both emit identically-shaped file objects — each
    file additionally carries its owning ``item_id`` for the merged-series UI."""
    file_progs = (
        item.get("progress", {}).get(profile_id, {}).get("file_progress", {})
        if profile_id else {}
    )

    cfg = _download_cfg(item)
    has_torrent = bool(item.get("torrent_hash"))
    is_ready = item.get("status") == "ready"
    # Map per-file qBit download progress so the UI shows which files are actually on
    # disk — for a downloading torrent AND a "ready" one (a partial selection flips
    # ready with skipped files still absent; without live progress they'd masquerade
    # as complete). Falls back to status when qBit has no data (uploaded item, or the
    # torrent was removed).
    qmap: dict[str, float] = {}     # full path → progress
    qbase: dict[str, float] = {}    # basename → progress (fallback if path keys drift)
    if has_torrent:
        info = await qbit_info(item["torrent_hash"])
        qfiles = await qbit_files(item["torrent_hash"])
        if info and qfiles:
            sp = info.get("save_path", settings.qbit_download_path)
            for i, qf in enumerate(qfiles):
                name = qf.get("name", "")
                prog = qf.get("progress", 0.0)
                qmap[str(Path(sp) / name)] = prog
                qbase[Path(name).name] = prog   # best-effort; collisions rare (SxxExx names)

    prep_cfg = _prep_cfg(item)
    out = []
    for f in item.get("files", []):
        path = f.get("path", "")
        fp = file_progs.get(path)
        if fp:
            dur = fp.get("duration_sec", 0)
            pos = fp.get("position_sec", 0)
            progress = {
                "position_sec": pos,
                "duration_sec": dur,
                "completed": fp.get("completed", False),
                "pct": round(pos / dur * 100, 1) if dur else 0,
            }
        else:
            progress = None
        mode = _effective_file_mode(cfg, path)
        compressed = _file_is_compressed(f)
        # Live qBit progress drives completeness for active files. Fall back to a
        # basename match if the full-path key didn't line up (save-path drift).
        # Skipped files are special-cased below (disk truth, not qBit's stale view).
        qp = qmap.get(path)
        if qp is None:
            qp = qbase.get(Path(path).name)
        if compressed:
            # Compressed-in-place file: its bytes no longer match the torrent pieces,
            # so qBit's view is stale/damaged. Disk is authoritative — it's complete.
            dl_pct, complete = 100.0, True
        elif mode == "skip":
            # Skipped files: trust the disk, not qBit. qBit keeps a file's progress at
            # 1.0 after we delete it out from under it (until a recheck), so a freed
            # file would otherwise masquerade as complete. Grounding "complete" in
            # actual existence makes a deleted file fall into the "not downloaded →
            # Download" UI path immediately.
            if qp is not None and qp >= 0.999 and Path(path).exists():
                dl_pct, complete = round(qp * 100, 1), True
            else:
                dl_pct, complete = 0.0, False
        elif qp is not None:
            dl_pct = round(qp * 100, 1)
            complete = qp >= 0.999
        else:
            # No live qBit data at all (uploaded item, or torrent gone): trust status.
            complete = is_ready or not has_torrent
            dl_pct = 100.0 if complete else None
        out.append({
            "item_id": item.get("id", ""),              # owning item (join key for merged-series)
            "name": f.get("name", Path(path).name),
            "path": path,
            "size_bytes": f.get("size_bytes", 0),
            "size_human": human_size(f.get("size_bytes", 0)),
            "season": f.get("season", 0),
            "episode": f.get("episode", 0),
            "progress": progress,
            "mode": mode,                               # now | low | mid | high | idle | skip
            "dl_priority": _dl_priority_of(mode),       # low | mid | high — download-order tier (mid default)
            "prep_mode": _effective_prep_mode(prep_cfg, path),  # now | idle | never (stream-prep schedule)
            "prep_priority": _effective_prep_priority(prep_cfg, path),  # low | mid | high — prep-queue order
            "dl_pct": dl_pct,                           # download % (None if unknown)
            "complete": complete,                       # file fully downloaded → playable
            "compressed": compressed,                   # re-encoded in place → local-only, not torrent-backed
        })
    return out


@app.get("/api/library/{item_id}/files")
async def get_item_files(item_id: str, profile_id: str = "") -> JSONResponse:
    """Return the video file list for a library item with per-profile progress."""
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")
    cfg = _download_cfg(item)
    prep_cfg = _prep_cfg(item)
    out = await _build_item_files(item, profile_id)
    return JSONResponse({
        "files": out,
        "item_status": item.get("status", "ready"),
        "has_torrent": bool(item.get("torrent_hash")),  # gates the download-scheduling controls
        "download_mode": cfg["mode"],
        "prep_priority_default": prep_cfg["priority_default"],   # item/series-level prep-queue tier (mid default)
        "idle_open": state.download_idle_open,
        "idle_configured": state.download_idle_configured,
        "ondemand_only": bool(item.get("ondemand_only")),          # user can toggle unless locked
        "ondemand_only_locked": bool(item.get("ondemand_only_locked")),  # admin-locked → toggle disabled
        "hls_available": HLS_AVAILABLE,                  # JIT/prep unavailable on macOS → hide the toggle
    })


@app.get("/api/library/series/{series_key}")
async def get_series_files(request: Request, series_key: str,
                            profile_id: str = "") -> JSONResponse:
    """Merged view of a show whose episodes span several single-episode items.
    Concatenates every member item's files (each tagged with its owning item_id),
    ordered by (season, episode), plus a series-level resume hint and the show's
    cached TMDb metadata — everything the one-cohesive-show UI needs to render and
    to drive cross-item play/resume. See docs/LIBRARY_DATA.md § merged series."""
    is_admin = _check_admin(request)
    lib = await get_library()
    elevated_ids = {p["id"] for p in lib["profiles"] if p.get("elevated")}
    is_elevated  = bool(profile_id) and profile_id in elevated_ids
    members = [it for it in _items_for_series_key(lib, series_key)
               if not (it.get("admin_only") and not is_admin and not is_elevated)]
    if not members:
        raise HTTPException(404, "Series not found.")

    files: list[dict] = []
    for it in members:
        files.extend(await _build_item_files(it, profile_id))
    files.sort(key=lambda f: (f.get("season", 0) or 9999,
                              f.get("episode", 0) or 9999, f.get("name", "")))

    # Title + metadata: prefer a member that already has cached TMDb metadata.
    title = next((it.get("series") for it in members if (it.get("series") or "").strip()),
                 members[0].get("title", ""))
    meta = next((it.get("metadata") for it in members if it.get("metadata")), None)
    resume = find_series_resume_hint(members, profile_id) if profile_id else None

    # Series-level on-demand-only state so the merged-series episode page can
    # render its toggle: "on" only when EVERY member is on-demand-only; "locked"
    # when ANY member is admin-locked (a non-admin then can't flip the group).
    return JSONResponse({
        "series_key": series_key,
        "title": title,
        "item_ids": [it["id"] for it in members],
        "files": files,
        "resume": resume,
        "metadata": meta,
        "img_base": LOCAL_IMG_BASE,
        "hls_available": HLS_AVAILABLE,
        "ondemand_only": all(it.get("ondemand_only") for it in members),
        "ondemand_only_locked": any(it.get("ondemand_only_locked") for it in members),
    })


@app.get("/api/library/{item_id}/metadata")
async def get_item_metadata(item_id: str, refresh: int = 0) -> JSONResponse:
    """Return cached TMDb metadata for an item; auto-fetches on first access.
    Response always includes `enabled` so the UI can gracefully fall back to
    filename parsing when no TMDb key is configured.

    The first-access fetch is NOT allowed to block the response: we wait at
    most a few seconds, then return `pending=true` with no metadata and let the
    fetch finish in the background (a `metadata_update` SSE event fires when it
    lands). Cached items always return instantly — internet down or not."""
    key_present = bool(await _tmdb_effective_key())
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")

    cached = item.get("metadata") or {}
    pending = False
    if not cached and key_present:
        task = _spawn_metadata_fetch(item_id)
        done, _ = await asyncio.wait({task}, timeout=4.0)
        if done:
            try:
                cached = task.result() or {}
            except Exception:
                cached = {}
        else:
            pending = True
    elif refresh and key_present:
        cached = await _fetch_item_metadata(item_id, force=True) or cached

    return JSONResponse({
        "enabled":  key_present,
        "img_base": LOCAL_IMG_BASE,
        "metadata": cached or None,
        "pending":  pending,
    })


@app.get("/api/metadata/img/{size}/{filename}")
async def metadata_image(size: str, filename: str) -> Response:
    """TMDb artwork proxy with a permanent on-disk cache. Clients join this
    route via the `img_base` returned by the metadata endpoints, so posters,
    backdrops and episode stills keep rendering on the LAN when the internet
    is down (once cached). TMDb image paths are content-addressed → immutable."""
    if size not in _TMDB_IMG_SIZES or not _TMDB_IMG_FILE_RE.match(filename):
        raise HTTPException(404, "Not found.")
    got = await _tmdb_img_bytes(size, filename)
    if not got:
        raise HTTPException(404, "Image unavailable (not cached, no internet).")
    body, ct = got
    return Response(content=body, media_type=ct, headers={
        "Cache-Control": "public, max-age=31536000, immutable",
    })


# (title, year, kind) → cached metadata dict, for the search show-detail screen
# which looks up TMDb by name (not by library item). Coalesces concurrent
# lookups and survives for the process lifetime (TMDb data is effectively static).
_tmdb_title_cache: dict[tuple, dict] = {}
_tmdb_title_locks: dict[tuple, asyncio.Lock] = {}

# (kind, tmdb_id) → cached metadata dict, for the TMDb-first search flow which
# opens a show-detail page from a specific candidate the user picked (so we fetch
# by id rather than re-matching by title). Same lifetime/coalescing as above.
_tmdb_id_cache: dict[tuple, dict] = {}
_tmdb_id_locks: dict[tuple, asyncio.Lock] = {}


async def _tmdb_lookup_by_id(tmdb_id: int, kind: str) -> Optional[dict]:
    """Fetch the cache-shaped metadata for an exact TMDb entry the user already
    picked from the search list — no fuzzy title re-match. Mirrors the TV
    season-enumeration + fetch path of _tmdb_lookup_by_title but keyed by id."""
    if not tmdb_id or kind not in ("tv", "movie") or not await _tmdb_effective_key():
        return None
    ck = (kind, int(tmdb_id))
    if ck in _tmdb_id_cache:
        return _tmdb_id_cache[ck]
    lock = _tmdb_id_locks.setdefault(ck, asyncio.Lock())
    async with lock:
        if ck in _tmdb_id_cache:
            return _tmdb_id_cache[ck]
        if kind == "tv":
            details = await _tmdb_get(f"/tv/{tmdb_id}", {}) or {}
            seasons = sorted({
                int(s.get("season_number", 0))
                for s in details.get("seasons", []) or []
                if int(s.get("season_number", 0)) > 0
            })
            data = await _tmdb_fetch_tv(int(tmdb_id), seasons)
        else:
            data = await _tmdb_fetch_movie(int(tmdb_id))
        if not data or not data.get("title"):
            return None
        data["source"] = "tmdb"
        _tmdb_id_cache[ck] = data
        _tmdb_bg(_prefetch_metadata_images(data))
        return data


async def _tmdb_lookup_by_title(title: str, year: Optional[int],
                                 kind: str = "") -> Optional[dict]:
    """Match a free-text show/movie title to TMDb and return the cache-shaped
    metadata (poster/backdrop/overview/seasons→episodes). Mirrors
    _tmdb_match_show but keyed off a bare title rather than a library item, so
    the grouped-search detail screen can show real metadata before anything is
    downloaded. `kind` ("tv"/"movie"/"") biases the search."""
    query = _strip_release_tags(title or "").strip() or (title or "").strip()
    if not query or not await _tmdb_effective_key():
        return None
    ck = (query.lower(), year or 0, kind or "")
    if ck in _tmdb_title_cache:
        return _tmdb_title_cache[ck]
    lock = _tmdb_title_locks.setdefault(ck, asyncio.Lock())
    async with lock:
        if ck in _tmdb_title_cache:
            return _tmdb_title_cache[ck]

        match = None
        if kind != "movie":
            tv = await _tmdb_get("/search/tv", {"query": query, "include_adult": "false"})
            tv_results = (tv or {}).get("results", []) or []
            if tv_results:
                best = _tmdb_pick_tv(query, tv_results)
                match = {"kind": "tv", "id": best["id"]}
        if match is None and kind != "tv":
            mv = await _tmdb_get("/search/movie",
                                 {"query": query, "include_adult": "false",
                                  **({"year": year} if year else {})})
            mv_results = (mv or {}).get("results", []) or []
            if mv_results:
                match = {"kind": "movie", "id": mv_results[0]["id"]}
        if match is None:
            return None

        if match["kind"] == "tv":
            # Fetch details first to learn how many seasons exist, then pull
            # every real season's episodes (skip specials / season 0).
            details = await _tmdb_get(f"/tv/{match['id']}", {}) or {}
            seasons = sorted({
                int(s.get("season_number", 0))
                for s in details.get("seasons", []) or []
                if int(s.get("season_number", 0)) > 0
            })
            data = await _tmdb_fetch_tv(match["id"], seasons)
        else:
            data = await _tmdb_fetch_movie(match["id"])
        data["source"] = "tmdb"
        _tmdb_title_cache[ck] = data
        _tmdb_bg(_prefetch_metadata_images(data))
        return data


@app.get("/api/tmdb/lookup")
async def tmdb_lookup(title: str = "", year: int = 0, kind: str = "",
                     tmdb_id: int = 0) -> JSONResponse:
    """TMDb lookup for the search show-detail screen. Returns the same shape as
    the per-item metadata endpoint so the frontend renderers are shared.
    `pending`/`enabled` let the UI fall back to filename parsing.

    When `tmdb_id` + `kind` are given (the TMDb-first flow, where the user picked
    a specific candidate) the entry is fetched **directly by id** — no fuzzy title
    re-match. Otherwise it matches by `title` (the grouped-search fallback)."""
    key_present = bool(await _tmdb_effective_key())
    data = None
    if key_present:
        if tmdb_id and kind in ("tv", "movie"):
            data = await _tmdb_lookup_by_id(tmdb_id, kind)
        elif title.strip():
            data = await _tmdb_lookup_by_title(
                title.strip(), year or None, kind if kind in ("tv", "movie") else "")
    return JSONResponse({
        "enabled":  key_present,
        "img_base": LOCAL_IMG_BASE,
        "metadata": data,
    })


@app.get("/api/tmdb/search")
async def tmdb_search(query: str = "", kind: str = "") -> JSONResponse:
    """TMDb candidate shows/movies for a free-text query — the entry point of the
    TMDb-first search flow. Returns `{enabled, img_base, results:[{id, kind, title,
    year, overview, poster_path}]}` (same candidate shape as the metadata /search
    endpoint but keyed off a bare query, not a library item). Not admin-gated.
    `kind` filters "tv"/"movie"; empty searches both. `enabled=false` (no key) is
    the frontend's signal to fall back to the Jackett-first grouped search."""
    if not await _tmdb_effective_key():
        return JSONResponse({"enabled": False, "img_base": LOCAL_IMG_BASE,
                             "results": []})
    q = (query or "").strip()
    if not q:
        return JSONResponse({"enabled": True, "img_base": LOCAL_IMG_BASE,
                             "results": []})

    kind = kind if kind in ("tv", "movie") else ""
    results: list[dict] = []

    if kind in ("", "tv"):
        tv = await _tmdb_get("/search/tv",
                             {"query": q, "include_adult": "false"})
        for r in (tv or {}).get("results", []) or []:
            results.append({
                "id":          r.get("id"),
                "kind":        "tv",
                "title":       r.get("name") or "",
                "year":        (r.get("first_air_date") or "")[:4],
                "overview":    r.get("overview") or "",
                "poster_path": r.get("poster_path") or "",
                "popularity":  r.get("popularity") or 0,
            })
    if kind in ("", "movie"):
        mv = await _tmdb_get("/search/movie",
                             {"query": q, "include_adult": "false"})
        for r in (mv or {}).get("results", []) or []:
            results.append({
                "id":          r.get("id"),
                "kind":        "movie",
                "title":       r.get("title") or "",
                "year":        (r.get("release_date") or "")[:4],
                "overview":    r.get("overview") or "",
                "poster_path": r.get("poster_path") or "",
                "popularity":  r.get("popularity") or 0,
            })

    # Interleave tv + movie by TMDb popularity so the most relevant title leads
    # regardless of type (each list already comes back popularity-sorted).
    results = [r for r in results if r.get("id") and r.get("title")]
    results.sort(key=lambda r: r.get("popularity") or 0, reverse=True)
    for r in results:
        r.pop("popularity", None)

    return JSONResponse({"enabled": True, "img_base": LOCAL_IMG_BASE,
                         "results": results})


@app.post("/api/library/{item_id}/metadata/refresh")
async def refresh_item_metadata(item_id: str, request: Request,
                                 req: MetadataRefreshReq) -> JSONResponse:
    """Admin-only manual rematch / refresh. Accepts an optional `{tmdb_id, kind}`
    to force-bind a specific TMDb entry (covers cases where auto-match picks
    the wrong show)."""
    _require_admin(request)
    if not await _tmdb_effective_key():
        raise HTTPException(400, "TMDb API key is not configured.")
    data = await _fetch_item_metadata(
        item_id,
        force=True,
        override_tmdb_id=req.tmdb_id,
        override_kind=req.kind if req.kind in ("tv", "movie") else None,
    )
    if not data:
        raise HTTPException(404, "No TMDb match found for this item.")
    return JSONResponse({"ok": True, "metadata": data, "img_base": LOCAL_IMG_BASE})


@app.get("/api/library/{item_id}/metadata/search")
async def search_item_metadata(item_id: str, query: str = "",
                               kind: str = "") -> JSONResponse:
    """Return a list of TMDb candidate matches so the user can pick the right
    show/movie when auto-match guessed wrong. Not admin-gated (any profile can
    correct metadata, same as `/rename`). `kind` filters to "tv"/"movie";
    empty searches both. Empty `query` falls back to the item's derived name."""
    if not await _tmdb_effective_key():
        return JSONResponse({"enabled": False, "results": []})

    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")

    q = (query or "").strip()
    if not q:
        q, _year = _search_terms_for_item(item)
    if not q:
        return JSONResponse({"enabled": True, "img_base": LOCAL_IMG_BASE,
                             "results": []})

    kind = kind if kind in ("tv", "movie") else ""
    results: list[dict] = []

    if kind in ("", "tv"):
        tv = await _tmdb_get("/search/tv",
                             {"query": q, "include_adult": "false"})
        for r in (tv or {}).get("results", []) or []:
            results.append({
                "id":          r.get("id"),
                "kind":        "tv",
                "title":       r.get("name") or "",
                "year":        (r.get("first_air_date") or "")[:4],
                "overview":    r.get("overview") or "",
                "poster_path": r.get("poster_path") or "",
            })
    if kind in ("", "movie"):
        mv = await _tmdb_get("/search/movie",
                             {"query": q, "include_adult": "false"})
        for r in (mv or {}).get("results", []) or []:
            results.append({
                "id":          r.get("id"),
                "kind":        "movie",
                "title":       r.get("title") or "",
                "year":        (r.get("release_date") or "")[:4],
                "overview":    r.get("overview") or "",
                "poster_path": r.get("poster_path") or "",
            })

    return JSONResponse({"enabled": True, "img_base": LOCAL_IMG_BASE,
                         "results": results})


@app.post("/api/library/{item_id}/metadata/set")
async def set_item_metadata(item_id: str,
                            req: MetadataSetReq) -> JSONResponse:
    """User-driven metadata correction (not admin-gated — same audience as
    `/rename`). Two modes:

    - "tmdb":   force-bind the chosen TMDb entry (pinned as source="manual",
                pulls full episode data). Needs a TMDb key.
    - "custom": store hand-entered metadata (pinned as source="custom"). Needs
                no key — this is the offline / no-good-TMDb-match path."""
    if req.mode == "tmdb":
        if not await _tmdb_effective_key():
            raise HTTPException(400, "TMDb API key is not configured.")
        if not req.tmdb_id or req.kind not in ("tv", "movie"):
            raise HTTPException(400, "tmdb_id and kind ('tv'|'movie') are required.")
        data = await _fetch_item_metadata(
            item_id, force=True,
            override_tmdb_id=req.tmdb_id, override_kind=req.kind,
        )
        if not data:
            raise HTTPException(404, "Could not load that TMDb entry.")
        return JSONResponse({"ok": True, "metadata": data,
                             "img_base": LOCAL_IMG_BASE})

    if req.mode != "custom":
        raise HTTPException(400, "mode must be 'tmdb' or 'custom'.")

    title = (req.title or "").strip()
    if not title:
        raise HTTPException(400, "A title is required for custom metadata.")

    genres = [g.strip() for g in (req.genres or []) if g and g.strip()]
    year = (req.year or "").strip()
    # The hero renderer reads the year via (first_air_date|release_date)[:4], so
    # stashing the bare year there is enough to surface it.
    data = {
        "source":        "custom",
        "tmdb_kind":     req.kind if req.kind in ("tv", "movie") else "",
        "title":         title,
        "overview":      (req.overview or "").strip(),
        "poster_url":    (req.poster_url or "").strip(),
        "backdrop_url":  (req.backdrop_url or "").strip(),
        "first_air_date": year,
        "vote_average":  float(req.vote_average) if req.vote_average else 0,
        "genres":        genres,
        "seasons":       {},
        "fetched_at":    _now_iso(),
    }

    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")
    item["metadata"] = data
    await put_library(lib)
    return JSONResponse({"ok": True, "metadata": data,
                         "img_base": LOCAL_IMG_BASE})


@app.post("/api/library/series/{series_key}/metadata/set")
async def set_series_metadata(series_key: str,
                              req: MetadataSetReq) -> JSONResponse:
    """Series-wide metadata correction — fans `metadata/set` across every member of
    a merged series (a show whose episodes were downloaded as separate single-episode
    items). Same two modes and pinning as the per-item `set_item_metadata`, applied to
    all members so the whole show re-binds together. Not admin-gated (same audience as
    `/rename`). Returns the representative (first member's) metadata for the UI to paint."""
    if req.mode == "tmdb":
        if not await _tmdb_effective_key():
            raise HTTPException(400, "TMDb API key is not configured.")
        if not req.tmdb_id or req.kind not in ("tv", "movie"):
            raise HTTPException(400, "tmdb_id and kind ('tv'|'movie') are required.")
        lib = await get_library()
        member_ids = [it["id"] for it in _items_for_series_key(lib, series_key)]
        if not member_ids:
            raise HTTPException(404, "Series not found.")
        rep_data = None
        for mid in member_ids:
            # Force-bind the chosen TMDb entry on every member (each pins
            # source="manual"; all resolve the same show-level metadata).
            d = await _fetch_item_metadata(
                mid, force=True,
                override_tmdb_id=req.tmdb_id, override_kind=req.kind,
            )
            if rep_data is None:
                rep_data = d
        if not rep_data:
            raise HTTPException(404, "Could not load that TMDb entry.")
        return JSONResponse({"ok": True, "metadata": rep_data,
                             "img_base": LOCAL_IMG_BASE})

    if req.mode != "custom":
        raise HTTPException(400, "mode must be 'tmdb' or 'custom'.")

    title = (req.title or "").strip()
    if not title:
        raise HTTPException(400, "A title is required for custom metadata.")

    genres = [g.strip() for g in (req.genres or []) if g and g.strip()]
    year = (req.year or "").strip()
    data = {
        "source":        "custom",
        "tmdb_kind":     req.kind if req.kind in ("tv", "movie") else "",
        "title":         title,
        "overview":      (req.overview or "").strip(),
        "poster_url":    (req.poster_url or "").strip(),
        "backdrop_url":  (req.backdrop_url or "").strip(),
        "first_air_date": year,
        "vote_average":  float(req.vote_average) if req.vote_average else 0,
        "genres":        genres,
        "seasons":       {},
        "fetched_at":    _now_iso(),
    }

    lib = await get_library()
    members = _items_for_series_key(lib, series_key)
    if not members:
        raise HTTPException(404, "Series not found.")
    for it in members:
        # dict() so each member owns its own copy (they diverge over time, e.g. seasons).
        it["metadata"] = dict(data)
    await put_library(lib)
    return JSONResponse({"ok": True, "metadata": data,
                         "img_base": LOCAL_IMG_BASE})


@app.post("/api/library/{item_id}/rename")
async def rename_library_item(item_id: str, req: RenameReq) -> JSONResponse:
    """Rename a series (or a movie/one-off's title). The name is what drives the
    TMDb metadata query (`_search_terms_for_item`), so changing it here re-binds
    the artwork/episode info to the right show — e.g. fixing an "AOT" download
    that auto-matched the wrong series. For a series item the whole group is
    renamed (the library grouping key is `item.series`); cached metadata is
    dropped so the next fetch re-matches against the new name."""
    new_name = (req.name or "").strip()
    if not new_name:
        raise HTTPException(400, "Name cannot be empty.")

    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")

    old_series = (item.get("series") or "").strip()
    if old_series:
        if new_name == old_series:
            raise HTTPException(400, "That's already the series name.")
        # Rename every entry in the group so the library grouping AND the TMDb
        # query both move together. Drop each one's cached metadata so it
        # re-matches against the new name on next access.
        for it in lib["items"]:
            if (it.get("series") or "").strip() == old_series:
                it["series"] = new_name
                # Keep manual picks / custom metadata — the user chose those on
                # purpose; only auto-matched art should re-resolve to the new name.
                if (it.get("metadata") or {}).get("source") not in ("manual", "custom"):
                    it.pop("metadata", None)
        # Series subtitle/audio prefs are keyed by the series string — re-key
        # them so a remembered track choice survives the rename.
        for prof in lib.get("profiles", []):
            for key in ("series_subtitle_prefs", "series_audio_prefs"):
                prefs = prof.get(key)
                if isinstance(prefs, dict) and old_series in prefs:
                    prefs[new_name] = prefs.pop(old_series)
    else:
        # Movie / one-off: no series group, so rename this item's own title
        # (which is what its metadata query falls back to).
        if new_name == (item.get("title") or "").strip():
            raise HTTPException(400, "That's already the title.")
        item["title"] = new_name
        if (item.get("metadata") or {}).get("source") not in ("manual", "custom"):
            item.pop("metadata", None)

    await put_library(lib)

    # Re-fetch this item's metadata now so the response carries the corrected
    # art/overview (best effort — no TMDb key just returns null and the UI falls
    # back to the filename, exactly as before). A pinned manual/custom binding is
    # left untouched: keep the user's choice and hand it straight back.
    pinned = (item.get("metadata") or {}).get("source") in ("manual", "custom")
    data = item.get("metadata") if pinned else None
    if not pinned and await _tmdb_effective_key():
        data = await _fetch_item_metadata(item_id, force=True)
    return JSONResponse({
        "ok": True,
        "series": new_name if old_series else "",
        "metadata": data,
        "img_base": LOCAL_IMG_BASE,
    })


# How long the background settle waits for qBittorrent to physically relocate a
# torrent's content before giving up, and how often it re-checks.
MOVE_SETTLE_TIMEOUT = 1800   # 30 min — large cross-disk moves can be slow
MOVE_SETTLE_POLL    = 4      # seconds between disk-existence checks
# In-memory status of in-flight / recent series moves, keyed by the primary item
# id. Surfaced via GET /api/library/{id}/move-status so the UI can show progress.
_move_status: "dict[str, dict]" = {}


def _move_caches_sync(old_files: list[dict], new_files: list[dict]) -> None:
    """Move each file's co-located `.streamlink_cache/<key>` bundle from its old
    parent to its new parent (qBit relocates the media but not our sidecar). Keyed
    by name+size, which the move preserves, so the key — and the bundle — stay
    valid. Best-effort; a missing bundle is simply skipped. Run in a thread."""
    old_by_name = {Path(o["path"]).name: o for o in old_files}
    for nf in new_files:
        of = old_by_name.get(Path(nf["path"]).name)
        if not of:
            continue
        old_parent = Path(of["path"]).parent
        new_parent = Path(nf["path"]).parent
        if old_parent == new_parent:
            continue
        key = _offline_cache_key_for(nf.get("name", "") or Path(nf["path"]).name,
                                     int(nf.get("size_bytes", 0) or 0))
        old_cache = old_parent / OFFLINE_CACHE_DIRNAME / key
        new_cache = new_parent / OFFLINE_CACHE_DIRNAME / key
        try:
            if old_cache.exists() and not new_cache.exists():
                new_cache.parent.mkdir(parents=True, exist_ok=True)
                shutil.move(str(old_cache), str(new_cache))
        except Exception:
            pass


def _move_nontorrent_files_sync(old_files: list[dict], dest: str) -> list[dict]:
    """Physically move uploaded/non-torrent files into `dest` (flat) and return the
    rebuilt file dicts. Run in a thread."""
    dest_p = Path(dest)
    out: list[dict] = []
    for o in old_files:
        old = Path(o["path"])
        new = dest_p / old.name
        try:
            if old.exists() and old != new:
                new.parent.mkdir(parents=True, exist_ok=True)
                shutil.move(str(old), str(new))
        except Exception:
            pass
        season, episode = parse_season_episode(old.name)
        out.append({"name": old.name, "path": str(new),
                    "size_bytes": int(o.get("size", 0) or 0),
                    "season": season, "episode": episode})
    return out


async def _commit_item_move(item_id: str, old_files: list[dict],
                            new_files: list[dict]) -> None:
    """Move the co-located caches, then rewrite one item's stored file paths to the
    settled `new_files` (carrying over each file's `validation` verdict by name)."""
    await asyncio.to_thread(_move_caches_sync, old_files, new_files)
    lib = await get_library()
    it = next((x for x in lib["items"] if x["id"] == item_id), None)
    if not it:
        return
    old_by_name = {f.get("name") or Path(f.get("path", "")).name: f
                   for f in it.get("files", [])}
    merged: list[dict] = []
    for nf in new_files:
        prev = old_by_name.get(nf["name"])
        if prev and isinstance(prev.get("validation"), dict):
            nf = dict(nf, validation=prev["validation"])
        merged.append(nf)
    it["files"] = merged
    await put_library(lib)


async def _settle_series_move(primary_id: str, snapshot: list[dict], dest: str) -> None:
    """Background completion of a series move. For each torrent item, poll qBit's
    real file list + save path and **only** commit the library paths once the files
    actually exist at the destination — so the library never points at files qBit
    hasn't finished moving. Non-torrent items are moved here directly."""
    dest_p = Path(dest)
    deadline = time.monotonic() + MOVE_SETTLE_TIMEOUT
    pending = [s for s in snapshot if not s.get("skip")]
    status = _move_status.setdefault(primary_id, {})
    status.update({"dest": dest, "total": len(pending), "settled": 0,
                   "status": "moving", "started_at": time.time()})
    while pending and time.monotonic() < deadline:
        still: list[dict] = []
        for s in pending:
            try:
                done = await _try_settle_item(s, dest_p)
            except Exception as exc:
                hls_log.warning("move-settle %s: %s", s.get("id"), exc)
                done = False
            if not done:
                still.append(s)
        status["settled"] = status["total"] - len(still)
        pending = still
        if pending:
            await asyncio.sleep(MOVE_SETTLE_POLL)
    _invalidate_offline_cache_inventory()
    _invalidate_cleanup_inventory()
    await _rebuild_bundle_index()
    await broadcast("library_update", {"item_id": primary_id})
    status["status"] = "done" if not pending else "timeout"
    status["pending"] = len(pending)
    status["finished_at"] = time.time()
    if pending:
        hls_log.warning("series move %s: %d item(s) did not settle within %ds",
                        primary_id, len(pending), MOVE_SETTLE_TIMEOUT)


async def _try_settle_item(s: dict, dest: Path) -> bool:
    """Return True once item `s` is committed at its new location, else False
    (still moving / not yet confirmed)."""
    h = s.get("hash") or ""
    if h:
        info = await qbit_info(h)
        qfiles = await qbit_files(h)
        cur_save = (info or {}).get("save_path") or str(dest)
        new_files = build_file_list(qfiles, cur_save)
        if not new_files:
            return False
        # Only commit once every file physically exists at the new location —
        # qBit's content move is async, so the paths must be verified, not assumed.
        if not all(Path(f["path"]).exists() for f in new_files):
            return False
        await _commit_item_move(s["id"], s["old_files"], new_files)
        return True
    # Non-torrent: we own the move; do it now and commit.
    new_files = await asyncio.to_thread(_move_nontorrent_files_sync, s["old_files"], str(dest))
    await _commit_item_move(s["id"], s["old_files"], new_files)
    return True


@app.post("/api/library/{item_id}/move")
async def move_library_item(item_id: str, req: MoveReq, request: Request) -> JSONResponse:
    """Admin: relocate a whole series (or a movie/one-off) to a new directory.

    Torrent-backed items are moved via qBittorrent's `setLocation` (they keep
    seeding from the new path); non-torrent files are moved directly. The library's
    stored paths are **not** rewritten until the files physically exist at the
    destination — qBit's content move is asynchronous, so the actual relocation +
    path commit happen in a background task (`_settle_series_move`), and the
    co-located `.streamlink_cache/<key>` bundle rides along (move-stable key, no
    re-encode). Returns immediately with `status:"moving"`; poll
    `GET /api/library/{id}/move-status` for completion."""
    _require_admin(request)
    dest_dir = (req.dest_dir or "").strip()
    if not dest_dir:
        raise HTTPException(400, "Destination directory cannot be empty.")
    dest = Path(dest_dir)
    if not dest.is_dir():
        raise HTTPException(400, f"Destination is not an existing directory: {dest_dir}")

    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")
    series = (item.get("series") or "").strip()
    group = [it for it in lib["items"]
             if (series and (it.get("series") or "").strip() == series) or it["id"] == item_id]

    # Snapshot each item's current files (paths/names/sizes) BEFORE qBit starts the
    # move, then kick off setLocation for torrent-backed items. Nothing in the
    # library is rewritten here — that waits for disk confirmation in the background.
    snapshot: list[dict] = []
    qbit_errors: list[str] = []
    for it in group:
        h = (it.get("torrent_hash") or "").lower()
        old_files = [{"path": f.get("path", ""),
                      "name": f.get("name") or Path(f.get("path", "")).name,
                      "size": int(f.get("size_bytes", 0) or 0)}
                     for f in it.get("files", [])]
        entry = {"id": it["id"], "hash": h, "old_files": old_files}
        if h:
            ok = await qbit_set_location(h, str(dest))
            if not ok:
                qbit_errors.append(it.get("title", "") or h)
                entry["skip"] = True
        snapshot.append(entry)

    if all(s.get("skip") for s in snapshot):
        raise HTTPException(502, f"qBittorrent could not relocate: {', '.join(qbit_errors)}")

    asyncio.create_task(_settle_series_move(item_id, snapshot, str(dest)))

    return JSONResponse({
        "ok": True,
        "status": "moving",
        "dest_dir": str(dest),
        "items_moved": len([s for s in snapshot if not s.get("skip")]),
        "qbit_errors": qbit_errors,
    })


@app.get("/api/library/{item_id}/move-status")
async def move_library_status(item_id: str, request: Request) -> JSONResponse:
    """Progress of an in-flight / recent series move (see `move_library_item`)."""
    _require_admin(request)
    st = _move_status.get(item_id)
    if not st:
        return JSONResponse({"status": "none"})
    return JSONResponse(st)


@app.post("/api/library/download")
async def library_download(req: DownloadReq) -> JSONResponse:
    if not state.vpn_secure:
        raise HTTPException(403, "VPN not connected — download blocked.")
    lib = await get_library()
    # Dedup: bulk "download all episodes" can fire the same torrent twice (a double
    # click, a retry, or overlapping season/episode pickers), which used to create
    # two library items backed by one torrent — one of which then errors on the qBit
    # duplicate-add reject. If a still-live item already backs this exact info-hash,
    # return it instead of minting a duplicate. Errored items are ignored so a real
    # retry of a failed add still works. Distinct per-episode torrents (different
    # hashes) never collide, so genuine bulk downloads are unaffected.
    want_hash = (req.torrent_hash or extract_hash(req.magnet) or "").lower()
    if want_hash:
        dup = next((it for it in lib["items"]
                    if (it.get("torrent_hash") or "").lower() == want_hash
                    and it.get("status") != "error"), None)
        if dup is None:
            # Also match an in-flight add that hasn't recorded its hash yet.
            dup = next((it for it in lib["items"]
                        if (extract_hash((it.get("pending_download") or {}).get("magnet", "")) or "").lower() == want_hash
                        and it.get("status") != "error"), None)
        if dup is not None:
            return JSONResponse({"ok": True, "item_id": dup["id"], "duplicate": True,
                                 "default_save_path": settings.qbit_download_path})
    item: dict = {
        "id": str(uuid.uuid4()),
        "title": req.title,
        "series": req.series,
        "season": req.season,
        "episode": req.episode,
        "files": [],
        "size_bytes": 0,
        "added_at": _now_iso(),
        "status": "downloading",
        "torrent_hash": "",
        "progress": {},
        "default_visible_profiles": req.default_visible_profiles,
        "hidden_by_profiles": [],
        "download": {"mode": req.download_mode if req.download_mode in ("now", "idle") else "now",
                     "files": {}},
        # Persist everything the pipeline needs so an interrupted add (app restart
        # before the torrent_hash is recorded) can be re-driven on startup instead
        # of leaving an orphaned, hash-less item stuck forever in the ongoing list.
        # Cleared by the pipeline the moment the hash is persisted. See
        # _recover_interrupted_downloads.
        "pending_download": {
            "magnet": req.magnet,
            "save_path": req.save_path.strip(),
            "torrent_hash": req.torrent_hash,
            "selected_file_indices": req.selected_file_indices or [],
        },
    }
    lib["items"].append(item)
    await put_library(lib)
    state.downloading_count += 1
    # A freshly-created download is never admin-locked yet (the lock is toggled
    # later from the Content Lock tab), so it always counts toward the visible
    # badge; the monitor re-derives both counts authoritatively each tick.
    if not item.get("admin_only"):
        state.downloading_count_visible += 1
    save_path = req.save_path.strip() or settings.qbit_download_path
    asyncio.create_task(library_download_pipeline(
        item["id"], req.magnet, save_path,
        torrent_hash=req.torrent_hash,
        selected_file_indices=req.selected_file_indices or None,
        download_mode=item["download"]["mode"],
    ))
    return JSONResponse({"ok": True, "item_id": item["id"],
                         "default_save_path": settings.qbit_download_path})


@app.delete("/api/library/{item_id}")
async def delete_library_item(item_id: str, delete_file: bool = True) -> JSONResponse:
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")
    h = item.get("torrent_hash")
    if h:
        await qbit_delete(h, delete_files=delete_file)
    lib["items"] = [it for it in lib["items"] if it["id"] != item_id]
    await put_library(lib)
    return JSONResponse({"ok": True})


@app.post("/api/library/{item_id}/visibility")
async def set_item_visibility(item_id: str, req: VisibilityReq) -> JSONResponse:
    """Toggle per-profile visibility. hidden=true moves item to the user's hidden tab;
    hidden=false restores it to the main list."""
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")
    pid = req.profile_id
    hidden_by: list = item.setdefault("hidden_by_profiles", [])
    default_visible: list = item.setdefault("default_visible_profiles", [])
    if req.hidden:
        # Move to hidden: remove from explicit visible list (if present), else add to hidden list
        if default_visible and pid in default_visible:
            default_visible.remove(pid)
        elif pid not in hidden_by:
            hidden_by.append(pid)
    else:
        # Move to visible: remove from hidden list; if still restricted by default, grant access
        if pid in hidden_by:
            hidden_by.remove(pid)
        if default_visible and pid not in default_visible:
            default_visible.append(pid)
    await put_library(lib)
    return JSONResponse({"ok": True})


@app.post("/api/library/{item_id}/queue-play")
async def queue_play(item_id: str, profile_id: str = "", file_path: str = "") -> JSONResponse:
    """Queue an in-progress download to auto-play when it (or a specific file) finishes."""
    if not profile_id:
        raise HTTPException(400, "profile_id required.")
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")
    if item.get("status") != "downloading":
        raise HTTPException(400, "Item is not currently downloading.")
    state.play_when_ready_item_id = item_id
    state.play_when_ready_profile_id = profile_id
    state.play_when_ready_file_path = file_path or None
    # Route the boost through the download model so the scheduler keeps it — a raw
    # filePrio write would be reverted on the next reconcile. A specific file is
    # forced "high" (download now, first); a whole-item queue ensures the item isn't
    # stuck idle (mode→now, sweep idle files→now) + bumps it in qBit's global queue.
    dl = item.setdefault("download", {"mode": "now", "files": {}})
    files = dl.setdefault("files", {})
    if file_path:
        files[file_path] = "high"
    else:
        dl["mode"] = "now"
        for p, m in list(files.items()):
            if m == "idle":
                files[p] = "now"
    await put_library(lib)
    h = item.get("torrent_hash")
    if h:
        idle_open = await _download_idle_open(lib)
        await _reconcile_item_downloads(item, idle_open)
        if not file_path:
            await qreq("POST", "/api/v2/torrents/topPrio", data={"hashes": h})
    return JSONResponse({"ok": True})


@app.delete("/api/library/{item_id}/queue-play")
async def cancel_queue_play(item_id: str) -> JSONResponse:
    """Cancel a pending Play When Ready for this item."""
    if state.play_when_ready_item_id == item_id:
        state.play_when_ready_item_id = None
        state.play_when_ready_profile_id = None
    return JSONResponse({"ok": True})


class DownloadScheduleReq(BaseModel):
    mode: str            # "now" = download immediately; "idle" = only during idle/night window
    reset_files: bool = False   # True ⇒ clear per-file overrides so EVERY file (incl. skipped) inherits `mode`


class FileScheduleReq(BaseModel):
    file_paths: list[str]
    mode: str   # "now" | "high" | "idle" | "skip"


class PrepScheduleReq(BaseModel):
    file_paths: list[str]
    mode: str   # "now" (prep immediately) | "idle" (auto-prep when idle) | "never" (opt out)


class PrepPriorityReq(BaseModel):
    priority: str                       # "low" | "mid" | "high"
    file_paths: list[str] = []          # per-episode override; empty ⇒ set the item/series default
    scope: str = "files"                # "files" (per-episode) | "item" (series-level default)


class RecheckReq(BaseModel):
    file_paths: list[str]   # which files to verify (the episode-picker checkboxes)


class DeleteFilesReq(BaseModel):
    file_paths: list[str]   # which files to delete from disk to reclaim space


@app.post("/api/library/{item_id}/download-schedule")
async def set_download_schedule(item_id: str, req: DownloadScheduleReq) -> JSONResponse:
    """Item-level download schedule. "idle" = Pause (download only during the idle/
    night window, auto-resuming there); "now" = Resume (download immediately). Sweeps
    the per-file overrides too, but leaves explicit "skip" choices alone."""
    mode = req.mode if req.mode in ("now", "idle") else "now"
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")
    dl = item.setdefault("download", {"mode": "now", "files": {}})
    dl["mode"] = mode
    files = dl.setdefault("files", {})
    if req.reset_files:
        # "Whole torrent now/idle": drop every override so all files (including ones
        # previously skipped) inherit `mode` — now ⇒ fetch everything, idle ⇒ defer all.
        files.clear()
    elif mode == "idle":
        # Pause: defer the active files, but keep explicit skips skipped.
        for p, m in list(files.items()):
            if m in ("now", "low", "mid", "high"):
                files[p] = "idle"
    else:
        for p, m in list(files.items()):
            if m == "idle":
                files[p] = "now"
    idle_open = await _apply_item_schedule(item, lib)   # may flip ready→downloading
    await put_library(lib)
    await broadcast("library_update", {"item_id": item_id, "status": item.get("status", "downloading")})
    return JSONResponse({"ok": True, "mode": mode, "idle_open": idle_open})


@app.post("/api/library/{item_id}/file-schedule")
async def set_file_schedule(item_id: str, req: FileScheduleReq) -> JSONResponse:
    """Set the download schedule for specific files (or a whole folder, by passing
    its files) within a library item: "now" (normal), "high" (download now, first),
    "idle" (only during the idle/night window), or "skip" (never)."""
    mode = req.mode if req.mode in _FILE_MODES else "now"
    if not req.file_paths:
        raise HTTPException(400, "file_paths required.")
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")
    dl = item.setdefault("download", {"mode": "now", "files": {}})
    files = dl.setdefault("files", {})
    for p in req.file_paths:
        files[p] = mode
    idle_open = await _apply_item_schedule(item, lib)   # may flip ready→downloading (e.g. un-skip)
    await put_library(lib)
    await broadcast("library_update", {"item_id": item_id, "status": item.get("status", "downloading")})
    return JSONResponse({"ok": True, "updated": len(req.file_paths), "mode": mode})


@app.post("/api/library/{item_id}/delete-files")
async def delete_item_files(item_id: str, req: DeleteFilesReq) -> JSONResponse:
    """Delete specific files from disk to reclaim space, keeping them re-downloadable.
    Each file is marked "skip" (so qBit drops it to priority 0 and never refetches),
    its bytes are removed from disk, and its cached HLS bundle is purged. The file's
    metadata stays in the item, so the episode picker shows it as "not downloaded"
    with a Download button to grab it again later.

    EXCEPTION: a compressed-in-place file is no longer torrent-backed and CANNOT be
    re-downloaded — deleting it here would lose it permanently. Such paths are refused
    and returned in `blocked`; remove the whole item if you really want them gone."""
    if not req.file_paths:
        raise HTTPException(400, "file_paths required.")
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")

    # Map paths → declared sizes so we can report how much space was freed.
    sizes = {f.get("path", ""): f.get("size_bytes", 0) for f in item.get("files", [])}
    # Refuse compressed files: this endpoint promises re-downloadability, which a
    # re-encoded file can't honour. Report them back instead of silently dropping them.
    compressed_paths = {f.get("path", "") for f in item.get("files", []) if _file_is_compressed(f)}
    blocked = [p for p in req.file_paths if p in compressed_paths]
    targets = [p for p in req.file_paths if p in sizes and p not in compressed_paths]

    # 1) Mark skip + reconcile FIRST, so qBit drops these files to priority 0 and
    #    stops writing to them before we remove the bytes (no recreate-mid-delete).
    dl = item.setdefault("download", {"mode": "now", "files": {}})
    files = dl.setdefault("files", {})
    for p in targets:
        files[p] = "skip"
    await _apply_item_schedule(item, lib)

    # 2) Remove the bytes from disk + 3) purge the cached HLS bundle.
    freed = 0
    deleted = 0
    for p in targets:
        src = Path(p)
        # Resolve the co-located bundle dir BEFORE unlinking — its key derives from
        # the file's name+size, which we can't read once the file is gone.
        bundle_dir: Optional[Path] = None
        try:
            if src.exists():
                bundle_dir = _offline_cache_dir(src)
        except OSError:
            pass
        try:
            existed = src.exists()
            await asyncio.to_thread(src.unlink, missing_ok=True)
            if existed:
                freed += sizes.get(p, 0)
                deleted += 1
        except OSError:
            pass
        try:
            if bundle_dir and bundle_dir.exists():
                await asyncio.to_thread(shutil.rmtree, bundle_dir, ignore_errors=True)
        except OSError:
            pass

    await put_library(lib)
    await broadcast("library_update", {"item_id": item_id, "status": item.get("status", "downloading")})
    return JSONResponse({
        "ok": True, "deleted": deleted, "freed_bytes": freed,
        # Compressed files we refused to delete (not re-downloadable). The UI surfaces
        # this so the user knows why nothing happened for those rows.
        "blocked": [Path(p).name for p in blocked],
    })


@app.post("/api/library/{item_id}/prep-schedule")
async def set_prep_schedule(item_id: str, req: PrepScheduleReq) -> JSONResponse:
    """Set the STREAM-PREP schedule for specific files (the episode-picker prep bar):
    "now" preps them immediately, "idle" lets Automatic Stream Prep build the bundle
    while the box is idle, "never" opts them out of all auto-prep (the existing bundle
    is kept). The sibling of /file-schedule, but for HLS prep instead of download."""
    if not HLS_AVAILABLE:
        raise HTTPException(503, HLS_UNAVAILABLE_MSG)
    mode = req.mode if req.mode in _PREP_MODES else "idle"
    if not req.file_paths:
        raise HTTPException(400, "file_paths required.")
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")
    pr = item.setdefault("prep", {"files": {}})
    files = pr.setdefault("files", {})
    for p in req.file_paths:
        files[p] = mode
    await put_library(lib)

    # "now" kicks off prep right away (bulk queue, like a scoped /prep-all). "idle"
    # and "never" only persist intent — auto_prep_loop / the prep bar act on them.
    started = 0
    if mode == "now":
        prep_cfg = _prep_cfg(item)
        for p in req.file_paths:
            src = Path(p)
            try:
                if src.suffix.lower() not in VIDEO_EXTS or not src.exists():
                    continue
            except OSError:
                continue
            prio = _PREP_PRIO_NUM.get(_effective_prep_priority(prep_cfg, p), 1)
            st = await _maybe_start_prep_job(src, item_id, prep_prio=prio)
            if st.get("status") in ("processing", "pending", "paused"):
                started += 1
            await asyncio.sleep(0)
    return JSONResponse({"ok": True, "updated": len(req.file_paths), "mode": mode, "started": started})


@app.post("/api/library/{item_id}/prep-priority")
async def set_prep_priority(item_id: str, req: PrepPriorityReq) -> JSONResponse:
    """Set the prep-queue PRIORITY (low/mid/high, mid = default) that orders bulk /
    auto-prep. `scope="item"` (or an empty `file_paths`) sets the item/series-level
    default every episode inherits; otherwise it's a per-episode override. Any bulk
    prep jobs already queued for the affected files are re-stamped so a change takes
    effect immediately, and a "high" bump re-triggers the auto-prep enqueue so the
    newly-prioritised files jump ahead without waiting for the next idle sweep."""
    if not HLS_AVAILABLE:
        raise HTTPException(503, HLS_UNAVAILABLE_MSG)
    prio = req.priority if req.priority in _PREP_PRIORITIES else "mid"
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")
    pr = item.setdefault("prep", {"files": {}})
    item_scope = req.scope == "item" or not req.file_paths
    if item_scope:
        pr["priority_default"] = prio
    else:
        prio_map = pr.setdefault("priority", {})
        for p in req.file_paths:
            prio_map[p] = prio
    await put_library(lib)

    # Re-stamp any queued/running bulk jobs for the affected files so the new tier
    # orders the queue right away (a running encode isn't preempted — HLS can't
    # checkpoint — but its tier updates so subsequent parking decisions are correct).
    prep_cfg = _prep_cfg(item)
    affected = set(req.file_paths) if not item_scope else {
        f.get("path", "") for f in item.get("files", [])
    }
    num = _PREP_PRIO_NUM.get(prio, 1)
    for j in _offline_jobs.values():
        if j.get("queue") == "bulk" and j.get("src") in affected:
            j["_prep_prio"] = _PREP_PRIO_NUM.get(
                _effective_prep_priority(prep_cfg, j.get("src", "")), num
            )
    return JSONResponse({
        "ok": True, "priority": prio,
        "scope": "item" if item_scope else "files",
        "priority_default": prep_cfg["priority_default"],
    })


@app.post("/api/library/{item_id}/recheck")
async def recheck_files(item_id: str, req: RecheckReq) -> JSONResponse:
    """Force a qBittorrent piece-level recheck of the item's torrent, then report
    which of the requested files came back damaged. A file is "damaged" if it was
    fully downloaded before the recheck but isn't after (qBit found bad pieces and
    will re-fetch them). Each damaged file's cached HLS bundle is purged so it
    re-preps from the repaired source.

    qBit rechecks whole torrents, not individual files, so the recheck covers the
    torrent; `file_paths` only narrows which files we report on + invalidate."""
    if not state.vpn_secure:
        raise HTTPException(403, "VPN not connected — qBittorrent is stopped, so hash recheck is unavailable.")
    if not req.file_paths:
        raise HTTPException(400, "file_paths required.")
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")
    h = item.get("torrent_hash")
    if not h:
        raise HTTPException(400, "This item has no torrent to recheck (uploaded content).")
    # qBit rechecks whole torrents, so a recheck would mark every compressed-in-place
    # file in this item as damaged and re-fetch over it. Refuse rather than destroy.
    if _item_has_compressed(item):
        raise HTTPException(409, "This item has compressed files that are no longer "
                                 "torrent-backed — rechecking would mark them damaged "
                                 "and re-download over them.")

    sel = set(req.file_paths)

    # Map the requested paths to qBit files and snapshot their pre-recheck progress,
    # so we can tell "was complete, now damaged" from "was never downloaded (skip)".
    info = await qbit_info(h)
    if not info:
        raise HTTPException(409, "Torrent not found in qBittorrent.")
    sp = info.get("save_path", settings.qbit_download_path)

    def _qmap(qfiles: list) -> dict:
        m = {}
        for i, qf in enumerate(qfiles):
            m[str(Path(sp) / qf.get("name", ""))] = float(qf.get("progress", 0.0))
        return m

    before = _qmap(await qbit_files(h))

    # Kick the recheck and wait for it to leave the checking states (bounded so a
    # stuck/huge torrent can't hang the request forever). A short initial grace lets
    # qBit actually enter the checking state first, so a tiny torrent that rechecks
    # in well under a tick isn't mistaken for "already done" before it even starts.
    await qbit_recheck(h)
    await asyncio.sleep(1.5)
    checked = False
    for _ in range(600):                       # up to ~5 min (600 × 0.5 s)
        inf = await qbit_info(h)
        st = (inf or {}).get("state", "")
        if st and not st.startswith("checking") and st != "queuedForChecking":
            checked = True
            break
        await asyncio.sleep(0.5)

    after = _qmap(await qbit_files(h))

    damaged: list[str] = []
    purged = 0
    for path in req.file_paths:
        was_complete = before.get(path, 0.0) >= 0.999
        now_complete = after.get(path, 0.0) >= 0.999
        if was_complete and not now_complete:
            damaged.append(path)
            # Invalidate the cached bundle so playback re-preps from the repaired file.
            src = Path(path)
            try:
                if src.exists():
                    out_dir = _offline_cache_dir(src)
                    if out_dir.exists():
                        await asyncio.to_thread(shutil.rmtree, out_dir, ignore_errors=True)
                        purged += 1
            except OSError:
                pass

    # If anything was damaged, make sure the torrent is allowed to re-fetch the bad
    # pieces (recheck can leave a finished torrent paused).
    if damaged:
        await qbit_resume(h)
        await broadcast("library_update", {"item_id": item_id, "status": item.get("status", "downloading")})

    return JSONResponse({
        "ok": True,
        "checked": checked,                    # False ⇒ recheck didn't finish within the timeout
        "rechecked": len(sel),
        "damaged": [Path(p).name for p in damaged],
        "damaged_count": len(damaged),
        "cache_purged": purged,
    })


async def _vlc_wait_until_ready(
    expected_file: Optional[Path] = None, timeout: float = 20.0,
) -> bool:
    """Poll VLC until it has actually opened the file, then return True.

    "Ready" = VLC reports a playing/paused state AND a non-zero `length` (the
    duration only becomes known once the demuxer is up, which is precisely the
    moment a `seek` takes effect). When `expected_file` is given we also require
    VLC's current playlist URI to match it, so we don't mistake the *previously*
    playing file (background video, prior episode) for the new one.

    This is the responsiveness lever for play/resume. VLC's HTTP reply to the
    `in_play` command itself can lag several seconds behind actual playback
    (which starts in <1 s); the lighter `status.json` poll reflects the real
    state far sooner. Polling here — instead of awaiting `in_play`'s reply — is
    what lets the UI flip to "playing" and the resume seek land almost
    immediately. We poll every 0.2 s and still wait out a genuinely slow open so
    nothing fires before VLC can honour it.
    """
    target: Optional[Path] = None
    if expected_file is not None:
        try:
            target = expected_file.resolve()
        except Exception:
            target = expected_file
    deadline = time.monotonic() + timeout
    while time.monotonic() < deadline:
        vs = await vlc_status()
        if vs and vs.get("state") in ("playing", "paused") and float(vs.get("length", 0) or 0) > 0:
            if target is None:
                return True
            uri = await vlc_playlist_uri()
            if uri:
                cur = uri_to_path(uri)
                try:
                    if Path(cur).resolve() == target:
                        return True
                except Exception:
                    if cur == str(target):
                        return True
        await asyncio.sleep(0.2)
    return False


async def _library_play_launch(
    playlist: list[str],
    item_id: str,
    profile_id: str,
    seek_sec: Optional[float],
    resume_mode: str,
) -> None:
    """VLC handoff for a library play, run in the background.

    Flow:
    1. Fire `in_play` for the first file *detached* — VLC's HTTP reply to this
       command can hang for several seconds while the demuxer spins up, even
       though playback actually starts in <1 s. Awaiting it (the old behaviour)
       pinned the UI on "buffering" for that whole window.
    2. Poll `status.json` for the new file to actually be live, then flip
       `stream_status` to "playing" and seek to the resume point — both happen
       as soon as VLC is genuinely ready, not when `in_play` finally replies.
    3. Enqueue the rest in parallel via `asyncio.gather`. We let the `in_play`
       call finish first (correct playlist order); that wait is invisible since
       the user is already watching the first file.
    """
    first = Path(playlist[0])
    first_resolved = first.resolve()
    # Clear any stale playlist items first (incl. the bg video) so VLC's list
    # mirrors `playlist` and can't auto-advance into a leftover entry. Awaited
    # so it completes before the in_play below appends the new item.
    await vlc_clear_playlist()
    # Detached: don't let in_play's slow reply gate the UI flip or the seek.
    play_task = asyncio.create_task(vlc("in_play", input=vlc_file_uri(first_resolved)))
    try:
        # Wait for VLC to actually be playing the new file (poll, not the slow
        # in_play reply). Falls through after the timeout and flips optimistically
        # — the command is already on its way — so the UI never sticks.
        ready = await _vlc_wait_until_ready(first_resolved, timeout=10.0)

        state.stream_status = "playing"
        await broadcast("stream_status", {"status": "playing", "message": f"Playing: {first.name}"})
        await broadcast("state", state_snapshot())

        asyncio.create_task(vlc_focus_and_fullscreen())

        # Resume seek / offer run detached so they can fire in parallel with the
        # enqueue below. They outlive a cancelled _library_play_launch, so each
        # re-checks state.library_current_file before touching VLC — a newer play
        # (or prev/next) moves that pointer and the stale resume bails instead of
        # seeking the wrong file. `ready` lets the common case skip a second poll.
        expected_file = playlist[0]
        if seek_sec and seek_sec > 5:
            if resume_mode == "auto":
                async def _resume_seek(s: float, already_ready: bool) -> None:
                    target = int(s)
                    if not already_ready and not await _vlc_wait_until_ready(first_resolved):
                        return
                    if state.library_current_file != expected_file:
                        return
                    await vlc("seek", val=str(target))
                    # VLC occasionally ignores a seek issued the instant the
                    # demuxer comes up. Re-issue once if we're still parked near
                    # the start a moment later (guarded so a user who manually
                    # seeks forward in this window isn't yanked back).
                    await asyncio.sleep(0.6)
                    if state.library_current_file != expected_file:
                        return
                    vs = await vlc_status()
                    if vs and float(vs.get("time", 0) or 0) < target - 15:
                        await vlc("seek", val=str(target))
                asyncio.create_task(_resume_seek(seek_sec, ready))
            elif resume_mode == "prompt":
                async def _resume_offer(s: float, fp: str, iid: str, pl: list, already_ready: bool) -> None:
                    if not already_ready and not await _vlc_wait_until_ready(first_resolved):
                        return
                    if state.library_current_file != expected_file:
                        return
                    state.resume_offer = {"position_sec": s, "file_path": fp, "item_id": iid, "playlist": pl}
                    await broadcast("state", state_snapshot())
                asyncio.create_task(_resume_offer(seek_sec, playlist[0], item_id, playlist, ready))

        asyncio.create_task(_apply_track_prefs(item_id, profile_id, playlist[0], delay=3.5))

        rest = playlist[1:]
        if rest:
            # Ensure in_play has been accepted (so the tail appends in the right
            # place); bounded by vlc()'s own per-call timeouts.
            try:
                await play_task
            except Exception:
                pass
            await asyncio.gather(
                *(vlc("in_enqueue", input=vlc_file_uri(Path(p))) for p in rest),
                return_exceptions=True,
            )
    except asyncio.CancelledError:
        play_task.cancel()
        raise
    except Exception as e:
        play_task.cancel()
        state.stream_status = "error"
        await broadcast("stream_status", {"status": "error", "message": f"Playback failed: {e}"})
        await broadcast("state", state_snapshot())


@app.post("/api/library/{item_id}/play")
async def play_library_item(item_id: str, req: LibraryPlayReq) -> JSONResponse:
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")

    # Resolve playlist — if caller passed explicit files use those, else auto-select
    playlist = req.files
    if not playlist:
        hint = find_resume_hint(item, req.profile_id)
        if hint and hint.get("file_path"):
            # Build playlist starting from the resume file
            all_paths = [f["path"] for f in item.get("files", [])]
            try:
                start_idx = all_paths.index(hint["file_path"])
                playlist = all_paths[start_idx:]
            except ValueError:
                playlist = all_paths
        else:
            playlist = [f["path"] for f in item.get("files", [])]

    if not playlist:
        raise HTTPException(400, "No video files available for this item.")

    # Filter to files that are on disk — partial downloads may not have all files yet
    existing = [p for p in playlist if Path(p).exists()]
    if not existing:
        raise HTTPException(400, f"File(s) not yet downloaded: {', '.join(Path(p).name for p in playlist[:3])}")
    playlist = existing
    first = Path(playlist[0])
    # Robust playback lock — refuse to start VLC on a file mid-compress (it would
    # hold the source open and break the in-place replace).
    _assert_not_compressing(str(first))

    # Resolve seek position and resume mode synchronously
    seek_sec = req.seek_first_to
    if seek_sec is None:
        hint = find_resume_hint(item, req.profile_id)
        # Only apply the hint's position when it actually refers to the file we're
        # about to start (playlist[0]). For a Shuffle Play (or any explicit file
        # list) the first file is not the last-watched one, so its resume position
        # is meaningless here — applying it would seek the wrong file partway in.
        if (hint and hint.get("file_path") == playlist[0]
                and hint.get("position_sec", 0) > 5 and not hint.get("all_completed")):
            seek_sec = hint["position_sec"]
    prof_obj = next((p for p in lib.get("profiles", []) if p["id"] == req.profile_id), {})
    resume_mode = prof_obj.get("resume_mode", "auto")

    # Starting a different episode supersedes whatever was playing — flush the
    # outgoing episode's final position first, so jumping to another episode from
    # the library list credits a near-finished one instead of leaving it
    # resumable (see _finalize_stopped_file). Skip a same-file replay.
    prev_item = state.library_item_id
    prev_profile = state.library_profile_id
    prev_file = state.library_current_file
    if prev_item and prev_profile and prev_file and prev_file != playlist[0]:
        asyncio.create_task(_finalize_stopped_file(
            prev_item, prev_profile, prev_file,
            float(state.vlc_time or 0), float(state.vlc_duration or 0),
        ))

    # If a prior library play is still mid-handoff, cancel it so we don't race VLC
    prior = state.library_play_task
    if prior and not prior.done():
        prior.cancel()
    await _cancel_skip_countdown()

    # Flip state to buffering NOW so the SSE-driven UI paints loading state
    # before the slow VLC roundtrips even start.
    state.stream_status = "buffering"
    state.active_title = item["title"]
    state.active_file = first
    state.current_audio_track = -1
    state.current_subtitle_track = -1
    state.track_pref_applied_file = playlist[0]
    state.active_hash = item.get("torrent_hash") or None
    state.library_item_id = item_id
    state.library_profile_id = req.profile_id
    state.library_profile_name = (prof_obj or {}).get("name", "") or ""
    state.library_profile_color = (prof_obj or {}).get("color", "") or ""
    state.library_item_file_count = len(item.get("files", []))
    state.library_playlist = playlist
    # Shuffle Play: remember the full random order (the filtered, on-disk playlist)
    # so next/prev walk it. Any normal play clears it back to natural order.
    state.library_shuffle_order = list(playlist) if req.shuffle else []
    state.library_shuffle_scope = (req.shuffle_scope or "") if req.shuffle else ""
    # Merged-series play: record the path→owning-item map so the progress tracker
    # re-targets the active item as playback crosses item boundaries (needed for
    # BOTH natural and shuffle order — else a later episode's progress lands under
    # the first episode's item). The full stable order (for prev/next/credits-
    # advance) is only set in natural order; shuffle owns navigation via
    # library_shuffle_order. Cleared for a normal single-item play.
    if req.items and len(req.items) == len(req.files):
        _full_map = {p: iid for p, iid in zip(req.files, req.items)}
        state.library_series_map = {p: _full_map[p] for p in playlist if p in _full_map}
        state.library_series_order = [] if req.shuffle else list(playlist)
    else:
        state.library_series_map = {}
        state.library_series_order = []
    # Persist the shuffle preference (or clear it on a normal play) so Resume can
    # offer to keep shuffling after a stop. Fire-and-forget — doesn't gate playback.
    asyncio.create_task(_set_shuffle_pref(
        item_id, req.profile_id, req.shuffle, req.shuffle_scope,
    ))
    state.library_current_file = playlist[0]
    state.skip_offer = None
    state.skip_offer_file = None
    state.resume_offer = None

    await broadcast("stream_status", {"status": "buffering", "message": f"Starting: {first.name}"})
    await broadcast("state", state_snapshot())

    state.library_play_task = asyncio.create_task(_library_play_launch(
        playlist, item_id, req.profile_id, seek_sec, resume_mode,
    ))

    # Auto-prep this episode (and the rest of the playlist) for on-device, if
    # enabled. Runs regardless of idle/activity settings — see _maybe_start_play_prep.
    # For a merged-series play the playlist spans items, but play-prep is per-item
    # (its files must belong to `item`), so restrict it to this item's own files.
    prep_playlist = playlist
    if state.library_series_map:
        own = {f.get("path", "") for f in item.get("files", [])}
        prep_playlist = [p for p in playlist if p in own] or playlist[:1]
    await _maybe_start_play_prep(lib, item, req.profile_id, prep_playlist, seek_sec)

    return JSONResponse(
        {"ok": True, "playlist_count": len(playlist), "seek_to": seek_sec},
        status_code=202,
    )


class ShufflePrefReq(BaseModel):
    profile_id: str
    shuffle: bool = False
    scope: str = ""               # "all" | "unwatched" | ""


@app.post("/api/library/{item_id}/shuffle-pref")
async def set_shuffle_pref(item_id: str, req: ShufflePrefReq) -> JSONResponse:
    """Record whether this item's playback is Shuffle Play (and its scope).

    The VLC play path persists this inline (LibraryPlayReq.shuffle_scope); the
    on-device player and the in-player "leave shuffle" control have no /play
    round-trip, so they call this directly to keep Resume's offer accurate."""
    await _set_shuffle_pref(item_id, req.profile_id, req.shuffle, req.scope)
    return JSONResponse({"ok": True})


@app.post("/api/library/{item_id}/progress")
async def update_progress(item_id: str, req: ProgressReq) -> JSONResponse:
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")
    dur = req.duration_sec
    pct = req.position_sec / dur if dur else 0
    prof_prog = item.setdefault("progress", {}).setdefault(req.profile_id, {})
    prof_prog["last_file"] = req.file_path
    file_progress = prof_prog.setdefault("file_progress", {})
    existing = file_progress.get(req.file_path, {})
    # `completed` is monotonic — a late/out-of-order progress POST (e.g. the
    # on-device player flushing a stale position after a resume) must never
    # un-finish an episode, or find_resume_hint jumps back into one already
    # watched. Matches the batch-sync endpoint's rule.
    already_done = bool(existing.get("completed"))
    file_progress[req.file_path] = {
        # Keep a finished episode pinned at the end rather than stamping the
        # incoming (older) mid position, so its resume point stays past-the-end.
        "position_sec": round(req.duration_sec if already_done and not (pct > 0.92)
                              else req.position_sec, 1),
        "duration_sec": round(req.duration_sec, 1),
        "completed": (pct > 0.92) or already_done,
        "updated_at": _now_iso(),
        # Preserve VLC + local-player track picks across progress writes —
        # these are sibling keys in the same file_progress dict. subtitle_sel
        # is the resolvable descriptor the on-device player restores from;
        # dropping it here reset subs to off on the next replay.
        **{k: v for k, v in existing.items() if k in _TRACK_PREF_KEYS},
    }
    await put_library(lib)
    return JSONResponse({"ok": True})


# ── Batch progress sync (iOS offline → server, plan A2) ──────────────────────
#
# The plain `update_progress` above is last-write-wins with no conflict detection
# — fine for the online dashboard where there's only ever one writer at a time.
# The iOS app, by contrast, accumulates watch progress *offline* (in its native
# OfflineStore) and flushes a whole batch when it reconnects. Between the device's
# last sync and now, the same episode may also have advanced elsewhere (e.g. the
# TV via the dashboard). So this endpoint does real per-event conflict detection
# using a per-file `base_synced_at` watermark the device carries:
#
#   • No server entry, OR server.updated_at <= base_synced_at  → server hasn't
#     moved since the device last synced this file → APPLY the device event.
#   • server.updated_at > base_synced_at (both advanced):
#       - positions agree within AUTO_RESOLVE_WINDOW, OR either side completed →
#         AUTO-RESOLVE (newest client/server timestamp wins; `completed` is
#         monotonic — never un-completed).
#       - otherwise → CONFLICT: write nothing, return {server, client} so the app
#         can ask the user (M4 resolution UI) and POST /sync/resolve.
#
# Every file the device can treat as settled (device won, server won, or a no-op
# acknowledgement) is returned in `applied` with the `server_updated_at` the
# device then records as that file's new `base_synced_at`. Only `conflicts` are
# left for the user. See docs/LIBRARY_DATA.md "base_synced_at watermark" and
# docs/API.md "POST /api/sync/progress".
#
# ⚠ PATH: these sync routes live at /api/sync/* — NOT /api/library/sync/* — on
# purpose. `/api/library/{item_id}/progress` (update_progress, registered earlier)
# would otherwise shadow `/api/library/sync/progress`, matching it with
# item_id="sync" and 422-ing on the missing top-level `file_path`. Keeping them
# outside the /api/library/{item_id} namespace makes that collision impossible.

SYNC_AUTO_RESOLVE_WINDOW = 60.0   # seconds; positions this close auto-merge


class SyncProgressEvent(BaseModel):
    item_id: str
    file_path: str
    position_sec: float
    duration_sec: float
    client_updated_at: str                       # when watched on the device (ISO)
    base_synced_at: Optional[str] = None         # device's last sync of THIS file (ISO)
    subtitle_sel: Optional[dict] = None          # preserved track picks (optional)
    audio_sel: Optional[dict] = None
    local_audio_idx: Optional[int] = None
    local_subtitle_idx: Optional[int] = None


class SyncProgressReq(BaseModel):
    profile_id: str
    events: list[SyncProgressEvent]


@app.post("/api/sync/progress")
async def sync_progress(req: SyncProgressReq, request: Request) -> JSONResponse:
    """Batch offline-progress sync with conflict detection (plan A2)."""
    _require_device_auth(request)
    applied: list[dict] = []
    conflicts: list[dict] = []
    now = _now_iso()
    _TRACK_KEYS = ("audio_track", "subtitle_track", "local_audio_idx", "local_subtitle_idx")

    async with _lib_lock:
        lib = await asyncio.to_thread(_load_lib_raw)
        items_by_id = {it["id"]: it for it in lib.get("items", [])}

        for ev in req.events:
            item = items_by_id.get(ev.item_id)
            if not item:
                # The library no longer has this item (deleted host-side). Tell the
                # device it's settled so it stops resending — nothing to apply.
                applied.append({"item_id": ev.item_id, "file_path": ev.file_path,
                                "server_updated_at": now, "skipped": "item_not_found"})
                continue

            prof_prog = item.setdefault("progress", {}).setdefault(req.profile_id, {})
            file_progress = prof_prog.setdefault("file_progress", {})
            existing = file_progress.get(ev.file_path)

            dur = ev.duration_sec
            pct = ev.position_sec / dur if dur else 0
            ev_completed = pct > 0.92

            def _apply() -> None:
                prev = existing or {}
                merged = {
                    "position_sec": round(ev.position_sec, 1),
                    "duration_sec": round(ev.duration_sec, 1),
                    # `completed` is monotonic — a fresh device position must never
                    # un-complete an episode the server already marked done.
                    "completed": ev_completed or bool(prev.get("completed")),
                    "updated_at": now,
                    # Preserve sibling track picks unless the event carries new ones.
                    **{k: v for k, v in prev.items() if k in _TRACK_KEYS},
                }
                if ev.local_audio_idx is not None:
                    merged["local_audio_idx"] = ev.local_audio_idx
                if ev.local_subtitle_idx is not None:
                    merged["local_subtitle_idx"] = ev.local_subtitle_idx
                if ev.subtitle_sel is not None:
                    norm = _norm_sub_sel(ev.subtitle_sel)
                    if norm:
                        merged["subtitle_sel"] = norm
                    elif prev.get("subtitle_sel") is not None:
                        merged["subtitle_sel"] = prev["subtitle_sel"]
                elif prev.get("subtitle_sel") is not None:
                    merged["subtitle_sel"] = prev["subtitle_sel"]
                if ev.audio_sel is not None:
                    norm = _norm_audio_sel(ev.audio_sel)
                    if norm:
                        merged["audio_sel"] = norm
                    elif prev.get("audio_sel") is not None:
                        merged["audio_sel"] = prev["audio_sel"]
                elif prev.get("audio_sel") is not None:
                    merged["audio_sel"] = prev["audio_sel"]
                file_progress[ev.file_path] = merged
                prof_prog["last_file"] = ev.file_path
                applied.append({"item_id": ev.item_id, "file_path": ev.file_path,
                                "server_updated_at": now})

            # No server entry → trivially apply.
            if not existing:
                _apply()
                continue

            server_dt = _parse_iso_dt(existing.get("updated_at"))
            base_dt = _parse_iso_dt(ev.base_synced_at)

            # Server unchanged since the device last synced this file → apply.
            if server_dt is None or base_dt is None or server_dt <= base_dt:
                _apply()
                continue

            # Both sides advanced — try to auto-resolve.
            server_pos = float(existing.get("position_sec", 0) or 0)
            server_completed = bool(existing.get("completed"))
            close = abs(server_pos - ev.position_sec) <= SYNC_AUTO_RESOLVE_WINDOW

            if close or ev_completed or server_completed:
                client_dt = _parse_iso_dt(ev.client_updated_at)
                device_newer = bool(client_dt and client_dt > server_dt)
                if device_newer:
                    _apply()                       # newest wins; _apply keeps completed monotonic
                elif ev_completed and not server_completed:
                    existing["completed"] = True   # server newer but device finished it
                    existing["updated_at"] = now
                    applied.append({"item_id": ev.item_id, "file_path": ev.file_path,
                                    "server_updated_at": now})
                else:
                    # Server wins, nothing to change — acknowledge so the device
                    # advances its watermark and stops resending.
                    applied.append({"item_id": ev.item_id, "file_path": ev.file_path,
                                    "server_updated_at": existing.get("updated_at") or now})
                continue

            # Genuine divergence — write nothing, surface for user resolution (M4).
            conflicts.append({
                "item_id": ev.item_id,
                "file_path": ev.file_path,
                "server": {
                    "position_sec": server_pos,
                    "duration_sec": float(existing.get("duration_sec", 0) or 0),
                    "completed": server_completed,
                    "updated_at": existing.get("updated_at"),
                },
                "client": {
                    "position_sec": round(ev.position_sec, 1),
                    "duration_sec": round(ev.duration_sec, 1),
                    "completed": ev_completed,
                    "client_updated_at": ev.client_updated_at,
                },
            })

        await asyncio.to_thread(_save_lib_raw, lib)

    return JSONResponse({"applied": applied, "conflicts": conflicts, "server_updated_at": now})


class SyncPullFile(BaseModel):
    item_id: str
    file_path: str


class SyncPullReq(BaseModel):
    profile_id: str
    files: list[SyncPullFile]


@app.post("/api/sync/pull")
async def sync_pull(req: SyncPullReq, request: Request) -> JSONResponse:
    """Server→device progress baseline (M3 companion to /sync/progress).

    Given the device's downloaded files, return the requesting profile's current
    server progress for each (`position_sec`/`duration_sec`/`completed`/`updated_at`)
    so the app can seed its OfflineStore baseline — making **offline resume reflect
    watch history accrued online** (and on other devices). Read-only; the device's
    `seedProgress` only adopts a baseline when it wouldn't clobber unsynced local
    offline progress."""
    _require_device_auth(request)
    lib = await get_library()
    items_by_id = {it["id"]: it for it in lib.get("items", [])}
    out: list[dict] = []
    for f in req.files:
        item = items_by_id.get(f.item_id)
        if not item:
            continue
        fp = (item.get("progress", {}).get(req.profile_id, {})
                  .get("file_progress", {}).get(f.file_path))
        if not fp:
            continue
        out.append({
            "item_id":      f.item_id,
            "file_path":    f.file_path,
            "position_sec": fp.get("position_sec", 0),
            "duration_sec": fp.get("duration_sec", 0),
            "completed":    bool(fp.get("completed")),
            "updated_at":   fp.get("updated_at") or "",
        })
    return JSONResponse({"progress": out})


class SyncResolution(BaseModel):
    item_id: str
    file_path: str
    choice: str                                  # "client" (keep device) | "server" (keep host)
    # Device values, written when choice == "client" (mirrors a SyncProgressEvent):
    position_sec: Optional[float] = None
    duration_sec: Optional[float] = None
    client_updated_at: Optional[str] = None
    subtitle_sel: Optional[dict] = None
    audio_sel: Optional[dict] = None
    local_audio_idx: Optional[int] = None
    local_subtitle_idx: Optional[int] = None


class SyncResolveReq(BaseModel):
    profile_id: str
    resolutions: list[SyncResolution]


@app.post("/api/sync/resolve")
async def sync_resolve(req: SyncResolveReq, request: Request) -> JSONResponse:
    """Write the user-chosen winner for conflicts /sync/progress reported (plan A3).

    `/sync/progress` returns genuine divergences in `conflicts` and writes nothing;
    the device surfaces a "mine vs server" UI (M4) and posts the user's choice here.
    `choice == "client"` writes the device values (bumping `updated_at`); `choice ==
    "server"` leaves the host untouched (the device adopts the returned server values
    as its new baseline). Either way the response carries the authoritative `server`
    values + `server_updated_at` the device records as the file's new watermark."""
    _require_device_auth(request)
    resolved: list[dict] = []
    now = _now_iso()
    _TRACK_KEYS = ("audio_track", "subtitle_track", "local_audio_idx", "local_subtitle_idx")

    async with _lib_lock:
        lib = await asyncio.to_thread(_load_lib_raw)
        items_by_id = {it["id"]: it for it in lib.get("items", [])}

        for rz in req.resolutions:
            item = items_by_id.get(rz.item_id)
            if not item:
                resolved.append({"item_id": rz.item_id, "file_path": rz.file_path,
                                 "choice": rz.choice, "server_updated_at": now,
                                 "skipped": "item_not_found"})
                continue

            prof_prog = item.setdefault("progress", {}).setdefault(req.profile_id, {})
            file_progress = prof_prog.setdefault("file_progress", {})
            existing = file_progress.get(rz.file_path) or {}

            if rz.choice == "client":
                pos = float(rz.position_sec or 0)
                dur = float(rz.duration_sec or 0)
                pct = pos / dur if dur else 0
                merged = {
                    "position_sec": round(pos, 1),
                    "duration_sec": round(dur, 1),
                    # `completed` stays monotonic even when the user keeps the device side.
                    "completed": (pct > 0.92) or bool(existing.get("completed")),
                    "updated_at": now,
                    **{k: v for k, v in existing.items() if k in _TRACK_KEYS},
                }
                if rz.local_audio_idx is not None:
                    merged["local_audio_idx"] = rz.local_audio_idx
                if rz.local_subtitle_idx is not None:
                    merged["local_subtitle_idx"] = rz.local_subtitle_idx
                if rz.subtitle_sel is not None:
                    norm = _norm_sub_sel(rz.subtitle_sel)
                    if norm:
                        merged["subtitle_sel"] = norm
                    elif existing.get("subtitle_sel") is not None:
                        merged["subtitle_sel"] = existing["subtitle_sel"]
                elif existing.get("subtitle_sel") is not None:
                    merged["subtitle_sel"] = existing["subtitle_sel"]
                if rz.audio_sel is not None:
                    norm = _norm_audio_sel(rz.audio_sel)
                    if norm:
                        merged["audio_sel"] = norm
                    elif existing.get("audio_sel") is not None:
                        merged["audio_sel"] = existing["audio_sel"]
                elif existing.get("audio_sel") is not None:
                    merged["audio_sel"] = existing["audio_sel"]
                file_progress[rz.file_path] = merged
                prof_prog["last_file"] = rz.file_path
                server_updated_at = now
                server_view = merged
            else:
                # "server" (or unknown choice → keep host, the safe default). No write;
                # the device adopts these values + watermark as its settled baseline.
                server_updated_at = existing.get("updated_at") or now
                server_view = existing

            resolved.append({
                "item_id": rz.item_id, "file_path": rz.file_path,
                "choice": rz.choice, "server_updated_at": server_updated_at,
                "server": {
                    "position_sec": float(server_view.get("position_sec", 0) or 0),
                    "duration_sec": float(server_view.get("duration_sec", 0) or 0),
                    "completed": bool(server_view.get("completed")),
                },
            })

        await asyncio.to_thread(_save_lib_raw, lib)

    return JSONResponse({"resolved": resolved})


class LocalTracksReq(BaseModel):
    profile_id: str
    file_path: str
    audio_idx: Optional[int] = None
    subtitle_idx: Optional[int] = None   # -1 = subtitles off (bundle index space only)
    # Resolvable descriptor for the chosen subtitle, used to re-apply the pick on
    # replay AND on other episodes of the same series.
    # {off,lang,ai,name,title,idx,sig,at} — see _norm_sub_sel.
    # Supersedes subtitle_idx, which can't address sidecar/AI picks (see GOTCHAS).
    subtitle_sel: Optional[dict] = None
    # Resolvable descriptor for the chosen audio track, applied on replay AND on
    # other episodes of the series. {lang,title,idx,sig,at} — see _norm_audio_sel.
    audio_sel: Optional[dict] = None
    # False ⇒ update the per-file pick only, NOT the per-series memory. The
    # client sends False for automatic writes (e.g. the late-AI-sub upgrade);
    # only a deliberate viewer pick may rewrite the series-wide preference —
    # unintended series writes were how subs "reverted to off" for whole series.
    sub_series: bool = True


@app.post("/api/library/{item_id}/local-tracks")
async def set_local_tracks(item_id: str, req: LocalTracksReq) -> JSONResponse:
    """Persist the in-browser player's audio/subtitle picks for a file.

    These are 0-based indices into the HLS bundle's audios/subtitles arrays
    (the order seen in meta.json), distinct from the VLC `audio_track` /
    `subtitle_track` ES IDs sitting next to them in the same file_progress
    dict. The two systems use different addressing schemes that don't
    interchange — that's why they're kept under separate keys.
    """
    series = ""
    async with _lib_lock:
        lib = await asyncio.to_thread(_load_lib_raw)
        item = next((it for it in lib["items"] if it["id"] == item_id), None)
        if not item:
            raise HTTPException(404, "Item not found.")
        series = _series_of_item(item)
        fp = (item.setdefault("progress", {})
                  .setdefault(req.profile_id, {})
                  .setdefault("file_progress", {})
                  .setdefault(req.file_path, {}))
        if req.audio_idx is not None:
            fp["local_audio_idx"] = req.audio_idx
        if req.audio_sel is not None:
            norm = _norm_audio_sel(req.audio_sel)
            if norm:
                norm.setdefault("at", _now_iso())   # newest-wins vs series pick
                fp["audio_sel"] = norm
                # Drop any older VLC ES-ID pick for this file — it would
                # otherwise outrank this newer descriptor on the next VLC play.
                fp.pop("audio_track", None)
        if req.subtitle_idx is not None:
            fp["local_subtitle_idx"] = req.subtitle_idx
        if req.subtitle_sel is not None:
            norm = _norm_sub_sel(req.subtitle_sel)
            if norm:
                norm.setdefault("at", _now_iso())   # newest-wins vs series pick
                fp["subtitle_sel"] = norm
                # Drop any older VLC ES-ID pick for this file — it would
                # otherwise outrank this newer descriptor on the next VLC play
                # (_apply_track_prefs prefers the raw ES ID when present).
                fp.pop("subtitle_track", None)
        await asyncio.to_thread(_save_lib_raw, lib)
    # Remember this kind of subtitle for the rest of the series (separate lock)
    # — but only for a deliberate viewer pick (see LocalTracksReq.sub_series).
    if req.subtitle_sel is not None and req.sub_series and series:
        await _save_series_sub_sel(req.profile_id, series, req.subtitle_sel)
    # An audio pick is always a deliberate viewer action (no automatic audio
    # writes), so it always updates the series-wide preference AND the
    # profile-level language fallback (which carries across separate items).
    if req.audio_sel is not None:
        await _learn_profile_audio_pref(req.profile_id, req.audio_sel)
        if series:
            await _save_series_audio_sel(req.profile_id, series, req.audio_sel)
    return JSONResponse({"ok": True})


@app.get("/api/library/{item_id}/saved-tracks")
async def get_saved_tracks(item_id: str, file_path: str = "", profile_id: str = "") -> JSONResponse:
    """Lightweight read of the persisted track picks for one file — the same
    `saved_tracks` shape /offline-prepare returns.

    Exists for the iOS app's on-device bundle playback, which never calls
    /offline-prepare (the stream is served by the phone's loopback server) but
    should still restore the remembered audio/subtitle picks while online.
    Deliberately no HLS_AVAILABLE gate or on-disk file check: track prefs live
    in library.json and are meaningful even when the host can't prep."""
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")
    return JSONResponse({
        "saved_tracks": _saved_local_tracks(lib, item, profile_id, file_path)
                        if profile_id else {},
    })


@app.post("/api/library/{item_id}/mark-watched")
async def mark_watched(item_id: str, req: MarkWatchedReq) -> JSONResponse:
    """Mark or unmark episodes as watched for a profile."""
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")

    files = item.get("files", [])
    if req.file_paths:
        targets = {p for p in req.file_paths}
        target_files = [f for f in files if f.get("path", "") in targets]
    elif req.season is not None:
        target_files = [f for f in files if f.get("season", 0) == req.season]
    else:
        target_files = files

    prof_prog = item.setdefault("progress", {}).setdefault(req.profile_id, {})
    file_prog = prof_prog.setdefault("file_progress", {})

    for f in target_files:
        path = f.get("path", "")
        if not path:
            continue
        existing = file_prog.get(path, {})
        if req.watched:
            file_prog[path] = {
                "position_sec": existing.get("duration_sec", 0),
                "duration_sec": existing.get("duration_sec", 0),
                "completed": True,
                "updated_at": _now_iso(),
                **{k: v for k, v in existing.items()
                   if k in ("audio_track", "subtitle_track",
                            "local_audio_idx", "local_subtitle_idx",
                            "subtitle_sel", "audio_sel")},
            }
        else:
            file_prog[path] = {
                "position_sec": 0,
                "duration_sec": existing.get("duration_sec", 0),
                "completed": False,
                "updated_at": _now_iso(),
                **{k: v for k, v in existing.items()
                   if k in ("audio_track", "subtitle_track",
                            "local_audio_idx", "local_subtitle_idx",
                            "subtitle_sel", "audio_sel")},
            }

    await put_library(lib)
    await broadcast("library_update", {"item_id": item_id, "status": item.get("status", "ready")})
    return JSONResponse({"ok": True, "updated": len(target_files)})


# ── Routes: Search & Stream ───────────────────────────────────────────────────

async def _apply_indexer_health(health: list) -> None:
    """Update indexer-health state from a *normalised* health list
    (``[{id, name, ok, error, results}]``) and broadcast a fresh ``state`` only on
    a degraded↔healthy transition so it doesn't spam every keystroke-debounced
    search. "Degraded" = at least one indexer failed AND at least one worked
    (all-failing is a different condition — likely Jackett/VPN down — covered by
    ``jackett_ok``)."""
    total = len(health)
    failing = sum(1 for h in health if not h["ok"])
    degraded = failing > 0 and failing < total

    state.indexer_health = health
    state.indexer_health_checked_at = time.time()
    state.indexers_total = total
    state.indexers_failing = failing

    if degraded != state.indexers_degraded:
        state.indexers_degraded = degraded
        if degraded:
            print(f"[indexers] DEGRADED — {failing}/{total} configured indexers failing")
        await broadcast("state", state_snapshot())


async def _record_indexer_health(idx_info: list) -> None:
    """Normalise a Jackett results-payload 'Indexers' block (each entry carries an
    ``Error`` string when that indexer failed) and feed it to ``_apply_indexer_health``."""
    health = [{
        "id": it.get("ID", ""),
        "name": it.get("Name", it.get("ID", "Unknown")),
        "ok": not (it.get("Error") or "").strip(),
        "error": (it.get("Error") or "").strip(),
        "results": it.get("Results", 0),
    } for it in (idx_info or [])]
    await _apply_indexer_health(health)


async def _list_configured_indexers() -> Optional[list]:
    """Return ``[{id, name}]`` for every configured Jackett indexer, or ``None`` if
    the list can't be fetched (so the caller can fall back to the aggregate query)."""
    try:
        async with _jackett_admin() as c:
            r = await c.get(
                f"{settings.indexer_url}/api/v2.0/indexers",
                params={"configured": "true"},
            )
        if r.status_code != 200:
            return None
        return [
            {"id": ix.get("id", ""), "name": ix.get("name", ix.get("id", "")) or ix.get("id", "")}
            for ix in r.json() if ix.get("id")
        ]
    except Exception:
        return None


# Torznab top-level category buckets (an ID's first digit-group) → friendly
# content-type label, so the search UI can show what each indexer carries.
_TORZNAB_TOP_TYPES = {
    "1000": "games",
    "2000": "movies",
    "3000": "music",
    "4000": "apps",
    "5000": "tv",
    "6000": "xxx",
    "7000": "books",
    "8000": "other",
}
# Friendly, stable display order for content-type chips.
_CONTENT_TYPE_ORDER = ["movies", "tv", "anime", "music", "books", "games", "apps", "xxx", "other"]

# Reverse of _TORZNAB_TOP_TYPES: a friendly content-type label → its Torznab
# top-level category bucket, so the search UI's category picker can translate a
# user's content-type selection into a Jackett ``Category[]`` filter. ``anime``
# has no distinct Torznab bucket (it lives inside Movies/TV and is name-matched),
# so it isn't separately filterable — the category picker omits it.
_CONTENT_TYPE_TO_TORZNAB = {
    "games": "1000", "movies": "2000", "music": "3000", "apps": "4000",
    "tv": "5000", "xxx": "6000", "books": "7000", "other": "8000",
}


def _torznab_top_bucket(cid: str) -> str:
    """The Torznab top-level bucket id (e.g. ``2040`` → ``2000``) for a category id,
    or the id unchanged if it isn't numeric."""
    return f"{(int(cid) // 1000) * 1000}" if cid.isdigit() else cid


def _resolve_search_categories(admin_raw: str, user_categories: Optional[str]):
    """Resolve the effective Torznab ``Category[]`` filter for a search.

    Combines the **admin** ``INDEXER_CATEGORIES`` override (a base restriction —
    explicit category ids; ``"0"``/blank means unrestricted) with the **user's**
    per-search content-type selection from the category picker. Returns:

    - ``None`` ⇒ no category filter (query everything the indexer carries),
    - ``[]``   ⇒ an explicit empty selection (the caller should return no results),
    - ``[ids…]`` ⇒ the category-id list to pass to Jackett.

    The two narrow each other: when the admin pins specific (sub)categories, the
    user's content-type selection keeps only those whose top-level bucket the user
    left selected, so the user can never broaden past the admin's restriction.
    """
    admin = {c.strip() for c in admin_raw.replace(",", " ").split()
             if c.strip() and c.strip() != "0"}
    user = None
    if user_categories is not None:
        user = {cid for lbl in user_categories.split(",")
                if (cid := _CONTENT_TYPE_TO_TORZNAB.get(lbl.strip().lower()))}
    if admin:
        eff = {a for a in admin if _torznab_top_bucket(a) in user} if user is not None else admin
    else:
        eff = user
    if eff is None:
        return None
    return sorted(eff)


def _indexer_content_types(caps: list) -> list:
    """Derive friendly content-type tags (movies, tv, anime, xxx, music, …) from a
    Jackett indexer's ``caps`` list of ``{ID, Name}`` Torznab categories. Anime is a
    name match (its Torznab cats — 5070/2070 or custom 1xxxxx — vary by indexer)."""
    types: set = set()
    for cap in caps or []:
        cid = str(cap.get("ID") or cap.get("id") or "")
        name = (cap.get("Name") or cap.get("name") or "")
        if "anime" in name.lower():
            types.add("anime")
        if not cid.isdigit():
            continue
        label = _TORZNAB_TOP_TYPES.get(f"{(int(cid) // 1000) * 1000}")
        if label:
            types.add(label)
    return [t for t in _CONTENT_TYPE_ORDER if t in types]


async def _configured_indexers_full() -> Optional[list]:
    """Return ``[{id, name, type, content_types}]`` for every configured Jackett
    indexer (with caps-derived content types), or ``None`` if the list can't be
    fetched. Feeds the search-source picker + the admin per-profile editor."""
    try:
        async with _jackett_admin() as c:
            r = await c.get(
                f"{settings.indexer_url}/api/v2.0/indexers",
                params={"configured": "true"},
            )
        if r.status_code != 200:
            return None
        out = []
        for ix in r.json():
            ixid = ix.get("id", "")
            if not ixid:
                continue
            out.append({
                "id": ixid,
                "name": ix.get("name", ixid) or ixid,
                "type": ix.get("type", ""),
                "content_types": _indexer_content_types(ix.get("caps", [])),
            })
        return out
    except Exception:
        return None


def _profile_allowed_indexers(lib: dict, profile_id: str) -> Optional[set]:
    """The set of indexer IDs a profile may search, or ``None`` for 'no restriction'.
    A profile's ``allowed_indexers`` that is absent or empty means unrestricted (all
    configured indexers) — the admin opt-in is to *narrow* it to a chosen subset."""
    if not profile_id:
        return None
    prof = next((p for p in lib.get("profiles", []) if p.get("id") == profile_id), None)
    if not prof:
        return None
    allowed = prof.get("allowed_indexers")
    if not allowed:
        return None
    return {str(x) for x in allowed}


def _shape_search_results(items: list, limit: int) -> list:
    """Map raw Jackett result dicts → the trimmed UI shape, drop entries with no
    magnet/link, de-duplicate (same torrent surfaced by multiple indexers keeps
    the highest-seeder copy), and sort by seeders."""
    seen: dict = {}
    results: list = []
    for it in items:
        mag = it.get("MagnetUri") or it.get("Link", "")
        if not mag:
            continue
        row = {
            "title": it.get("Title", "Unknown"),
            "size": it.get("Size", 0),
            "size_human": human_size(it.get("Size", 0)),
            "seeders": it.get("Seeders", 0),
            "peers": it.get("Peers", 0),
            "magnet": mag,
            "tracker": it.get("Tracker", ""),
        }
        h = extract_hash(mag) if mag.startswith("magnet:") else None
        key = h or (row["title"].lower(), row["size"])
        prev = seen.get(key)
        if prev is not None:
            if row["seeders"] > prev["seeders"]:
                prev.update(row)   # same object lives in `results`
            continue
        seen[key] = row
        results.append(row)
    results.sort(key=lambda x: x["seeders"], reverse=True)
    return results[:limit]


# ── Search-result relevance ──────────────────────────────────────────────────
# A raw seeder sort floats a high-seed *unrelated* release above the title the
# user actually opened — e.g. searching "Attack of the Clones" surfaces a brand-
# new "Star Wars: The Mandalorian and Grogu" (7869 seeders) at the top purely
# because it shares the "Star Wars" franchise words. We score each result title
# against the query so the intended release ranks first even with fewer seeders.
# See docs/GOTCHAS.md § search-result relevance.
_REL_STOPWORDS = {"the", "a", "an", "of", "and", "to", "in", "on", "at",
                  "for", "with", "from"}


def _rel_squash(s: str) -> str:
    """A title collapsed to bare alphanumerics (years dropped) for matching
    delimiter-less scene names — a hyphenated title and its space-stripped scene
    form collapse to the same string."""
    return re.sub(r"[^a-z0-9]+", "", _YEAR_RE.sub(" ", (s or "").lower()))


def _rel_tokens(s: str) -> set:
    """Distinctive lowercase word tokens of a title: split on punctuation, drop
    stop-words and bare release years (years are scored separately below)."""
    toks = re.sub(r"[^a-z0-9]+", " ", (s or "").lower()).split()
    return {t for t in toks if t not in _REL_STOPWORDS and not _YEAR_RE.fullmatch(t)}


def _title_relevance(query: str, title: str, name: str,
                     year_hint: Optional[int]) -> float:
    """Relevance of a torrent to the search `query`, scored against its *parsed
    show name* (`name`, release tags already stripped) with the raw `title` used
    only for the year signal. Two components:

    - **recall** — fraction of the query's distinctive tokens present in the name
      (the original signal: did we find what the user asked for?),
    - **precision** — fraction of the *name's* tokens that the query accounts for.
      This is the new lever: a franchise sibling, parody, or soundtrack
      ("The Matrix **Reloaded**", "**Rifftrax** The Matrix", "The Matrix
      **Soundtrack**") carries extra distinctive words the query never had, so it
      ranks below a clean exact-title match instead of tying at a saturated score.
      Scoring `name` rather than the raw title keeps quality tags (1080p, x264,
      BluRay…) from counting as "extra" words.

    Blended recall-heavy (0.7/0.3) so a longer *official* title whose every query
    word is present ("Star Wars Episode II Attack of the Clones") still scores
    high. A matching release year confirms (+0.5), a *different* one strongly
    demotes (−0.7) — almost always a different film sharing franchise words."""
    qt = _rel_tokens(query)
    if not qt:
        return 0.0
    ct = _rel_tokens(name) or _rel_tokens(title)
    inter = len(qt & ct)
    recall = inter / len(qt)
    precision = inter / len(ct) if ct else 0.0
    score = 0.7 * recall + 0.3 * precision
    # Squashed-name fallback: a delimiter-less scene name (all spaces/punctuation
    # stripped) tokenizes to one blob that matches nothing, so a legit release
    # scores 0.
    # If the whole query, stripped to alphanumerics, is contained in the same-
    # stripped name (or vice versa), floor the score to a strong match.
    if score < 0.9:
        sqq = _rel_squash(query)
        sqn = _rel_squash(name) or _rel_squash(title)
        if len(sqq) >= 5 and sqn and (sqq in sqn or sqn in sqq):
            score = 0.9
    if year_hint:
        ym = _YEAR_RE.search(title)
        if ym:
            score += 0.5 if int(ym.group(0)) == year_hint else -0.7
    return score


def _group_search_results(shaped: list, query: str,
                          akas: Optional[list] = None,
                          year_hint: Optional[int] = None) -> list:
    """Group already-shaped, seeder-sorted search results into one entry per
    detected show (see parse_torrent_title). Each group carries its member
    results (enriched with kind/season/episode and a per-result ``rel`` relevance
    score) so the show-detail screen needs no second search call and can rank its
    downloads by relevance. Groups are ordered by relevance, then seeders.

    ``akas`` are alternative titles (e.g. an anime's romaji name alongside the
    English one) — a result's ``rel`` is the **best** score across the query and
    every alias, so a JP-named season pack ranks with the English ones instead of
    scoring 0. ``year_hint`` overrides the year parsed from ``query`` (the show
    page passes it separately so the year can drive ranking without being baked
    into the indexer query, where it would exclude anime releases that carry no
    year)."""
    cands = [query] + [a for a in (akas or []) if a and a.strip()]
    if year_hint is None:
        qy = _YEAR_RE.search(query or "")
        year_hint = int(qy.group(0)) if qy else None
    groups: dict[str, dict] = {}
    for r in shaped:
        p = parse_torrent_title(r["title"])
        rel = max(_title_relevance(c, r["title"], p["show"], year_hint) for c in cands)
        aud, aud_lang = _parse_release_audio(r["title"])
        er = dict(r)
        er.update({
            "kind": p["kind"], "season": p["season"], "episode": p["episode"],
            "season_from": p["season_from"], "season_to": p["season_to"],
            "ep_from": p["ep_from"], "ep_to": p["ep_to"],
            "rel": round(rel, 3),
            "audio": aud, "audio_lang": aud_lang,
        })
        key = p["show_key"] or "?"
        g = groups.get(key)
        if g is None:
            g = groups[key] = {
                "key": key, "title": p["show"] or r["title"], "year": p["year"],
                "torrent_count": 0, "seeders_max": 0, "seasons": set(),
                "kinds": {"episode": 0, "season": 0, "multiseason": 0, "movie": 0},
                "results": [],
            }
        # Prefer a clean Latin display title once one appears — CJK-decorated
        # variants ("DanDaDan ダンダダン") share the key but make a noisy card.
        if (p["show"] and g["title"] != p["show"]
                and any(ord(ch) > 127 for ch in g["title"])
                and all(ord(ch) <= 127 for ch in p["show"])):
            g["title"] = p["show"]
        g["results"].append(er)
        g["torrent_count"] += 1
        g["seeders_max"] = max(g["seeders_max"], r.get("seeders", 0))
        g["kinds"][p["kind"]] = g["kinds"].get(p["kind"], 0) + 1
        if p["year"] and not g["year"]:
            g["year"] = p["year"]
        if p["kind"] in ("episode", "season") and p["season"]:
            g["seasons"].add(p["season"])
        elif p["kind"] == "multiseason" and p["season_from"]:
            for s in range(p["season_from"], (p["season_to"] or p["season_from"]) + 1):
                g["seasons"].add(s)
    out = []
    for g in groups.values():
        g["seasons"] = sorted(g["seasons"])
        # A group is as relevant as its best-matching member title.
        g["_rel"] = max((m.get("rel", 0) for m in g["results"]), default=0)
        out.append(g)
    out.sort(key=lambda g: (g["_rel"], g["seeders_max"], g["torrent_count"]), reverse=True)
    for g in out:
        g.pop("_rel", None)
    return out


@app.get("/api/search")
async def search(q: str, limit: int = 30,
                 indexers: Optional[str] = None,
                 categories: Optional[str] = None,
                 profile_id: Optional[str] = None,
                 year: int = 0,
                 aka: Optional[str] = None) -> JSONResponse:
    """Search configured indexers. ``indexers`` (comma-separated IDs) narrows the
    query to the user-chosen subset; ``categories`` (comma-separated content-type
    labels — movies/tv/music/…) narrows it to those Torznab category buckets so
    deselected types (e.g. ``xxx``) are never returned by any indexer; ``profile_id``
    enforces the admin's per-profile allowlist. All three intersect — a user can only
    ever search within what the admin allows the profile, and within the admin's
    ``INDEXER_CATEGORIES`` base restriction.

    ``year`` and ``aka`` (comma-separated alternative titles) tune **relevance
    only** — they are *not* sent to the indexer. The show-detail page passes them
    so the year can rank releases without being baked into the indexer query
    (which would drop anime/TV releases that carry no year), and so a result under
    an alias (e.g. an anime's romaji name) scores against that alias too."""
    if not q.strip():
        return JSONResponse({"results": [], "groups": []})
    akas = [a.strip() for a in (aka or "").split(",") if a.strip()]
    year_hint = year or None

    lib = await get_library()
    cats_override = lib.get("settings", {}).get("admin_overrides", {}).get("indexer_categories")
    cats = (cats_override if cats_override is not None else settings.indexer_categories).strip()
    # Admin base restriction ∩ the user's category-picker selection → Category[] filter.
    cat_filter = _resolve_search_categories(cats, categories)
    if cat_filter == []:
        # Explicit empty selection (user unticked every category, or it's disjoint
        # from the admin restriction) — nothing to search, don't query everything.
        return JSONResponse({"results": [], "groups": []})
    params: dict = {"apikey": settings.indexer_api_key, "Query": q}
    if cat_filter:
        params["Category[]"] = cat_filter

    # Query each configured indexer *independently and concurrently* rather than via
    # Jackett's aggregate /indexers/all/results. The aggregate waits for the slowest
    # indexer, so a single hung/broken one would blow our client timeout and discard
    # ALL results — including the good ones. Per-indexer, a failing one only loses its
    # own results (bounded by its own short timeout) and we still return the rest.
    configured = await _list_configured_indexers()

    if configured is None:
        # Couldn't enumerate (Jackett auth/list failure) — fall back to the aggregate
        # endpoint so search still works, just without per-indexer isolation (and
        # without per-indexer filtering — best effort; the picker just won't apply).
        try:
            async with httpx.AsyncClient(timeout=20.0) as c:
                r = await c.get(
                    f"{settings.indexer_url}/api/v2.0/indexers/all/results",
                    params=params,
                )
            data = r.json()
        except Exception as e:
            raise HTTPException(502, f"Indexer unreachable: {e}")
        await _record_indexer_health(data.get("Indexers", []))
        shaped = _shape_search_results(data.get("Results", []), 10000)
        return JSONResponse({"results": shaped[:limit],
                             "groups": _group_search_results(shaped, q, akas, year_hint)})

    # Profile allowlist (admin-enforced) ∩ user selection (UI-chosen subset).
    allowed = _profile_allowed_indexers(lib, profile_id or "")
    if allowed is not None:
        configured = [ix for ix in configured if ix["id"] in allowed]
    if indexers is not None:
        sel = {s.strip() for s in indexers.split(",") if s.strip()}
        configured = [ix for ix in configured if ix["id"] in sel]
    if not configured:
        # Profile blocks every indexer, or the selection is empty/disjoint — nothing
        # to query, so don't fall through to the aggregate (which queries them all).
        return JSONResponse({"results": [], "groups": []})

    indexers = configured
    PER_INDEXER_TIMEOUT = 12.0

    async def _query_one(ix: dict) -> tuple:
        ixid, name = ix["id"], ix["name"]
        try:
            async with httpx.AsyncClient(timeout=PER_INDEXER_TIMEOUT) as c:
                r = await c.get(
                    f"{settings.indexer_url}/api/v2.0/indexers/{ixid}/results",
                    params=params,
                )
            if r.status_code >= 300:
                return [], {"id": ixid, "name": name, "ok": False, "error": f"HTTP {r.status_code}", "results": 0}
            d = r.json()
            res = d.get("Results", []) or []
            # A single-indexer query echoes that indexer's own error in its block.
            blk = (d.get("Indexers") or [{}])
            err = (blk[0].get("Error") or "").strip() if blk else ""
            return res, {"id": ixid, "name": name, "ok": not err, "error": err, "results": len(res)}
        except Exception as e:
            return [], {"id": ixid, "name": name, "ok": False, "error": str(e)[:200], "results": 0}

    pairs = await asyncio.gather(*[_query_one(ix) for ix in indexers])
    items: list = []
    health: list = []
    for res, h in pairs:
        items.extend(res)
        health.append(h)

    await _apply_indexer_health(health)

    # Only error out when *every* indexer failed — otherwise show whatever came back.
    if health and all(not h["ok"] for h in health):
        raise HTTPException(502, "All indexers failed to respond. Check Jackett / your VPN.")

    shaped = _shape_search_results(items, 10000)
    return JSONResponse({"results": shaped[:limit],
                         "groups": _group_search_results(shaped, q, akas, year_hint)})


@app.get("/api/search/indexers")
async def search_indexers(profile_id: str = "") -> JSONResponse:
    """Indexers this profile may search, each with caps-derived content types, for the
    search **Sources** picker. Honors the per-profile allowlist (admin Profile PINs
    tab); an unrestricted profile sees every configured indexer."""
    full = await _configured_indexers_full()
    if full is None:
        return JSONResponse({"indexers": []})
    allowed = _profile_allowed_indexers(await get_library(), profile_id)
    if allowed is not None:
        full = [ix for ix in full if ix["id"] in allowed]
    return JSONResponse({"indexers": full})


@app.post("/api/stream/prepare")
async def stream_prepare(req: StreamPrepareReq) -> JSONResponse:
    """Add magnet to qBit, wait for file metadata, return file list for the picker UI.

    The caller is responsible for either proceeding with /api/stream (using the returned
    hash) or cancelling with DELETE /api/stream/cancel?hash=... if the user dismisses
    the picker.  The torrent is stored in state.prepare_hash so /api/stop also cleans it up.
    """
    if not state.vpn_secure:
        raise HTTPException(403, "VPN not connected — streaming blocked.")

    # Clean up any previous prepare torrent that the user didn't explicitly cancel
    if state.prepare_hash:
        await qbit_delete(state.prepare_hash, delete_files=True)
        state.prepare_hash = None

    h = await qbit_add_magnet(req.magnet)
    if not h:
        raise HTTPException(500, "qBittorrent rejected the magnet.")

    state.prepare_hash = h

    # Wait for torrent to appear (metadata download)
    for _ in range(30):
        await asyncio.sleep(1)
        if await qbit_info(h):
            break
    else:
        await qbit_delete(h, delete_files=True)
        state.prepare_hash = None
        raise HTTPException(504, "Torrent metadata timed out — check connectivity and try again.")

    # Wait for file list (may need another moment after info appears)
    for _ in range(30):
        files = await qbit_files(h)
        if files:
            break
        await asyncio.sleep(1)
    else:
        await qbit_delete(h, delete_files=True)
        state.prepare_hash = None
        raise HTTPException(504, "Could not fetch file list — torrent may have no seeds.")

    result = [
        {
            "index": f.get("index", i),
            "name": f.get("name", ""),
            "size_bytes": f.get("size", 0),
            "size_human": human_size(f.get("size", 0)),
        }
        for i, f in enumerate(files)
    ]
    return JSONResponse({"hash": h, "files": result})


@app.delete("/api/stream/cancel")
async def stream_cancel(hash: str) -> JSONResponse:
    """Delete a torrent that was added by /stream/prepare but never started streaming."""
    await qbit_delete(hash, delete_files=True)
    if state.prepare_hash == hash:
        state.prepare_hash = None
    return JSONResponse({"ok": True})


@app.post("/api/library/prepare")
async def library_prepare(req: StreamPrepareReq) -> JSONResponse:
    """Fetch the file list for a torrent so the library file-picker UI can show checkboxes.

    Unlike /stream/prepare this does NOT touch state.prepare_hash — the caller is
    responsible for either completing the download (passing the returned hash to
    /api/library/download) or cancelling with DELETE /api/stream/cancel?hash=...
    """
    if not state.vpn_secure:
        raise HTTPException(403, "VPN not connected — download blocked.")

    h = await qbit_add_magnet(req.magnet)
    if not h:
        raise HTTPException(500, "qBittorrent rejected the magnet.")

    for _ in range(30):
        await asyncio.sleep(1)
        if await qbit_info(h):
            break
    else:
        await qbit_delete(h, delete_files=True)
        raise HTTPException(504, "Torrent metadata timed out — check connectivity and try again.")

    for _ in range(30):
        files = await qbit_files(h)
        if files:
            break
        await asyncio.sleep(1)
    else:
        await qbit_delete(h, delete_files=True)
        raise HTTPException(504, "Could not fetch file list — torrent may have no seeds.")

    result = [
        {
            "index": f.get("index", i),
            "name": f.get("name", ""),
            "size_bytes": f.get("size", 0),
            "size_human": human_size(f.get("size", 0)),
        }
        for i, f in enumerate(files)
    ]
    return JSONResponse({"hash": h, "files": result})


@app.post("/api/library/upload")
async def upload_to_library(
    files: list[UploadFile] = File(...),
    title: str = Form(""),
    series: str = Form(""),
    season: int = Form(0),
    episode: int = Form(0),
    save_path: str = Form(""),
) -> JSONResponse:
    """Accept one or more local video files and add them directly to the library."""
    if not files:
        raise HTTPException(400, "No files provided.")
    dest_dir = Path(save_path.strip() or settings.qbit_download_path)
    try:
        dest_dir.mkdir(parents=True, exist_ok=True)
    except Exception as e:
        raise HTTPException(500, f"Cannot create save directory: {e}")

    saved_files = []
    for upload in files:
        filename = Path(upload.filename or "upload").name
        if not filename or Path(filename).suffix.lower() not in VIDEO_EXTS:
            continue
        dest = dest_dir / filename
        stem, suffix = Path(filename).stem, Path(filename).suffix
        counter = 1
        while dest.exists():
            dest = dest_dir / f"{stem}_{counter}{suffix}"
            counter += 1
        with open(dest, "wb") as f:
            while chunk := await upload.read(1024 * 1024):
                f.write(chunk)
        s, ep = parse_season_episode(filename)
        saved_files.append({
            "name": dest.name,
            "path": str(dest),
            "size_bytes": dest.stat().st_size,
            "season": s,
            "episode": ep,
        })

    if not saved_files:
        raise HTTPException(400, "No supported video files were uploaded.")

    item: dict = {
        "id": str(uuid.uuid4()),
        "title": title.strip() or (Path(saved_files[0]["name"]).stem if len(saved_files) == 1 else "Uploaded Files"),
        "series": series.strip(),
        "season": season,
        "episode": episode,
        "files": saved_files,
        "size_bytes": sum(f["size_bytes"] for f in saved_files),
        "added_at": _now_iso(),
        "status": "ready",
        "torrent_hash": "",
        "progress": {},
    }
    lib = await get_library()
    lib["items"].append(item)
    await put_library(lib)
    await broadcast("library_update", {"item_id": item["id"], "status": "ready"})
    return JSONResponse({"ok": True, "item_id": item["id"], "file_count": len(saved_files)})


@app.post("/api/stream")
async def stream_now(req: StreamReq) -> JSONResponse:
    if not state.vpn_secure:
        raise HTTPException(403, "VPN not connected — streaming blocked.")

    if state.stream_task and not state.stream_task.done():
        state.stream_task.cancel()
    if state.library_play_task and not state.library_play_task.done():
        state.library_play_task.cancel()

    # Snapshot what needs cleaning up; the actual qBit delete runs in the
    # background so we can flip UI state to "buffering" and return immediately.
    prior_active = state.active_hash if not state.library_item_id else None
    prior_prepare = None
    if state.prepare_hash and state.prepare_hash != req.torrent_hash:
        prior_prepare = state.prepare_hash
        state.prepare_hash = None
    elif req.torrent_hash and state.prepare_hash == req.torrent_hash:
        state.prepare_hash = None

    state.active_hash = None
    state.active_file = None
    state.library_item_id = None
    state.library_profile_id = None
    state.library_profile_name = ""
    state.library_profile_color = ""
    state.library_item_file_count = 0
    state.library_playlist = []
    state.library_shuffle_order = []
    state.library_series_map = {}
    state.library_series_order = []
    state.library_current_file = None
    state.resume_offer = None

    if prior_active or prior_prepare:
        async def _cleanup_prior(active: Optional[str], prepare: Optional[str]) -> None:
            try:
                if active:
                    await qbit_delete(active)
                if prepare:
                    await qbit_delete(prepare, delete_files=True)
            except Exception:
                pass
        asyncio.create_task(_cleanup_prior(prior_active, prior_prepare))

    state.stream_task = asyncio.create_task(
        stream_pipeline(req.magnet, req.title, req.file_index, req.torrent_hash)
    )
    return JSONResponse({"ok": True}, status_code=202)


class SaveToLibraryReq(BaseModel):
    title: str = ""
    series: str = ""
    season: int = 0
    episode: int = 0
    save_path: str = ""


@app.post("/api/stream/save-to-library")
async def save_stream_to_library(req: SaveToLibraryReq) -> JSONResponse:
    """Adopt the currently streaming torrent into the persistent library.

    Restores all file priorities to 1 so the full torrent continues downloading,
    then creates a library entry and sets state.library_item_id so /api/stop
    will no longer auto-delete the torrent.
    """
    if not state.active_hash:
        raise HTTPException(400, "No active stream.")
    if state.library_item_id:
        raise HTTPException(400, "Stream is already saved to library.")

    h = state.active_hash

    # Restore all file priorities (streaming mode may have skipped some)
    all_files = await qbit_files(h)
    if all_files:
        all_ids = [f.get("index", i) for i, f in enumerate(all_files)]
        await qbit_set_file_priority(h, all_ids, 1)

    info = await qbit_info(h)
    save_path = req.save_path.strip() or (info.get("save_path") if info else None) or settings.qbit_download_path
    files = build_file_list(all_files, save_path) if all_files else []

    item: dict = {
        "id": str(uuid.uuid4()),
        "title": req.title.strip() or state.active_title or "Unknown",
        "series": req.series,
        "season": req.season,
        "episode": req.episode,
        "files": files,
        "size_bytes": info.get("size", 0) if info else 0,
        "added_at": _now_iso(),
        "status": "downloading",
        "torrent_hash": h,
        "progress": {},
    }

    lib = await get_library()
    lib["items"].append(item)
    await put_library(lib)
    state.downloading_count += 1
    state.library_item_id = item["id"]  # prevents auto-delete on stop

    await broadcast("library_update", {"item_id": item["id"], "status": "downloading"})
    return JSONResponse({"ok": True, "item_id": item["id"],
                         "default_save_path": settings.qbit_download_path})


# ── YouTube on TV ───────────────────────────────────────────────────────────
# VLC 3.0's bundled youtube.lua is perpetually broken (it "plays" the watch page
# for a few seconds, never resolves a title/length, then stops — see GOTCHAS).
# Instead we play YouTube in a Chrome kiosk window on the host display (the TV)
# via the YouTube IFrame Player API on our own /tv page, and drive it remotely
# from the dashboard: dashboard → POST /api/youtube/control → SSE `yt_command`
# → /tv page → IFrame API. The /tv page reports playback back via
# /api/youtube/tv-state, which we mirror onto the reused vlc_time/duration/volume
# fields so the existing footer + fullscreen controls render it unchanged.

_YT_ID_RE = re.compile(
    r"(?:youtu\.be/|youtube\.com/(?:watch\?(?:.*&)?v=|embed/|shorts/|live/|v/))"
    r"([0-9A-Za-z_-]{11})"
)


def _extract_youtube_id(url: str) -> Optional[str]:
    """Pull the 11-char video id from any common YouTube URL form.

    Accepts watch?v=, youtu.be/, /shorts/, /embed/, /live/, or a bare 11-char id.
    Returns None if nothing that looks like a video id is present.
    """
    if not url:
        return None
    url = url.strip()
    m = _YT_ID_RE.search(url)
    if m:
        return m.group(1)
    # Bare id pasted directly (e.g. "dQw4w9WgXcQ")
    if re.fullmatch(r"[0-9A-Za-z_-]{11}", url):
        return url
    return None


def _windows_chrome_from_registry() -> list[str]:
    """Resolve browser exes from the Windows `App Paths` registry keys.

    This is the most reliable discovery on Windows — it finds Chrome/Edge/Brave
    wherever they were installed, including per-user installs under
    %LOCALAPPDATA% that the hard-coded Program Files paths miss. Checked for both
    HKLM (machine-wide) and HKCU (per-user)."""
    found: list[str] = []
    try:
        import winreg  # type: ignore[import-not-found]
    except Exception:
        return found
    subkey_root = r"SOFTWARE\Microsoft\Windows\CurrentVersion\App Paths"
    for exe in ("chrome.exe", "msedge.exe", "brave.exe", "chromium.exe"):
        for hive in (winreg.HKEY_CURRENT_USER, winreg.HKEY_LOCAL_MACHINE):
            try:
                with winreg.OpenKey(hive, subkey_root + "\\" + exe) as k:
                    val, _ = winreg.QueryValueEx(k, None)  # default value = full path
                    if val and Path(val).exists():
                        found.append(val)
            except (FileNotFoundError, OSError):
                continue
    return found


def _find_chrome() -> Optional[str]:
    """Locate a Chromium-family browser binary for the kiosk window.

    Windows is the primary target, so it gets the widest net: an explicit
    `_CHROME_BIN` override, the `App Paths` registry, per-user %LOCALAPPDATA%
    installs, both Program Files trees, and PATH — for Chrome, Edge, Brave and
    Chromium. Edge is preinstalled on Windows 10/11, so this should essentially
    always resolve there."""
    saved = os.environ.get("_CHROME_BIN")
    if saved and Path(saved).exists():
        return saved

    system = platform.system()
    candidates: list[str] = []

    if system == "Windows":
        # Registry first — handles per-user installs and non-default locations.
        candidates.extend(_windows_chrome_from_registry())
        local = os.environ.get("LOCALAPPDATA", "")
        pf = os.environ.get("ProgramFiles", r"C:\Program Files")
        pfx86 = os.environ.get("ProgramFiles(x86)", r"C:\Program Files (x86)")
        rel = [
            (r"Google\Chrome\Application\chrome.exe"),
            (r"Microsoft\Edge\Application\msedge.exe"),
            (r"BraveSoftware\Brave-Browser\Application\brave.exe"),
            (r"Chromium\Application\chrome.exe"),
        ]
        roots = [r for r in (pf, pfx86, local) if r]
        for root in roots:
            for r in rel:
                candidates.append(str(Path(root) / r))
        # PATH fallbacks (e.g. choco/scoop shims).
        candidates += ["chrome.exe", "msedge.exe", "brave.exe", "chrome", "msedge"]
    elif system == "Darwin":
        candidates = [
            "/Applications/Google Chrome.app/Contents/MacOS/Google Chrome",
            "/Applications/Microsoft Edge.app/Contents/MacOS/Microsoft Edge",
            "/Applications/Brave Browser.app/Contents/MacOS/Brave Browser",
            "/Applications/Chromium.app/Contents/MacOS/Chromium",
        ]
    else:  # Linux / other
        candidates = [
            "google-chrome", "google-chrome-stable", "chromium", "chromium-browser",
            "microsoft-edge", "microsoft-edge-stable", "brave-browser",
            "/usr/bin/google-chrome", "/usr/bin/chromium", "/usr/bin/microsoft-edge",
            "/snap/bin/chromium",
        ]

    for c in candidates:
        # A bare command name (no separator) → resolve via PATH; otherwise treat
        # as a literal path and test existence.
        has_sep = (os.path.sep in c) or bool(os.path.altsep and os.path.altsep in c)
        if has_sep:
            if Path(c).exists():
                log.info("YouTube TV: using browser %s", c)
                return c
        else:
            resolved = shutil.which(c)
            if resolved:
                log.info("YouTube TV: using browser %s (from PATH: %s)", resolved, c)
                return resolved

    log.warning(
        "YouTube TV: no Chromium-family browser found on %s. Tried registry + %d "
        "candidate path(s). Install Chrome/Edge or set _CHROME_BIN in .env.",
        system, len(candidates),
    )
    return None


def _launch_kiosk_browser(url: str, profile_dir: Path, label: str) -> bool:
    """Open `url` in a fullscreen Chrome kiosk on the host display.

    Uses an isolated --user-data-dir so we never disturb the user's Chrome and
    can identify/kill exactly this instance later (match `profile_dir` in the
    cmdline). --autoplay-policy lets media start with sound without a user
    gesture. Returns False if no Chrome/Edge was found or the spawn failed.
    """
    chrome = _find_chrome()
    if not chrome:
        return False
    args = [
        chrome,
        f"--user-data-dir={profile_dir}",
        "--no-first-run",
        "--no-default-browser-check",
        # Suppress the Edge / Chrome welcome / signin / promo modals that can
        # block a fresh --user-data-dir profile from rendering the requested URL.
        "--disable-features=msImplicitSignin,SigninInterceptBubbleV2,DesktopPWAsRunOnOsLogin",
        "--disable-fre",                # Edge first-run experience
        "--disable-default-apps",
        "--disable-component-update",
        "--noerrdialogs",               # no crash dialog if a prior kiosk crashed
        "--autoplay-policy=no-user-gesture-required",
        "--kiosk",
        f"--app={url}",
    ]
    kw: dict = {"stdout": subprocess.DEVNULL, "stderr": subprocess.DEVNULL}
    if platform.system() == "Windows":
        kw["creationflags"] = subprocess.DETACHED_PROCESS | subprocess.CREATE_NEW_PROCESS_GROUP  # type: ignore[attr-defined]
    else:
        kw["start_new_session"] = True
    try:
        subprocess.Popen(args, **kw)
        log.info("%s: launched kiosk (%s) at %s", label, Path(chrome).name, url)
        return True
    except Exception as e:
        log.warning("%s: kiosk launch failed (%s): %s", label, chrome, e)
        return False


def _launch_tv_browser(video_id: str) -> bool:
    """Open the /tv player page in a fullscreen Chrome kiosk on the host display.

    127.0.0.1, NOT localhost. On Windows the hosts file resolves localhost to
    both `::1` and `127.0.0.1`, and Chromium prefers IPv6 first; uvicorn binds
    `0.0.0.0` (IPv4 only), so the kiosk hits ECONNREFUSED on `::1` and may
    show an error page or hang long enough that the heartbeat watchdog fires
    before the page ever loads. Pinning v4 sidesteps all of that. See
    docs/GOTCHAS.md.
    """
    return _launch_kiosk_browser(
        f"http://127.0.0.1/tv?v={video_id}", TV_CHROME_PROFILE, "YouTube TV")


def _kill_tv_browser() -> None:
    """Kill the dedicated kiosk Chrome (matched by our --user-data-dir) — and
    only that instance, leaving the user's normal Chrome windows alone."""
    needle = str(TV_CHROME_PROFILE)
    for p in psutil.process_iter(["pid", "cmdline"]):
        try:
            cmdline = p.info.get("cmdline") or []
            if any(needle in str(a) for a in cmdline):
                p.kill()
        except Exception:
            pass


# ── OS system volume ─────────────────────────────────────────────────────────
# YouTube plays through the host's normal audio mixer (the IFrame player has
# no direct VLC-style amp), so the dashboard volume slider must drive the OS
# system volume during YouTube playback — otherwise every video plays at
# whatever volume the host happened to be at (often max). On Stop we restore
# the OS volume to a configured "expected max" (`settings.system_volume_default`)
# so headphones at 100 % don't blow eardrums after a movie session.

# Last human-readable failure reason from the OS-volume path, surfaced in API
# responses (e.g. the YouTube volume endpoint) so the operator can act. On
# Windows it's set from the helper child's error reply; on POSIX it stays a
# generic message (pactl/osascript failures are rare).
_PYCAW_LAST_ERROR: Optional[str] = None

# ── Windows OS-mixer volume: isolated in a CHILD PROCESS ─────────────────────
# Driving the Windows endpoint volume via pycaw/COM *in-process* crashed the
# whole server: after a handful of rapid calls the process vanished with a
# native access violation and NO Python traceback. It crashed even when pinned
# to a single COM-initialized thread that never CoUninitialized. A native crash
# can only be contained by an OS process boundary, so all Windows volume ops now
# run in `winvol_helper.py` as a long-lived child: if it ever crashes, only the
# child dies and we respawn it — the server stays up. See docs/GOTCHAS.md.
WINVOL_HELPER = Path(__file__).parent / "winvol_helper.py"
_winvol_proc: Optional[subprocess.Popen] = None   # the live helper child
_winvol_lock: Optional[asyncio.Lock] = None       # serializes round-trips


def _winvol_roundtrip_sync(req: dict) -> dict:
    """Send one request to the helper child (spawning/respawning as needed) and
    return its parsed reply. Runs in a worker thread (blocking pipe IO). Raises
    on IO failure / dead child so the async caller can recover."""
    global _winvol_proc
    if _winvol_proc is None or _winvol_proc.poll() is not None:
        flags = getattr(subprocess, "CREATE_NO_WINDOW", 0) if platform.system() == "Windows" else 0
        _winvol_proc = subprocess.Popen(
            [sys.executable, str(WINVOL_HELPER)],
            stdin=subprocess.PIPE, stdout=subprocess.PIPE, stderr=subprocess.DEVNULL,
            text=True, bufsize=1, creationflags=flags,
        )
    proc = _winvol_proc
    try:
        proc.stdin.write(json.dumps(req) + "\n")
        proc.stdin.flush()
        line = proc.stdout.readline()
        if not line:
            raise RuntimeError("helper closed its pipe (child exited)")
        return json.loads(line.strip())
    except Exception:
        # Force a clean child on the next call.
        try:
            proc.kill()
        except Exception:
            pass
        _winvol_proc = None
        raise


async def _winvol_request(req: dict) -> Optional[dict]:
    """Async wrapper around the helper round-trip: serialized, time-bounded, and
    self-healing. Returns the reply dict, or None on failure (sets _PYCAW_LAST_ERROR)."""
    global _winvol_lock, _winvol_proc, _PYCAW_LAST_ERROR
    if _winvol_lock is None:
        _winvol_lock = asyncio.Lock()
    async with _winvol_lock:
        try:
            # First call pays the child's comtypes/pycaw import + CoInitialize
            # (a few hundred ms); later calls are fast. 5 s covers a cold start.
            resp = await asyncio.wait_for(
                asyncio.to_thread(_winvol_roundtrip_sync, req), timeout=5,
            )
        except Exception as e:
            # Timeout or IO error — kill the (possibly wedged) child so the next
            # call respawns a clean one, and remember why for the API surface.
            p = _winvol_proc
            if p is not None:
                try:
                    p.kill()
                except Exception:
                    pass
                _winvol_proc = None
            _PYCAW_LAST_ERROR = f"Windows volume helper failed: {type(e).__name__}: {e}"
            log.warning("%s", _PYCAW_LAST_ERROR)
            return None
        if resp and not resp.get("ok"):
            _PYCAW_LAST_ERROR = resp.get("error") or "Windows volume helper returned an error."
            log.warning("System volume: %s", _PYCAW_LAST_ERROR)
        return resp


def _set_system_volume_sync(pct: int) -> bool:
    """POSIX system-volume set (osascript / pactl / amixer). Windows is handled
    out-of-process via the helper child — see set_system_volume."""
    pct = max(0, min(100, int(pct)))
    sys_name = platform.system()
    try:
        if sys_name == "Darwin":
            subprocess.run(
                ["osascript", "-e", f"set volume output volume {pct}"],
                check=False, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL,
                timeout=3,
            )
            return True
        if sys_name == "Linux":
            if shutil.which("pactl"):
                subprocess.run(
                    ["pactl", "set-sink-mute", "@DEFAULT_SINK@", "0"],
                    check=False, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL,
                    timeout=3,
                )
                subprocess.run(
                    ["pactl", "set-sink-volume", "@DEFAULT_SINK@", f"{pct}%"],
                    check=False, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL,
                    timeout=3,
                )
                return True
            if shutil.which("amixer"):
                subprocess.run(
                    ["amixer", "-q", "set", "Master", f"{pct}%", "unmute"],
                    check=False, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL,
                    timeout=3,
                )
                return True
    except Exception as e:
        log.warning("System volume set failed (%s, %d%%): %s", sys_name, pct, e)
    return False


def _get_system_volume_sync() -> Optional[int]:
    """POSIX system-volume read. Windows is handled out-of-process — see
    get_system_volume."""
    sys_name = platform.system()
    try:
        if sys_name == "Darwin":
            r = subprocess.run(
                ["osascript", "-e", "output volume of (get volume settings)"],
                capture_output=True, text=True, timeout=3,
            )
            if r.returncode == 0:
                return max(0, min(100, int(r.stdout.strip() or 0)))
        if sys_name == "Linux":
            if shutil.which("pactl"):
                r = subprocess.run(
                    ["pactl", "get-sink-volume", "@DEFAULT_SINK@"],
                    capture_output=True, text=True, timeout=3,
                )
                if r.returncode == 0:
                    m = re.search(r"(\d+)%", r.stdout)
                    if m:
                        return max(0, min(100, int(m.group(1))))
    except Exception:
        pass
    return None


async def set_system_volume(pct: int) -> bool:
    pct = max(0, min(100, int(pct)))
    if platform.system() == "Windows":
        resp = await _winvol_request({"op": "set", "pct": pct})
        ok = bool(resp and resp.get("ok"))
    else:
        ok = await asyncio.to_thread(_set_system_volume_sync, pct)
    if ok:
        # Every legitimate OS-volume write records itself so remote_volume_guard
        # can tell "we did this" apart from a remote volume press it must revert.
        state.host_volume_expected = pct
    return ok


async def get_system_volume() -> Optional[int]:
    if platform.system() == "Windows":
        resp = await _winvol_request({"op": "get"})
        if resp and resp.get("ok"):
            return resp.get("value")
        return None
    return await asyncio.to_thread(_get_system_volume_sync)


async def _system_volume_default() -> int:
    """Configured system volume to restore when YouTube stops (0-100)."""
    lib = await get_library()
    raw = lib.get("settings", {}).get("system_volume_default", 70)
    return max(0, min(100, int(raw)))


async def _youtube_start_volume() -> int:
    """Configured OS volume to pre-set BEFORE a YouTube video starts (0-100).

    Sensible default 30 — quieter than restore-on-stop because the user is about
    to actively start a video and can turn up from there if they want, but a
    "max-by-default" first frame on a movie at 100 % blows out the room. Stored
    in `library.json → settings.youtube_start_volume`."""
    lib = await get_library()
    raw = lib.get("settings", {}).get("youtube_start_volume", 30)
    return max(0, min(100, int(raw)))


# Window title set by static/tv.html — used to find the kiosk window on Windows
# and pull it to the foreground (Chrome is multi-process, so PID matching is
# unreliable; the --app window's title is the page <title>). Keep both in sync.
_TV_WINDOW_MARKER = "StreamLink TV Player"


def _find_tv_browser_hwnds_windows(marker: str = None) -> list:
    """Visible top-level windows whose title marks them as our kiosk page.
    `marker` defaults to the YouTube kiosk; the TV UI kiosk passes its own."""
    if marker is None:
        marker = _TV_WINDOW_MARKER
    try:
        import ctypes
        from ctypes import wintypes
        user32 = ctypes.windll.user32
        found: list = []
        EnumWindowsProc = ctypes.WINFUNCTYPE(ctypes.c_bool, wintypes.HWND, wintypes.LPARAM)

        def _cb(hwnd, _):
            if user32.IsWindowVisible(hwnd):
                n = user32.GetWindowTextLengthW(hwnd)
                if n:
                    buf = ctypes.create_unicode_buffer(n + 1)
                    user32.GetWindowTextW(hwnd, buf, n + 1)
                    if marker in buf.value:
                        found.append(hwnd)
            return True

        cb = EnumWindowsProc(_cb)   # keep ref alive — ctypes GC pitfall
        user32.EnumWindows(cb, 0)
        return found
    except Exception:
        return []


def _focus_tv_browser_windows(marker: str = None) -> bool:
    """Pull a kiosk window to the foreground past focus-stealing prevention.

    Same cocktail as `_vlc_focus_windows` (zero foreground-lock timeout +
    synthetic ALT + AttachThreadInput + SetForegroundWindow + clear taskbar
    flash). Returns True once a kiosk window exists (so the caller can stop
    retrying). `marker` picks which kiosk (default: the YouTube player)."""
    hwnds = _find_tv_browser_hwnds_windows(marker)
    if not hwnds:
        return False
    hwnd = hwnds[0]
    try:
        import ctypes
        from ctypes import wintypes
        user32 = ctypes.windll.user32
        kernel32 = ctypes.windll.kernel32

        SPI_SETFOREGROUNDLOCKTIMEOUT = 0x2001
        SPIF_SENDCHANGE = 0x02
        user32.SystemParametersInfoW(SPI_SETFOREGROUNDLOCKTIMEOUT, 0, 0, SPIF_SENDCHANGE)

        VK_MENU = 0x12
        KEYEVENTF_KEYUP = 0x0002
        user32.keybd_event(VK_MENU, 0, 0, 0)
        user32.keybd_event(VK_MENU, 0, KEYEVENTF_KEYUP, 0)

        fg_thread = user32.GetWindowThreadProcessId(user32.GetForegroundWindow(), None)
        my_thread = kernel32.GetCurrentThreadId()
        if fg_thread != my_thread:
            user32.AttachThreadInput(my_thread, fg_thread, True)
        user32.ShowWindow(hwnd, 9)   # SW_RESTORE
        user32.BringWindowToTop(hwnd)
        user32.SetForegroundWindow(hwnd)
        if fg_thread != my_thread:
            user32.AttachThreadInput(my_thread, fg_thread, False)

        class FLASHWINFO(ctypes.Structure):
            _fields_ = [
                ("cbSize", ctypes.c_uint), ("hwnd", wintypes.HWND),
                ("dwFlags", wintypes.DWORD), ("uCount", wintypes.UINT),
                ("dwTimeout", wintypes.DWORD),
            ]
        FLASHW_STOP = 0x00000000
        for h in hwnds:
            info = FLASHWINFO(ctypes.sizeof(FLASHWINFO), h, FLASHW_STOP, 0, 0)
            user32.FlashWindowEx(ctypes.byref(info))
    except Exception:
        pass
    return True


async def _bring_tv_to_front(video_id: str) -> None:
    """Get VLC out of the way and pull the kiosk window to the foreground.

    On Windows the server isn't the foreground process, so the browser's window
    is blocked from taking focus (it just flashes in the taskbar) and the
    still-visible VLC window keeps the screen — the user has to click the taskbar
    icon. We minimize VLC, then poll for the kiosk window and force it forward
    for a few seconds (it takes ~1–2 s to appear). Best-effort; never raises."""
    await vlc_minimize()
    if platform.system() != "Windows":
        return  # macOS/Linux foreground the --app kiosk on their own
    loop = asyncio.get_running_loop()
    reinforced = 0
    for delay in [0.4] * 6 + [0.8] * 5 + [1.5] * 3:   # ~10 s, slowing cadence
        if not state.youtube_active or state.youtube_video_id != video_id:
            return  # superseded (stopped / different video)
        try:
            got = await loop.run_in_executor(None, _focus_tv_browser_windows)
        except Exception:
            got = False
        if got:
            reinforced += 1
            if reinforced >= 3:   # found + two reinforcing passes → settle
                return
        await asyncio.sleep(delay)


# ── TV UI (Firestick-style dashboard kiosk on the host display) ──────────────
# The dashboard itself, in a fullscreen Chrome kiosk at `/?tv=1`, driven from
# the couch with the air-mouse remote (pointer + buttons). The host display
# cycles between three surfaces:
#
#   idle background video  ──any remote button──▶  TV UI (dashboard kiosk)
#   TV UI ──idle `tv_ui_idle_secs` w/ no input──▶  background video
#   TV UI ──user plays something──────────────▶  VLC / YouTube fullscreen
#   playback ──🏠 Home button────────────────▶  stop + TV UI
#   playback ──⏻ Power button────────────────▶  stop + background video
#   background video ⇄ TV UI ──⏻ Power──────▶  toggle between the two
#
# `state.tv_ui_active` means "the kiosk should hold the screen": every VLC
# focus assertion (vlc_focus_and_fullscreen, the background-video loop) stands
# down while it's set, exactly like the YouTube kiosk. It's cleared the moment
# real content plays (`vlc("in_play")` / youtube_play) so those paths regain
# the screen. Wake events come from remote_input.py's global input listener
# (`_tv_input_event`, called on its hook threads). See docs/REMOTE.md.

# index.html sets document.title to this when loaded with ?tv=1 — it's how the
# Windows focus code finds the kiosk window. Must NOT contain (or be contained
# by) the YouTube marker "StreamLink TV Player".
_TVUI_WINDOW_MARKER = "StreamLink TV Dashboard"

TV_UI_MIN_IDLE_SECS = 15   # floor for the configurable idle hand-back


def _tvui_kiosk_alive() -> bool:
    """True if the TV UI kiosk Chrome is running (matched by --user-data-dir).
    Blocking psutil scan — call via asyncio.to_thread."""
    needle = str(TVUI_CHROME_PROFILE)
    for p in psutil.process_iter(["pid", "cmdline"]):
        try:
            if any(needle in str(a) for a in (p.info.get("cmdline") or [])):
                return True
        except Exception:
            pass
    return False


def _launch_tvui_browser() -> bool:
    """Spawn the dashboard kiosk (`/?tv=1`). Blocking — call via to_thread."""
    return _launch_kiosk_browser("http://127.0.0.1/?tv=1", TVUI_CHROME_PROFILE, "TV UI")


async def _bring_tvui_to_front() -> None:
    """Get VLC out of the way and pull the dashboard kiosk forward.

    Mirrors `_bring_tv_to_front` (the YouTube variant): minimize VLC, then on
    Windows force the kiosk window past focus-stealing prevention for a few
    seconds (a fresh launch takes ~1–2 s to create its window). Aborts if the
    TV UI loses the screen mid-loop (playback started / idle hand-back)."""
    await vlc_minimize()
    system = platform.system()
    if system != "Windows":
        # Linux: wmctrl by window title, best-effort. macOS: the freshly
        # launched --app kiosk fronts itself; an existing one can't be raised
        # reliably without scripting the specific browser — dev-only gap.
        if system == "Linux" and shutil.which("wmctrl"):
            try:
                proc = await asyncio.create_subprocess_exec(
                    "wmctrl", "-a", _TVUI_WINDOW_MARKER,
                    stdout=asyncio.subprocess.DEVNULL,
                    stderr=asyncio.subprocess.DEVNULL,
                )
                await proc.wait()
            except Exception:
                pass
        return
    loop = asyncio.get_running_loop()
    reinforced = 0
    for delay in [0.4] * 6 + [0.8] * 5 + [1.5] * 3:   # ~10 s, slowing cadence
        if not state.tv_ui_active:
            return  # superseded (playback took over / hidden again)
        try:
            got = await loop.run_in_executor(
                None, _focus_tv_browser_windows, _TVUI_WINDOW_MARKER)
        except Exception:
            got = False
        if got:
            reinforced += 1
            if reinforced >= 3:   # found + two reinforcing passes → settle
                return
        await asyncio.sleep(delay)


async def _tv_ui_show(reason: str) -> None:
    """Put the dashboard kiosk on the screen (launching it if needed)."""
    if not settings.tv_ui or state.tv_ui_active or window_mgmt_paused():
        return
    state.tv_ui_active = True
    state.tv_input_last = time.time()
    log.info("TV UI: showing dashboard kiosk (%s)", reason)
    # Silence the idle background video while the UI is up — it keeps its
    # playlist position, background_playing stays True, and the paused state
    # keeps background_video_loop from restarting it underneath the kiosk.
    if state.background_playing:
        await vlc("pl_forcepause")
    alive = await asyncio.to_thread(_tvui_kiosk_alive)
    if not alive:
        ok = await asyncio.to_thread(_launch_tvui_browser)
        if not ok:
            log.warning("TV UI: no Chrome/Edge found — cannot show the dashboard kiosk")
            state.tv_ui_active = False
            if state.background_playing:
                await vlc("pl_forceresume")
            return
    asyncio.create_task(_bring_tvui_to_front())


async def _tv_ui_hide(reason: str) -> None:
    """Hand the screen back to whatever owns it (background video / YouTube).
    The kiosk window is left running behind, so the next wake is instant."""
    if not state.tv_ui_active:
        return
    state.tv_ui_active = False
    log.info("TV UI: hiding dashboard kiosk (%s)", reason)
    if state.youtube_active:
        asyncio.create_task(_bring_tv_to_front(state.youtube_video_id or ""))
        return
    if state.background_playing:
        await vlc("pl_forceresume")
    asyncio.create_task(vlc_focus_and_fullscreen())


# Debounce for the click→⏯ path below (remote_input debounces key actions,
# but raw clicks arrive straight off the activity feed).
_tv_click_pause_last: float = 0.0


def _tv_input_event(kind: str) -> None:
    """Any HID input, reported by remote_input.py FROM ITS HOOK THREADS.

    kind ∈ {key, click, move, media}. Keep this to plain attribute reads plus
    (at most) a run_coroutine_threadsafe — on Windows part of it runs on the
    low-level hook thread, which has a hard OS time budget.

    Rules: everything refreshes the idle timer; only a key or click *wakes*
    the UI, and only while nothing is playing (during playback the media keys
    control VLC and the 🏠 Home key is the deliberate way to the dashboard —
    a stray key must not pop the UI over a movie). Pointer motion never wakes
    (gyro drift would light the TV up at night). A **click during VLC
    playback** is the remote's OK button in pointer mode landing on the
    fullscreen video — treat it as ⏯ (YouTube excluded: the IFrame player
    already toggles on its own clicks; VLC doesn't act on single clicks, so
    there's no double-toggle)."""
    global _tv_click_pause_last
    state.tv_input_last = time.time()
    playing = state.youtube_active or state.stream_status in ("playing", "buffering")
    if kind == "click" and playing:
        if (not state.youtube_active and not state.tv_ui_active
                and not window_mgmt_paused()):
            now = time.monotonic()
            if now - _tv_click_pause_last >= 0.4:
                _tv_click_pause_last = now
                loop = _MAIN_LOOP
                if loop is not None:
                    asyncio.run_coroutine_threadsafe(
                        _remote_key_action("playpause"), loop)
        return
    if kind in ("move", "media"):
        return
    if not settings.tv_ui or state.tv_ui_active or window_mgmt_paused():
        return
    if playing:
        return
    loop = _MAIN_LOOP
    if loop is not None:
        asyncio.run_coroutine_threadsafe(_tv_ui_show("input"), loop)


async def _bg_video_ready() -> bool:
    """True when the idle background video is configured, enabled, on disk."""
    try:
        lib = await get_library()
        bg = lib.get("settings", {}).get("background_video") or {}
        p = bg.get("path", "")
        return bool(p and bg.get("enabled", True) and Path(p).exists())
    except Exception:
        return False


async def tv_ui_loop() -> None:
    """Every 5 s: reconcile who owns the host display.

    - Real playback started → the kiosk is no longer the foreground surface;
      just drop the flag (VLC/YouTube already grabbed the screen).
    - No input for `tv_ui_idle_secs` while idle → hand the screen back to the
      background video. If no background video is configured, the dashboard
      stays up — a black VLC window is worse than the UI.
    """
    while True:
        await asyncio.sleep(5)
        try:
            if not settings.tv_ui or not state.tv_ui_active:
                continue
            if window_mgmt_paused():
                continue
            if state.youtube_active or state.stream_status in ("playing", "buffering"):
                # Janitor only: the normal paths already release the claim
                # (vlc() in_play / youtube_play). Require stale input so a
                # just-pressed 🏠 Home (UI shown, stop() still tearing the old
                # playback down) isn't robbed of the screen it just claimed.
                if time.time() - state.tv_input_last > 10:
                    state.tv_ui_active = False
                continue
            idle_for = time.time() - state.tv_input_last
            if idle_for < max(TV_UI_MIN_IDLE_SECS, settings.tv_ui_idle_secs):
                continue
            if not await _bg_video_ready():
                continue
            await _tv_ui_hide(f"idle {int(idle_for)}s")
        except Exception:
            pass


@app.get("/tv", include_in_schema=False)
async def tv_player_page() -> FileResponse:
    """The host-side kiosk page: YouTube IFrame player + SSE command listener."""
    return FileResponse(str(Path(__file__).parent / "static" / "tv.html"))


@app.post("/api/youtube")
async def youtube_play(req: YouTubeReq) -> JSONResponse:
    """Play a YouTube URL on the TV (host browser), remote-controlled from here.

    Not VPN-gated — this is ordinary HTTPS playback in a browser, not P2P.
    """
    video_id = _extract_youtube_id(req.url)
    if not video_id:
        raise HTTPException(400, "Not a recognisable YouTube link.")

    # Cancel any in-flight VLC pipeline so it can't grab the screen mid-launch.
    if state.stream_task and not state.stream_task.done():
        state.stream_task.cancel()
    if state.library_play_task and not state.library_play_task.done():
        state.library_play_task.cancel()

    # Snapshot the current OS volume so we can restore it on Stop if no default
    # is configured. Do this BEFORE we change anything below (so the snapshot is
    # the user's "before" state, not whatever we set later).
    cur_sys_vol = await get_system_volume()
    if cur_sys_vol is not None:
        state.system_volume_before_yt = cur_sys_vol

    # Pre-set the OS mixer to the configured "start" volume BEFORE the kiosk
    # loads the page — once the IFrame player begins producing audio (which can
    # be near-instantaneous after Chrome paints) the system mixer is already at
    # the right level, instead of whatever the OS was at (often max). If the
    # set call fails, we fall back to the user's current OS volume so the
    # dashboard slider isn't out of sync.
    start_vol = await _youtube_start_volume()
    initial_vol = start_vol if await set_system_volume(start_vol) else cur_sys_vol

    # Take over the "now playing" state. Title fills in once the /tv page reports
    # it back via /api/youtube/tv-state; show a placeholder until then.
    state.active_hash = None
    state.active_file = None
    state.library_item_id = None
    state.library_profile_id = None
    state.library_profile_name = ""
    state.library_profile_color = ""
    state.library_item_file_count = 0
    state.library_playlist = []
    state.library_shuffle_order = []
    state.library_series_map = {}
    state.library_series_order = []
    state.library_current_file = None
    state.youtube_active = True
    state.youtube_video_id = video_id
    state.youtube_playback = "buffering"
    # The YouTube kiosk takes the screen from the TV UI dashboard kiosk (its
    # own focus loop must not be gated off, and `_bring_tv_to_front` needs the
    # dashboard's claim released).
    state.tv_ui_active = False
    state.active_title = "YouTube"
    state.vlc_time = 0
    state.vlc_duration = 0
    state.stream_status = "playing"
    # During YouTube the dashboard volume slider drives the *system* volume
    # (0-100), not VLC's 0-200 amp. Initialise to the pre-set "start" volume
    # we just wrote (or the OS's current value if pycaw isn't usable on this
    # host) so the slider doesn't jump when the user first touches it.
    if initial_vol is not None:
        state.vlc_volume = initial_vol

    # Stop VLC + clear any idle background so only the browser shows on the TV.
    await vlc("pl_stop")

    # If the /tv page is already open (recent heartbeat), just hot-swap the video
    # via SSE — smoother than relaunching the whole kiosk. Otherwise launch it;
    # the fresh page reads ?v=<id> and autoplays even if it missed the broadcast.
    page_open = (time.time() - state.youtube_tv_seen_at) < 6.0
    await broadcast("yt_command", {"action": "load", "video_id": video_id})
    if not page_open:
        launch_at = time.time()
        launched = await asyncio.to_thread(_launch_tv_browser, video_id)
        if not launched:
            state.youtube_active = False
            state.youtube_video_id = None
            state.youtube_playback = ""
            state.active_title = None
            state.stream_status = "idle"
            await broadcast("state", state_snapshot())
            raise HTTPException(
                500,
                "No Chrome/Edge/Chromium browser found on the host to play YouTube "
                "on the TV. Install Google Chrome or Microsoft Edge (or set "
                "_CHROME_BIN in .env). See logs/streamlink_app.log for details.",
            )
        # The browser was spawned, but Popen can't tell us it actually came up
        # (locked profile, instant exit, …). The /tv page heartbeats within ~1 s
        # of loading, so if nothing checks in we know the kiosk never rendered —
        # surface that instead of silently dropping back to the idle background.
        asyncio.create_task(_youtube_kiosk_healthcheck(video_id, launch_at))

    # Minimize VLC and pull the kiosk window to the foreground. On Windows the
    # server can't give the new browser window focus (focus-stealing prevention),
    # so without this the kiosk just flashes in the taskbar behind VLC and the
    # user has to click it. Covers both fresh-launch and hot-swap (user may have
    # alt-tabbed away from an already-open kiosk).
    asyncio.create_task(_bring_tv_to_front(video_id))

    # Note: we deliberately do NOT broadcast a `stream_status` event here — the
    # client's stream_status handler phrases playing as "Now playing in VLC".
    # The `state` snapshot below already carries stream_status="playing".
    await broadcast("state", state_snapshot())
    return JSONResponse({"ok": True, "video_id": video_id}, status_code=202)


async def _youtube_kiosk_healthcheck(video_id: str, launch_at: float) -> None:
    """If the freshly-launched kiosk never heartbeats, the browser didn't render
    the /tv page — report a clear error rather than leaving the TV blank."""
    await asyncio.sleep(12)
    # Superseded (stopped, or a different video started) → nothing to check.
    if not state.youtube_active or state.youtube_video_id != video_id:
        return
    if state.youtube_tv_seen_at >= launch_at:
        return  # the page checked in — all good
    log.warning(
        "YouTube TV: kiosk for %s launched but never reported in within 12 s — "
        "the browser likely failed to open the /tv page (locked profile, blocked "
        "network, or session-0 service with no desktop).", video_id,
    )
    state.youtube_active = False
    state.youtube_video_id = None
    state.youtube_playback = ""
    state.active_title = None
    state.stream_status = "idle"
    await broadcast("stream_status", {
        "status": "error",
        "message": "YouTube didn't start on the TV — the browser failed to open. "
                   "See logs/streamlink_app.log.",
    })
    await broadcast("state", state_snapshot())


@app.post("/api/youtube/control")
async def youtube_control(req: YouTubeControlReq) -> JSONResponse:
    """Drive the kiosk player from the dashboard.

    Playback actions (play/pause/seek) are relayed to the `/tv` page over SSE.
    Volume actions are handled **server-side** by setting the host's OS volume
    (the IFrame player has no real amp; its setVolume only scales the audio it
    emits *before* the system mixer), so the dashboard slider behaves like the
    user expects on the TV — and a configured default is restored on Stop.

    action ∈ {playpause, play, pause, seek, seek_to, volume_set, volume_step}.
    """
    if not state.youtube_active:
        raise HTTPException(409, "No YouTube video is playing on the TV.")
    if req.action not in ("playpause", "play", "pause", "seek", "seek_to",
                          "volume_set", "volume_step"):
        raise HTTPException(400, f"Unknown action: {req.action}")

    if req.action in ("volume_set", "volume_step"):
        # Volume slider sends a dashboard value (historically 0-200 for VLC); for
        # YouTube clamp to the OS scale 0-100. For volume_step, read the OS
        # volume so an out-of-sync client doesn't snap us back to a stale value.
        if req.action == "volume_set":
            target = max(0, min(100, int(req.value or 0)))
        else:
            cur = await get_system_volume()
            base = cur if cur is not None else (state.vlc_volume or 50)
            target = max(0, min(100, int(base) + int(req.value or 0)))
        ok = await set_system_volume(target)
        if ok:
            state.vlc_volume = target
            await broadcast("state", state_snapshot())
            return JSONResponse({"ok": True, "volume": target})
        # Failure: surface *why* so the user can act (most often: pycaw not
        # installed on Windows, or the helper child errored). _PYCAW_LAST_ERROR
        # is set from the helper's error reply on Windows; on POSIX we fall back
        # to a generic message since pactl/osascript failures are rare.
        err = _PYCAW_LAST_ERROR if platform.system() == "Windows" else \
            "Couldn't set the host system volume."
        return JSONResponse({"ok": False, "volume": target, "error": err},
                            status_code=503)

    await broadcast("yt_command", {"action": req.action, "value": req.value})
    return JSONResponse({"ok": True})


@app.post("/api/youtube/tv-state")
async def youtube_tv_state(req: YouTubeTvStateReq) -> JSONResponse:
    """Heartbeat + playback report from the /tv page. Mirrors the player's
    position/duration/volume/title onto the reused display fields and rebroadcasts
    so every dashboard reflects the TV instantly."""
    state.youtube_tv_seen_at = time.time()
    if not state.youtube_active:
        # A stale page still beating after Stop — tell it to close itself.
        return JSONResponse({"ok": True, "active": False})

    if req.video_id:
        state.youtube_video_id = req.video_id
    if req.title and req.title.strip():
        state.active_title = req.title.strip()
    if req.time is not None:
        state.vlc_time = int(req.time)
    if req.duration is not None:
        state.vlc_duration = int(req.duration)
    # Intentionally ignore req.volume here. During YouTube the *system mixer* is
    # the real amp — the IFrame `player.getVolume()` only describes the player's
    # pre-mixer gain (which we lock at 100 in tv.html), so reading it back over
    # the heartbeat would just stomp the dashboard's authoritative OS-volume
    # value with 100 every second. /api/youtube/control owns state.vlc_volume.
    if req.playback:
        state.youtube_playback = req.playback
    await broadcast("state", state_snapshot())
    return JSONResponse({"ok": True, "active": True})


@app.post("/api/stop")
async def stop() -> JSONResponse:
    # Cancel any in-flight pipelines first so a buffering stream doesn't race the teardown
    if state.stream_task and not state.stream_task.done():
        state.stream_task.cancel()
    if state.library_play_task and not state.library_play_task.done():
        state.library_play_task.cancel()

    # Snapshot the cleanup targets before clearing state so the background task knows what to do
    active_hash = state.active_hash
    library_item_id = state.library_item_id
    prepare_hash = state.prepare_hash
    was_youtube = state.youtube_active

    # Flush the outgoing episode's final position before we clear state — stopping
    # near the end otherwise leaves it un-completed and resumable (see
    # _finalize_stopped_file). Snapshot the live pos/dur (kept fresh every 2 s by
    # stat_broadcaster) as a consistent pair with the current file.
    fin_profile = state.library_profile_id
    fin_file = state.library_current_file
    fin_pos = float(state.vlc_time or 0)
    fin_dur = float(state.vlc_duration or 0)
    if library_item_id and fin_profile and fin_file:
        asyncio.create_task(_finalize_stopped_file(
            library_item_id, fin_profile, fin_file, fin_pos, fin_dur,
        ))

    # Clear state + broadcast idle immediately — the UI updates before slow qBit/VLC roundtrips run
    state.active_hash = None
    state.active_file = None
    state.active_title = None
    state.stream_status = "idle"
    state.youtube_active = False
    state.youtube_video_id = None
    state.youtube_playback = ""
    state.vlc_time = 0
    state.vlc_duration = 0
    state.library_item_id = None
    state.library_profile_id = None
    state.library_profile_name = ""
    state.library_profile_color = ""
    state.library_item_file_count = 0
    state.library_playlist = []
    state.library_shuffle_order = []
    state.library_series_map = {}
    state.library_series_order = []
    state.library_current_file = None
    state.progress = 0.0
    state.downloaded_mb = 0.0
    state.total_mb = 0.0
    state.dl_speed_bps = 0
    state.ul_speed_bps = 0
    state.skip_offer = None
    state.skip_offer_file = None
    state.resume_offer = None
    state.prepare_hash = None
    await _cancel_skip_countdown()

    # Tell the TV page to pause + close itself, then hard-kill the kiosk browser
    # so a YouTube play doesn't linger on the TV after Stop.
    if was_youtube:
        await broadcast("yt_command", {"action": "close"})

    await broadcast("stream_status", {"status": "idle", "message": "Stopped."})
    await broadcast("state", state_snapshot())

    # Snapshot the system-volume restore target *before* clearing state — we
    # need the pre-stop snapshot to fall back on if no default is configured.
    yt_sys_vol_snapshot = state.system_volume_before_yt
    state.system_volume_before_yt = None

    async def _stop_cleanup(ah: Optional[str], lid: Optional[str], ph: Optional[str],
                            yt: bool, sys_vol_snapshot: Optional[int]) -> None:
        try:
            if ah and not lid:
                await qbit_delete(ah)
            if ph:
                await qbit_delete(ph, delete_files=True)
            if yt:
                # Give the page a beat to pause via the SSE 'close' command, then
                # kill the dedicated kiosk Chrome instance (matched by profile dir).
                await asyncio.sleep(0.4)
                await asyncio.to_thread(_kill_tv_browser)
                # Verify the kiosk is actually gone before we touch the OS
                # volume — otherwise we'd be turning the still-playing YouTube
                # video's volume up/down underneath the user. Poll a few times.
                deadline = time.monotonic() + 4.0
                needle = str(TV_CHROME_PROFILE)
                while time.monotonic() < deadline:
                    still = False
                    for p in psutil.process_iter(["cmdline"]):
                        try:
                            cl = p.info.get("cmdline") or []
                            if any(needle in str(a) for a in cl):
                                still = True
                                break
                        except Exception:
                            pass
                    if not still:
                        break
                    await asyncio.to_thread(_kill_tv_browser)
                    await asyncio.sleep(0.3)
                # Now safe to restore the OS volume. Prefer the admin-configured
                # default (the user's "expected max"); fall back to the pre-YT
                # snapshot if no default is set.
                target = await _system_volume_default()
                if target is None and sys_vol_snapshot is not None:
                    target = sys_vol_snapshot
                if target is not None:
                    await set_system_volume(target)
                    log.info("YouTube TV: restored system volume to %d%%", target)
            await vlc("pl_stop")
            # Empty the playlist too — pl_stop leaves the enqueued episodes in
            # the list, and a leftover entry can later win an auto-advance and
            # play an episode instead of the bg video. See vlc_clear_playlist().
            await vlc_clear_playlist()
            await vlc_minimize()
        except Exception:
            pass

    asyncio.create_task(_stop_cleanup(active_hash, library_item_id, prepare_hash,
                                       was_youtube, yt_sys_vol_snapshot))
    return JSONResponse({"ok": True}, status_code=202)


@app.post("/api/retry")
async def retry_playback() -> JSONResponse:
    """Relaunch VLC and replay the current file (handles VLC freezes / crashes)."""
    file_path: Optional[Path] = None
    if state.library_current_file:
        file_path = Path(state.library_current_file)
    elif state.active_file:
        file_path = state.active_file
    if not file_path:
        raise HTTPException(400, "Nothing to retry.")
    asyncio.create_task(_retry_task(file_path))
    return JSONResponse({"ok": True})


@app.post("/api/vlc/pause")
async def pause() -> JSONResponse:
    await vlc("pl_pause")
    return JSONResponse({"ok": True})


async def _global_max_volume() -> int:
    """Return the global max-volume cap (0-200). Defaults to 200 = no cap."""
    lib = await get_library()
    raw = lib.get("settings", {}).get("max_volume", 200)
    return max(0, min(200, int(raw)))


async def _global_vlc_start_volume_pct() -> int:
    """Return the VLC startup volume as a % of the max-volume cap (0-100).

    Defaults to 50 (half the cap), preserving the historical 1/2-max behaviour.
    """
    lib = await get_library()
    raw = lib.get("settings", {}).get("vlc_start_volume", 50)
    return max(0, min(100, int(raw)))


@app.post("/api/vlc/volume/set")
async def volume_set(volume: int) -> JSONResponse:
    # volume is 0-200 (100 = normal); VLC uses 0-512 (256 = 100%)
    cap = await _global_max_volume()
    capped = max(0, min(cap, max(0, min(200, volume))))
    raw = max(0, min(512, round(capped / 100 * 256)))
    await vlc("volume", val=str(raw))
    state.vlc_volume = capped
    return JSONResponse({"ok": True, "volume": capped, "max_volume": cap})


@app.post("/api/vlc/volume/{direction}")
async def volume(direction: str, step: int = 10) -> JSONResponse:
    if direction not in ("up", "down"):
        raise HTTPException(400, "direction must be 'up' or 'down'")
    # Server-authoritative relative adjustment so out-of-sync clients can't
    # snap volume back to a stale value (e.g. phone unlocks showing 50 while
    # actual is 35 — pressing − must apply -step to 35, not jump to 45).
    magnitude = max(0, min(200, abs(int(step))))
    delta = magnitude if direction == "up" else -magnitude
    cap = await _global_max_volume()
    next_vol = max(0, min(cap, state.vlc_volume + delta))
    raw = max(0, min(512, round(next_vol / 100 * 256)))
    await vlc("volume", val=str(raw))
    state.vlc_volume = next_vol
    return JSONResponse({"ok": True, "volume": next_vol, "max_volume": cap})


@app.post("/api/vlc/seek")
async def seek(delta: float) -> JSONResponse:
    """Seek relative to current position.  delta is seconds; negative = rewind."""
    sign = "+" if delta >= 0 else ""
    await vlc("seek", val=f"{sign}{int(delta)}s")
    return JSONResponse({"ok": True})


@app.post("/api/vlc/seek/to")
async def seek_to(position_pct: float) -> JSONResponse:
    """Seek to an absolute position (0–100 %)."""
    pct = max(0.0, min(100.0, position_pct))
    await vlc("seek", val=f"{pct:.2f}%")
    return JSONResponse({"ok": True})


# ── HID wireless remote (air-mouse) media keys ───────────────────────────────
# remote_input.py hooks the host's media keys globally (the remote's dongle
# presents as a HID keyboard) and calls back into the two functions below —
# `_remote_should_handle` synchronously from the listener thread, the dispatch
# via run_coroutine_threadsafe onto the main loop. See docs/REMOTE.md.

REMOTE_SEEK_STEP_SECS = 10   # remote ⏮/⏭ buttons: ± seconds (matches the UI's small skip)
REMOTE_VOLUME_STEP    = 5    # remote vol ± buttons: % per press (matches the UI's ± buttons)


async def _neuter_sleep_button() -> None:
    """Windows: set the active power plan's sleep-button action to "Do
    nothing" (AC + DC), so the remote's ⏻ press stops suspending the box.

    Most air-mouse power buttons emit a HID System Control usage that goes
    straight to the Windows power manager — no keyboard hook can see or
    suppress it, so the box locks + sleeps and wakes to the lock screen
    (autologin only runs at boot). With the OS action disabled, the press
    does nothing system-wide and the Raw Input listener
    (remote_input.start_power_listener) handles it instead. Persistent,
    machine-wide power-plan change, deliberately: a media box must never be
    slept by a stray remote press, even while StreamLink isn't running. The
    physical power button (PBUTTONACTION) is left alone.

    powercfg needs an elevated process — on failure, log the manual commands.
    """
    cmds = [
        ("powercfg", "/setacvalueindex", "SCHEME_CURRENT", "SUB_BUTTONS", "SBUTTONACTION", "0"),
        ("powercfg", "/setdcvalueindex", "SCHEME_CURRENT", "SUB_BUTTONS", "SBUTTONACTION", "0"),
        ("powercfg", "/setactive", "SCHEME_CURRENT"),
    ]
    for cmd in cmds:
        try:
            proc = await asyncio.create_subprocess_exec(
                *cmd,
                stdout=asyncio.subprocess.DEVNULL,
                stderr=asyncio.subprocess.DEVNULL,
            )
            rc = await proc.wait()
        except Exception:
            rc = -1
        if rc != 0:
            log.warning(
                "could not set the sleep-button action to 'do nothing' "
                "(powercfg rc=%s — not elevated?). The remote's ⏻ press may "
                "still sleep the box; run from an ADMIN prompt:  "
                "powercfg /setacvalueindex SCHEME_CURRENT SUB_BUTTONS SBUTTONACTION 0  &&  "
                "powercfg /setdcvalueindex SCHEME_CURRENT SUB_BUTTONS SBUTTONACTION 0  &&  "
                "powercfg /setactive SCHEME_CURRENT", rc)
            return
    log.info("sleep-button action set to 'do nothing' — remote ⏻ presses are "
             "intercepted via Raw Input instead")


def _remote_should_handle(action: str = "") -> bool:
    """Whether a remote key press should be acted on (and, on Windows,
    suppressed system-wide).

    Called from the pynput listener thread — keep it to plain attribute reads
    (no awaits, no locks).

    - While the user paused window control ("Use My Computer") nothing is
      claimed: a real keyboard's volume keys must drive the OS mixer and the
      Home key may open their browser — it's their desktop.
    - `home` (🏠) is claimed whenever the TV UI is enabled OR playback is up
      (it must never fall through to launching Edge mid-session).
    - `back` (←) is claimed during playback (exit to the TV UI, Firestick
      style) and while the kiosk holds the screen (step back *inside* the
      dashboard — unsuppressed, Chrome would treat VK_BROWSER_BACK as
      history-back and navigate the kiosk away from `?tv=1`). Idle it passes
      through and counts as generic input, waking the TV UI like any button.
    - `volume_up`/`volume_down` are **always** claimed: the remote's volume
      must never reach the host OS mixer (no Windows volume overlay, no
      changed system volume after a session) — it drives VLC's amp (or the
      YouTube player's own gain) instead, whatever the playback state.
    - `power` (⏻, VK_SLEEP) is **always** claimed: unsuppressed, Windows
      sleeps/hibernates the media box — never desirable from the couch. It
      toggles between the two idle surfaces instead (background video ⇄
      TV UI; during playback: stop, back to the background video).
    - `ok` (Enter) is claimed only during real playback while the TV UI is
      NOT up — it acts as ⏯; with the dashboard kiosk foreground it must keep
      activating the focused element (D-pad navigation).
    - The remaining media keys are claimed while real playback is up (VLC
      stream / library play, incl. paused, or YouTube-on-TV); when idle they
      pass through to the OS untouched.
    """
    if window_mgmt_paused():
        return False
    playing = state.youtube_active or state.stream_status in ("playing", "buffering")
    if action == "home":
        return bool(settings.tv_ui) or playing
    if action == "back":
        return playing or state.tv_ui_active
    if action in ("volume_up", "volume_down", "power"):
        return True
    if action == "ok":
        return playing and not state.tv_ui_active
    return playing


async def _remote_key_action(action: str) -> None:
    """Dispatch a remote media-key press into the normal control paths.

    action ∈ {playpause, ok, volume_up, volume_down, seek_forward, seek_back,
    home, back, power}. Routes like the dashboard footer with one deliberate exception:
    the remote's **volume never touches the host OS mixer** — VLC playback and
    idle adjust VLC's amp (capped by settings.max_volume); YouTube-on-TV
    adjusts the IFrame player's own gain via a `player_volume_step` yt_command
    (NOT the dashboard slider's server-side OS-volume path). `home` (🏠) is
    the Firestick Home equivalent: end whatever is playing and put the
    dashboard kiosk on the screen. `back` (←) is the Firestick Back
    equivalent: during playback it exits the player to the dashboard (same
    path as Home — here the dashboard IS the screen behind every playback);
    with the kiosk up it steps back inside the UI via a `tv_command` SSE
    event (`?tv=1` closes its topmost modal / drops focus). `power` (⏻,
    VK_SLEEP — unsuppressed it would sleep the box) is the standby toggle
    between the two idle surfaces: background video showing → dashboard
    kiosk; kiosk showing → background video; playback up → stop, back to
    the background video. `ok` (Enter / OK button) is ⏯.
    """
    try:
        if action == "ok":
            action = "playpause"   # only dispatched while claimed (= playback up)
        if action == "home":
            # Show the UI first so tv_ui_active gates the focus/background
            # churn that stop() kicks off, then end the active playback.
            if settings.tv_ui:
                await _tv_ui_show("home key")
            if state.youtube_active or state.stream_status != "idle" \
                    or state.library_item_id or state.active_hash:
                await stop()
            return
        if action == "back":
            if state.youtube_active or state.stream_status != "idle" \
                    or state.library_item_id or state.active_hash:
                # Exit the player back to the dashboard — UI first so
                # tv_ui_active gates the focus churn, exactly like Home.
                if settings.tv_ui:
                    await _tv_ui_show("back key")
                await stop()
            elif state.tv_ui_active:
                # Kiosk foreground, nothing playing: navigate back inside the
                # dashboard. The key was suppressed (Chrome must not
                # history-back the kiosk), so the page acts on this instead.
                await broadcast("tv_command", {"action": "back"})
            return
        if action == "power":
            # Cross-path debounce: a single press can arrive twice — remotes
            # may emit BOTH the VK_SLEEP keyboard key (hook path) and the HID
            # System Control usage (raw-input path) — and neither path shares
            # the RemoteListener per-action debounce.
            global _remote_power_ts
            now_m = time.monotonic()
            if now_m - _remote_power_ts < 1.0:
                return
            _remote_power_ts = now_m
            # Standby toggle between the two idle surfaces — never the OS
            # sleep the key means to Windows (suppressed / neutered while claimed).
            if state.youtube_active or state.stream_status != "idle" \
                    or state.library_item_id or state.active_hash:
                # "Screen off": end playback. background_video_loop brings the
                # idle video back within ~3 s — starting it here directly would
                # race stop()'s async VLC teardown (pl_stop/pl_empty would kill
                # the just-started video).
                await stop()
            elif state.tv_ui_active:
                # Kiosk showing → hand back to the background video. With no
                # video configured keep the dashboard — a black VLC window is
                # worse (same rule as tv_ui_loop's idle hand-back).
                if await _bg_video_ready():
                    await _tv_ui_hide("power key")
            elif state.background_playing:
                await _tv_ui_show("power key")
            elif not await _play_background_video():
                # Idle with nothing on screen: prefer the background video,
                # fall back to the dashboard kiosk.
                await _tv_ui_show("power key")
            return
        if action in ("volume_up", "volume_down"):
            global _remote_vol_key_ts
            _remote_vol_key_ts = time.monotonic()   # dedupe vs remote_volume_guard
            delta = REMOTE_VOLUME_STEP if action == "volume_up" else -REMOTE_VOLUME_STEP
            if state.youtube_active:
                # Player gain only — never set_system_volume from the remote.
                # tv.html applies this to the IFrame player (see its
                # `player_volume_step` case); the host mixer stays put.
                await broadcast("yt_command",
                                {"action": "player_volume_step", "value": float(delta)})
            else:
                await volume("up" if delta > 0 else "down", step=REMOTE_VOLUME_STEP)
                await broadcast("state", state_snapshot())
            return
        if state.youtube_active:
            yt_action, yt_value = {
                "playpause":    ("playpause", None),
                "seek_forward": ("seek", float(REMOTE_SEEK_STEP_SECS)),
                "seek_back":    ("seek", float(-REMOTE_SEEK_STEP_SECS)),
            }[action]
            await youtube_control(YouTubeControlReq(action=yt_action, value=yt_value))
            return
        if action == "playpause":
            await vlc("pl_pause")
        elif action == "seek_forward":
            await vlc("seek", val=f"+{REMOTE_SEEK_STEP_SECS}s")
        elif action == "seek_back":
            await vlc("seek", val=f"-{REMOTE_SEEK_STEP_SECS}s")
        # Reflect the change on every open dashboard immediately instead of
        # waiting for the next 2 s stat_broadcaster tick.
        await broadcast("state", state_snapshot())
    except Exception:
        # Races are expected (YouTube stopping between the gate and the call,
        # VLC mid-restart) — a lost keypress is fine; never let it propagate
        # out of the scheduled coroutine.
        log.debug("remote key '%s' dispatch failed", action, exc_info=True)


# monotonic() of the last volume press the KEYBOARD HOOK dispatched — lets the
# guard below tell hook-handled presses (already routed to VLC) apart from
# consumer-control presses it must route itself.
_remote_vol_key_ts: float = 0.0

# monotonic() of the last acted-on ⏻ power press — cross-path debounce (see
# the power branch above; VK_SLEEP hook path + raw-input path can both fire).
_remote_power_ts: float = 0.0


async def remote_volume_guard() -> None:
    """OPT-IN (REMOTE_VOLUME_GUARD=1) Windows backstop for remotes whose
    volume buttons bypass the keyboard hook.

    Some HID remotes emit volume as consumer-control usages the hook can't
    suppress — the system volume then changes even with remote support
    active. This loop polls the endpoint volume (~3 Hz, via the winvol
    helper child): every legitimate writer goes through set_system_volume,
    which records `state.host_volume_expected`; any other change is treated
    as remote volume — **reverted**, and the delta re-routed to VLC's amp
    (or the YouTube player gain) unless the keyboard hook already dispatched
    a volume press in the last ~1.2 s (then it's only reverted; the hook
    path already stepped VLC, and double-stepping would jump 2× per press
    on remotes that emit both forms).

    Default OFF, deliberately: on the reference hardware the hook's
    suppression alone keeps the mixer untouched (v9.13.0 behaviour, verified
    live), and an always-on guard can FIGHT endpoints that quantize volume
    (HDMI audio often can't hold every integer percent): revert to 43 →
    device stores 42 → next tick sees a fresh "change" → revert again,
    flickering the mixer forever and drip-stepping VLC's volume. Two
    defences below for when the guard IS enabled: a ±1 tolerance band that
    adopts drift instead of reverting it, and adopting the endpoint's ACTUAL
    post-revert value as the new expectation.

    Stands down during the "Use My Computer" window-pause (the user owns
    their mixer then) — it resyncs, so changes made during the pause stick.
    Windows-only: POSIX volume reads spawn a process per call, and the
    consumer-control problem is a Windows-target concern.
    """
    if (platform.system() != "Windows" or not settings.remote_control
            or not settings.remote_volume_guard):
        return
    log.info("remote volume guard active (REMOTE_VOLUME_GUARD=1)")
    while True:
        await asyncio.sleep(0.35)
        try:
            if window_mgmt_paused():
                state.host_volume_expected = None   # resync when the pause lifts
                continue
            cur = await get_system_volume()
            if cur is None:
                await asyncio.sleep(5)   # pycaw/helper unavailable — back off
                continue
            exp = state.host_volume_expected
            if exp is None or abs(cur - exp) <= 1:
                # In-band drift is endpoint quantization, not a press — adopt
                # it, or the loop would fight the device forever.
                state.host_volume_expected = cur
                continue
            delta = cur - exp
            await set_system_volume(exp)   # revert (re-records expected)
            # Adopt whatever the endpoint ACTUALLY stored — a quantizing
            # device may be unable to hold `exp` exactly.
            actual = await get_system_volume()
            if actual is not None:
                state.host_volume_expected = actual
            if time.monotonic() - _remote_vol_key_ts < 1.2:
                continue   # the keyboard hook already routed this press
            # Windows steps the mixer by 2 per volume-key press; a tick may
            # batch several presses of a held button.
            presses = max(1, round(abs(delta) / 2))
            step = min(50, presses * REMOTE_VOLUME_STEP)
            if state.youtube_active:
                await broadcast("yt_command", {
                    "action": "player_volume_step",
                    "value": float(step if delta > 0 else -step)})
            else:
                await volume("up" if delta > 0 else "down", step=step)
                await broadcast("state", state_snapshot())
        except Exception:
            pass


async def _item_all_paths() -> list[str]:
    """Return the full sorted file path list for the current playback. For a
    merged-series play this is the stable cross-item order (so prev/unshuffle can
    walk back past an item boundary); otherwise the active item's file list."""
    if state.library_series_order:
        return list(state.library_series_order)
    if not state.library_item_id:
        return []
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == state.library_item_id), None)
    return [f["path"] for f in item.get("files", [])] if item else []


def _find_in_paths(current: str, paths: list[str]) -> int:
    """Return the index of current in paths, trying exact match then resolved match."""
    try:
        return paths.index(current)
    except ValueError:
        pass
    try:
        resolved = Path(current).resolve()
        for i, p in enumerate(paths):
            try:
                if Path(p).resolve() == resolved:
                    return i
            except Exception:
                continue
    except Exception:
        pass
    return -1


async def _vlc_replace_upcoming(upcoming: list[str]) -> bool:
    """Swap VLC's *upcoming* queue without touching the current item — no rebuffer.

    Used to leave Shuffle Play mid-episode: the playing file keeps going while the
    queue behind it is rewritten from the random tail to natural order. `pl_empty`
    can't do this (it drops the current item too — see vlc_clear_playlist), so we
    delete only the leaves that come *after* the current one, then enqueue the new
    tail. Returns False if VLC's playlist couldn't be read/edited so the caller can
    fall back to a (briefly rebuffering) relaunch."""
    try:
        r = await _vlc_http().get("/requests/playlist.json", timeout=3.0)
        if r.status_code != 200:
            return False
        leaves: list[dict] = []   # ordered leaf nodes ({id, uri, current})

        def _walk(node: dict) -> None:
            children = node.get("children")
            if children:
                for c in children:
                    _walk(c)
            elif node.get("uri") is not None:
                leaves.append(node)

        _walk(r.json())
        cur_idx = next((i for i, n in enumerate(leaves) if n.get("current") == "current"), -1)
        if cur_idx < 0:
            return False
        # Drop every entry after the current one (the stale shuffle tail).
        for n in leaves[cur_idx + 1:]:
            nid = n.get("id")
            if nid is not None:
                await vlc("pl_delete", id=str(nid))
        # Enqueue the natural-order tail behind the still-playing current file.
        for p in upcoming:
            await vlc("in_enqueue", input=vlc_file_uri(Path(p)))
        return True
    except Exception:
        return False


async def _vlc_relaunch_playlist(playlist: list[str], target_name: str) -> None:
    """Background VLC handoff used by prev/next so slow VLC roundtrips don't block the response.

    Fires `in_play` detached and flips `stream_status` to "playing" the moment a
    `status.json` poll shows VLC is actually on the new file — not when in_play's
    (often multi-second) HTTP reply finally comes back, and not after the whole
    playlist has been enqueued. Either of those would pin the UI to "buffering"
    for seconds while the user is already watching the new episode.
    """
    first = Path(playlist[0])
    first_resolved = first.resolve()
    # Clear stale playlist items (a leftover bg entry could otherwise win an
    # end-of-file auto-advance and play the bg video instead of this episode).
    await vlc_clear_playlist()
    play_task = asyncio.create_task(vlc("in_play", input=vlc_file_uri(first_resolved)))
    try:
        await _vlc_wait_until_ready(first_resolved, timeout=10.0)
        state.stream_status = "playing"
        await broadcast("stream_status", {"status": "playing", "message": f"Playing: {target_name}"})
        await broadcast("state", state_snapshot())
        if state.library_item_id and state.library_profile_id:
            asyncio.create_task(_apply_track_prefs(
                state.library_item_id, state.library_profile_id, playlist[0], delay=2.0,
            ))
        rest = playlist[1:]
        if rest:
            try:
                await play_task
            except Exception:
                pass
            await asyncio.gather(
                *(vlc("in_enqueue", input=vlc_file_uri(Path(p))) for p in rest),
                return_exceptions=True,
            )
    except asyncio.CancelledError:
        play_task.cancel()
        raise
    except Exception as e:
        play_task.cancel()
        state.stream_status = "error"
        await broadcast("stream_status", {"status": "error", "message": f"Playback failed: {e}"})
        await broadcast("state", state_snapshot())


@app.post("/api/vlc/prev")
async def vlc_prev() -> JSONResponse:
    """Jump to the previous episode (shuffle order when shuffling, else series order)."""
    current = state.library_current_file
    if not current:
        raise HTTPException(400, "No active playback.")

    prev_file: Optional[str] = None
    new_tail: list[str] = []

    if state.library_shuffle_order:
        # Shuffle Play: step back through the temp random order. new_tail keeps the
        # whole forward run so VLC auto-advance continues the shuffle from here.
        order = state.library_shuffle_order
        oi = _find_in_paths(current, order)
        if oi > 0:
            prev_file = order[oi - 1]
            new_tail  = order[oi - 1:]
    else:
        # Try the active playlist first, then fall back to the item's full file list
        idx = _find_in_paths(current, state.library_playlist)
        if idx > 0:
            prev_file = state.library_playlist[idx - 1]
            new_tail  = state.library_playlist[idx - 1:]
        else:
            all_paths = await _item_all_paths()
            item_idx  = _find_in_paths(current, all_paths)
            if item_idx > 0:
                prev_file = all_paths[item_idx - 1]
                new_tail  = all_paths[item_idx - 1:]

    if not prev_file:
        raise HTTPException(400, "Already at first episode.")
    if not Path(prev_file).exists():
        raise HTTPException(400, f"File not found: {Path(prev_file).name}")

    prior = state.library_play_task
    if prior and not prior.done():
        prior.cancel()

    await _cancel_skip_countdown()
    state.library_playlist     = new_tail
    state.library_current_file = prev_file
    state.current_audio_track  = -1
    state.current_subtitle_track = -1
    state.track_pref_applied_file = prev_file
    state.skip_offer = None
    state.skip_offer_file = None
    state.stream_status = "buffering"

    await broadcast("stream_status", {"status": "buffering", "message": f"Loading: {Path(prev_file).name}"})
    await broadcast("state", state_snapshot())

    state.library_play_task = asyncio.create_task(_vlc_relaunch_playlist(new_tail, Path(prev_file).name))
    return JSONResponse({"ok": True}, status_code=202)


@app.post("/api/vlc/next")
async def vlc_next() -> JSONResponse:
    """Jump to the next episode (shuffle order when shuffling, else series order)."""
    current = state.library_current_file
    if not current:
        raise HTTPException(400, "No active playback.")

    next_file: Optional[str] = None
    new_tail: list[str] = []

    if state.library_shuffle_order:
        # Shuffle Play: step forward through the temp random order.
        order = state.library_shuffle_order
        oi = _find_in_paths(current, order)
        if 0 <= oi < len(order) - 1:
            next_file = order[oi + 1]
            new_tail  = order[oi + 1:]
    else:
        # Try the active playlist first, then fall back to the item's full file list
        idx = _find_in_paths(current, state.library_playlist)
        if 0 <= idx < len(state.library_playlist) - 1:
            next_file = state.library_playlist[idx + 1]
            new_tail  = state.library_playlist[idx + 1:]
        else:
            all_paths = await _item_all_paths()
            item_idx  = _find_in_paths(current, all_paths)
            if 0 <= item_idx < len(all_paths) - 1:
                next_file = all_paths[item_idx + 1]
                new_tail  = all_paths[item_idx + 1:]

    if not next_file:
        raise HTTPException(400, "Already at last episode.")
    if not Path(next_file).exists():
        raise HTTPException(400, f"File not found: {Path(next_file).name}")

    # Skipping forward to the next episode — arm the deferred watch from any
    # position (cancelled if they return to this file within the grace window).
    vs_now = await vlc_status()
    _arm_credit_skip_watch(
        state.library_item_id, state.library_profile_id, current,
        float((vs_now or {}).get("time", 0) or 0),
        float((vs_now or {}).get("length", 0) or 0),
    )

    prior = state.library_play_task
    if prior and not prior.done():
        prior.cancel()

    await _cancel_skip_countdown()
    state.library_playlist     = new_tail
    state.library_current_file = next_file
    state.current_audio_track  = -1
    state.current_subtitle_track = -1
    state.track_pref_applied_file = next_file
    state.skip_offer = None
    state.skip_offer_file = None
    state.stream_status = "buffering"

    await broadcast("stream_status", {"status": "buffering", "message": f"Loading: {Path(next_file).name}"})
    await broadcast("state", state_snapshot())

    state.library_play_task = asyncio.create_task(_vlc_relaunch_playlist(new_tail, Path(next_file).name))
    return JSONResponse({"ok": True}, status_code=202)


@app.post("/api/library/unshuffle")
async def library_unshuffle() -> JSONResponse:
    """Leave Shuffle Play mid-episode → back to natural order, no interruption.

    The currently-playing file keeps going; only the *upcoming* queue flips from
    the random tail to sequential. Clears the persisted shuffle pref too so a later
    Resume won't offer to keep shuffling."""
    if not state.library_shuffle_order:
        raise HTTPException(400, "Not shuffling.")
    current = state.library_current_file
    if not current:
        raise HTTPException(400, "No active playback.")

    natural = await _item_all_paths()
    idx = _find_in_paths(current, natural)
    new_tail = natural[idx:] if idx >= 0 else [current]

    state.library_shuffle_order = []
    state.library_playlist = new_tail

    # Rewrite VLC's queue behind the playing file. If the in-place edit fails for
    # any reason, relaunch the natural tail reseeked to the live position so order
    # is correct even at the cost of a brief rebuffer.
    ok = await _vlc_replace_upcoming(new_tail[1:])
    if not ok:
        vs = await vlc_status()
        try:
            pos = int(float((vs or {}).get("time", 0) or 0))
        except (TypeError, ValueError):
            pos = 0
        prior = state.library_play_task
        if prior and not prior.done():
            prior.cancel()
        state.library_play_task = asyncio.create_task(
            _vlc_relaunch_playlist(new_tail, Path(current).name))
        if pos > 5:
            async def _reseek() -> None:
                await asyncio.sleep(0.5)
                if await _vlc_wait_until_ready(Path(current).resolve(), timeout=10.0):
                    await vlc("seek", val=str(pos))
            asyncio.create_task(_reseek())

    if state.library_item_id and state.library_profile_id:
        asyncio.create_task(_set_shuffle_pref(
            state.library_item_id, state.library_profile_id, False, "",
        ))
    await broadcast("state", state_snapshot())
    return JSONResponse({"ok": True})


def _vlc_es_label(lang: str, title: str, codec: str, fallback: str) -> str:
    """Label a VLC ES track to match the on-device player's `_track_label`:
    '<Language> (<title>)' when both are present, else whichever exists.

    VLC exposes the container track *title* (e.g. an MKV's "Signs/Songs" vs
    "Full Subtitles") in the status `Description` field — only when the track
    actually carries a title; untitled tracks have no `Description`. Without it
    two same-language subs were indistinguishable (both rendered as just
    'English'), unlike the on-device menu which shows the real titles. Keep this
    in sync with `_track_label` (the HLS/meta.json path)."""
    lang  = (lang  or "").strip()
    title = (title or "").strip()
    if lang and title:
        return f"{lang} ({title})"
    return title or lang or codec or fallback


def _parse_track_streams(vs: Optional[dict]) -> tuple[list[dict], list[dict]]:
    """Parse a VLC status payload into (audio, subtitle) track lists.

    Each entry is {id, label, language, codec, title}. `id` is the ES
    (elementary stream) ID — the N in each 'Stream N' key, the same value VLC's
    audio_track / subtitle_track commands take (a sequential counter would
    silently fail). `title` is VLC's `Description` (the container track title),
    folded into `label` so same-language tracks are distinguishable — matching
    the on-device menu. Shared by the /api/vlc/tracks endpoint and the playback
    subtitle-default policy (`_apply_track_prefs`), so they agree on ES IDs.
    """
    audio: list[dict] = []
    subtitle: list[dict] = []
    if not vs:
        return audio, subtitle
    cat = vs.get("information", {}).get("category", {})
    # Sort numerically by stream index so we process in file order.
    stream_keys = sorted(
        (k for k in cat if k.startswith("Stream")),
        key=lambda k: int(k.split()[-1]) if k.split()[-1].isdigit() else 999,
    )
    audio_n = sub_n = 1   # display-only counters for fallback labels
    for key in stream_keys:
        try:
            es_id = int(key.split()[-1])
        except (ValueError, IndexError):
            continue
        s     = cat[key]
        typ   = s.get("Type", "")
        lang  = s.get("Language", s.get("language", ""))
        codec = s.get("Codec", s.get("codec", ""))
        # VLC reports the container track title (MKV title tag) here, only when
        # the track actually has one. Folded into the label so two same-language
        # tracks aren't both shown as bare 'English' (see _vlc_es_label).
        title = (s.get("Description") or "").strip()
        if typ == "Audio":
            audio.append({"id": es_id,
                          "label": _vlc_es_label(lang, title, codec, f"Track {audio_n}"),
                          "language": lang, "codec": codec, "title": title})
            audio_n += 1
        elif typ == "Subtitle":
            subtitle.append({"id": es_id,
                             "label": _vlc_es_label(lang, title, codec, f"Track {sub_n}"),
                             "language": lang, "codec": codec, "title": title})
            sub_n += 1
    return audio, subtitle


async def _vlc_subtitle_tracks() -> list[dict]:
    """Live subtitle tracks VLC currently knows about (embedded + any loaded
    sidecars), each {id, label, language, codec}. Excludes the synthetic 'Off'."""
    _, subtitle = _parse_track_streams(await vlc_status())
    return subtitle


@app.get("/api/vlc/tracks")
async def get_tracks() -> JSONResponse:
    """Return available audio/subtitle tracks and which are currently selected.

    Track IDs are the actual ES (elementary stream) IDs from VLC. The
    <audiotrack> / <subtitletrack> XML values are also ES IDs, so they must be
    compared against the same ES IDs for the 'current' highlight to work.
    """
    vs = await vlc_status()
    audio, subs = _parse_track_streams(vs)
    subtitle = [{"id": -1, "label": "Off", "language": ""}] + subs

    # VLC 3.x does not expose current track selection in its HTTP API
    # (no <audiotrack>/<subtitletrack> in status.xml). We track it ourselves.
    return JSONResponse({
        "audio":    audio,
        "subtitle": subtitle,
        "current_audio":    state.current_audio_track,
        "current_subtitle": state.current_subtitle_track,
        "time":   vs.get("time",   0) if vs else 0,
        "length": vs.get("length", 0) if vs else 0,
    })


@app.post("/api/vlc/track/audio/{track_id}")
async def set_audio_track(track_id: int) -> JSONResponse:
    state.current_audio_track = track_id
    await vlc("audio_track", val=str(track_id))
    if state.library_item_id and state.library_profile_id and state.library_current_file:
        asyncio.create_task(_save_track_pref(
            state.library_item_id, state.library_profile_id,
            state.library_current_file, audio=track_id,
        ))
        asyncio.create_task(_remember_vlc_audio_pick(track_id))
    return JSONResponse({"ok": True})


async def _remember_vlc_audio_pick(track_id: int) -> None:
    """Best-effort: record the viewer's manual VLC audio pick as a resolvable
    descriptor — per-file (so this file replays with it, and the on-device
    player picks it up on a VLC→device switch) and per-series (so the next
    episode gets the same track). The language/title/signature come from VLC's
    live audio-track list. A pick with no lang, title, or resolvable slot can't
    be re-matched later, so it isn't remembered (the raw ES ID saved by
    set_audio_track still covers same-file replays)."""
    item_id, profile_id = state.library_item_id, state.library_profile_id
    file_path = state.library_current_file
    if not (item_id and profile_id) or track_id is None or track_id < 0:
        return
    audio_tracks, _ = _parse_track_streams(await vlc_status())
    entry = next((t for t in audio_tracks if t["id"] == track_id), None)
    if not entry:
        return
    idx = next((i for i, t in enumerate(audio_tracks) if t["id"] == track_id), -1)
    sel = {"lang": _canon_lang(entry.get("language", "")),
           "title": _norm_sub_title(entry.get("title")),
           "idx": idx, "sig": _audio_sig_of(audio_tracks), "at": _now_iso()}
    if _norm_audio_sel(sel) is None:
        return                            # nothing matchable — not rememberable
    if file_path:
        await _save_track_pref(item_id, profile_id, file_path, audio_sel=sel)
    await _learn_profile_audio_pref(profile_id, sel)
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if item:
        await _save_series_audio_sel(profile_id, _series_of_item(item), sel)


@app.post("/api/vlc/track/subtitle/{track_id}")
async def set_subtitle_track(track_id: int) -> JSONResponse:
    state.current_subtitle_track = track_id
    state.sub_auto_ai_path = ""                    # explicit pick → not auto-AI
    await vlc("subtitle_track", val=str(track_id))
    if state.library_item_id and state.library_profile_id and state.library_current_file:
        asyncio.create_task(_save_track_pref(
            state.library_item_id, state.library_profile_id,
            state.library_current_file, subtitle=track_id,
        ))
        asyncio.create_task(_remember_vlc_sub_pick(track_id))
    return JSONResponse({"ok": True})


async def _remember_vlc_sub_pick(track_id: int) -> None:
    """Best-effort: record the viewer's manual VLC subtitle pick as a resolvable
    descriptor — per-file (so this file replays with it, and the on-device player
    picks it up on a VLC→device switch) and per-series (so the next episode gets
    the same kind). The lang/ai/sidecar-name come from state.vlc_sub_meta (built
    by _load_all_local_subs); VLC's own language tag is the fallback. A pick that
    yields no lang *and* no name can't be resolved later, so it isn't remembered
    (the raw ES ID saved by set_subtitle_track still covers same-file replays)."""
    item_id, profile_id = state.library_item_id, state.library_profile_id
    file_path = state.library_current_file
    if not (item_id and profile_id):
        return
    if track_id is None or track_id < 0:
        sel: dict = {"off": True, "at": _now_iso()}
    else:
        # Annotate the live track list with the lang/ai/path recorded when the
        # sidecars were loaded (state.vlc_sub_meta) so we can build the full
        # descriptor: language + kind + sidecar name, plus the embedded-text
        # signature/index that lets episodes with the exact same track layout
        # (a "group") restore this slot even with no language/title tags.
        meta = state.vlc_sub_meta.get(track_id, {})
        raw = await _vlc_subtitle_tracks()
        tracks = [{**t,
                   "lang": (state.vlc_sub_meta.get(t["id"], {}).get("lang")
                            or _canon_lang(t.get("language", ""))),
                   "ai":   bool(state.vlc_sub_meta.get(t["id"], {}).get("ai")),
                   "path": state.vlc_sub_meta.get(t["id"], {}).get("path", "")}
                  for t in raw]
        entry = next((t for t in tracks if t["id"] == track_id), None)
        lang = meta.get("lang", "") or (entry["lang"] if entry else "")
        name = Path(meta["path"]).name if meta.get("path") else ""
        title = _norm_sub_title(entry.get("title")) if entry else ""
        emb_text = _vlc_embedded_text_subs(tracks)
        sig = _sub_sig_of(emb_text)
        idx = next((i for i, t in enumerate(emb_text) if t["id"] == track_id), -1)
        sel = {"off": False, "lang": lang, "ai": bool(meta.get("ai")), "name": name,
               "title": title, "idx": idx, "sig": sig, "at": _now_iso()}
        if _norm_sub_sel(sel) is None:
            return                        # nothing matchable — not rememberable
    if file_path:
        await _save_track_pref(item_id, profile_id, file_path, sub_sel=sel)
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if item:
        await _save_series_sub_sel(profile_id, _series_of_item(item), sel)


@app.get("/api/subtitles/search")
async def search_subtitles(query: str = "", lang: str = "") -> JSONResponse:
    """Find subtitles for the file VLC is playing — by movie hash (exact) and by
    name (fallback). `query` overrides the auto-derived name.

    `lang` is the OpenSubtitles language filter: a 3-letter code, the literal
    `"all"` for every language, or blank to fall back to the admin's preferred
    subtitle language (`settings.subtitles.default_language`). Defaulting to the
    preferred language is what surfaces English instead of burying it under a
    handful of foreign hits. The effective filter is echoed back as `lang`."""
    video = await _current_playback_path()
    file_hash: Optional[str] = None
    file_size: Optional[int] = None
    file_name = ""
    if video:
        file_name = video.name
        file_size = video.stat().st_size
        file_hash = await asyncio.to_thread(_opensubtitles_hash, video)
    q = query.strip() or (video.stem if video else "")
    if not file_hash and not q:
        raise HTTPException(409, "Nothing is playing and no search query was given.")
    sel = lang.strip().lower()
    if sel == "all":
        sel = ""                                       # explicit all-languages
    elif not sel:
        sel = _subs_cfg(await get_library())["default_language"]   # default → preferred
    results = await _opensubtitles_search(file_hash, file_size, q, sel)
    return JSONResponse({"file": file_name, "hash": file_hash, "lang": sel, "results": results})


class SubtitleDownloadReq(BaseModel):
    download_link: str
    lang: str = ""


async def _download_and_attach_subtitle(
    video: Path, link: str, lang: str, save_pref: bool = True,
) -> tuple[Optional[int], Optional[Path]]:
    """Download an OpenSubtitles .gz/.srt, save it as a sidecar next to `video`,
    load it into VLC via `addsubtitle`, and select the newly-added track.

    Returns (selected ES ID, saved sidecar path). Shared by the manual download
    endpoint (`save_pref=True` → persists the pick as a per-file preference) and
    the playback auto-search (`save_pref=False` → the choice stays a live policy
    decision, so a later profile/admin subs-off toggle still wins). Raises
    httpx/OS errors for the caller to map; the auto-search wrapper swallows them.
    """
    headers = {"User-Agent": settings.opensubtitles_user_agent}
    async with httpx.AsyncClient(timeout=30.0, follow_redirects=True) as c:
        r = await c.get(link, headers=headers)
    r.raise_for_status()
    data = r.content
    if data[:2] == b"\x1f\x8b":       # gzip magic — OpenSubtitles serves .gz
        data = gzip.decompress(data)

    safe = re.sub(r"[^a-zA-Z]", "", lang)[:5].lower() or "sub"
    dest = video.with_name(f"{video.stem}.{safe}.srt")
    n = 2
    while dest.exists():
        dest = video.with_name(f"{video.stem}.{safe}.{n}.srt")
        n += 1
    dest.write_bytes(data)

    # Load into VLC, then select the newly added subtitle track (highest ES ID).
    await vlc("addsubtitle", val=str(dest.resolve()))
    await asyncio.sleep(0.6)
    new_id: Optional[int] = None
    subs = await _vlc_subtitle_tracks()
    if subs:
        new_id = max(s["id"] for s in subs)
        state.current_subtitle_track = new_id
        state.vlc_sub_meta[new_id] = {
            "lang": _canon_lang(lang), "ai": False, "path": str(dest)}
        await vlc("subtitle_track", val=str(new_id))
        if save_pref and state.library_item_id and state.library_profile_id and state.library_current_file:
            asyncio.create_task(_save_track_pref(
                state.library_item_id, state.library_profile_id,
                state.library_current_file, subtitle=new_id,
            ))
            asyncio.create_task(_remember_vlc_sub_pick(new_id))
    return new_id, dest


async def _auto_fetch_subtitle(video: Path, lang: str) -> Optional[int]:
    """Search OpenSubtitles for a `lang` subtitle for `video` and load the best
    match into VLC. Best-effort: returns the selected ES ID or None. Used by the
    playback subtitle-default policy when no preferred-language track is present."""
    try:
        file_size = video.stat().st_size
        file_hash = await asyncio.to_thread(_opensubtitles_hash, video)
        results = await _opensubtitles_search(file_hash, file_size, video.stem, lang)
        results = [r for r in results if r.get("download_link")]
        if not results:
            return None
        new_id, _ = await _download_and_attach_subtitle(
            video, results[0]["download_link"], lang, save_pref=False)
        return new_id
    except Exception:
        return None


@app.post("/api/subtitles/download")
async def download_subtitle(req: SubtitleDownloadReq) -> JSONResponse:
    """Download a chosen subtitle, save it next to the playing video, and load it
    into VLC as a new (and selected) subtitle track."""
    link = req.download_link.strip()
    host = (urlparse(link).hostname or "").lower()
    if not (host == "opensubtitles.org" or host.endswith(".opensubtitles.org")):
        raise HTTPException(400, "Invalid subtitle source.")
    video = await _current_playback_path()
    if not video:
        raise HTTPException(409, "No file is currently playing.")
    try:
        new_id, dest = await _download_and_attach_subtitle(video, link, req.lang, save_pref=True)
    except OSError as e:
        raise HTTPException(500, f"Could not save subtitle file: {e}")
    except Exception as e:
        raise HTTPException(502, f"Subtitle download failed: {e}")
    return JSONResponse({"ok": True, "saved": dest.name if dest else None, "subtitle_track": new_id})


@app.get("/api/state")
async def get_state() -> JSONResponse:
    return JSONResponse(state_snapshot())


@app.get("/api/version")
async def get_ui_version() -> JSONResponse:
    # no-cache so an out-of-date browser can detect that its cached HTML is stale
    return JSONResponse(
        {"version": UI_VERSION},
        headers={"Cache-Control": "no-cache, no-store, must-revalidate"},
    )


# Files an iOS "player snapshot" must carry — the dashboard page plus every asset
# it can lazily load (see docs/PLAYER_CACHE_PLAN.md). A fixed allowlist, not a
# directory walk, so the snapshot never grows surprise files; every entry is
# served by the root StaticFiles mount, which is what the app downloads from.
_PLAYER_SNAPSHOT_FILES = [
    "index.html",
    "vendor/tailwind.js",
    "vendor/hls.min.js",
    "vendor/subtitles-octopus.js",
    "vendor/subtitles-octopus-worker.js",
    "vendor/subtitles-octopus-worker.wasm",
    "vendor/libass-fallback-font.ttf",
]
_UI_BADGE_RE = re.compile(r"data-ui-version[^>]*>([^<]+)<")


@app.get("/api/player-manifest")
async def player_manifest(request: Request) -> JSONResponse:
    """Manifest for the iOS app's offline player snapshot (docs/PLAYER_CACHE_PLAN.md).

    Returns {version, files:[{name,size}]} — the app compares `version` against
    its cached snapshot's and re-downloads on mismatch (BundleDownloader's
    size-match resume makes a same-version refresh a no-op). The version is read
    from the live index.html badge (the file on disk is the source of truth;
    the UI_VERSION constant historically drifts)."""
    _require_device_auth(request)

    def _build() -> tuple[str, list[dict]]:
        static_dir = Path(__file__).parent / "static"
        files: list[dict] = []
        for name in _PLAYER_SNAPSHOT_FILES:
            try:
                files.append({"name": name, "size": (static_dir / name).stat().st_size})
            except OSError:
                continue   # optional asset missing — the snapshot just omits it
        version = UI_VERSION
        try:
            m = _UI_BADGE_RE.search((static_dir / "index.html").read_text("utf-8", errors="replace"))
            if m:
                version = m.group(1).strip()
        except OSError:
            pass
        return version, files

    version, files = await asyncio.to_thread(_build)
    return JSONResponse({"version": version, "files": files})


async def _all_library_paths() -> list[dict]:
    """All configured library paths: static (.env) + dynamic (UI-added via library.json)."""
    lib = await get_library()
    dynamic: list[str] = lib.get("settings", {}).get("library_paths", [])
    seen: set[str] = set()
    result = []
    for raw, is_static in [
        (settings.qbit_download_path, True),
        (settings.library_path_2, True),
        (settings.library_path_3, True),
        (settings.library_path_4, True),
        *((p, False) for p in dynamic),
    ]:
        p = (raw or "").strip()
        if p and p not in seen:
            seen.add(p)
            result.append({"path": p, "label": Path(p).name or p, "static": is_static})
    return result


@app.get("/api/settings/download-path")
async def get_download_path() -> JSONResponse:
    return JSONResponse({"path": settings.qbit_download_path})


@app.get("/api/settings/library-paths")
async def get_library_paths_api() -> JSONResponse:
    return JSONResponse({"paths": await _all_library_paths()})


@app.post("/api/settings/library-paths")
async def add_library_path(path: str) -> JSONResponse:
    p = path.strip()
    if not p:
        raise HTTPException(400, "Path cannot be empty.")
    if not Path(p).is_dir():
        raise HTTPException(400, f"Directory does not exist: {p}")
    lib = await get_library()
    existing = [info["path"] for info in await _all_library_paths()]
    if p in existing:
        raise HTTPException(400, "Path is already configured.")
    lib.setdefault("settings", {}).setdefault("library_paths", []).append(p)
    await put_library(lib)
    return JSONResponse({"ok": True})


@app.delete("/api/settings/library-paths")
async def remove_library_path(path: str) -> JSONResponse:
    lib = await get_library()
    paths: list = lib.get("settings", {}).get("library_paths", [])
    if path not in paths:
        raise HTTPException(404, "Path not found in UI-configured paths (static .env paths cannot be removed here).")
    paths.remove(path)
    await put_library(lib)
    return JSONResponse({"ok": True})


@app.get("/api/settings/disk-space")
async def get_disk_space() -> JSONResponse:
    disks = []
    for info in await _all_library_paths():
        try:
            usage = await asyncio.to_thread(shutil.disk_usage, info["path"])
            disks.append({
                "path":        info["path"],
                "label":       info["label"],
                "total_bytes": usage.total,
                "free_bytes":  usage.free,
                "total_human": human_size(usage.total),
                "free_human":  human_size(usage.free),
                "free_pct":    round(usage.free / usage.total * 100, 1) if usage.total else 0,
            })
        except Exception as e:
            disks.append({"path": info["path"], "label": info["label"], "error": str(e)})
    primary = disks[0] if disks else {}
    return JSONResponse({**primary, "disks": disks})


@app.get("/api/library/{item_id}/download")
async def download_library_file(item_id: str, file_path: str = "") -> FileResponse:
    """Stream a library file to the browser for download.

    For single-file items the path can be omitted; for multi-file items pass
    the absolute file_path as a query parameter.
    """
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")

    files = item.get("files", [])
    if not files:
        raise HTTPException(404, "No files associated with this item.")

    if file_path:
        target = next((f for f in files if f["path"] == file_path), None)
        if not target:
            raise HTTPException(404, "File not found in this item.")
        path = Path(target["path"])
    else:
        if len(files) != 1:
            raise HTTPException(400, "Multiple files — pass file_path query parameter.")
        path = Path(files[0]["path"])

    if not path.exists():
        raise HTTPException(404, f"File not on disk: {path.name}")

    return FileResponse(
        path=str(path),
        filename=path.name,
        media_type="application/octet-stream",
    )


class ZipDownloadReq(BaseModel):
    file_paths: list[str] = []   # empty = all files in item


@app.post("/api/library/{item_id}/download-zip")
async def download_library_zip(item_id: str, req: ZipDownloadReq) -> StreamingResponse:
    """Stream a ZIP of selected (or all) library files to the browser.

    Uses a pipe so the ZIP is streamed without buffering entire video files in memory.
    ZIP_STORED is used — video files are already compressed.
    """
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")

    all_files = item.get("files", [])
    if req.file_paths:
        valid_paths = {f["path"] for f in all_files}
        targets = [p for p in req.file_paths if p in valid_paths and Path(p).exists()]
    else:
        targets = [f["path"] for f in all_files if Path(f["path"]).exists()]

    if not targets:
        raise HTTPException(404, "No files available for download.")

    zip_name = re.sub(r'[\\/*?:"<>|]', "_", item["title"]) + ".zip"

    # Compute expected ZIP size (ZIP_STORED = no compression, so size is predictable).
    # Local header: 30 + len(name); central dir entry: 46 + len(name); EOCD: 22.
    total_bytes = 22
    for p_str in targets:
        name_len = len(Path(p_str).name.encode())
        size = Path(p_str).stat().st_size
        total_bytes += size + (30 + name_len) + (46 + name_len)

    r_fd, w_fd = os.pipe()

    def _write_zip() -> None:
        try:
            with os.fdopen(w_fd, "wb") as wf, zipfile.ZipFile(wf, "w", zipfile.ZIP_STORED) as zf:
                for path_str in targets:
                    p = Path(path_str)
                    zf.write(str(p), p.name)
        except Exception:
            pass  # reader will get EOF; any partial data is discarded by the browser

    threading.Thread(target=_write_zip, daemon=True).start()

    async def _read_pipe() -> AsyncGenerator[bytes, None]:
        rf = os.fdopen(r_fd, "rb")
        try:
            while True:
                chunk = await asyncio.to_thread(rf.read, 65536)
                if not chunk:
                    break
                yield chunk
        finally:
            rf.close()

    return StreamingResponse(
        _read_pipe(),
        media_type="application/zip",
        headers={
            "Content-Disposition": f'attachment; filename="{zip_name}"',
            "X-Total-Bytes": str(total_bytes),
            "Access-Control-Expose-Headers": "X-Total-Bytes",
        },
    )


@app.get("/api/events")
async def events(request: Request) -> StreamingResponse:
    q: asyncio.Queue = asyncio.Queue(maxsize=100)
    state.sse_queues.append(q)
    # Opening the dashboard = a viewer is present → shed idle prep immediately, even
    # though a page load is a GET (which doesn't stamp last_activity). The for_prep
    # idle check then keeps prep paused while the tab stays open.
    try:
        _activity_kick()
    except Exception:
        pass

    async def stream() -> AsyncGenerator[str, None]:
        yield f"event: state\ndata: {json.dumps(state_snapshot())}\n\n"
        try:
            while True:
                if await request.is_disconnected():
                    break
                try:
                    yield await asyncio.wait_for(q.get(), timeout=20.0)
                except asyncio.TimeoutError:
                    # Named `ping` event (not a bare `: comment`) so the browser
                    # EventSource fires a listener the client can observe — comment
                    # lines are invisible to JS, leaving no way to detect a dead
                    # connection that's silently gone half-open (common after a
                    # mobile device sleeps / the app is backgrounded). See the
                    # client liveness watchdog in static/index.html.
                    yield f"event: ping\ndata: {int(time.time())}\n\n"
        finally:
            if q in state.sse_queues:
                state.sse_queues.remove(q)

    return StreamingResponse(
        stream(),
        media_type="text/event-stream",
        headers={"Cache-Control": "no-cache", "X-Accel-Buffering": "no"},
    )


# ── Routes: Admin Panel ───────────────────────────────────────────────────────

@app.get("/admin", include_in_schema=False)
async def admin_page() -> FileResponse:
    return FileResponse(str(Path(__file__).parent / "static" / "admin.html"))


@app.get("/api/admin/status")
async def admin_status() -> JSONResponse:
    return JSONResponse({"enabled": bool(settings.admin_password)})


@app.post("/api/admin/login")
async def admin_login(req: AdminLoginReq) -> JSONResponse:
    if not settings.admin_password:
        raise HTTPException(503, "Admin panel is not configured (set ADMIN_PASSWORD in .env).")
    if req.password != settings.admin_password:
        raise HTTPException(401, "Incorrect admin password.")
    token = secrets.token_hex(32)
    _admin_sessions[token] = time.time() + 86400   # 24-hour session
    return JSONResponse({"ok": True, "token": token})


@app.post("/api/admin/logout")
async def admin_logout(request: Request) -> JSONResponse:
    auth = request.headers.get("authorization", "")
    token = auth[7:].strip() if auth.lower().startswith("bearer ") else ""
    _admin_sessions.pop(token, None)
    return JSONResponse({"ok": True})


# ── Routes: iOS app device pairing (M5, plan A4) ──────────────────────────────

class PairReq(BaseModel):
    admin_password: str
    label: str = ""


@app.get("/api/pair/status")
async def pair_status(request: Request) -> JSONResponse:
    """Let the client app discover whether pairing is required and whether its
    stored token is still valid (so it can show the pairing screen when needed)."""
    return JSONResponse({
        "required":         bool(settings.require_device_auth),
        "admin_configured": bool(settings.admin_password),
        "paired":           _check_device_token(request),
    })


@app.post("/api/pair")
async def pair_device(req: PairReq) -> JSONResponse:
    """Issue a long-lived device token for the iOS client (plan A4).

    The host's admin password is the pairing secret. The returned token is sent
    as `Authorization: Bearer <token>` on the device-facing endpoints (sync,
    bundle-manifest) and is enforced only when REQUIRE_DEVICE_AUTH is on."""
    if not settings.admin_password:
        raise HTTPException(503, "Pairing is unavailable — set ADMIN_PASSWORD on the host.")
    if req.admin_password != settings.admin_password:
        raise HTTPException(401, "Incorrect host password.")
    token = secrets.token_hex(32)
    _device_tokens[token] = {
        "created_at": _now_iso(),
        "last_seen":  _now_iso(),
        "label":      (req.label or "iOS device").strip()[:64],
    }
    _save_device_tokens()
    return JSONResponse({"ok": True, "token": token})


@app.delete("/api/pair")
async def unpair_device(request: Request) -> JSONResponse:
    """Revoke the calling device's own pairing token (used by the app on sign-out)."""
    tok = _request_bearer(request)
    if tok and _device_tokens.pop(tok, None) is not None:
        _save_device_tokens()
    return JSONResponse({"ok": True})


@app.get("/api/admin/devices")
async def admin_list_devices(request: Request) -> JSONResponse:
    """Admin view of paired devices (token prefix only, never the full secret)."""
    _require_admin(request)
    return JSONResponse({"devices": [
        {"id": tok[:8], "label": meta.get("label", ""),
         "created_at": meta.get("created_at", ""), "last_seen": meta.get("last_seen", "")}
        for tok, meta in _device_tokens.items()
    ]})


@app.delete("/api/admin/devices/{token_prefix}")
async def admin_revoke_device(token_prefix: str, request: Request) -> JSONResponse:
    """Admin revoke of a paired device by the 8-char id from /api/admin/devices."""
    _require_admin(request)
    victims = [t for t in _device_tokens if t[:8] == token_prefix]
    for t in victims:
        _device_tokens.pop(t, None)
    if victims:
        _save_device_tokens()
    return JSONResponse({"ok": True, "revoked": len(victims)})


