@app.get("/api/admin/ondemand-only")
async def admin_get_ondemand_only(request: Request) -> JSONResponse:
    """List shows (grouped by series) with their on-demand-only + lock flags for the
    Storage tab. Episodes downloaded individually collapse into ONE row keyed by
    `series_key`, so the admin toggles / locks the whole show at once instead of
    episode-by-episode (matching the merged-series dashboard). A season pack or an
    untagged item is its own single-item row (`item:<id>` key). Each row carries the
    member `item_ids[]` and aggregate flags: `ondemand_only`/`ondemand_only_locked`
    are true only when EVERY member is on/locked; the `*_mixed` flags mark a partial
    state so the UI can show it."""
    _require_admin(request)
    lib = await get_library()
    order: list[str] = []
    groups: dict[str, dict] = {}
    for it in lib.get("items", []):
        key = _series_key(it)
        g = groups.get(key)
        if g is None:
            g = groups[key] = {"series_key": key, "title": "", "item_ids": [],
                               "file_count": 0, "on": [], "locked": []}
            order.append(key)
        if not g["title"]:
            g["title"] = (it.get("series") or "").strip() or it.get("title", "")
        g["item_ids"].append(it.get("id", ""))
        g["file_count"] += sum(1 for f in it.get("files", [])
                               if Path(f.get("path", "")).suffix.lower() in VIDEO_EXTS)
        g["on"].append(bool(it.get("ondemand_only")))
        g["locked"].append(bool(it.get("ondemand_only_locked")))
    items = [{
        "series_key": g["series_key"],
        "title": g["title"],
        "item_ids": g["item_ids"],
        "file_count": g["file_count"],
        "ondemand_only": all(g["on"]),
        "ondemand_only_mixed": any(g["on"]) and not all(g["on"]),
        "ondemand_only_locked": all(g["locked"]),
        "ondemand_only_locked_mixed": any(g["locked"]) and not all(g["locked"]),
    } for g in (groups[k] for k in order)]
    return JSONResponse({"items": items, "hls_available": HLS_AVAILABLE})


@app.get("/api/admin/storage-breakdown")
async def admin_storage_breakdown(request: Request) -> JSONResponse:
    """Per-series storage breakdown for the Storage tab: every library item with its
    total bytes on disk, plus a per-file drill-in (source media + HLS bundle +
    sidecars) so the admin can see exactly what's consuming space.

    Bundle bytes come from the offline-cache inventory (its recursive bundle walk is
    cached / offloaded already); the source + sidecar stats run in a worker thread
    so a large library never stalls the event loop. `orphan_bytes` is bundle space
    no longer attached to any library file (purge it from the Cleanup tab)."""
    _require_admin(request)
    lib = await get_library()
    inv = await _build_offline_cache_inventory()
    bundle_by_path: dict[str, int] = {}
    for it in inv.get("items", []):
        for f in it.get("files", []):
            fp = f.get("file_path", "")
            if fp:
                bundle_by_path[fp] = bundle_by_path.get(fp, 0) + int(f.get("bytes", 0) or 0)
    orphan_bytes = sum(int(o.get("bytes", 0) or 0) for o in inv.get("orphans", []))
    data = await asyncio.to_thread(_storage_breakdown_sync, lib, bundle_by_path)
    data["orphan_bytes"]   = orphan_bytes
    data["bundles_stale_at"] = inv.get("generated_at", 0)
    data["generated_at"]   = time.time()
    return JSONResponse(data)


async def _purge_ondemand_bundles(item_id: str) -> None:
    """Background reclamation for a freshly on-demand-only item: walk the cache
    and delete the item's permanent HLS bundles. Runs detached from the request
    so the (heavy, GIL-contending) forced inventory walk + deletes never stall
    the event loop for other users — the flag is already live by the time this
    starts, so playback behaviour is correct regardless of when space is freed."""
    try:
        inv = await _build_offline_cache_inventory(force=True)
        it_inv = next((x for x in inv["items"] if x["item_id"] == item_id), None)
        if not it_inv:
            return
        for f in it_inv["files"]:
            if _offline_cache_path_active(f["cache_key"]):
                continue
            await asyncio.to_thread(_delete_cache_artifacts, f["cache_key"], f.get("root"))
        _invalidate_offline_cache_inventory()
        _invalidate_bundle_index()
    except Exception:
        log.exception("ondemand-only background bundle purge failed for %s", item_id)


async def _apply_ondemand_only(item_id: str, enabled: bool) -> dict:
    """Core on-demand-only mutation shared by the admin and user endpoints: flip
    `item["ondemand_only"]`, persist, rebuild `state.ondemand_only_items`, and —
    when enabling — cancel any in-flight prep for the item (fast, inline) and purge
    its existing permanent bundles to reclaim space.

    The flag flip + job cancel are fast and happen inline so the toggle takes
    effect immediately. The bundle purge requires a forced full-cache inventory
    walk (heavy on a large `.offline_cache/`) and is run in a DETACHED background
    task — doing it inline made the request hold the event loop long enough that
    other users couldn't load the page or act on it. Space is reclaimed shortly
    after the response returns. Raises HTTPException(404) if the item is gone."""
    lib = await get_library()
    item = next((it for it in lib["items"] if it.get("id") == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")
    item["ondemand_only"] = bool(enabled)
    await put_library(lib)
    _rebuild_ondemand_only_items(lib)

    cancelled = 0
    purging = False
    if enabled:
        # Stop any in-flight / queued prep for this item's files (fast).
        for j in list(_offline_jobs.values()):
            if (j.get("item_id") == item_id
                    and j.get("status") in ("pending", "processing", "paused")):
                # Flag the kill as intentional BEFORE terminating so _run_offline_job
                # treats the resulting non-zero exit as a clean cancel — without it a
                # full-GPU encode would retry on the transparent path (restarting,
                # ignoring the toggle) and a regular encode would surface a spurious
                # "ffmpeg failed" error. Also read by `is_stopped` so an in-flight
                # validate/repair phase bails too.
                j["_ondemand_cancelled"] = True
                proc = j.get("_proc")
                if proc is not None and proc.returncode is None:
                    try:
                        proc.terminate()
                    except Exception:
                        pass
                j["status"] = "cancelled"
                cancelled += 1
        # Reclaim existing permanent bundles in the background so the request
        # returns immediately and the loop stays free for everyone else.
        _spawn_bg(_purge_ondemand_bundles(item_id))
        purging = True
    return {"ok": True, "ondemand_only": bool(enabled),
            "purging": purging, "jobs_cancelled": cancelled}


@app.post("/api/admin/ondemand-only")
async def admin_set_ondemand_only(request: Request, body: OndemandOnlyReq) -> JSONResponse:
    """Flag (or unflag) a show as **on-demand stream only**: on-device browser
    playback uses the just-in-time pipeline and NO permanent HLS bundle is built,
    so it costs ~no disk. Enabling also cancels any in-flight prep for the item and
    purges its existing bundles to reclaim space. VLC (TV) playback is unaffected
    — it reads the source file directly. Admin can always change the flag, even when
    it's locked against non-admin dashboard users."""
    _require_admin(request)
    return JSONResponse(await _apply_ondemand_only(body.item_id, body.enabled))


@app.post("/api/admin/ondemand-only-lock")
async def admin_set_ondemand_only_lock(request: Request, body: OndemandOnlyLockReq) -> JSONResponse:
    """Lock (or unlock) an item's on-demand-only flag so **non-admin dashboard users
    can't change it** from the episode page. Admin keeps full control either way.
    Persisted as `item["ondemand_only_locked"]`."""
    _require_admin(request)
    lib = await get_library()
    item = next((it for it in lib["items"] if it.get("id") == body.item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")
    item["ondemand_only_locked"] = bool(body.locked)
    await put_library(lib)
    return JSONResponse({"ok": True, "ondemand_only_locked": bool(body.locked)})


@app.post("/api/admin/series/{series_key}/ondemand-only-lock")
async def admin_set_series_ondemand_only_lock(series_key: str, body: SeriesLockReq,
                                              request: Request) -> JSONResponse:
    """Series-wide on-demand-only lock — sets `ondemand_only_locked` on **every**
    member of a merged show so the admin locks/unlocks the whole show in one action
    (bulk-downloaded episodes render as one row in the Storage tab). Admin only.
    A season pack / untagged item is its own single-member series (`item:<id>` key),
    so this also drives the single-row case. Returns the count applied."""
    _require_admin(request)
    lib = await get_library()
    members = _items_for_series_key(lib, series_key)
    if not members:
        raise HTTPException(404, "Series not found.")
    for it in members:
        it["ondemand_only_locked"] = bool(body.locked)
    await put_library(lib)
    return JSONResponse({"ok": True, "ondemand_only_locked": bool(body.locked),
                         "applied": len(members)})


@app.post("/api/library/{item_id}/ondemand-only")
async def set_ondemand_only(item_id: str, body: OndemandOnlyUserReq,
                            request: Request) -> JSONResponse:
    """User-facing on-demand-only toggle (the dashboard episode page). Same effect as
    the admin endpoint, but **refuses (HTTP 403) when the item is admin-locked**
    (`item["ondemand_only_locked"]`) and the requester isn't an admin."""
    lib = await get_library()
    item = next((it for it in lib["items"] if it.get("id") == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")
    if item.get("ondemand_only_locked") and not _check_admin(request):
        raise HTTPException(403, "This setting is locked by the administrator.")
    return JSONResponse(await _apply_ondemand_only(item_id, body.enabled))


@app.post("/api/library/series/{series_key}/ondemand-only")
async def set_series_ondemand_only(series_key: str, body: OndemandOnlyUserReq,
                                   request: Request) -> JSONResponse:
    """Series-wide on-demand-only toggle for the merged-series episode page. Fans
    `_apply_ondemand_only` across every member of the series. Members that are
    admin-locked (`ondemand_only_locked`) are **skipped** for non-admins rather than
    failing the whole call — so a partly-locked show still toggles the rest. Returns
    the count applied and skipped. Raises 404 if the series has no members, or 403
    only when EVERY member is locked (nothing the requester may change)."""
    is_admin = _check_admin(request)
    lib = await get_library()
    members = _items_for_series_key(lib, series_key)
    if not members:
        raise HTTPException(404, "Series not found.")

    changeable = [it["id"] for it in members
                  if is_admin or not it.get("ondemand_only_locked")]
    skipped_locked = len(members) - len(changeable)
    if not changeable:
        raise HTTPException(403, "This setting is locked by the administrator.")

    for mid in changeable:
        # _apply_ondemand_only re-reads/persists the library per call (and rebuilds
        # state.ondemand_only_items), so looping is safe and self-consistent.
        await _apply_ondemand_only(mid, body.enabled)
    return JSONResponse({"ok": True, "ondemand_only": bool(body.enabled),
                         "applied": len(changeable), "skipped_locked": skipped_locked})


@app.get("/api/admin/cache-autopurge")
async def admin_get_cache_autopurge(request: Request) -> JSONResponse:
    """Return the orphan-cache auto-purge config + the result of the last run."""
    _require_admin(request)
    cfg = _cache_autopurge_cfg(await get_library())
    cfg["last"] = state.cache_autopurge_last or None
    return JSONResponse(cfg)


@app.post("/api/admin/cache-autopurge")
async def admin_set_cache_autopurge(request: Request, body: CacheAutopurgeReq) -> JSONResponse:
    """Save the orphan-cache auto-purge config. Clamps max_gb to 1–10000 GB. The
    next `cache_autopurge_loop` tick (≤5 min) evaluates the cap against the new
    value; nothing is purged inline here."""
    _require_admin(request)
    max_gb = max(1.0, min(10000.0, float(body.max_gb)))

    lib = await get_library()
    cp = lib.setdefault("settings", {}).setdefault("cache_autopurge", {})
    cp["enabled"] = bool(body.enabled)
    cp["max_gb"]  = max_gb
    await put_library(lib)

    cfg = _cache_autopurge_cfg(lib)
    cfg["last"] = state.cache_autopurge_last or None
    return JSONResponse({"ok": True, **cfg})


@app.get("/api/admin/auto-maintenance")
async def admin_get_auto_maintenance(request: Request) -> JSONResponse:
    """Auto-maintenance config + live backlog counts for the admin card."""
    _require_admin(request)
    lib = await get_library()
    cfg = _auto_maint_cfg(lib)
    return JSONResponse({
        **cfg,
        "analyzer_available": analyzer.is_available(),
        "ffmpeg_available":   bool(analyzer.ffmpeg_bin()),
        "fingerprint_backlog": _fingerprint_backlog(lib),
        "validate_backlog":    _validation_backlog(lib),
        "validate_running":    bool(state.auto_validate.get("running")),
        "analysis_running":    _any_analysis_running(),
    })


@app.post("/api/admin/auto-maintenance")
async def admin_set_auto_maintenance(request: Request, body: AutoMaintReq) -> JSONResponse:
    """Enable/disable the idle background fingerprint + validate workers
    (`library.json → settings.auto_maintenance`). Turning a worker off also stops
    its in-flight run: the next `background_maintenance_loop` tick won't restart
    it, and auto-validation checks the stop flag between files."""
    _require_admin(request)
    lib = await get_library()
    am = lib.setdefault("settings", {}).setdefault("auto_maintenance", {})
    am["fingerprint"] = bool(body.fingerprint)
    am["validate"]    = bool(body.validate_files)
    await put_library(lib)
    if not body.validate_files:
        state.auto_validate_stop = True   # halt an in-flight auto-validation pass
    cfg = _auto_maint_cfg(lib)
    return JSONResponse({
        "ok": True, **cfg,
        "fingerprint_backlog": _fingerprint_backlog(lib),
        "validate_backlog":    _validation_backlog(lib),
    })


# ── Background activity snapshot (admin "Activity" tab) ──────────────────────
# A single, human-readable view of everything the server is doing in the
# background RIGHT NOW, and — crucially — WHY, plus whether each piece of work
# survives a server restart / auto-update. Most background work (HLS prep, STT,
# file validation/repair, Smart Skip analysis, on-demand transcode sessions) is
# process-local with no on-disk checkpoint, so a restart or auto-update silently
# discards it. This endpoint makes that visible so an operator understands that a
# progress bar that "reset" wasn't a bug — the process restarted under it.

def _activity_title(item_id: str, src: str, items_by_id: dict) -> str:
    """Best display name for a job: the library item's title, else the filename."""
    it = items_by_id.get(item_id) if item_id else None
    if it and it.get("title"):
        return it["title"]
    if src:
        try:
            return Path(src).name
        except Exception:
            pass
    return "Library content"


async def _activity_snapshot() -> dict:
    """Aggregate every in-flight background activity with a plain-English reason
    and a restart-survival flag. Read-only; safe to poll."""
    lib = await get_library()
    items_by_id = {it["id"]: it for it in lib.get("items", [])}
    now = time.time()
    acts: list[dict] = []

    def add(*, category, title, status, reason, resumes, restart_note,
            progress=None, detail="", started_at=None):
        acts.append({
            "category":   category,
            "title":      title,
            "detail":     detail,
            "status":     status,
            "progress":   (round(float(progress), 3) if progress is not None else None),
            "reason":     reason,
            "resumes_after_restart": bool(resumes),
            "restart_note": restart_note,
            "elapsed_sec": (round(now - started_at) if started_at else None),
        })

    # 1. HLS stream prep (interactive / admin force / bulk auto-prep)
    for j in _offline_jobs.values():
        st = j.get("status")
        if st not in ("pending", "processing", "paused"):
            continue
        queue = j.get("queue", "bulk")
        if queue == "interactive":
            reason = "On-device play prep — a viewer is (or recently was) playing this, so it's being prepped for smooth streaming to the browser player."
            resumes = False
            note = "The in-flight encode is discarded on restart and only re-preps if the episode is played again."
        elif queue == "admin":
            reason = "Admin Force Prep is preparing this for on-device streaming (ignores host activity and the Pause gate)."
            resumes = False
            note = "Force Prep does NOT auto-resume after a restart — re-run Force Prep from the System tab to continue."
        else:  # bulk
            reason = "Automatic Stream Prep is preparing un-prepped library files for on-device streaming."
            resumes = True
            note = "The in-flight encode restarts from scratch (HLS prep can't checkpoint), but Automatic Stream Prep re-queues remaining files automatically after restart."
        if st == "paused":
            reason += " (Currently paused — held at the prep gate.)"
        add(category="Stream Prep",
            title=_activity_title(j.get("item_id", ""), j.get("src", ""), items_by_id),
            status=st, reason=reason, resumes=resumes, restart_note=note,
            progress=j.get("progress"), started_at=j.get("started_at"))

    # 2. AI subtitles (whisper.cpp STT)
    for j in _stt_jobs.values():
        st = j.get("status")
        if st not in ("pending", "processing", "paused"):
            continue
        queue = j.get("queue", "bulk")
        resumes = (queue == "bulk")
        reason = ("AI subtitle generation (whisper.cpp) for a file with no usable "
                  "subtitle track" + (" — requested for the file now playing." if queue == "interactive"
                  else ", from Automatic Stream Prep."))
        note = ("Transcription has no checkpoint; an interrupted run restarts from the beginning. "
                + ("Auto-prep re-queues it after restart." if resumes
                   else "It only restarts if the file is played again."))
        if st == "paused":
            reason += " (Currently paused.)"
        add(category="AI Subtitles",
            title=_activity_title(j.get("item_id", ""), j.get("src", ""), items_by_id),
            status=st, reason=reason, resumes=resumes, restart_note=note,
            progress=j.get("progress"), started_at=j.get("started_at"))

    # 3. Torrent downloads (qBittorrent — separate process, persists state)
    for it in lib.get("items", []):
        if it.get("status") != "downloading":
            continue
        add(category="Download",
            title=it.get("title") or "Library content",
            status="downloading",
            reason="A library torrent is still downloading from peers (subject to any idle/night download window and seeding limits).",
            resumes=True,
            restart_note="qBittorrent stores download state independently of this server and resumes automatically after a restart.",
            progress=None)

    # 4. File validation scan
    fv = state.file_validation or {}
    if fv.get("running"):
        total = fv.get("total") or 0
        scanned = fv.get("scanned") or 0
        add(category="File Validation",
            title=("Whole library" if (fv.get("scope") in ("all", "", None)) else _activity_title(fv.get("scope", ""), "", items_by_id)),
            status="running",
            detail=fv.get("current_name", ""),
            reason="Deep-decoding source files with ffmpeg to find corrupt/unreadable media (independent of qBit's piece check).",
            resumes=False,
            restart_note="Validation state lives only in memory and does NOT resume after a restart — re-run it from the System tab.",
            progress=(scanned / total if total else None))

    # 5. File repair run
    fr = state.file_repair or {}
    if fr.get("running"):
        total = fr.get("total") or 0
        scanned = fr.get("scanned") or 0
        add(category="File Repair",
            title=f"{total} damaged file(s)" if total else "Damaged files",
            status="running",
            detail=fr.get("current_name", ""),
            reason="Repairing damaged source files (remux, then optional re-encode); each candidate is re-validated before it replaces the original.",
            resumes=False,
            restart_note="Repair state is in-memory and does NOT resume after a restart — a file already replaced stays repaired; the rest must be re-run.",
            progress=(scanned / total if total else None))

    # 5a. Source compression run
    fc = state.file_compression or {}
    if fc.get("running"):
        total = fc.get("total") or 0
        scanned = fc.get("scanned") or 0
        freed = max(0, (fc.get("bytes_before") or 0) - (fc.get("bytes_after") or 0))
        codec = (fc.get("codec") or "").upper()
        add(category="Compression",
            title=("Whole library" if (fc.get("scope") in ("all", "", None)) else _activity_title(fc.get("scope", ""), "", items_by_id)),
            status="running",
            detail=fc.get("current_name", ""),
            reason=f"Re-encoding source files smaller ({codec or 'video'}) to reclaim disk space; "
                   f"{human_size(freed)} freed so far.",
            resumes=False,
            restart_note="Compression state is in-memory and does NOT resume after a restart — a file already replaced stays compressed; the rest must be re-run from the Storage tab.",
            progress=(scanned / total if total else None))

    # 5b. Automatic background validation (idle-gated, resumable)
    av = state.auto_validate or {}
    if av.get("running"):
        total = av.get("total") or 0
        scanned = av.get("scanned") or 0
        add(category="File Validation",
            title="Automatic validation",
            status="running",
            detail=av.get("current_name", ""),
            reason="Background source-file validation — deep-decoding files that have never been validated, while the box is idle.",
            resumes=True,
            restart_note="Each verdict is persisted per file, so this resumes right where it left off after a restart or auto-update (it does not start over).",
            progress=(scanned / total if total else None))

    # 6. Smart Skip analysis
    for sk, job in (state.analysis_jobs or {}).items():
        if job.get("status") != "running":
            continue
        total = job.get("total") or 0
        cur = job.get("current") or 0
        add(category="Smart Skip",
            title=sk or "Series analysis",
            status="running",
            detail=job.get("message", "") or job.get("stage", ""),
            reason="Analyzing episodes to detect intro/credits boundaries so the player can offer skip buttons.",
            resumes=False,
            restart_note="Analysis is in-memory; an interrupted run restarts from scratch, but background maintenance re-picks the series automatically once the box is idle (if auto-fingerprint is on).",
            # Prefer the analyzer's monotonic all-stages fraction; the per-stage
            # current/total resets at each stage boundary (looks like restarts).
            progress=(job.get("progress") if job.get("progress") is not None
                      else (cur / total if total else None)))

    # 7. On-demand transcode sessions (live just-in-time streaming)
    try:
        od_n = len(_od_sessions)
    except Exception:
        od_n = 0
    if od_n:
        add(category="On-Demand Stream",
            title=f"{od_n} live transcode session(s)",
            status="processing",
            reason="A viewer is streaming a non-prepped file; ffmpeg transcodes HLS segments just-in-time as they watch.",
            resumes=False,
            restart_note="Tied to the live viewer — sessions end on restart and resume only when the viewer resumes playback.")

    # ── Outstanding / idle work: what HASN'T been done, and why it isn't running ──
    # Distinct from `activities` (running NOW). This is the backlog — the answer to
    # "lots of shows aren't fingerprinted/validated, why is nothing happening?".
    cfg = _auto_prep_cfg(lib)
    maint = _auto_maint_cfg(lib)
    outstanding: list[dict] = []

    prep_mode = cfg.get("mode", "off")
    prep_n = _prep_backlog_from_snapshot()
    if prep_n:
        outstanding.append({
            "category": "Stream Prep",
            "count": prep_n,
            "label": f"{prep_n} file(s) not prepped for on-device streaming",
            "auto": prep_mode != "off",
            "why": ("Automatic Stream Prep is ON (always) — these prep in the background."
                    if prep_mode == "always" else
                    "Automatic Stream Prep runs WHEN IDLE — these prep once the box is idle."
                    if prep_mode == "idle" else
                    "Automatic Stream Prep is OFF — nothing preps unless you Prep a row or run admin Force Prep."),
        })

    fp_n = _fingerprint_backlog(lib)
    if fp_n:
        outstanding.append({
            "category": "Smart Skip",
            "count": fp_n,
            "label": f"{fp_n} file(s) not fingerprinted for intro/credits skip",
            "auto": maint["fingerprint"],
            "why": ("Auto-fingerprint is ON — these run automatically, one series at a time, while the box is idle."
                    if maint["fingerprint"] else
                    "Auto-fingerprint is OFF — enable it under Automatic Maintenance, or analyze a series by hand on the Smart Skip tab."),
        })

    val_n = _validation_backlog(lib)
    if val_n:
        outstanding.append({
            "category": "File Validation",
            "count": val_n,
            "label": f"{val_n} file(s) never validated for corruption",
            "auto": maint["validate"],
            "why": ("Auto-validate is ON — these deep-decode automatically, one at a time, while the box is idle (and the result is remembered)."
                    if maint["validate"] else
                    "Auto-validate is OFF — enable it under Automatic Maintenance, or run a scan from the System tab."),
        })

    fragile = sum(1 for a in acts if not a["resumes_after_restart"])
    return {
        "generated_at": _now_iso(),
        "host_busy": await _machine_in_use(300),
        "gates": {
            "prep_paused":     state.prep_paused,
            "prep_pause_reason": ("Bulk stream prep is paused — the manual Pause control or activity "
                                  "returning in idle Auto-Prep mode holds it at the gate."
                                  if state.prep_paused else ""),
            "auto_prep_mode":  prep_mode,
            "admin_prep_stop": state.admin_prep_stop,
            "vpn_secure":      state.vpn_secure,
            "auto_fingerprint": maint["fingerprint"],
            "auto_validate":    maint["validate"],
        },
        "activities": acts,
        "count": len(acts),
        "fragile_count": fragile,
        "outstanding": outstanding,
    }


@app.get("/api/admin/activity")
async def admin_activity(request: Request) -> JSONResponse:
    """Unified background-activity view: what's running, why, and whether it
    survives a restart/auto-update. Drives the admin Activity tab."""
    _require_admin(request)
    return JSONResponse(await _activity_snapshot())


def _subtitle_language_options() -> list[dict]:
    """The 3-letter language options for the admin subtitle-language picker."""
    return [{"code": c, "name": n}
            for c, n in sorted(_LANG_NAMES.items(), key=lambda kv: kv[1])
            if n and len(c) == 3]


@app.get("/api/admin/stt")
async def admin_get_stt(request: Request) -> JSONResponse:
    """Return the auto-subtitle (STT) config + whether the host can actually run
    it. The preferred language lives in the unified subtitle policy
    (`/api/admin/subtitles`), so it's reported but not editable here."""
    _require_admin(request)
    cfg = _stt_cfg(await get_library())
    cfg["available"] = _stt_available()
    return JSONResponse(cfg)


@app.post("/api/admin/stt")
async def admin_set_stt(request: Request, body: SttConfigReq) -> JSONResponse:
    """Save the STT config (enabled + translate). The preferred language is owned
    by the unified subtitle policy (`POST /api/admin/subtitles`), not here."""
    _require_admin(request)
    lib = await get_library()
    s = lib.setdefault("settings", {}).setdefault("stt", {})
    s["enabled"]   = bool(body.enabled)
    s["translate"] = bool(body.translate)
    await put_library(lib)
    cfg = _stt_cfg(lib)
    cfg["available"] = _stt_available()
    return JSONResponse({"ok": True, **cfg})


@app.get("/api/admin/subtitles")
async def admin_get_subtitles(request: Request) -> JSONResponse:
    """Return the unified subtitle policy (preferred language, subs on/off by
    default, auto-search-online) + the language option list for the picker."""
    _require_admin(request)
    cfg = _subs_cfg(await get_library())
    cfg["languages"] = _subtitle_language_options()
    return JSONResponse(cfg)


@app.post("/api/admin/subtitles")
async def admin_set_subtitles(request: Request, body: SubsConfigReq) -> JSONResponse:
    """Save the unified subtitle policy. `default_language` is canonicalized to a
    3-letter code; "" means "Any" (no preferred language). This same language
    also drives AI generation (`_stt_cfg` reads it) and the search default."""
    _require_admin(request)
    lib = await get_library()
    s = lib.setdefault("settings", {}).setdefault("subtitles", {})
    s["default_language"] = _canon_lang(body.default_language) if body.default_language.strip() else ""
    s["on_by_default"]    = bool(body.on_by_default)
    s["auto_search"]      = bool(body.auto_search)
    s["upgrade_late_subs"] = bool(body.upgrade_late_subs)
    s["single_option"]     = bool(body.single_option)
    await put_library(lib)
    cfg = _subs_cfg(lib)
    state.subtitle_default_language = cfg["default_language"]
    state.subtitle_upgrade_late = cfg["upgrade_late_subs"]
    state.subtitle_single_option = cfg["single_option"]
    await broadcast("state", state_snapshot())
    return JSONResponse({"ok": True, **cfg})


class VpnKillswitchReq(BaseModel):
    block_ui: bool


@app.get("/api/admin/vpn-killswitch")
async def admin_get_vpn_killswitch(request: Request) -> JSONResponse:
    """Return the VPN kill-switch policy. `block_ui=true` ⇒ a VPN drop locks the
    whole dashboard behind the overlay; `false` ⇒ only qBittorrent is killed (it's
    killed either way) and the rest of the UI keeps working."""
    _require_admin(request)
    return JSONResponse(_vpn_killswitch_cfg(await get_library()))


@app.post("/api/admin/vpn-killswitch")
async def admin_set_vpn_killswitch(request: Request, body: VpnKillswitchReq) -> JSONResponse:
    """Save the VPN kill-switch policy. `block_ui` only governs the UI lockout —
    qBittorrent is always killed when the VPN is down (enforced unconditionally by
    `vpn_guard` and `watchdog.py`). Broadcasts a state snapshot so every client's
    overlay updates live (e.g. the overlay clears the moment block_ui is turned
    off while the VPN happens to be down)."""
    _require_admin(request)
    lib = await get_library()
    s = lib.setdefault("settings", {}).setdefault("vpn_killswitch", {})
    s["block_ui"] = bool(body.block_ui)
    await put_library(lib)
    cfg = _vpn_killswitch_cfg(lib)
    state.vpn_block_ui = cfg["block_ui"]
    await broadcast("state", state_snapshot())
    return JSONResponse({"ok": True, **cfg})


def _network_status(lib: dict) -> dict:
    """Enumerate physical LAN adapters + resolve the active primary IP.

    Shape: `{preferred_adapter, active_ip, used_fallback, fallback_reason,
    adapters:[{name, ip, priority, is_preferred, is_active}]}`. `active_ip` is
    the IP everything (mDNS, redirect target, printed URL) currently resolves to.
    """
    import netadapters
    name = _network_cfg(lib)["preferred_adapter"]
    adapters = netadapters.list_adapters()
    active_ip, used_fallback, reason = netadapters.resolve_preferred(name, adapters)
    return {
        "preferred_adapter": name,
        "active_ip": active_ip,
        "used_fallback": used_fallback,
        "fallback_reason": reason,
        "adapters": [
            {
                "name": a["name"],
                "ip": a["ip"],
                "priority": a["priority"],
                "is_preferred": bool(name) and a["name"] == name,
                "is_active": a["ip"] == active_ip,
            }
            for a in adapters
        ],
    }


@app.get("/api/admin/network")
async def admin_get_network(request: Request) -> JSONResponse:
    """List the host's physical network adapters + the admin-selected primary.

    `active_ip` is whatever the server currently advertises (mDNS / redirect
    target); when the preferred adapter is offline, `used_fallback` is true and
    `fallback_reason` explains which adapter was used instead."""
    _require_admin(request)
    return JSONResponse(_network_status(await get_library()))


@app.post("/api/admin/network")
async def admin_set_network(request: Request, body: NetworkReq) -> JSONResponse:
    """Choose which physical adapter is the server's primary. Stores the interface
    *name* (survives DHCP IP changes); "" restores auto-pick. The redirect
    middleware re-points immediately (it reads `state.preferred_adapter`); mDNS
    re-advertises within one keepalive cycle. Validated against the live adapter
    list so a typo can't silently strand every other adapter on a dead target."""
    _require_admin(request)
    name = (body.preferred_adapter or "").strip()
    import netadapters
    adapters = netadapters.list_adapters()
    if name and name not in {a["name"] for a in adapters}:
        names = ", ".join(a["name"] for a in adapters) or "(none detected)"
        raise HTTPException(400, f"Unknown network adapter '{name}'. Available: {names}")
    lib = await get_library()
    net = lib.setdefault("settings", {}).setdefault("network", {})
    net["preferred_adapter"] = name
    await put_library(lib)
    state.preferred_adapter = name
    return JSONResponse({"ok": True, **_network_status(lib)})


@app.get("/api/admin/qbit-limits")
async def admin_get_qbit_limits(request: Request) -> JSONResponse:
    """Return qBittorrent's global seeding-ratio limit + max up/down speeds. Read
    live from qBit (the source of truth — it persists them in its own config), so
    the payload is `{ok: false}` when qBit isn't reachable."""
    _require_admin(request)
    return JSONResponse(await qbit_global_limits())


@app.post("/api/admin/qbit-limits")
async def admin_set_qbit_limits(request: Request, body: QbitLimitsReq) -> JSONResponse:
    """Write the global ratio limit + speed caps to qBittorrent. These are global
    qBit settings (apply to every torrent — stream-now and library) and persist in
    qBit's own config. The ratio action is fixed to 'pause' (max_ratio_act=0) so a
    torrent stops seeding — keeping its files on disk — the moment the ratio is hit
    (e.g. a 1.0 ratio stops a 10 GB show after it has uploaded 10 GB). Speeds are
    bytes/sec, 0 = unlimited."""
    _require_admin(request)
    ratio = max(0.0, min(9998.0, float(body.ratio)))
    dl = max(0, int(body.dl_limit_bytes))
    up = max(0, int(body.up_limit_bytes))
    ok = await qbit_set_preferences({
        "max_ratio_enabled": bool(body.ratio_enabled),
        "max_ratio":         ratio,
        "max_ratio_act":     0,   # 0 = pause/stop the torrent (keep files); 1 = remove
    })
    ok = (await qbit_set_speed_limit("download", dl)) and ok
    ok = (await qbit_set_speed_limit("upload", up)) and ok
    if not ok:
        raise HTTPException(502, "Could not reach qBittorrent to apply the limits.")
    return JSONResponse({"ok": True, **(await qbit_global_limits())})


@app.get("/api/admin/components")
async def admin_components(request: Request) -> JSONResponse:
    """Status of the installable portable dependencies (ffmpeg, fpcalc, whisper
    binary, whisper model) + any in-flight install job. Polled by the admin
    Components card while an install runs. `nvenc` flags an NVIDIA GPU so the UI
    can recommend a CUDA whisper build."""
    _require_admin(request)
    payload = _component_status_payload()
    try:
        payload["nvenc"] = await _has_nvenc()
    except Exception:
        payload["nvenc"] = False
    return JSONResponse(payload)


class ComponentInstallReq(BaseModel):
    component: str
    model: str = "base"      # whisper_model only: base | small | medium
    build: str = "cpu"       # whisper only: cpu | cuda12 | cuda11


@app.post("/api/admin/components/install")
async def admin_components_install(request: Request, req: ComponentInstallReq) -> JSONResponse:
    """Download + install one portable component in the background. Poll
    /api/admin/components for progress. ffmpeg/whisper binaries are Windows-only
    here (elsewhere use the OS package manager); fpcalc + the model work anywhere.
    For whisper, `build` picks the CPU or a CUDA/cuBLAS variant."""
    _require_admin(request)
    if req.component not in _COMPONENT_KEYS:
        raise HTTPException(400, "Unknown component.")
    if req.component in ("ffmpeg", "whisper") and platform.system() != "Windows":
        raise HTTPException(400, "This component can only be auto-installed on Windows. "
                                 "Install it via your OS package manager instead.")
    if req.component == "flaresolverr" and platform.system() not in ("Windows", "Linux"):
        raise HTTPException(400, "FlareSolverr has a prebuilt binary only for Windows/Linux. "
                                 "On macOS run it via Docker instead.")
    existing = _component_jobs.get(req.component)
    if existing and existing.get("status") in ("pending", "downloading"):
        return JSONResponse({"ok": True, "status": existing["status"], "already_running": True})
    _component_jobs[req.component] = {
        "status": "pending", "progress": 0.0, "error": None,
        "component": req.component, "started_at": time.time(),
    }
    asyncio.create_task(_run_component_install(req.component, req.model, req.build))
    return JSONResponse({"ok": True, "status": "started"})


# ── Routes: Auto-Updater ──────────────────────────────────────────────────────
# Periodic git-pull + setup-rerun + service-restart, gated to the main / beta /
# alpha branches. State lives in library.json → settings.autoupdate; in-flight
# operation status is mirrored on AppState for live UI. See `updater_loop` and
# the updater.py module for the actual git plumbing.

class UpdaterConfigReq(BaseModel):
    enabled:        Optional[bool] = None
    branch:         Optional[str]  = None     # main | beta | alpha (any branch when dev_mode)
    interval_hours: Optional[int]  = None     # 1-168
    auto_apply:     Optional[bool] = None
    dev_mode:       Optional[bool] = None     # "show all branches" — relax the branch gate


class UpdaterCommitReq(BaseModel):
    commit: str                      # 7–40 hex chars — pin HEAD to this exact build
    dev_mode: Optional[bool] = None  # picker's "show all branches" state; required (commit-pin is dev-only)


class UpdaterApplyReq(BaseModel):
    branch: Optional[str] = None     # default: settings.autoupdate.branch
    dev_mode: Optional[bool] = None  # picker's "show all branches" state; gates a non-canonical branch
    # When True (default), the apply ends with daemon.uninstall() +
    # daemon.install() + a full host reboot for a clean-state restart on the
    # new code. False = code-only refresh: git apply + setup.py, no service
    # reinstall, no reboot. Used by the dev "Apply files only" toggle.
    reboot: bool = True


@app.get("/api/admin/updater")
async def admin_get_updater(request: Request) -> JSONResponse:
    """Return the persisted updater config + the live git state + the current
    phase of any in-flight check/apply.

    Fields:
        cfg            — settings.autoupdate (enabled, branch, interval_hours, auto_apply, …)
        allowed_branches — the three branches the picker is allowed to select
        is_git_repo    — False ⇒ the dashboard is running from a non-git copy
                         (admin UI hides the Apply controls in that case)
        current_branch — git's view of the active branch
        current_commit — short HEAD sha
        phase          — idle | checking | applying | setup | restarting | error
        message        — human-readable detail for the current phase
        busy           — True while an admin endpoint is mid-operation
        last_output    — last 8 KiB of setup.py stdout/stderr (diagnostics)
    """
    _require_admin(request)
    lib = await get_library()
    cfg = _autoupdate_cfg(lib)
    is_repo = await updater.is_git_repo()
    return JSONResponse({
        "cfg":             cfg,
        "allowed_branches": list(updater.ALLOWED_BRANCHES),
        "is_git_repo":     is_repo,
        "current_branch":  (await updater.current_branch()) if is_repo else "",
        "current_commit":  (await updater.current_commit()) if is_repo else "",
        # True when HEAD is pinned to a raw commit (dev-mode "switch to commit").
        # Auto-update is disabled in this state — the UI surfaces a notice + the
        # admin returns to auto-update by switching back to a branch.
        "detached_head":   (await updater.is_detached_head()) if is_repo else False,
        "phase":           state.updater_phase,
        "message":         state.updater_message,
        "busy":            state.updater_busy,
        "last_output":     state.updater_last_output,
        "service_installed": await updater.service_is_installed(),
        "ui_version":      UI_VERSION,
    })


@app.get("/api/admin/updater/branches")
async def admin_updater_branches(request: Request) -> JSONResponse:
    """List every branch on origin (a fresh `git ls-remote`), for the dev-mode
    "show all branches" picker.

    Kept off the polled `/api/admin/updater` payload on purpose — it costs a
    network round-trip, so the UI fetches it only when the admin opens the
    expanded picker rather than every 4 s. `ALLOWED_BRANCHES` (main/beta/alpha)
    sort to the top; the rest follow alphabetically. Returns `[]` (not an error)
    when this isn't a git checkout so the UI can fall back to the defaults.
    """
    _require_admin(request)
    branches = await updater.list_remote_branches()
    return JSONResponse({
        "ok": True,
        "branches": branches,
        "allowed_branches": list(updater.ALLOWED_BRANCHES),
    })


@app.get("/api/admin/updater/changelog")
async def admin_updater_changelog(request: Request) -> JSONResponse:
    """Return the raw CHANGELOG.md so the admin can see what each release changed
    before (or after) updating. Lightly rendered client-side. Returns
    `{ok:false}` (not an error) when the file is missing so the UI degrades
    gracefully."""
    _require_admin(request)
    path = Path(__file__).parent / "CHANGELOG.md"
    try:
        text = await asyncio.to_thread(path.read_text, encoding="utf-8")
    except OSError as exc:
        return JSONResponse({"ok": False, "error": str(exc), "markdown": ""})
    # Cap the payload — the whole history can grow large and the UI only needs
    # the recent entries to be useful.
    if len(text) > 200_000:
        text = text[:200_000] + "\n\n…(truncated)"
    return JSONResponse({"ok": True, "markdown": text})


@app.post("/api/admin/updater/config")
async def admin_set_updater_config(request: Request, body: UpdaterConfigReq) -> JSONResponse:
    """Persist a partial update to settings.autoupdate. Fields that aren't
    provided are left untouched. Branch is validated against ALLOWED_BRANCHES
    (or, when dev_mode is on, any structurally-valid branch name);
    interval_hours is clamped to [1, 168]."""
    _require_admin(request)
    lib = await get_library()
    au = lib.setdefault("settings", {}).setdefault("autoupdate", {})
    # Apply dev_mode first so the branch validation below uses the new value.
    if body.dev_mode is not None:
        au["dev_mode"] = bool(body.dev_mode)
    allow_any = bool(au.get("dev_mode", False))
    if body.branch is not None:
        ok, err = updater.branch_allowed(body.branch, allow_any=allow_any)
        if not ok:
            raise HTTPException(400, err)
        au["branch"] = body.branch
    if body.interval_hours is not None:
        try:
            ih = int(body.interval_hours)
        except (TypeError, ValueError):
            raise HTTPException(400, "interval_hours must be an integer.")
        au["interval_hours"] = max(1, min(168, ih))
    if body.enabled is not None:
        au["enabled"] = bool(body.enabled)
    if body.auto_apply is not None:
        au["auto_apply"] = bool(body.auto_apply)
    await put_library(lib)
    return JSONResponse({"ok": True, "cfg": _autoupdate_cfg(lib)})


@app.post("/api/admin/updater/check")
async def admin_check_update(request: Request) -> JSONResponse:
    """Force an immediate git fetch + compare. Branch defaults to settings.autoupdate.branch."""
    _require_admin(request)
    if state.updater_busy:
        raise HTTPException(409, "An update operation is already running.")
    lib = await get_library()
    cfg = _autoupdate_cfg(lib)
    branch = cfg["branch"]
    async with _updater_lock:
        await _set_updater_phase("checking", f"Checking origin/{branch}…", busy=True)
        try:
            res = await _run_check(branch, allow_any=cfg["dev_mode"])
        finally:
            if state.updater_busy:
                if res.get("ok"):
                    msg = (f"Update available ({res.get('behind_by', 0)} commits)"
                           if res.get("has_update")
                           else f"Up to date with origin/{branch}.")
                    await _set_updater_phase("idle", msg, busy=False)
                else:
                    await _set_updater_phase("error", res.get("error") or "check failed",
                                            busy=False)
    return JSONResponse(res)


@app.post("/api/admin/updater/apply")
async def admin_apply_update(request: Request, body: UpdaterApplyReq) -> JSONResponse:
    """Run the full update sequence right now (git apply → setup.py → service
    reinstall → host reboot).

    `body.branch` accepts main / beta / alpha (or any branch when dev_mode is
    on) — passing a branch that differs from the current working tree triggers
    a downgrade or sidegrade (git apply handles the switch). With
    `body.reboot=False` the service reinstall and machine reboot are skipped
    (dev convenience — refresh the code without tearing the box down).

    Does NOT check `_machine_in_use` — an admin clicking Apply Now is taken at
    their word. The auto-apply loop (in `updater_loop`) is the path that defers
    to the idle gate.
    """
    _require_admin(request)
    if state.updater_busy:
        raise HTTPException(409, "An update operation is already running.")

    lib = await get_library()
    cfg = _autoupdate_cfg(lib)
    allow_any = bool(body.dev_mode) if body.dev_mode is not None else cfg["dev_mode"]
    branch = (body.branch or cfg["branch"]).strip()
    ok, err = updater.branch_allowed(branch, allow_any=allow_any)
    if not ok:
        raise HTTPException(400, err)

    res = await _run_apply(branch, reboot=bool(body.reboot), allow_any=allow_any)
    if not res.get("ok"):
        raise HTTPException(500, res.get("message") or "Update failed.")
    return JSONResponse(res)


@app.post("/api/admin/updater/switch-branch")
async def admin_switch_branch(request: Request, body: UpdaterConfigReq) -> JSONResponse:
    """Switch the working tree to a new branch (without auto-applying yet).

    Useful when an admin wants to try the alpha branch immediately — sets
    the saved branch AND does a hard checkout of origin/<branch>. Does NOT
    run setup.py or restart; the admin can follow up with /apply if they
    want the full sequence.

    `body.dev_mode` rides along so the picker's "show all branches" state takes
    effect even before a separate Save: when provided it is persisted and used
    to gate the (possibly non-canonical) target branch.
    """
    _require_admin(request)
    if state.updater_busy:
        raise HTTPException(409, "An update operation is already running.")
    if body.branch is None:
        raise HTTPException(400, "branch is required.")

    lib = await get_library()
    allow_any = bool(body.dev_mode) if body.dev_mode is not None \
        else _autoupdate_cfg(lib)["dev_mode"]
    ok, err = updater.branch_allowed(body.branch, allow_any=allow_any)
    if not ok:
        raise HTTPException(400, err)

    async with _updater_lock:
        await _set_updater_phase("applying", f"Switching to {body.branch}…", busy=True)
        res = await updater.switch_branch(body.branch, allow_any=allow_any)
        if not res.get("ok"):
            await _set_updater_phase("error", res.get("error", "switch failed"), busy=False)
            raise HTTPException(500, res.get("error", "switch failed"))

        # Persist the new branch (+ the dev-mode preference) as the default for
        # future auto-checks.
        lib = await get_library()
        au = lib.setdefault("settings", {}).setdefault("autoupdate", {})
        au["branch"] = body.branch
        if body.dev_mode is not None:
            au["dev_mode"] = bool(body.dev_mode)
        await put_library(lib)

        await _set_updater_phase("idle",
                                f"Switched to {body.branch} ({res['commit']}).",
                                busy=False)
    return JSONResponse({"ok": True, "branch": body.branch, "commit": res["commit"]})


@app.post("/api/admin/updater/switch-commit")
async def admin_switch_commit(request: Request, body: UpdaterCommitReq) -> JSONResponse:
    """Pin the working tree to a specific commit id — a detached HEAD. **Dev mode
    only.**

    Lets a developer ride an exact build by SHA (e.g. to reproduce a regression
    on `f8e920a…`). The repo ends up in a detached-HEAD state, which
    deliberately **disables the auto-updater** (no branch to track — see
    `updater_loop`'s detached-HEAD guard). The admin re-enables auto-update by
    selecting a branch and clicking Switch Branch.

    Gated on the picker's developer-mode toggle: without it the request is
    rejected, mirroring the way a non-canonical branch is gated.
    """
    _require_admin(request)
    if state.updater_busy:
        raise HTTPException(409, "An update operation is already running.")
    commit = (body.commit or "").strip()
    if not commit:
        raise HTTPException(400, "commit is required.")

    lib = await get_library()
    allow_any = bool(body.dev_mode) if body.dev_mode is not None \
        else _autoupdate_cfg(lib)["dev_mode"]
    if not allow_any:
        raise HTTPException(400, "Pinning a commit requires developer mode.")

    async with _updater_lock:
        await _set_updater_phase("applying",
                                f"Pinning to commit {commit[:12]}…", busy=True)
        res = await updater.switch_commit(commit, allow_any=allow_any)
        if not res.get("ok"):
            await _set_updater_phase("error", res.get("error", "switch failed"),
                                    busy=False)
            raise HTTPException(500, res.get("error", "switch failed"))

        # Persist the dev-mode preference if the picker sent it, so the saved
        # state matches the action just taken (the branch itself is left as-is —
        # a detached HEAD has none, and the saved branch is what Switch Branch
        # restores onto).
        if body.dev_mode is not None:
            lib = await get_library()
            au = lib.setdefault("settings", {}).setdefault("autoupdate", {})
            au["dev_mode"] = bool(body.dev_mode)
            await put_library(lib)

        await _set_updater_phase(
            "idle",
            f"Pinned to commit {res['commit']} (detached HEAD — auto-update disabled).",
            busy=False)
    return JSONResponse({"ok": True, "commit": res["commit"], "detached": True})


@app.post("/api/admin/updater/reset-hard")
async def admin_reset_hard(request: Request) -> JSONResponse:
    """Force the working tree back onto origin/<current-branch>.

    Recovery for a wedged / diverged checkout: `git fetch` + `git reset
    --hard origin/<current-branch>`, discarding local commits and edits to
    tracked files. Stays on the same branch and does no `git clean`, so
    untracked / gitignored files (library.json, .env, .offline_cache/,
    .background/) survive. Does NOT run setup.py or reboot.
    """
    _require_admin(request)
    if state.updater_busy:
        raise HTTPException(409, "An update operation is already running.")

    lib = await get_library()
    allow_any = _autoupdate_cfg(lib)["dev_mode"]
    async with _updater_lock:
        await _set_updater_phase("applying", "Resetting hard to origin…", busy=True)
        res = await updater.reset_hard(allow_any=allow_any)
        if not res.get("ok"):
            await _set_updater_phase("error", res.get("error", "reset failed"), busy=False)
            raise HTTPException(500, res.get("error", "reset failed"))
        await _set_updater_phase("idle",
                                f"Reset {res['branch']} to origin ({res['commit']}).",
                                busy=False)
    return JSONResponse({"ok": True, "branch": res["branch"], "commit": res["commit"]})


# ── Routes: Env Keys ──────────────────────────────────────────────────────────
# Companion to the auto-updater: when an update introduces a new required env
# key (e.g. an API key for a new feature), the dashboard surfaces a banner and
# the admin sets the missing keys from the Updates tab — no shell access needed.

class EnvKeysReq(BaseModel):
    # key → value. Empty string removes the entry from .env (Settings falls
    # back to its declared default). Non-listed keys are left untouched.
    keys: dict[str, str]


@app.get("/api/admin/env-keys")
async def admin_get_env_keys(request: Request) -> JSONResponse:
    """Return the env-key feature registry + which keys are currently missing.

    The non-admin UI uses /api/state.missing_env_keys (a redacted subset) to
    drive its banner; this admin-only endpoint includes the full registry
    metadata (label / description / required / secret) plus a `present` flag
    on each entry so the form can show "(set)" instead of asking again.
    """
    _require_admin(request)
    out = []
    for feat in ENV_KEY_FEATURES:
        val = getattr(settings, feat["attr"], "") or ""
        present = bool(val)
        # tmdb_api_key has the live admin-overrides path too — reflect that.
        if feat["attr"] == "tmdb_api_key" and not present:
            try:
                lib_raw = _load_lib_raw()
                ov = (lib_raw.get("settings", {}) or {}).get("admin_overrides", {}) or {}
                if ov.get("tmdb_api_key"):
                    present = True
            except Exception:
                pass
        out.append({
            "key":         feat["key"],
            "label":       feat["label"],
            "description": feat["description"],
            "required":    feat["required"],
            "secret":      feat["secret"],
            "present":     present,
        })
    return JSONResponse({"features": out})


@app.post("/api/admin/env-keys")
async def admin_set_env_keys(request: Request, body: EnvKeysReq) -> JSONResponse:
    """Write the provided keys into .env (creating it if needed), then reload
    Settings so the new values take effect for the running process without
    requiring a service restart.

    Only keys listed in ENV_KEY_FEATURES are accepted — the endpoint can't be
    used as a generic .env editor.
    """
    _require_admin(request)
    allowed = {feat["key"] for feat in ENV_KEY_FEATURES}
    sanitised: dict[str, str] = {}
    for k, v in (body.keys or {}).items():
        if k not in allowed:
            raise HTTPException(400, f"Env key '{k}' is not in the writable feature registry.")
        # Strip newlines and surrounding whitespace; never write multi-line values.
        sanitised[k] = (v or "").replace("\r", "").replace("\n", "").strip()
    written = _write_env_keys(sanitised)
    _reload_settings()
    # Broadcast immediately so the banner clears on every connected client.
    try:
        await broadcast("state", state_snapshot())
    except Exception:
        pass
    return JSONResponse({"ok": True, "written": written,
                         "missing_env_keys": _missing_env_keys()})


# ── Routes: Idle Background Video ─────────────────────────────────────────────

@app.get("/api/admin/background-video")
async def admin_get_background_video(request: Request) -> JSONResponse:
    _require_admin(request)
    lib = await get_library()
    bg = lib.get("settings", {}).get("background_video") or {}
    path = bg.get("path", "")
    exists = bool(path) and Path(path).exists()
    size = Path(path).stat().st_size if exists else 0
    return JSONResponse({
        "name":              bg.get("name", ""),
        "volume":            int(bg.get("volume", 50)),
        "enabled":           bool(bg.get("enabled", True)) if bg else False,
        "exists":            exists,
        "size_bytes":        size,
        "currently_playing": state.background_playing,
    })


@app.post("/api/admin/background-video")
async def admin_upload_background_video(
    request: Request,
    file: UploadFile = File(...),
) -> JSONResponse:
    _require_admin(request)
    filename = Path(file.filename or "background").name
    if not filename or Path(filename).suffix.lower() not in VIDEO_EXTS:
        raise HTTPException(400, "File must be a supported video format.")
    BACKGROUND_DIR.mkdir(parents=True, exist_ok=True)
    # Wipe any existing background file(s) so disk usage stays bounded
    for old in BACKGROUND_DIR.iterdir():
        try:
            old.unlink()
        except Exception:
            pass
    dest = BACKGROUND_DIR / filename
    with open(dest, "wb") as f:
        while chunk := await file.read(1024 * 1024):
            f.write(chunk)
    lib = await get_library()
    bg_settings = lib.setdefault("settings", {}).setdefault("background_video", {})
    bg_settings["path"]    = str(dest.resolve())
    bg_settings["name"]    = dest.name
    bg_settings.setdefault("volume", 50)
    bg_settings.setdefault("enabled", True)
    await put_library(lib)
    # If bg was already on screen, swap in the new file immediately
    if state.background_playing:
        asyncio.create_task(_play_background_video())
    return JSONResponse({
        "ok":         True,
        "name":       dest.name,
        "size_bytes": dest.stat().st_size,
    })


@app.delete("/api/admin/background-video")
async def admin_delete_background_video(request: Request) -> JSONResponse:
    _require_admin(request)
    lib = await get_library()
    bg = lib.get("settings", {}).get("background_video") or {}
    path = bg.get("path", "")
    if path:
        try:
            Path(path).unlink()
        except Exception:
            pass
    if "background_video" in lib.get("settings", {}):
        lib["settings"].pop("background_video", None)
        await put_library(lib)
    if state.background_playing:
        state.background_playing = False
        state.vlc_volume = state.user_volume_before_bg
        await vlc("pl_stop")
    return JSONResponse({"ok": True})


@app.post("/api/admin/background-video/volume")
async def admin_set_background_volume(request: Request, req: BackgroundVolumeReq) -> JSONResponse:
    _require_admin(request)
    capped = max(0, min(200, int(req.volume)))
    lib = await get_library()
    bg_settings = lib.setdefault("settings", {}).setdefault("background_video", {})
    bg_settings["volume"] = capped
    await put_library(lib)
    # Apply the new volume live if bg is on screen right now
    if state.background_playing:
        cap = await _global_max_volume()
        applied = min(capped, cap)
        raw = max(0, min(512, round(applied / 100 * 256)))
        await vlc("volume", val=str(raw))
        state.vlc_volume = applied
        await broadcast("state", state_snapshot())
    return JSONResponse({"ok": True, "volume": capped})


@app.post("/api/admin/background-video/enabled")
async def admin_set_background_enabled(request: Request, req: BackgroundEnabledReq) -> JSONResponse:
    _require_admin(request)
    lib = await get_library()
    bg_settings = lib.setdefault("settings", {}).setdefault("background_video", {})
    bg_settings["enabled"] = bool(req.enabled)
    await put_library(lib)
    if not req.enabled and state.background_playing:
        state.background_playing = False
        state.vlc_volume = state.user_volume_before_bg
        await vlc("pl_stop")
    return JSONResponse({"ok": True, "enabled": bool(req.enabled)})


# ── Routes: Stream-to-Device prep + HLS streaming ────────────────────────────
#
# These endpoints prepare an HLS bundle of any library file so the device's
# local <video> can stream it via hls.js (Chrome/Firefox/Edge) or Safari
# native HLS playback:
#   1. Client POSTs /api/library/{id}/offline-prepare with a file_path.
#   2. Server hashes the source into a cache key. If a bundle directory
#      `<sha>/master.m3u8` already exists, returns master_url + audios[] +
#      subtitles[] from meta.json. Otherwise kicks off a single ffmpeg job
#      that maps the video + every audio track + every text subtitle into
#      one HLS bundle and returns {ready:false, job_id, operation:"hls"}.
#   3. Client polls /api/library/offline-job/{job_id} until status=="done",
#      then hands master_url to hls.js (or sets <video>.src on Safari).
#      Per-rendition playlists + fmp4 segments are served from
#      /api/library/offline-cache/<sha>/<filename>.
#   4. Subtitles, skip-data, and the saved track picks all come back in the
#      same /offline-prepare response; the client wires them into the audio
#      / subtitle dropdowns and the skip-offer logic.
#
# The `offline` token in the endpoint paths is a historical artifact — these
# powered the older "download to device" Handoff feature. The cache namespace
# stays for backwards compatibility; the user-facing UX is stream-to-device.
# See docs/STREAMING.md for the full design.

# Legacy central cache root. As of v8 each file's HLS bundle lives *beside the
# media* in `<file_dir>/.streamlink_cache/<key>/` (so it travels with the series
# on a move). This central dir is kept only so the startup migration
# (`_migrate_offline_cache_layout`) can find and relocate pre-v8 bundles, and so
# the cache inventory still surfaces any stragglers as orphans to purge.
OFFLINE_CACHE = Path(__file__).parent / ".offline_cache"
# Per-media-file bundle directory name. Lives inside each source file's folder.
OFFLINE_CACHE_DIRNAME = ".streamlink_cache"
# Bump this when offline-output requirements change (codec rules, ffmpeg args,
# cache layout) so previously-cached bundles built by older logic get rebuilt
# on next request. v3-hls switched single-MP4 output to per-source HLS bundles;
# v4-hls moved subtitles out of the (broken) in-manifest renditions into
# standalone sub_<i>.vtt sidecars; v5-hls pinned the fmp4 init filename
# (-hls_fmp4_init_filename init_%v.mp4); v6-hls makes every output a bare name
# and runs ffmpeg with cwd=<bundle dir> so the init segment actually lands in
# the bundle on Windows (backslash playlist paths otherwise misdirect it → the
# player 404s init_video.mp4 and stalls with fragLoadError); v7-hls-abr emits
# multiple video variants (Original + 720p + 480p, capped at source height) so
# the player can offer Auto/manual quality switching; v8-colocated stores each
# bundle beside its source file and keys it path/mtime-independently (name|size)
# so a series move (even cross-device) never invalidates the cache.
OFFLINE_CACHE_VERSION = "v8-colocated"
# The pre-v8 key formula, kept ONLY so the startup migration can locate old
# central bundles by their original `<version>|<abs_path>|<mtime>|<size>` hash.
_LEGACY_OFFLINE_CACHE_VERSION = "v7-hls-abr"

# Stream-to-device (HLS prep) is unavailable on macOS hosts. ffmpeg/ffprobe run
# as children of the (non-GUI) server process, and macOS TCC blocks them from
# reading media in the user's protected ~/Downloads / ~/Desktop / ~/Documents —
# every prep would abort at the probe step with "Operation not permitted". VLC
# ("On TV") is unaffected because it's a separate, individually-granted app.
HLS_AVAILABLE = platform.system() != "Darwin"
HLS_UNAVAILABLE_MSG = (
    "Stream-to-device isn’t available on macOS hosts — the server can’t read "
    "media in TCC-protected folders. Use “On TV (VLC)” instead."
)
# Cap ffmpeg worker threads for offline prep so bulk Save Offline on a 30+ episode
# show can't saturate every core on the host. The browser and OS need headroom —
# without this, ffmpeg pegs all cores and the dashboard becomes unresponsive.
# Only used on the CPU (libx264) path; NVENC offloads to the GPU and ignores it.
OFFLINE_FFMPEG_THREADS = 2

# Watchdog timeout (seconds) for the all-GPU prep path only. The cuda-resident
# decode→scale→encode pipeline can occasionally DEADLOCK ffmpeg (NVDEC surface
# pool / muxer backpressure): it wedges at low CPU+GPU with no progress and no
# exit, so neither the failure-retry nor a crash supervisor would ever fire. If
# job["progress"] doesn't advance for this long while the encode is alive, we
# kill ffmpeg and let _run_offline_job retry on the transparent -hwaccel path.
# Generous enough that a genuinely-encoding job (out_time ticks every ~second)
# never trips it; only a true stall does.
GPU_STALL_TIMEOUT_SECS = 90

# Lower ffmpeg's OS scheduling priority so a bulk prep can't starve the web
# server (the asyncio event loop), VLC playback, or qBit — the whole point of
# "the website still works while prepping". On Windows we pass
# BELOW_NORMAL_PRIORITY_CLASS (== 0x00004000) via creationflags (also tames the
# NVIDIA driver's DPC/ISR "System Interrupts" storm during a fast NVENC encode).
# On POSIX we prepend `nice -n 10` to the command (preferred over preexec_fn,
# which is fork-unsafe in a threaded process); ffmpeg then yields CPU to every
# normal-priority process. Falls back to no-nice if the `nice` binary is absent.
_FFMPEG_SUBPROCESS_KW: dict = {}
if sys.platform == "win32":
    _FFMPEG_SUBPROCESS_KW["creationflags"] = 0x00004000  # BELOW_NORMAL_PRIORITY_CLASS

def _ffmpeg_nice_prefix() -> list[str]:
    """`['nice','-n','10']` on POSIX when available, else `[]` (Windows uses
    creationflags instead)."""
    if os.name == "posix" and shutil.which("nice"):
        return ["nice", "-n", "10"]
    return []


def _raise_own_priority() -> None:
    """Raise the StreamLink server process ABOVE normal priority so its
    control / UI / VLC-control request handling stays snappy even when a
    background prep (or anything else) is saturating the CPU.

    The server is overwhelmingly I/O-bound, so a high priority just lets its
    short request bursts preempt the encoder — it doesn't hog the box when idle.
    Combined with prep ffmpeg running BELOW normal (and the analyzer likewise),
    StreamLink's core path decisively wins the CPU. Both the HTTP and HTTPS
    uvicorn processes run this (each imports `main` → `lifespan`).

    Best-effort — never crashes startup:
    - Windows: HIGH_PRIORITY_CLASS (allowed for one's own process without admin;
      REALTIME is deliberately avoided — it can starve OS/driver threads).
    - POSIX: a negative nice, which needs privilege (root / CAP_SYS_NICE, e.g.
      the installed system service). Tries a strong boost, backs off, then gives
      up — even at nice 0 the de-prioritized encoder still yields to the server.
    """
    try:
        p = psutil.Process()
    except Exception:
        return
    try:
        if sys.platform == "win32":
            p.nice(psutil.HIGH_PRIORITY_CLASS)
            print("[priority] StreamLink server set to HIGH_PRIORITY_CLASS")
        else:
            for target in (-10, -5, -1):
                try:
                    p.nice(target)
                    print(f"[priority] StreamLink server niceness set to {target}")
                    break
                except (psutil.AccessDenied, PermissionError, OSError):
                    continue
            else:
                print("[priority] could not raise server niceness (needs root / "
                      "CAP_SYS_NICE) — prep/analyzer are still de-prioritized below it")
    except Exception as exc:
        print(f"[priority] could not raise server priority: {exc}")
# Lazy-probed once per process: True if this ffmpeg can open an h264_nvenc session
# on the host's GPU. Pascal (GTX 10xx) and newer all qualify; the only failure
# modes are (a) ffmpeg built without --enable-nvenc, (b) no NVIDIA driver loaded,
# (c) headless containers without /dev/nvidia*. We fall back to libx264 silently.
_nvenc_probe: dict[str, bool] = {}
_offline_jobs: dict[str, dict] = {}   # job_id → {id, src, out, status, operation, progress, error, started_at}
_stt_jobs: dict[str, dict] = {}       # job_id → {id, src, item_id, status, progress, error, tracks, ...}
_stt_available_probe: dict[str, bool] = {}   # cached stt.is_available() (see _stt_available)

# Cap how many ffmpeg prep jobs can run AT THE SAME TIME. Without this,
# /prep-all on a 77-episode pack fires asyncio.create_task for every file,
# spawning 77 simultaneous ffmpeg processes — host CPU is pegged, and
# consumer NVIDIA GPUs (Pascal/Turing) silently reject NVENC sessions past
# their 2–3 concurrent-encoder limit, so most jobs error out before
# emitting a single frame. Jobs stay in `pending` until they grab the
# semaphore; pending jobs are still surfaced by /prep-status and
# /api/offline-active so the UI shows the queue correctly.
OFFLINE_JOB_CONCURRENCY = 1
_OFFLINE_JOB_SEM: Optional[asyncio.Semaphore] = None

def _offline_job_sem() -> asyncio.Semaphore:
    # Lazily constructed so the semaphore binds to the running event loop on
    # first use (asyncio.Semaphore() at import time would attach to whatever
    # loop happened to be current, which uvicorn replaces on startup).
    global _OFFLINE_JOB_SEM
    if _OFFLINE_JOB_SEM is None:
        _OFFLINE_JOB_SEM = asyncio.Semaphore(OFFLINE_JOB_CONCURRENCY)
    return _OFFLINE_JOB_SEM


async def _has_nvenc() -> bool:
    """Detect whether ffmpeg can actually open an h264_nvenc session right now."""
    if "result" in _nvenc_probe:
        return _nvenc_probe["result"]
    ffmpeg = analyzer.ffmpeg_bin()
    if not ffmpeg:
        _nvenc_probe["result"] = False
        return False
    # Step 1: is the encoder compiled in at all?
    try:
        proc = await asyncio.create_subprocess_exec(
            ffmpeg, "-hide_banner", "-encoders",
            stdout=asyncio.subprocess.PIPE,
            stderr=asyncio.subprocess.DEVNULL,
        )
        out, _ = await proc.communicate()
        if b"h264_nvenc" not in (out or b""):
            _nvenc_probe["result"] = False
            print("[offline] h264_nvenc not compiled into ffmpeg — using libx264.")
            return False
    except Exception:
        _nvenc_probe["result"] = False
        return False
    # Step 2: can we actually open a session? An encoder can be listed even when
    # the driver/library is missing, so we try a 1-frame dummy encode.
    try:
        proc = await asyncio.create_subprocess_exec(
            ffmpeg, "-hide_banner", "-loglevel", "error",
            "-f", "lavfi", "-i", "color=size=64x64:duration=0.04:rate=25",
            "-c:v", "h264_nvenc", "-frames:v", "1", "-f", "null", "-",
            stdout=asyncio.subprocess.DEVNULL,
            stderr=asyncio.subprocess.PIPE,
        )
        _, err = await proc.communicate()
        ok = proc.returncode == 0
        if not ok:
            tail = (err or b"").decode("utf-8", "replace").strip().splitlines()[-1:]
            print(f"[offline] NVENC probe failed — using libx264. ({'; '.join(tail) or 'no detail'})")
    except Exception:
        ok = False
    _nvenc_probe["result"] = ok
    if ok:
        print("[offline] NVENC available — H.264 encodes will run on the GPU.")
    return ok


# Lazy-probed once per process: True if this ffmpeg exposes the `scale_cuda`
# filter, which the all-GPU prep pipeline needs to resize ON the GPU (keeping
# decode→scale→encode resident in VRAM). Gyan/BtbN "full" builds carry it;
# some "essentials" builds compile NVENC but not the CUDA filters, so we probe
# and fall back to the transparent `-hwaccel cuda` path (GPU decode, CPU scale)
# when it's missing.
_cuda_scale_probe: dict[str, bool] = {}

# Source codec / pixel-format combos NVDEC decodes reliably across every
# NVENC-capable consumer GPU. The all-GPU pipeline pins the decoder output to
# `cuda` (`-hwaccel_output_format cuda`), which — unlike the transparent
# `-hwaccel cuda` — has NO software fallback: an unsupported source HARD-fails
# the encode. So we only take that path for these safe 4:2:0 sources; anything
# else (AV1 on older cards, 4:2:2/4:4:4, 12-bit, odd codecs) uses the
# transparent path instead. A genuine failure still auto-retries on the
# transparent path in _run_offline_job, but gating keeps that rare.
_NVDEC_SAFE_CODECS  = {"h264", "hevc", "h265", "mpeg2video", "vc1", "vp9"}
_NVDEC_SAFE_PIXFMTS = {"yuv420p", "yuvj420p", "yuv420p10le", "nv12", "p010le"}


async def _has_cuda_scale() -> bool:
    """True if this ffmpeg lists the scale_cuda filter (needed for all-GPU prep)."""
    if "result" in _cuda_scale_probe:
        return _cuda_scale_probe["result"]
    ffmpeg = analyzer.ffmpeg_bin()
    if not ffmpeg:
        _cuda_scale_probe["result"] = False
        return False
    try:
        proc = await asyncio.create_subprocess_exec(
            ffmpeg, "-hide_banner", "-filters",
            stdout=asyncio.subprocess.PIPE,
            stderr=asyncio.subprocess.DEVNULL,
        )
        out, _ = await proc.communicate()
        ok = b"scale_cuda" in (out or b"")
    except Exception:
        ok = False
    _cuda_scale_probe["result"] = ok
    if not ok:
        print("[offline] scale_cuda filter absent — prep will GPU-decode but "
              "CPU-scale (transparent -hwaccel cuda).")
    return ok


def _source_nvdec_safe(info: dict) -> bool:
    """True if the source is a codec+pixfmt NVDEC decodes reliably, so it's safe
    to pin the decoder output to VRAM (`-hwaccel_output_format cuda`)."""
    v = info.get("video") or {}
    codec = (v.get("codec") or "").lower()
    pix   = (v.get("pix_fmt") or "").lower()
    return codec in _NVDEC_SAFE_CODECS and pix in _NVDEC_SAFE_PIXFMTS


# Lazy-probed per source codec (+ pixfmt): can THIS box's NVDEC actually
# hardware-decode it? ffmpeg's transparent `-hwaccel cuda` is *documented* to
# fall back to software for codecs NVDEC can't handle, but in practice the
# hwaccel *initialisation* for an unsupported codec HARD-fails the whole ffmpeg
# rather than falling back — e.g. AV1 on a Pascal GTX 1060:
#   "Your platform doesn't support hardware accelerated AV1 decoding"
#   "Failed setup for format cuda: hwaccel initialisation returned error"  → rc≠0
# So before adding `-hwaccel cuda` we VERIFY NVDEC can decode the source, probing
# once per codec by hardware-decoding a single frame of a real sample. Keyed by
# codec+pixfmt because support varies by bit depth (e.g. HEVC Main vs Main12);
# when the codec is unknown we key by the sample path instead.
_hwdec_probe: dict[str, bool] = {}


async def _gpu_can_hwdecode(sample: Path, codec: str = "", pix_fmt: str = "") -> bool:
    """True if NVDEC on this box can hardware-decode `sample`. Probes once per
    codec+pixfmt (or per path when codec is unknown) by hardware-decoding one
    frame with the transparent `-hwaccel cuda`; rc≠0 ⇒ NVDEC can't handle it, so
    the caller should CPU-decode (NVENC still encodes). Trivially False without
    NVENC (no NVIDIA GPU). Cached for the process."""
    codec = (codec or "").lower()
    key = f"{codec}:{(pix_fmt or '').lower()}" if codec else f"@{sample}"
    if key in _hwdec_probe:
        return _hwdec_probe[key]
    if not await _has_nvenc():
        _hwdec_probe[key] = False
        return False
    ffmpeg = analyzer.ffmpeg_bin()
    ok = False
    if ffmpeg:
        try:
            proc = await asyncio.create_subprocess_exec(
                ffmpeg, "-hide_banner", "-loglevel", "error",
                "-hwaccel", "cuda", "-i", str(sample),
                "-map", "0:v:0", "-frames:v", "1", "-f", "null", "-",
                stdout=asyncio.subprocess.DEVNULL,
                stderr=asyncio.subprocess.DEVNULL, **_FFMPEG_SUBPROCESS_KW)
            rc = await proc.wait()
            ok = (rc == 0)
        except Exception:
            ok = False
    _hwdec_probe[key] = ok
    if not ok:
        print(f"[offline] NVDEC can't hardware-decode {codec or sample.name} on "
              f"this GPU — CPU-decoding it (NVENC still encodes).")
    return ok


async def _decode_hwaccel_args(sample: Optional[Path] = None,
                               info: Optional[dict] = None) -> list[str]:
    """GPU decode prefix (`-hwaccel cuda`) for the validator/repair/compress
    ffmpeg when NVENC is present, else `[]`. Goes BEFORE `-i`. Uses the
    TRANSPARENT `-hwaccel cuda` form (per-frame CPU fallback for codecs that
    negotiate one), but that fallback does NOT cover codecs whose hwaccel init
    hard-fails (e.g. AV1 on older cards) — so when a `sample` is given we first
    probe NVDEC (`_gpu_can_hwdecode`) and return `[]` if the GPU can't decode it,
    letting the caller CPU-decode instead of hard-failing. `info` (from
    `_ffprobe_full`) supplies codec/pixfmt for a cross-file probe cache."""
    if not await _has_nvenc():
        return []
    if sample is not None:
        v = (info or {}).get("video") or {}
        if not await _gpu_can_hwdecode(sample, v.get("codec", ""), v.get("pix_fmt", "")):
            return []
    return ["-hwaccel", "cuda"]

# HLS prep target — H.264 yuv420p video, AAC stereo audio, WebVTT subtitles.
#   • Video that's already H.264 yuv420p with a browser-safe profile is stream-copied
#     (no re-encode). Anything else transcodes to libx264 / h264_nvenc.
#   • Every audio track is transcoded to AAC stereo regardless of source — uniform
#     codec across renditions, and Safari iOS won't play FLAC/Opus/DTS/TrueHD.
#   • Text subtitles (subrip/ass/ssa) are remuxed to WebVTT. Image-based subs
#     (PGS/VOBSUB/DVB) can't go into HTML5 video tracks; they're reported in
#     meta.json as `skipped_image_subs` so the UI can flag them.
_HLS_PROFILE_BAD = {"high 10", "high 4:2:2", "high 4:4:4 predictive"}
_TEXT_SUB_CODECS  = {"subrip", "srt", "ass", "ssa", "webvtt", "mov_text", "text"}
_IMAGE_SUB_CODECS = {"hdmv_pgs_subtitle", "pgssub", "dvd_subtitle", "dvdsub",
                     "dvb_subtitle", "vobsub", "xsub"}
# ASS/SSA carry styling (karaoke, positioning, fonts, animation) that the
# `-c:s webvtt` downgrade throws away. For these we ALSO emit the raw subtitle
# (sub_<i>.ass) + extract embedded fonts so the browser player can render them
# faithfully with libass-wasm (SubtitlesOctopus). See GOTCHAS.md / STREAMING.md.
_STYLED_SUB_CODECS = {"ass", "ssa"}
# Attachment streams that are fonts an ASS renderer needs. Matched by extension
# first (most reliable), then MIME as a fallback — muxers set these inconsistently.
_FONT_ATTACH_EXTS  = {".ttf", ".otf", ".ttc", ".woff", ".woff2"}
_FONT_ATTACH_MIMES = {"font/ttf", "font/otf", "font/sfnt", "font/collection",
                      "application/font-sfnt", "application/x-truetype-font",
                      "application/x-font-ttf", "application/x-font-otf",
                      "application/vnd.ms-opentype"}

# ffmpeg ≥ 4.3 is required for reliable multi-rendition HLS with var_stream_map
# (subtitle groups and the agroup/sgroup tagging system are flaky on older builds).
_FFMPEG_MIN_VERSION = (4, 3)
_ffmpeg_version_probe: dict = {}

# HLS segment duration. 6 s is the de-facto default — Safari and hls.js both
# tune their buffering for this range, and segment-boundary seek granularity
# stays under the user-perceptible threshold.
HLS_SEGMENT_SECS = 6

# Adaptive-bitrate ladder: lower video renditions emitted alongside the original.
# Each rung is (name, target_height, maxrate_kbps, bufsize_kbps). The original
# (source-resolution) variant is always emitted as index 0; a rung is added only
# when the source is TALLER than it (no upscaling). The maxrate/bufsize VBV caps
# keep the down-rungs genuinely smaller and give the master playlist realistic
# BANDWIDTH numbers so hls.js / Safari pick sensibly under ABR.
HLS_ABR_LADDER = [
    ("video_1080", 1080, 6000, 12000),
    ("video_720",   720, 3000,  6000),
    ("video_480",   480, 1200,  2400),
    ("video_360",   360,  700,  1400),
]
# Rungs emitted by default when the admin hasn't overridden the ladder. Keeps
# the historical behaviour (Original + 720p + 480p down-rungs); the admin can
# pick any subset of the ladder heights via settings.admin_overrides.hls_ladder.
DEFAULT_HLS_LADDER_HEIGHTS = [720, 480]
HLS_LADDER_HEIGHTS = {h for _n, h, _m, _b in HLS_ABR_LADDER}


def _hls_ladder_heights(lib: dict) -> list[int]:
    """Admin-selected ABR down-rung heights (settings.admin_overrides.hls_ladder),
    falling back to DEFAULT_HLS_LADDER_HEIGHTS. The original (source-resolution)
    rendition is always emitted regardless and is NOT listed here. Unknown
    heights are dropped so a stale value can't request a rung that doesn't exist."""
    ov = (lib.get("settings", {}) or {}).get("admin_overrides", {}) or {}
    raw = ov.get("hls_ladder")
    if not isinstance(raw, list):
        return list(DEFAULT_HLS_LADDER_HEIGHTS)
    heights = [int(h) for h in raw if isinstance(h, (int, float)) and int(h) in HLS_LADDER_HEIGHTS]
    return heights


def _hls_video_variants(info: dict, heights: Optional[list[int]] = None) -> list[dict]:
    """Video renditions to emit for this source, capped at its height.

    Returns a list ordered original-first:
      [{name, height, scale}]  where scale=None means "no -filter, keep source".
    Down-rungs carry maxrate/bufsize too. A down-rung is emitted only when the
    source is TALLER than it AND its height is in `heights` (the admin-selected
    ladder; defaults to DEFAULT_HLS_LADDER_HEIGHTS). A source shorter than every
    selected rung yields a single variant (the original) — i.e. no ABR menu.
    """
    allowed = set(DEFAULT_HLS_LADDER_HEIGHTS if heights is None else heights)
    src_h = int((info.get("video") or {}).get("height") or 0)
    variants: list[dict] = [{"name": "video", "height": src_h, "scale": None}]
    for name, h, maxrate, bufsize in HLS_ABR_LADDER:
        if src_h > h and h in allowed:
            variants.append({
                "name": name, "height": h, "scale": h,
                "maxrate": maxrate, "bufsize": bufsize,
            })
    return variants


def _ffprobe_bin() -> Optional[str]:
    """Locate ffprobe alongside ffmpeg (or via PATH)."""
    ffm = analyzer.ffmpeg_bin()
    if ffm:
        sib = Path(ffm).with_name("ffprobe" + Path(ffm).suffix)
        if sib.exists():
            return str(sib)
    return shutil.which("ffprobe")


async def _ffmpeg_version() -> Optional[tuple[int, int]]:
    """Return (major, minor) of the active ffmpeg binary, or None if unavailable.

    Cached per process — `ffmpeg -version` is cheap but we hit this on every
    prep job and there's no reason to re-spawn it.
    """
    if "result" in _ffmpeg_version_probe:
        return _ffmpeg_version_probe["result"]
    ffmpeg = analyzer.ffmpeg_bin()
    if not ffmpeg:
        _ffmpeg_version_probe["result"] = None
        return None
    try:
        proc = await asyncio.create_subprocess_exec(
            ffmpeg, "-version",
            stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.DEVNULL,
        )
        out, _ = await proc.communicate()
        m = re.search(rb"ffmpeg version (\d+)\.(\d+)", out or b"")
        ver: Optional[tuple[int, int]] = (int(m.group(1)), int(m.group(2))) if m else None
    except Exception:
        ver = None
    _ffmpeg_version_probe["result"] = ver
    return ver


# Crude ISO 639-2/3-letter → display name. Anything not in the map falls back
# to the upper-cased code (better than blank), so unknown tags still render
# something the user can identify against the MKV's track list.
_LANG_NAMES = {
    "eng": "English", "jpn": "Japanese", "spa": "Spanish", "esp": "Spanish",
    "fre": "French",  "fra": "French",  "ger": "German",   "deu": "German",
    "ita": "Italian", "por": "Portuguese", "rus": "Russian",
    "chi": "Chinese", "zho": "Chinese", "kor": "Korean",
    "ara": "Arabic",  "hin": "Hindi",   "nld": "Dutch",
    "swe": "Swedish", "fin": "Finnish", "nor": "Norwegian",
    "dan": "Danish",  "pol": "Polish",  "tur": "Turkish",
    "ukr": "Ukrainian", "tha": "Thai",  "vie": "Vietnamese",
    "und": "",
}


def _track_label(track: dict, fallback: str) -> str:
    """Build a user-facing label for an audio/sub track."""
    lang = (track.get("language") or "und").lower()
    base = _LANG_NAMES.get(lang, lang.upper())
    title = (track.get("title") or "").strip()
    if title and base:
        return f"{base} ({title})"
    return title or base or fallback


# Edit-list threshold (seconds). An MP4/MOV edit list shifts presentation in a way
# the player (and VLC) honor, but STREAM-COPYING the video into HLS mishandles it
# while the re-encoded audio is normalized to zero — baking a constant A/V offset
# into the bundle (audio a steady amount early/late). RE-ENCODING the original rung
# applies the edit list to the frames and removes the offset. This is the dominant
# real-world cause (common in `-ss` copies / web-DL / many MP4 muxers).
EDITLIST_REENCODE_SECS = 0.05


def _probe_first_pts(path: str, stream: str, *, ignore_editlist: bool = False) -> Optional[float]:
    """First presentation timestamp (seconds) of one stream of a media file or HLS
    playlist, via ffprobe. `stream` is a stream specifier (e.g. "v:0", "a:0").
    `ignore_editlist` disables MP4 edit-list application. None on any failure.
    Sync — call via to_thread."""
    binp = _ffprobe_bin()
    if not binp:
        return None
    cmd = [binp, "-v", "error", "-of", "json"]
    if ignore_editlist:
        cmd += ["-ignore_editlist", "1"]
    cmd += ["-select_streams", stream, "-read_intervals", "%+#1",
            "-show_entries", "packet=pts_time", path]
    try:
        r = subprocess.run(cmd, capture_output=True, text=True, timeout=20)
        pkts = (json.loads(r.stdout or "{}").get("packets") or [])
        return float(pkts[0]["pts_time"]) if pkts else None
    except Exception:
        return None


def _source_has_editlist(path: str) -> bool:
    """True when the source's video stream carries a non-trivial edit list — i.e.
    its first video pts WITH the edit list applied differs from the raw pts. That's
    exactly the case where stream-copying the video bakes a constant A/V offset into
    the bundle (see EDITLIST_REENCODE_SECS). Sync — call via to_thread."""
    honored = _probe_first_pts(path, "v:0")
    raw     = _probe_first_pts(path, "v:0", ignore_editlist=True)
    return honored is not None and raw is not None and abs(honored - raw) > EDITLIST_REENCODE_SECS


def _ffprobe_full(path: str) -> dict:
    """Enumerate every stream + container metadata.

    Returns:
      {
        duration_sec, container,
        video: {codec, profile, pix_fmt, width, height} | None,
        audios:    [{idx, codec, language, title, channels, default}],
        subtitles: [{idx, codec, language, title, default, image_based, styled}],
        attachments: [{filename, mimetype, codec}],
      }
    `idx` is the index within the stream's own type — what ffmpeg `-map`
    accepts as `0:a:<idx>` / `0:s:<idx>`. `styled` marks ASS/SSA subs (they
    carry karaoke/positioning/font styling worth preserving via libass); the
    `attachments` list enumerates embedded fonts those styled subs depend on —
    see `_extract_bundle_fonts` / GOTCHAS.md.
    """
    binp = _ffprobe_bin()
    if not binp:
        return {}
    try:
        r = subprocess.run(
            [binp, "-v", "error", "-print_format", "json",
             "-show_streams", "-show_format", path],
            capture_output=True, text=True, timeout=15,
        )
        data = json.loads(r.stdout or "{}")
    except Exception:
        return {}
    fmt = data.get("format") or {}
    out: dict = {
        "duration_sec": float(fmt.get("duration", 0) or 0),
        "container":    fmt.get("format_name", ""),
        "video":        None,
        "audios":       [],
        "subtitles":    [],
        "attachments":  [],
    }
    audio_i = sub_i = 0
    for s in data.get("streams") or []:
        kind = s.get("codec_type")
        tags = s.get("tags") or {}
        disp = s.get("disposition") or {}
        if kind == "video" and out["video"] is None:
            out["video"] = {
                "codec":   s.get("codec_name", ""),
                "profile": (s.get("profile", "") or "").lower(),
                "pix_fmt": (s.get("pix_fmt", "") or "").lower(),
                "width":   s.get("width", 0),
                "height":  s.get("height", 0),
            }
        elif kind == "audio":
            out["audios"].append({
                "idx":      audio_i,
                "codec":    s.get("codec_name", ""),
                "language": (tags.get("language") or "und").lower(),
                "title":    tags.get("title", ""),
                "channels": s.get("channels", 0),
                "default":  bool(disp.get("default")),
            })
            audio_i += 1
        elif kind == "subtitle":
            codec = (s.get("codec_name", "") or "").lower()
            out["subtitles"].append({
                "idx":         sub_i,
                "codec":       codec,
                "language":    (tags.get("language") or "und").lower(),
                "title":       tags.get("title", ""),
                "default":     bool(disp.get("default")),
                "image_based": codec in _IMAGE_SUB_CODECS,
                "styled":      codec in _STYLED_SUB_CODECS,
            })
            sub_i += 1
        elif kind == "attachment":
            out["attachments"].append({
                "filename": tags.get("filename", ""),
                "mimetype": (tags.get("mimetype", "") or "").lower(),
                "codec":    (s.get("codec_name", "") or "").lower(),
            })
    return out


def _video_can_copy(v: Optional[dict]) -> bool:
    """True iff the video stream is already H.264 / yuv420p / good profile —
    safe to stream-copy into HLS instead of re-encoding.
    """
    if not v:
        return False
    return (v.get("codec") == "h264"
            and v.get("pix_fmt") == "yuv420p"
            and v.get("profile") not in _HLS_PROFILE_BAD)


# ── Aggressive local subtitle discovery ──────────────────────────────────────
# Sidecar subtitle file extensions VLC can load via `addsubtitle`.
_SUB_FILE_EXTS = {".srt", ".vtt", ".ass", ".ssa", ".sub"}
# Folder names releases commonly tuck subtitles into (alongside the video).
_SUB_DIR_NAMES = {"subs", "subtitles", "sub", "subtitle"}
# Full language names → canonical 3-letter codes (the reverse of _LANG_NAMES,
# plus a few aliases torrents use). Lets us read a language out of names like
# "2_English.srt", "Movie.Spanish.srt" or "3_Brazilian.Portuguese.srt".
_LANG_NAME_TO_CODE = {
    "english": "eng", "japanese": "jpn", "spanish": "spa", "castilian": "spa",
    "french": "fre", "german": "ger", "italian": "ita", "portuguese": "por",
    "brazilian": "por", "russian": "rus", "chinese": "chi", "mandarin": "chi",
    "cantonese": "chi", "korean": "kor", "arabic": "ara", "hindi": "hin",
    "dutch": "nld", "swedish": "swe", "finnish": "fin", "norwegian": "nor",
    "danish": "dan", "polish": "pol", "turkish": "tur", "ukrainian": "ukr",
    "thai": "tha", "vietnamese": "vie",
}


def _parse_sub_lang(name: str) -> str:
    """Best-effort canonical language code from a subtitle filename. Recognises
    ISO codes (en, eng) and English language names (English, 2_English.SDH),
    splitting on the usual separators. Returns "" when nothing matches."""
    tokens = re.split(r"[\s._\-\[\]()]+", Path(name).stem.lower())
    for tok in tokens:
        if tok in _LANG_NAME_TO_CODE:
            return _LANG_NAME_TO_CODE[tok]
    for tok in tokens:
        c = _canon_lang(tok)
        if c in _LANG_NAMES and c != "und":
            return c
    return ""


def _is_ai_sub_file(p: Path) -> bool:
    """True when a sidecar `.srt` is one we generated (`<stem>.<lang>.ai[.<model>].srt`)
    rather than a real downloaded/release subtitle. The upgrade watcher prefers a
    real sub over one of these."""
    return stt.AI_SUFFIX in p.stem.split(".")


def _discover_local_subs(video: Path) -> list[Path]:
    """Aggressively locate every sidecar subtitle file for `video`.

    Releases scatter subs across several layouts: next to the video
    (`Movie.srt`, `Movie.eng.srt`), or inside a `Subs/` / `Subtitles/` folder —
    flat for a single-video release, or in a per-episode subfolder named after
    the video for season packs. We scan the video's own directory plus any
    sibling subtitle folders (and one level up, in case the video sits in its
    own subfolder), recursing into the subtitle folders. A file belongs to this
    video when its name carries the stem, it lives in a folder named after the
    stem, or the release holds only one video (so loose subs must be its). For a
    lone-video release we take everything; for a season pack we keep only subs
    that match the episode stem, so neighbours' subs don't leak in.

    Returns de-duplicated absolute paths.
    """
    found: list[Path] = []
    seen: set[str] = set()

    def _is_sub(p: Path) -> bool:
        try:
            return p.is_file() and p.suffix.lower() in _SUB_FILE_EXTS
        except OSError:
            return False

    def _add(p: Path) -> None:
        try:
            rp = p.resolve()
        except OSError:
            return
        k = str(rp).lower()
        if k not in seen and _is_sub(rp):
            seen.add(k)
            found.append(rp)

    stem_l = video.stem.lower()
    parent = video.parent
    if not parent.exists():
        return found

    def _sole_video(d: Path) -> bool:
        try:
            vids = [f for f in d.iterdir()
                    if f.is_file() and f.suffix.lower() in VIDEO_EXTS]
        except OSError:
            return False
        return len(vids) <= 1

    def _belongs(p: Path, sole: bool) -> bool:
        n = p.stem.lower()
        if n == stem_l or n.startswith(stem_l + ".") or stem_l in n:
            return True
        if stem_l and stem_l in p.parent.name.lower():
            return True
        return sole

    sole_in_parent = _sole_video(parent)

    # 1) Same directory as the video.
    try:
        for p in parent.iterdir():
            if _is_sub(p) and _belongs(p, sole_in_parent):
                _add(p)
    except OSError:
        pass

    # 2) Dedicated subtitle folders beside the video and one level up, recursed.
    bases = [parent]
    if parent.parent != parent:
        bases.append(parent.parent)
    for base in bases:
        # The lone-video "take everything" fallback only applies to the video's
        # OWN directory. A shared Subs/ one level up may serve sibling episodes
        # in their own subfolders, so there we match strictly by stem.
        sole = sole_in_parent and base is parent
        try:
            entries = list(base.iterdir())
        except OSError:
            continue
        for d in entries:
            if not (d.is_dir() and d.name.lower() in _SUB_DIR_NAMES):
                continue
            try:
                for p in d.rglob("*"):
                    if _is_sub(p) and _belongs(p, sole):
                        _add(p)
            except OSError:
                pass
    # Stable order so loaded-sidecar ES IDs don't drift between replays
    # (iterdir/rglob order is filesystem-dependent).
    found.sort(key=lambda p: str(p).lower())
    return found


def _list_sidecar_subs(src: Path, item_id: str) -> list[dict]:
    """Aggressively list sidecar subtitle files for a video — everywhere
    `_discover_local_subs` looks (next to the file, in `Subs/`-style folders,
    one level up), not just exact-stem files beside it. This is what makes the
    on-device player surface subs stored in a `Subs/` folder. Each entry is
    servable via `/api/library/{id}/subtitle?path=…`, which converts
    SRT/ASS/SSA → WebVTT on demand.

    AI-generated subs the box wrote itself (`<stem>.<lang>.ai[.<model>].srt`,
    always next to the source) keep their `ai`/`model`/`stale` flags so the UI
    can label them and offer Regenerate; for every other file the language is
    guessed from the filename via `_parse_sub_lang`.
    """
    out: list[dict] = []
    stem = src.stem
    cur_model = stt.model_name()
    try:
        src_dir = src.resolve().parent
    except OSError:
        src_dir = src.parent
    for p in _discover_local_subs(src):
        # `.sub` is usually image-based VobSub (needs the .idx + OCR/burn-in) —
        # the browser can't render it and ffmpeg can't make WebVTT from it, so
        # don't offer it on-device. VLC still loads it natively on the TV path.
        if p.suffix.lower() == ".sub":
            continue
        ai = False
        model = ""
        lang = ""
        # AI subs live beside the source and encode lang + model in the stem.
        if p.parent == src_dir and p.stem.startswith(stem + "."):
            segs = p.stem[len(stem) + 1:].split(".")
            ai = stt.AI_SUFFIX in segs
            if ai:
                i = segs.index(stt.AI_SUFFIX)
                model = segs[i + 1] if i + 1 < len(segs) else ""
                lang = _canon_lang(segs[0]) if segs[0] != stt.AI_SUFFIX else ""
        if not lang:
            lang = _parse_sub_lang(p.name)
        out.append({
            "name":  p.name,
            "lang":  lang or "und",
            "ai":    ai,
            "model": model,
            "stale": bool(ai and model != cur_model),
            "fmt":   p.suffix.lower().lstrip("."),
            "url":   f"/api/library/{item_id}/subtitle?path={quote(str(p))}",
        })
    return out


def _needs_stt_subs(info: dict, default_lang: str = "") -> bool:
    """Decide whether a source warrants generated (STT) subtitles.

    True when there is no usable *text* subtitle: none at all, only image-based
    (PGS/VOBSUB/DVB) tracks, or — when `default_lang` is set — none matching that
    language. `default_lang` is canonicalized so en/eng etc. compare equal.
    """
    text_subs = [s for s in (info.get("subtitles") or []) if not s.get("image_based")]
    if not text_subs:
        return True
    if default_lang:
        want = _canon_lang(default_lang)
        if not any(_canon_lang(s.get("language")) == want for s in text_subs):
            return True
    return False


def _srt_to_vtt(srt: str) -> str:
    """Convert SRT cues to WebVTT. SRT timestamps use a comma; VTT uses a period."""
    body = re.sub(r"(\d\d:\d\d:\d\d),(\d\d\d)", r"\1.\2", srt)
    return "WEBVTT\n\n" + body


# A bare ASS vector-drawing token: a path command (m/n/l/b/s/p/c) or a coordinate.
_ASS_DRAW_TOKEN_RE = re.compile(r"^(?:[mnlbspc]|-?\d+(?:\.\d+)?)$", re.I)
_NUM_TOKEN_RE      = re.compile(r"^-?\d+(?:\.\d+)?$")
_HTML_TAG_RE       = re.compile(r"<[^>]+>")
_ASS_OVERRIDE_RE   = re.compile(r"\{[^}]*\}")


def _is_ass_drawing(text: str) -> bool:
    """True when a cue body is an ASS vector drawing (`\\p` mode) that ffmpeg
    leaked into the WebVTT as a giant `m -222 -409.5 l -220.5 …` text blob.
    Such a cue is only drawing commands + coordinate numbers (≥6 numbers), so it
    can never be a real subtitle line — drop it."""
    toks = _HTML_TAG_RE.sub("", text).split()
    if len(toks) < 6:
        return False
    nums = 0
    for t in toks:
        if not _ASS_DRAW_TOKEN_RE.match(t):
            return False
        if _NUM_TOKEN_RE.match(t):
            nums += 1
    return nums >= 6


def _clean_webvtt(text: str) -> str:
    """Sanitise WebVTT produced by ffmpeg's ASS/SSA→WebVTT conversion.

    Heavily-typeset fansub ASS (the common case for anime releases) survives that
    conversion badly: ffmpeg emits every overlapping Dialogue layer as a separate
    *identical* cue (so each line renders doubled/tripled on screen), dumps `\\p`
    vector drawings as raw coordinate-blob cues, and leaks ASS escapes like `\\h`
    (hard space) verbatim. This collapses all of that:

    - **drops** ASS drawing-blob cues (`_is_ass_drawing`),
    - **de-duplicates** cues with the same timing *and* text (the doubled lines),
    - converts leaked `\\h`→space and `\\N`/`\\n`→newline, strips stray `{…}`
      override blocks.

    Idempotent — re-running on already-clean WebVTT is a no-op, so it's safe to
    apply both at generation time and as an in-place heal when serving older
    bundles built before this fix. Header / NOTE / STYLE / REGION blocks pass
    through untouched.
    """
    text = text.replace("\r\n", "\n").replace("\r", "\n")
    blocks = text.split("\n\n")
    if not blocks:
        return text
    out: list[str] = [blocks[0].rstrip()]          # WEBVTT header (+ metadata)
    seen: set[tuple[str, str]] = set()
    for blk in blocks[1:]:
        lines = blk.split("\n")
        ts_i = next((i for i, ln in enumerate(lines) if "-->" in ln), -1)
        if ts_i < 0:
            if blk.strip():
                out.append(blk.rstrip())           # NOTE / STYLE / REGION
            continue
        body = "\n".join(lines[ts_i + 1:])
        if _is_ass_drawing(body):
            continue
        body = _ASS_OVERRIDE_RE.sub("", body)
        body = body.replace("\\h", " ").replace("\\N", "\n").replace("\\n", "\n")
        if not body.strip():
            continue
        ts_parts = lines[ts_i].split()
        ts_key = (ts_parts[0] + "-->" + ts_parts[2]) if len(ts_parts) >= 3 else lines[ts_i]
        key = (ts_key, body.strip())
        if key in seen:
            continue
        seen.add(key)
        out.append("\n".join(lines[:ts_i + 1] + [body]).rstrip())
    return "\n\n".join(out) + "\n"


async def _sub_to_vtt(path: Path) -> str:
    """Read a sidecar subtitle file and return WebVTT text the browser can render.

    `.vtt` passes through and `.srt` is converted inline (both instant); `.ass`,
    `.ssa` and text `.sub` are converted via ffmpeg on demand — this is the
    "prep" for a non-WebVTT sub. Raises on conversion failure so the endpoint can
    surface it. Styling (ASS karaoke/positioning) is lost in the WebVTT downgrade;
    `_clean_webvtt` then strips the artefacts that downgrade leaves behind
    (duplicate cues, leaked `\\p` drawings / `\\h` escapes).
    """
    ext = path.suffix.lower()
    if ext == ".vtt":
        return _clean_webvtt(path.read_text(encoding="utf-8", errors="replace"))
    if ext == ".srt":
        return _clean_webvtt(_srt_to_vtt(path.read_text(encoding="utf-8", errors="replace")))
    ffmpeg = analyzer.ffmpeg_bin()
    if not ffmpeg:
        raise RuntimeError("ffmpeg unavailable for subtitle conversion")
    proc = await asyncio.create_subprocess_exec(
        ffmpeg, "-y", "-i", str(path), "-f", "webvtt", "pipe:1",
        stdout=asyncio.subprocess.PIPE, stderr=asyncio.subprocess.PIPE,
        **_FFMPEG_SUBPROCESS_KW,
    )
    stdout, stderr = await proc.communicate()
    if proc.returncode != 0 or not stdout.strip():
        tail = stderr.decode("utf-8", "replace")[-200:].strip()
        raise RuntimeError(tail or "ffmpeg subtitle conversion failed")
    return _clean_webvtt(stdout.decode("utf-8", "replace"))


def _offline_cache_key(src: Path) -> str:
    """Path- and mtime-independent bundle key: `version | filename | size`.

    Dropping the absolute path and mtime makes the key stable across a move (even
    a cross-device one, where mtime can change), so a bundle co-located with its
    source file stays valid wherever the file goes. Two files can't share a name
    inside one directory, and identical name+size in *different* directories land
    in different `.streamlink_cache/` dirs, so there's no collision. mtime is safe
    to omit because every in-place rewrite path (repair / compress) already purges
    the bundle explicitly — we never relied on mtime to notice a rewrite.
    """
    st = src.stat()
    return _offline_cache_key_for(src.name, st.st_size)


def _offline_cache_key_for(name: str, size: int) -> str:
    """The bundle key from a filename + byte size alone — lets the move operation
    derive a file's key from its library metadata without touching disk (the file
    may be mid-move by qBittorrent)."""
    raw = f"{OFFLINE_CACHE_VERSION}|{name}|{size}"
    return hashlib.sha256(raw.encode()).hexdigest()[:24]


def _offline_cache_dir(src: Path) -> Path:
    """Where this source file's HLS bundle lives: a hidden cache folder beside the
    media file. The single source of truth for bundle location."""
    src = Path(src)
    return src.parent / OFFLINE_CACHE_DIRNAME / _offline_cache_key(src)


def _offline_cache_key_legacy(src: Path) -> str:
    """Reproduce the pre-v8 central-cache key (`version | abs_path | mtime | size`).
    Used ONLY by `_migrate_offline_cache_layout` to find old central bundles."""
    st = src.stat()
    raw = f"{_LEGACY_OFFLINE_CACHE_VERSION}|{src}|{int(st.st_mtime)}|{st.st_size}"
    return hashlib.sha256(raw.encode()).hexdigest()[:24]


# ── Bundle serving index ─────────────────────────────────────────────────────
# Bundles now live beside the media (`<file_dir>/.streamlink_cache/<key>/`), so
# the serving endpoint can no longer locate a bundle from its `<key>` alone the
# way `OFFLINE_CACHE / key` used to. `_bundle_index` maps key → bundle dir; it's
# the O(1) lookup on the segment hot path. Discovery is by *directory name* (the
# subdir name IS the key) so we never have to stat the source file to rebuild it.
_bundle_index: "dict[str, Path]" = {}
_bundle_index_built = False


def _invalidate_bundle_index() -> None:
    """Force the next lookup to rediscover (call after move / migrate / delete)."""
    global _bundle_index_built
    _bundle_index_built = False


def _bundle_index_register(key: str, bundle_dir: Path) -> None:
    """Point a freshly-built/located bundle's key at its dir without a full rescan."""
    if key and _CACHE_KEY_RE.match(key):
        _bundle_index[key] = Path(bundle_dir)


def _bundle_cache_dirs_sync(lib: dict) -> set[Path]:
    """Every `.streamlink_cache` dir that could hold a bundle: one per distinct
    parent directory of a library file. Cheap — just library-path arithmetic."""
    dirs: set[Path] = set()
    for it in lib.get("items", []):
        for f in it.get("files", []):
            p = f.get("path", "")
            if p:
                dirs.add(Path(p).parent / OFFLINE_CACHE_DIRNAME)
    return dirs


def _rebuild_bundle_index_sync(lib: dict) -> dict[str, Path]:
    """Walk every co-located `.streamlink_cache/` (plus the legacy central
    OFFLINE_CACHE for un-migrated stragglers) and map each `<key>` subdir → path.
    Synchronous; call via asyncio.to_thread."""
    idx: dict[str, Path] = {}
    roots = _bundle_cache_dirs_sync(lib)
    if OFFLINE_CACHE.exists():
        roots.add(OFFLINE_CACHE)
    for root in roots:
        try:
            children = list(root.iterdir()) if root.is_dir() else []
        except OSError:
            continue
        for sub in children:
            if sub.is_dir() and _CACHE_KEY_RE.match(sub.name):
                idx[sub.name] = sub
    return idx


async def _rebuild_bundle_index() -> None:
    global _bundle_index, _bundle_index_built
    lib = await get_library()
    idx = await asyncio.to_thread(_rebuild_bundle_index_sync, lib)
    _bundle_index = idx
    _bundle_index_built = True


async def _resolve_bundle_dir(key: str) -> Optional[Path]:
    """Locate a bundle dir by key, rebuilding the index once on a cold miss."""
    d = _bundle_index.get(key)
    if d is not None and d.is_dir():
        return d
    if not _bundle_index_built or d is not None:
        # Either never built, or a stale entry points at a vanished dir — rescan.
        await _rebuild_bundle_index()
        d = _bundle_index.get(key)
    return d if (d is not None and d.is_dir()) else None


def _migrate_offline_cache_layout_sync(items: list[dict]) -> tuple[int, int, int]:
    """Relocate pre-v8 central `.offline_cache/<legacy_key>/` bundles to their
    new home beside the media (`<file_dir>/.streamlink_cache/<new_key>/`).

    Returns (moved, skipped, failed). Pure file moves — **no re-encode**, so
    already-processed content is never rebuilt. Idempotent: a bundle already
    co-located is skipped, so a re-run only finishes leftovers. Best-effort per
    file; one failure never aborts the rest. Synchronous — call via to_thread."""
    moved = skipped = failed = 0
    if not OFFLINE_CACHE.exists():
        return (0, 0, 0)
    for it in items:
        for fmeta in it.get("files", []):
            p = fmeta.get("path", "")
            if not p:
                continue
            src = Path(p)
            try:
                if not src.exists():
                    continue
                legacy_key = _offline_cache_key_legacy(src)
            except OSError:
                continue
            old_dir = OFFLINE_CACHE / legacy_key
            # Only migrate *complete* bundles — a partial would just rebuild anyway.
            if not (old_dir / "master.m3u8").exists():
                continue
            new_dir = _offline_cache_dir(src)
            if new_dir.exists():
                skipped += 1
                continue
            try:
                new_dir.parent.mkdir(parents=True, exist_ok=True)
                shutil.move(str(old_dir), str(new_dir))
                moved += 1
            except Exception:
                failed += 1
    return (moved, skipped, failed)


async def _migrate_offline_cache_layout() -> None:
    """Startup health-check: bring an older (centrally-cached) install up to the
    v8 co-located layout without reprocessing anything. Runs BEFORE the background
    tasks spawn, so nothing observes a half-migrated state and queues a rebuild for
    a bundle that's merely being relocated. Rebuilds the serving index afterward."""
    if not OFFLINE_CACHE.exists():
        await _rebuild_bundle_index()
        return
    try:
        lib = await get_library()
        moved, skipped, failed = await asyncio.to_thread(
            _migrate_offline_cache_layout_sync, lib.get("items", []))
        if moved or failed:
            hls_log.info(
                "offline-cache migration: relocated %d bundle(s) beside their media "
                "(%d already co-located, %d failed)", moved, skipped, failed)
    except Exception as exc:
        hls_log.warning("offline-cache migration skipped: %s", exc)
    finally:
        await _rebuild_bundle_index()


def _build_hls_ffmpeg_args(
    ffmpeg: str,
    src: Path,
    info: dict,
    use_nvenc: bool,
    full_gpu: bool = False,
    ladder_heights: Optional[list[int]] = None,
    force_reencode_original: bool = False,
    hw_decode: bool = True,
) -> tuple[list[str], list[dict], list[dict], list[dict]]:
    """Construct the full ffmpeg invocation that emits one HLS bundle.

    All OUTPUT paths are bare filenames (init/segments/playlists/subs) — the
    caller MUST run ffmpeg with cwd set to the bundle directory so they land
    there. This is deliberate: ffmpeg derives the init segment's directory by
    parsing the playlist path, which fails on Windows backslash paths and sends
    the init file to the wrong place (→ 404 → fragLoadError). Bare names + cwd
    sidesteps that on every OS. The only absolute path is the `-i` source input.

    Emits an ABR ladder: the original video (stream-copied when compatible) plus
    a 720p and/or 480p down-rung (capped at source height — see
    `_hls_video_variants`). All video variants share one audio group, so the
    player switches video quality without re-fetching audio.

    Returns (args, kept_audios, kept_subs, video_variants) — audios/subs are the
    tracks (from `info`) included in the output in manifest order (image-based
    subs filtered out); video_variants is the ladder actually emitted, in master
    playlist order (index 0 = original).
    """
    audios = list(info.get("audios") or [])
    subs   = [s for s in (info.get("subtitles") or []) if not s.get("image_based")]
    videos = _hls_video_variants(info, ladder_heights)
    # Original can stream-copy when already browser-safe H.264; down-rungs must
    # always re-encode (they're scaled). Decoupled from use_nvenc so the source
    # rung stays a cheap remux even when the GPU encoder is present.
    # `force_reencode_original` overrides the copy to fix A/V sync: re-encoding the
    # original rung routes BOTH video and audio through the same timestamp
    # normalization, so a source with a video edit list can't bake a constant
    # audio offset into the bundle (which a stream-copy would). See
    # _run_offline_job / _source_has_editlist.
    copy_original = _video_can_copy(info.get("video")) and not force_reencode_original

    # Exactly one audio rendition should be marked DEFAULT in the master
    # playlist. Honor the source's disposition.default if any; otherwise the
    # first audio is the default.
    default_audio_i = next(
        (i for i, a in enumerate(audios) if a.get("default")),
        0 if audios else -1,
    )

    args: list[str] = [
        ffmpeg, "-y",
        # -progress emits machine-readable key=value to stdout — we tail it
        # below for an accurate % instead of guessing from output-dir growth.
        "-progress", "pipe:1", "-nostats",
    ]

    # GPU-accelerated decode for the NVENC path, in two tiers. Without either,
    # NVENC only offloads the *encode* while the source is decoded (and every
    # down-rung scaled) on the CPU — so the CPU pegs while the GPU idles.
    #
    #   full_gpu  → `-hwaccel cuda -hwaccel_output_format cuda` + scale_cuda:
    #     the WHOLE pipeline (decode → scale → nvenc) stays resident in VRAM —
    #     no per-frame GPU↔CPU copy, no CPU scaling. The caller only sets this
    #     when the source must fully re-encode (NOT copy_original) AND is
    #     NVDEC-safe: that guarantees there's NO stream-copy rung in the ladder.
    #     Mixing `-c:v copy` with cuda-filtered rungs DEADLOCKS ffmpeg (the copy
    #     stream races ahead while the muxer/NVDEC surface pool backs up, wedging
    #     at low CPU/GPU with no progress and no exit). `-extra_hw_frames`
    #     enlarges the decoder surface pool so the parallel scale_cuda branches
    #     don't starve it. A stall watchdog + retry in _run_offline_job still
    #     guards against any residual hang.
    #   else (transparent) → `-hwaccel cuda` only: NVDEC decodes, frames
    #     auto-download to system memory for the CPU `scale` filter. ffmpeg's
    #     transparent path falls back to software for codecs that negotiate one,
    #     but NOT for codecs whose hwaccel init hard-fails (e.g. AV1 on a Pascal
    #     card) — so this is only added when `hw_decode` (the caller's per-source
    #     NVDEC probe, `_gpu_can_hwdecode`) confirms the GPU can decode it. When
    #     it can't we CPU-decode here; NVENC still encodes.
    #
    # Only added when something actually decodes (a pure stream-copy rung has
    # no decode to accelerate).
    needs_decode = (not copy_original) or len(videos) > 1
    if full_gpu and needs_decode:
        args += ["-hwaccel", "cuda", "-hwaccel_output_format", "cuda",
                 "-extra_hw_frames", "8"]
    elif use_nvenc and needs_decode and hw_decode:
        args += ["-hwaccel", "cuda"]

    args += [
        # Regenerate presentation timestamps on the input. Some sources carry
        # broken / missing / non-monotonic PTS (or a per-stream start_time skew
        # between video and audio); left alone they desync the re-encoded audio
        # from the stream-copied video, since the two land in SEPARATE HLS
        # renditions that the player aligns purely by media timestamps. +genpts
        # gives every stream a clean monotonic clock to anchor to. See the audio
        # `aresample=async=1` filter below — together they keep A/V in sync.
        "-fflags", "+genpts",
        # Larger input buffers coalesce disk reads; without these the Windows
        # storage stack can dominate kernel time during a fast encode.
        "-thread_queue_size", "1024",
        "-rtbufsize", "64M",
        "-i", str(src),
    ]

    # Stream mapping for the HLS output: the source video mapped once per ladder
    # rung, then every audio. Text subs are mapped separately into their own
    # sidecar .vtt outputs further below.
    for _ in videos:
        args += ["-map", "0:v:0"]
    for a in audios:
        args += ["-map", f"0:a:{a['idx']}"]

    # Per-output video codec. Output video stream index `i` matches `videos[i]`:
    #   • original (i==0): stream-copy when browser-safe, else encode full-res
    #   • down-rungs:      always encode + scale=-2:<h> (even width for yuv420p),
    #                      with a maxrate/bufsize VBV cap so the rendition is
    #                      genuinely smaller and the master BANDWIDTH is realistic
    # NVENC encodes on the GPU when available; decode runs on NVDEC too (see
    # the `-hwaccel` block above). On the full_gpu path the scale happens on the
    # GPU as well (scale_cuda), so frames never leave VRAM; otherwise a CPU
    # `scale` filter sits between the NVDEC decode and the NVENC encode.
    def _encode_video(i: int, v: dict) -> list[str]:
        a: list[str] = []
        if full_gpu:
            # All-GPU: scale_cuda both resizes AND pins the pixel format on the
            # GPU, handing nvenc a ready cuda surface — so NO `-pix_fmt yuv420p`
            # (that would force a hwdownload/CPU convert and defeat the point).
            # The original full-res rung still routes through scale_cuda (to its
            # own height) purely to normalise to browser-safe 8-bit 4:2:0.
            a += [
                f"-filter:v:{i}", f"scale_cuda=-2:{v['height']}:format=yuv420p",
                f"-c:v:{i}", "h264_nvenc",
                "-preset", "medium", "-rc", "vbr", f"-cq:v:{i}", "23",
            ]
        elif use_nvenc:
            if v["scale"]:
                a += [f"-filter:v:{i}", f"scale=-2:{v['scale']}"]
            a += [
                f"-c:v:{i}", "h264_nvenc",
                "-preset", "medium", "-rc", "vbr", f"-cq:v:{i}", "23",
                f"-pix_fmt:v:{i}", "yuv420p",
            ]
        else:
            if v["scale"]:
                a += [f"-filter:v:{i}", f"scale=-2:{v['scale']}"]
            a += [
                f"-c:v:{i}", "libx264",
                "-preset", "veryfast", f"-crf:v:{i}", "23",
                # Caps x264 worker threads so the host stays responsive during
                # bulk /prep-all runs. NVENC ignores this (runs on the GPU).
                "-threads", str(OFFLINE_FFMPEG_THREADS),
                f"-pix_fmt:v:{i}", "yuv420p",
            ]
        if v.get("maxrate"):
            a += [f"-maxrate:v:{i}", f"{v['maxrate']}k",
                  f"-bufsize:v:{i}", f"{v['bufsize']}k"]
        a += [f"-profile:v:{i}", "high", f"-level:v:{i}", "4.1"]
        return a

    for i, v in enumerate(videos):
        if i == 0 and copy_original:
            args += [f"-c:v:{i}", "copy"]
        else:
            args += _encode_video(i, v)

    # Audio: every track to AAC stereo, regardless of source. Safari iOS only
    # plays AAC/MP3/AC3/EAC3 reliably and won't decode FLAC/Opus/DTS in MP4 —
    # uniform AAC across renditions is the only safe lowest common denominator.
    #
    # A/V SYNC: every audio output gets `aresample=async=1`, the canonical ffmpeg
    # resync filter. It stretches/squeezes the resampled audio and pads gaps with
    # silence so the re-encoded audio tracks the (stream-copied) video clock —
    # correcting the timestamp drift / gaps that otherwise leave audio misaligned
    # in the bundle (audio and video are separate HLS renditions sharing one
    # timeline, so any per-stream skew shows up as desync). Applied PER output
    # audio stream (`-filter:a:{i}`) because there's one AAC rendition per source
    # track.
    #
    # `first_pts=0` (added ONLY on the fully-re-encoded ladder) pads the start of
    # the audio rendition with real silence up to t=0 when the source audio starts
    # AFTER the video — its documented purpose. WHY this matters: the source's
    # intrinsic audio-start delay (e.g. EMBER anime BDRips carry audio first-PTS
    # ≈ +1.0s vs video 0) is faithfully reproduced by ffmpeg as a cross-rendition
    # baseMediaDecodeTime gap (the audio rendition's first SAMPLE is real dialog
    # timestamped ~1s in, with no leading silence). A correct player schedules it
    # there; but Safari/AVPlayer/hls.js playing SEPARATE audio+video fmp4
    # renditions ignore that tfdt gap and anchor the audio's first sample to
    # playback start → the +1s dialog plays ~1s EARLY. Single-program on-demand
    # (one mpegts, interleaved) and VLC (source direct) never hit this. Baking the
    # offset as leading silence makes the audio rendition START at t=0 (same zero
    # as the re-encoded video), so there's no gap for the player to drop and the
    # dialog still lands at its true time on BOTH faithful and naive players.
    #
    # SCOPED to `not copy_original`: when the original rung is stream-COPIED its
    # video first PTS can be non-zero/arbitrary, and forcing audio to 0 against it
    # would INTRODUCE a constant offset — so the copy path keeps the old behavior.
    # Re-encoding routes video through `+genpts` (first PTS ≈ 0), making 0 the
    # correct shared anchor. (Old escape hatch `-copyts -start_at_zero` preserved
    # the gap rather than removing it, so it didn't cure the naive-player case.)
    if audios:
        args += ["-c:a", "aac", "-b:a", "160k", "-ac", "2"]
        afilter = "aresample=async=1:min_hard_comp=0.100000"
        if not copy_original:
            afilter += ":first_pts=0"
        for i in range(len(audios)):
            args += [f"-filter:a:{i}", afilter]

    args += [
        "-f", "hls",
        "-hls_time", str(HLS_SEGMENT_SECS),
        "-hls_playlist_type", "vod",
        "-hls_segment_type", "fmp4",
        # independent_segments: every segment starts on a keyframe so the
        # player can switch renditions without an extra fetch round-trip.
        "-hls_flags", "independent_segments",
        # Template the fmp4 init filename per-variant. Two reasons this is
        # critical, both of which produce the *same* symptom — a fatal hls.js
        # `fragLoadError` on the init segment after the manifest + variant
        # playlists already parsed (so audio/sub dropdowns populate first,
        # making it look like "everything loaded but won't play"):
        #   1. Without an explicit -hls_fmp4_init_filename, ffmpeg picks its OWN
        #      %v expansion for the init segment, which across versions doesn't
        #      always match the `#EXT-X-MAP:URI=` it writes into the playlist.
        #   2. The init filename MUST be a BARE name (no directory). ffmpeg
        #      joins it to the directory it parses out of the playlist path; a
        #      full path breaks the encode ("Failed to open segment"), and on
        #      Windows the backslash playlist path defeats that dir-parse so the
        #      init lands in the process CWD instead of the bundle → 404.
        # The portable fix: bare names for EVERY output (init/segments/playlists
        # /subs below) and run ffmpeg with cwd=<bundle dir> (see _run_offline_job)
        # so all of them land in the bundle on every OS. See GOTCHAS.md.
        "-hls_fmp4_init_filename", "init_%v.mp4",
        "-hls_segment_filename", "seg_%v_%05d.m4s",
        "-master_pl_name", "master.m3u8",
    ]

    # Build the var_stream_map for the HLS output — VIDEO + AUDIO ONLY.
    #
    # Subtitles are deliberately NOT part of the HLS manifest. ffmpeg's HLS
    # muxer cannot package WebVTT renditions: a single inline subtitle works,
    # but two or more (declared as their own `s:N,sgroup:…` variants) fail with
    # "No streams to mux were specified" / "Could not write header". Every real
    # release MKV has many subtitle tracks, so in-manifest subs meant HLS prep
    # ALWAYS failed. Instead we emit one standalone `sub_<i>.vtt` per text track
    # (see below) and the player wires them as <track> children. See GOTCHAS.md.
    # One entry per video variant (all sharing the single audio group) followed
    # by one per audio rendition. %v in the playlist/segment/init templates
    # expands to each `name:` tag, so the bundle gets video.m3u8 / video_720.m3u8
    # / video_480.m3u8 (+ matching init_*/seg_*).
    parts: list[str] = []
    for i, v in enumerate(videos):
        vp = [f"v:{i}"]
        if audios:
            vp.append("agroup:aud")
        vp.append(f"name:{v['name']}")
        parts.append(",".join(vp))

    for i, a in enumerate(audios):
        p = [f"a:{i}", "agroup:aud", f"name:audio_{i}",
             f"language:{a.get('language') or 'und'}"]
        if i == default_audio_i:
            p.append("default:yes")
        parts.append(",".join(p))

    args += ["-var_stream_map", " ".join(parts)]
    # Per-rendition playlist template — %v expands to the `name:` tag above.
    # Bare name (relative to ffmpeg's cwd, which the caller sets to the bundle
    # dir) — see the init-filename note above for why every output is bare.
    args += ["%v.m3u8"]

    # Sidecar subtitle outputs, one additional WebVTT output file per text sub,
    # produced in the SAME ffmpeg pass. subrip / ass / ssa convert transparently;
    # ASS styling (karaoke, positioning, fonts) is lost — see GOTCHAS.md. The
    # `sub_<i>.vtt` index matches `meta.json["subtitles"][i]`.
    for i, s in enumerate(subs):
        args += [
            "-map", f"0:s:{s['idx']}",
            "-c:s", "webvtt",
            "-f", "webvtt",
            f"sub_{i}.vtt",   # bare name — lands in ffmpeg's cwd (the bundle dir)
        ]
        # Styled ASS/SSA: ALSO emit the raw subtitle (stream-copied, styling
        # intact) so the browser player can render it via libass-wasm. The VTT
        # above is kept as the universal fallback (players/hosts without libass,
        # and old bundles). Fonts are extracted separately — see
        # `_extract_bundle_fonts`. `sub_<i>.ass` index matches `sub_<i>.vtt`.
        if s.get("styled"):
            args += [
                "-map", f"0:s:{s['idx']}",
                "-c:s", "copy",
                "-f", "ass",
                f"sub_{i}.ass",
            ]

    return args, audios, subs, videos


def _extract_bundle_fonts(src: Path, bundle_dir: Path, info: dict) -> list[str]:
    """Dump the source's embedded font attachments into `bundle_dir` as flat
    `font_<n>.<ext>` files, returning the relative filenames written.

    Styled ASS/SSA rendering (libass-wasm) needs the fansub's own fonts. They're
    written FLAT (not in a `fonts/` subdir) because `offline_cache_bundle_file`
    serves a single path segment — a subdir couldn't be fetched, and the iOS
    `_enumerate_bundle_files` listing is one level deep too.

    Best-effort: any failure yields []. NOTE ffmpeg's `-dump_attachment` writes
    the files but then exits NON-ZERO ("At least one output file must be
    specified"), so success is gated on the file existing, not the return code.
    Non-font attachments (cover art, etc.) are skipped. Windows-first: ffmpeg is
    the already-bundled binary — no mkvtoolnix/`mkvextract` dependency.
    """
    ffmpeg = analyzer.ffmpeg_bin()
    atts = info.get("attachments") or []
    if not ffmpeg or not atts:
        return []
    cmd = [ffmpeg, "-y"]
    planned: list[str] = []
    # The `t:<n>` specifier indexes attachment streams in order — the same order
    # `_ffprobe_full` enumerated them, so `n` here is the attachment index.
    for n, a in enumerate(atts):
        fn   = a.get("filename", "") or ""
        ext  = Path(fn).suffix.lower()
        mime = (a.get("mimetype", "") or "").lower()
        if ext not in _FONT_ATTACH_EXTS and mime not in _FONT_ATTACH_MIMES:
            continue
        if ext not in _FONT_ATTACH_EXTS:
            ext = ".ttf"
        out_name = f"font_{n}{ext}"
        cmd += [f"-dump_attachment:t:{n}", out_name]
        planned.append(out_name)
    if not planned:
        return []
    cmd += ["-i", str(src)]
    try:
        subprocess.run(cmd, cwd=str(bundle_dir), capture_output=True,
                       timeout=60, **_FFMPEG_SUBPROCESS_KW)
    except Exception:
        pass
    written: list[str] = []
    for out_name in planned:
        p = bundle_dir / out_name
        try:
            if p.is_file() and p.stat().st_size > 0:
                written.append(out_name)
        except OSError:
            pass
    return written


async def _prep_validate_repair(job: dict, src: Path) -> str:
    """In-prep hook for settings.prep_validate: deep-decode `src` and, if damaged,
    remux-repair it in place (lossless, no re-encode). Returns one of
    "clean" | "repaired" | "damaged" | "skipped". Best-effort — any failure
    returns "skipped" and never fails the prep job.

    The live ffmpeg is stashed in job["_proc"] (same slot the encode uses), so the
    existing pause/kill machinery — `_pause_prep(kill=True)` and the activity-kick
    hard-stop — terminates an in-flight scan/repair with no extra plumbing; the
    same flags drive cancellation via `is_stopped`."""
    ffmpeg = analyzer.ffmpeg_bin()
    if not ffmpeg:
        return "skipped"
    set_proc   = lambda p: job.__setitem__("_proc", p)
    is_stopped = lambda: (bool(job.get("_paused_kill"))
                          or bool(job.get("_ondemand_cancelled"))
                          or state.prep_paused)
    try:
        ok, detail = await _validate_one_file(
            ffmpeg, str(src), True, set_proc=set_proc, is_stopped=is_stopped)
        if is_stopped():
            return "skipped"
        if ok:
            return "clean"
        hls_log.info("prep-validate: %s is damaged (%s) — attempting remux repair", src.name, detail)
        result, rdetail = await _repair_one_file(
            ffmpeg, str(src), False, set_proc=set_proc, is_stopped=is_stopped)
        if result == "repaired":
            hls_log.info("prep-validate: repaired %s via %s", src.name, rdetail)
            return "repaired"
        hls_log.warning("prep-validate: could not repair %s (%s)", src.name, rdetail)
        return "damaged"
    except Exception as exc:
        hls_log.warning("prep-validate: scan/repair of %s skipped: %s", src.name, exc)
        return "skipped"
    finally:
        job["_proc"] = None


async def _run_offline_job(job_id: str) -> None:
    """Build an HLS bundle for one source file. The output is a directory
    keyed by `_offline_cache_key(src)` inside the source file's co-located
    `.streamlink_cache/` (see `_offline_cache_dir`), containing the master
    playlist, per-rendition playlists, segments, and meta.json.
    """
    job = _offline_jobs.get(job_id)
    if not job:
        return
    if not HLS_AVAILABLE:
        job["status"] = "error"; job["error"] = HLS_UNAVAILABLE_MSG
        return
    is_bulk = job.get("queue") == "bulk"
    # Priority-prep precedence. A bulk job parks here until no priority HLS prep is
    # queued or encoding — that's interactive (fullscreen "Prep for Device" /
    # play-on-device) AND admin force-prep, both of which must run ahead of
    # auto-prep / manual bulk prep. The file a bulk job is *currently*
    # encoding is separately booted by _preempt_running_bulk so the slot frees
    # without waiting for it. (The `not prep_paused` escape lets a bulk job fall
    # through to park at the pause gate below instead of spinning here.)
    my_prio = int(job.get("_prep_prio", 1))
    if is_bulk:
        while not state.prep_paused and (
            _priority_hls_pending() > 0 or _higher_priority_bulk_pending(my_prio) > 0
        ):
            await asyncio.sleep(0.25)
    # Hold pending until the global concurrency slot frees up. This is what
    # keeps a 77-file /prep-all from spawning 77 ffmpegs at once.
    async with _offline_job_sem():
        # An interactive prep may have arrived while this bulk job sat in the
        # semaphore queue. Yield the slot straight back and re-queue so the
        # interactive job (also waiting on the slot) takes it first. (When prep is
        # paused, skip this and fall through to park at the pause gate instead — a
        # paused job holds no slot, so interactive still wins without the churn.)
        if is_bulk and not state.prep_paused and (
            _priority_hls_pending() > 0 or _higher_priority_bulk_pending(my_prio) > 0
        ):
            job["status"] = "pending"
            asyncio.create_task(_requeue_offline_job(job_id))
            return
        out_dir = Path(job["out"])
        # Sibling-job race: another worker may have produced this bundle while
        # we sat in the queue. If so, exit fast.
        if (out_dir / "master.m3u8").exists():
            job["progress"] = 1.0
            job["status"]   = "done"
            return
        # Global pause gate. A bulk ("Prep for later" / auto-prep) job that reaches
        # the head of the queue while prep is paused marks itself "paused" and
        # EXITS — releasing the single concurrency slot so an interactive
        # play-on-device prep can still run. _resume_prep() re-spawns this worker
        # when the user (or the auto-prep loop) resumes. Interactive jobs ignore
        # the gate entirely. See PrepPauseReq / _pause_prep / _resume_prep.
        if is_bulk and state.prep_paused:
            job["status"] = "paused"
            return
        # Admin force-prep stop gate. The admin Stop control sets admin_prep_stop
        # to cancel the whole force-prep batch; an "admin" job that reaches the
        # slot after Stop was pressed cancels itself (releasing the slot so other
        # work proceeds). A hard stop additionally terminates the in-flight encode
        # — handled below via the `_admin_stopped` branch. Unlike the bulk pause
        # gate, this is a one-way cancel: stopped jobs are not auto-resumed.
        if job.get("queue") == "admin" and state.admin_prep_stop:
            job["status"] = "cancelled"
            return
        job["status"] = "processing"
        # Re-baseline started_at to when the work actually begins so per-job
        # ETAs reflect real ffmpeg throughput, not queue wait time.
        job["started_at"] = time.time()
        src = Path(job["src"])
        # On-demand-only backstop: if this file's item was flagged while the job was
        # queued, don't build a permanent bundle (the creation gates normally catch
        # this; this covers any job that slipped through).
        if job.get("item_id") and job["item_id"] in state.ondemand_only_items:
            job["status"] = "cancelled"
            job["progress"] = 0.0
            return
        # Compression playback lock — never read a source that's being rewritten in
        # place (it would race the os.replace and could read a half-written file).
        # Park as pending and re-check shortly; the compressor releases the lock the
        # moment that file finishes.
        if _is_compressing(str(src)):
            job["status"] = "pending"
            job.pop("_compress_block", None)
            asyncio.create_task(_requeue_offline_job(job_id, delay=3.0))
            return
        hls_log.info("job %s START src=%s out=%s", job_id, src, out_dir.name)
        tmp_dir = out_dir.with_name(out_dir.name + ".part")
        ffmpeg = analyzer.ffmpeg_bin()
        if not ffmpeg:
            job["status"] = "error"; job["error"] = "ffmpeg not available."
            hls_log.error("job %s ABORT: ffmpeg binary not found on PATH", job_id)
            return
        ver = await _ffmpeg_version()
        if ver is None or ver < _FFMPEG_MIN_VERSION:
            job["status"] = "error"
            need = f"{_FFMPEG_MIN_VERSION[0]}.{_FFMPEG_MIN_VERSION[1]}"
            have = (f"{ver[0]}.{ver[1]}" if ver else "unknown")
            job["error"] = f"ffmpeg too old ({have}) — need ≥ {need} for HLS prep."
            hls_log.error("job %s ABORT: %s", job_id, job["error"])
            return
        info = await asyncio.to_thread(_ffprobe_full, str(src))
        duration = float(info.get("duration_sec", 0) or 0)
        if not info.get("video"):
            job["status"] = "error"; job["error"] = "No video stream in source."
            hls_log.error(
                "job %s ABORT: no video stream in %s (ffprobe keys: %s)",
                job_id, src, sorted(info.keys()),
            )
            return

        # Validate-and-repair-on-prep (settings.prep_validate). Bulk jobs only —
        # interactive play-on-device preps never validate so playback isn't
        # delayed. "before" heals the source ahead of the encode; "after" runs
        # post-encode (in the done-hook block below). GPU-accelerated when NVENC
        # is present (see _prep_validate_repair / _decode_hwaccel_args).
        prep_validate_mode = "off"
        try:
            _lib_for_cfg = await get_library()
            ladder_heights = _hls_ladder_heights(_lib_for_cfg)
            if is_bulk:
                prep_validate_mode = _prep_validate_cfg(_lib_for_cfg)["mode"]
        except Exception:
            ladder_heights = list(DEFAULT_HLS_LADDER_HEIGHTS)
        if prep_validate_mode == "before":
            res = await _prep_validate_repair(job, src)
            if res == "repaired":
                # The repair rewrote the file, so its cache key (name|size) changed.
                # out_dir/tmp_dir were keyed off the OLD source, leaving the bundle
                # we'd build orphaned — re-point them at the healed file's key, and
                # short-circuit if that bundle already exists.
                new_out = _offline_cache_dir(src)
                if new_out != out_dir:
                    out_dir   = new_out
                    job["out"] = str(out_dir)
                    tmp_dir   = out_dir.with_name(out_dir.name + ".part")
                    if (out_dir / "master.m3u8").exists():
                        job["progress"] = 1.0
                        job["status"]   = "done"
                        return
                # Re-probe the healed file so the encode sees its real streams.
                info = await asyncio.to_thread(_ffprobe_full, str(src))
                duration = float(info.get("duration_sec", 0) or 0)
                if not info.get("video"):
                    job["status"] = "error"; job["error"] = "No video stream after repair."
                    return

        # On-demand-only flipped during the (interruptible) validate/repair phase?
        # The terminate from _apply_ondemand_only already fired, so don't fall
        # through and start a fresh encode that nothing would stop. (Also covers a
        # job whose item was flagged after the start-of-job backstop ran.)
        if job.get("_ondemand_cancelled") or (
                job.get("item_id") and job["item_id"] in state.ondemand_only_items):
            job.pop("_ondemand_cancelled", None)
            job["status"] = "cancelled"
            job["progress"] = 0.0
            return

        # Clean any leftover .part dir from a previous crashed run. Offloaded to a
        # thread so a large stale bundle's recursive unlink can't stall the event
        # loop (and with it every other HTTP request) while prep is starting.
        if tmp_dir.exists():
            await asyncio.to_thread(shutil.rmtree, tmp_dir, ignore_errors=True)
        tmp_dir.mkdir(parents=True, exist_ok=True)

        try:
            use_nvenc = await _has_nvenc()
            down_encoder = "h264_nvenc" if use_nvenc else "libx264"
            copy_original = _video_can_copy(info.get("video"))
            # A/V SYNC GUARD. Stream-copying the original video rung while
            # re-encoding audio bakes a CONSTANT offset into the bundle when the
            # source has a video EDIT LIST: copy mishandles the edit list while the
            # re-encoded audio is normalized to zero, so audio ends up a steady
            # amount early/late even though VLC plays the source fine (which the
            # duration-based resync detector can't see). Re-encoding the original
            # rung applies the edit list to the frames and removes the offset.
            # Engaged when (a) the source has an edit list, or (b) a repair re-prep
            # explicitly requests it (a bundle we measured as misaligned). Only
            # probed/forced when we'd otherwise copy — a re-encode already normalizes.
            force_reencode = bool(job.get("_force_reencode_video"))
            if copy_original and not force_reencode:
                if await asyncio.to_thread(_source_has_editlist, str(src)):
                    force_reencode = True
                    hls_log.info("job %s: source has a video edit list — re-encoding "
                                 "original rung to avoid a baked-in A/V offset", job_id)
            elif copy_original and force_reencode:
                hls_log.info("job %s: re-encoding original rung to correct A/V sync "
                             "(repair re-prep)", job_id)
            copy_original = copy_original and not force_reencode
            # All-GPU pipeline (decode→scale_cuda→nvenc resident in VRAM), chosen
            # only when:
            #   • the build has scale_cuda (_has_cuda_scale), and
            #   • the source is NVDEC-safe (_source_nvdec_safe), and
            #   • the source must FULLY re-encode (not copy_original) — i.e. there
            #     is NO `-c:v copy` rung in the ladder. Mixing stream-copy with
            #     cuda-filtered rungs deadlocks ffmpeg (hangs at low CPU/GPU). By
            #     restricting to the all-encode case we both dodge that and target
            #     the worst CPU offender (e.g. h265 packs that re-encode 3 rungs).
            # Copyable H.264 sources keep the proven transparent path (cheap copy
            # original + CPU-scaled down-rungs). Pinning frames to VRAM has no
            # software fallback, so a stall/failure auto-retries on the
            # transparent path below (full_gpu=False) — never regressing a file.
            # Can NVDEC hardware-decode this source on THIS box? Gates every GPU
            # decode path below. AV1 on an older card (or any codec NVDEC can't
            # handle) probes False → we CPU-decode instead of hard-failing.
            _v = info.get("video") or {}
            hw_decode = use_nvenc and await _gpu_can_hwdecode(
                src, _v.get("codec", ""), _v.get("pix_fmt", ""))
            full_gpu = (
                use_nvenc
                and not copy_original
                and await _has_cuda_scale()
                and _source_nvdec_safe(info)
                and hw_decode
            )

            while True:
                args, kept_audios, kept_subs, kept_videos = _build_hls_ffmpeg_args(
                    ffmpeg, src, info, use_nvenc, full_gpu=full_gpu,
                    ladder_heights=ladder_heights,
                    force_reencode_original=force_reencode,
                    hw_decode=hw_decode,
                )
                # Record encoder for admin/UI display. The original rung may copy
                # while the ABR down-rungs (if any) still transcode, so reflect both.
                if copy_original and len(kept_videos) > 1:
                    job["encoder"] = f"copy+{down_encoder}"
                elif copy_original:
                    job["encoder"] = "copy"
                else:
                    job["encoder"] = down_encoder

                hls_log.info(
                    "job %s encode: encoder=%s duration=%.1fs videos=%d audios=%d subs=%d nvenc=%s gpu=%s",
                    job_id, job["encoder"], duration,
                    len(kept_videos), len(kept_audios), len(kept_subs), use_nvenc, full_gpu,
                )
                # Run ffmpeg at lowered OS priority (POSIX: `nice -n 10`; Windows:
                # BELOW_NORMAL via _FFMPEG_SUBPROCESS_KW) so the bulk encode yields CPU
                # to the web server, VLC, and qBit — keeping the dashboard responsive.
                cmd = _ffmpeg_nice_prefix() + args
                hls_log.info(
                    "job %s ffmpeg cmd: %s",
                    job_id, " ".join(shlex.quote(a) for a in cmd),
                )

                proc = await asyncio.create_subprocess_exec(
                    *cmd,
                    # Run inside the staging dir: every OUTPUT arg is a bare filename
                    # (init/segments/playlists/subs), so they all land here. This is
                    # what keeps the fmp4 init segment in the bundle on Windows,
                    # where a backslash playlist path otherwise misdirects it (→ 404
                    # → fragLoadError). The `-i` source is absolute, so cwd is safe.
                    cwd=str(tmp_dir),
                    stdout=asyncio.subprocess.PIPE,
                    stderr=asyncio.subprocess.PIPE,
                    **_FFMPEG_SUBPROCESS_KW,
                )
                # Expose the handle so _pause_prep(kill=True) can terminate this encode.
                job["_proc"] = proc

                # Drain stderr concurrently into a bounded buffer. Two reasons:
                # (1) ffmpeg with -nostats still writes stream mapping, warnings and
                #     the fatal error line to stderr; if nobody reads it the OS pipe
                #     buffer can fill and ffmpeg blocks on write → proc.wait() hangs.
                # (2) on failure we want the *whole* error, not the 500-char tail
                #     job["error"] keeps for the UI — it goes to logs/hls.log.
                stderr_tail: deque[str] = deque(maxlen=300)

                async def _drain_stderr() -> None:
                    assert proc.stderr is not None
                    while True:
                        try:
                            line = await proc.stderr.readline()
                        except Exception:
                            return
                        if not line:
                            return
                        stderr_tail.append(line.decode("utf-8", "replace").rstrip())

                async def _drain_progress() -> None:
                    assert proc.stdout is not None
                    while True:
                        try:
                            line = await proc.stdout.readline()
                        except Exception:
                            return
                        if not line:
                            return
                        try:
                            txt = line.decode("ascii", "replace").strip()
                        except Exception:
                            continue
                        if not txt or "=" not in txt:
                            continue
                        k, _, v = txt.partition("=")
                        if k in ("out_time_ms", "out_time_us") and duration > 0:
                            # out_time_ms is microseconds despite the name on
                            # older ffmpeg; out_time_us is always microseconds.
                            try:
                                out_us = int(v)
                                job["progress"] = max(0.0, min(0.99,
                                    (out_us / 1_000_000.0) / duration))
                            except ValueError:
                                pass
                        elif k == "progress" and v == "end":
                            job["progress"] = 1.0
                            return

                # Stall watchdog — GUARDS THE ALL-GPU ATTEMPT ONLY. If the cuda
                # pipeline deadlocks it hangs forever at low CPU/GPU with no exit;
                # nothing else can break that, so we watch out_time and kill the
                # encode if it stops advancing. The kill makes proc exit non-zero,
                # which (since no intentional-kill flag is set) falls into the
                # `if full_gpu:` retry below → transparent path. Skipped entirely
                # on the transparent / libx264 paths, which are proven and whose
                # progress always advances.
                stall = {"killed": False}

                async def _stall_watchdog() -> None:
                    # Needs a known duration to read progress; without one,
                    # job["progress"] never advances even on a healthy encode, so
                    # skip rather than false-kill (the encode still runs).
                    if not full_gpu or duration <= 0:
                        return
                    last = -1.0
                    idle = 0.0
                    while proc.returncode is None:
                        await asyncio.sleep(5)
                        cur = float(job.get("progress") or 0.0)
                        if cur > last + 1e-9:
                            last, idle = cur, 0.0
                            continue
                        idle += 5
                        if idle >= GPU_STALL_TIMEOUT_SECS:
                            stall["killed"] = True
                            hls_log.warning(
                                "job %s all-GPU encode STALLED %.0fs with no "
                                "progress — killing to retry on transparent path",
                                job_id, idle,
                            )
                            try:
                                proc.kill()
                            except Exception:
                                pass
                            return

                progress_task = asyncio.create_task(_drain_progress())
                stderr_task   = asyncio.create_task(_drain_stderr())
                watchdog_task = asyncio.create_task(_stall_watchdog())
                await proc.wait()
                # Both drain loops end on pipe EOF once the process exits; bound the
                # wait so a wedged pipe can't hang the job indefinitely. The
                # watchdog ends on its own once proc.returncode is set.
                for t in (progress_task, stderr_task, watchdog_task):
                    try:
                        await asyncio.wait_for(t, timeout=5)
                    except (asyncio.TimeoutError, asyncio.CancelledError):
                        t.cancel()

                job["_proc"] = None
                if proc.returncode == 0:
                    break  # success → leave the retry loop and write meta.json

                # Did _free_file_for_compression() terminate us so the source could
                # be rewritten in place? Not a failure — re-queue as pending; the
                # start-of-job compression-lock check parks it until the compress
                # finishes, then it re-preps from the (now smaller) source.
                if job.pop("_compress_block", False):
                    job["status"]   = "pending"
                    job["progress"] = 0.0
                    await asyncio.to_thread(shutil.rmtree, tmp_dir, ignore_errors=True)
                    asyncio.create_task(_requeue_offline_job(job_id, delay=3.0))
                    hls_log.info("job %s re-queued (source being compressed)", job_id)
                    return
                # Did _preempt_running_bulk() boot us for an interactive prep? If so,
                # this isn't a failure — re-queue this bulk file as "pending" so it
                # resumes once the interactive encode releases the slot (it restarts
                # from scratch; HLS prep can't checkpoint mid-file).
                if job.pop("_preempted", False):
                    job["status"]   = "pending"
                    job["progress"] = 0.0
                    await asyncio.to_thread(shutil.rmtree, tmp_dir, ignore_errors=True)
                    asyncio.create_task(_requeue_offline_job(job_id))
                    hls_log.info("job %s re-queued after interactive preemption", job_id)
                    return
                # Did _pause_prep(kill=True) terminate us on purpose? If so, this
                # isn't a real failure — re-queue the job as "paused" (it restarts
                # from scratch on resume; HLS prep can't checkpoint mid-file) and
                # don't surface a spurious error.
                if job.pop("_paused_kill", False):
                    job["status"] = "paused"
                    job["progress"] = 0.0
                    await asyncio.to_thread(shutil.rmtree, tmp_dir, ignore_errors=True)
                    hls_log.info("job %s PAUSED (encode terminated by user)", job_id)
                    return
                # Did the admin hard-stop this force-prep encode? Same deal — the
                # non-zero rc is intentional, so mark it cancelled (not an error)
                # and drop the partial bundle. Not re-queued; the batch is over.
                if job.pop("_admin_stopped", False):
                    job["status"] = "cancelled"
                    job["progress"] = 0.0
                    await asyncio.to_thread(shutil.rmtree, tmp_dir, ignore_errors=True)
                    hls_log.info("job %s CANCELLED (admin hard-stop)", job_id)
                    return
                # Did the item get flagged on-demand-only mid-encode? The terminate
                # came from _apply_ondemand_only, so the non-zero rc is intentional —
                # mark cancelled and drop the partial bundle. Must precede the
                # `full_gpu` retry below so a GPU encode doesn't restart on the
                # transparent path (which is what made the toggle look unresponsive).
                if job.pop("_ondemand_cancelled", False):
                    job["status"] = "cancelled"
                    job["progress"] = 0.0
                    await asyncio.to_thread(shutil.rmtree, tmp_dir, ignore_errors=True)
                    hls_log.info("job %s CANCELLED (flagged on-demand-only)", job_id)
                    return
                # All-GPU attempt failed or stalled. The cuda decode→scale_cuda→
                # nvenc chain can be unsupported for this source/driver (non-zero
                # exit) or DEADLOCK (the watchdog killed it). Either way, wipe the
                # partial bundle and retry ONCE on the transparent CPU-scale path
                # before surfacing an error — so the GPU pipeline can never leave a
                # file unpreppable.
                if full_gpu:
                    reason = ("stalled (watchdog kill)" if stall["killed"]
                              else f"failed rc={proc.returncode}")
                    tail = "\n".join(stderr_tail).strip()
                    hls_log.warning(
                        "job %s all-GPU encode %s — retrying on the transparent "
                        "-hwaccel path.\n  stderr tail:\n%s",
                        job_id, reason, tail[-800:] or "(no stderr captured)",
                    )
                    full_gpu = False
                    await asyncio.to_thread(shutil.rmtree, tmp_dir, ignore_errors=True)
                    tmp_dir.mkdir(parents=True, exist_ok=True)
                    job["progress"] = 0.0
                    continue

                err = "\n".join(stderr_tail).strip()
                elapsed = time.time() - job["started_at"]
                hls_log.error(
                    "job %s FAILED rc=%s after %.1fs src=%s\n"
                    "  ffmpeg cmd: %s\n"
                    "  ffmpeg stderr (last %d lines):\n%s",
                    job_id, proc.returncode, elapsed, src,
                    " ".join(shlex.quote(a) for a in args),
                    len(stderr_tail), err or "(no stderr captured)",
                )
                job["status"] = "error"
                job["error"]  = f"ffmpeg failed: {err[-500:] or 'unknown error'}"
                await asyncio.to_thread(shutil.rmtree, tmp_dir, ignore_errors=True)
                return

            # Sanitise each emitted sub_<i>.vtt: ffmpeg's ASS→WebVTT conversion
            # of typeset fansub tracks leaves duplicate cues, `\p` drawing blobs,
            # and leaked `\h` escapes that render as doubled/garbled subtitles.
            # `_clean_webvtt` collapses them so the bundle is born clean (the
            # serve route applies the same heal to pre-existing bundles).
            for vtt in sorted(tmp_dir.glob("sub_*.vtt")):
                try:
                    raw = await asyncio.to_thread(vtt.read_text, encoding="utf-8", errors="replace")
                    cleaned = _clean_webvtt(raw)
                    if cleaned != raw:
                        await asyncio.to_thread(vtt.write_text, cleaned, encoding="utf-8")
                except OSError:
                    pass

            # Extract embedded fonts for styled ASS/SSA subs so the browser
            # player can render them faithfully with libass-wasm. Only worth the
            # extra ffmpeg pass when a styled sub was actually kept; a source
            # with no font attachments just yields []. Best-effort — never fails
            # the prep. Runs after the .part encode, before the atomic swap, so
            # the fonts land in the same staging dir as everything else.
            bundle_fonts: list[str] = []
            if any(s.get("styled") for s in kept_subs):
                bundle_fonts = await asyncio.to_thread(
                    _extract_bundle_fonts, src, tmp_dir, info)

            # Write meta.json with everything the UI needs to build dropdowns
            # without re-probing the bundle. Held next to the manifest so a
            # straight directory move keeps them in sync.
            meta = {
                "version":      OFFLINE_CACHE_VERSION,
                "src":          str(src),
                "duration_sec": duration,
                # True when the audio renditions were padded with leading silence
                # to start at t≈0 (the `first_pts=0` on the fully-re-encoded ladder
                # — see _build_hls_ffmpeg_args). The detector reads this: a padded
                # bundle's source-offset is baked AS SILENCE, not expressed as a
                # cross-rendition first-pts gap, so its audio-vs-video first-pts
                # should be ≈0 (not ≈source offset). Absent/False ⇒ copy path ⇒
                # faithful-reproduction expectation still applies.
                "audio_padded_to_zero": bool(kept_audios) and not copy_original,
                # ABR video ladder, master-playlist order (idx 0 = original).
                # Informational for admin/API — the player builds its quality
                # menu from hls.js `levels`, not from this ordering.
                "videos": [
                    {
                        "idx":      i,
                        "name":     v["name"],
                        "height":   v["height"],
                        "label":    (f"{v['height']}p (Source)" if i == 0
                                     else f"{v['height']}p"),
                    }
                    for i, v in enumerate(kept_videos)
                ],
                "audios": [
                    {
                        "idx":      i,
                        "playlist": f"audio_{i}.m3u8",
                        "language": a.get("language") or "und",
                        "title":    a.get("title") or "",
                        "label":    _track_label(a, f"Audio {i+1}"),
                        "default":  (i == 0) if all(not x.get("default") for x in kept_audios)
                                    else bool(a.get("default")),
                    }
                    for i, a in enumerate(kept_audios)
                ],
                "subtitles": [
                    {
                        "idx":      i,
                        # Standalone WebVTT sidecar emitted alongside the HLS
                        # bundle (not an in-manifest rendition). The player loads
                        # it as a <track> child. Relative to the bundle dir.
                        "file":     f"sub_{i}.vtt",
                        "language": s.get("language") or "und",
                        "title":    s.get("title") or "",
                        "label":    _track_label(s, f"Subtitles {i+1}"),
                        # Styled ASS/SSA: raw sidecar for the libass-wasm overlay.
                        # Absent ⇒ the player uses the VTT <track> (old bundles /
                        # non-styled subs). See STREAMING.md / GOTCHAS.md.
                        **({"styled": True, "ass_file": f"sub_{i}.ass"}
                           if s.get("styled") else {}),
                    }
                    for i, s in enumerate(kept_subs)
                ],
                "skipped_image_subs": [
                    {"codec": s["codec"], "language": s.get("language") or "und"}
                    for s in (info.get("subtitles") or []) if s.get("image_based")
                ],
                # Embedded fonts (flat filenames in the bundle) the styled subs
                # depend on; [] when there are no styled subs / no font
                # attachments. The player feeds these to libass-wasm.
                "fonts": bundle_fonts,
            }
            (tmp_dir / "meta.json").write_text(json.dumps(meta, indent=2))

            # Atomic-ish swap: rename .part dir into place. Path.rename onto an
            # existing directory fails on every platform, so we drop any prior
            # output first; the master.m3u8 guard at the top of this function
            # handles the "another worker beat us" race separately. The recursive
            # drop of a prior bundle runs in a thread so it doesn't stall the loop.
            if out_dir.exists():
                await asyncio.to_thread(shutil.rmtree, out_dir, ignore_errors=True)
            tmp_dir.rename(out_dir)
            # The bundle now lives beside the source — make the serving index aware
            # of it so the player can fetch segments by key without a rescan.
            _bundle_index_register(out_dir.name, out_dir)

            job["progress"] = 1.0
            job["status"]   = "done"
            size_mb = (await asyncio.to_thread(_dir_size_bytes, out_dir)) / 1_000_000
            hls_log.info(
                "job %s DONE in %.1fs encoder=%s size=%.1f MB src=%s",
                job_id, time.time() - job["started_at"], job["encoder"], size_mb, src,
            )
            # Auto-generate subtitles for sources that have none usable. Reuses
            # the ffprobe we already ran; enqueues a bulk STT job that runs after
            # this HLS encode releases the shared concurrency slot. Best-effort —
            # a failure here must never fail the HLS bundle.
            try:
                await _ensure_stt_for(src, job.get("item_id", ""), info=info, queue="bulk")
            except Exception as exc:
                hls_log.warning("job %s: STT enqueue skipped: %s", job_id, exc)
            # Smart Skip fingerprinting also rides along with prep now (replacing
            # the old download-ready trigger). Fire-and-forget at BELOW_NORMAL
            # priority — a failure here must never fail the HLS bundle.
            try:
                await _ensure_analysis_for(src, job.get("item_id", ""))
            except Exception as exc:
                hls_log.warning("job %s: fingerprint enqueue skipped: %s", job_id, exc)
            # Validate-and-repair-on-prep, "after" mode: deep-decode the source now
            # that the bundle is built. A repair rewrites the file and purges the
            # just-built bundle (keyed on the OLD path|mtime|size), so it re-preps
            # from the healed file next idle cycle — correct, since the bundle was
            # encoded from a damaged source. Best-effort.
            if prep_validate_mode == "after":
                try:
                    await _prep_validate_repair(job, src)
                except Exception as exc:
                    hls_log.warning("job %s: post-prep validate skipped: %s", job_id, exc)
        except Exception as e:
            hls_log.exception("job %s CRASHED: %s", job_id, e)
            job["status"] = "error"; job["error"] = str(e)
            await asyncio.to_thread(shutil.rmtree, tmp_dir, ignore_errors=True)


def _pause_prep(kill: bool) -> int:
    """Pause bulk stream-prep. Sets the global gate so no further bulk job starts.

    kill=False ("Finish current file, then halt") — the file ffmpeg is encoding
    right now runs to completion; every queued file then holds at the gate.
    kill=True ("Stop now") — the in-flight bulk encode is terminated immediately
    for instant relief; it restarts from scratch on resume (HLS prep can't
    checkpoint mid-file). Interactive play-on-device encodes are never killed.

    Returns the number of encodes terminated.
    """
    state.prep_paused = True
    killed = 0
    if kill:
        for j in _offline_jobs.values():
            if j.get("queue") != "bulk" or j.get("status") != "processing":
                continue
            proc = j.get("_proc")
            if proc is not None and proc.returncode is None:
                j["_paused_kill"] = True   # tells _run_offline_job this was intentional
                try:
                    proc.terminate()
                except Exception:
                    pass
                killed += 1
        # Kill running bulk STT (whisper) too — it's the heaviest background load and
        # was previously left churning the CPU/GPU long after HLS prep "paused", which
        # made the box barely usable in the morning. The signalled job re-queues as
        # "paused" (see _run_stt_job) and _resume_prep re-spawns it later.
        for j in _stt_jobs.values():
            if j.get("queue") != "bulk" or j.get("status") != "processing":
                continue
            ev = j.get("_cancel")
            if ev is not None:
                ev.set()
            proc = j.get("_proc")
            if proc is not None:
                try:
                    proc.kill()   # whisper ignores graceful term; SIGKILL/TerminateProcess
                except Exception:
                    pass
            killed += 1
    return killed


def _resume_prep() -> int:
    """Clear the global pause gate and re-spawn a worker for every paused job.

    Paused jobs exited their task at the gate (so they didn't hold the
    concurrency slot), so resuming means creating fresh `_run_offline_job`
    tasks for them. Returns how many were re-queued.
    """
    state.prep_paused = False
    n = 0
    for jid, j in list(_offline_jobs.items()):
        if j.get("status") == "paused":
            j["status"] = "pending"
            j["_proc"] = None
            j.pop("_paused_kill", None)
            asyncio.create_task(_run_offline_job(jid))
            n += 1
    for jid, j in list(_stt_jobs.items()):
        if j.get("status") == "paused":
            j["status"] = "pending"
            asyncio.create_task(_run_stt_job(jid))
            n += 1
    return n


def _bulk_processing_now() -> bool:
    """True if any bulk HLS-prep or STT job is actively encoding/transcribing."""
    return any(j.get("queue") == "bulk" and j.get("status") == "processing"
               for j in (*_offline_jobs.values(), *_stt_jobs.values()))


def _prep_in_progress() -> bool:
    """True if any HLS-prep or STT job is actively encoding/transcribing (any
    queue), or a user/admin-priority prep is queued to start. Used by the
    scheduled reboot's idle guard so the nightly reboot won't interrupt
    in-flight prep — HLS prep can't checkpoint and restarts from scratch.

    Paused bulk prep doesn't count: a soft-paused file still encoding shows as
    `processing` (and is caught here), but jobs parked at the pause gate are
    `paused` and won't run, so they don't hold off the reboot. A momentary
    pending bulk job (slot free, about to start) is picked up on the next 20 s
    loop tick once it flips to `processing`."""
    if any(j.get("status") == "processing"
           for j in (*_offline_jobs.values(), *_stt_jobs.values())):
        return True
    return _priority_hls_pending() > 0


def _priority_hls_pending() -> int:
    """Count priority (non-bulk) HLS jobs that are queued or encoding — both
    interactive (fullscreen "Prep for Device" / play-on-device) and admin
    force-prep. Bulk prep defers to these so a user-initiated prep OR an admin
    force-prep always jumps the queue ahead of auto-prep / manual bulk
    prep — see the precedence gate in `_run_offline_job`."""
    return sum(1 for j in _offline_jobs.values()
               if j.get("queue") in ("interactive", "admin")
               and j.get("status") in ("pending", "processing"))


def _higher_priority_bulk_pending(prio: int) -> int:
    """Count bulk HLS jobs of a STRICTLY-higher prep-priority tier that are queued or
    encoding. A bulk job parks at the encode-slot gate while any exist, so a whole
    series / episode marked "high" preps ahead of "mid"/"low" auto-prep work. Equal
    tiers don't block each other (FIFO), and the top tier never parks, so there's no
    deadlock or starvation of the highest-priority work — see _run_offline_job."""
    return sum(1 for j in _offline_jobs.values()
               if j.get("queue") == "bulk"
               and j.get("status") in ("pending", "processing")
               and int(j.get("_prep_prio", 1)) > prio)


def _preempt_running_bulk(except_job_id: str = "") -> bool:
    """Terminate the bulk HLS encode currently holding the single concurrency slot
    (if any) so a just-queued interactive prep can take it over immediately, instead
    of waiting — potentially minutes — for the in-flight bulk file to finish. The
    killed job re-queues itself (see the `_preempted` branch in `_run_offline_job`)
    and resumes once interactive prep clears; it is **not** abandoned, and the global
    pause gate is left untouched. Returns True if an encode was preempted."""
    for j in _offline_jobs.values():
        if j.get("id") == except_job_id:
            continue
        if j.get("queue") != "bulk" or j.get("status") != "processing":
            continue
        proc = j.get("_proc")
        if proc is not None and proc.returncode is None:
            j["_preempted"] = True   # tells _run_offline_job this kill was intentional
            try:
                proc.terminate()
            except Exception:
                pass
            hls_log.info("job %s PREEMPTED by interactive prep", j.get("id"))
            return True
    return False


async def _requeue_offline_job(job_id: str, delay: float = 0.3) -> None:
    """Re-spawn a worker for a bulk job that yielded its slot to interactive prep,
    after a brief delay so the interactive encode claims the freed slot first."""
    await asyncio.sleep(delay)
    j = _offline_jobs.get(job_id)
    if j and j.get("status") == "pending":
        asyncio.create_task(_run_offline_job(job_id))


def _activity_kick() -> None:
    """Called on genuine user interaction. When Automatic Stream Prep is in **idle
    mode with a hard stop**, stop bulk background work *immediately* — kill the
    in-flight HLS encode AND whisper — instead of waiting up to a full
    `auto_prep_loop` tick. This is the responsiveness lever: a user who shows up
    mid-idle-prep shouldn't sit through ~15 s (or, when whisper wasn't being killed,
    much longer) of a laggy box. The loop then leaves prep paused until the box is
    idle again.

    No-op for "always" mode (prep is meant to run through activity) and for idle
    **soft** stop (the loop's falling-edge graceful pause lets the in-flight file
    finish). No-op once already paused, so it's cheap to call on every request."""
    if state.prep_paused:
        return
    if not state.idle_prep_hard:
        return
    if not (state.auto_prep_engaged or _bulk_processing_now()):
        return
    killed = _pause_prep(kill=True)
    state.auto_prep_engaged = False
    print(f"[autoprep] user activity — pausing prep immediately (killed {killed} in-flight)")


async def _enqueue_library_prep() -> int:
    """Queue a bulk HLS-prep job for every un-prepped video file in the library.

    Used by `auto_prep_loop` (always / idle modes). Idempotent: `_maybe_start_prep_job`
    skips files already cached or already queued, so re-running (e.g. on a
    mid-window restart) only adds genuinely-new work. Returns the count of files
    that still need prep (newly-queued + already in flight).
    """
    if not HLS_AVAILABLE:
        return 0
    lib = await get_library()
    queued = 0
    for item in lib.get("items", []):
        if item.get("ondemand_only"):
            continue   # on-demand-only shows never get a permanent bundle
        prep_cfg = _prep_cfg(item)
        for f in item.get("files", []):
            p = Path(f.get("path", ""))
            if p.suffix.lower() not in VIDEO_EXTS:
                continue
            # Per-file "never" opts a file out of all automatic stream-prep (the
            # episode-picker prep bar). The bundle, if already built, is kept.
            if _effective_prep_mode(prep_cfg, f.get("path", "")) == "never":
                continue
            try:
                if not p.exists():
                    continue
            except OSError:
                continue
            prio = _PREP_PRIO_NUM.get(_effective_prep_priority(prep_cfg, f.get("path", "")), 1)
            st = await _maybe_start_prep_job(p, item.get("id", ""), prep_prio=prio)
            if st.get("status") in ("processing", "pending", "paused"):
                queued += 1
            elif st.get("status") == "cached":
                # Already HLS-prepped, so the post-encode STT hook never fires for
                # it — check here so auto-prep still backfills generated subs for
                # files prepped before STT existed (or before the lang setting).
                await _ensure_stt_for(p, item.get("id", ""), queue="bulk")
            # Yield between every file (sync FS stat + task spawn, no internal
            # await) so scanning a large library never stalls the event loop and
            # the dashboard stays responsive during the auto-prep enqueue.
            await asyncio.sleep(0)
    return queued


# ── Auto-prep on play (settings.play_prep) ───────────────────────────────────
# When a video is played on VLC, immediately HLS-prep that episode for on-device
# viewing, then the rest of the playlist one episode at a time. These jobs are
# queued as "interactive" so they bypass the bulk pause gate AND survive the
# activity-kill — by design they run regardless of the Automatic Stream Prep mode
# or whether someone is actively using the box.

PLAY_PREP_TAIL_SECS = 300  # <5 min left on the current episode ⇒ skip it, start at the next


def _file_duration_sec(item: dict, profile_id: str, file_path: str) -> float:
    """Best-known duration (s) of a file from saved progress, or 0 if unknown."""
    fp = (item.get("progress", {}).get(profile_id, {})
              .get("file_progress", {}).get(file_path, {}))
    try:
        return float(fp.get("duration_sec", 0) or 0)
    except (TypeError, ValueError):
        return 0.0


def _start_interactive_prep_job(src: Path, item_id: str) -> Optional[str]:
    """Start (or coalesce with) an *interactive* HLS-prep job for `src`.

    Returns the job id, or None if the bundle is already cached or ffmpeg is
    unavailable. Interactive jobs ignore the bulk pause gate and are never killed
    by `_pause_prep` / `_activity_kick`, and they preempt any in-flight bulk encode
    so play-driven prep takes the slot immediately. Mirrors the queue-jumping
    branch of `offline_prepare` without an HTTP request."""
    out_dir = _offline_cache_dir(src)
    if (out_dir / "master.m3u8").exists():
        return None
    existing = next(
        (j for j in _offline_jobs.values()
         if j["src"] == str(src) and j["status"] in ("pending", "processing", "paused")),
        None,
    )
    if existing:
        existing["queue"] = "interactive"
        if existing.get("status") == "paused":
            existing["status"] = "pending"
            existing["_proc"] = None
            existing.pop("_paused_kill", None)
            asyncio.create_task(_run_offline_job(existing["id"]))
        _preempt_running_bulk(except_job_id=existing["id"])
        return existing["id"]
    if not analyzer.ffmpeg_bin():
        return None
    job_id = secrets.token_hex(8)
    _offline_jobs[job_id] = {
        "id": job_id, "src": str(src), "out": str(out_dir),
        "status": "pending", "operation": "hls",
        "progress": 0.0, "error": None,
        "started_at": time.time(), "item_id": item_id,
        "queue": "interactive",
    }
    asyncio.create_task(_run_offline_job(job_id))
    _preempt_running_bulk(except_job_id=job_id)
    return job_id


# ── Admin force-prep (settings-free, admin-only) ─────────────────────────────
# An admin can force-prep the whole library (or one item) on demand. These jobs
# use a dedicated "admin" queue: like "interactive" they ignore the bulk pause
# gate and the activity-kill and preempt in-flight bulk work — so neither a
# viewer's Pause control nor live host activity can stop them. UNLIKE
# interactive, the admin can stop them via _stop_admin_prep (soft = let the
# current file finish then cancel the rest; hard = kill the in-flight encode now).

def _start_admin_prep_job(src: Path, item_id: str) -> Optional[str]:
    """Start (or coalesce with) an *admin* force-prep HLS job for `src`.

    Returns the job id, or None if the bundle is already cached or ffmpeg is
    unavailable. Mirrors `_start_interactive_prep_job` but tags the job
    `queue:"admin"` so the admin Stop control (and only it) can halt the batch."""
    if item_id and item_id in state.ondemand_only_items:
        return None   # on-demand-only items never get a permanent bundle
    out_dir = _offline_cache_dir(src)
    if (out_dir / "master.m3u8").exists():
        return None
    existing = next(
        (j for j in _offline_jobs.values()
         if j["src"] == str(src) and j["status"] in ("pending", "processing", "paused")),
        None,
    )
    if existing:
        existing["queue"] = "admin"
        if existing.get("status") == "paused":
            existing["status"] = "pending"
            existing["_proc"] = None
            existing.pop("_paused_kill", None)
            asyncio.create_task(_run_offline_job(existing["id"]))
        _preempt_running_bulk(except_job_id=existing["id"])
        return existing["id"]
    if not analyzer.ffmpeg_bin():
        return None
    job_id = secrets.token_hex(8)
    _offline_jobs[job_id] = {
        "id": job_id, "src": str(src), "out": str(out_dir),
        "status": "pending", "operation": "hls",
        "progress": 0.0, "error": None,
        "started_at": time.time(), "item_id": item_id,
        "queue": "admin",
    }
    asyncio.create_task(_run_offline_job(job_id))
    _preempt_running_bulk(except_job_id=job_id)
    return job_id


async def _enqueue_admin_prep(item_id: str = "") -> int:
    """Force-queue an admin HLS-prep job for every un-prepped video file in the
    library, or just in `item_id` when given. Clears any prior Stop so the new
    batch runs. Returns the count of files newly queued (already-cached files are
    skipped). Yields between files so scanning a large library never stalls the
    event loop."""
    if not HLS_AVAILABLE:
        return 0
    state.admin_prep_stop = False   # a fresh batch overrides a previous Stop
    lib = await get_library()
    queued = 0
    for item in lib.get("items", []):
        if item_id and item.get("id") != item_id:
            continue
        for f in item.get("files", []):
            p = Path(f.get("path", ""))
            if p.suffix.lower() not in VIDEO_EXTS:
                continue
            try:
                if not p.exists():
                    continue
            except OSError:
                continue
            if _start_admin_prep_job(p, item.get("id", "")):
                queued += 1
            await asyncio.sleep(0)
    return queued


def _stop_admin_prep(hard: bool) -> dict:
    """Stop the admin force-prep batch. Sets the gate so no further "admin" job
    starts, and cancels every queued one. `hard=True` also terminates the
    in-flight admin encode immediately; `hard=False` lets the current file finish
    (it completes and is cached) while the rest are dropped. Returns counts."""
    state.admin_prep_stop = True
    cancelled = killed = 0
    for j in _offline_jobs.values():
        if j.get("queue") != "admin":
            continue
        st = j.get("status")
        if st == "pending":
            j["status"] = "cancelled"
            cancelled += 1
        elif st == "processing" and hard:
            proc = j.get("_proc")
            if proc is not None and proc.returncode is None:
                j["_admin_stopped"] = True   # tells _run_offline_job this rc is intentional
                try:
                    proc.terminate()
                except Exception:
                    pass
                killed += 1
    return {"cancelled": cancelled, "killed": killed}


def _force_prep_status() -> dict:
    """Live status of the admin force-prep batch for the admin panel."""
    admin_jobs = [j for j in _offline_jobs.values() if j.get("queue") == "admin"]
    active = [j for j in admin_jobs if j.get("status") in ("pending", "processing")]
    processing = [j for j in active if j.get("status") == "processing"]
    progress = (sum(float(j.get("progress", 0)) for j in active) / len(active)
                if active else 0.0)
    return {
        "hls_available": HLS_AVAILABLE,
        "active":        bool(active),
        "stopped":       state.admin_prep_stop,
        "total":         len(active),
        "processing":    len(processing),
        "pending":       len(active) - len(processing),
        "progress":      round(progress, 3),
    }


# ── Source-file validator ─────────────────────────────────────────────────────
# Decodes each library video with ffmpeg to surface CORRUPT or unreadable SOURCE
# files. Deliberately independent of qBit's piece recheck: a torrent only proves
# the bytes on disk match the torrent's hashes, so it happily seeds a perfect
# copy of a file that was already damaged at the source (bad encode, truncated
# rip, bit-rot before it was added). This actually decodes the media.
#
#   • deep  (default) — full ffmpeg decode of every video+audio stream
#     (`-f null -`, `-xerror` to bail on the first error); any ffmpeg error
#     output ⇒ damaged. Catches mid-file corruption a header probe misses, at
#     the cost of reading the whole file.
#   • quick — ffprobe the container only (header + stream list + duration). Fast,
#     but only catches files that won't even open.
#
# ffmpeg runs BELOW normal priority (_FFMPEG_SUBPROCESS_KW / nice) so a scan
# can't starve playback, one file at a time. The Stop flag is checked between
# files and the in-flight proc is terminated. Works on every OS (plain decode —
# not HLS, so unlike prep it is NOT macOS-gated).

def _safe_unlink(p: Path) -> None:
    """Best-effort delete of a temp file; never raises."""
    try:
        if p.exists():
            p.unlink()
    except OSError:
        pass


async def _run_ffmpeg_capture(args: list[str], set_proc) -> tuple[int, str]:
    """Run an ffmpeg command at below-normal priority, capturing the last line of
    its stderr. `set_proc(proc)` stashes the live process so a Stop control can
    terminate it (and `set_proc(None)` clears it on exit). Returns (rc, tail)."""
    cmd = _ffmpeg_nice_prefix() + args
    try:
        proc = await asyncio.create_subprocess_exec(
            *cmd,
            stdout=asyncio.subprocess.DEVNULL,
            stderr=asyncio.subprocess.PIPE,
            **_FFMPEG_SUBPROCESS_KW,
        )
    except Exception as e:
        return 1, f"Could not launch ffmpeg: {e}"
    set_proc(proc)
    try:
        _, err = await proc.communicate()
    finally:
        set_proc(None)
    errtext = (err or b"").decode("utf-8", "replace").strip()
    tail = errtext.splitlines()[-1][:300] if errtext else ""
    return (proc.returncode or 0), tail


async def _ffmpeg_decode_scan(ffmpeg: str, path: str, set_proc, is_stopped) -> tuple[int, str]:
    """Full decode of every video+audio stream (`-f null -`, `-xerror`). Returns
    (rc, error_tail); rc 0 + empty tail ⇒ clean. If the scan was Stopped mid-decode
    (`is_stopped()` true), returns (0, "") so a cancelled file isn't judged.
    Decodes on the GPU when NVENC is present (`_decode_hwaccel_args`)."""
    args = [
        ffmpeg, "-hide_banner", "-v", "error", "-xerror",
        *(await _decode_hwaccel_args(sample=Path(path))),
        "-i", path, "-map", "0:v?", "-map", "0:a?",
        "-f", "null", "-",
    ]
    rc, tail = await _run_ffmpeg_capture(args, set_proc)
    if is_stopped():
        return 0, ""
    return rc, tail


def _file_validation_status() -> dict:
    """JSON-safe snapshot of the current/last validation run for the admin card."""
    fv = dict(state.file_validation)
    fv.pop("_proc", None)
    fv.setdefault("running", False)
    fv.setdefault("scanned", 0)
    fv.setdefault("total", 0)
    fv.setdefault("damaged", [])
    fv.setdefault("missing", [])
    fv["available"] = bool(analyzer.ffmpeg_bin())
    return fv


async def _validate_one_file(ffmpeg: str, path: str, deep: bool, *,
                             set_proc, is_stopped) -> tuple[bool, str]:
    """Return (ok, detail). ok=False ⇒ the file is damaged/unreadable; `detail` is
    a short human-readable reason (the tail of ffmpeg/ffprobe's error output).
    `set_proc`/`is_stopped` thread the live ffmpeg + a cancel check through so the
    same helper serves both the admin scan and the in-prep hook (each bound to its
    own process slot / stop flag)."""
    if not deep:
        info = await asyncio.to_thread(_ffprobe_full, path)
        if not info:
            return False, "ffprobe could not read the file (corrupt or unsupported container)."
        if not info.get("video"):
            return False, "No decodable video stream found."
        if float(info.get("duration_sec") or 0) <= 0:
            return False, "Container reports no / zero duration."
        return True, ""
    # Deep: decode the whole file. `-xerror` aborts on the first decode error so a
    # badly-damaged file fails fast.
    rc, tail = await _ffmpeg_decode_scan(ffmpeg, path, set_proc, is_stopped)
    # A Stop-terminated decode is not a verdict — don't flag a cancelled file as
    # damaged. The runner halts the loop separately on the same flag.
    if is_stopped():
        return True, ""
    if rc != 0 or tail:
        return False, tail or f"ffmpeg exited with code {rc}."
    return True, ""


# ── Persistent validation verdicts + backlog accounting ──────────────────────
# Validation results are written back into library.json (`files[].validation`)
# so: (a) the outstanding-work counts are a cheap library read, (b) a file is
# never re-validated until it actually changes, and (c) the idle auto-validator
# RESUMES across restarts instead of starting the whole library over.

def _file_sig(path: str) -> str:
    """`mtime:size` signature used to detect a file changing under a stored
    verdict (re-download, repair, re-encode). Empty when the file is gone."""
    try:
        st = os.stat(path)
        return f"{int(st.st_mtime)}:{st.st_size}"
    except OSError:
        return ""


def _make_verdict(status: str, error: str, path: str) -> dict:
    """Build a persisted validation verdict. `status ∈ ok|damaged|missing`."""
    return {
        "status": status,
        "error":  (error or "")[:300],
        "sig":    "" if status == "missing" else _file_sig(path),
        "at":     _now_iso(),
    }


def _needs_validation(f: dict) -> bool:
    """True if a video file needs a (re)validation pass: never validated, or its
    signature changed since the stored verdict. A file last seen *missing* is only
    re-validated once it actually exists again (non-empty signature) — so a
    deselected / not-yet-downloaded file doesn't get decoded on every idle cycle.
    Stats the file (used by the auto-validator to decide real work)."""
    if Path(f.get("path", "")).suffix.lower() not in VIDEO_EXTS:
        return False
    v = f.get("validation")
    if not isinstance(v, dict) or not v.get("status"):
        return True
    if v.get("status") == "missing":
        return bool(_file_sig(f.get("path", "")))   # only when the file is back
    return v.get("sig", "") != _file_sig(f.get("path", ""))


def _needs_validation_cheap(f: dict) -> bool:
    """Backlog-count variant of `_needs_validation` that does NOT stat the file
    (so the outstanding-work counts stay cheap on the 4 s Activity poll). A file
    is counted only until it has ANY settled verdict — including `missing`, so a
    deselected file doesn't keep the backlog non-zero forever."""
    if Path(f.get("path", "")).suffix.lower() not in VIDEO_EXTS:
        return False
    v = f.get("validation")
    return not (isinstance(v, dict) and v.get("status"))


async def _persist_validations(verdicts: dict) -> None:
    """Write a batch of {path → verdict} into the matching `files[].validation`."""
    if not verdicts:
        return
    lib = await get_library()
    changed = False
    for it in lib.get("items", []):
        for f in it.get("files", []):
            v = verdicts.get(f.get("path", ""))
            if v is not None:
                f["validation"] = v
                changed = True
    if changed:
        await put_library(lib)


def _validation_backlog(lib: dict) -> int:
    return sum(1 for it in lib.get("items", [])
               for f in it.get("files", []) if _needs_validation_cheap(f))


def _needs_fingerprint(f: dict, skip_data: dict) -> bool:
    """Whether a file still needs Smart Skip fingerprinting (mirrors the eligibility
    test in `_schedule_series_analysis_if_eligible`: manual edits and prior
    failures are sticky; a version bump re-qualifies)."""
    fd = skip_data.get(f.get("path", ""))
    if not fd:
        return True
    ana = fd.get("analysis") or {}
    if ana.get("source") == "manual":
        return False
    return ana.get("version", 0) < analyzer.ANALYZER_VERSION


def _fingerprint_backlog(lib: dict) -> int:
    if not analyzer.is_available():
        return 0
    n = 0
    for it in lib.get("items", []):
        if it.get("status") != "ready":
            continue
        sk = it.get("skip_data", {})
        for f in _analyzable_files(it):
            if _needs_fingerprint(f, sk):
                n += 1
    return n


def _any_analysis_running() -> bool:
    return any((j or {}).get("status") == "running"
               for j in state.analysis_jobs.values())


def _find_unfingerprinted_series(lib: dict) -> Optional[str]:
    """First series key with a never-fingerprinted analyzable file among its ready
    items, skipping series already running or marked failed this session (failures
    are sticky — don't auto-retry in a loop)."""
    seen: set[str] = set()
    for it in lib.get("items", []):
        if it.get("status") != "ready":
            continue
        key = _series_key(it)
        if key in seen:
            continue
        seen.add(key)
        job = state.analysis_jobs.get(key) or {}
        if job.get("status") in ("running", "failed"):
            continue
        for peer in _items_for_series_key(lib, key):
            if peer.get("status") != "ready":
                continue
            sk = peer.get("skip_data", {})
            if any(_needs_fingerprint(f, sk) for f in _analyzable_files(peer)):
                return key
    return None


def _prep_backlog_from_snapshot() -> Optional[int]:
    """Un-prepped (no HLS bundle) video-file count from the cached offline-cache
    inventory, or None if no snapshot has been built yet. Deliberately reuses the
    cached walk — never triggers a fresh (heavy) filesystem walk from a poll."""
    snap = _offline_cache_inv_snapshot
    if not snap:
        return None
    n = 0
    for it in snap.get("items", []):
        n += max(0, int(it.get("file_count", 0)) - int(it.get("cached_count", 0)))
    return n


async def _run_auto_validation() -> None:
    """Idle-gated background validation of files lacking a current verdict. One
    file at a time at below-normal priority; persists each verdict (incrementally)
    so it resumes after a restart. Bails the instant the box becomes active or an
    admin scan starts, so it never competes with viewing or the manual scan."""
    av = state.auto_validate
    ffmpeg = analyzer.ffmpeg_bin()
    if not ffmpeg:
        av["running"] = False
        return
    verdicts: dict[str, dict] = {}

    def _interrupted() -> bool:
        return bool(state.auto_validate_stop) or bool(state.file_validation.get("running"))

    try:
        lib = await get_library()
        targets: list[tuple[str, str]] = []   # (path, name)
        for it in lib.get("items", []):
            for f in it.get("files", []):
                if _needs_validation(f):
                    targets.append((f.get("path", ""),
                                    f.get("name") or Path(f.get("path", "")).name))
                await asyncio.sleep(0)
        av["total"] = len(targets)
        av["scanned"] = 0
        for (path, name) in targets:
            if _interrupted() or await _machine_in_use(60):
                break
            av["current_name"] = name
            src = Path(path)
            try:
                exists = src.exists()
            except OSError:
                exists = False
            if not exists:
                verdicts[path] = _make_verdict("missing", "File not found on disk.", path)
            else:
                ok, detail = await _validate_one_file(
                    ffmpeg, path, True,
                    set_proc=lambda p: setattr(state, "auto_validate_proc", p),
                    is_stopped=_interrupted,
                )
                if _interrupted():
                    break
                verdicts[path] = _make_verdict("ok" if ok else "damaged",
                                               "" if ok else detail, path)
            av["scanned"] = av.get("scanned", 0) + 1
            if len(verdicts) >= 5:        # checkpoint so a crash loses ≤5 files
                await _persist_validations(verdicts)
                verdicts = {}
    except asyncio.CancelledError:
        raise
    except Exception as e:
        av["error"] = str(e)
        log.warning("auto-validation: %s", e)
    finally:
        await _persist_validations(verdicts)
        av["running"] = False
        av["current_name"] = ""
        state.auto_validate_proc = None


async def background_maintenance_loop() -> None:
    """Every 30 s, while the host is idle, drain outstanding background work that
    would otherwise wait for a manual trigger — Smart Skip fingerprinting and
    source-file validation (see `_auto_maint_cfg`). Idle-gated and serialized so
    it never competes with viewing and never runs both heavy passes at once.

    NB: idle is checked WITHOUT `for_prep=True` on purpose — an admin watching the
    Activity tab (which holds an SSE connection) must not block the very work the
    tab exists to show. Genuine playback / recent interaction still pauses it."""
    await asyncio.sleep(20)   # let startup settle before the first sweep
    while True:
        try:
            lib = await get_library()
            cfg = _auto_maint_cfg(lib)
            if (cfg["fingerprint"] or cfg["validate"]) and not await _machine_in_use(300):
                started_fp = False
                if cfg["fingerprint"] and analyzer.is_available() and not _any_analysis_running():
                    key = _find_unfingerprinted_series(lib)
                    if key:
                        asyncio.create_task(_run_series_analysis(key))
                        started_fp = True
                # Don't stack the two heavy passes: skip validation on a tick that
                # just kicked off a fingerprint run, or while either is active.
                if (cfg["validate"] and not started_fp and analyzer.ffmpeg_bin()
                        and not state.auto_validate.get("running")
                        and not state.file_validation.get("running")
                        and not _any_analysis_running()
                        # Accurate (stat-based) check — a flat os.stat per library
                        # file is cheap (unlike the recursive cache walk), and it
                        # catches sig-changed files the no-stat count would miss.
                        and any(_needs_validation(f)
                                for it in lib.get("items", []) for f in it.get("files", []))):
                    state.auto_validate_stop = False
                    state.auto_validate = {"running": True, "total": 0, "scanned": 0,
                                           "current_name": "", "started_at": _now_iso()}
                    state.auto_validate_task = asyncio.create_task(_run_auto_validation())
        except Exception as e:
            log.warning("background_maintenance_loop: %s", e)
        await asyncio.sleep(30)


async def _run_file_validation(scope: str, deep: bool) -> None:
    """Walk the library (or one item) and validate each video file, updating
    state.file_validation in place so the admin card can poll progress."""
    fv = state.file_validation
    ffmpeg = analyzer.ffmpeg_bin()
    verdicts: dict[str, dict] = {}   # path → persisted verdict (drains the backlog)
    try:
        lib = await get_library()
        targets: list[tuple[str, str, str, str]] = []   # (item_id, item_title, path, name)
        for item in lib.get("items", []):
            if scope not in ("", "all") and item.get("id") != scope:
                continue
            for f in item.get("files", []):
                p = f.get("path", "")
                if Path(p).suffix.lower() not in VIDEO_EXTS:
                    continue
                targets.append((item.get("id", ""), item.get("title", ""),
                                p, f.get("name") or Path(p).name))
                await asyncio.sleep(0)
        fv["total"] = len(targets)
        for (iid, title, path, name) in targets:
            if state.file_validation_stop:
                fv["stopped"] = True
                break
            fv["current_name"] = name
            src = Path(path)
            try:
                exists = src.exists()
            except OSError:
                exists = False
            if not exists:
                fv["missing"].append({"item_id": iid, "item_title": title,
                                      "path": path, "name": name})
                verdicts[path] = _make_verdict("missing", "File not found on disk.", path)
            elif not ffmpeg:
                fv["error"] = "ffmpeg is not installed — cannot validate files."
                break
            else:
                ok, detail = await _validate_one_file(
                    ffmpeg, path, deep,
                    set_proc=lambda p: setattr(state, "file_validation_proc", p),
                    is_stopped=lambda: state.file_validation_stop,
                )
                if not state.file_validation_stop:
                    if not ok:
                        fv["damaged"].append({"item_id": iid, "item_title": title,
                                              "path": path, "name": name, "error": detail})
                    verdicts[path] = _make_verdict("ok" if ok else "damaged",
                                                   "" if ok else detail, path)
            fv["scanned"] = fv.get("scanned", 0) + 1
    except asyncio.CancelledError:
        fv["stopped"] = True
        raise
    except Exception as e:
        fv["error"] = str(e)
    finally:
        await _persist_validations(verdicts)
        fv["running"] = False
        fv["current_name"] = ""
        fv["finished_at"] = _now_iso()
        state.file_validation_proc = None


# ── Source-file repair ────────────────────────────────────────────────────────
# Best-effort, in-place repair of a damaged source file. Two staged attempts,
# each validated with the same deep decode the validator uses; the original is
# only replaced when a candidate decodes CLEAN:
#
#   1. REMUX (lossless, fast) — `-c copy` with `-err_detect ignore_err` and
#      regenerated timestamps. Fixes the common cases: broken index / moov atom,
#      bad/missing PTS, a few recoverable stream errors. No quality loss.
#   2. RE-ENCODE (lossy, slow, opt-in) — decode with error concealment and
#      re-encode the video (libx264) so genuinely corrupt frames are dropped /
#      concealed rather than aborting playback.
#
# On success the stale HLS bundle (keyed on the OLD path|mtime|size) is purged so
# playback re-preps from the repaired file. NOTE: this rewrites the file, so a
# torrent-backed file will stop matching its pieces and seeding will halt — for
# those, re-downloading (qBit recheck) is usually the better fix; repair is aimed
# at uploaded / non-torrent content. Surfaced as a caveat in the UI.

def _file_repair_status() -> dict:
    """JSON-safe snapshot of the current/last repair run for the admin card."""
    fr = dict(state.file_repair)
    fr.setdefault("running", False)
    fr.setdefault("scanned", 0)
    fr.setdefault("total", 0)
    fr.setdefault("repaired", [])
    fr.setdefault("failed", [])
    fr["available"] = bool(analyzer.ffmpeg_bin())
    return fr


async def _repair_one_file(ffmpeg: str, path: str, reencode: bool, *,
                           set_proc, is_stopped) -> tuple[str, str]:
    """Attempt to repair a damaged file in place. Returns (result, detail) where
    result ∈ "repaired" | "failed". On success the original is atomically replaced
    by the validated repair and its stale HLS bundle is purged; `detail` is the
    method ("remux" / "re-encode") or, on failure, the reason. `set_proc`/
    `is_stopped` thread the live ffmpeg + cancel check through so the same helper
    serves both the admin repair and the in-prep hook."""
    src = Path(path)
    try:
        if not src.exists():
            return "failed", "File is no longer on disk."
        old_bundle = _offline_cache_dir(src)     # stash BEFORE we change name/size
    except OSError as e:
        return "failed", f"Cannot access file: {e}"

    stopped = is_stopped
    suffix = src.suffix or ".mkv"

    attempts: list[tuple[str, Path, list[str]]] = []
    tmp_remux = src.with_name(src.stem + ".repair-remux" + suffix)
    attempts.append(("remux", tmp_remux, [
        ffmpeg, "-hide_banner", "-v", "error", "-y",
        "-err_detect", "ignore_err", "-fflags", "+genpts+igndts",
        "-i", str(src), "-map", "0", "-ignore_unknown",
        "-c", "copy", str(tmp_remux),
    ]))
    if reencode:
        tmp_reenc = src.with_name(src.stem + ".repair-reenc" + suffix)
        # GPU the heavy re-encode when NVENC is present (decode on the GPU too,
        # transparent `-hwaccel cuda`, gated on an NVDEC probe so AV1/odd sources
        # CPU-decode instead of hard-failing). NVENC uses p-presets + `-cq` rather
        # than libx264's veryfast/crf, so swap the whole video leg.
        hw = await _decode_hwaccel_args(sample=src)
        if hw:
            venc = ["-c:v", "h264_nvenc", "-preset", "p4", "-cq", "23"]
        else:
            venc = ["-c:v", "libx264", "-preset", "veryfast", "-crf", "20",
                    "-threads", str(OFFLINE_FFMPEG_THREADS)]
        # Carry every embedded subtitle through the re-encode — the remux leg keeps
        # them via `-map 0`, and the re-encode must too, or repairing a damaged file
        # would silently strip its baked-in subs. `-c:s copy` survives in MKV (and
        # also preserves image subs like PGS/VOBSUB); MP4/MOV can't copy subrip, so
        # text subs go in as mov_text. Attachments (ASS fonts) only ride along in
        # MKV — MP4 can't hold them, and mapping `0:t?` there would fail the encode.
        is_mp4ish = suffix.lower() in {".mp4", ".m4v", ".mov"}
        sub_map = ["-map", "0:v:0?", "-map", "0:a?", "-map", "0:s?"]
        if not is_mp4ish:
            sub_map += ["-map", "0:t?"]
        attempts.append(("re-encode", tmp_reenc, [
            ffmpeg, "-hide_banner", "-v", "error", "-y",
            "-err_detect", "ignore_err", "-fflags", "+genpts",
            *hw,
            "-i", str(src),
            *sub_map,
            "-ignore_unknown",
            *venc,
            "-c:a", "aac", "-b:a", "192k",
            "-c:s", "mov_text" if is_mp4ish else "copy",
            str(tmp_reenc),
        ]))

    last_err = "Repair did not produce a playable file."
    for method, tmp, args in attempts:
        if stopped():
            break
        rc, tail = await _run_ffmpeg_capture(args, set_proc)
        if stopped():
            _safe_unlink(tmp)
            break
        try:
            ok_file = tmp.exists() and tmp.stat().st_size > 0
        except OSError:
            ok_file = False
        if rc != 0 or not ok_file:
            last_err = tail or f"{method} failed (ffmpeg exited {rc})."
            _safe_unlink(tmp)
            continue
        # Validate the candidate with the same deep decode used by the scanner.
        vrc, vtail = await _ffmpeg_decode_scan(ffmpeg, str(tmp), set_proc, stopped)
        if stopped():
            _safe_unlink(tmp)
            break
        if vrc != 0 or vtail:
            last_err = f"{method} ran but the result still has decode errors" + (f": {vtail}" if vtail else ".")
            _safe_unlink(tmp)
            continue
        # Clean — atomically replace the original, then purge its stale HLS bundle.
        try:
            os.replace(str(tmp), str(src))
        except OSError as e:
            _safe_unlink(tmp)
            return "failed", f"Could not replace the original file: {e}"
        try:
            if old_bundle.exists():
                await asyncio.to_thread(shutil.rmtree, old_bundle, ignore_errors=True)
            _invalidate_offline_cache_inventory()
            _invalidate_bundle_index()
        except Exception:
            pass
        return "repaired", method
    return "failed", last_err


async def _run_file_repair(paths: list[str], reencode: bool) -> None:
    """Repair each path in turn (remux, then optional re-encode), updating
    state.file_repair in place so the admin card can poll progress."""
    fr = state.file_repair
    ffmpeg = analyzer.ffmpeg_bin()
    try:
        lib = await get_library()
        meta: dict[str, tuple[str, str, bool]] = {}   # path → (item_title, name, torrent-backed)
        for item in lib.get("items", []):
            torrent = bool(item.get("torrent_hash"))
            for f in item.get("files", []):
                p = f.get("path", "")
                meta[p] = (item.get("title", ""), f.get("name") or Path(p).name, torrent)
        fr["total"] = len(paths)
        for path in paths:
            if state.file_repair_stop:
                fr["stopped"] = True
                break
            title, name, torrent = meta.get(path, ("", Path(path).name, False))
            fr["current_name"] = name
            if not ffmpeg:
                fr["error"] = "ffmpeg is not installed — cannot repair files."
                break
            result, detail = await _repair_one_file(
                ffmpeg, path, reencode,
                set_proc=lambda p: setattr(state, "file_repair_proc", p),
                is_stopped=lambda: state.file_repair_stop,
            )
            if state.file_repair_stop and result != "repaired":
                fr["stopped"] = True
                break
            entry = {"path": path, "name": name, "item_title": title, "torrent": torrent}
            if result == "repaired":
                entry["method"] = detail
                fr["repaired"].append(entry)
            else:
                entry["error"] = detail
                fr["failed"].append(entry)
            fr["scanned"] = fr.get("scanned", 0) + 1
    except asyncio.CancelledError:
        fr["stopped"] = True
        raise
    except Exception as e:
        fr["error"] = str(e)
    finally:
        fr["running"] = False
        fr["current_name"] = ""
        fr["finished_at"] = _now_iso()
        state.file_repair_proc = None


# ── Source-file compression ──────────────────────────────────────────────────
# In-place lossy re-encode of source files to reclaim disk space, modelled on the
# repair re-encode: re-encode the video (H.264 or HEVC) at a chosen quality, copy
# audio + every embedded subtitle/attachment, deep-decode the candidate, and
# replace the original ONLY when it decodes clean AND came out smaller — then purge
# the stale HLS bundle so on-device playback re-preps from the smaller source.
# Like repair, this rewrites the file, so a torrent-backed copy stops seeding;
# aimed at uploaded / non-torrent content. Surfaced as a caveat in the UI.

# Compression presets → (x264 CRF, x265 CRF, max output height | None = keep).
# Higher CRF = smaller + lower quality. The down-scale cap on the stronger tiers
# is where most of the savings come from on 4K/1080p sources.
COMPRESSION_PRESETS = {
    "light":    {"crf264": 21, "crf265": 24, "max_height": None},
    "balanced": {"crf264": 24, "crf265": 27, "max_height": 1080},
    "maximum":  {"crf264": 28, "crf265": 30, "max_height": 720},
}
# Rough target VIDEO bitrate (kbps) by output-height bucket × preset, used ONLY by
# the savings estimator (the real encode is CRF/quality-driven). HEVC is scaled by
# ~0.6 for the same perceptual quality.
_COMPRESS_EST_KBPS = {
    1080: {"light": 4000, "balanced": 2500, "maximum": 1500},
    720:  {"light": 2000, "balanced": 1400, "maximum": 900},
    480:  {"light": 1000, "balanced": 800,  "maximum": 500},
    0:    {"light": 600,  "balanced": 450,  "maximum": 300},
}


def _compression_params(level: str, codec: str, crf: Optional[int]) -> tuple[int, Optional[int]]:
    """Resolve (crf, max_height) for a compression run. An explicit `crf` (Advanced
    mode) overrides the preset's CRF and disables down-scaling; otherwise the preset
    maps to a codec-appropriate CRF + optional height cap."""
    preset = COMPRESSION_PRESETS.get(level, COMPRESSION_PRESETS["balanced"])
    if crf is not None:
        return max(18, min(32, int(crf))), None
    return (preset["crf265"] if codec == "hevc" else preset["crf264"]), preset["max_height"]


def _est_bucket(height: int) -> int:
    for b in (1080, 720, 480):
        if height >= b:
            return b
    return 0


def _file_compression_status() -> dict:
    """JSON-safe snapshot of the current/last compression run for the admin card."""
    fc = dict(state.file_compression)
    fc.setdefault("running", False)
    fc.setdefault("scanned", 0)
    fc.setdefault("total", 0)
    fc.setdefault("results", [])
    fc.setdefault("bytes_before", 0)
    fc.setdefault("bytes_after", 0)
    fc["bytes_freed"] = max(0, fc.get("bytes_before", 0) - fc.get("bytes_after", 0))
    fc["available"] = bool(analyzer.ffmpeg_bin())
    return fc


def _norm_path(path: str) -> str:
    """Canonical path key — case- and separator-insensitive so Windows path
    variants of the same file collide. Used for the compression playback lock
    and for matching a bundle's source against a library item's files."""
    try:
        return os.path.normcase(os.path.normpath(os.path.abspath(str(path))))
    except Exception:
        return os.path.normcase(str(path))


def _compress_lock_key(path: str) -> str:
    """Normalised path key for the compression playback-lock set."""
    return _norm_path(path)


def _is_compressing(path: str) -> bool:
    """True if `path` is currently being compressed (playback is locked)."""
    return _compress_lock_key(path) in state.compressing_paths


def _assert_not_compressing(path: str) -> None:
    """Raise 423 if a file is mid-compress. The robust server-side gate behind
    every playback/read path — even the ones the user didn't click (auto-advance,
    warm-prep, on-demand, clip, handoff) — so nothing can hold the file open while
    it's being rewritten in place."""
    if _is_compressing(path):
        raise HTTPException(
            423, "This episode is being compressed to save space — playback is "
                 "locked until it finishes. Try again in a moment.")


async def _free_file_for_compression(path: str) -> None:
    """Release every handle on `path` so the in-place replace can't hit WinError 5:
    stop VLC if it's playing this exact file, tear down any on-demand JIT session
    reading it, and terminate any in-flight HLS prep encoding it. The lock (already
    set by the caller) stops anything new from grabbing it again."""
    key = _compress_lock_key(path)
    # 1. VLC (TV) — holds the source open for the whole playback. Stop it.
    try:
        cur = state.library_current_file
        if cur and _compress_lock_key(cur) == key:
            hls_log.info("compression: stopping VLC playback of %s", Path(path).name)
            await stop()
    except Exception:
        pass
    # 2. On-demand JIT sessions — ffmpeg reads the source live; tear them down.
    try:
        for skey, s in list(_od_sessions.items()):
            if _compress_lock_key(s.get("src", "")) == key:
                await _od_teardown(skey)
    except Exception:
        pass
    # 3. In-flight HLS prep of this file — terminate it so it stops reading the
    #    source. `_compress_block` makes _run_offline_job re-queue (defer) rather
    #    than error, so it picks the file back up after the lock clears.
    try:
        for j in list(_offline_jobs.values()):
            if (_compress_lock_key(j.get("src", "")) == key
                    and j.get("status") in ("pending", "processing")):
                j["_compress_block"] = True
                proc = j.get("_proc")
                if proc is not None and proc.returncode is None:
                    try:
                        proc.terminate()
                    except Exception:
                        pass
    except Exception:
        pass


async def _compress_one_file(ffmpeg: str, path: str, *, crf: int, codec: str,
                             max_height: Optional[int], set_proc, is_stopped
                             ) -> tuple[str, str, int, int]:
    """Lock-guarded wrapper around the actual compress. Adds the file to the
    playback lock, frees any in-flight reader (VLC / on-demand / prep), runs the
    re-encode, then always releases the lock — so a file is never left
    unplayable if the encode errors or is cancelled."""
    lock_key = _compress_lock_key(path)
    state.compressing_paths.add(lock_key)
    try:
        await _free_file_for_compression(path)
        return await _compress_one_file_inner(
            ffmpeg, path, crf=crf, codec=codec, max_height=max_height,
            set_proc=set_proc, is_stopped=is_stopped)
    finally:
        state.compressing_paths.discard(lock_key)


async def _compress_one_file_inner(ffmpeg: str, path: str, *, crf: int, codec: str,
                                   max_height: Optional[int], set_proc, is_stopped
                                   ) -> tuple[str, str, int, int]:
    """Re-encode one source file in place to save space. Returns
    (status, detail, bytes_before, bytes_after) where status ∈
    "compressed" | "skipped" | "failed". On success the original is atomically
    replaced and its stale HLS bundle purged; "skipped" means the re-encode wasn't
    smaller (already-efficient source) and the original is left untouched."""
    src = Path(path)
    try:
        if not src.exists():
            return "failed", "File is no longer on disk.", 0, 0
        before = src.stat().st_size
        old_bundle = _offline_cache_dir(src)     # stash BEFORE we change name/size
    except OSError as e:
        return "failed", f"Cannot access file: {e}", 0, 0

    stopped = is_stopped
    info = await asyncio.to_thread(_ffprobe_full, str(src))
    if not info.get("video"):
        return "failed", "No decodable video stream.", before, before
    src_h = int((info.get("video") or {}).get("height") or 0)

    suffix = src.suffix or ".mkv"
    is_mp4ish = suffix.lower() in {".mp4", ".m4v", ".mov"}
    tmp = src.with_name(src.stem + ".compress" + suffix)

    # GPU-accelerate decode (and encode) when NVENC is present; CPU fallback uses
    # libx264/libx265. NVENC uses p-presets + `-cq`; libx26x uses `-preset/-crf`.
    # Decode hwaccel is gated on an NVDEC probe so AV1/odd sources CPU-decode
    # instead of hard-failing.
    hw = await _decode_hwaccel_args(sample=src, info=info)
    if hw:
        venc = ["-c:v", ("hevc_nvenc" if codec == "hevc" else "h264_nvenc"),
                "-preset", "p4", "-cq", str(crf)]
    else:
        venc = ["-c:v", ("libx265" if codec == "hevc" else "libx264"),
                "-preset", "medium", "-crf", str(crf),
                "-threads", str(OFFLINE_FFMPEG_THREADS)]
        if codec == "hevc":
            venc += ["-x265-params", "log-level=error"]
    if codec == "hevc" and is_mp4ish:
        venc += ["-tag:v", "hvc1"]            # so QuickTime/Safari recognise the HEVC

    vf = []
    if max_height and src_h and src_h > max_height:
        vf = ["-vf", f"scale=-2:{max_height}"]   # -2 keeps an even width for yuv420p

    # Keep every audio + embedded subtitle/attachment (copy), like the repair leg —
    # we re-encode only the video. Same container ⇒ audio copy is always muxable.
    sub_map = ["-map", "0:v:0?", "-map", "0:a?", "-map", "0:s?"]
    if not is_mp4ish:
        sub_map += ["-map", "0:t?"]
    args = [
        ffmpeg, "-hide_banner", "-v", "error", "-y",
        *hw,
        "-i", str(src),
        *sub_map, "-ignore_unknown",
        *vf, *venc, "-pix_fmt", "yuv420p",
        "-c:a", "copy",
        "-c:s", "mov_text" if is_mp4ish else "copy",
        str(tmp),
    ]

    if stopped():
        return "skipped", "stopped", before, before
    rc, tail = await _run_ffmpeg_capture(args, set_proc)
    if stopped():
        _safe_unlink(tmp)
        return "skipped", "stopped", before, before
    try:
        ok_file = tmp.exists() and tmp.stat().st_size > 0
    except OSError:
        ok_file = False
    if rc != 0 or not ok_file:
        _safe_unlink(tmp)
        return "failed", (tail or f"ffmpeg exited {rc}."), before, before

    # Trust the result only if it decodes clean — a re-encode that introduced
    # corruption must never replace a good source.
    vrc, vtail = await _ffmpeg_decode_scan(ffmpeg, str(tmp), set_proc, stopped)
    if stopped():
        _safe_unlink(tmp)
        return "skipped", "stopped", before, before
    if vrc != 0 or vtail:
        _safe_unlink(tmp)
        return "failed", ("re-encode produced decode errors" + (f": {vtail}" if vtail else ".")), before, before

    try:
        after = tmp.stat().st_size
    except OSError:
        after = before
    # Only replace when we actually saved space — an already-efficient source can
    # re-encode LARGER, in which case keep the original untouched.
    if after >= before:
        _safe_unlink(tmp)
        return "skipped", "already efficient (no smaller result)", before, before
    # Replace in place. The lock + _free_file_for_compression already released
    # every known reader, but on Windows a handle can linger briefly after the
    # process is told to stop, so retry across that release latency before giving up.
    replace_err: Optional[OSError] = None
    for attempt in range(6):
        try:
            os.replace(str(tmp), str(src))
            replace_err = None
            break
        except OSError as e:
            replace_err = e
            await _free_file_for_compression(path)   # re-kick any reader that reappeared
            await asyncio.sleep(0.5 * (attempt + 1))
    if replace_err is not None:
        _safe_unlink(tmp)
        return "failed", f"Could not replace the original file: {replace_err}", before, before
    try:
        if old_bundle.exists():
            await asyncio.to_thread(shutil.rmtree, old_bundle, ignore_errors=True)
        _invalidate_offline_cache_inventory()
        _invalidate_bundle_index()
    except Exception:
        pass
    return "compressed", (f"{codec.upper()} CRF {crf}"), before, after


async def _run_file_compression(scope: str, crf: int, codec: str,
                                 max_height: Optional[int]) -> None:
    """Walk the library (or one item) and compress each video in turn, updating
    state.file_compression in place so the admin card can poll progress."""
    fc = state.file_compression
    ffmpeg = analyzer.ffmpeg_bin()
    try:
        lib = await get_library()
        targets: list[tuple[str, str, str, bool]] = []   # (item_title, path, name, torrent)
        for item in lib.get("items", []):
            if scope not in ("", "all") and item.get("id") != scope:
                continue
            torrent = bool(item.get("torrent_hash"))
            for f in item.get("files", []):
                p = f.get("path", "")
                if Path(p).suffix.lower() not in VIDEO_EXTS:
                    continue
                targets.append((item.get("title", ""), p, f.get("name") or Path(p).name, torrent))
                await asyncio.sleep(0)
        fc["total"] = len(targets)
        for (title, path, name, torrent) in targets:
            if state.file_compression_stop:
                fc["stopped"] = True
                break
            fc["current_name"] = name
            if not ffmpeg:
                fc["error"] = "ffmpeg is not installed — cannot compress files."
                break
            status, detail, before, after = await _compress_one_file(
                ffmpeg, path, crf=crf, codec=codec, max_height=max_height,
                set_proc=lambda p: setattr(state, "file_compression_proc", p),
                is_stopped=lambda: state.file_compression_stop,
            )
            if state.file_compression_stop and status != "compressed":
                fc["stopped"] = True
                break
            # Persist the per-file "compressed" marker so every qBit-dependent feature
            # treats this file as a local (no-longer-torrent-backed) file: progress is
            # read from disk, re-download is blocked, and recheck/recover/delete refuse
            # it. Only torrent-backed files need the marker — an uploaded file already
            # has no hash. Re-fetch under the lock so we don't clobber concurrent edits.
            if status == "compressed" and torrent:
                lib2 = await get_library()
                for it in lib2.get("items", []):
                    for ff in it.get("files", []):
                        if ff.get("path") == path:
                            ff["compressed"] = True
                            ff["compressed_at"] = _now_iso()
                await put_library(lib2)
            fc["results"].append({
                "path": path, "name": name, "item_title": title, "torrent": torrent,
                "status": status, "detail": detail, "before": before, "after": after,
                "saved": max(0, before - after) if status == "compressed" else 0,
            })
            fc["bytes_before"] = fc.get("bytes_before", 0) + before
            fc["bytes_after"]  = fc.get("bytes_after", 0) + (after if status == "compressed" else before)
            fc["scanned"] = fc.get("scanned", 0) + 1
    except asyncio.CancelledError:
        fc["stopped"] = True
        raise
    except Exception as e:
        fc["error"] = str(e)
    finally:
        fc["running"] = False
        fc["current_name"] = ""
        fc["finished_at"] = _now_iso()
        state.file_compression_proc = None


async def _compress_estimate(scope: str, level: str, codec: str) -> dict:
    """Estimate the disk space a compression run would reclaim across the target
    files — both the re-encoded SOURCE (a bitrate model — the real result depends
    on content) and the current HLS bundle (deleted on replace, re-built smaller on
    next prep). Runs probes in a worker thread; returns a JSON-safe summary."""
    _crf, max_height = _compression_params(level, codec, None)
    hevc_factor = 0.6 if codec == "hevc" else 1.0
    lib = await get_library()
    paths: list[str] = []
    for item in lib.get("items", []):
        if scope not in ("", "all") and item.get("id") != scope:
            continue
        for f in item.get("files", []):
            p = f.get("path", "")
            if Path(p).suffix.lower() in VIDEO_EXTS:
                paths.append(p)

    cur_src = est_src = cur_hls = 0
    counted = 0
    for p in paths:
        src = Path(p)
        try:
            size = src.stat().st_size
        except OSError:
            continue
        info = await asyncio.to_thread(_ffprobe_full, p)
        dur = float(info.get("duration_sec") or 0)
        src_h = int((info.get("video") or {}).get("height") or 0)
        cur_src += size
        counted += 1
        # current HLS bundle for this source (freed immediately on replace)
        try:
            cur_hls += await asyncio.to_thread(_dir_size_bytes, _offline_cache_dir(src))
        except Exception:
            pass
        if dur <= 0 or src_h <= 0:
            est_src += size          # can't model → assume unchanged
            continue
        out_h = min(src_h, max_height) if max_height else src_h
        kbps = _COMPRESS_EST_KBPS[_est_bucket(out_h)][level] * hevc_factor
        est_video = kbps * 1000 / 8 * dur
        est_new = est_video + 0.10 * size      # +copied audio/container overhead
        est_src += int(min(size, est_new))     # never claim a negative saving

    src_saved = max(0, cur_src - est_src)
    return {
        "files": counted,
        "current_source_bytes": cur_src,
        "est_source_bytes": est_src,
        "est_source_saved": src_saved,
        "current_hls_bytes": cur_hls,
        "est_total_saved": src_saved + cur_hls,
    }


async def _play_prep_chain(item_id: str, files: list[str]) -> None:
    """Sequentially HLS-prep each file in `files` for on-device, one at a time.

    Started by a VLC play (`_maybe_start_play_prep`). Each file finishes before the
    next starts, so the episode the viewer is most likely to reach next is always
    prepped first. Cancellable: a new play cancels this chain (the in-flight ffmpeg
    keeps running — only further enqueues stop)."""
    if not HLS_AVAILABLE or not analyzer.ffmpeg_bin():
        return
    # Honor the per-file "never" prep opt-out — even on the play-driven warm-prep of
    # the upcoming playlist (the file being watched still streams via the on-demand
    # path; "never" only suppresses building a cached bundle ahead of time).
    _lib = await get_library()
    _item = next((it for it in _lib.get("items", []) if it.get("id") == item_id), None)
    prep_cfg = _prep_cfg(_item) if _item else {"files": {}}
    for path in files:
        if _effective_prep_mode(prep_cfg, path) == "never":
            continue
        p = Path(path)
        try:
            if p.suffix.lower() not in VIDEO_EXTS or not p.exists():
                continue
        except OSError:
            continue
        out_dir = _offline_cache_dir(p)
        if (out_dir / "master.m3u8").exists():
            continue
        job_id = _start_interactive_prep_job(p, item_id)
        if not job_id:
            continue
        # Block until this episode is done (or errored) before queuing the next.
        while True:
            await asyncio.sleep(2)
            j = _offline_jobs.get(job_id)
            if not j or j.get("status") in ("done", "error"):
                break


async def _maybe_start_play_prep(
    lib: dict, item: dict, profile_id: str,
    playlist: list[str], seek_sec: Optional[float],
) -> None:
    """If auto-prep-on-play is enabled, prep the playing episode (then the rest of
    the playlist) for on-device. If the viewer is resuming within `PLAY_PREP_TAIL_SECS`
    of the current episode's end, skip it and start at the next (prepping it would
    finish after they've moved on). Cancels any prior chain so only the current
    series' tail is being prepped."""
    if not HLS_AVAILABLE or not _play_prep_cfg(lib)["enabled"]:
        return
    files = list(playlist)
    if not files:
        return
    if seek_sec and seek_sec > 0 and len(files) > 1:
        dur = _file_duration_sec(item, profile_id, files[0])
        if dur and (dur - seek_sec) < PLAY_PREP_TAIL_SECS:
            files = files[1:]
    prior = state.play_prep_task
    if prior and not prior.done():
        prior.cancel()
    state.play_prep_task = asyncio.create_task(_play_prep_chain(item["id"], files))


# ── STT subtitle generation (whisper.cpp) ────────────────────────────────────
# Generated subs are sidecar `<stem>.<lang>.ai.srt` files written next to the
# source. They flow into both players through existing plumbing: VLC via
# `addsubtitle`, the HLS on-device player via `_list_sidecar_subs`. STT jobs
# share the offline-prep concurrency semaphore + pause gate so a transcription
# never competes with (or starves alongside) an HLS encode. See docs/STT.md.

def _stt_available() -> bool:
    """stt.is_available() with a 60 s TTL cache. Probing every state broadcast
    (reads .env + shutil.which) is wasteful, but caching forever meant installing
    whisper.cpp after startup never took effect until a full server restart — so
    the Generate-subtitles affordances stayed hidden. The TTL lets a fresh setup
    light them up within a minute, no restart needed."""
    now = time.time()
    if now - _stt_available_probe.get("at", 0.0) > 60:
        _stt_available_probe["result"] = stt.is_available()
        _stt_available_probe["at"] = now
    return bool(_stt_available_probe.get("result", False))


async def _attach_stt_to_vlc(src: Path, tracks: list[dict]) -> None:
    """Load a freshly-generated sidecar into VLC and select it — but only if VLC
    is still playing the same file. Mirrors download_subtitle's load+select."""
    try:
        cur = await _current_playback_path()
        if not cur or cur.resolve() != src.resolve():
            return
    except Exception:
        return
    dest = Path(tracks[0]["path"])
    await vlc("addsubtitle", val=str(dest.resolve()))
    await asyncio.sleep(0.6)
    vs = await vlc_status()
    if not vs:
        return
    cat = vs.get("information", {}).get("category", {})
    sub_ids = [
        int(k.split()[-1]) for k, v in cat.items()
        if k.startswith("Stream") and k.split()[-1].isdigit()
        and v.get("Type") == "Subtitle"
    ]
    if sub_ids:
        new_id = max(sub_ids)
        state.current_subtitle_track = new_id
        await vlc("subtitle_track", val=str(new_id))


async def _run_stt_job(job_id: str) -> None:
    """Transcribe one source to sidecar .srt(s). Shares the offline-prep
    semaphore + bulk pause gate; runs whisper at lowered OS priority (stt.py)."""
    job = _stt_jobs.get(job_id)
    if not job:
        return
    async with _offline_job_sem():
        # Bulk STT honors the same global pause as bulk HLS prep; interactive
        # (play-now / "Generate now") jobs ignore it.
        if job.get("queue") == "bulk" and state.prep_paused:
            job["status"] = "paused"
            return
        job["status"] = "processing"
        job["started_at"] = time.time()
        src = Path(job["src"])
        hls_log.info("stt job %s START src=%s translate=%s", job_id, src, job.get("translate"))

        # Cancellation: an activity-pause sets this event and kills the registered
        # whisper/ffmpeg subprocess so STT stops *immediately* (whisper is the heaviest
        # background load; without this it churned the CPU/GPU long after prep "paused").
        cancel = threading.Event()
        job["_cancel"] = cancel
        job["_proc"] = None

        def _set_progress(p: float) -> None:
            job["progress"] = max(0.0, min(1.0, p))

        def _on_proc(p) -> None:
            job["_proc"] = p

        result = await asyncio.to_thread(
            stt.generate, src,
            want_translation=bool(job.get("translate", True)),
            progress_cb=_set_progress,
            on_proc=_on_proc, cancel_check=cancel.is_set,
        )
        job["_proc"] = None
        if result.get("cancelled") or cancel.is_set():
            # Intentionally killed by a pause — re-queue (don't mark error/done).
            # _resume_prep re-spawns "paused" STT jobs on the next idle stretch.
            job["status"] = "paused"
            hls_log.info("stt job %s PAUSED (cancelled) src=%s", job_id, src)
            return
        if result.get("error"):
            job["status"] = "error"
            job["error"]  = result["error"]
            hls_log.error("stt job %s FAILED: %s", job_id, result["error"])
            return
        job["tracks"]   = result.get("tracks", [])
        job["progress"] = 1.0
        job["status"]   = "done"
        hls_log.info("stt job %s DONE tracks=%d src=%s", job_id, len(job["tracks"]), src)

        if job.get("vlc_attach") and job["tracks"]:
            await _attach_stt_to_vlc(src, job["tracks"])


def _maybe_start_stt_job(src: Path, item_id: str = "", *,
                         translate: bool = True, queue: str = "bulk",
                         vlc_attach: bool = False) -> dict:
    """Per-file: return current STT state, starting a job if none exists.

    Returns {status:"cached"} when current-model sidecars already exist,
    {status:"error"} when STT is unavailable, else {status, job_id, progress}.
    Generated subs made with a DIFFERENT model are treated as stale, so an
    explicit request regenerates them (generate() replaces the old ones).
    """
    if not _stt_available():
        return {"status": "error", "error": "Subtitle generation is not available on this host."}
    if stt.has_ai_subs(src) and not stt.ai_subs_stale(src):
        return {"status": "cached"}
    existing = next(
        (j for j in _stt_jobs.values()
         if j["src"] == str(src) and j["status"] in ("pending", "processing", "paused")),
        None,
    )
    if existing:
        # Promote a queued bulk job to interactive when a user asks for it now.
        if vlc_attach or queue == "interactive":
            existing["queue"] = "interactive"
            existing["vlc_attach"] = existing.get("vlc_attach") or vlc_attach
            if existing.get("status") == "paused":
                existing["status"] = "pending"
                asyncio.create_task(_run_stt_job(existing["id"]))
        return {"status": existing["status"], "job_id": existing["id"],
                "progress": existing["progress"]}
    job_id = secrets.token_hex(8)
    _stt_jobs[job_id] = {
        "id": job_id, "src": str(src), "item_id": item_id,
        "status": "pending", "progress": 0.0, "error": None,
        "tracks": [], "translate": bool(translate),
        "queue": queue, "vlc_attach": vlc_attach,
        "started_at": time.time(),
    }
    asyncio.create_task(_run_stt_job(job_id))
    return {"status": "processing", "job_id": job_id, "progress": 0.0}


async def _ensure_stt_for(src: Path, item_id: str = "", *,
                          info: Optional[dict] = None, queue: str = "bulk") -> Optional[dict]:
    """Start a bulk STT job for `src` iff STT is enabled and the source lacks a
    usable text subtitle (honoring the admin default language). Idempotent: skips
    when sidecars already exist or a job is already in flight. `info` (ffprobe
    output) is reused when the caller already has it to avoid a re-probe."""
    if not _stt_available():
        return None
    cfg = _stt_cfg(await get_library())
    if not cfg["enabled"]:
        return None
    if stt.has_ai_subs(src):
        return None
    if info is None:
        info = await asyncio.to_thread(_ffprobe_full, str(src))
    if not _needs_stt_subs(info, cfg["default_language"]):
        return None
    return _maybe_start_stt_job(src, item_id, translate=cfg["translate"], queue=queue)


# ── Optional component installer (admin-driven setup) ────────────────────────
# Lets the admin install the portable dependencies — ffmpeg, fpcalc, the
# whisper.cpp binary, and a whisper model — from the web panel instead of a
# terminal. The auto-updater runs setup.py NON-interactively and skips every
# install_* step, so these never landed on the production box otherwise. We reuse
# setup.py's URL/extract/detect helpers (it imports cleanly — its prompts live
# under __main__) and stream the download here for live progress. Once a file is
# in tools/, setup.py's detect_tools()+merge_tool_paths() keep .env pointing at it
# across future auto-updates, so a one-time install here persists. See docs/SETUP.md.

_component_jobs: dict[str, dict] = {}   # component → {status, progress, error, ...}
_COMPONENT_KEYS = ("ffmpeg", "fpcalc", "whisper", "whisper_model", "flaresolverr")
_WHISPER_MODEL_SIZES = ("base", "small", "medium")


async def _download_to(url: str, dest: Path, job: dict) -> None:
    """Stream `url` to `dest` (atomic via a `.part` temp), updating job['progress'].
    Follows redirects (GitHub/HuggingFace assets resolve to signed CDN URLs)."""
    dest.parent.mkdir(parents=True, exist_ok=True)
    tmp = dest.with_name(dest.name + ".part")
    async with httpx.AsyncClient(follow_redirects=True,
                                 timeout=httpx.Timeout(60.0, read=600.0)) as c:
        async with c.stream("GET", url, headers={"User-Agent": "StreamLink"}) as r:
            r.raise_for_status()
            total = int(r.headers.get("content-length") or 0)
            got = 0
            with open(tmp, "wb") as f:
                async for chunk in r.aiter_bytes(131072):
                    f.write(chunk)
                    got += len(chunk)
                    job["progress"] = (min(0.99, got / total) if total > 0 else 0.5)
    tmp.replace(dest)


async def _run_component_install(component: str, model: str = "base", build: str = "cpu") -> None:
    """Download + install one portable component, then point .env at it and clear
    the relevant detection caches so the new binary takes effect without a restart.

    `build` (whisper only) selects the whisper.cpp variant: cpu / cuda12 / cuda11.
    """
    job = _component_jobs[component]
    job["status"] = "downloading"
    try:
        import setup  # stdlib-only, prompts gated under __main__ — safe to import
    except Exception as e:
        job["status"] = "error"; job["error"] = f"setup module import failed: {e}"
        return
    try:
        if component == "whisper_model":
            size = model if model in _WHISPER_MODEL_SIZES else "base"
            fname = f"ggml-{size}.bin"
            url = f"https://huggingface.co/ggerganov/whisper.cpp/resolve/main/{fname}"
            dest = setup.TOOLS_DIR / "whisper" / "models" / fname
            await _download_to(url, dest, job)
            _write_env_keys({"_WHISPER_MODEL": str(dest)})

        elif component == "whisper":
            if os.name != "nt":
                raise RuntimeError("Portable whisper.cpp is Windows-only here — build it on "
                                   "Linux, or `brew install whisper-cpp` on macOS.")
            url = await asyncio.to_thread(setup._resolve_whisper_win_url, build)
            wh_dir = setup.TOOLS_DIR / "whisper"
            tmp_zip = setup.TOOLS_DIR / "_dl_whisper.zip"
            await _download_to(url, tmp_zip, job)
            ok = await asyncio.to_thread(setup._extract_archive, tmp_zip, wh_dir)
            tmp_zip.unlink(missing_ok=True)
            if not ok:
                raise RuntimeError("Could not extract the whisper.cpp archive.")
            binp = (setup._find_in_tree(wh_dir, ["whisper-cli.exe"])
                    or setup._find_in_tree(wh_dir, ["main.exe"])
                    or setup._find_in_tree(wh_dir, ["whisper.exe"]))
            if not binp:
                raise RuntimeError("whisper-cli.exe not found inside the downloaded archive.")
            _write_env_keys({"_WHISPER_BIN": binp})

        elif component == "ffmpeg":
            if os.name != "nt":
                raise RuntimeError("Portable ffmpeg is Windows-only here — install it via your "
                                   "package manager (brew / apt / dnf).")
            ff_dir = setup.TOOLS_DIR / "ffmpeg"
            tmp_zip = setup.TOOLS_DIR / "_dl_ffmpeg.zip"
            await _download_to(setup.FFMPEG_WIN_URL, tmp_zip, job)
            ok = await asyncio.to_thread(setup._extract_archive, tmp_zip, ff_dir)
            tmp_zip.unlink(missing_ok=True)
            if not ok:
                raise RuntimeError("Could not extract the ffmpeg archive.")
            binp = setup._find_in_tree(ff_dir, ["ffmpeg.exe"])
            if not binp:
                raise RuntimeError("ffmpeg.exe not found inside the downloaded archive.")
            _write_env_keys({"_FFMPEG_BIN": binp})
            _ffmpeg_version_probe.clear(); _nvenc_probe.clear(); _cuda_scale_probe.clear()

        elif component == "fpcalc":
            sysname = platform.system()
            if sysname == "Windows":
                url, arcname, exe = setup.FPCALC_WIN_URL, "_dl_fpcalc.zip", "fpcalc.exe"
            elif sysname == "Linux":
                url, arcname, exe = setup.FPCALC_LINUX_URL, "_dl_fpcalc.tar.gz", "fpcalc"
            else:
                url, arcname, exe = setup.FPCALC_MAC_URL, "_dl_fpcalc.tar.gz", "fpcalc"
            fp_dir = setup.TOOLS_DIR / "chromaprint"
            tmp_arc = setup.TOOLS_DIR / arcname
            await _download_to(url, tmp_arc, job)
            ok = await asyncio.to_thread(setup._extract_archive, tmp_arc, fp_dir)
            tmp_arc.unlink(missing_ok=True)
            if not ok:
                raise RuntimeError("Could not extract the fpcalc archive.")
            binp = setup._find_in_tree(fp_dir, [exe])
            if not binp:
                raise RuntimeError(f"{exe} not found inside the downloaded archive.")
            if os.name == "posix":
                try:
                    os.chmod(binp, 0o755)
                except OSError:
                    pass
            _write_env_keys({"_FPCALC_BIN": binp})

        elif component == "flaresolverr":
            sysname = platform.system()
            if sysname not in ("Windows", "Linux"):
                raise RuntimeError("FlareSolverr has a prebuilt binary only for Windows/Linux "
                                   "here — on macOS run it via Docker.")
            url = await asyncio.to_thread(setup._resolve_flaresolverr_url, sysname)
            fs_dir = setup.TOOLS_DIR / "flaresolverr"
            suffix = ".zip" if sysname == "Windows" else ".tar.gz"
            tmp_arc = setup.TOOLS_DIR / f"_dl_flaresolverr{suffix}"
            await _download_to(url, tmp_arc, job)
            ok = await asyncio.to_thread(setup._extract_archive, tmp_arc, fs_dir)
            tmp_arc.unlink(missing_ok=True)
            if not ok:
                raise RuntimeError("Could not extract the FlareSolverr archive.")
            exe = "flaresolverr.exe" if sysname == "Windows" else "flaresolverr"
            binp = setup._find_in_tree(fs_dir, [exe])
            if not binp:
                raise RuntimeError(f"{exe} not found inside the downloaded archive.")
            if os.name == "posix":
                try:
                    os.chmod(binp, 0o755)
                except OSError:
                    pass
            _write_env_keys({"_FLARESOLVERR_BIN": binp})
            _spawn_flaresolverr()   # best-effort: start it now so it's usable immediately
        else:
            raise RuntimeError(f"Unknown component: {component}")

        _stt_available_probe.clear()   # re-probe STT availability on next state read
        job["progress"] = 1.0
        job["status"] = "done"
        hls_log.info("component install DONE: %s", component)
    except Exception as e:
        job["status"] = "error"
        job["error"] = str(e)
        hls_log.error("component install FAILED: %s — %s", component, e)


def _component_status_payload() -> dict:
    """Status of every installable portable dependency + any in-flight install job."""
    import setup
    win = (platform.system() == "Windows")
    ffmpeg  = analyzer.ffmpeg_bin()
    fpcalc  = analyzer.fpcalc_bin()
    whisper = stt.whisper_bin()
    model   = stt.whisper_model()
    comps = {
        "ffmpeg":        {"label": "ffmpeg",               "installed": bool(ffmpeg),
                          "path": ffmpeg or "",  "installable": win,
                          "purpose": "Stream-prep (HLS), Smart Skip, AI-subtitle audio extraction"},
        "fpcalc":        {"label": "fpcalc (chromaprint)", "installed": bool(fpcalc),
                          "path": fpcalc or "",  "installable": True,
                          "purpose": "Smart Skip intro/credits fingerprinting"},
        "whisper":       {"label": "whisper.cpp",          "installed": bool(whisper),
                          "path": whisper or "", "installable": win,
                          "purpose": "AI subtitle generation engine"},
        "whisper_model": {"label": "whisper model",        "installed": bool(model),
                          "path": model or "",   "installable": True,
                          "purpose": "AI subtitle language model (multilingual)"},
        "flaresolverr":  {"label": "FlareSolverr",          "installed": bool(_flaresolverr_bin_path()),
                          "path": _flaresolverr_bin_path(), "installable": win or platform.system() == "Linux",
                          "purpose": "Cloudflare/DDoS-Guard challenge solver for protected Jackett indexers"},
    }
    for k, c in comps.items():
        j = _component_jobs.get(k)
        if j:
            c["job"] = {"status": j["status"], "progress": round(j.get("progress", 0.0), 3),
                        "error": j.get("error")}
    return {
        "components":   comps,
        "platform":     platform.system(),
        "model_sizes":  list(_WHISPER_MODEL_SIZES),
        "stt_available": _stt_available(),
    }


def _read_meta(out_dir: Path) -> dict:
    try:
        return json.loads((out_dir / "meta.json").read_text())
    except (OSError, ValueError):
        return {}


def _dir_size_bytes(p: Path) -> int:
    """Sum the size of every file under `p` (one level deep is enough for HLS
    bundles, but we recurse anyway for safety). Missing/unreadable files
    contribute 0 — used by the admin cache view, where best-effort is fine.
    """
    total = 0
    try:
        for entry in p.rglob("*"):
            try:
                if entry.is_file():
                    total += entry.stat().st_size
            except OSError:
                pass
    except OSError:
        pass
    return total


def _saved_local_tracks(lib: dict, item: dict, profile_id: str, file_path: str) -> dict:
    """Return the local-player track picks saved for this profile + file.

    `subtitle_sel`/`audio_sel` are the per-file resolvable descriptors;
    `series_subtitle_sel`/`series_audio_sel` are the per-series fallbacks (applied
    when this file has no own pick). The client resolves whichever applies against
    its live track list. `subtitle_idx`/`audio_idx` are kept for the legacy
    bundle-index path only."""
    fp = (item.get("progress", {})
              .get(profile_id, {})
              .get("file_progress", {})
              .get(file_path, {}))
    out: dict = {}
    if "local_audio_idx" in fp:
        out["audio_idx"] = fp["local_audio_idx"]
    if "local_subtitle_idx" in fp:
        out["subtitle_idx"] = fp["local_subtitle_idx"]
    if isinstance(fp.get("subtitle_sel"), dict):
        out["subtitle_sel"] = fp["subtitle_sel"]
    if isinstance(fp.get("audio_sel"), dict):
        out["audio_sel"] = fp["audio_sel"]
    series_sel = _get_series_sub_sel(lib, profile_id, _series_of_item(item))
    if series_sel:
        out["series_subtitle_sel"] = series_sel
    series_asel = _get_series_audio_sel(lib, profile_id, _series_of_item(item))
    if series_asel:
        out["series_audio_sel"] = series_asel
    # Profile-level audio-language fallback (8.9.3) — carries a pick across
    # separate items when no per-file/per-series descriptor resolves. Same role
    # the admin subtitle language default plays for subs. The client applies it
    # after its descriptor chain, before the rendition `default`.
    audio_pref = _get_profile_audio_pref(lib, profile_id)
    if audio_pref:
        out["audio_language_pref"] = audio_pref
    return out


class OfflinePrepareReq(BaseModel):
    file_path: str
    profile_id: str = ""   # Optional: when set, response includes saved track picks.
    # True ⇒ this is a "Prep for later" request (per-row Prep button / bulk prep) and
    # the job honors the global pause. False (default) ⇒ interactive play-on-device, which
    # must run even while bulk prep is paused so a user can still watch on demand.
    bulk: bool = False


@app.post("/api/library/{item_id}/offline-prepare")
async def offline_prepare(item_id: str, req: OfflinePrepareReq) -> JSONResponse:
    """Decide what processing a file needs for HLS browser playback.

    Returns either {ready:true, master_url, audios, subtitles, ...} if the
    bundle is already on disk, or {ready:false, job_id, operation:"hls"} after
    spawning a background prep job. The master_url points at
    /api/library/offline-cache/<sha>/master.m3u8 — both hls.js (Chrome /
    Firefox / Edge) and Safari (native HLS) load it the same way.
    """
    if not HLS_AVAILABLE:
        raise HTTPException(503, HLS_UNAVAILABLE_MSG)
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")
    target = next((f for f in item.get("files", []) if f["path"] == req.file_path), None)
    if not target:
        raise HTTPException(404, "File not found in this item.")
    src = Path(target["path"])
    if not src.exists():
        raise HTTPException(404, "File not on disk.")
    _assert_not_compressing(str(src))

    sidecar_subs = await asyncio.to_thread(_list_sidecar_subs, src, item_id)
    saved_tracks = (_saved_local_tracks(lib, item, req.profile_id, req.file_path)
                    if req.profile_id else {})
    out_dir = _offline_cache_dir(src)
    key = out_dir.name
    out_dir.parent.mkdir(parents=True, exist_ok=True)

    if (out_dir / "master.m3u8").exists():
        _bundle_index_register(key, out_dir)
        meta = _read_meta(out_dir)
        return JSONResponse({
            "ready":             True,
            "needs_processing":  False,
            "master_url":        f"/api/library/offline-cache/{key}/master.m3u8",
            "duration_sec":      meta.get("duration_sec", 0),
            "videos":            meta.get("videos", []),
            "audios":            meta.get("audios", []),
            "subtitles":         meta.get("subtitles", []),
            "skipped_image_subs": meta.get("skipped_image_subs", []),
            # Embedded fonts for styled ASS subs (libass-wasm). Empty for
            # non-styled / old bundles → the player uses the VTT <track>.
            "fonts":             meta.get("fonts", []),
            "subs":              sidecar_subs,
            "saved_tracks":      saved_tracks,
        })

    # On-demand-only item: never build a permanent bundle. Return not-ready with no
    # job so the client falls straight through to the JIT on-demand pipeline (which
    # leaves nothing permanent on disk). VLC playback is unaffected (separate path).
    if item.get("ondemand_only"):
        return JSONResponse({
            "ready":             False,
            "needs_processing":  False,
            "ondemand_only":     True,
            "subs":              sidecar_subs,
            "saved_tracks":      saved_tracks,
        })

    # Coalesce: if a job for this exact source is already running, return its id.
    existing = next(
        (j for j in _offline_jobs.values()
         if j["src"] == str(src) and j["status"] in ("pending", "processing", "paused")),
        None,
    )
    if existing:
        # An interactive (play-now / fullscreen prep) request must jump the queue.
        # Promote it to interactive (bypasses the pause gate); re-spawn it if it was
        # parked; and preempt any *other* bulk encode hogging the single slot so this
        # file starts now instead of waiting behind auto-prep / manual prep.
        if not req.bulk:
            existing["queue"] = "interactive"
            if existing.get("status") == "paused":
                existing["status"] = "pending"
                existing["_proc"] = None
                existing.pop("_paused_kill", None)
                asyncio.create_task(_run_offline_job(existing["id"]))
            _preempt_running_bulk(except_job_id=existing["id"])
        return JSONResponse({
            "ready":             False,
            "needs_processing":  True,
            "job_id":            existing["id"],
            "operation":         existing["operation"],
            "subs":              sidecar_subs,
            "saved_tracks":      saved_tracks,
        })

    if not analyzer.ffmpeg_bin():
        raise HTTPException(503, "ffmpeg is not available — cannot prepare this file for streaming.")

    job_id = secrets.token_hex(8)
    _offline_jobs[job_id] = {
        "id": job_id, "src": str(src), "out": str(out_dir),
        "status": "pending", "operation": "hls",
        "progress": 0.0, "error": None,
        "started_at": time.time(),
        "item_id": item_id,
        # Interactive play-on-device bypasses the pause gate; "Prep for later" honors it.
        "queue": "bulk" if req.bulk else "interactive",
    }
    asyncio.create_task(_run_offline_job(job_id))
    if not req.bulk:
        # Interactive prep: boot any in-flight bulk encode so this file claims the
        # slot immediately. The booted job re-queues and resumes afterwards.
        _preempt_running_bulk(except_job_id=job_id)
    return JSONResponse({
        "ready":             False,
        "needs_processing":  True,
        "job_id":            job_id,
        "operation":         "hls",
        "subs":              sidecar_subs,
        "saved_tracks":      saved_tracks,
    })


@app.get("/api/library/{item_id}/subs")
async def list_file_subs(item_id: str, file_path: str = "") -> JSONResponse:
    """Re-list a file's sidecar subtitles (incl. late-downloaded ones).

    Cheap, no-prep endpoint the on-device player polls while watching: real subs
    often finish downloading after playback starts, so the client re-checks this
    to upgrade off an auto-applied AI sub. Mirrors the `subs` field of
    /offline-prepare via `_list_sidecar_subs`."""
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")
    target = next((f for f in item.get("files", []) if f["path"] == file_path), None)
    if not target:
        raise HTTPException(404, "File not found in this item.")
    src = Path(target["path"])
    subs = await asyncio.to_thread(_list_sidecar_subs, src, item_id) if src.exists() else []
    return JSONResponse({"subs": subs})


def _rebuild_ondemand_only_items(lib: dict) -> None:
    """Refresh state.ondemand_only_items from the library's item flags."""
    state.ondemand_only_items = {
        it.get("id", "") for it in lib.get("items", []) if it.get("ondemand_only")
    }


async def _maybe_start_prep_job(src: Path, item_id: str = "",
                                force_reencode_video: bool = False,
                                prep_prio: int = 1) -> dict:
    """Per-file: return current prep state, starting an HLS job if none exists.

    `force_reencode_video` re-encodes the original video rung instead of
    stream-copying it (used by the audio-sync repair so the re-prep can't carry
    the same constant offset forward — see _run_offline_job's A/V sync guard).

    `prep_prio` (0=low, 1=mid, 2=high) orders this bulk job against other queued
    bulk prep — a higher tier reaches the single encode slot first (see the gate
    in _run_offline_job). Interactive / admin prep outrank all bulk work regardless.

    Returns one of:
      {status:"cached"}                              — bundle already on disk
      {status:"ondemand_only"}                       — item is on-demand-only; no bundle built
      {status:"processing", job_id, progress, operation}
      {status:"error", error}                        — ffmpeg unavailable / macOS
    """
    if not HLS_AVAILABLE:
        return {"status": "error", "error": HLS_UNAVAILABLE_MSG}
    # On-demand-only items never get a permanent bundle — playback uses the JIT
    # pipeline instead. This is the single chokepoint every prep path funnels
    # through (auto-prep, play-prep, the JIT background prep, prep-all).
    if item_id and item_id in state.ondemand_only_items:
        return {"status": "ondemand_only"}
    out_dir = _offline_cache_dir(src)
    if (out_dir / "master.m3u8").exists():
        _bundle_index_register(out_dir.name, out_dir)
        return {"status": "cached"}
    existing = next(
        (j for j in _offline_jobs.values()
         if j["src"] == str(src) and j["status"] in ("pending", "processing", "paused")),
        None,
    )
    if existing:
        return {"status": existing["status"], "job_id": existing["id"],
                "progress": existing["progress"], "operation": existing["operation"]}
    if not analyzer.ffmpeg_bin():
        return {"status": "error", "error": "ffmpeg not available."}
    job_id = secrets.token_hex(8)
    _offline_jobs[job_id] = {
        "id": job_id, "src": str(src), "out": str(out_dir),
        "status": "pending", "operation": "hls",
        "progress": 0.0, "error": None,
        "started_at": time.time(),
        "item_id": item_id,
        # Bulk / per-item / auto-prep — honors the global pause gate.
        "queue": "bulk",
        # Prep-queue priority tier (0=low, 1=mid, 2=high) — orders this against
        # other queued bulk prep at the encode-slot gate.
        "_prep_prio": int(prep_prio),
        # Repair flag: re-encode the original rung to fix a baked-in A/V offset.
        "_force_reencode_video": bool(force_reencode_video),
    }
    asyncio.create_task(_run_offline_job(job_id))
    return {"status": "processing", "job_id": job_id, "progress": 0.0, "operation": "hls"}


def _peek_prep_state(src: Path) -> dict:
    """Read-only sibling of _maybe_start_prep_job — never starts new work.

    Used by /prep-status polling. Includes finished+errored jobs so the UI can
    show a final result for a few seconds before the bundle is consulted.
    """
    out_dir = _offline_cache_dir(src)
    if (out_dir / "master.m3u8").exists():
        return {"status": "cached"}
    # Pick the most recent matching job — done/error states still surface here
    # so the UI can show "error" until the user retries.
    matching = [j for j in _offline_jobs.values() if j["src"] == str(src)]
    if matching:
        j = max(matching, key=lambda x: x.get("started_at", 0))
        out: dict = {
            "status": j["status"], "job_id": j["id"],
            "progress": j["progress"], "operation": j["operation"],
            "error": j["error"],
            "started_at": j.get("started_at", 0),
        }
        # Per-file ETA: scale elapsed by (1-progress)/progress. Skip until we
        # have at least 2s of elapsed AND >2% progress, otherwise the estimate
        # is dominated by ffmpeg startup overhead and bounces wildly.
        if j["status"] in ("pending", "processing"):
            elapsed = max(0.0, time.time() - j.get("started_at", time.time()))
            p = float(j.get("progress", 0))
            if elapsed > 2.0 and p > 0.02:
                out["eta_secs"] = max(0.0, elapsed * (1 - p) / p)
                out["elapsed_secs"] = elapsed
        return out
    return {"status": "needs_prep"}


@app.post("/api/library/{item_id}/prep-all")
async def prep_all(item_id: str) -> JSONResponse:
    """Kick off (or coalesce with existing) remux/transcode jobs for every video file in an item.

    Returns the current state of every file. The UI then polls /prep-status to track progress.
    """
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")
    prep_cfg = _prep_cfg(item)
    out = []
    for f in item.get("files", []):
        p = Path(f.get("path", ""))
        if not p.exists():
            out.append({"file_path": f.get("path", ""), "name": f.get("name", ""), "status": "missing"})
            continue
        prio = _PREP_PRIO_NUM.get(_effective_prep_priority(prep_cfg, f.get("path", "")), 1)
        st = await _maybe_start_prep_job(p, item_id, prep_prio=prio)
        out.append({"file_path": f["path"], "name": f.get("name", ""), **st})
        # _maybe_start_prep_job is sync (FS stat + task spawn, no internal await),
        # so yield between files — a 77-file pack otherwise hogs the event loop in
        # one burst and briefly stalls every other request.
        await asyncio.sleep(0)
    return JSONResponse({"files": out, **_prep_summary(out)})


@app.get("/api/library/{item_id}/prep-status")
async def prep_status(item_id: str) -> JSONResponse:
    """Aggregated read-only prep state for one library item — what /prep-all kicked off."""
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")
    out = []
    for f in item.get("files", []):
        p = Path(f.get("path", ""))
        if not p.exists():
            out.append({"file_path": f.get("path", ""), "name": f.get("name", ""), "status": "missing"})
            continue
        st = await asyncio.to_thread(_peek_prep_state, p)
        out.append({"file_path": f["path"], "name": f.get("name", ""), **st})
    return JSONResponse({"files": out, **_prep_summary(out)})


def _prep_summary(files: list[dict]) -> dict:
    """Roll up per-file states into the chip the UI shows on the library card.

    `eta_secs` is for the whole item: ETA of the in-flight file plus an
    extrapolated estimate for each file still queued (uses the in-flight file's
    observed throughput as the per-file estimate). When no file is in flight
    yet, returns None — the UI falls back to "starting…".
    """
    ready_states = ("cached", "done")
    busy_states  = ("pending", "processing")
    ready      = sum(1 for x in files if x["status"] in ready_states)
    processing = sum(1 for x in files if x["status"] in busy_states)
    paused     = sum(1 for x in files if x["status"] == "paused")
    errored    = sum(1 for x in files if x["status"] == "error")
    needs_prep = sum(1 for x in files if x["status"] == "needs_prep")
    missing    = sum(1 for x in files if x["status"] == "missing")

    # Aggregate ETA: sum of the in-flight files' remaining time + (queued *
    # estimated full-file time, derived from the busiest in-flight file).
    eta_secs: Optional[float] = None
    in_flight = [x for x in files if x["status"] in busy_states and x.get("eta_secs") is not None]
    if in_flight:
        in_flight_eta = sum(float(x["eta_secs"]) for x in in_flight)
        # Per-file estimate from the most-progressed in-flight file
        # (elapsed / progress = full-file estimate).
        per_file_estimate = max(
            (float(x["elapsed_secs"]) / max(float(x["progress"]), 0.01)
             for x in in_flight if x.get("elapsed_secs") and x.get("progress")),
            default=0.0,
        )
        # Files that have a job entry but aren't started yet contribute a full estimate each.
        not_started = sum(
            1 for x in files
            if x["status"] in busy_states and x.get("eta_secs") is None
        )
        # Files that have not been touched at all (needs_prep) also contribute.
        queued_full = not_started + needs_prep
        eta_secs = in_flight_eta + queued_full * per_file_estimate

    return {
        "total":       len(files),
        "ready":       ready,
        "processing":  processing,
        "paused":      paused,
        "errored":     errored,
        "needs_prep":  needs_prep,
        "missing":     missing,
        "eta_secs":    eta_secs,
    }


@app.get("/api/offline-active")
async def offline_active(request: Request, profile_id: str = "") -> JSONResponse:
    """Global view of every offline-prep job currently running.

    The library card chip is only rendered when the card is on-screen, so prep
    progress disappears the moment the user navigates away or reloads the page.
    This endpoint surfaces ALL active jobs (across all items) so a persistent
    indicator can stay visible regardless of which tab the user is on.

    Active = status in (pending, processing, paused) — paused jobs are included
    so the global bar keeps showing (with a Resume affordance) while the queue is
    held. Done/error jobs are NOT returned; those are still visible via the
    per-item /prep-status when the card mounts.

    Prep jobs for **admin-locked** items are **fully excluded** for any requester
    who can't see the item (not admin and not an elevated profile) — not redacted.
    A viewer who can't see the content must see NO evidence it's being prepped: no
    job, no count, no "something is running" bar. If admin-locked jobs are the only
    thing active, such a viewer gets `active:false`, exactly as if the box were
    idle. Privileged requesters (admin / elevated) still see everything, including
    real item titles. See docs/ADMIN.md § Content Lock.
    """
    active = [j for j in _offline_jobs.values()
              if j.get("status") in ("pending", "processing", "paused")]
    if not active:
        return JSONResponse({"active": False, "paused": state.prep_paused,
                             "total_jobs": 0, "items": []})
    lib = await get_library()
    is_admin = _check_admin(request)
    elevated_ids = {p["id"] for p in lib.get("profiles", []) if p.get("elevated")}
    is_elevated = bool(profile_id) and profile_id in elevated_ids
    items_by_id = {it["id"]: it for it in lib.get("items", [])}
    # Drop every job the requester isn't allowed to know about. A job with no
    # resolvable item (untagged / deleted) can't be admin-locked, so it stays.
    if not is_admin and not is_elevated:
        active = [j for j in active
                  if not (items_by_id.get(j.get("item_id", "")) or {}).get("admin_only")]
    if not active:
        # Everything active was admin-locked and hidden from this viewer — report
        # idle so no trace of the hidden prep leaks.
        return JSONResponse({"active": False, "paused": state.prep_paused,
                             "total_jobs": 0, "items": []})
    # Group by item_id, falling back to "" for jobs created before item_id
    # tagging existed (shouldn't happen after the upgrade, but be defensive).
    by_item: dict[str, list[dict]] = {}
    for j in active:
        by_item.setdefault(j.get("item_id", ""), []).append(j)
    items_out: list[dict] = []
    now = time.time()
    for item_id, jobs in by_item.items():
        total_progress = 0.0
        eta_total = 0.0
        eta_count = 0
        for j in jobs:
            p = float(j.get("progress", 0))
            total_progress += p
            elapsed = max(0.0, now - j.get("started_at", now))
            if elapsed > 2.0 and p > 0.02:
                eta_total += elapsed * (1 - p) / p
                eta_count += 1
        it = items_by_id.get(item_id)
        items_out.append({
            "item_id":    item_id,
            "title":      it.get("title", "") if it else "",
            "processing": len(jobs),
            "progress":   round(total_progress / len(jobs), 3) if jobs else 0,
            "eta_secs":   round(eta_total, 1) if eta_count > 0 else None,
            "operation":  jobs[0].get("operation", "transcode"),
        })
    return JSONResponse({
        "active": True,
        "paused": state.prep_paused,
        "total_jobs": len(active),
        "processing_jobs": sum(1 for j in active if j.get("status") == "processing"),
        "pending_jobs":    sum(1 for j in active if j.get("status") == "pending"),
        "paused_jobs":     sum(1 for j in active if j.get("status") == "paused"),
        "items": items_out,
    })


@app.post("/api/offline-prep/pause")
async def offline_prep_pause(req: PrepPauseReq) -> JSONResponse:
    """Pause bulk stream-prep from the (non-admin) UI. `kill` decides whether the
    in-flight encode is terminated now or allowed to finish. See _pause_prep."""
    killed = _pause_prep(req.kill)
    await broadcast("state", state_snapshot())
    return JSONResponse({"ok": True, "paused": True, "killed": killed})


@app.post("/api/offline-prep/resume")
async def offline_prep_resume() -> JSONResponse:
    """Resume bulk stream-prep from the (non-admin) UI — re-spawns paused jobs."""
    n = _resume_prep()
    await broadcast("state", state_snapshot())
    return JSONResponse({"ok": True, "paused": False, "resumed": n})


@app.get("/api/library/offline-job/{job_id}")
async def offline_job_status(job_id: str) -> JSONResponse:
    job = _offline_jobs.get(job_id)
    if not job:
        raise HTTPException(404, "Job not found.")
    out: dict = {
        "status":    job["status"],
        "operation": job["operation"],
        "progress":  round(job["progress"], 3),
        "error":     job["error"],
    }
    if job["status"] == "done":
        out_dir = Path(job["out"])
        key = out_dir.name
        meta = _read_meta(out_dir)
        out["master_url"]        = f"/api/library/offline-cache/{key}/master.m3u8"
        out["duration_sec"]      = meta.get("duration_sec", 0)
        out["videos"]            = meta.get("videos", [])
        out["audios"]            = meta.get("audios", [])
        out["subtitles"]         = meta.get("subtitles", [])
        out["skipped_image_subs"] = meta.get("skipped_image_subs", [])
        out["bundle_size_bytes"] = await asyncio.to_thread(_dir_size_bytes, out_dir)
        # Include on-disk sidecars (incl. any generated `.ai.srt`) so the local
        # player can attach them as <track>s without a separate prep round-trip.
        src = Path(job.get("src", ""))
        out["subs"] = await asyncio.to_thread(_list_sidecar_subs, src, job.get("item_id", ""))
    return JSONResponse(out)


class GenerateSubsReq(BaseModel):
    file_path: str
    translate: bool = True


@app.post("/api/library/{item_id}/generate-subtitles")
async def generate_subtitles(item_id: str, req: GenerateSubsReq) -> JSONResponse:
    """On-demand STT for a library file (on-device context). Writes sidecar
    `.srt`(s) next to the source; poll /api/stt-job/{job_id} until done, then the
    sidecars appear in the file's `subs` list. Runs even while bulk prep is
    paused (interactive)."""
    if not _stt_available():
        raise HTTPException(503, "Subtitle generation isn’t available — whisper.cpp "
                                 "or its model isn’t installed. Re-run setup.py.")
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")
    target = next((f for f in item.get("files", []) if f["path"] == req.file_path), None)
    if not target:
        raise HTTPException(404, "File not found in this item.")
    src = Path(target["path"])
    if not src.exists():
        raise HTTPException(404, "File not on disk.")
    st = _maybe_start_stt_job(src, item_id, translate=req.translate, queue="interactive")
    return JSONResponse(st)


class VlcGenerateSubsReq(BaseModel):
    translate: bool = True


@app.post("/api/subtitles/generate")
async def generate_subtitles_vlc(req: VlcGenerateSubsReq) -> JSONResponse:
    """On-demand STT for the file VLC is currently playing. On completion the
    sidecar is loaded into VLC and selected (like the OpenSubtitles download
    flow). Poll /api/stt-job/{job_id} for progress."""
    if not _stt_available():
        raise HTTPException(503, "Subtitle generation isn’t available — whisper.cpp "
                                 "or its model isn’t installed. Re-run setup.py.")
    video = await _current_playback_path()
    if not video:
        raise HTTPException(409, "No file is currently playing.")
    st = _maybe_start_stt_job(video, state.library_item_id or "",
                              translate=req.translate, queue="interactive",
                              vlc_attach=True)
    return JSONResponse(st)


@app.get("/api/stt-job/{job_id}")
async def stt_job_status(job_id: str) -> JSONResponse:
    """Status of an STT subtitle-generation job. On `done`, `subs` carries the
    file's sidecar list (incl. the generated tracks) for the on-device player."""
    job = _stt_jobs.get(job_id)
    if not job:
        raise HTTPException(404, "Job not found.")
    out: dict = {
        "status":   job["status"],
        "progress": round(job["progress"], 3),
        "error":    job["error"],
        "tracks":   job.get("tracks", []),
    }
    if job["status"] == "done":
        out["subs"] = await asyncio.to_thread(
            _list_sidecar_subs, Path(job["src"]), job.get("item_id", ""))
    return JSONResponse(out)


# Cache keys are sha256[:24] hex (24 chars). Bundle filenames are
# manifest / segment / meta files — alnum, dot, underscore, dash only.
_CACHE_KEY_RE = re.compile(r"^[a-f0-9]{24}$")
_BUNDLE_FILE_RE = re.compile(r"^[A-Za-z0-9._-]+$")

_HLS_MIME = {
    ".m3u8": "application/vnd.apple.mpegurl",
    ".m4s":  "video/iso.segment",
    ".mp4":  "video/mp4",
    ".vtt":  "text/vtt",
    ".json": "application/json",
    # Styled-subtitle assets (libass-wasm): raw ASS + embedded fonts. Fetched by
    # SubtitlesOctopus in the browser; MIME is advisory for these (it fetches as
    # text / ArrayBuffer) but set them correctly anyway.
    ".ass":   "text/plain; charset=utf-8",
    ".ssa":   "text/plain; charset=utf-8",
    ".ttf":   "font/ttf",
    ".otf":   "font/otf",
    ".ttc":   "font/collection",
    ".woff":  "font/woff",
    ".woff2": "font/woff2",
}


@app.get("/api/library/offline-cache/{cache_key}/{filename}")
async def offline_cache_bundle_file(cache_key: str, filename: str) -> FileResponse:
    """Serve one file from an HLS bundle directory.

    Bundles live beside the media (`<file_dir>/.streamlink_cache/<key>/`), so the
    dir is resolved from the key via `_bundle_index` (rebuilt on a cold miss).

    Strict regex validation on both segments prevents path traversal: even
    though FastAPI doesn't pass slashes through `{filename}` by default, ".."
    or absolute filenames would still resolve outside the cache root via
    Path arithmetic without the guard.
    """
    if not _CACHE_KEY_RE.match(cache_key) or not _BUNDLE_FILE_RE.match(filename):
        raise HTTPException(400, "Invalid path.")
    bundle_dir = await _resolve_bundle_dir(cache_key)
    if bundle_dir is None:
        raise HTTPException(404, "Cached file not found.")
    p = bundle_dir / filename
    if not p.exists() or not p.is_file():
        raise HTTPException(404, "Cached file not found.")
    media = _HLS_MIME.get(p.suffix.lower(), "application/octet-stream")
    if p.suffix.lower() == ".vtt":
        # Heal bundles built before the WebVTT sanitiser: ffmpeg's ASS→WebVTT
        # conversion left duplicate cues / `\p` drawing blobs / `\h` escapes in
        # the sidecar, which the player rendered as doubled, garbled subtitles.
        # `_clean_webvtt` is idempotent, so a freshly-prepped (already-clean)
        # bundle just round-trips. Rewrite in place (best-effort, atomic) so the
        # heal also reaches the iOS download path, which fetches via this route.
        raw = await asyncio.to_thread(p.read_text, encoding="utf-8", errors="replace")
        cleaned = _clean_webvtt(raw)
        if cleaned != raw:
            try:
                tmp = p.with_suffix(p.suffix + ".tmp")
                await asyncio.to_thread(tmp.write_text, cleaned, encoding="utf-8")
                await asyncio.to_thread(os.replace, str(tmp), str(p))
            except OSError:
                pass
        return Response(content=cleaned, media_type=media)
    return FileResponse(str(p), media_type=media, filename=p.name)


def _enumerate_bundle_files(out_dir: Path) -> tuple[list[dict], int]:
    """Flat list of the downloadable files in a built HLS bundle + total bytes.

    Every file the iOS BundleDownloader must fetch to serve the bundle offline
    lives directly in `out_dir` (master.m3u8, variant playlists, init_*.mp4,
    seg_*.m4s, embedded sub_*.vtt renditions, meta.json) — a self-contained HLS
    bundle, so a flat one-level listing is exhaustive. Names are validated with
    `_BUNDLE_FILE_RE` (the same guard the per-file server uses) so the client can
    fetch each via /api/library/offline-cache/<key>/<name> without traversal risk.
    """
    files: list[dict] = []
    total = 0
    for entry in sorted(out_dir.iterdir()):
        if not entry.is_file():
            continue
        if not _BUNDLE_FILE_RE.match(entry.name):
            continue
        try:
            size = entry.stat().st_size
        except OSError:
            continue
        files.append({"name": entry.name, "size": size})
        total += size
    return files, total


def _bundle_rung_name(name: str, video_name: str) -> bool:
    """True when bundle file `name` belongs to the video rung `video_name`
    (its playlist, fmp4 init, or a segment).

    The segment test is anchored to the numeric counter (`seg_<name>_<NNNNN>.m4s`),
    NOT a plain `startswith` prefix: the source rung is named `video` and the
    down-rungs `video_720` / `video_480`, so `"seg_video_720_00001.m4s"
    .startswith("seg_video_")` is True — the `video` rung would wrongly claim the
    720p rung's segments. That mis-attribution made a **reduced-quality download
    drop the very segments it kept** (the source rung in `drop_names` swallowed the
    kept down-rung's `seg_video_720_*`), so the bundle's playlist referenced
    segments that were never downloaded → 404 on the first fragment → unplayable."""
    if name in (f"{video_name}.m3u8", f"init_{video_name}.mp4"):
        return True
    return re.fullmatch(rf"seg_{re.escape(video_name)}_\d+\.m4s", name) is not None


def _bundle_rung_info(files: list[dict], meta: dict) -> list[dict]:
    """The bundle's video ladder annotated with the **download** byte size of
    each rung — what the device transfers if that quality is chosen: the rung's
    own video files plus the shared audio/subtitle/playlist/meta files (which
    every rung carries). Powers the app's per-download quality chooser so it can
    show "1080p (Source) — 1.4 GB / 720p — 600 MB / …".
    """
    videos = meta.get("videos") or []
    names = {v.get("name") for v in videos if v.get("name")}

    def _rung_of(fname: str) -> Optional[str]:
        for n in names:
            if _bundle_rung_name(fname, n):
                return n
        return None

    per: dict[str, int] = {}
    shared = 0
    for f in files:
        rn = _rung_of(f["name"])
        if rn is None:
            shared += f["size"]
        else:
            per[rn] = per.get(rn, 0) + f["size"]
    return [{**v, "bytes": shared + per.get(v.get("name"), 0)} for v in videos]


def _bundle_select_rung(out_dir: Path, files: list[dict], meta: dict,
                        keep_name: Optional[str] = None
                        ) -> tuple[list[dict], int, Optional[str]]:
    """Filter an enumerated bundle down to a SINGLE video rung for the iOS offline
    downloader — the device plays a downloaded file at one quality, so shipping the
    other ABR rungs just wastes storage. `keep_name` is the rung to keep (its
    `videos[].name`); None keeps the HIGHEST (source, idx 0) rung — the default.

    Drops every other rung's playlist + init + segments from `files`, and rewrites
    master.m3u8 *in memory* to reference only the kept rung — the same master
    rewrite `_trim_one_bundle` does on disk, but non-destructive (the shared
    on-disk bundle still serves all rungs for streaming clients). The trimmed
    master is returned inline so the app writes it verbatim instead of fetching the
    full one; the master entry in `files` keeps its (new, smaller) byte size so the
    downloader's resume check treats the written file as complete.

    Returns (filtered_files, total_bytes, trimmed_master_text). master_text is None
    when there's nothing to drop (≤1 rung, or the requested rung doesn't exist) —
    caller leaves the bundle untouched.
    """
    videos = meta.get("videos") or []
    if keep_name is None:
        keep_name = next((v.get("name") for v in videos
                          if v.get("idx", 0) == 0 and v.get("name")), None)
    drop_names = {v.get("name") for v in videos
                  if v.get("name") and v.get("name") != keep_name}
    if not drop_names:
        return files, sum(f["size"] for f in files), None

    # Rewrite master.m3u8: drop each #EXT-X-STREAM-INF whose following URI names a
    # dropped rung (audio #EXT-X-MEDIA lines are left untouched). Mirrors the
    # rewrite in _trim_one_bundle so the kept rung's playlist URI stays intact.
    drop_uris = {f"{n}.m3u8" for n in drop_names}
    try:
        lines = (out_dir / "master.m3u8").read_text("utf-8").splitlines()
    except OSError:
        return files, sum(f["size"] for f in files), None
    kept_lines: list[str] = []
    i = 0
    while i < len(lines):
        line = lines[i]
        if line.startswith("#EXT-X-STREAM-INF"):
            uri = lines[i + 1].strip() if i + 1 < len(lines) else ""
            if uri in drop_uris:
                i += 2
                continue
            kept_lines.append(line)
            if i + 1 < len(lines):
                kept_lines.append(lines[i + 1])
            i += 2
            continue
        kept_lines.append(line)
        i += 1
    master_text = "\n".join(kept_lines) + "\n"
    master_bytes = len(master_text.encode("utf-8"))

    # Reuse the rung membership test so the segment match is anchored to the numeric
    # counter — a plain `startswith("seg_video_")` would let the dropped source rung
    # swallow the kept down-rung's `seg_video_720_*` segments (see _bundle_rung_name).
    def _is_dropped(name: str) -> bool:
        return any(_bundle_rung_name(name, n) for n in drop_names)

    out: list[dict] = []
    for f in files:
        nm = f["name"]
        if _is_dropped(nm):
            continue
        out.append({"name": nm, "size": master_bytes} if nm == "master.m3u8" else f)
    return out, sum(f["size"] for f in out), master_text


# Memoized poster data URLs, keyed "<size><path>". A bulk download fetches the
# bundle-manifest for every episode of a series, and each one inlines the SAME
# series poster — without this cache that was one TMDb round-trip (up to a 12 s
# timeout) per episode, the dominant cost that left later episodes sitting at
# "Queued…" for 20-30 s. Posters are immutable for a given path, so the cache
# never needs invalidation; only successful fetches are stored (a transient
# failure can retry). The lock both serializes the network fetch and dedups
# concurrent identical requests (the first caches, the rest hit it).
_TMDB_IMG_DATA_URL_CACHE: dict[str, str] = {}
_TMDB_IMG_DATA_URL_LOCK = asyncio.Lock()


async def _tmdb_image_data_url(path: str, size: str = "w342") -> str:
    """Fetch a TMDb image and return it as a `data:` URL so the iOS offline
    Downloads picker can show a poster with no network (the bundle carries it).
    Best-effort: returns "" on any failure or when no path/key. Cached by
    path+size so a bulk per-episode manifest fetch downloads it once. Only called
    at download time (manifest fetch), not persisted to library.json."""
    if not path:
        return ""
    ck = f"{size}{path}"
    cached = _TMDB_IMG_DATA_URL_CACHE.get(ck)
    if cached is not None:
        return cached
    async with _TMDB_IMG_DATA_URL_LOCK:
        # Re-check under the lock: a concurrent caller may have just filled it.
        cached = _TMDB_IMG_DATA_URL_CACHE.get(ck)
        if cached is not None:
            return cached
        try:
            # Reads through the shared on-disk artwork cache (_tmdb_img_bytes),
            # so a poster already cached for the dashboard needs no internet.
            fn = path.lstrip("/")
            if _TMDB_IMG_FILE_RE.match(fn):
                got = await _tmdb_img_bytes(size, fn)
                if got:
                    body, ct = got
                    data_url = f"data:{ct};base64,{base64.b64encode(body).decode('ascii')}"
                    _TMDB_IMG_DATA_URL_CACHE[ck] = data_url
                    return data_url
        except Exception:
            pass
        return ""


async def _bundle_meta_for_file(item: dict, file_entry: dict, tmdb: Optional[dict],
                                include_poster: bool = True) -> dict:
    """Build the per-file series/episode metadata block carried by the bundle so
    the offline iOS Downloads picker can group and label downloads (and show a
    poster) without the host. Episode name/overview are resolved from the cached
    TMDb metadata; the poster is inlined as a data URL (see _tmdb_image_data_url)."""
    series = (item.get("series") or item.get("title") or "").strip()
    season = int(file_entry.get("season") or 0)
    episode = int(file_entry.get("episode") or 0)
    tmdb = tmdb or {}
    ep_name = ""
    ep_overview = ""
    still_path = ""
    if season and episode:
        s = (tmdb.get("seasons") or {}).get(str(season)) or {}
        for ep in s.get("episodes", []) or []:
            if int(ep.get("episode") or 0) == episode:
                ep_name = ep.get("name") or ""
                ep_overview = ep.get("overview") or ""
                still_path = ep.get("still_path") or ""
                break
    poster_path = tmdb.get("poster_path") or ""
    return {
        "series":        series,
        "title":         tmdb.get("title") or series,
        "season":        season,
        "episode":       episode,
        "episode_name":  ep_name,
        "overview":      ep_overview or tmdb.get("overview") or "",
        "tmdb_kind":     tmdb.get("tmdb_kind") or ("tv" if season else ""),
        "poster_path":   poster_path,
        "img_base":      TMDB_IMG_BASE,
        "poster_data_url": (await _tmdb_image_data_url(poster_path) if (include_poster and poster_path) else ""),
    }


@app.get("/api/library/{item_id}/bundle-manifest")
async def bundle_manifest(item_id: str, request: Request, file_path: str = "", profile_id: str = "", quality: str = "") -> JSONResponse:
    """Enumerate a built HLS bundle for the iOS offline downloader (plan A1).

    Returns a flat `files` list (relative names + byte sizes) plus `total_bytes`
    and the playback metadata (`duration_sec`, `audios`, `subtitles`, sidecar
    `subs`) so the BundleDownloader can enqueue every file deterministically and
    report real progress instead of crawling playlists. Each file is fetched via
    the existing, traversal-guarded /api/library/offline-cache/<key>/<name>.

    Only *fully-prepped* bundles are downloadable. If the bundle isn't built yet
    the endpoint returns **409 not_ready** (with `ondemand_only` when the item
    never builds one); the app then triggers a normal POST /offline-prepare and
    polls /offline-job/{id} before retrying. JIT on-demand stays online-only.
    """
    _require_device_auth(request)
    if not HLS_AVAILABLE:
        raise HTTPException(503, HLS_UNAVAILABLE_MSG)
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")
    target = next((f for f in item.get("files", []) if f["path"] == file_path), None)
    if not target:
        raise HTTPException(404, "File not found in this item.")
    src = Path(target["path"])
    if not src.exists():
        raise HTTPException(404, "File not on disk.")

    out_dir = _offline_cache_dir(src)
    key = out_dir.name
    if not (out_dir / "master.m3u8").exists():
        return JSONResponse(
            {
                "ready": False,
                "reason": "not_ready",
                "ondemand_only": bool(item.get("ondemand_only")),
            },
            status_code=409,
        )
    # Register so the app's subsequent segment fetches resolve by key without a rescan.
    _bundle_index_register(key, out_dir)

    meta = _read_meta(out_dir)
    files, total = await asyncio.to_thread(_enumerate_bundle_files, out_dir)
    # The full ABR ladder annotated with per-rung download sizes, so the app's
    # download-quality chooser can list only the qualities that actually exist.
    videos_full = _bundle_rung_info(files, meta)
    # Download a single video rung — drop the others the device never picks for a
    # downloaded file. Defaults to the highest (source) rung; the app may request a
    # specific one via ?quality=<height> (or "original"). Falls back to highest when
    # the requested height isn't in this bundle.
    keep_name: Optional[str] = None
    q = (quality or "").strip().lower()
    if q and q not in ("original", "highest", "source", "0"):
        try:
            qh = int(q.rstrip("p"))
            match = next((v for v in videos_full
                          if int(v.get("height") or 0) == qh), None)
            if match:
                keep_name = match.get("name")
        except ValueError:
            pass
    files, total, master_text = await asyncio.to_thread(
        _bundle_select_rung, out_dir, files, meta, keep_name)
    sidecar_subs = await asyncio.to_thread(_list_sidecar_subs, src, item_id)

    # Series/episode metadata + poster so the offline Downloads picker can group
    # and label this download without the host (M3). Fetch+cache TMDb data if it
    # isn't cached yet (one-time per item; best-effort if no key).
    tmdb = item.get("metadata") or {}
    if not tmdb and await _tmdb_effective_key():
        tmdb = await _fetch_item_metadata(item_id) or {}
    bundle_meta = await _bundle_meta_for_file(item, target, tmdb)

    # The requesting profile's current server progress for this file, so the app
    # can seed its OfflineStore baseline (offline resume reflects online history).
    prog = None
    if profile_id:
        fp = (item.get("progress", {}).get(profile_id, {})
                  .get("file_progress", {}).get(file_path))
        if fp:
            prog = {
                "position_sec": fp.get("position_sec", 0),
                "duration_sec": fp.get("duration_sec", 0),
                "completed":    bool(fp.get("completed")),
                "updated_at":   fp.get("updated_at") or "",
            }

    return JSONResponse({
        "ready":              True,
        "cache_key":          key,
        "item_id":            item_id,
        "file_path":          file_path,
        "name":               target.get("name", src.name),
        "bundle_url":         f"/api/library/offline-cache/{key}/",
        "files":              files,
        "file_count":         len(files),
        "total_bytes":        total,
        "master_m3u8":        master_text,   # inline trimmed master (chosen rung only); None ⇒ fetch as-is
        "videos":             videos_full,    # full ABR ladder w/ per-rung download bytes (chooser)
        "duration_sec":       meta.get("duration_sec", 0),
        "audios":             meta.get("audios", []),
        "subtitles":          meta.get("subtitles", []),
        "skipped_image_subs": meta.get("skipped_image_subs", []),
        "fonts":              meta.get("fonts", []),
        "subs":               sidecar_subs,
        "meta":               bundle_meta,
        "progress":           prog,
    })


# ── On-demand (just-in-time) HLS streaming ──────────────────────────────────
#
# The full-prep bundle above encodes an ENTIRE file before playback can start.
# On-demand is the opposite trade-off: playback begins almost immediately and
# segments are transcoded just-in-time as the player requests them — the
# Jellyfin/Plex model. It's the fallback when a file isn't fully prepped yet.
#
# How it works:
#   1. POST /stream-ondemand registers a "session" (one ffmpeg per source+audio)
#      and returns a master playlist URL. ffmpeg is NOT started yet (lazy).
#   2. The player loads master.m3u8 → media.m3u8. media.m3u8 is VIRTUAL: it's
#      computed from the source duration alone (no encoding), listing every
#      6-second segment as if it already existed.
#   3. When the player fetches seg_<n>.ts, the segment endpoint ensures an ffmpeg
#      is running that covers segment n (starting one seeked to n*6 if the
#      current encode can't reach it — i.e. the user seeked), then HOLDS the HTTP
#      response open until that .ts lands on disk. The browser shows its native
#      buffering spinner the whole time — that IS the "loading/waiting" UX.
#
# Key technical choices (see docs/STREAMING.md § On-Demand and docs/GOTCHAS.md):
#   • mpegts segments (NOT fmp4): self-contained, no shared EXT-X-MAP init, so
#     independently-seeked encodes never produce mismatched init segments.
#   • video ALWAYS transcodes with forced keyframes every OD_SEGMENT_SECS
#     (`-force_key_frames expr:gte(t,n_forced*6)`). With `-ss` BEFORE `-i`
#     (fast keyframe seek, output PTS reset to 0) this guarantees segment N
#     covers exactly [N*6,(N+1)*6) — which is what makes the virtual playlist's
#     timing correct and seeking land precisely. Stream-copy can't guarantee
#     that boundary alignment, so it's not used here (it stays a full-prep win).
#   • single source-resolution rendition + one (switchable) audio track. The ABR
#     ladder, seamless quality menu and seamless multi-audio stay full-prep-only.

ONDEMAND_CACHE = Path(__file__).parent / ".ondemand_cache"
OD_SEGMENT_SECS = HLS_SEGMENT_SECS    # MUST match for segment-index ↔ time math
OD_SESSION_IDLE_SECS = 90             # reap a session this long without a fetch
OD_SEG_WAIT_TIMEOUT  = 30             # max seconds to hold a segment request open
OD_LOOKAHEAD_SEGS    = 12             # running encode may be this far behind a
                                      # requested seg before we restart vs. wait
OD_MAX_SESSIONS      = 4              # reap the least-recently-used beyond this
_OD_SEG_RE = re.compile(r"^seg_(\d+)\.ts$")

# session_key → {src, dir, duration, audio_idx, has_audio, start_seg, proc,
#                last_access, lock}
_od_sessions: dict[str, dict] = {}


def _od_session_key(src: Path, audio_idx: int) -> str:
    """Stable 24-hex key per (source bundle key + audio track). A different audio
    selection is a different encode, hence a different session/dir."""
    raw = f"{_offline_cache_key(src)}:{audio_idx}"
    return hashlib.sha256(raw.encode()).hexdigest()[:24]


def _od_seg_path(session: dict, n: int) -> Path:
    return session["dir"] / f"seg_{n}.ts"


def _od_max_seg_on_disk(session: dict) -> int:
    """Highest segment index currently written, or start_seg-1 if none yet."""
    mx = session["start_seg"] - 1
    try:
        for f in session["dir"].iterdir():
            m = _OD_SEG_RE.match(f.name)
            if m:
                mx = max(mx, int(m.group(1)))
    except (FileNotFoundError, OSError):
        pass
    return mx


def _od_wipe_segments(d: Path) -> None:
    """Drop a session dir's segments + internal playlist (sync; tiny tree). Called
    on every (re)start so a previous seek's stale far-ahead segments can't fool
    the 'is the encode ahead of n' check."""
    try:
        for f in d.iterdir():
            if _OD_SEG_RE.match(f.name) or f.name == "internal.m3u8":
                try:
                    f.unlink()
                except OSError:
                    pass
    except (FileNotFoundError, OSError):
        pass


def _od_text_subs(info: dict) -> list[dict]:
    """The source's text (non-image) subtitle streams — the ones we can serve as
    WebVTT alongside an on-demand session, same set the bundle extracts."""
    return [s for s in (info.get("subtitles") or []) if not s.get("image_based")]


def _od_subs_meta(info: dict) -> list[dict]:
    """Build the on-demand `subtitles` list (UI index → sub_<i>.vtt), mirroring the
    bundle's meta.json subtitles[] so the client attaches them identically. Styled
    ASS/SSA subs also carry `ass_file` (raw sidecar extracted lazily) so the client
    renders them with libass-wasm — same as bundle mode; the VTT stays the fallback."""
    return [{
        "idx":      i,
        "file":     f"sub_{i}.vtt",
        "language": s.get("language") or "und",
        "title":    s.get("title") or "",
        "label":    _track_label(s, f"Subtitles {i+1}"),
        **({"styled": True, "ass_file": f"sub_{i}.ass"} if s.get("styled") else {}),
    } for i, s in enumerate(_od_text_subs(info))]


async def _od_extract_sub(src: str, src_sub_idx: int, out: Path) -> None:
    """Extract one embedded text subtitle stream from the source to WebVTT (lazy —
    on first fetch). Below-normal priority; best-effort. Embedded text-sub
    extraction is fast (no video decode)."""
    ffmpeg = analyzer.ffmpeg_bin()
    if not ffmpeg:
        return
    args = [ffmpeg, "-hide_banner", "-v", "error", "-y",
            "-i", src, "-map", f"0:s:{src_sub_idx}",
            "-c:s", "webvtt", "-f", "webvtt", str(out)]
    try:
        proc = await asyncio.create_subprocess_exec(
            *args, stdout=asyncio.subprocess.DEVNULL,
            stderr=asyncio.subprocess.DEVNULL, **_FFMPEG_SUBPROCESS_KW)
        await proc.wait()
    except Exception:
        pass


async def _od_extract_ass(src: str, src_sub_idx: int, out: Path) -> None:
    """Extract one embedded ASS/SSA subtitle stream from the source to a raw `.ass`
    sidecar (stream-copied, styling intact) — the libass-wasm input for styled
    on-demand subs. Lazy (first fetch), below-normal priority, best-effort. Mirrors
    the bundle's `sub_<i>.ass` output; the flattened `sub_<i>.vtt` remains the
    fallback. ffmpeg picks the ass muxer from the `.ass` extension."""
    ffmpeg = analyzer.ffmpeg_bin()
    if not ffmpeg:
        return
    args = [ffmpeg, "-hide_banner", "-v", "error", "-y",
            "-i", src, "-map", f"0:s:{src_sub_idx}",
            "-c:s", "copy", "-f", "ass", str(out)]
    try:
        proc = await asyncio.create_subprocess_exec(
            *args, stdout=asyncio.subprocess.DEVNULL,
            stderr=asyncio.subprocess.DEVNULL, **_FFMPEG_SUBPROCESS_KW)
        await proc.wait()
    except Exception:
        pass


_OD_SUB_RE = re.compile(r"^sub_(\d+)\.vtt$")
_OD_ASS_RE = re.compile(r"^sub_(\d+)\.ass$")
_OD_FONT_RE = re.compile(r"^font_\d+\.[A-Za-z0-9]+$")


def _od_build_ffmpeg_args(
    ffmpeg: str, src: Path, audio_idx: int, has_audio: bool,
    start_seg: int, use_nvenc: bool, hw_decode: bool = True,
) -> list[str]:
    """JIT ffmpeg command: transcode from segment `start_seg` forward, emitting
    mpegts HLS segments named seg_<start_seg>.ts, seg_<start_seg+1>.ts, … . All
    outputs are bare names — the caller runs ffmpeg with cwd=<session dir> (same
    Windows-safe rule as the bundle path)."""
    start_sec = start_seg * OD_SEGMENT_SECS
    args = [ffmpeg, "-y", "-hide_banner", "-loglevel", "error"]
    if use_nvenc and hw_decode:
        # Transparent NVDEC tier (no -hwaccel_output_format): NVDEC decodes the
        # source on the GPU. Only added when the caller's `_gpu_can_hwdecode`
        # probe confirms this box's NVDEC can decode the source codec — ffmpeg's
        # transparent path does NOT gracefully fall back when hwaccel init itself
        # hard-fails (e.g. AV1 on a Pascal card), so an unverified codec would
        # abort the encode. When it can't hw-decode we CPU-decode below; NVENC
        # still encodes.
        args += ["-hwaccel", "cuda"]
    # `-ss` BEFORE `-i` is a fast keyframe seek that resets output PTS to 0, so
    # `-force_key_frames` (which reads output time t) places keyframes at exact
    # 0/6/12… boundaries → segment N == [N*6,(N+1)*6).
    args += ["-ss", str(start_sec), "-i", str(src), "-map", "0:v:0"]
    if has_audio:
        args += ["-map", f"0:a:{audio_idx}"]
    if use_nvenc:
        args += ["-c:v", "h264_nvenc", "-preset", "medium", "-rc", "vbr", "-cq", "23"]
    else:
        args += ["-c:v", "libx264", "-preset", "veryfast", "-crf", "23",
                 "-threads", str(OFFLINE_FFMPEG_THREADS)]
    args += [
        "-pix_fmt", "yuv420p", "-profile:v", "high", "-level", "4.1",
        "-force_key_frames", f"expr:gte(t,n_forced*{OD_SEGMENT_SECS})",
    ]
    if has_audio:
        args += ["-c:a", "aac", "-b:a", "160k", "-ac", "2"]
    args += [
        # Shift the MUXED timestamps to the absolute source position. `-ss` reset
        # output PTS to 0 (so force_key_frames' `t` is correctly 0-based and
        # boundaries land at 0/6/12…), but a player seeking across a session
        # restart needs each segment's timestamps to match its playlist position.
        # output_ts_offset is applied after encoding, so it shifts PTS to
        # [start_sec, …] WITHOUT disturbing the keyframe spacing — segments from
        # any seek-restarted session then share one consistent absolute timeline
        # (no EXT-X-DISCONTINUITY needed; works on hls.js AND Safari native).
        "-output_ts_offset", str(start_sec),
        "-f", "hls",
        "-hls_time", str(OD_SEGMENT_SECS),
        "-hls_segment_type", "mpegts",
        "-hls_flags", "independent_segments",
        "-start_number", str(start_seg),
        "-hls_segment_filename", "seg_%d.ts",   # bare name → lands in cwd (session dir)
        "-hls_list_size", "0",
        "internal.m3u8",   # ffmpeg's own playlist; ignored (we serve a virtual one)
    ]
    return args


async def _od_drain_stderr(proc, tail: deque) -> None:
    """Drain ffmpeg stderr so the OS pipe can't fill (which would wedge the
    encode), keeping the last lines for failure logging."""
    if proc.stderr is None:
        return
    while True:
        try:
            line = await proc.stderr.readline()
        except Exception:
            return
        if not line:
            return
        tail.append(line.decode("utf-8", "replace").rstrip())


async def _od_start_encode(session: dict, start_seg: int) -> None:
    """(Re)start the session's ffmpeg seeked to `start_seg`. Caller holds
    session['lock']. Terminates any prior encode and wipes stale segments first."""
    start_seg = max(0, start_seg)
    old = session.get("proc")
    if old is not None and old.returncode is None:
        try:
            old.terminate()
        except Exception:
            pass
    await asyncio.to_thread(_od_wipe_segments, session["dir"])
    session["dir"].mkdir(parents=True, exist_ok=True)
    session["start_seg"] = start_seg
    ffmpeg = analyzer.ffmpeg_bin()
    if not ffmpeg:
        raise HTTPException(503, "ffmpeg is not available.")
    use_nvenc = await _has_nvenc()
    # Gate GPU decode on an NVDEC capability probe — AV1 (and other codecs this
    # box's NVDEC can't decode) would otherwise hard-fail `-hwaccel cuda` instead
    # of falling back, tearing down every session. When it can't, CPU-decode +
    # NVENC-encode.
    v = session.get("video") or {}
    hw_decode = use_nvenc and await _gpu_can_hwdecode(
        Path(session["src"]), v.get("codec", ""), v.get("pix_fmt", ""))
    args = _od_build_ffmpeg_args(
        ffmpeg, Path(session["src"]), session["audio_idx"],
        session["has_audio"], start_seg, use_nvenc, hw_decode,
    )
    cmd = _ffmpeg_nice_prefix() + args
    hls_log.info("ondemand %s START seg=%d nvenc=%s hwdec=%s cmd: %s",
                 session["key"], start_seg, use_nvenc, hw_decode,
                 " ".join(shlex.quote(a) for a in cmd))
    proc = await asyncio.create_subprocess_exec(
        *cmd, cwd=str(session["dir"]),
        stdout=asyncio.subprocess.DEVNULL,
        stderr=asyncio.subprocess.PIPE,
        **_FFMPEG_SUBPROCESS_KW,
    )
    session["proc"] = proc
    session["last_access"] = time.time()
    tail: deque = deque(maxlen=40)

    async def _watch() -> None:
        await _od_drain_stderr(proc, tail)
        await proc.wait()
        if proc.returncode not in (0, None) and session.get("proc") is proc:
            # Non-zero AND still the live proc (i.e. not a deliberate restart):
            # log the tail so a broken source surfaces in logs/hls.log.
            hls_log.warning("ondemand %s ffmpeg rc=%s\n  %s",
                            session["key"], proc.returncode,
                            "\n  ".join(tail) or "(no stderr)")

    asyncio.create_task(_watch())


async def _od_teardown(session_key: str) -> None:
    """Terminate a session's ffmpeg and delete its segment dir (best-effort)."""
    session = _od_sessions.pop(session_key, None)
    if not session:
        return
    proc = session.get("proc")
    if proc is not None and proc.returncode is None:
        try:
            proc.terminate()
        except Exception:
            pass
    await asyncio.to_thread(shutil.rmtree, session["dir"], ignore_errors=True)
    hls_log.info("ondemand %s torn down", session_key)


async def _od_reaper() -> None:
    """Background loop: reap idle sessions and cap the live count. Idle is long
    (90 s) and active playback refreshes last_access on every segment fetch, so a
    watching session is never reaped mid-stream."""
    while True:
        await asyncio.sleep(30)
        try:
            now = time.time()
            for key, s in list(_od_sessions.items()):
                if now - s.get("last_access", 0) > OD_SESSION_IDLE_SECS:
                    await _od_teardown(key)
            if len(_od_sessions) > OD_MAX_SESSIONS:
                victims = sorted(_od_sessions.items(),
                                 key=lambda kv: kv[1].get("last_access", 0))
                for key, _s in victims[:len(_od_sessions) - OD_MAX_SESSIONS]:
                    await _od_teardown(key)
        except Exception:
            hls_log.exception("ondemand reaper tick failed")


class OnDemandReq(BaseModel):
    file_path: str
    profile_id: str = ""
    audio_idx: Optional[int] = None   # source audio stream index; None ⇒ default


@app.post("/api/library/{item_id}/stream-ondemand")
async def stream_ondemand(item_id: str, req: OnDemandReq) -> JSONResponse:
    """Begin (or re-attach to) a just-in-time HLS session for a file and return a
    master playlist URL the player can load immediately. Also kicks off the normal
    full background prep so the NEXT play gets the rich ABR/multi-audio bundle."""
    if not HLS_AVAILABLE:
        raise HTTPException(503, HLS_UNAVAILABLE_MSG)
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")
    target = next((f for f in item.get("files", []) if f["path"] == req.file_path), None)
    if not target:
        raise HTTPException(404, "File not found in this item.")
    src = Path(target["path"])
    if not src.exists():
        raise HTTPException(404, "File not on disk.")
    _assert_not_compressing(str(src))

    info = await asyncio.to_thread(_ffprobe_full, str(src))
    duration = float(info.get("duration_sec", 0) or 0)
    if not info.get("video"):
        raise HTTPException(422, "No video stream in source.")
    if duration <= 0:
        raise HTTPException(422, "Could not determine source duration.")

    src_audios = info.get("audios") or []
    audios_meta = [
        {
            "idx":      a["idx"],
            "label":    _track_label(a, f"Audio {a['idx']+1}"),
            "language": a.get("language") or "und",
            "title":    a.get("title") or "",
            "default":  (a["idx"] == 0) if all(not x.get("default") for x in src_audios)
                        else bool(a.get("default")),
        }
        for a in src_audios
    ]
    saved = (_saved_local_tracks(lib, item, req.profile_id, req.file_path)
             if req.profile_id else {})

    valid_idxs = {a["idx"] for a in src_audios}
    if req.audio_idx is not None and req.audio_idx in valid_idxs:
        aidx = req.audio_idx
    elif isinstance(saved.get("audio_idx"), int) and saved["audio_idx"] in valid_idxs:
        aidx = saved["audio_idx"]
    elif src_audios:
        aidx = next((a["idx"] for a in src_audios if a.get("default")), src_audios[0]["idx"])
    else:
        aidx = -1   # no audio in source

    # Source stream indices of the text subtitles, in UI order — so a sub_<i>.vtt
    # fetch can extract the right embedded stream on demand.
    sub_idxs = [s["idx"] for s in _od_text_subs(info)]

    key = _od_session_key(src, aidx)
    session = _od_sessions.get(key)
    if session is None:
        ONDEMAND_CACHE.mkdir(exist_ok=True)
        session = {
            "key":         key,
            "src":         str(src),
            "dir":         ONDEMAND_CACHE / key,
            "duration":    duration,
            "audio_idx":   aidx,
            "has_audio":   aidx >= 0,
            "start_seg":   0,
            "proc":        None,
            "last_access": time.time(),
            "lock":        asyncio.Lock(),
            "sub_idxs":    sub_idxs,
            "fonts":       [],           # embedded fonts for styled ASS subs (libass)
            "video":       info.get("video") or {},   # codec/pix_fmt for NVDEC probe
        }
        session["dir"].mkdir(parents=True, exist_ok=True)
        _od_sessions[key] = session
        # Styled subs need the fansub's embedded fonts. Extract them eagerly (once,
        # cheap `-dump_attachment` pass, only when a styled sub exists) so the
        # `fonts` list below is populated before the client's first libass apply;
        # the raw `sub_<i>.ass` files stay lazy (extracted on first fetch). The
        # reaper wipes the whole session dir, fonts included.
        if any(s.get("styled") for s in _od_text_subs(info)):
            try:
                session["fonts"] = await asyncio.to_thread(
                    _extract_bundle_fonts, src, session["dir"], info)
            except Exception as exc:
                hls_log.warning("ondemand %s: font extraction skipped: %s", key, exc)
        hls_log.info("ondemand %s session created src=%s audio=%d dur=%.1fs",
                     key, src.name, aidx, duration)
    else:
        session["last_access"] = time.time()
        session["sub_idxs"] = sub_idxs   # keep fresh across re-attach

    # Kick off the full bundle prep in the background (bulk queue — low priority,
    # honors the global pause) so a SUBSEQUENT play uses the rich multi-audio/ABR
    # bundle instead of JIT. _maybe_start_prep_job only registers the job + spawns
    # its own task (no long await), so this returns immediately; best-effort.
    try:
        await _maybe_start_prep_job(src, item_id)
    except Exception as exc:
        hls_log.warning("ondemand %s: background full-prep enqueue skipped: %s", key, exc)

    sidecar_subs = await asyncio.to_thread(_list_sidecar_subs, src, item_id)
    return JSONResponse({
        "ready":             True,
        "mode":              "ondemand",
        "master_url":        f"/api/library/ondemand/{key}/master.m3u8",
        "duration_sec":      duration,
        "audios":            audios_meta,
        "subtitles":         _od_subs_meta(info),   # embedded text subs, served as sub_<i>.vtt
        "fonts":             session.get("fonts") or [],  # for styled ASS (libass-wasm)
        "subs":              sidecar_subs,
        "saved_tracks":      saved,
        "default_audio_idx": aidx,
    })


def _od_media_playlist(duration: float) -> str:
    """Build the VIRTUAL VOD media playlist from duration alone — no encoding.
    Lists every OD_SEGMENT_SECS segment as if it already existed; the segment
    endpoint conjures each .ts on demand when the player fetches it."""
    n = int(duration // OD_SEGMENT_SECS)
    if duration - n * OD_SEGMENT_SECS > 0.001:
        n += 1
    lines = [
        "#EXTM3U",
        "#EXT-X-VERSION:3",
        f"#EXT-X-TARGETDURATION:{OD_SEGMENT_SECS + 1}",
        "#EXT-X-MEDIA-SEQUENCE:0",
        "#EXT-X-PLAYLIST-TYPE:VOD",
    ]
    for i in range(n):
        seglen = duration - i * OD_SEGMENT_SECS if i == n - 1 else OD_SEGMENT_SECS
        if seglen <= 0:
            seglen = OD_SEGMENT_SECS
        lines.append(f"#EXTINF:{seglen:.3f},")
        lines.append(f"seg_{i}.ts")
    lines.append("#EXT-X-ENDLIST")
    return "\n".join(lines) + "\n"


@app.get("/api/library/ondemand/{session_key}/{filename}")
async def ondemand_file(session_key: str, filename: str):
    """Serve a JIT session's master/media playlist or a segment (transcoding it
    on demand). See the module comment above for the full flow."""
    if not _CACHE_KEY_RE.match(session_key):
        raise HTTPException(400, "Invalid session.")
    session = _od_sessions.get(session_key)
    if session is None:
        # Reaped or never created — the client should re-POST /stream-ondemand.
        raise HTTPException(410, "Streaming session expired.")
    session["last_access"] = time.time()

    if filename == "master.m3u8":
        master = ("#EXTM3U\n"
                  "#EXT-X-STREAM-INF:BANDWIDTH=4000000\n"
                  "media.m3u8\n")
        return Response(content=master, media_type="application/vnd.apple.mpegurl")

    if filename == "media.m3u8":
        return Response(content=_od_media_playlist(session["duration"]),
                        media_type="application/vnd.apple.mpegurl")

    # Embedded text subtitle, extracted from the source on first fetch (lazy) and
    # cached in the session dir — so on-demand playback has the same in-MKV subs
    # the full bundle would. The reaper wipes these with the session dir.
    sm = _OD_SUB_RE.match(filename)
    if sm:
        i = int(sm.group(1))
        sub_idxs = session.get("sub_idxs") or []
        if i >= len(sub_idxs):
            raise HTTPException(404, "No such subtitle.")
        out = session["dir"] / f"sub_{i}.vtt"
        if not out.exists():
            await _od_extract_sub(session["src"], sub_idxs[i], out)
        if not out.exists():
            raise HTTPException(404, "Subtitle could not be extracted.")
        return FileResponse(str(out), media_type="text/vtt")

    # Raw styled ASS/SSA sidecar for the libass-wasm overlay, extracted lazily on
    # first fetch (styling intact). Same set as the VTT subs above; the client only
    # requests it for subs `_od_subs_meta` flagged `styled`.
    am = _OD_ASS_RE.match(filename)
    if am:
        i = int(am.group(1))
        sub_idxs = session.get("sub_idxs") or []
        if i >= len(sub_idxs):
            raise HTTPException(404, "No such subtitle.")
        out = session["dir"] / f"sub_{i}.ass"
        if not out.exists():
            await _od_extract_ass(session["src"], sub_idxs[i], out)
        if not out.exists():
            raise HTTPException(404, "Subtitle could not be extracted.")
        return FileResponse(str(out), media_type=_HLS_MIME[".ass"])

    # Embedded font for styled ASS rendering (extracted eagerly at session create).
    if _OD_FONT_RE.match(filename):
        out = session["dir"] / filename
        if not out.exists() or not out.is_file():
            raise HTTPException(404, "Font not found.")
        media = _HLS_MIME.get(out.suffix.lower(), "application/octet-stream")
        return FileResponse(str(out), media_type=media, filename=out.name)

    m = _OD_SEG_RE.match(filename)
    if not m:
        raise HTTPException(400, "Invalid path.")
    n = int(m.group(1))
    seg_path = _od_seg_path(session, n)

    # Already produced → serve straight away.
    if seg_path.exists():
        return FileResponse(str(seg_path), media_type="video/mp2t")

    # Decide (under the session lock) whether the running encode will reach n soon
    # or whether we must (re)start seeked to n. The lock is held only for this
    # decision + any restart — NOT for the wait below — so concurrent segment
    # requests during a seek don't each spawn an ffmpeg.
    async with session["lock"]:
        if not seg_path.exists():   # re-check inside the lock
            proc = session.get("proc")
            alive = proc is not None and proc.returncode is None
            covered = alive and session["start_seg"] <= n
            near = (n - _od_max_seg_on_disk(session)) <= OD_LOOKAHEAD_SEGS
            if not (covered and near):
                # n is before the current encode, or too far ahead of it (a seek)
                # — start a fresh encode at n.
                await _od_start_encode(session, n)

    # Hold the response open until the segment lands — the browser's buffering
    # spinner is the user-visible "generating that part" state.
    deadline = time.time() + OD_SEG_WAIT_TIMEOUT
    while time.time() < deadline:
        if seg_path.exists():
            session["last_access"] = time.time()
            return FileResponse(str(seg_path), media_type="video/mp2t")
        proc = session.get("proc")
        # Encode ended without producing n (crash / unexpected EOF) — stop waiting.
        if proc is not None and proc.returncode not in (None, 0) \
                and _od_max_seg_on_disk(session) < n:
            break
        await asyncio.sleep(0.15)
    raise HTTPException(504, "Segment generation timed out.")


@app.post("/api/library/ondemand/{session_key}/close")
async def ondemand_close(session_key: str) -> JSONResponse:
    """Best-effort teardown when the player stops (sendBeacon on unload). The
    reaper is the backstop if this never arrives."""
    if not _CACHE_KEY_RE.match(session_key):
        raise HTTPException(400, "Invalid session.")
    await _od_teardown(session_key)
    return JSONResponse({"ok": True})


# ── Clip: save & share the last N seconds of whatever is playing ────────────
#
# A "clip" is a short, standalone MP4 (H.264 + AAC, +faststart) cut from the end
# of the current playback position — pressed from the fullscreen VLC controls
# ("On TV") or the on-device player. It's re-encoded to a universally-compatible
# container so it can be AirDropped / shared straight off the phone. Clips are
# ephemeral: written under `.clips/<token>/` and purged after CLIP_TTL_SECS.
#
# We require the source to already be HLS-prepped (the bundle exists) before
# clipping — that guarantees the file is on disk and probed, and matches the
# product decision that clipping is a prepped-only feature. The clip itself is
# cut from the ORIGINAL source (not the HLS segments) for best quality + precise
# track mapping.
CLIPS_CACHE = Path(__file__).parent / ".clips"
CLIP_TTL_SECS = 2 * 3600           # generated clips are purged after 2 hours
CLIP_MAX_SECONDS = 300             # cap "last X seconds" so a clip can't balloon into a huge re-encode
CLIP_ENCODE_TIMEOUT = 240          # kill a wedged clip encode after this long
_CLIP_TOKEN_RE = re.compile(r"^[a-f0-9]{16}$")
_CLIP_FILE_RE = re.compile(r"^[A-Za-z0-9._-]+\.mp4$")


def _safe_clip_stem(name: str) -> str:
    """Filesystem/URL-safe stem (regex-validated charset, capped length)."""
    stem = re.sub(r"[^A-Za-z0-9._-]+", "_", Path(name or "").stem).strip("._-")
    return (stem or "clip")[:60]


def _purge_old_clips() -> None:
    """Drop clip dirs older than CLIP_TTL_SECS (best-effort; sync, tiny tree)."""
    try:
        cutoff = time.time() - CLIP_TTL_SECS
        for d in CLIPS_CACHE.iterdir():
            try:
                if d.is_dir() and d.stat().st_mtime < cutoff:
                    shutil.rmtree(d, ignore_errors=True)
            except Exception:
                pass
    except FileNotFoundError:
        pass
    except Exception:
        pass


async def _build_clip(src: Path, start: float, dur: float, audio_idx: int,
                      out_path: Path) -> tuple[bool, str]:
    """Re-encode `[start, start+dur]` of `src` to a shareable MP4 at `out_path`.

    `-ss` before `-i` keyframe-seeks for speed; the re-encode then lands on the
    exact start. Maps the first video + the requested audio stream (optional, so
    a bad index doesn't fail the encode). NVENC when available, else libx264.
    Returns (ok, error_message).
    """
    ffmpeg = analyzer.ffmpeg_bin()
    if not ffmpeg:
        return False, "ffmpeg is not available."
    use_nvenc = await _has_nvenc()
    args = [
        ffmpeg, "-y", "-hide_banner", "-loglevel", "error",
        "-ss", f"{max(0.0, start):.3f}", "-i", str(src), "-t", f"{dur:.3f}",
        "-map", "0:v:0", "-map", f"0:a:{max(0, audio_idx)}?",
    ]
    if use_nvenc:
        args += ["-c:v", "h264_nvenc", "-preset", "medium", "-rc", "vbr", "-cq", "23"]
    else:
        args += ["-c:v", "libx264", "-preset", "veryfast", "-crf", "23",
                 "-threads", str(OFFLINE_FFMPEG_THREADS)]
    args += [
        "-pix_fmt", "yuv420p", "-profile:v", "high", "-level", "4.1",
        "-c:a", "aac", "-b:a", "160k", "-ac", "2",
        "-movflags", "+faststart", str(out_path),
    ]
    cmd = _ffmpeg_nice_prefix() + args
    try:
        proc = await asyncio.create_subprocess_exec(
            *cmd,
            stdout=asyncio.subprocess.DEVNULL,
            stderr=asyncio.subprocess.PIPE,
            **_FFMPEG_SUBPROCESS_KW,
        )
        try:
            _, err = await asyncio.wait_for(proc.communicate(), timeout=CLIP_ENCODE_TIMEOUT)
        except asyncio.TimeoutError:
            try:
                proc.terminate()
            except Exception:
                pass
            return False, "Clip encode timed out."
    except Exception as e:
        return False, f"Failed to start clip encode: {e}"
    if proc.returncode != 0 or not out_path.exists():
        tail = (err or b"").decode("utf-8", "replace").strip().splitlines()[-1:]
        hls_log.warning("clip encode failed rc=%s src=%s: %s",
                        proc.returncode, src, "; ".join(tail) or "no detail")
        return False, "; ".join(tail) or "Clip encode failed."
    return True, ""


class ClipReq(BaseModel):
    file_path: str
    end_sec: float                  # clip ENDS here (current playback position)
    duration_sec: float = 30.0      # length to grab back from end_sec
    audio_idx: int = 0              # source audio stream index (on-device passes its rendition idx)


@app.post("/api/library/{item_id}/clip")
async def make_clip(item_id: str, req: ClipReq) -> JSONResponse:
    """Cut & re-encode a shareable MP4 of the last `duration_sec` seconds.

    Ends at `end_sec` (the live playback position). Requires the file to be
    HLS-prepped first (bundle on disk). Returns {ok, url, filename, duration_sec};
    the browser then downloads / shares the URL. 503 on macOS (no HLS), 409 when
    the file isn't prepped yet.
    """
    if not HLS_AVAILABLE:
        raise HTTPException(503, HLS_UNAVAILABLE_MSG)
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")
    target = next((f for f in item.get("files", []) if f["path"] == req.file_path), None)
    if not target:
        raise HTTPException(404, "File not found in this item.")
    src = Path(target["path"])
    if not src.exists():
        raise HTTPException(404, "File not on disk.")
    _assert_not_compressing(str(src))

    # Clippable when the file is actively watchable on-device: either a full HLS
    # bundle exists, OR a live JIT (on-demand) session is streaming it. Both
    # guarantee the source is on disk + probed — the same invariant the old
    # bundle-only gate provided. `_build_clip` cuts straight from the source, so no
    # bundle artifact is actually read; this only gates on active playback.
    bundle_ready = (_offline_cache_dir(src) / "master.m3u8").exists()
    od_active = any(s.get("src") == str(src) for s in _od_sessions.values())
    if not (bundle_ready or od_active):
        raise HTTPException(409, "Play this episode on-device first, then you can clip it.")

    dur = max(1.0, min(float(CLIP_MAX_SECONDS), float(req.duration_sec or 30.0)))
    end = max(0.0, float(req.end_sec or 0.0))
    start = max(0.0, end - dur)
    real_dur = end - start
    if real_dur < 0.5:
        raise HTTPException(400, "Play a little further in before clipping.")

    _purge_old_clips()
    token = secrets.token_hex(8)
    out_dir = CLIPS_CACHE / token
    out_dir.mkdir(parents=True, exist_ok=True)
    filename = f"{_safe_clip_stem(target.get('name') or src.name)}-clip-{int(round(real_dur))}s.mp4"
    out_path = out_dir / filename

    ok, err = await _build_clip(src, start, real_dur, int(req.audio_idx or 0), out_path)
    if not ok:
        shutil.rmtree(out_dir, ignore_errors=True)
        raise HTTPException(500, err or "Couldn't create the clip.")
    return JSONResponse({
        "ok": True,
        "url": f"/api/library/clip/{token}/{filename}",
        "filename": filename,
        "duration_sec": round(real_dur, 1),
    })


@app.get("/api/library/clip/{token}/{filename}")
async def serve_clip(token: str, filename: str) -> FileResponse:
    """Serve a generated clip as a downloadable MP4 attachment."""
    if not _CLIP_TOKEN_RE.match(token) or not _CLIP_FILE_RE.match(filename):
        raise HTTPException(400, "Invalid path.")
    p = CLIPS_CACHE / token / filename
    if not p.exists() or not p.is_file():
        raise HTTPException(404, "Clip not found (it may have expired).")
    return FileResponse(str(p), media_type="video/mp4", filename=p.name)


# ── Admin: offline-cache inventory + cleanup ────────────────────────────────
#
# `.offline_cache/<cache_key>.mp4` accumulates indefinitely — there's no
# automatic eviction, and re-encoding a source (mtime/size change) leaves the
# old entry on disk as an orphan. These endpoints power an admin tab that
# shows what's there, how much space it costs, and lets the operator delete
# per-file, per-item, or every orphan in one shot.

# Cached inventory snapshot. The FS walk below is O(total segments) and on a
# large ABR cache takes long enough that re-walking on every admin tab open felt
# broken. We keep the last result + when it was built; reads serve the snapshot
# instantly and the admin "Refresh" button forces a fresh walk (`force=True`).
# Mutations (deletes) invalidate it via `_invalidate_offline_cache_inventory`.
_offline_cache_inv_snapshot: "dict | None" = None
_offline_cache_inv_lock = asyncio.Lock()


def _invalidate_offline_cache_inventory() -> None:
    """Drop the cached inventory so the next read rebuilds from disk. Called
    after any delete so a stale snapshot can't show purged bundles."""
    global _offline_cache_inv_snapshot
    _offline_cache_inv_snapshot = None


async def _build_offline_cache_inventory(*, force: bool = False) -> dict:
    """Return the offline-cache inventory, serving a cached snapshot unless
    `force` (or no snapshot yet). Adds `generated_at` (epoch secs) so the UI can
    show how old the data is.

    On a miss it fetches the library + snapshots the jobs, then runs the (heavy,
    blocking) filesystem walk in a worker thread.

    The walk sums every file in every HLS bundle via `_dir_size_bytes` (recursive
    `rglob` + `stat`). Since the ABR ladder tripled the segment count per bundle,
    a sizeable `.offline_cache/` makes that walk take long enough that doing it
    inline on the event loop freezes the WHOLE server — SSE, VLC polling, and
    every other request stall until it looks crashed and the service restarts.
    Offloading keeps the loop free (same discipline as `_run_offline_job`). The
    job list is snapshotted here so the worker thread never iterates the live
    `_offline_jobs` dict while the loop mutates it.

    The lock serialises concurrent builds so two near-simultaneous opens (or an
    open racing the auto-purge loop) don't both walk the whole tree.
    """
    global _offline_cache_inv_snapshot
    if not force and _offline_cache_inv_snapshot is not None:
        return _offline_cache_inv_snapshot
    async with _offline_cache_inv_lock:
        # Re-check inside the lock: a concurrent caller may have just built it.
        if not force and _offline_cache_inv_snapshot is not None:
            return _offline_cache_inv_snapshot
        lib = await get_library()
        jobs = list(_offline_jobs.values())
        data = await asyncio.to_thread(_offline_cache_inventory_sync, lib, jobs)
        data["generated_at"] = time.time()
        _offline_cache_inv_snapshot = data
        return data


def _offline_cache_inventory_sync(lib: dict, jobs: list[dict]) -> dict:
    """Walk every co-located `.streamlink_cache/` (+ the legacy central
    OFFLINE_CACHE) + the library + the job snapshot and return the admin payload.

    Each per-file entry has a `status` of:
      cached         — `<sha>/master.m3u8` exists, ready for HLS playback
      processing     — ffmpeg is actively encoding now (progress + ETA included)
      pending        — queued behind the OFFLINE_JOB_CONCURRENCY semaphore
      error          — the most recent prep job failed; `error` carries the message
      partial_stale  — a `<sha>.part/` directory exists with no live job
                       (process crashed mid-encode, or the job entry was evicted)
    Only entries with one of those states are included; "no work has ever started
    for this file" is just absent.

    Bundles live beside the media now, so a cache/orphan entry carries the `root`
    (its containing `.streamlink_cache` dir) — that's what `_delete_cache_artifacts`
    needs to actually remove it.
    """
    # 1) Inventory every cache root: distinguish completed bundles (`<sha>/`) from
    #    in-flight staging dirs (`<sha>.part/`). Both count toward total bytes. We
    #    also include any leftover top-level `.mp4` files from pre-v3-hls central
    #    caches in the "orphan" pool so the operator can clear them.
    roots = _bundle_cache_dirs_sync(lib)
    if OFFLINE_CACHE.exists():
        roots.add(OFFLINE_CACHE)
    PART_SUFFIX = ".part"
    cached_dirs:  dict[str, dict] = {}   # cache_key → {bytes, mtime, root}
    partial_dirs: dict[str, dict] = {}   # cache_key → {bytes, mtime, root}
    legacy_files: list[dict] = []        # pre-v3-hls leftovers (.mp4 / .part.mp4)
    total_bytes = 0
    for root in roots:
        try:
            children = list(root.iterdir()) if root.is_dir() else []
        except OSError:
            continue
        for p in children:
            try:
                st = p.stat()
            except OSError:
                continue
            if p.is_dir() and _CACHE_KEY_RE.match(p.name):
                sz = _dir_size_bytes(p)
                cached_dirs[p.name] = {"bytes": sz, "mtime": st.st_mtime, "root": str(root)}
                total_bytes += sz
            elif p.is_dir() and p.name.endswith(PART_SUFFIX):
                key = p.name[: -len(PART_SUFFIX)]
                if _CACHE_KEY_RE.match(key):
                    sz = _dir_size_bytes(p)
                    partial_dirs[key] = {"bytes": sz, "mtime": st.st_mtime, "root": str(root)}
                    total_bytes += sz
            elif p.is_file() and p.suffix == ".mp4":
                # Pre-v3-hls single-MP4 cache. Always orphan now — surface it so
                # the operator can purge with one click.
                legacy_files.append({
                    "cache_key": p.stem.removesuffix(".part"),
                    "name":      p.name,
                    "kind":      "legacy",
                    "bytes":     st.st_size,
                    "mtime":     st.st_mtime,
                    "root":      str(root),
                })
                total_bytes += st.st_size
    # 2) Index jobs by their output cache key. Keep only the most recent job per
    #    key so a series of failed retries collapses to one row.
    jobs_by_key: dict[str, dict] = {}
    for j in jobs:
        try:
            key = Path(j.get("out", "")).name
        except Exception:
            continue
        if not key:
            continue
        prev = jobs_by_key.get(key)
        if prev is None or j.get("started_at", 0) > prev.get("started_at", 0):
            jobs_by_key[key] = j
    # 3) For every library file still on disk, compute the cache key and combine
    #    cache + partial + job state into one entry. Anything not referenced by
    #    a current library file lands in `orphans` below.
    items_out: list[dict] = []
    matched_keys: set[str] = set()
    now = time.time()
    for it in lib.get("items", []):
        files_out: list[dict] = []
        item_bytes = 0
        cached_n = processing_n = pending_n = error_n = partial_n = 0
        for f in it.get("files", []):
            src = Path(f.get("path", ""))
            try:
                if not src.exists():
                    continue
                key = _offline_cache_key(src)
            except OSError:
                continue
            cached  = cached_dirs.get(key)
            partial = partial_dirs.get(key)
            job     = jobs_by_key.get(key)
            entry: dict = {
                "file_path": f.get("path", ""),
                "name":      f.get("name", "") or src.name,
                "cache_key": key,
                "root":      (cached or partial or {}).get(
                                 "root", str(src.parent / OFFLINE_CACHE_DIRNAME)),
                "bytes":     0,
            }
            if cached:
                entry["status"] = "cached"
                entry["bytes"]  = cached["bytes"]
                entry["mtime"]  = cached["mtime"]
                item_bytes += cached["bytes"]
                cached_n   += 1
                matched_keys.add(key)
            elif job and job["status"] in ("pending", "processing"):
                entry["status"]     = job["status"]
                entry["progress"]   = float(job.get("progress", 0) or 0)
                entry["operation"]  = job.get("operation", "hls")
                entry["encoder"]    = job.get("encoder", "")
                entry["job_id"]     = job.get("id", "")
                entry["started_at"] = job.get("started_at", 0)
                if partial:
                    entry["bytes"] = partial["bytes"]
                    item_bytes += partial["bytes"]
                # Per-file ETA (only meaningful once ffmpeg has been running long
                # enough for the progress reading to stabilize).
                elapsed = max(0.0, now - entry["started_at"])
                if entry["status"] == "processing" and elapsed > 2.0 and entry["progress"] > 0.02:
                    entry["eta_secs"] = elapsed * (1 - entry["progress"]) / entry["progress"]
                if entry["status"] == "processing":
                    processing_n += 1
                else:
                    pending_n    += 1
                matched_keys.add(key)
            elif job and job["status"] == "error":
                entry["status"]     = "error"
                entry["error"]      = job.get("error", "")
                entry["operation"]  = job.get("operation", "hls")
                entry["encoder"]    = job.get("encoder", "")
                entry["job_id"]     = job.get("id", "")
                entry["started_at"] = job.get("started_at", 0)
                if partial:
                    entry["bytes"] = partial["bytes"]
                    item_bytes += partial["bytes"]
                error_n += 1
                matched_keys.add(key)
            elif partial:
                # `<sha>.part/` on disk with no remembered job — almost always
                # a process crash mid-encode. Surface so the operator can clean.
                entry["status"] = "partial_stale"
                entry["bytes"]  = partial["bytes"]
                entry["mtime"]  = partial["mtime"]
                item_bytes += partial["bytes"]
                partial_n  += 1
                matched_keys.add(key)
            else:
                continue
            files_out.append(entry)
        if files_out:
            items_out.append({
                "item_id":          it["id"],
                "title":            it.get("title", ""),
                "file_count":       len(files_out),
                "total_bytes":      item_bytes,
                "cached_count":     cached_n,
                "processing_count": processing_n,
                "pending_count":    pending_n,
                "error_count":      error_n,
                "partial_count":    partial_n,
                "files":            sorted(files_out, key=lambda x: x["name"].lower()),
            })
    items_out.sort(key=lambda x: x["total_bytes"], reverse=True)
    # 4) Orphans: cache/partial dirs whose source no longer maps to any library
    #    file (re-encoded, deleted, or library item removed), plus legacy
    #    single-MP4 files from the pre-HLS cache layout.
    orphans: list[dict] = []
    for k, v in cached_dirs.items():
        if k not in matched_keys:
            orphans.append({"cache_key": k, "kind": "cached", "root": v["root"],
                            "bytes": v["bytes"], "mtime": v["mtime"]})
    for k, v in partial_dirs.items():
        if k not in matched_keys:
            orphans.append({"cache_key": k, "kind": "partial", "root": v["root"],
                            "bytes": v["bytes"], "mtime": v["mtime"]})
    orphans.extend(legacy_files)
    orphans.sort(key=lambda x: x["bytes"], reverse=True)
    return {
        "total_bytes": total_bytes,
        "cache_dir":   str(OFFLINE_CACHE),
        "colocated":   True,
        "items":       items_out,
        "orphans":     orphans,
    }


def _storage_breakdown_sync(lib: dict, bundle_by_path: dict[str, int]) -> dict:
    """Per-series storage breakdown for the admin Storage tab. Walks every library
    item and, for each video file, sums three components:

      source  — the source media file's actual bytes on disk (falls back to the
                stored `size_bytes` when the file can't be stat'd, e.g. mid-move)
      bundle  — its HLS / on-device bundle bytes, passed in as `bundle_by_path`
                (already computed by the offline-cache inventory walk, so we don't
                re-walk every bundle here)
      extras  — same-stem sidecar files in the source directory (subtitles, .nfo,
                AI subs, posters) — small individually but counted for an honest
                total

    Returns `items` sorted by total bytes descending, each carrying its own
    per-file breakdown so the UI can drill into a series without a second request.
    Source/extra stats are one `stat()` per file plus one `iterdir()` per distinct
    directory — cheap next to the recursive bundle walk the inventory already did,
    but still offloaded to a worker thread by the caller because a large library is
    a lot of stats.
    """
    # One directory listing per parent dir, reused across that dir's files so a
    # season folder isn't re-listed once per episode.
    dir_cache: dict[Path, list[Path]] = {}

    def _siblings(d: Path) -> list[Path]:
        if d not in dir_cache:
            try:
                dir_cache[d] = [p for p in d.iterdir() if p.is_file()]
            except OSError:
                dir_cache[d] = []
        return dir_cache[d]

    items_out: list[dict] = []
    g_src = g_bundle = g_extra = 0
    for it in lib.get("items", []):
        files_out: list[dict] = []
        i_src = i_bundle = i_extra = 0
        for f in it.get("files", []):
            p = f.get("path", "")
            src = Path(p)
            if src.suffix.lower() not in VIDEO_EXTS:
                continue
            try:
                sbytes = src.stat().st_size
            except OSError:
                sbytes = int(f.get("size_bytes", 0) or 0)
            bbytes = int(bundle_by_path.get(p, 0) or 0)
            # Same-stem sidecars: `<stem>.srt`, `<stem>.eng.srt`, `<stem>.nfo`,
            # `<stem>-poster.jpg`, etc. Match the video's stem but exclude the
            # video file itself and any other video.
            ebytes = 0
            stem = src.stem
            for sib in _siblings(src.parent):
                if (sib.name != src.name
                        and sib.suffix.lower() not in VIDEO_EXTS
                        and (sib.stem == stem
                             or sib.name.startswith(stem + ".")
                             or sib.name.startswith(stem + "-"))):
                    try:
                        ebytes += sib.stat().st_size
                    except OSError:
                        pass
            total = sbytes + bbytes + ebytes
            files_out.append({
                "name":         f.get("name", "") or src.name,
                "path":         p,
                "source_bytes": sbytes,
                "bundle_bytes": bbytes,
                "extra_bytes":  ebytes,
                "total_bytes":  total,
            })
            i_src += sbytes; i_bundle += bbytes; i_extra += ebytes
        if not files_out:
            continue
        files_out.sort(key=lambda x: x["total_bytes"], reverse=True)
        items_out.append({
            "id":           it.get("id", ""),
            "title":        it.get("title", ""),
            "file_count":   len(files_out),
            "source_bytes": i_src,
            "bundle_bytes": i_bundle,
            "extra_bytes":  i_extra,
            "total_bytes":  i_src + i_bundle + i_extra,
            "files":        files_out,
        })
        g_src += i_src; g_bundle += i_bundle; g_extra += i_extra
    items_out.sort(key=lambda x: x["total_bytes"], reverse=True)
    return {
        "items":        items_out,
        "source_bytes": g_src,
        "bundle_bytes": g_bundle,
        "extra_bytes":  g_extra,
        "total_bytes":  g_src + g_bundle + g_extra,
    }


def _delete_cache_artifacts(cache_key: str, root: Optional[str] = None) -> int:
    """Remove `<key>/` and `<key>.part/` bundle directories, plus any legacy
    pre-v3-hls `.mp4` files keyed by `cache_key`, AND any terminal job entries
    targeting this cache key. Returns total bytes freed on disk. The caller is
    responsible for the active-job 409 check.

    Bundles now live beside the media, so `root` is the containing
    `.streamlink_cache` dir (from the inventory entry). The legacy central
    OFFLINE_CACHE is always checked too, so old central bundles still purge.
    """
    bytes_freed = 0
    roots: list[Path] = [OFFLINE_CACHE]
    if root:
        rp = Path(root)
        if rp not in roots:
            roots.insert(0, rp)
    for r in roots:
        for name in (cache_key, f"{cache_key}.part"):
            d = r / name
            if d.exists() and d.is_dir():
                bytes_freed += _dir_size_bytes(d)
                shutil.rmtree(d, ignore_errors=True)
        # Legacy single-MP4 cache from v2 — orphaned by the v3 cache-key rebase,
        # but still on disk until purged.
        for fname in (f"{cache_key}.mp4", f"{cache_key}.part.mp4"):
            p = r / fname
            try:
                sz = p.stat().st_size
                p.unlink()
                bytes_freed += sz
            except OSError:
                pass
    _bundle_index.pop(cache_key, None)
    # Drop terminal job entries for this key so the UI doesn't keep showing the
    # stale error after the operator has cleaned it up.
    for jid, j in list(_offline_jobs.items()):
        try:
            if Path(j.get("out", "")).name == cache_key and j.get("status") in ("done", "error"):
                _offline_jobs.pop(jid, None)
        except Exception:
            pass
    return bytes_freed


def _offline_cache_path_active(cache_key: str) -> bool:
    """True if a pending/processing prep job is currently writing to this key."""
    return any(Path(j.get("out", "")).name == cache_key
               and j.get("status") in ("pending", "processing")
               for j in _offline_jobs.values())


def _trim_one_bundle(bdir: Path, keep: set[int], dry_run: bool,
                     allowed_srcs: Optional[set[str]] = None) -> int:
    """Drop every down-rung whose height ∉ `keep` from one HLS bundle dir (the
    original rendition, idx 0, is always kept). Deletes the rung's playlist + init
    + segments, rewrites master.m3u8 (dropping its #EXT-X-STREAM-INF + URI pair),
    and updates meta.json. Returns the bytes freed (or that WOULD be freed on a
    dry run). When `allowed_srcs` is given (a scoped run), the bundle is skipped
    unless its meta.json `src` is in that set. Sync — call via asyncio.to_thread."""
    meta_path = bdir / "meta.json"
    try:
        meta = json.loads(meta_path.read_text("utf-8"))
    except Exception:
        return 0
    if allowed_srcs is not None and _norm_path(meta.get("src", "")) not in allowed_srcs:
        return 0
    videos = meta.get("videos") or []
    drop_names = {v.get("name") for v in videos
                  if v.get("idx", 0) != 0 and int(v.get("height") or 0) not in keep}
    if not drop_names:
        return 0

    victims: list[Path] = []
    for name in drop_names:
        victims += list(bdir.glob(f"{name}.m3u8"))
        victims += list(bdir.glob(f"init_{name}.mp4"))
        victims += list(bdir.glob(f"seg_{name}_*.m4s"))
    freed = 0
    for f in victims:
        try:
            freed += f.stat().st_size
        except OSError:
            pass
    if dry_run:
        return freed

    # Rewrite master.m3u8: drop each #EXT-X-STREAM-INF whose following URI line
    # names a dropped rung (the audio #EXT-X-MEDIA lines are left untouched).
    master = bdir / "master.m3u8"
    drop_uris = {f"{n}.m3u8" for n in drop_names}
    try:
        lines = master.read_text("utf-8").splitlines()
        out: list[str] = []
        i = 0
        while i < len(lines):
            line = lines[i]
            if line.startswith("#EXT-X-STREAM-INF"):
                uri = lines[i + 1].strip() if i + 1 < len(lines) else ""
                if uri in drop_uris:
                    i += 2
                    continue
                out.append(line)
                if i + 1 < len(lines):
                    out.append(lines[i + 1])
                i += 2
                continue
            out.append(line)
            i += 1
        master.write_text("\n".join(out) + "\n", "utf-8")
    except Exception:
        return 0   # leave the bundle intact rather than orphan its segments

    for f in victims:
        try:
            f.unlink()
        except OSError:
            pass
    meta["videos"] = [v for v in videos
                      if v.get("idx", 0) == 0 or int(v.get("height") or 0) in keep]
    try:
        meta_path.write_text(json.dumps(meta), "utf-8")
    except Exception:
        pass
    return freed


async def _hls_trim_bundles(keep: set[int], *, dry_run: bool, scope: str = "all") -> dict:
    """Trim existing bundles down to the original + the `keep` heights. `scope`
    None/""/"all" ⇒ every bundle; else a library item id, restricting the trim to
    that item's files (matched by the bundle's meta.json `src`). Skips bundles with
    an active prep job. Returns {bundles, bytes_freed, dry_run}."""
    allowed_srcs: Optional[set[str]] = None
    if scope not in ("", "all", None):
        lib = await get_library()
        item = next((it for it in lib.get("items", []) if it.get("id") == scope), None)
        # An unknown item id ⇒ empty allow-set ⇒ trims nothing (rather than all).
        allowed_srcs = {_norm_path(f.get("path", ""))
                        for f in (item.get("files", []) if item else [])}
    bundles = 0
    freed = 0
    # Bundles live beside the media now (+ legacy central stragglers).
    _lib_for_roots = await get_library()
    roots = _bundle_cache_dirs_sync(_lib_for_roots)
    roots.add(OFFLINE_CACHE)
    for root in roots:
        if not root.exists():
            continue
        for p in sorted(root.iterdir()):
            if not (p.is_dir() and _CACHE_KEY_RE.match(p.name)):
                continue
            if _offline_cache_path_active(p.name):
                continue
            b = await asyncio.to_thread(_trim_one_bundle, p, keep, dry_run, allowed_srcs)
            if b > 0:
                bundles += 1
                freed += b
            await asyncio.sleep(0)
    if not dry_run and freed > 0:
        _invalidate_offline_cache_inventory()
    return {"bundles": bundles, "bytes_freed": freed, "dry_run": dry_run}


# Audio-sync repair. Bundles built before the A/V-sync fixes can have audio
# misaligned with video. Two independent failure modes, two detectors:
#   1. DRIFT / GAP — audio gradually slips or has dropped/padded samples. The
#      audio rendition's total playlist duration diverges from the video's.
#      Cheap to detect (sum the playlist #EXTINF lines — no decode).
#   2. CONSTANT OFFSET — audio is a fixed amount early/late for the whole file
#      (a source audio-start delay, an edit-list / stream-copy artifact, or skew).
#      Both renditions are the SAME length, so detector #1 is blind to it. We
#      ffprobe the bundle's audio-vs-video first-pts GAP and flag it directly: any
#      non-trivial gap plays as desync because the bundle player (Safari / iOS
#      AVPlayer / hls.js on SEPARATE fmp4 renditions) ignores the cross-rendition
#      baseMediaDecodeTime gap and anchors each rendition to playback start. (We do
#      NOT diff against the source's offset: single-program on-demand + VLC honor
#      that offset, but the bundle player does not — so a "faithfully reproduced"
#      source delay is itself the bug here. See _bundle_introduced_av_offset.)
# A bundle flagged by EITHER is purged and re-prepped from source with
# `_force_reencode_video=True`, which re-encodes the original rung AND silence-pads
# the audio to the video's zero (`first_pts=0` → meta `audio_padded_to_zero`),
# collapsing the gap to ≈0 while preserving any real delay as leading silence.
HLS_SYNC_FLAG_SECS  = 1.0    # drift: flag when |audio_total − video_total| > max(this, 1% of duration)
AV_OFFSET_FLAG_SECS = 0.12   # gap (unpadded bundle): flag when audio-vs-video first-pts gap exceeds this
# Padded bundle (audio_padded_to_zero): audio is silence-padded to the video's zero,
# so a correct bundle reads ≈0 while the bug it targets was ~the full source delay
# (often ≥0.5–1.0s). The looser bound tolerates the encoder frame-reorder residual
# (first displayed frame's baseMediaDecodeTime, e.g. ~0.125s on B-frame sources) —
# which re-prepping can't remove — without missing a failed pad.
AV_OFFSET_PAD_FLAG_SECS = 0.35


def _sum_extinf(playlist: Path) -> Optional[float]:
    """Sum the `#EXTINF:<sec>,` durations in an HLS media playlist. Returns None
    if the file is missing/unreadable or carries no EXTINF lines (an incomplete
    or non-media playlist we shouldn't judge). Sync — call via to_thread."""
    try:
        text = playlist.read_text("utf-8")
    except Exception:
        return None
    total = 0.0
    found = False
    for line in text.splitlines():
        if line.startswith("#EXTINF:"):
            try:
                total += float(line[len("#EXTINF:"):].split(",", 1)[0])
                found = True
            except (ValueError, IndexError):
                return None
    return total if found else None


def _bundle_audio_sync_delta(bdir: Path, allowed_srcs: Optional[set[str]] = None) -> Optional[float]:
    """Measure a bundle's worst audio-vs-video duration divergence (seconds).

    Reads meta.json for the video rendition playlist + each audio rendition
    playlist, sums their `#EXTINF` durations, and returns max_i |audio_i − video|.
    Returns None (⇒ skip, don't flag) when the bundle is unreadable, incomplete,
    or (with `allowed_srcs` given) its source isn't in scope. Sync — to_thread."""
    try:
        meta = json.loads((bdir / "meta.json").read_text("utf-8"))
    except Exception:
        return None
    if allowed_srcs is not None and _norm_path(meta.get("src", "")) not in allowed_srcs:
        return None
    videos = meta.get("videos") or []
    audios = meta.get("audios") or []
    if not videos or not audios:
        return None   # nothing to compare (e.g. a silent source) — never flag
    vname = (videos[0].get("name") or "video")
    vdur = _sum_extinf(bdir / f"{vname}.m3u8")
    if vdur is None or vdur <= 0:
        return None
    worst = 0.0
    for a in audios:
        adur = _sum_extinf(bdir / (a.get("playlist") or f"audio_{a.get('idx', 0)}.m3u8"))
        if adur is None:
            continue
        worst = max(worst, abs(adur - vdur))
    return worst


def _probe_rendition_first_pts(playlist: Path) -> Optional[float]:
    """First presentation timestamp (seconds) of an HLS rendition playlist, via
    ffprobe. ffprobe reads the playlist (and its fmp4 EXT-X-MAP init) and reports
    the first packet's pts_time. Returns None if ffprobe is missing or the probe
    fails. Sync — call via to_thread."""
    binp = _ffprobe_bin()
    if not binp or not playlist.exists():
        return None
    try:
        r = subprocess.run(
            [binp, "-v", "error", "-of", "json",
             "-read_intervals", "%+#1",          # only the first packet
             "-show_entries", "packet=pts_time",
             str(playlist)],
            capture_output=True, text=True, timeout=20,
        )
        pkts = (json.loads(r.stdout or "{}").get("packets") or [])
        if not pkts:
            return None
        return float(pkts[0].get("pts_time"))
    except Exception:
        return None


def _bundle_introduced_av_offset(bdir: Path) -> Optional[float]:
    """Measure the bundle's audio-vs-video first-pts GAP (seconds) — the amount a
    naive HLS player will desync by. Returns `apts − vpts` (default-audio rendition
    first-pts minus video rendition first-pts), or None when it can't be measured
    (ffprobe missing, renditions absent).

    Why the RAW gap, not a diff against the source's intended offset: the bundle's
    two fmp4 renditions (audio + video) are aligned by the player via each
    rendition's first `baseMediaDecodeTime`. Safari / iOS AVPlayer / hls.js playing
    SEPARATE renditions effectively ignore a large initial gap and anchor each
    rendition's first sample to playback start — so ANY non-trivial gap (whether it
    came from the source's intrinsic audio delay, a stream-copied edit list, or
    per-stream skew) plays as audio early/late. We no longer treat "faithful
    reproduction of the source offset" as correct (single-program on-demand + VLC
    honor it, but the bundle player does NOT — confirmed with av_probe.py: source
    A/V +1.0s reproduced as bundle +0.976s, yet the bundle plays audio early).
    The cure is always the same: re-prep so the audio rendition is silence-padded
    to the video's zero (`first_pts=0` on the re-encode path → meta
    `audio_padded_to_zero`), collapsing the gap to ≈0 while preserving the delay as
    real leading silence. So a correctly-padded bundle reads ≈0 here; an unfixed
    one reads ≈ its full audio-start gap.

    The caller picks the flag threshold by meta `audio_padded_to_zero`: the padded
    path tolerates the encoder frame-reorder residual (first displayed frame's
    baseMediaDecodeTime) that re-prepping can't remove. Sync — call via to_thread."""
    try:
        meta = json.loads((bdir / "meta.json").read_text("utf-8"))
    except Exception:
        return None
    videos = meta.get("videos") or []
    audios = meta.get("audios") or []
    if not videos or not audios:
        return None
    vname = (videos[0].get("name") or "video")
    a = next((x for x in audios if x.get("default")), audios[0])   # default audio, else first
    vpts = _probe_rendition_first_pts(bdir / f"{vname}.m3u8")
    apts = _probe_rendition_first_pts(bdir / (a.get("playlist") or f"audio_{a.get('idx', 0)}.m3u8"))
    if vpts is None or apts is None:
        return None
    return apts - vpts


def _bundle_sync_flagged(delta: Optional[float], duration_sec: float) -> bool:
    """Drift check (detector #1): flag when the audio/video duration divergence
    exceeds the larger of HLS_SYNC_FLAG_SECS and 1% of duration."""
    if delta is None:
        return False
    return delta > max(HLS_SYNC_FLAG_SECS, 0.01 * max(0.0, duration_sec))


async def _hls_resync_bundles(*, dry_run: bool, scope: str = "all") -> dict:
    """Scan existing bundles for audio misalignment — duration DRIFT
    (`_bundle_audio_sync_delta`) OR a prep-introduced constant OFFSET
    (`_bundle_introduced_av_offset`, ffprobe vs the source)
    — and, unless `dry_run`, purge + re-prep each flagged one from source forcing an
    original-rung re-encode so the offset can't survive. `scope` None/""/"all" ⇒
    every bundle; else a library item id restricting to that item's files (by
    meta.json `src`). Skips bundles with an active prep job. Returns
    {bundles, repaired, dry_run}."""
    lib = await get_library()
    allowed_srcs: Optional[set[str]] = None
    if scope not in ("", "all", None):
        item = next((it for it in lib.get("items", []) if it.get("id") == scope), None)
        # Unknown item id ⇒ empty allow-set ⇒ matches nothing (rather than all).
        allowed_srcs = {_norm_path(f.get("path", ""))
                        for f in (item.get("files", []) if item else [])}
    # Map a source path → owning library item id so a repair re-prep carries the
    # right item_id (drives on-demand-only gating + skip/STT hooks).
    src_to_item: dict[str, str] = {}
    for it in lib.get("items", []):
        for f in it.get("files", []):
            src_to_item[_norm_path(f.get("path", ""))] = it.get("id", "")

    roots = _bundle_cache_dirs_sync(lib)
    roots.add(OFFLINE_CACHE)
    flagged = 0
    repaired = 0
    for root in roots:
        if not root.exists():
            continue
        for p in sorted(root.iterdir()):
            if not (p.is_dir() and _CACHE_KEY_RE.match(p.name)):
                continue
            if _offline_cache_path_active(p.name):
                continue
            # Scope gate first (cheap): skip bundles whose source isn't in scope
            # before spending an ffprobe on them.
            try:
                meta = json.loads((p / "meta.json").read_text("utf-8"))
            except Exception:
                await asyncio.sleep(0)
                continue
            src = meta.get("src", "")
            if allowed_srcs is not None and _norm_path(src) not in allowed_srcs:
                await asyncio.sleep(0)
                continue
            # Detector #1: duration drift (cheap, no decode).
            delta = await asyncio.to_thread(_bundle_audio_sync_delta, p)
            drift = _bundle_sync_flagged(delta, float(meta.get("duration_sec") or 0.0))
            # Detector #2: prep-introduced constant offset (ffprobe the bundle's
            # renditions vs the source's intended A/V offset).
            offset = await asyncio.to_thread(_bundle_introduced_av_offset, p)
            off_thresh = (AV_OFFSET_PAD_FLAG_SECS if meta.get("audio_padded_to_zero")
                          else AV_OFFSET_FLAG_SECS)
            off_flag = offset is not None and abs(offset) > off_thresh
            if not (drift or off_flag):
                await asyncio.sleep(0)
                continue
            reason = (f"drift={delta:.2f}s" if drift else "") + \
                     (" " if drift and off_flag else "") + \
                     (f"offset={offset:+.2f}s" if off_flag else "")
            flagged += 1
            if dry_run:
                hls_log.info("hls-resync: bundle %s would repair (%s)", p.name, reason)
                await asyncio.sleep(0)
                continue
            src_path = Path(src)
            if not src or not await asyncio.to_thread(src_path.exists):
                hls_log.warning("hls-resync: bundle %s flagged (%s) but source "
                                "missing (%s) — skipping repair", p.name, reason, src)
                await asyncio.sleep(0)
                continue
            # Purge the bad bundle, then re-queue a prep that RE-ENCODES the original
            # rung (force_reencode_video) so the rebuilt bundle can't carry the same
            # offset. Runs at the usual bulk concurrency/pause semantics.
            await asyncio.to_thread(_delete_cache_artifacts, p.name, str(root))
            _invalidate_bundle_index()
            await _maybe_start_prep_job(src_path, src_to_item.get(_norm_path(src), ""),
                                        force_reencode_video=True)
            repaired += 1
            hls_log.info("hls-resync: re-prepping %s (%s)", src, reason)
            await asyncio.sleep(0)
    if not dry_run and repaired > 0:
        _invalidate_offline_cache_inventory()
    return {"bundles": flagged, "repaired": repaired, "dry_run": dry_run}


@app.get("/api/admin/offline-cache")
async def admin_offline_cache_list(request: Request) -> JSONResponse:
    """Inventory: totals + per-item breakdown + orphans.

    Serves a cached snapshot for an instant open; `?refresh=1` forces a fresh
    filesystem walk. The payload carries `generated_at` so the UI can show how
    stale the data is.
    """
    _require_admin(request)
    refresh = request.query_params.get("refresh") in ("1", "true", "yes")
    return JSONResponse(await _build_offline_cache_inventory(force=refresh))


# Route order matters — declare /orphans BEFORE /{cache_key} so FastAPI doesn't
# try to parse "orphans" as a 24-hex cache key.
@app.delete("/api/admin/offline-cache/orphans")
async def admin_offline_cache_purge_orphans(request: Request) -> JSONResponse:
    """Delete every cache/partial dir + legacy MP4 that no longer maps to any library file."""
    _require_admin(request)
    inv = await _build_offline_cache_inventory(force=True)
    deleted = 0
    bytes_freed = 0
    for o in inv["orphans"]:
        if _offline_cache_path_active(o["cache_key"]):
            continue
        freed = await asyncio.to_thread(_delete_cache_artifacts, o["cache_key"], o.get("root"))
        if freed > 0:
            deleted += 1
            bytes_freed += freed
    _invalidate_offline_cache_inventory()
    _invalidate_bundle_index()
    return JSONResponse({"deleted_count": deleted, "bytes_freed": bytes_freed})


@app.delete("/api/admin/offline-cache/{cache_key}")
async def admin_offline_cache_delete_one(cache_key: str, request: Request) -> JSONResponse:
    """Delete the HLS bundle dir, any `.part` staging dir, and any terminal
    job entries targeting `cache_key`. 409 if an active job is writing it.
    """
    _require_admin(request)
    if not _CACHE_KEY_RE.match(cache_key):
        raise HTTPException(400, "Invalid cache key.")
    if _offline_cache_path_active(cache_key):
        raise HTTPException(409, "An active prep job is writing this bundle.")
    # Bundles live beside the media — find which `.streamlink_cache` root (or the
    # legacy central one) actually holds this key before deleting.
    lib = await get_library()
    roots = _bundle_cache_dirs_sync(lib)
    roots.add(OFFLINE_CACHE)
    found_root: Optional[Path] = None
    for r in roots:
        if any((r / n).exists() for n in
               (cache_key, f"{cache_key}.part", f"{cache_key}.mp4", f"{cache_key}.part.mp4")):
            found_root = r
            break
    has_job = any(Path(j.get("out", "")).name == cache_key for j in _offline_jobs.values())
    if found_root is None and not has_job:
        raise HTTPException(404, "Nothing on disk and no job for that cache key.")
    bytes_freed = await asyncio.to_thread(
        _delete_cache_artifacts, cache_key, str(found_root) if found_root else None)
    _invalidate_offline_cache_inventory()
    _invalidate_bundle_index()
    return JSONResponse({"deleted": True, "bytes_freed": bytes_freed})


@app.delete("/api/admin/library/{item_id}/offline-cache")
async def admin_offline_cache_delete_for_item(item_id: str, request: Request) -> JSONResponse:
    """Delete every cached/partial bundle + clear every error-state job entry
    for one library item. Active prep jobs are skipped (the operator can stop
    them via the library card if they really want to abandon them).
    """
    _require_admin(request)
    inv = await _build_offline_cache_inventory(force=True)
    item = next((x for x in inv["items"] if x["item_id"] == item_id), None)
    if not item:
        return JSONResponse({"deleted_count": 0, "bytes_freed": 0})
    deleted = 0
    bytes_freed = 0
    for f in item["files"]:
        if _offline_cache_path_active(f["cache_key"]):
            continue
        freed = await asyncio.to_thread(_delete_cache_artifacts, f["cache_key"], f.get("root"))
        if freed > 0 or f.get("status") == "error":
            deleted += 1
            bytes_freed += freed
    _invalidate_offline_cache_inventory()
    _invalidate_bundle_index()
    return JSONResponse({"deleted_count": deleted, "bytes_freed": bytes_freed})


# ── Admin: qBittorrent + download-folder cleanup ────────────────────────────
#
# qBittorrent, the library, and the download folder drift out of sync over time:
# a crashed stream-now leaves an orphan torrent behind; a user deletes a file on
# disk so qBit flips to `missingFiles`; a buggy add drops stray files no torrent
# owns; a library item points at files that are gone. None of that was visible to
# the operator (the File Validator only decodes *existing* library sources; the
# Offline Cache tab only manages `.offline_cache/`). These endpoints cross-
# reference the three sources into four problem categories, each with a guided
# Recover (where possible) and a confirm-gated Delete.
#
# Mirrors the offline-cache inventory discipline above: a cached snapshot built
# off the event loop (the stray-file disk walk can block), served instantly,
# invalidated on every mutation.

_BROKEN_TORRENT_STATES = {"error", "missingFiles"}

_cleanup_inv_snapshot: "dict | None" = None
_cleanup_inv_lock = asyncio.Lock()


def _invalidate_cleanup_inventory() -> None:
    """Drop the cached cleanup snapshot so the next read rebuilds from disk +
    qBit. Called after any cleanup mutation (recover / adopt / delete)."""
    global _cleanup_inv_snapshot
    _cleanup_inv_snapshot = None


def _cleanup_in_use_hashes(lib: dict) -> set[str]:
    """Torrent hashes cleanup must NEVER touch destructively: the live stream /
    prepare torrent, and any torrent backing a still-downloading library item."""
    in_use: set[str] = set()
    for h in (state.active_hash, state.prepare_hash):
        if h:
            in_use.add(h.lower())
    for it in lib.get("items", []):
        if it.get("status") == "downloading" and it.get("torrent_hash"):
            in_use.add(it["torrent_hash"].lower())
    return in_use


# Directory names StreamLink owns inside media folders — never "stray" in cleanup.
_STREAMLINK_RESERVED_DIRS = {OFFLINE_CACHE_DIRNAME, ".offline_cache", ".ondemand_cache"}


def _cleanup_inventory_sync(lib: dict, torrents: list[dict], in_use: set[str],
                            download_paths: list[str]) -> dict:
    """Cross-reference qBit torrents + the library + EVERY configured download/
    library folder into the four cleanup categories. Synchronous (runs in a worker
    thread) because the stray-file walk + per-path existence checks block."""
    items = lib.get("items", [])
    lib_hashes: dict[str, dict] = {}
    owned: set[str] = set()                 # normalised on-disk paths something owns
    for it in items:
        h = (it.get("torrent_hash") or "").lower()
        if h:
            lib_hashes[h] = it
        for f in it.get("files", []):
            p = f.get("path", "")
            if p:
                owned.add(_norm_path(p))

    broken: list[dict] = []
    orphans: list[dict] = []
    for t in torrents:
        h = (t.get("hash") or "").lower()
        cpath = t.get("content_path") or ""
        spath = t.get("save_path") or ""
        name  = t.get("name", "") or h
        if cpath:
            owned.add(_norm_path(cpath))
        if spath and name:
            owned.add(_norm_path(str(Path(spath) / name)))
        tstate = t.get("state", "")
        linked = lib_hashes.get(h) or {}
        row = {
            "hash": h,
            "name": name,
            "state": tstate,
            "size_bytes": t.get("size", 0) or 0,
            "progress": float(t.get("progress", 0) or 0),
            "save_path": spath,
            "content_path": cpath,
            "added_on": t.get("added_on", 0) or 0,
            "in_use": h in in_use,
            "item_id": linked.get("id", ""),
            "item_title": linked.get("title", ""),
        }
        content_missing = bool(cpath) and not Path(cpath).exists()
        if tstate in _BROKEN_TORRENT_STATES or content_missing:
            row["reason"] = ("qBittorrent reports an error / missing files"
                             if tstate in _BROKEN_TORRENT_STATES
                             else "content path no longer exists on disk")
            broken.append(row)
        elif h not in lib_hashes and h not in in_use:
            orphans.append(row)

    # Category C: library items (not actively downloading) with a non-skip file
    # absent on disk. Recoverable only when a qBit torrent still backs them.
    qbit_hashes = {(t.get("hash") or "").lower() for t in torrents}
    missing_items: list[dict] = []
    for it in items:
        if it.get("status") == "downloading":
            continue
        sched = (it.get("download") or {}).get("files", {})
        gone: list[dict] = []
        for f in it.get("files", []):
            p = f.get("path", "")
            if not p or sched.get(p) == "skip":
                continue
            if not Path(p).exists():
                gone.append({"name": f.get("name", "") or Path(p).name,
                             "path": p, "size_bytes": f.get("size_bytes", 0) or 0})
        if gone:
            h = (it.get("torrent_hash") or "").lower()
            missing_items.append({
                "item_id":       it["id"],
                "title":         it.get("title", ""),
                "missing":       gone,
                "missing_count": len(gone),
                "has_torrent":   bool(h and h in qbit_hashes),
            })

    # Category D: top-level entries in ANY configured download/library folder owned
    # by no torrent or library file. Delete-only. A trailing `.!qB` (qBit's
    # incomplete-file marker) is stripped before the ownership test so an in-progress
    # download isn't stray. StreamLink's own dirs (the co-located `.streamlink_cache`
    # bundles, the central caches) are never stray, and a configured root nested in
    # another isn't flagged when its parent is scanned.
    dl_dirs = [Path(p) for p in download_paths if (p or "").strip()]
    dl_norms = {_norm_path(str(d)) for d in dl_dirs}
    stray: list[dict] = []
    seen_children: set[str] = set()
    for dl in dl_dirs:
        try:
            children = list(dl.iterdir()) if dl.is_dir() else []
        except OSError:
            children = []
        for child in children:
            if child.name in _STREAMLINK_RESERVED_DIRS:
                continue
            cp = str(child)
            if cp in seen_children:
                continue
            seen_children.add(cp)
            raw = cp
            if raw.endswith(".!qB"):
                raw = raw[:-4]
            n = _norm_path(raw)
            # A configured root that's itself a child here (nested library paths) is
            # never stray — it's scanned in its own right.
            if n in dl_norms:
                continue
            if any(o == n or o.startswith(n + os.sep) or n.startswith(o + os.sep)
                   for o in owned):
                continue
            try:
                is_dir = child.is_dir()
                sz = _dir_size_bytes(child) if is_dir else child.stat().st_size
                mtime = child.stat().st_mtime
            except OSError:
                continue
            stray.append({"path": str(child), "name": child.name,
                          "is_dir": is_dir, "bytes": sz, "mtime": mtime})

    broken.sort(key=lambda x: x["name"].lower())
    orphans.sort(key=lambda x: x["size_bytes"], reverse=True)
    stray.sort(key=lambda x: x["bytes"], reverse=True)
    return {
        "download_path":   str(dl_dirs[0]) if dl_dirs else "",
        "download_paths":  [str(d) for d in dl_dirs],
        "broken_torrents": broken,
        "orphan_torrents": orphans,
        "missing_items":   missing_items,
        "stray_files":     stray,
        "totals": {
            "broken":        len(broken),
            "orphans":       len(orphans),
            "missing_items": len(missing_items),
            "stray":         len(stray),
            "stray_bytes":   sum(s["bytes"] for s in stray),
        },
    }


async def _build_cleanup_inventory(*, force: bool = False) -> dict:
    """Return the cleanup inventory, serving a cached snapshot unless `force`.
    Loads the library + the qBit torrent list, then offloads the disk walk to a
    worker thread (same discipline as `_build_offline_cache_inventory`). Stamps
    `generated_at` + `qbit_ok` (false ⇒ qBit unreachable, so the UI shows an
    offline chip instead of treating every library torrent as broken/orphan)."""
    global _cleanup_inv_snapshot
    if not force and _cleanup_inv_snapshot is not None:
        return _cleanup_inv_snapshot
    async with _cleanup_inv_lock:
        if not force and _cleanup_inv_snapshot is not None:
            return _cleanup_inv_snapshot
        lib = await get_library()
        torrents = await qbit_info_all()
        qbit_ok = torrents is not None
        in_use = _cleanup_in_use_hashes(lib)
        all_paths = [info["path"] for info in await _all_library_paths()]
        data = await asyncio.to_thread(
            _cleanup_inventory_sync, lib, torrents or [], in_use,
            all_paths,
        )
        data["generated_at"] = time.time()
        data["qbit_ok"] = qbit_ok
        _cleanup_inv_snapshot = data
        return data


async def _adopt_torrent_to_library(h: str) -> Optional[str]:
    """Build a library item from an existing (orphan) qBit torrent — no new magnet
    needed, the torrent is already in qBit. Returns the new item id, or None if the
    torrent is gone or has no video files. A complete torrent becomes `ready`; an
    incomplete one becomes `downloading` so `library_download_monitor` tracks it."""
    info = await qbit_info(h)
    if info is None:
        return None
    qfiles = await qbit_files(h)
    save_path = info.get("save_path", settings.qbit_download_path)
    files = build_file_list(qfiles, save_path)
    if not files:
        return None
    complete = float(info.get("progress", 0) or 0) >= 0.999
    lib = await get_library()
    item = {
        "id":         str(uuid.uuid4()),
        "title":      info.get("name", "") or files[0]["name"],
        "series":     "",
        "season":     files[0].get("season", 0),
        "episode":    files[0].get("episode", 0),
        "files":      files,
        "size_bytes": info.get("size", 0) or sum(f.get("size_bytes", 0) for f in files),
        "added_at":   _now_iso(),
        "status":     "ready" if complete else "downloading",
        "torrent_hash": h,
        "progress":   {},
        "download":   {"mode": "now", "files": {}},
    }
    lib["items"].append(item)
    await put_library(lib)
    return item["id"]


@app.get("/api/admin/cleanup")
async def admin_cleanup_list(request: Request) -> JSONResponse:
    """Inventory: broken/orphan torrents, library items with missing files, and
    stray download-folder entries. Serves a cached snapshot; `?refresh=1` forces a
    fresh qBit query + disk walk."""
    _require_admin(request)
    refresh = request.query_params.get("refresh") in ("1", "true", "yes")
    return JSONResponse(await _build_cleanup_inventory(force=refresh))


@app.post("/api/admin/cleanup/torrent/{torrent_hash}/recover")
async def admin_cleanup_recover_torrent(torrent_hash: str, request: Request) -> JSONResponse:
    """Re-verify a broken torrent and resume it so qBit re-fetches any missing
    pieces (recheck + resume). 409 if the torrent is currently in use."""
    _require_admin(request)
    h = torrent_hash.lower()
    lib = await get_library()
    if h in _cleanup_in_use_hashes(lib):
        raise HTTPException(409, "That torrent is currently in use.")
    if await qbit_info(h) is None:
        raise HTTPException(404, "Torrent not found in qBittorrent.")
    # If this torrent backs an item with compressed-in-place files, recheck + resume
    # would re-fetch over them. Refuse rather than destroy the re-encoded bytes.
    if any((it.get("torrent_hash") or "").lower() == h and _item_has_compressed(it)
           for it in lib["items"]):
        raise HTTPException(409, "This torrent has compressed files that are no longer "
                                 "torrent-backed — recovering would re-download over them.")
    await qbit_recheck(h)
    await qbit_resume(h)
    _invalidate_cleanup_inventory()
    return JSONResponse({"ok": True})


@app.delete("/api/admin/cleanup/torrent/{torrent_hash}")
async def admin_cleanup_delete_torrent(torrent_hash: str, request: Request,
                                       delete_files: bool = True) -> JSONResponse:
    """Remove a broken/orphan torrent from qBit (+files by default). If it backs a
    library item, drop that item too. 409 if the torrent is currently in use."""
    _require_admin(request)
    h = torrent_hash.lower()
    lib = await get_library()
    if h in _cleanup_in_use_hashes(lib):
        raise HTTPException(409, "That torrent is currently in use.")
    await qbit_delete(h, delete_files=delete_files)
    before = len(lib["items"])
    lib["items"] = [it for it in lib["items"]
                    if (it.get("torrent_hash") or "").lower() != h]
    dropped = before - len(lib["items"])
    if dropped:
        await put_library(lib)
    _invalidate_cleanup_inventory()
    return JSONResponse({"ok": True, "items_removed": dropped})


@app.post("/api/admin/cleanup/orphan/{torrent_hash}/adopt")
async def admin_cleanup_adopt_orphan(torrent_hash: str, request: Request) -> JSONResponse:
    """Create a library item from an orphan qBit torrent so it's no longer stray."""
    _require_admin(request)
    item_id = await _adopt_torrent_to_library(torrent_hash.lower())
    if not item_id:
        raise HTTPException(404, "Torrent not found in qBittorrent, or it has no video files.")
    _invalidate_cleanup_inventory()
    return JSONResponse({"ok": True, "item_id": item_id})


@app.post("/api/admin/cleanup/item/{item_id}/recover")
async def admin_cleanup_recover_item(item_id: str, request: Request) -> JSONResponse:
    """Re-download a library item's missing files: recheck + resume its torrent and
    flip it back to `downloading` so the monitor + scheduler manage it again. 404
    when no qBit torrent backs the item (nothing to recover — delete it instead)."""
    _require_admin(request)
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")
    h = (item.get("torrent_hash") or "").lower()
    if not h or await qbit_info(h) is None:
        raise HTTPException(404, "No qBittorrent torrent backs this item — delete it instead.")
    # Recover = recheck + resume, which would re-fetch over any compressed-in-place file.
    if _item_has_compressed(item):
        raise HTTPException(409, "This item has compressed files that are no longer "
                                 "torrent-backed — recovering would re-download over them.")
    await qbit_recheck(h)
    await qbit_resume(h)
    item["status"] = "downloading"
    await _apply_item_schedule(item, lib)   # reconcile file priorities/pause state
    await put_library(lib)
    _invalidate_cleanup_inventory()
    return JSONResponse({"ok": True})


@app.delete("/api/admin/cleanup/item/{item_id}")
async def admin_cleanup_delete_item(item_id: str, request: Request,
                                    delete_files: bool = True) -> JSONResponse:
    """Remove a library item (and its torrent + files by default)."""
    _require_admin(request)
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")
    h = item.get("torrent_hash")
    if h:
        await qbit_delete(h, delete_files=delete_files)
    lib["items"] = [it for it in lib["items"] if it["id"] != item_id]
    await put_library(lib)
    _invalidate_cleanup_inventory()
    return JSONResponse({"ok": True})


@app.delete("/api/admin/cleanup/stray")
async def admin_cleanup_delete_stray(request: Request, path: str = "") -> JSONResponse:
    """Delete one stray file/dir. Path-guarded: it must resolve strictly inside one
    of the configured download/library folders (no traversal), can't be a configured
    root itself, and must not be owned by a live torrent."""
    _require_admin(request)
    if not path:
        raise HTTPException(400, "Missing path.")
    roots: list[Path] = []
    for info in await _all_library_paths():
        try:
            roots.append(Path(info["path"]).resolve())
        except OSError:
            continue
    try:
        target = Path(path).resolve()
    except OSError:
        raise HTTPException(400, "Invalid path.")
    if target in roots:
        raise HTTPException(400, "Refusing to delete a configured library folder itself.")
    def _within(t: Path, root: Path) -> bool:
        try:
            t.relative_to(root)
            return True
        except ValueError:
            return False
    if not any(_within(target, r) for r in roots):
        raise HTTPException(400, "Path is outside the configured download/library folders.")
    if not target.exists():
        raise HTTPException(404, "Path not found.")
    # Refuse if a current torrent owns this path (only stray clutter is deletable).
    torrents = await qbit_info_all() or []
    n = _norm_path(str(target))
    for t in torrents:
        for owned in (t.get("content_path") or "",
                      str(Path(t.get("save_path") or "") / (t.get("name") or ""))):
            if not owned:
                continue
            o = _norm_path(owned)
            if o == n or o.startswith(n + os.sep) or n.startswith(o + os.sep):
                raise HTTPException(409, "A current torrent owns this path.")
    bytes_freed = await asyncio.to_thread(_dir_size_bytes, target) if target.is_dir() else 0
    try:
        if target.is_dir():
            shutil.rmtree(target, ignore_errors=True)
        else:
            bytes_freed = target.stat().st_size
            target.unlink()
    except OSError as exc:
        raise HTTPException(500, f"Could not delete: {exc}")
    _invalidate_cleanup_inventory()
    return JSONResponse({"deleted": True, "bytes_freed": bytes_freed})


@app.get("/api/library/{item_id}/subtitle")
async def get_subtitle(item_id: str, path: str = "", file: str = "") -> Response:
    """Return a sidecar subtitle as WebVTT, converting SRT/ASS/SSA on demand.

    `path` is the absolute path of a sub found by `_discover_local_subs` (the
    aggressive search — so it may live in a `Subs/` folder). It's validated to
    resolve *inside* the item's media tree (a video file's directory, that
    directory's parent, or a child of either) before anything is read, so it
    can't be used to fetch arbitrary files. `file` (a bare filename next to a
    video) is still accepted for backward compatibility with old links.
    """
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")

    # Allowed roots: each video file's directory + that directory's parent
    # (covers a shared `Subs/` one level up). A requested sub must resolve to,
    # or under, one of these.
    roots: set[Path] = set()
    for vf in item.get("files", []):
        try:
            d = Path(vf.get("path", "")).resolve().parent
        except OSError:
            continue
        roots.add(d)
        roots.add(d.parent)

    target: Optional[Path] = None
    if path:
        try:
            cand = Path(path).resolve()
        except OSError:
            cand = None
        if (cand and cand.is_file() and cand.suffix.lower() in _SUB_FILE_EXTS
                and any(cand == r or r in cand.parents for r in roots)):
            target = cand
    elif file:
        if "/" in file or "\\" in file or ".." in file:
            raise HTTPException(400, "Invalid filename.")
        for r in roots:
            cand = r / file
            if cand.is_file() and cand.suffix.lower() in _SUB_FILE_EXTS:
                target = cand
                break

    if target is None:
        raise HTTPException(404, "Subtitle not found.")
    try:
        vtt = await _sub_to_vtt(target)
    except Exception as e:
        raise HTTPException(422, f"Could not convert subtitle: {e}")
    return Response(vtt, media_type="text/vtt")


@app.get("/api/library/{item_id}/skip-data")
async def get_skip_data_for_play(item_id: str, file_path: str = "") -> JSONResponse:
    """Return per-file intro/credits times so the local player can run skip-intro.

    No admin auth — any profile that can play the item can read its skip data.
    Returns the entry for one file when file_path is given, else the full map.
    """
    lib = await get_library()
    item = next((it for it in lib["items"] if it["id"] == item_id), None)
    if not item:
        raise HTTPException(404, "Item not found.")
    sd = item.get("skip_data", {}) or {}
    if file_path:
        return JSONResponse(sd.get(file_path) or {})
    return JSONResponse(sd)


# Static files must be mounted last so API routes take priority
app.mount("/", StaticFiles(directory="static", html=True), name="static")
